async function init() {
  state.catalogue = await loadCatalogue(state.spriteSet);
  state.enemy.catalogue = await loadJson("./public/monsters/layers.json").catch(() => null);
  state.spellIndex = await loadJson("./public/spellfx/index.json").catch(() => ({ spells: [] }));
  state.itemData = await loadJson("./src/data/items.json").catch(() => ({ items: [] }));
  state.mapTileIndex = await loadJson("./public/maptiles/index.json").catch(() => ({ sets: [] }));
  state.mapObjectIndex = await loadJson("./public/mapobjects/index.json").catch(() => ({ sets: [] }));
  state.mapStampIndex = await loadJson(`./public/mapstamps/index.json?v=${MAP_STAMP_ASSET_VERSION}`).catch(() => ({ stamps: [] }));
  state.sfxManifest = await loadJson("./public/audio/sfx/manifest.json").catch(() => ({ byKey: {}, groups: [] }));
  state.prototypeStats.playerId = loadPrototypeStatsPlayerId();
  await loadPrototypeStatsConfig();
  state.mapSet = state.mapTileIndex.sets.find((set) => set.id === state.mapSet)?.id ?? state.mapTileIndex.sets[0]?.id ?? state.mapSet;
  state.warriorSkillAtlases = await loadWarriorSkillAtlases();
  state.wizardSpellAtlases = await loadCombatSpellAtlases(WIZARD_COMBAT_SPELLS);
  state.taoistSpellAtlases = await loadCombatSpellAtlases(TAOIST_COMBAT_SPELLS);
  state.taoistDefenceBuffImpactAtlases = Object.fromEntries(
    (await Promise.all(
      Object.entries(TAOIST_DEFENCE_BUFF_IMPACT_FX).map(async ([spellId, fxId]) => [
        spellId,
        await loadJson(`./public/spellfx/${fxId}/atlas.json`).catch(() => null),
      ]),
    )).filter(([, atlas]) => atlas),
  );
  state.taoPetAtlases = Object.fromEntries(
    await Promise.all(
      [
        CRYSTAL_SUMMON_SKELETON_PET_INDEX,
        CRYSTAL_SUMMON_SHINSU_PET_INDEX,
        CRYSTAL_SUMMON_SHINSU_VISIBLE_PET_INDEX,
      ].map(async (index) => [
        index,
        await loadJson(`./public/monsters/monster/${index}.json`).catch(() => null),
      ]),
    ),
  );
  state.taoPetAtlas = state.taoPetAtlases[CRYSTAL_SUMMON_SKELETON_PET_INDEX] ?? null;
  state.levelUpAtlas = await loadJson(`./public/spellfx/${LEVEL_UP_FX_ID}/atlas.json`).catch(() => null);
  state.healingRestoreAtlas = await loadJson(`./public/spellfx/${HEALING_RESTORE_FX_ID}/atlas.json`).catch(() => null);
  state.mapLightningAtlas = await loadJson(`./public/spellfx/${MAP_LIGHTNING_FX_ID}/atlas.json`).catch(() => null);
  if (state.mapLightningAtlas) await preloadSpellAtlasSheets(MAP_LIGHTNING_FX_ID, state.mapLightningAtlas);
  state.townNpcAtlases = await loadTownNpcAtlases();
  state.characterStateItems = {
    ...CHARACTER_PAPER_DOLL_FRAMES,
    ...(await loadJson("./public/ui/character/stateitems.json").catch(() => ({}))),
  };
  const loadedSave = loadSavedGameState();
  if (!loadedSave) {
    state.characters = createDefaultCharacterStates();
    applyCharacterState("Warrior", state.characters.Warrior);
  }
  resetBattleForCurrentMode(loadedSave);
  applyPendingOfflineProgress();

  renderLayerControls();
  renderEnemyControls();
  renderSpellControls();
  renderMapControls();
  renderGamePanel();
  renderSceneOverlay();
  renderOfflineReport();
  renderPrototypeStatsNotice();
  renderCombatSkillBar();
  renderZoneEditor();
  renderActionControls();
  bindControls();
  syncBackgroundMusic();
  await reloadAtlases();
  await reloadEnemyAtlas();
  saveReady = true;
  saveGameState(true);
  lastSimulationAt = performance.now();
  requestAnimationFrame(tick);
}

async function preloadSpellAtlasSheets(spellId, atlas) {
  if (!atlas?.layers?.length) return;
  const sheets = [...new Set(atlas.layers.map((layer) => layer.sheet).filter(Boolean))];
  await Promise.all(
    sheets.map((sheet) => loadCachedImage(`./public/spellfx/${spellId}/${sheet}`).catch(() => null)),
  );
}

async function loadWarriorSkillAtlases() {
  const entries = await Promise.all(
    WARRIOR_COMBAT_SKILLS.filter((skill) => skill.id !== "None").map(async (skill) => [
      skill.id,
      await loadJson(`./public/spellfx/${skill.id}/atlas.json`).catch(() => null),
    ]),
  );
  const atlases = Object.fromEntries(entries.filter(([, atlas]) => atlas));
  await Promise.all(Object.entries(atlases).map(([spellId, atlas]) => preloadSpellAtlasSheets(spellId, atlas)));
  return atlases;
}

async function loadCombatSpellAtlases(spells) {
  const entries = await Promise.all(
    spells.map(async (spell) => [
      spell.id,
      await loadJson(`./public/spellfx/${spell.id}/atlas.json`).catch(() => null),
    ]),
  );
  return Object.fromEntries(entries.filter(([, atlas]) => atlas));
}

async function loadTownNpcAtlases() {
  const sprites = [...new Set(TOWN_NPCS.map((npc) => npc.sprite).filter(Boolean))];
  const entries = await Promise.all(
    sprites.map(async (sprite) => [
      sprite,
      await loadJson(`./public/npcs/${sprite}/atlas.json`).catch(() => null),
    ]),
  );
  return Object.fromEntries(entries.filter(([, atlas]) => atlas));
}

function resetBattleForCurrentMode(loadedSave = false) {
  const zone = activeZone();
  if (state.game.mode === "mining" && zone) {
    ensureMiningSpotId(false);
    state.showEnemies = true;
    resetBattle();
    ensureMapStampArenaLock();
    state.battle.cameraX = state.battle.playerX - playerScreenX();
    state.battle.enemy = null;
    state.battle.running = false;
    state.battle.phase = "idle";
    restorePendingSavedPlayerResources();
    const spot = activeMiningSpot();
    state.battle.log = [loadedSave ? `Save loaded at ${spot?.label ?? zone.label}.` : `Mining at ${spot?.label ?? zone.label}.`];
    applyEquippedVisualIndexes();
    queueVisualAtlasReload(["weapon"]);
    setPlayerAction("mine", performance.now(), true);
    return;
  }
  if (state.game.mode === "zone" && zone) {
    state.showEnemies = true;
    resetBattle(randomZoneEnemyTemplate(zone).id);
    restorePendingSavedPlayerResources();
    state.battle.log = [loadedSave ? `Save loaded in ${zone.label}.` : `Teleported to ${zone.label}.`];
    if ((state.battle.player?.hp ?? 0) <= 0) {
      finishBattle(performance.now());
      setPlayerAction("die", performance.now());
      return;
    }
    startBattle();
    return;
  }

  state.game.mode = "town";
  state.game.activeZoneId = null;
  state.showEnemies = false;
  resetBattle();
  restorePendingSavedPlayerResources();
  if (loadedSave) state.battle.log = ["Save loaded."];
}

function createSaveSnapshot() {
  if (bossPartyOnField()) {
    const leaderClassId = bossPartyLeaderClassId();
    if (normalizeCharacterId(state.activeCharacterId) === leaderClassId) {
      syncBossPartyControlledMemberFromState(leaderClassId);
    } else {
      captureActiveCharacterState();
    }
    syncBossPartyMembersToCharacters(state.battle.bossParty, { applyControlled: false });
  } else {
    captureActiveCharacterState();
  }
  const activeCharacter = state.characters[state.activeCharacterId] ?? serializeCurrentCharacterState();
  const groupDungeonRun = groupDungeonOfflineRunSnapshot?.()
    ?? sanitizeGroupDungeonOfflineRun?.(activeCharacter.game?.groupDungeonRun, activeCharacter.game?.activeZoneId, state.activeCharacterId)
    ?? null;
  return {
    version: SAVE_VERSION,
    savedAt: Date.now(),
    activeCharacterId: state.activeCharacterId,
    groupDungeonRun,
    characters: serializeCharactersState(),
    account: {
      storage: cloneStorageState(state.account.storage),
      upgrades: cloneAccountUpgradeState(state.account.upgrades),
      rebirthPoints: accountRebirthPoints(),
      bossRespawns: { ...accountBossRespawns() },
      stats: sanitizeAccountStats(state.account.stats),
    },
    game: {
      ...activeCharacter.game,
      progress: { ...activeCharacter.game.progress },
      dropPity: { ...activeCharacter.game.dropPity },
      bossRespawns: { ...activeCharacter.game.bossRespawns },
      bossKills: { ...activeCharacter.game.bossKills },
      recentLoot: [...activeCharacter.game.recentLoot],
    },
    inventory: cloneInventoryStateIncludingWeaponRefineStaged(activeCharacter.inventory),
    hotbar: cloneHotbarState(activeCharacter.hotbar),
    magic: cloneMagicState(activeCharacter.magic),
    battle: {
      combatClass: state.battle.combatClass,
      ...activeCharacter.battle,
    },
    indexes: {
      armour: state.indexes.armour,
      hair: state.indexes.hair,
      weapon: state.indexes.weapon,
    },
    characterTab: state.characterTab,
    settings: {
      musicSettingsVersion: MUSIC_SETTINGS_VERSION,
      musicEnabled: Boolean(state.settings.musicEnabled),
      musicVolume: normalizedVolume(state.settings.musicVolume),
      musicMode: normalizedMusicMode(state.settings.musicMode),
      musicTrackId: currentMusicTrack()?.id ?? BACKGROUND_MUSIC_TRACKS[0]?.id ?? null,
      sfxEnabled: Boolean(state.settings.sfxEnabled),
      sfxVolume: normalizedVolume(state.settings.sfxVolume),
      prototypeStatsEnabled: Boolean(state.settings.prototypeStatsEnabled),
      prototypeStatsNoticeVersion: Math.max(0, Math.trunc(Number(state.settings.prototypeStatsNoticeVersion) || 0)),
      prototypeResetNoticeVersion: Math.max(0, Math.trunc(Number(state.settings.prototypeResetNoticeVersion) || 0)),
      prototypeResetNoticeLastSeenAt: Math.max(0, Math.trunc(Number(state.settings.prototypeResetNoticeLastSeenAt) || 0)),
    },
  };
}

function saveGameState(force = false) {
  if (!saveReady && !force) return false;
  try {
    localStorage.setItem(SAVE_KEY, JSON.stringify(createSaveSnapshot()));
    lastSaveAt = performance.now();
    return true;
  } catch (err) {
    console.warn("Unable to save game state", err);
    return false;
  }
}

function parseSaveSnapshotText(rawText) {
  const trimmed = String(rawText ?? "").trim();
  if (!trimmed) {
    return { ok: false, error: "Paste a save file or choose a JSON file first." };
  }
  let snapshot;
  try {
    snapshot = JSON.parse(trimmed);
  } catch {
    return { ok: false, error: "That text is not valid JSON." };
  }
  if (!snapshot || typeof snapshot !== "object") {
    return { ok: false, error: "Save data must be a JSON object." };
  }
  const version = Number(snapshot.version);
  if (!Number.isFinite(version)) {
    return { ok: false, error: "Save is missing a version number." };
  }
  if (version !== SAVE_VERSION) {
    return {
      ok: false,
      error: `Save version ${version} is not supported (expected ${SAVE_VERSION}).`,
    };
  }
  if (!snapshot.characters || typeof snapshot.characters !== "object") {
    return { ok: false, error: "Save is missing character data." };
  }
  return { ok: true, snapshot };
}

function saveImportBlockedReason() {
  if (bossPartyOnField()) return "Return to town before importing a save.";
  return null;
}

function exportSaveDownloadName() {
  const stamp = new Date().toISOString().slice(0, 10);
  return `lom-idle-v2-save-${stamp}.json`;
}

function exportGameSave() {
  try {
    const snapshot = createSaveSnapshot();
    const json = JSON.stringify(snapshot, null, 2);
    const blob = new Blob([json], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = exportSaveDownloadName();
    link.click();
    URL.revokeObjectURL(url);
    pushBattleLog("Save exported.");
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return true;
  } catch (err) {
    console.warn("Unable to export game save", err);
    window.alert("Export failed. Try again after returning to town.");
    return false;
  }
}

function clearTransientBattleForSaveImport() {
  stopOneStepTest();
  state.continuousWalk = false;
  state.battle.bossParty = null;
  dismissTaoistPet();
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  state.battle.pendingPetAttack = null;
  state.battle.pendingTwinDrakeHits = [];
  state.battle.groundSpellEffects = [];
  state.battle.attachedSpellFx = [];
  clearTwinDrakePendingState();
}

async function importGameSaveFromText(rawText) {
  const blockReason = saveImportBlockedReason();
  if (blockReason) {
    window.alert(blockReason);
    return false;
  }

  const parsed = parseSaveSnapshotText(rawText);
  if (!parsed.ok) {
    window.alert(parsed.error);
    return false;
  }

  if (!window.confirm("Import this save? Progress on this device will be replaced.")) {
    return false;
  }

  saveReady = false;
  clearTransientBattleForSaveImport();
  if (!applySaveSnapshot(parsed.snapshot)) {
    saveReady = true;
    window.alert("Could not apply that save.");
    return false;
  }

  saveGameState(true);
  resetBattleForCurrentMode(true);
  applyPendingOfflineProgress();
  await reloadAtlases();
  await reloadEnemyAtlas();
  saveReady = true;
  invalidateUi();
  renderLayerControls();
  renderMapControls();
  renderGamePanel();
  renderBattlePanel();
  renderSceneOverlay();
  renderOfflineReport();
  renderCombatSkillBar();
  renderHotbar();
  render();
  closeScene("options");
  pushBattleLog("Save imported.");
  playSfx("ui.teleport", { volume: 0.42, throttleMs: 300 });
  return true;
}

function loadSavedGameState() {
  let snapshot;
  try {
    const raw = localStorage.getItem(SAVE_KEY);
    if (!raw) return false;
    const parsed = parseSaveSnapshotText(raw);
    if (!parsed.ok) return false;
    snapshot = parsed.snapshot;
  } catch (err) {
    console.warn("Unable to load game state", err);
    return false;
  }

  return applySaveSnapshot(snapshot);
}

function applySaveSnapshot(snapshot) {
  if (!snapshot) return false;

  state.characters = restoreCharactersState(snapshot);
  const savedStorageRaw = snapshot.account?.storage ?? snapshot.storage;
  const hadUnpaidStoragePage2 = Math.trunc(Number(savedStorageRaw?.pagesUnlocked) || 1) >= 2
    && !savedStorageRaw?.page2Purchased;
  state.account.storage = sanitizeStorageState(savedStorageRaw);
  state.account.upgrades = sanitizeAccountUpgradeState(snapshot.account?.upgrades ?? snapshot.upgrades);
  state.account.rebirthPoints = Math.max(0, Math.trunc(Number(snapshot.account?.rebirthPoints) || 0));
  state.account.bossRespawns = sanitizeBossRespawns(snapshot.account?.bossRespawns);
  state.account.stats = sanitizeAccountStats(snapshot.account?.stats);
  migrateAccountBossRespawns();
  migrateAccountStats();
  state.activeCharacterId = normalizeCharacterId(snapshot.activeCharacterId ?? snapshot.battle?.combatClass);
  applyCharacterState(state.activeCharacterId, state.characters[state.activeCharacterId]);
  if (hadUnpaidStoragePage2 && state.account.storage.pagesUnlocked === 1) {
    state.storagePage = 0;
    pushBattleLog("Storage page 2 was reset. Unlock it for 1,000,000 gold when you're ready.");
  }
  restoreSettingsState(snapshot);
  restoreEquipmentVisualIndexes(snapshot);
  state.characterTab = CHARACTER_TABS.some((tab) => tab.id === snapshot.characterTab) ? snapshot.characterTab : "character";
  const groupDungeonRun = savedGroupDungeonRunFromCharacters(snapshot, state.game.activeZoneId, state.activeCharacterId);
  if (groupDungeonRun?.zoneId === state.game.activeZoneId) {
    state.game.groupDungeonRun = groupDungeonRun;
    state.pendingBossAssistSelection = groupDungeonRun.classIds.filter((classId) => classId !== state.activeCharacterId);
    state.bossAssistSelection = [...state.pendingBossAssistSelection];
  } else {
    state.game.groupDungeonRun = null;
    state.pendingBossAssistSelection = [];
    state.bossAssistSelection = [];
  }
  pendingOfflineProgress = createPendingOfflineProgress({
    ...snapshot,
    game: state.game,
    battle: {
      ...(snapshot.battle ?? {}),
      ...(state.characters[state.activeCharacterId]?.battle ?? {}),
      combatClass: state.activeCharacterId,
    },
  });
  return true;
}

function normalizeCharacterId(classId) {
  const candidate = String(classId ?? "");
  const match = CHARACTER_SELECT_CLASSES.find((entry) => entry.id === candidate && !entry.disabled);
  return match?.id ?? "Warrior";
}

function createDefaultCharacterStates() {
  return Object.fromEntries(CHARACTER_IDS.map((classId) => [classId, createDefaultCharacterState(classId)]));
}

function createDefaultStorageState() {
  return {
    pagesUnlocked: 1,
    page2Purchased: false,
    maxSlots: STORAGE_BASE_SLOTS,
    nextInstanceId: 1,
    items: [],
  };
}

function createDefaultAccountStats() {
  return {
    rebirthCount: 0,
    rebirthPointsGained: 0,
    rebirthPointsSpent: 0,
    bossKills: {},
  };
}

function createDefaultAccountUpgradeState() {
  return {
    tiers: {},
  };
}

function createDefaultCharacterState(classId) {
  const inventory = createStarterInventoryState(classId);
  return {
    classId,
    game: {
      mode: "town",
      activeZoneId: null,
      kills: 0,
      zoneKills: 0,
      distance: 0,
      playtimeMs: 0,
      lastReward: null,
      recentLoot: [],
      dropPity: {},
      bossRespawns: {},
      bossKills: {},
      progress: {
        level: PLAYER_TEMPLATE.level,
        experience: PLAYER_TEMPLATE.experience,
        gold: inventory.gold,
      },
      starterGearVersion: STARTER_GEAR_VERSION,
      miningNextRollAt: 0,
      miningSpotId: null,
      groupDungeonRun: null,
    },
    inventory,
    hotbar: { slots: Array(HOTBAR_SLOT_COUNT).fill(null) },
    magic: { learned: {} },
    battle: {
      running: false,
      paused: false,
      playerHp: null,
      playerMp: null,
      potHealthAmount: 0,
      potManaAmount: 0,
      healAmount: 0,
      statBuffs: [],
      petStatBuffs: [],
    },
  };
}

function createStarterInventoryState(classId) {
  const inventory = {
    gold: PLAYER_TEMPLATE.gold,
    pagesUnlocked: 1,
    maxSlots: INVENTORY_BASE_SLOTS,
    nextInstanceId: 1,
    items: [],
    equipment: Object.fromEntries(EQUIPMENT_SLOTS.map((slot) => [slot.id, null])),
  };
  const starterItems = ["Warrior", "Wizard", "Taoist"].includes(classId)
    ? [["wooden-sword", 1], ["base-dress", 1], ["hp-drug-small", 5], ["mp-drug-small", 5]]
    : [["base-dress", 1], ["hp-drug-small", 5], ["mp-drug-small", 5]];
  for (const [itemId, quantity] of starterItems) addStarterInventoryEntry(inventory, itemId, quantity);
  return inventory;
}

function addStarterInventoryEntry(inventory, itemId, quantity = 1) {
  const item = itemDefinition(itemId);
  if (!item) return;
  const entry = {
    id: `item-${inventory.nextInstanceId}`,
    itemId,
    quantity: Math.max(1, Math.trunc(Number(quantity) || 1)),
    slot: nextFreeSlotInInventoryState(inventory),
    ...normalizeInventoryEntryFields({}, item),
  };
  inventory.nextInstanceId += 1;
  inventory.items.push(entry);
}

function nextFreeSlotInInventoryState(inventory) {
  syncInventoryCapacity(inventory);
  const used = new Set();
  for (const entry of inventory.items ?? []) {
    const slot = entry.slot;
    if (Number.isInteger(slot) && slot >= 0 && slot < inventory.maxSlots) used.add(slot);
  }
  for (let slot = 0; slot < inventory.maxSlots; slot++) {
    if (!used.has(slot)) return slot;
  }
  return null;
}

function restoreCharactersState(snapshot) {
  const characters = createDefaultCharacterStates();
  if (snapshot.characters && typeof snapshot.characters === "object") {
    for (const classId of CHARACTER_IDS) {
      characters[classId] = sanitizeCharacterState(snapshot.characters[classId], classId);
    }
    return characters;
  }

  const activeClassId = normalizeCharacterId(snapshot.battle?.combatClass);
  characters[activeClassId] = legacyCharacterStateFromSnapshot(snapshot, activeClassId);
  return characters;
}

function legacyCharacterStateFromSnapshot(snapshot, classId) {
  const character = createDefaultCharacterState(classId);
  character.game = sanitizeCharacterGameState(snapshot.game, snapshot.inventory?.gold ?? snapshot.game?.progress?.gold, classId);
  character.inventory = sanitizeInventoryState(snapshot.inventory, snapshot.hotbar, character.game.progress.gold);
  character.game.progress.gold = character.inventory.gold;
  character.hotbar = sanitizeHotbarState(snapshot.hotbar, character.inventory);
  character.magic = removeRetiredTestingDefaultMagic(classId, sanitizeMagicState(snapshot.magic));
  character.battle = sanitizeCharacterBattleState(snapshot.battle);
  backfillStarterGear(character, classId);
  return character;
}

function sanitizeCharacterState(savedCharacter, classId) {
  const character = createDefaultCharacterState(classId);
  if (!savedCharacter || typeof savedCharacter !== "object") return character;
  character.game = sanitizeCharacterGameState(savedCharacter.game, savedCharacter.inventory?.gold, classId);
  character.inventory = sanitizeInventoryState(savedCharacter.inventory, savedCharacter.hotbar, character.game.progress.gold);
  character.game.progress.gold = character.inventory.gold;
  character.hotbar = sanitizeHotbarState(savedCharacter.hotbar, character.inventory);
  character.magic = removeRetiredTestingDefaultMagic(classId, sanitizeMagicState(savedCharacter.magic));
  character.battle = sanitizeCharacterBattleState(savedCharacter.battle);
  backfillStarterGear(character, classId);
  return character;
}

function backfillStarterGear(character, classId) {
  if ((Number(character.game?.starterGearVersion) || 0) >= STARTER_GEAR_VERSION) return;
  if (classId === "Taoist") backfillInventoryItem(character.inventory, "wooden-sword", 1);
  character.game.starterGearVersion = STARTER_GEAR_VERSION;
}

function backfillInventoryItem(inventory, itemId, quantity = 1) {
  if (!inventory || inventory.items?.some((entry) => entry.itemId === itemId)) return false;
  addStarterInventoryEntry(inventory, itemId, quantity);
  return true;
}

function sanitizeCharacterGameState(savedGame, fallbackGold = PLAYER_TEMPLATE.gold, fallbackClassId = state.activeCharacterId) {
  const zoneExists = PROTOTYPE_ZONES.some((zone) => zone.id === savedGame?.activeZoneId);
  const miningMode = savedGame?.mode === "mining" && savedGame?.activeZoneId === MINING_ZONE_ID;
  const zoneMode = savedGame?.mode === "zone" && zoneExists;
  const game = {
    mode: miningMode ? "mining" : zoneMode ? "zone" : "town",
    activeZoneId: miningMode || zoneMode ? savedGame.activeZoneId : null,
    miningNextRollAt: Math.max(0, Math.trunc(Number(savedGame?.miningNextRollAt) || 0)),
    miningSpotId: miningSpotById(savedGame?.miningSpotId)?.id ?? null,
    kills: Math.max(0, Math.trunc(Number(savedGame?.kills) || 0)),
    zoneKills: Math.max(0, Math.trunc(Number(savedGame?.zoneKills) || 0)),
    distance: Math.max(0, Math.trunc(Number(savedGame?.distance) || 0)),
    playtimeMs: Math.max(0, Math.trunc(Number(savedGame?.playtimeMs) || 0)),
    lastReward: savedGame?.lastReward && typeof savedGame.lastReward === "object" ? savedGame.lastReward : null,
    recentLoot: Array.isArray(savedGame?.recentLoot) ? savedGame.recentLoot.map(String).slice(0, 6) : [],
    dropPity: sanitizeDropPity(savedGame?.dropPity),
    bossRespawns: sanitizeBossRespawns(savedGame?.bossRespawns),
    bossKills: sanitizeBossKills(savedGame?.bossKills),
    progress: {
      level: Math.max(1, Math.trunc(Number(savedGame?.progress?.level) || PLAYER_TEMPLATE.level)),
      experience: Math.max(0, Math.trunc(Number(savedGame?.progress?.experience) || 0)),
      gold: Math.max(0, Math.trunc(Number(savedGame?.progress?.gold ?? fallbackGold ?? PLAYER_TEMPLATE.gold) || 0)),
    },
    starterGearVersion: Math.max(0, Math.trunc(Number(savedGame?.starterGearVersion) || 0)),
  };
  game.groupDungeonRun = sanitizeGroupDungeonOfflineRun?.(savedGame?.groupDungeonRun, game.activeZoneId, fallbackClassId) ?? null;
  return game;
}

function sanitizeBossRespawns(respawns = {}) {
  if (!respawns || typeof respawns !== "object") return {};
  return Object.fromEntries(
    Object.entries(respawns)
      .filter(([zoneId]) => zoneTracksBossRespawn(zoneId))
      .map(([zoneId, readyAt]) => [zoneId, Math.max(0, Math.trunc(Number(readyAt) || 0))]),
  );
}

function sanitizeAccountStats(saved = {}) {
  return {
    rebirthCount: Math.max(0, Math.trunc(Number(saved?.rebirthCount) || 0)),
    rebirthPointsGained: Math.max(0, Math.trunc(Number(saved?.rebirthPointsGained) || 0)),
    rebirthPointsSpent: Math.max(0, Math.trunc(Number(saved?.rebirthPointsSpent) || 0)),
    bossKills: sanitizeBossKills(saved?.bossKills),
  };
}

function ensureAccountStats() {
  state.account.stats = sanitizeAccountStats(state.account?.stats);
}

function accountBossKills() {
  ensureAccountStats();
  return { ...sanitizeBossKills(state.account.stats.bossKills) };
}

function syncAccountBossKillsToCharacters() {
  const kills = accountBossKills();
  state.game.bossKills = { ...kills };
  for (const classId of CHARACTER_IDS) {
    const character = state.characters[classId];
    if (!character) continue;
    character.game.bossKills = { ...kills };
  }
}

function migrateAccountStats() {
  ensureAccountStats();
  const mergedKills = { ...accountBossKills() };
  for (const classId of CHARACTER_IDS) {
    const kills = sanitizeBossKills(state.characters[classId]?.game?.bossKills);
    for (const [zoneId, count] of Object.entries(kills)) {
      mergedKills[zoneId] = Math.max(mergedKills[zoneId] ?? 0, count);
    }
  }
  state.account.stats.bossKills = mergedKills;
  syncAccountBossKillsToCharacters();
}

function trackRebirthPointsGained(quantity) {
  const amount = Math.max(0, Math.trunc(Number(quantity) || 0));
  if (amount <= 0) return;
  ensureAccountStats();
  state.account.stats.rebirthPointsGained += amount;
}

function trackRebirthPointsSpent(quantity) {
  const amount = Math.max(0, Math.trunc(Number(quantity) || 0));
  if (amount <= 0) return;
  ensureAccountStats();
  state.account.stats.rebirthPointsSpent += amount;
}

function accountTotalGold() {
  captureActiveCharacterState();
  let total = 0;
  for (const classId of CHARACTER_IDS) {
    const character = state.characters[classId];
    total += Math.max(0, Math.trunc(Number(character?.game?.progress?.gold ?? character?.inventory?.gold) || 0));
  }
  return total;
}

function accountStatsSnapshot() {
  ensureAccountStats();
  captureActiveCharacterState();
  const bossKills = accountBossKills();
  const characterLevels = {};
  for (const classId of CHARACTER_IDS) {
    const progress = state.characters[classId]?.game?.progress;
    characterLevels[classId] = Math.max(1, Math.trunc(Number(progress?.level) || 1));
  }
  return {
    rebirthCount: state.account.stats.rebirthCount,
    rebirthPointsGained: state.account.stats.rebirthPointsGained,
    rebirthPointsSpent: state.account.stats.rebirthPointsSpent,
    rebirthPointsHeld: accountRebirthPoints(),
    awakeningSoulsHeld: accountAwakenedSoulCount(),
    totalGold: accountTotalGold(),
    bossKills,
    bossKillsTotal: Object.values(bossKills).reduce((sum, count) => sum + Math.max(0, Math.trunc(Number(count) || 0)), 0),
    characterLevels,
    highestCharacterLevel: Math.max(1, ...Object.values(characterLevels)),
  };
}

function sanitizeBossKills(kills = {}) {
  if (!kills || typeof kills !== "object") return {};
  return Object.fromEntries(
    Object.entries(kills)
      .filter(([zoneId]) => zoneTracksBossRespawn(zoneId))
      .map(([zoneId, count]) => [zoneId, Math.max(0, Math.trunc(Number(count) || 0))]),
  );
}

function sanitizeInventoryState(savedInventory = {}, savedHotbar = {}, fallbackGold = 0) {
  const usedIds = new Set();
  let maxGeneratedId = 0;
  const items = [];

  for (const savedEntry of Array.isArray(savedInventory.items) ? savedInventory.items : []) {
    if (!savedEntry?.itemId) continue;
    const id = typeof savedEntry.id === "string" && savedEntry.id ? savedEntry.id : "";
    if (!id || usedIds.has(id)) continue;
    usedIds.add(id);
    const generatedId = /^item-(\d+)$/.exec(id)?.[1];
    if (generatedId) maxGeneratedId = Math.max(maxGeneratedId, Number(generatedId));
    items.push({
      id,
      itemId: savedEntry.itemId,
      quantity: Math.max(1, Math.trunc(Number(savedEntry.quantity) || 1)),
      slot: Number.isInteger(savedEntry.slot) ? savedEntry.slot : null,
      ...normalizeInventoryEntryFields(savedEntry),
    });
  }

  const savedEquippedIds = new Set(Object.values(savedInventory.equipment ?? {}).filter(Boolean));
  const savedHotbarIds = new Set((savedHotbar.slots ?? []).filter(Boolean));
  const savedBagItems = items.filter((entry) => !savedEquippedIds.has(entry.id) && !savedHotbarIds.has(entry.id));
  const needsSecondPage = savedBagItems.length > INVENTORY_PAGE_SIZE
    || savedBagItems.some((entry) => Number.isInteger(entry.slot) && entry.slot >= INVENTORY_PAGE_SIZE);
  const pagesUnlocked = Math.max(
    Math.max(1, Math.min(inventoryPageCount(), Math.trunc(Number(savedInventory.pagesUnlocked) || 1))),
    needsSecondPage ? 2 : 1,
  );
  const inventory = {
    gold: Math.max(0, Math.trunc(Number(savedInventory.gold ?? fallbackGold) || 0)),
    pagesUnlocked,
    maxSlots: Math.min(INVENTORY_MAX_SLOTS, pagesUnlocked * INVENTORY_PAGE_SIZE),
    nextInstanceId: Math.max(maxGeneratedId + 1, Math.trunc(Number(savedInventory.nextInstanceId) || 1), 1),
    items,
    equipment: Object.fromEntries(EQUIPMENT_SLOTS.map((slot) => [slot.id, null])),
  };

  const availableEntryIds = new Set(items.map((entry) => entry.id));
  const equippedIds = new Set();
  for (const slot of EQUIPMENT_SLOTS) {
    const entryId = savedInventory.equipment?.[slot.id] ?? null;
    if (!availableEntryIds.has(entryId) || equippedIds.has(entryId)) continue;
    inventory.equipment[slot.id] = entryId;
    equippedIds.add(entryId);
  }
  return inventory;
}

function sanitizeStorageState(savedStorage = {}) {
  const usedIds = new Set();
  let maxGeneratedId = 0;
  const items = [];

  for (const savedEntry of Array.isArray(savedStorage.items) ? savedStorage.items : []) {
    if (!savedEntry?.itemId) continue;
    let id = typeof savedEntry.id === "string" && savedEntry.id ? savedEntry.id : "";
    if (!id || usedIds.has(id)) {
      maxGeneratedId += 1;
      id = `storage-item-${maxGeneratedId}`;
    }
    usedIds.add(id);
    const generatedId = /^storage-item-(\d+)$/.exec(id)?.[1];
    if (generatedId) maxGeneratedId = Math.max(maxGeneratedId, Number(generatedId));
    items.push({
      id,
      itemId: savedEntry.itemId,
      quantity: Math.max(1, Math.trunc(Number(savedEntry.quantity) || 1)),
      slot: Number.isInteger(savedEntry.slot) ? savedEntry.slot : null,
      ...normalizeInventoryEntryFields(savedEntry),
    });
  }

  const savedPagesUnlocked = Math.max(
    1,
    Math.min(storagePageCount(), Math.trunc(Number(savedStorage.pagesUnlocked) || 1)),
  );
  const page2Purchased = Boolean(savedStorage.page2Purchased);
  let pagesUnlocked = savedPagesUnlocked;
  if (pagesUnlocked >= 2 && !page2Purchased) {
    for (const entry of items) {
      if (Number.isInteger(entry.slot) && entry.slot >= STORAGE_PAGE_SIZE) {
        entry.slot = null;
      }
    }
    pagesUnlocked = 1;
  }
  const storage = {
    pagesUnlocked,
    page2Purchased,
    maxSlots: STORAGE_BASE_SLOTS,
    nextInstanceId: Math.max(maxGeneratedId + 1, Math.trunc(Number(savedStorage.nextInstanceId) || 1), 1),
    items,
  };
  syncStorageCapacity(storage);
  ensureStorageSlots(storage);
  return storage;
}

function sanitizeAccountUpgradeState(savedUpgrades = {}) {
  const rawPurchased = savedUpgrades?.purchased && typeof savedUpgrades.purchased === "object"
    ? savedUpgrades.purchased
    : savedUpgrades;
  const rawTiers = savedUpgrades?.tiers && typeof savedUpgrades.tiers === "object"
    ? savedUpgrades.tiers
    : {};
  const tiers = {};
  for (const upgrade of ACCOUNT_UPGRADE_DEFS) {
    const fromTiers = Math.max(0, Math.trunc(Number(rawTiers?.[upgrade.id]) || 0));
    const fromPurchased = rawPurchased?.[upgrade.id] ? 1 : 0;
    const tier = Math.max(fromTiers, fromPurchased);
    const maxTier = accountUpgradeMaxTier(upgrade);
    if (tier > 0) {
      tiers[upgrade.id] = Number.isFinite(maxTier) ? Math.min(tier, maxTier) : tier;
    }
  }
  const legacyStatTier = Math.max(0, Math.trunc(Number(rawTiers?.[LEGACY_REBIRTH_BASE_STAT_UPGRADE_ID]) || 0));
  if (legacyStatTier > 0) {
    for (const upgradeId of REBIRTH_BASE_STAT_UPGRADE_IDS) {
      tiers[upgradeId] = Math.max(tiers[upgradeId] ?? 0, legacyStatTier);
    }
  }
  return { tiers };
}

function awakeningSoulQuantityInInventory(inventory, itemId = AWAKENING_SOUL_ITEM_ID) {
  return (inventory?.items ?? [])
    .filter((entry) => entry.itemId === itemId)
    .reduce((total, entry) => total + Math.max(1, Math.trunc(Number(entry.quantity) || 1)), 0);
}

function accountAwakenedSoulCount() {
  captureActiveCharacterState();
  let total = 0;
  for (const classId of CHARACTER_IDS) {
    total += awakeningSoulQuantityInInventory(state.characters[classId]?.inventory);
  }
  for (const entry of storageEntries()) {
    if (entry.itemId === AWAKENING_SOUL_ITEM_ID) {
      total += Math.max(1, Math.trunc(Number(entry.quantity) || 1));
    }
  }
  return total;
}

function canPerformRebirth() {
  if (!REBIRTH_ENABLED) return false;
  return accountAwakenedSoulCount() >= 1;
}

function deductItemQuantityFromInventoryState(inventory, itemId, quantity) {
  let remaining = Math.max(0, Math.trunc(Number(quantity) || 0));
  if (!inventory || remaining <= 0) return remaining;
  const entries = [...(inventory.items ?? [])].filter((entry) => entry.itemId === itemId);
  for (const entry of entries) {
    if (remaining <= 0) break;
    const stack = Math.max(1, Math.trunc(Number(entry.quantity) || 1));
    const taken = Math.min(remaining, stack);
    entry.quantity = stack - taken;
    remaining -= taken;
    if (entry.quantity <= 0) {
      inventory.items = inventory.items.filter((candidate) => candidate.id !== entry.id);
    }
  }
  return remaining;
}

function deductItemQuantityFromStorage(itemId, quantity) {
  let remaining = Math.max(0, Math.trunc(Number(quantity) || 0));
  if (remaining <= 0) return remaining;
  const entries = [...storageEntries()].filter((entry) => entry.itemId === itemId);
  for (const entry of entries) {
    if (remaining <= 0) break;
    const stack = Math.max(1, Math.trunc(Number(entry.quantity) || 1));
    const taken = Math.min(remaining, stack);
    entry.quantity = stack - taken;
    remaining -= taken;
    if (entry.quantity <= 0) {
      state.account.storage.items = state.account.storage.items.filter((candidate) => candidate.id !== entry.id);
    }
  }
  return remaining;
}

function createStorageEntry(itemId, quantity) {
  ensureStorageSlots();
  const slot = nextFreeStorageSlot();
  const maxSlots = state.account.storage.maxSlots;
  return {
    id: allocateStorageEntryId(),
    itemId,
    quantity,
    slot: Number.isInteger(slot) && slot < maxSlots ? slot : null,
  };
}

function addItemQuantityToStorage(itemId, quantity = 1) {
  ensureStorageSlots();
  const item = itemDefinition(itemId);
  if (!item) return 0;
  let remaining = Math.max(1, Math.floor(Number(quantity) || 1));
  const maxStack = maxItemStack(item);
  let added = 0;

  while (remaining > 0) {
    if (isStackableItem(item)) {
      const existing = storageEntries().find((entry) => entry.itemId === itemId && entry.quantity < maxStack);
      if (existing) {
        const add = Math.min(remaining, maxStack - existing.quantity);
        existing.quantity += add;
        remaining -= add;
        added += add;
        continue;
      }
      if (nextFreeStorageSlot() >= state.account.storage.maxSlots) break;
      const entry = createStorageEntry(itemId, Math.min(remaining, maxStack));
      state.account.storage.items.push(entry);
      added += entry.quantity;
      remaining -= entry.quantity;
      continue;
    }

    if (nextFreeStorageSlot() >= state.account.storage.maxSlots) break;
    const entry = createStorageEntry(itemId, 1);
    state.account.storage.items.push(entry);
    added += 1;
    remaining -= 1;
  }

  ensureStorageSlots();
  return added;
}

function accountRebirthPoints() {
  return Math.max(0, Math.trunc(Number(state.account.rebirthPoints) || 0));
}

function payRebirthPoints(quantity) {
  const cost = Math.max(1, Math.trunc(Number(quantity) || 1));
  if (accountRebirthPoints() < cost) return false;
  state.account.rebirthPoints = accountRebirthPoints() - cost;
  trackRebirthPointsSpent(cost);
  return true;
}

function resetCharacterProgressForRebirth(classId) {
  return createDefaultCharacterState(classId);
}

function awakeningSoulQuantityInStorage() {
  return storageEntries()
    .filter((entry) => entry.itemId === AWAKENING_SOUL_ITEM_ID)
    .reduce((total, entry) => total + Math.max(1, Math.trunc(Number(entry.quantity) || 1)), 0);
}

function resetAccountStorageForRebirth() {
  captureActiveCharacterState();
  state.account.storage = createDefaultStorageState();
}

function resetNonRebirthAccountUpgrades() {
  state.account.upgrades = sanitizeAccountUpgradeState(state.account.upgrades);
  const tiers = { ...(state.account.upgrades.tiers ?? {}) };
  for (const upgradeId of Object.keys(tiers)) {
    const upgrade = accountUpgradeById(upgradeId);
    if (!upgrade || upgrade.category !== "rebirth") delete tiers[upgradeId];
  }
  state.account.upgrades = { tiers };
}

function performAccountRebirth() {
  if (!REBIRTH_ENABLED) {
    pushBattleLog("Rebirth is not available yet.");
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  if (!canPerformRebirth()) {
    pushBattleLog("Need at least 1 Awakening Soul to rebirth.");
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  captureActiveCharacterState();
  const soulsConverted = accountAwakenedSoulCount();
  resetAccountStorageForRebirth();
  resetNonRebirthAccountUpgrades();
  ensureAccountStats();
  if (soulsConverted > 0) {
    state.account.rebirthPoints = accountRebirthPoints() + soulsConverted;
    trackRebirthPointsGained(soulsConverted);
  }
  state.account.stats.rebirthCount += 1;
  for (const classId of CHARACTER_IDS) {
    state.characters[classId] = resetCharacterProgressForRebirth(classId);
  }
  state.game.mode = "town";
  state.game.activeZoneId = null;
  state.showEnemies = false;
  state.continuousWalk = false;
  state.paused = false;
  state.bossEmpowerSelected = false;
  applyCharacterState(state.activeCharacterId, state.characters[state.activeCharacterId]);
  normalizeAutoCastSpellsForClass(state.battle.combatClass);
  resetBattleForCurrentMode(false);
  pushBattleLog(`Rebirth complete. All characters reset to level 1 with starter gear.${soulsConverted > 0 ? ` ${soulsConverted} Awakening Soul${soulsConverted === 1 ? "" : "s"} converted into Rebirth Points.` : ""}`);
  playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  renderMapControls();
  render();
  saveGameState(true);
  return true;
}

function sanitizeHotbarState(savedHotbar = {}, inventory = state.inventory) {
  const availableEntryIds = new Set((inventory.items ?? []).map((entry) => entry.id));
  const equippedIds = new Set(Object.values(inventory.equipment ?? {}).filter(Boolean));
  return {
    slots: Array.from({ length: HOTBAR_SLOT_COUNT }, (_, slot) => {
      const entryId = savedHotbar?.slots?.[slot] ?? null;
      return availableEntryIds.has(entryId) && !equippedIds.has(entryId) ? entryId : null;
    }),
  };
}

function sanitizeMagicState(savedMagic = {}) {
  const learned = savedMagic?.learned ?? {};
  return {
    learned: Object.fromEntries(
      Object.entries(learned)
        .filter(([spellId]) => magicSpellById(spellId))
        .map(([spellId, savedSpell]) => [
          spellId,
          {
            spellId,
            level: Math.max(0, Math.min(3, Math.trunc(Number(savedSpell.level) || 0))),
            experience: Math.max(0, Math.trunc(Number(savedSpell.experience) || 0)),
            key: savedSpell.key ?? null,
            autoCast: Boolean(savedSpell.autoCast),
            castReadyAt: 0,
            learnedAt: Number(savedSpell.learnedAt) || 0,
          },
        ]),
    ),
  };
}

function sanitizeCharacterBattleState(savedBattle = {}) {
  return {
    running: savedBattle?.running !== false,
    paused: savedBattle?.paused === true,
    playerHp: finiteNumberOrNull(savedBattle?.playerHp),
    playerMp: finiteNumberOrNull(savedBattle?.playerMp),
    potHealthAmount: Math.max(0, Math.trunc(Number(savedBattle?.potHealthAmount) || 0)),
    potManaAmount: Math.max(0, Math.trunc(Number(savedBattle?.potManaAmount) || 0)),
    healAmount: Math.max(0, Math.trunc(Number(savedBattle?.healAmount) || 0)),
    statBuffs: sanitizeStatBuffs(savedBattle?.statBuffs),
    petStatBuffs: sanitizeStatBuffs(savedBattle?.petStatBuffs),
  };
}

function applyCharacterState(classId, character = createDefaultCharacterState(classId)) {
  const safeClassId = normalizeCharacterId(classId);
  state.activeCharacterId = safeClassId;
  state.battle.combatClass = safeClassId;
  state.game.mode = character.game.mode;
  state.game.activeZoneId = character.game.activeZoneId;
  state.game.kills = character.game.kills;
  state.game.zoneKills = character.game.zoneKills;
  state.game.distance = character.game.distance;
  state.game.playtimeMs = character.game.playtimeMs;
  sessionStartedAt = performance.now();
  state.game.lastReward = character.game.lastReward;
  state.game.recentLoot = [...character.game.recentLoot];
  state.game.lootToasts = [];
  state.game.dropPity = { ...character.game.dropPity };
  state.game.bossRespawns = { ...accountBossRespawns() };
  state.game.bossKills = { ...accountBossKills() };
  state.game.selectedTownNpcId = null;
  state.game.hoveredTownNpcId = null;
  state.game.miningNextRollAt = Math.max(0, Math.trunc(Number(character.game.miningNextRollAt) || 0));
  state.game.miningSpotId = miningSpotById(character.game.miningSpotId)?.id ?? null;
  state.game.groupDungeonRun = sanitizeGroupDungeonOfflineRun?.(character.game.groupDungeonRun, character.game.activeZoneId, safeClassId) ?? null;
  state.game.progress = { ...character.game.progress };
  state.inventory = cloneInventoryState(character.inventory);
  state.hotbar = cloneHotbarState(character.hotbar);
  state.magic = cloneMagicState(character.magic);
  removeRetiredTestingDefaultMagic(safeClassId, state.magic);
  normalizeAutoCastSpellsForClass(safeClassId);
  state.paused = character.battle?.paused === true;
  state.battle.statBuffs = sanitizeStatBuffs(character.battle?.statBuffs);
  state.battle.petStatBuffs = sanitizeStatBuffs(character.battle?.petStatBuffs);
  pendingSavedPlayerResources = {
    hp: finiteNumberOrNull(character.battle?.playerHp),
    mp: finiteNumberOrNull(character.battle?.playerMp),
    potHealthAmount: Math.max(0, Math.trunc(Number(character.battle?.potHealthAmount) || 0)),
    potManaAmount: Math.max(0, Math.trunc(Number(character.battle?.potManaAmount) || 0)),
    healAmount: Math.max(0, Math.trunc(Number(character.battle?.healAmount) || 0)),
  };
  syncInventoryCapacity();
  ensureInventorySlots();
  state.game.progress.gold = state.inventory.gold;
  applyEquippedVisualIndexes();
}

function captureActiveCharacterState() {
  const classId = normalizeCharacterId(state.activeCharacterId);
  state.characters[classId] = serializeCurrentCharacterState();
}

// Keep every saved character's zone/town state aligned (boss party assist chars each
// have their own character slot and reload via applyCharacterState on tab switch).
function persistCharacterGameLocation({ mode, zoneId = null, classIds = null, running = false } = {}) {
  const ids = (classIds ?? CHARACTER_IDS).map(normalizeCharacterId).filter((classId) => state.characters?.[classId]);
  for (const classId of ids) {
    const character = state.characters[classId];
    character.game.mode = mode;
    character.game.activeZoneId = zoneId;
    if (mode === "town") {
      character.game.zoneKills = 0;
      character.game.distance = 0;
      character.game.miningNextRollAt = 0;
      character.game.miningSpotId = null;
      state.game.groupDungeonRun = null;
      character.game.groupDungeonRun = null;
    } else if (mode === "mining") {
      character.game.miningSpotId = state.game.miningSpotId ?? null;
      state.game.groupDungeonRun = null;
      character.game.groupDungeonRun = null;
    } else if (mode === "zone" && groupDungeonZone?.(PROTOTYPE_ZONES.find((zone) => zone.id === zoneId))) {
      const entryZone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId);
      const groupRun = groupDungeonOfflineRunSnapshot?.() ?? {
        kind: "groupDungeon",
        zoneId,
        leaderClassId: state.activeCharacterId,
        classIds: ids,
        waveNumber: 1,
        killedThisWave: 0,
        targetThisWave: groupDungeonWaveSpawnCount(1, entryZone),
        endless: false,
      };
      state.game.groupDungeonRun = groupRun;
      character.game.groupDungeonRun = groupRun;
    } else {
      state.game.groupDungeonRun = null;
      character.game.groupDungeonRun = null;
    }
    character.battle = {
      ...character.battle,
      running: Boolean(running),
      paused: false,
    };
    if (mode === "town") {
      character.battle.statBuffs = [];
      character.battle.petStatBuffs = [];
    }
    state.characters[classId] = character;
  }
}

function bossPartyMemberClassIds(party = state.battle.bossParty) {
  if (!party?.members?.length) return [state.activeCharacterId];
  return party.members.map((member) => member.classId);
}

function bossPartyOnField(party = state.battle.bossParty) {
  return Boolean(party?.members?.length && (party.active || party.finished));
}

function freezeBossPartyMembersForAftermath(party, now = performance.now()) {
  if (!party?.members?.length) return;
  for (const member of party.members) {
    if (!member.alive || member.hp <= 0) continue;
    member.targetWorldX = null;
    member.meleeAdvanceFromX = null;
    member.meleeAdvanceStartedAt = null;
    member.visualAction = "stance";
    member.visualOneShot = false;
    member.visualFrame = 0;
    member.visualLastTick = now;
    member.nextActionAt = Number.POSITIVE_INFINITY;
    member.returnToStandAt = now + COMBAT_STANCE_HOLD_MS;
    if (member.classId === bossPartyControlledClassId()) setPlayerAction("stance", now);
  }
}

function updateBossPartyMemberRestState(member, now) {
  if (!member?.alive || member.hp <= 0 || !member.returnToStandAt) return;
  if (now < member.returnToStandAt) return;
  member.returnToStandAt = 0;
  member.visualAction = "standing";
  member.visualFrame = 0;
  member.visualOneShot = false;
  member.visualLastTick = now;
  if (member.classId === bossPartyControlledClassId()) setPlayerAction("standing", now);
}

function returnAllCharactersToTown() {
  if (bossPartyOnField()) {
    syncBossPartyControlledMemberFromState(bossPartyLeaderClassId());
    syncBossPartyMembersToCharacters(state.battle.bossParty, { applyControlled: true });
  } else {
    captureActiveCharacterState();
  }
  clearGroupDungeonRunState();
  state.battle.bossParty = null;
  state.game.mode = "town";
  state.game.activeZoneId = null;
  lastStageShellSize = { w: 0, h: 0, mode: "", scale: 0 };
  state.game.zoneKills = 0;
  state.game.distance = 0;
  state.game.miningNextRollAt = 0;
  state.game.miningSpotId = null;
  state.game.selectedTownNpcId = null;
  persistCharacterGameLocation({ mode: "town", zoneId: null, classIds: CHARACTER_IDS, running: false });
}

function serializeCurrentCharacterState() {
  return {
    classId: state.activeCharacterId,
    game: {
      mode: state.game.mode,
      activeZoneId: state.game.activeZoneId,
      kills: state.game.kills,
      zoneKills: state.game.zoneKills,
      distance: Math.floor(Number(state.game.distance) || 0),
      playtimeMs: Math.floor(totalPlaytimeMs()),
      lastReward: state.game.lastReward,
      recentLoot: state.game.recentLoot.slice(0, 6),
      dropPity: { ...state.game.dropPity },
      bossRespawns: { ...state.game.bossRespawns },
      bossKills: { ...state.game.bossKills },
      progress: {
        level: state.game.progress.level,
        experience: state.game.progress.experience,
        gold: state.inventory.gold,
      },
      starterGearVersion: STARTER_GEAR_VERSION,
      miningNextRollAt: Math.max(0, Math.trunc(Number(state.game.miningNextRollAt) || 0)),
      miningSpotId: state.game.miningSpotId ?? null,
      groupDungeonRun: state.game.groupDungeonRun ?? null,
    },
    inventory: cloneInventoryState(state.inventory),
    hotbar: cloneHotbarState(state.hotbar),
    magic: magicStateForPersistence(state.magic),
    battle: {
      running: state.battle.running,
      paused: state.paused,
      playerHp: state.battle.player?.hp ?? pendingSavedPlayerResources?.hp ?? null,
      playerMp: state.battle.player?.mp ?? pendingSavedPlayerResources?.mp ?? null,
      potHealthAmount: state.battle.potHealthAmount ?? pendingSavedPlayerResources?.potHealthAmount ?? 0,
      potManaAmount: state.battle.potManaAmount ?? pendingSavedPlayerResources?.potManaAmount ?? 0,
      healAmount: state.battle.healAmount ?? pendingSavedPlayerResources?.healAmount ?? 0,
      statBuffs: pruneStatBuffs(state.battle.statBuffs ?? []),
      petStatBuffs: pruneStatBuffs(state.battle.petStatBuffs ?? []),
    },
  };
}

function serializeCharactersState() {
  return Object.fromEntries(CHARACTER_IDS.map((classId) => {
    const character = state.characters[classId] ?? createDefaultCharacterState(classId);
    return [classId, {
      classId,
      game: {
        ...character.game,
        progress: { ...character.game.progress },
        starterGearVersion: Math.max(STARTER_GEAR_VERSION, Math.trunc(Number(character.game.starterGearVersion) || 0)),
        dropPity: { ...character.game.dropPity },
        bossRespawns: { ...character.game.bossRespawns },
        bossKills: { ...character.game.bossKills },
        recentLoot: [...character.game.recentLoot],
      },
      inventory: cloneInventoryState(character.inventory),
      hotbar: cloneHotbarState(character.hotbar),
      magic: magicStateForPersistence(character.magic),
      battle: { ...character.battle },
    }];
  }));
}

function cloneInventoryState(inventory) {
  const cloned = {
    gold: Math.max(0, Math.trunc(Number(inventory?.gold) || 0)),
    pagesUnlocked: Math.max(1, Math.min(inventoryPageCount(), Math.trunc(Number(inventory?.pagesUnlocked) || 1))),
    maxSlots: INVENTORY_BASE_SLOTS,
    nextInstanceId: Math.max(1, Math.trunc(Number(inventory?.nextInstanceId) || 1)),
    items: (inventory?.items ?? []).map((entry) => ({
      id: entry.id,
      itemId: entry.itemId,
      quantity: Math.max(1, Math.trunc(Number(entry.quantity) || 1)),
      slot: Number.isInteger(entry.slot) ? entry.slot : null,
      ...normalizeInventoryEntryFields(entry),
    })),
    equipment: Object.fromEntries(EQUIPMENT_SLOTS.map((slot) => [slot.id, inventory?.equipment?.[slot.id] ?? null])),
  };
  syncInventoryCapacity(cloned);
  return cloned;
}

function cloneInventoryStateIncludingWeaponRefineStaged(inventory) {
  const cloned = cloneInventoryState(inventory);
  for (const staged of Object.values(state.weaponRefine?.stagedEntries ?? {})) {
    if (!staged?.entry || cloned.items.some((entry) => entry.id === staged.entry.id)) continue;
    cloned.items.push({
      id: staged.entry.id,
      itemId: staged.entry.itemId,
      quantity: Math.max(1, Math.trunc(Number(staged.entry.quantity) || 1)),
      slot: Number.isInteger(staged.returnSlot) ? staged.returnSlot : (
        Number.isInteger(staged.entry.slot) ? staged.entry.slot : null
      ),
      ...normalizeInventoryEntryFields(staged.entry),
    });
  }
  syncInventoryCapacity(cloned);
  return cloned;
}

function cloneStorageState(storage) {
  const cloned = {
    pagesUnlocked: Math.max(1, Math.min(storagePageCount(), Math.trunc(Number(storage?.pagesUnlocked) || 1))),
    page2Purchased: Boolean(storage?.page2Purchased),
    maxSlots: STORAGE_BASE_SLOTS,
    nextInstanceId: Math.max(1, Math.trunc(Number(storage?.nextInstanceId) || 1)),
    items: (storage?.items ?? []).map((entry) => ({
      id: entry.id,
      itemId: entry.itemId,
      quantity: Math.max(1, Math.trunc(Number(entry.quantity) || 1)),
      slot: Number.isInteger(entry.slot) ? entry.slot : null,
      ...normalizeInventoryEntryFields(entry),
    })),
  };
  if (cloned.pagesUnlocked >= 2 && !cloned.page2Purchased) {
    for (const entry of cloned.items) {
      if (Number.isInteger(entry.slot) && entry.slot >= STORAGE_PAGE_SIZE) {
        entry.slot = null;
      }
    }
    cloned.pagesUnlocked = 1;
  }
  syncStorageCapacity(cloned);
  ensureStorageSlots(cloned);
  return cloned;
}

function cloneAccountUpgradeState(upgrades) {
  return sanitizeAccountUpgradeState(upgrades);
}

function cloneHotbarState(hotbar) {
  return {
    slots: Array.from({ length: HOTBAR_SLOT_COUNT }, (_, slot) => hotbar?.slots?.[slot] ?? null),
  };
}

function cloneMagicState(magic) {
  return {
    learned: Object.fromEntries(
      Object.entries(magic?.learned ?? {}).map(([spellId, learned]) => [
        spellId,
        {
          spellId: learned.spellId ?? spellId,
          level: Math.max(0, Math.min(3, Math.trunc(Number(learned.level) || 0))),
          experience: Math.max(0, Math.trunc(Number(learned.experience) || 0)),
          key: learned.key ?? null,
          autoCast: Boolean(learned.autoCast),
          castReadyAt: Math.max(0, Number(learned.castReadyAt) || 0),
          learnedAt: Number(learned.learnedAt) || 0,
        },
      ]),
    ),
  };
}

function magicStateForPersistence(magic) {
  const cloned = cloneMagicState(magic);
  for (const learned of Object.values(cloned.learned ?? {})) {
    learned.castReadyAt = 0;
  }
  return cloned;
}

function removeRetiredTestingDefaultMagic(classId, magic) {
  if (classId !== "Wizard") return magic;
  if (!magic.learned || typeof magic.learned !== "object") magic.learned = {};
  for (const spellId of RETIRED_TEST_DEFAULT_WIZARD_SPELLS) {
    const learned = magic.learned[spellId];
    if (learned && !learned.learnedAt) delete magic.learned[spellId];
  }
  return magic;
}

function restoreInventoryState(snapshot) {
  const savedInventory = snapshot.inventory ?? {};
  const savedItems = Array.isArray(savedInventory.items) ? savedInventory.items : [];
  const usedIds = new Set();
  let maxGeneratedId = 0;
  const items = [];

  for (const savedEntry of savedItems) {
    if (!savedEntry?.itemId) continue;
    const id = typeof savedEntry.id === "string" && savedEntry.id ? savedEntry.id : "";
    if (!id || usedIds.has(id)) continue;
    usedIds.add(id);
    const generatedId = /^item-(\d+)$/.exec(id)?.[1];
    if (generatedId) maxGeneratedId = Math.max(maxGeneratedId, Number(generatedId));
    items.push({
      id,
      itemId: savedEntry.itemId,
      quantity: Math.max(1, Math.trunc(Number(savedEntry.quantity) || 1)),
      slot: Number.isInteger(savedEntry.slot) ? savedEntry.slot : null,
      ...normalizeInventoryEntryFields(savedEntry),
    });
  }

  const savedEquippedIds = new Set(Object.values(savedInventory.equipment ?? {}).filter(Boolean));
  const savedHotbarIds = new Set((snapshot.hotbar?.slots ?? []).filter(Boolean));
  const savedBagItems = items.filter((entry) => !savedEquippedIds.has(entry.id) && !savedHotbarIds.has(entry.id));
  const needsSecondPage = savedBagItems.length > INVENTORY_PAGE_SIZE
    || savedBagItems.some((entry) => Number.isInteger(entry.slot) && entry.slot >= INVENTORY_PAGE_SIZE);
  const savedPagesUnlocked = Math.max(1, Math.min(inventoryPageCount(), Math.trunc(Number(savedInventory.pagesUnlocked) || 1)));
  state.inventory.gold = Math.max(0, Math.trunc(Number(savedInventory.gold ?? snapshot.game?.progress?.gold ?? 0) || 0));
  state.inventory.pagesUnlocked = Math.max(savedPagesUnlocked, needsSecondPage ? 2 : 1);
  syncInventoryCapacity();
  state.inventory.items = items;
  state.inventory.nextInstanceId = Math.max(
    maxGeneratedId + 1,
    Math.trunc(Number(savedInventory.nextInstanceId) || 1),
    1,
  );
  state.inventory.equipment = Object.fromEntries(EQUIPMENT_SLOTS.map((slot) => [slot.id, null]));

  const availableEntryIds = new Set(items.map((entry) => entry.id));
  const equippedIds = new Set();
  for (const slot of EQUIPMENT_SLOTS) {
    const entryId = savedInventory.equipment?.[slot.id] ?? null;
    if (!availableEntryIds.has(entryId) || equippedIds.has(entryId)) continue;
    state.inventory.equipment[slot.id] = entryId;
    equippedIds.add(entryId);
  }
}

function restoreGameProgress(snapshot) {
  const savedGame = snapshot.game ?? {};
  const zoneExists = PROTOTYPE_ZONES.some((zone) => zone.id === savedGame.activeZoneId);
  const miningMode = savedGame.mode === "mining" && savedGame.activeZoneId === MINING_ZONE_ID;
  state.game.mode = miningMode ? "mining" : savedGame.mode === "zone" && zoneExists ? "zone" : "town";
  state.game.activeZoneId = state.game.mode === "town" ? null : savedGame.activeZoneId;
  state.game.miningNextRollAt = Math.max(0, Math.trunc(Number(savedGame.miningNextRollAt) || 0));
  state.game.miningSpotId = miningSpotById(savedGame.miningSpotId)?.id ?? null;
  state.game.kills = Math.max(0, Math.trunc(Number(savedGame.kills) || 0));
  state.game.zoneKills = Math.max(0, Math.trunc(Number(savedGame.zoneKills) || 0));
  state.game.distance = Math.max(0, Math.trunc(Number(savedGame.distance) || 0));
  state.game.playtimeMs = Math.max(0, Math.trunc(Number(savedGame.playtimeMs) || 0));
  sessionStartedAt = performance.now();
  state.game.lastReward = savedGame.lastReward && typeof savedGame.lastReward === "object" ? savedGame.lastReward : null;
  state.game.recentLoot = Array.isArray(savedGame.recentLoot) ? savedGame.recentLoot.map(String).slice(0, 6) : [];
  state.game.lootToasts = [];
  state.game.dropPity = sanitizeDropPity(savedGame.dropPity);
  state.game.bossRespawns = sanitizeBossRespawns(savedGame.bossRespawns);
  state.game.bossKills = sanitizeBossKills(savedGame.bossKills);
  state.game.selectedTownNpcId = null;
  state.game.hoveredTownNpcId = null;

  state.game.progress.level = Math.max(1, Math.trunc(Number(savedGame.progress?.level) || PLAYER_TEMPLATE.level));
  state.game.progress.experience = Math.max(0, Math.trunc(Number(savedGame.progress?.experience) || 0));
  normalizeSavedProgress();
  state.game.progress.gold = state.inventory.gold;
}

function restoreMagicState(snapshot) {
  const learned = snapshot.magic?.learned ?? {};
  state.magic.learned = {};
  for (const [spellId, savedSpell] of Object.entries(learned)) {
    const spell = magicSpellById(spellId);
    if (!spell) continue;
    state.magic.learned[spellId] = {
      spellId,
      level: Math.max(0, Math.min(3, Math.trunc(Number(savedSpell.level) || 0))),
      experience: Math.max(0, Math.trunc(Number(savedSpell.experience) || 0)),
      key: savedSpell.key ?? null,
      autoCast: Boolean(savedSpell.autoCast),
      castReadyAt: 0,
      learnedAt: Number(savedSpell.learnedAt) || 0,
    };
  }
}

function restoreHotbarState(snapshot) {
  const availableEntryIds = new Set(state.inventory.items.map((entry) => entry.id));
  const equippedIds = new Set(Object.values(state.inventory.equipment).filter(Boolean));
  state.hotbar.slots = Array.from({ length: HOTBAR_SLOT_COUNT }, (_, slot) => {
    const entryId = snapshot.hotbar?.slots?.[slot] ?? null;
    return availableEntryIds.has(entryId) && !equippedIds.has(entryId) ? entryId : null;
  });
  ensureInventorySlots();
}

function restoreSettingsState(snapshot) {
  const savedSettings = snapshot.settings ?? {};
  const hasCurrentMusicSettings = Number(savedSettings.musicSettingsVersion) >= MUSIC_SETTINGS_VERSION;
  state.settings.musicEnabled = hasCurrentMusicSettings && Object.prototype.hasOwnProperty.call(savedSettings, "musicEnabled")
    ? savedSettings.musicEnabled === true
    : DEFAULT_MUSIC_ENABLED;
  state.settings.musicVolume = normalizedVolume(savedSettings.musicVolume ?? DEFAULT_MUSIC_VOLUME);
  state.settings.musicMode = normalizedMusicMode(savedSettings.musicMode);
  state.settings.sfxEnabled = Object.prototype.hasOwnProperty.call(savedSettings, "sfxEnabled")
    ? savedSettings.sfxEnabled === true
    : DEFAULT_SFX_ENABLED;
  state.settings.sfxVolume = normalizedVolume(savedSettings.sfxVolume ?? DEFAULT_SFX_VOLUME);
  state.settings.prototypeStatsEnabled = Object.prototype.hasOwnProperty.call(savedSettings, "prototypeStatsEnabled")
    ? savedSettings.prototypeStatsEnabled === true
    : DEFAULT_PROTOTYPE_STATS_ENABLED;
  state.settings.prototypeStatsNoticeVersion = Math.max(0, Math.trunc(Number(savedSettings.prototypeStatsNoticeVersion) || 0));
  state.settings.prototypeResetNoticeVersion = Math.max(0, Math.trunc(Number(savedSettings.prototypeResetNoticeVersion) || 0));
  state.settings.prototypeResetNoticeLastSeenAt = Math.max(0, Math.trunc(Number(savedSettings.prototypeResetNoticeLastSeenAt) || 0));
  const savedTrackIndex = BACKGROUND_MUSIC_TRACKS.findIndex((track) => track.id === savedSettings.musicTrackId);
  musicTrackIndex = savedTrackIndex >= 0 ? savedTrackIndex : 0;
}

function restoreEquipmentVisualIndexes(snapshot) {
  state.indexes.armour = 0;
  state.indexes.hair = Number.isInteger(snapshot.indexes?.hair) ? snapshot.indexes.hair : 0;
  state.indexes.weapon = null;
  applyEquippedVisualIndexes();
}

function restorePendingSavedPlayerResources() {
  if (!pendingSavedPlayerResources || !state.battle.player) return;
  if (pendingSavedPlayerResources.hp != null) {
    state.battle.player.hp = Math.max(0, Math.min(state.battle.player.maxHp, Math.trunc(pendingSavedPlayerResources.hp)));
  }
  if (pendingSavedPlayerResources.mp != null) {
    state.battle.player.mp = Math.max(0, Math.min(state.battle.player.maxMp, Math.trunc(pendingSavedPlayerResources.mp)));
  }
  state.battle.potHealthAmount = Math.max(0, Math.trunc(Number(pendingSavedPlayerResources.potHealthAmount) || 0));
  state.battle.potManaAmount = Math.max(0, Math.trunc(Number(pendingSavedPlayerResources.potManaAmount) || 0));
  state.battle.potTickAt = state.battle.potHealthAmount > 0 || state.battle.potManaAmount > 0
    ? performance.now() + CRYSTAL_POT_DELAY_MS
    : 0;
  state.battle.healAmount = Math.max(0, Math.trunc(Number(pendingSavedPlayerResources.healAmount) || 0));
  state.battle.healTickAt = state.battle.healAmount > 0
    ? performance.now() + CRYSTAL_HEAL_DELAY_MS
    : 0;
  pendingSavedPlayerResources = null;
}

function createPendingOfflineProgress(snapshot) {
  const savedAt = Number(snapshot?.savedAt) || 0;
  const elapsedMs = Date.now() - savedAt;
  const activeZoneId = snapshot?.game?.activeZoneId;
  const zoneExists = PROTOTYPE_ZONES.some((zone) => zone.id === activeZoneId);
  const savedHp = finiteNumberOrNull(snapshot?.battle?.playerHp);
  const wasRunning = snapshot?.battle?.running !== false;
  const wasPaused = snapshot?.battle?.paused === true;

  if (!savedAt || elapsedMs < OFFLINE_PROGRESS_MIN_MS) return null;

  const pending = {
    elapsedMs: Math.min(elapsedMs, OFFLINE_PROGRESS_CAP_MS),
    rawElapsedMs: elapsedMs,
    capped: elapsedMs > OFFLINE_PROGRESS_CAP_MS,
    savedAt,
  };
  const groupDungeonRun = sanitizeGroupDungeonOfflineRun?.(snapshot?.groupDungeonRun, activeZoneId, snapshot?.activeCharacterId ?? snapshot?.battle?.combatClass);
  if (groupDungeonRun?.zoneId === activeZoneId) pending.groupDungeonRun = groupDungeonRun;

  if (snapshot?.game?.mode === "mining" && activeZoneId === MINING_ZONE_ID && !wasPaused) {
    return { ...pending, kind: "mining" };
  }

  if (snapshot?.game?.mode !== "zone" || !zoneExists || !wasRunning || wasPaused) return null;
  if (savedHp != null && savedHp <= 0) return null;

  return { ...pending, kind: "zone" };
}

function applyPendingOfflineProgress() {
  const pending = pendingOfflineProgress;
  pendingOfflineProgress = null;
  if (!pending) return;
  if (pending.kind === "mining") applyOfflineMiningProgress(pending);
  else applyOfflineProgress(pending);
}

function applyOfflineProgress(pending) {
  const zone = activeZone();
  if (!pending || !zone || state.game.mode !== "zone" || !state.battle.running || !state.battle.player) return;
  if (state.paused) return;
  if (state.battle.player.hp <= 0) return;

  const groupDungeonMode = Boolean(pending.groupDungeonRun && groupDungeonZone(zone));
  if (groupDungeonMode) {
    // Offline simulation is not supported in group dungeons. The live save already
    // preserved the party's progress on the way out, so skip the (non-functional)
    // simulation and just tell the player instead of presenting an empty report.
    presentGroupDungeonOfflineNotice(pending);
    refreshOfflineProgressUi();
    return;
  }

  const bossPartyMode = bossPartyOfflineSimulationActive(zone);
  let report;
  suppressSimulationRender = true;
  try {
    report = bossPartyMode
      ? simulateBossPartyCatchUp(pending.elapsedMs, performance.now())
      : simulateOfflineProgress(zone, pending);
  } finally {
    suppressSimulationRender = false;
  }

  if (!report || report.elapsedMs < OFFLINE_PROGRESS_MIN_MS) return;
  rebaseOfflineTransientTimers(report.simulatedEndedAt, performance.now());
  if (bossPartyMode) finalizeOfflineBossPartyState(report);
  else finalizeOfflineBattleState(zone, report);
  presentOfflineReport(report);
  refreshOfflineProgressUi();
}

function applyOfflineMiningProgress(pending) {
  if (!pending || state.game.mode !== "mining" || state.paused) return;

  let report;
  suppressSimulationRender = true;
  try {
    report = simulateOfflineMining(pending);
  } finally {
    suppressSimulationRender = false;
  }

  if (!report || report.elapsedMs < OFFLINE_PROGRESS_MIN_MS) return;
  finalizeOfflineMiningState(report);
  presentOfflineMiningReport(report);
  refreshOfflineProgressUi();
}

function refreshOfflineProgressUi() {
  gamePanelSignature = "";
  battlePanelSignature = "";
  sceneSignature = "";
  playerHudSignature = "";
  hotbarSignature = "";
  saveGameState(true);
}

function simulateOfflineMining(pending) {
  const limitMs = Math.max(0, Math.trunc(Number(pending.elapsedMs) || 0));
  const report = {
    kind: "mining",
    elapsedMs: 0,
    capped: pending.capped,
    swings: 0,
    hits: 0,
    drops: new Map(),
    ignoredDrops: new Map(),
  };

  let simMs = 0;
  while (simMs + MINING_SWING_CYCLE_MS <= limitMs) {
    simMs += MINING_SWING_CYCLE_MS;
    report.swings += 1;
    if (Math.random() >= MINING_HIT_CHANCE) continue;
    report.hits += 1;
    addOfflineMiningOre(
      report,
      rollMiningOreItemId(),
      rollMiningOrePurity(),
    );
  }

  report.elapsedMs = simMs;
  return report;
}

function offlineMiningOreLabel(itemId, purity) {
  const item = itemDefinition(itemId);
  if (!item) return itemId;
  const purityLabel = purity > 0 ? ` P${purity}` : "";
  return `${item.name}${purityLabel}`;
}

function addOfflineMiningOre(report, itemId, purity) {
  syncInventoryCapacity();
  ensureInventorySlots();
  const label = offlineMiningOreLabel(itemId, purity);
  if (inventoryUsedSlots() >= state.inventory.maxSlots) {
    incrementReportCount(report.ignoredDrops, label);
    return false;
  }
  state.inventory.items.push(createOreInventoryEntry(itemId, purity));
  syncBossPartyControlledInventoryFromState();
  incrementReportCount(report.drops, label);
  return true;
}

function finalizeOfflineMiningState(report) {
  const now = performance.now();
  ensureMiningSpotId(false);
  state.showEnemies = true;
  state.battle.running = false;
  state.battle.returnToStandAt = 0;
  state.battle.enemy = null;
  state.battle.phase = "idle";
  state.battle.cameraX = state.battle.playerX - playerScreenX();
  setPlayerAction("mine", now, true);
  const spot = activeMiningSpot();
  if (spot?.label) {
    pushBattleLog(`Resumed mining at ${spot.label}.`);
  }
}

function presentOfflineMiningReport(report) {
  const duration = formatDuration(report.elapsedMs);
  const dropsText = reportCountText(report.drops, 5);
  const ignoredText = reportCountText(report.ignoredDrops, 3);
  const lines = [
    `Offline mining ${duration}: ${report.swings} swings, ${report.hits} ore finds`,
  ];
  if (dropsText) lines.push(`Found ${dropsText}`);
  if (ignoredText) lines.push(`No room for ${ignoredText}`);
  if (report.capped) lines.push("Offline cap reached: 8h");

  state.game.offlineReport = {
    kind: "mining",
    duration,
    swings: report.swings,
    hits: report.hits,
    drops: [...report.drops.entries()],
    ignoredDrops: [...report.ignoredDrops.entries()],
    capped: report.capped,
  };
  state.game.recentLoot = [...lines, ...state.game.recentLoot].slice(0, 6);
  for (const line of [...lines].reverse()) pushBattleLog(line);
  addLootNotice(`Offline: ${report.hits} ore`, "item");
  renderOfflineReport();
}

function simulateOfflineTrainingRoomProgress(zone, report, startedAt, limitMs) {
  const template = trainingRoomEnemyTemplate(zone);
  const enemy = {
    ...template,
    hp: template.maxHp,
    mp: template.maxMp,
    poisons: [],
    debuffs: { slowUntil: 0, frozenUntil: 0 },
  };
  state.battle.enemy = enemy;
  state.battle.enemyId = enemy.id;
  state.battle.phase = "engaged";
  state.battle.enemyAggro = true;
  state.battle.playerX = 0;
  state.battle.enemyX = playerAttackRange();
  dismissTaoistPet();

  let elapsedMs = 0;
  let nextCastAt = Math.max(0, (state.battle.trainingRoomNextCastAt ?? 0) - startedAt);
  offlineUpdateRecovery(startedAt, report);

  while (elapsedMs < limitMs && (state.battle.player?.hp ?? 0) > 0) {
    if (elapsedMs < nextCastAt) {
      const jump = Math.min(nextCastAt - elapsedMs, limitMs - elapsedMs);
      elapsedMs += jump;
      offlineUpdateRecovery(startedAt + elapsedMs, report);
      if (elapsedMs >= limitMs) break;
    }

    const now = startedAt + elapsedMs;
    const cast = tryTrainingRoomAutocastCycle(now);
    if (cast) {
      const gap = trainingRoomCastGapMs(cast.spell, cast.learned);
      nextCastAt = elapsedMs + gap;
      state.battle.trainingRoomNextCastAt = startedAt + nextCastAt;
      state.battle.nextPlayerAttackAt = state.battle.trainingRoomNextCastAt;
      state.battle.lastPlayerAttackCooldownMs = gap;
    } else {
      nextCastAt = elapsedMs + CRYSTAL_SPELL_GLOBAL_LOCK_MS;
      state.battle.trainingRoomNextCastAt = startedAt + nextCastAt;
    }
    offlineUpdateRecovery(now, report);
  }

  report.elapsedMs = Math.min(elapsedMs, limitMs);
  report.simulatedEndedAt = startedAt + report.elapsedMs;
  report.finalEnemy = enemy;
  state.battle.level = state.game.progress.level;
  state.battle.experience = state.game.progress.experience;
  state.battle.gold = state.inventory.gold;
  clearTransientCombatBuffs();
  return report;
}

function simulateOfflineProgress(zone, pending) {
  const report = {
    elapsedMs: 0,
    capped: pending.capped,
    kills: 0,
    xp: 0,
    gold: 0,
    levels: [],
    drops: new Map(),
    ignoredDrops: new Map(),
    potionsUsed: new Map(),
    damageTaken: 0,
    diedAtMs: 0,
    finalEnemy: null,
  };
  const startedAt = performance.now();
  report.simulatedStartedAt = startedAt;
  const limitMs = Math.max(0, Math.trunc(Number(pending.elapsedMs) || 0));

  if (isTrainingRoomZone(zone)) {
    return simulateOfflineTrainingRoomProgress(zone, report, startedAt, limitMs);
  }

  state.battle.phase = "engaged";
  state.battle.enemyAggro = true;
  state.battle.playerX = 0;
  state.battle.enemyX = playerAttackRange();

  while (report.elapsedMs < limitMs && (state.battle.player?.hp ?? 0) > 0) {
    const template = randomZoneEnemyTemplate(zone);
    const result = simulateOfflineFight(template, startedAt + report.elapsedMs, limitMs - report.elapsedMs, report);
    report.elapsedMs += result.elapsedMs;
    report.finalEnemy = result.enemy;

    if (result.playerDied) {
      report.diedAtMs = report.elapsedMs;
      break;
    }
    if (!result.killed) break;

    report.finalEnemy = null;
    dismissTaoistPet();
    awardOfflineEnemyRewards(zone, template, report);
    state.game.distance += enemySpawnDistance();

    const respawnMs = Math.min(LANE.respawnDelayMs, Math.max(0, limitMs - report.elapsedMs));
    report.elapsedMs += respawnMs;
    offlineUpdateRecovery(startedAt + report.elapsedMs, report);
  }

  report.elapsedMs = Math.min(report.elapsedMs, limitMs);
  report.simulatedEndedAt = startedAt + report.elapsedMs;
  state.battle.level = state.game.progress.level;
  state.battle.experience = state.game.progress.experience;
  state.battle.gold = state.inventory.gold;
  return report;
}

function rebaseOfflineTransientTimers(simulatedNow, actualNow = performance.now()) {
  if (!Number.isFinite(simulatedNow) || simulatedNow <= 0) return;

  for (const [spellId, learned] of Object.entries(state.magic.learned ?? {})) {
    const spell = magicSpellById(spellId);
    if (!spell || !learned) continue;
    learned.castReadyAt = rebaseTransientTimestamp(
      learned.castReadyAt,
      simulatedNow,
      actualNow,
      wizardCastCooldownMs(spell, learned),
    );
  }

  state.battle.wizardSpellLockUntil = rebaseTransientTimestamp(
    state.battle.wizardSpellLockUntil,
    simulatedNow,
    actualNow,
    CRYSTAL_SPELL_GLOBAL_LOCK_MS,
  );

  state.battle.trainingRoomNextCastAt = rebaseTransientTimestamp(
    state.battle.trainingRoomNextCastAt,
    simulatedNow,
    actualNow,
    CRYSTAL_SPELL_GLOBAL_LOCK_MS,
  );

  state.battle.furyUntil = rebaseTransientTimestamp(state.battle.furyUntil, simulatedNow, actualNow, 120000);
  state.battle.potTickAt = rebaseTransientTimestamp(state.battle.potTickAt, simulatedNow, actualNow, CRYSTAL_POT_DELAY_MS);
  state.battle.healTickAt = rebaseTransientTimestamp(state.battle.healTickAt, simulatedNow, actualNow, CRYSTAL_HEAL_DELAY_MS);
  if (state.battle.pendingHeal) {
    state.battle.pendingHeal.at = rebaseTransientTimestamp(
      state.battle.pendingHeal.at,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_APPLY_DELAY_MS,
    );
  }
  if (state.battle.pendingPoison) {
    state.battle.pendingPoison.at = rebaseTransientTimestamp(
      state.battle.pendingPoison.at,
      simulatedNow,
      actualNow,
      CRYSTAL_POISON_APPLY_DELAY_MS,
    );
  }
  if (state.battle.pendingEnemyStrike) {
    const strikeSpan = Math.max(
      EVIL_CENTIPEDE_ATTACK_IMPACT_MS,
      Number(state.battle.pendingEnemyStrike.moveDurationMs) || BONE_LORD_ATTACK_IMPACT_MS,
    );
    state.battle.pendingEnemyStrike.at = rebaseTransientTimestamp(
      state.battle.pendingEnemyStrike.at,
      simulatedNow,
      actualNow,
      strikeSpan,
    );
    if (state.battle.pendingEnemyStrike.startedAt != null) {
      state.battle.pendingEnemyStrike.startedAt = rebaseTransientTimestamp(
        state.battle.pendingEnemyStrike.startedAt,
        simulatedNow,
        actualNow,
        strikeSpan,
      );
    }
  }
  if (state.battle.pendingTaoPet) {
    state.battle.pendingTaoPet.at = rebaseTransientTimestamp(
      state.battle.pendingTaoPet.at,
      simulatedNow,
      actualNow,
      CRYSTAL_SUMMON_SKELETON_DELAY_MS,
    );
  }
  if (state.battle.pendingPetAttack) {
    state.battle.pendingPetAttack.at = rebaseTransientTimestamp(
      state.battle.pendingPetAttack.at,
      simulatedNow,
      actualNow,
      taoistShinsuAttackImpactMs(),
    );
  }
  if (state.battle.pendingDefenceBuff) {
    state.battle.pendingDefenceBuff.at = rebaseTransientTimestamp(
      state.battle.pendingDefenceBuff.at,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_APPLY_DELAY_MS,
    );
  }
  if (state.battle.pendingUltimateEnhancer) {
    state.battle.pendingUltimateEnhancer.at = rebaseTransientTimestamp(
      state.battle.pendingUltimateEnhancer.at,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_APPLY_DELAY_MS,
    );
  }
  if (state.battle.taoPet?.active) {
    state.battle.taoPet.nextAttackAt = rebaseTransientTimestamp(
      state.battle.taoPet.nextAttackAt,
      simulatedNow,
      actualNow,
      state.battle.taoPet.attackMs,
    );
    state.battle.taoPet.healTickAt = rebaseTransientTimestamp(
      state.battle.taoPet.healTickAt,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_DELAY_MS,
    );
  }
  state.battle.autoPotionReadyAt = {
    hp: rebaseTransientTimestamp(state.battle.autoPotionReadyAt?.hp, simulatedNow, actualNow, AUTO_POTION_COOLDOWN_MS),
    mp: rebaseTransientTimestamp(state.battle.autoPotionReadyAt?.mp, simulatedNow, actualNow, AUTO_POTION_COOLDOWN_MS),
  };
  state.battle.statBuffs = (state.battle.statBuffs ?? []).map((buff) => ({
    ...buff,
    expiresAt: rebaseTransientTimestamp(
      buff.expiresAt,
      simulatedNow,
      actualNow,
      maxStatBuffRemainingMs(buff),
    ),
  })).filter((buff) => buff.expiresAt > actualNow);
  state.battle.petStatBuffs = (state.battle.petStatBuffs ?? []).map((buff) => ({
    ...buff,
    expiresAt: rebaseTransientTimestamp(
      buff.expiresAt,
      simulatedNow,
      actualNow,
      maxStatBuffRemainingMs(buff),
    ),
  })).filter((buff) => buff.expiresAt > actualNow);
}

function maxStatBuffRemainingMs(buff) {
  if (buff?.kind === "magicShield" || buff?.stat === "damageReduction") return 30 * 60 * 1000;
  if (buff?.stat === "ac" || buff?.stat === "amc") return 30 * 60 * 1000;
  if (buff?.kind === "ultimateEnhancer") return 30 * 60 * 1000;
  return BUFF_POTION_DURATION_MS;
}

function rebaseTransientTimestamp(value, simulatedNow, actualNow, maxRemainingMs = Infinity) {
  const timestamp = Number(value) || 0;
  if (timestamp <= simulatedNow) return 0;
  const remaining = timestamp - simulatedNow;
  const cappedRemaining = Number.isFinite(maxRemainingMs)
    ? Math.min(remaining, Math.max(0, maxRemainingMs))
    : remaining;
  return cappedRemaining > 0 ? actualNow + cappedRemaining : 0;
}

function simulateOfflineFight(template, startedAt, remainingMs, report) {
  const enemy = { ...template, hp: template.maxHp, mp: template.maxMp, poisons: [], debuffs: { slowUntil: 0, frozenUntil: 0 } };
  let elapsedMs = 0;
  const travelMs = Math.min(offlineTravelTimeMs(), remainingMs);
  elapsedMs += travelMs;
  state.battle.enemy = enemy;
  state.battle.enemyId = enemy.id;
  state.battle.phase = "engaged";
  state.battle.enemyAggro = true;
  state.battle.playerX = 0;
  state.battle.enemyX = playerAttackRange();
  dismissTaoistPet();
  offlineUpdateRecovery(startedAt + elapsedMs, report);

  if ((state.battle.player?.hp ?? 0) <= 0) return { elapsedMs, killed: false, playerDied: true, enemy };
  if (elapsedMs >= remainingMs) return { elapsedMs, killed: false, playerDied: false, enemy };

  let nextPlayerAttack = 0;
  let nextEnemyAttack = Math.max(1, Math.trunc(Number(enemy.attackMs) || 2500));
  let guard = 0;

  while (elapsedMs < remainingMs && enemy.hp > 0 && (state.battle.player?.hp ?? 0) > 0 && guard < 5000) {
    guard += 1;
    const pet = state.battle.taoPet?.active ? state.battle.taoPet : null;
    const nextPetAttack = offlinePetAttackDelayMs(pet, startedAt + elapsedMs);
    const delta = Math.min(nextPlayerAttack, nextEnemyAttack, nextPetAttack);
    if (elapsedMs + delta > remainingMs) {
      elapsedMs = remainingMs;
      offlineUpdateRecovery(startedAt + elapsedMs, report);
      return { elapsedMs, killed: false, playerDied: false, enemy };
    }

    elapsedMs += delta;
    nextPlayerAttack -= delta;
    nextEnemyAttack -= delta;
    const now = startedAt + elapsedMs;
    offlineUpdateRecovery(now, report);
    if ((state.battle.player?.hp ?? 0) <= 0) break;

    if (nextPlayerAttack <= 0) {
      if (offlinePlayerAttack(enemy, now)) {
        nextPlayerAttack += consumeLastPlayerAttackCooldown(now);
      }
    }
    if (enemy.hp <= 0) break;

    if (state.battle.taoPet?.active && (state.battle.taoPet.nextAttackAt ?? 0) <= now) {
      updateTaoistPetAttack(now, { offline: true });
    }
    if (enemy.hp <= 0) break;

    if (nextEnemyAttack <= 0 && !enemyFrozenActive(enemy, now)) {
      offlineEnemyAttack(enemy, now, report);
      nextEnemyAttack += effectiveEnemyAttackMs(enemy, now);
      offlineUpdateRecovery(now, report);
    }
  }

  return {
    elapsedMs,
    killed: enemy.hp <= 0,
    playerDied: (state.battle.player?.hp ?? 0) <= 0,
    enemy,
  };
}

function offlineTravelTimeMs() {
  const distance = Math.max(0, enemySpawnDistance() - playerAttackRange());
  const walkDistance = Math.min(distance, TRAVEL_WALK_DISTANCE);
  const runDistance = Math.max(0, distance - walkDistance);
  return Math.round((walkDistance / Math.max(1, LANE.playerSpeed) + runDistance / Math.max(1, LANE.runSpeed)) * 1000);
}

function offlinePetAttackDelayMs(pet, simNow) {
  if (!pet?.active) return Infinity;
  const readyIn = Math.max(0, (pet.nextAttackAt ?? 0) - simNow);
  if (readyIn > 0) return readyIn;
  if (state.battle.pendingPetAttack) return 1;
  if (pet.spellId === "SummonShinsu" && !pet.shinsuVisible && pet.action === "show") return 1;
  if (taoistPetEnemyDistance() > taoistPetAttackRangePx(pet)) return Infinity;
  return 0;
}

function offlineUpdateRecovery(now, report) {
  updatePendingHeal(now);
  updatePendingDefenceBuff(now, { offline: true });
  updatePendingUltimateEnhancer(now, { offline: true });
  updatePendingPoison(now, { offline: true });
  updatePendingPetAttack(now, { offline: true });
  updatePendingTaoPet(now);
  updateHealingRegen(now);
  updateEnemyPoisons(now, { offline: true });
  updatePotionRegen(now);
  offlineAutoUsePotions(now, report);
  updatePendingHeal(now);
  updatePendingDefenceBuff(now, { offline: true });
  updatePendingUltimateEnhancer(now, { offline: true });
  updatePendingPoison(now, { offline: true });
  updatePendingTwinDrakeHits(now);
  updateAttachedSpellFx(now);
  updatePendingPetAttack(now, { offline: true });
  updatePendingTaoPet(now);
  updateHealingRegen(now);
  updateEnemyPoisons(now, { offline: true });
  updatePotionRegen(now);
}

function offlineAutoUsePotions(now, report) {
  const resources = ["hp", "mp"].sort((a, b) => resourceRatio(a) - resourceRatio(b));
  for (const kind of resources) {
    if (!shouldAutoUsePotion(kind, now)) continue;
    const candidate = autoPotionCandidates(kind)[0];
    if (!candidate) continue;
    const hpRestore = potionRestoreAmount(candidate.item, "hp");
    const mpRestore = potionRestoreAmount(candidate.item, "mp");
    if (!removeInventoryEntry(candidate.entry.id, 1)) continue;
    queuePotionRestore(hpRestore, mpRestore, now);
    state.battle.autoPotionReadyAt[kind] = now + AUTO_POTION_COOLDOWN_MS;
    incrementReportCount(report.potionsUsed, candidate.item.name);
  }
}

function offlinePlayerAttack(enemy, now) {
  state.battle.enemy = enemy;
  state.battle.enemyId = enemy.id;
  state.battle.enemyX = state.battle.playerX + playerAttackRange();

  if (state.battle.combatClass === "Wizard") {
    offlineWizardAttack(enemy, now);
    return true;
  }
  if (state.battle.combatClass === "Taoist") {
    offlineTaoistAttack(enemy, now);
    return true;
  }
  return offlineWarriorAttack(enemy, now);
}

function offlineWarriorAttack(enemy, now) {
  const battle = state.battle;
  const { skill, learned, cost, charged } = usableWarriorAttackSkill(now);

  if (skill.buff) {
    castWarriorBuff(skill, learned, cost, now);
    battle.lastPlayerAttackCooldownMs = CRYSTAL_PLAYER_ACTION_LOCK_MS;
    return true;
  }

  if (learned) commitWarriorSpellUse(skill, learned, cost, now);
  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, skill);
  if (!rollHit(battle.player.accuracy, enemy.agility)) {
    rollSlayingChargeAfterAttack(now);
    if (!warriorSlayingPending()) maybeAutoWarriorCharge(now);
    return true;
  }

  const damage = learned
    ? rollWarriorMagicDamage(skill, learned, battle.player, enemy)
    : rollDamage(battle.player.dc, enemyPhysicalDefence(enemy), battle.player.luck);
  const scaled = scaleEnemyPhysicalDamage(damage, enemy, now);
  if (scaled <= 0) {
    rollSlayingChargeAfterAttack(now);
    if (!warriorSlayingPending()) maybeAutoWarriorCharge(now);
    return true;
  }
  reduceEnemyHp(enemy, scaled);
  if (learned) levelWarriorMagic(skill, learned, now);
  levelPassiveWeaponMagic(now);
  rollSlayingChargeAfterAttack(now);
  if (skill.id === "TwinDrakeBlade" && charged && enemy.hp > 0) {
    queueTwinDrakeSecondHit({ classId: battle.combatClass }, learned, damage, now);
  }
  if (!warriorSlayingPending()) maybeAutoWarriorCharge(now);
  return true;
}

function offlineMagicAttack(enemy, now, statKey, multiplier = 1) {
  const player = state.battle.player;
  if (!rollMagicHit(enemy)) return;
  const damage = Math.max(0, Math.round(rollDamage(player[statKey] ?? player.dc, enemyMagicalDefence(enemy), player.luck) * multiplier));
  if (damage <= 0) return;
  reduceEnemyHp(enemy, damage);
}

function offlineWizardAttack(enemy, now) {
  const battle = state.battle;
  const magicShield = usableWizardDefenceBuff(now);
  if (magicShield) {
    castWizardDefenceBuff(magicShield, now, { offline: true });
    return;
  }
  const queued = queuedCombatSpell("Wizard");
  if (queued?.spell.id === "MagicShield") {
    const manualShield = usableWizardDefenceBuff(now, { requireAuto: false });
    if (manualShield) {
      castWizardDefenceBuff(manualShield, now, { offline: true });
      return;
    }
  }
  const attackSpell = usableWizardAttackSpell(now);
  if (!attackSpell) {
    offlineWizardWeaponAttack(enemy, now);
    return;
  }
  const { spell, learned, cost, cooldownWaiting } = attackSpell;
  if (cooldownWaiting) {
    offlineWizardWeaponAttack(enemy, now);
    return;
  }
  if ((battle.player?.mp ?? 0) < cost) {
    offlineWizardWeaponAttack(enemy, now);
    return;
  }

  battle.lastPlayerAttackCooldownMs = wizardCastCooldownMs(spell, learned);
  commitWizardSpellUse(spell, learned, cost, now);
  if (!rollMagicHit(enemy)) return;
  const damage = rollWizardMagicDamage(spell, learned, battle.player, enemy);
  if (damage <= 0) return;
  reduceEnemyHp(enemy, damage);
  if (spell.id === "FrostCrunch") applyFrostCrunchEffects(enemy, learned, battle.player, now);
  if (learned) levelMagicSkill(spell, learned, now);
}

function offlineWizardWeaponAttack(enemy, now) {
  const battle = state.battle;
  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, BASIC_ATTACK_SKILL);
  if (!rollHit(battle.player.accuracy, enemy.agility)) return;
  const damage = rollDamage(battle.player.dc, enemyPhysicalDefence(enemy), battle.player.luck);
  if (damage <= 0) return;
  reduceEnemyHp(enemy, damage);
}

function offlineTaoistAttack(enemy, now) {
  const battle = state.battle;
  const queuedRequest = queuedCombatSpell("Taoist");
  const queued = usableQueuedTaoistSpell(now);
  if (queued) {
    if (queued.spell.id === "SoulFireBall") return offlineTaoistSoulFireBall(enemy, now, queued);
    if (queued.spell.id === "Healing") return castTaoistHealing(queued, now, { offline: true });
    if (queued.spell.id === "Poisoning") return castTaoistPoisoning(queued, now, { offline: true });
    if (queued.spell.id === "SummonSkeleton" || queued.spell.id === "SummonShinsu") {
      castTaoistSummonPet(queued, now, { offline: true });
      const delayMs = queued.spell.id === "SummonShinsu"
        ? CRYSTAL_SUMMON_SHINSU_DELAY_MS
        : CRYSTAL_SUMMON_SKELETON_DELAY_MS;
      updatePendingTaoPet(now + delayMs);
      battle.lastPlayerAttackCooldownMs = spellDelayMs(queued.spell, queued.learned);
      return;
    }
    if (queued.spell.id === "SoulShield" || queued.spell.id === "BlessedArmour") {
      castTaoistDefenceBuff(queued, now, { offline: true });
      return;
    }
    if (queued.spell.id === "UltimateEnhancer") {
      castTaoistUltimateEnhancer(queued, now, { offline: true });
      return;
    }
  }
  if (queuedRequest) return offlineTaoistWeaponAttack(enemy, now);

  const summon = usableTaoistSummonSkeleton(now);
  if (summon) {
    castTaoistSummonPet(summon, now, { offline: true });
    updatePendingTaoPet(now + CRYSTAL_SUMMON_SKELETON_DELAY_MS);
    battle.lastPlayerAttackCooldownMs = spellDelayMs(summon.spell, summon.learned);
    return;
  }

  const shinsu = usableTaoistSummonShinsu(now);
  if (shinsu) {
    castTaoistSummonPet(shinsu, now, { offline: true });
    updatePendingTaoPet(now + CRYSTAL_SUMMON_SHINSU_DELAY_MS);
    battle.lastPlayerAttackCooldownMs = spellDelayMs(shinsu.spell, shinsu.learned);
    return;
  }

  if (taoistPetCanTank()) {
    if (!taoistPetSupportAttackOffline(now)) battle.lastPlayerAttackCooldownMs = TAOIST_COMBAT_POLL_MS;
    return;
  }
  if (enemy.hp <= 0) return;

  const soulFireBall = usableTaoistSoulFireBall(now);
  if (soulFireBall) offlineTaoistSoulFireBall(enemy, now, soulFireBall, { secondary: true });
  if (enemy.hp <= 0) return;

  const healing = usableTaoistHealing(now);
  if (healing) {
    castTaoistHealing(healing, now, { offline: true });
    return;
  }

  for (const spellId of ["SoulShield", "BlessedArmour"]) {
    const defenceBuff = usableTaoistDefenceBuff(spellId, now);
    if (defenceBuff) {
      castTaoistDefenceBuff(defenceBuff, now, { offline: true });
      return;
    }
  }

  const ultimateEnhancer = usableTaoistUltimateEnhancer(now);
  if (ultimateEnhancer) {
    castTaoistUltimateEnhancer(ultimateEnhancer, now, { offline: true });
    return;
  }

  const poisoning = usableTaoistPoisoning(now);
  if (poisoning) {
    castTaoistPoisoning(poisoning, now, { offline: true });
    return;
  }
  offlineTaoistWeaponAttack(enemy, now);
}

function taoistPetSupportAttackOffline(now) {
  const healing = usableTaoistHealing(now);
  if (healing) return castTaoistHealing(healing, now, { offline: true });

  for (const spellId of ["SoulShield", "BlessedArmour"]) {
    const defenceBuff = usableTaoistDefenceBuff(spellId, now);
    if (defenceBuff) return castTaoistDefenceBuff(defenceBuff, now, { offline: true });
  }

  const ultimateEnhancer = usableTaoistUltimateEnhancer(now);
  if (ultimateEnhancer) return castTaoistUltimateEnhancer(ultimateEnhancer, now, { offline: true });

  const poisoning = usableTaoistPoisoning(now);
  if (poisoning) return castTaoistPoisoning(poisoning, now, { offline: true });

  const soulFireBall = usableTaoistSoulFireBall(now);
  if (soulFireBall) return offlineTaoistSoulFireBall(state.battle.enemy, now, soulFireBall);

  return false;
}

function offlineTaoistSoulFireBall(enemy, now, soulFireBall, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost, entry } = soulFireBall;
  if (!consumeOneInventoryUnit(entry.id)) return false;
  if (!options.secondary) battle.lastPlayerAttackCooldownMs = spellDelayMs(spell, learned);
  commitTaoistSpellUse(spell, learned, cost, now);
  if (!rollMagicHit(enemy)) return true;
  const damage = rollTaoistMagicDamage(spell, learned, battle.player, enemy);
  if (damage <= 0) return true;
  reduceEnemyHp(enemy, damage);
  if (learned) levelMagicSkill(spell, learned, now);
  return true;
}

function offlineTaoistWeaponAttack(enemy, now) {
  const battle = state.battle;
  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, BASIC_ATTACK_SKILL);
  if (!rollHit(battle.player.accuracy, enemy.agility)) return;
  const damage = rollDamage(battle.player.dc, enemyPhysicalDefence(enemy), battle.player.luck);
  if (damage <= 0) return;
  reduceEnemyHp(enemy, damage);
  levelPassiveWeaponMagic(now);
}

function offlineEnemyAttack(enemy, now, report) {
  if (isTrainingDummyEnemy(enemy)) return;
  state.battle.enemy = enemy;
  const player = state.battle.player;
  if (!player || player.hp <= 0) return;
  if (taoistPetCanTank()) {
    const pet = state.battle.taoPet;
    const { hit, damage } = resolveIncomingEnemyAttack(enemy, defenceTargetForIncomingAttack(pet));
    if (!hit) return;
    pet.hp = Math.max(0, pet.hp - damage);
    if (pet.hp <= 0) markTaoistPetDead(now, { sound: false });
    return;
  }
  const { hit, damage } = resolveIncomingEnemyAttack(enemy, defenceTargetForIncomingAttack(player));
  if (!hit) return;
  player.hp = Math.max(0, player.hp - damage);
  report.damageTaken += damage;
  if (player.hp <= 0) {
    state.battle.running = false;
    state.battle.phase = "idle";
  }
}

function awardOfflineEnemyRewards(zone, enemy, report) {
  const reward = zone?.rewards ?? { gold: [1, 2] };
  const xp = adjustedKillExperience(enemy?.experience ?? 0, state.game.progress.level, enemy?.level ?? 0);
  const gold = randomInt(reward.gold[0], reward.gold[1]);
  const drops = isRedThunderZumaEnemy(enemy)
    ? rollRedThunderZumaDrops()
    : rollZoneDrops(zone, enemy);
  const leveledTo = applyExperienceReward(xp);
  if (leveledTo.length) {
    applyEquippedStatsToBattlePlayer();
    restoreBattlePlayerResources();
  }

  state.inventory.gold += gold;
  state.game.progress.gold = state.inventory.gold;
  state.game.kills += 1;
  state.game.zoneKills += 1;
  state.game.lastReward = { xp, gold, drops: drops.added };
  state.battle.experience = state.game.progress.experience;
  state.battle.gold = state.game.progress.gold;
  state.battle.level = state.game.progress.level;

  report.kills += 1;
  report.xp += xp;
  report.gold += gold;
  report.levels.push(...leveledTo);
  for (const item of drops.added) incrementReportCount(report.drops, item.name);
  for (const item of drops.ignored) incrementReportCount(report.ignoredDrops, item.name);
}

function finalizeOfflineBattleState(zone, report) {
  const now = performance.now();
  const player = state.battle.player;
  if (!player) return;

  state.showEnemies = true;
  state.battle.running = player.hp > 0;
  state.battle.returnToStandAt = 0;
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.activeSkill = "None";
  state.battle.activeSkillAtlas = null;
  state.battle.activeWizardSpell = null;
  state.battle.activeWizardSpellAtlas = null;
  state.battle.activeTaoSpell = null;
  state.battle.activeTaoSpellAtlas = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;

  if (player.hp <= 0 || report.diedAtMs) {
    dismissTaoistPet();
    player.hp = 0;
    state.battle.phase = "idle";
    state.battle.nextPlayerAttackAt = 0;
    state.battle.nextEnemyAttackAt = 0;
    setPlayerAction("die", now);
    return;
  }

  const enemy = report.finalEnemy?.hp > 0
    ? report.finalEnemy
    : { ...randomZoneEnemyTemplate(zone), hp: undefined, mp: undefined };
  if (!(report.finalEnemy?.hp > 0)) dismissTaoistPet();
  enemy.hp = enemy.hp ?? enemy.maxHp;
  enemy.mp = enemy.mp ?? enemy.maxMp;
  enemy.poisons = Array.isArray(enemy.poisons) ? enemy.poisons : [];
  state.battle.enemy = enemy;
  state.battle.enemyId = enemy.id;
  state.battle.enemyAggro = Boolean(report.finalEnemy?.hp > 0);
  state.battle.phase = report.finalEnemy?.hp > 0 ? "engaged" : "advance";
  state.battle.playerX = 0;
  state.battle.enemyX = report.finalEnemy?.hp > 0 ? playerAttackRange() : enemySpawnDistance();
  if (report.finalEnemy?.hp > 0 && state.battle.taoPet?.active) {
    if (enemyUsesFixedArenaSpawn()) {
      placeTaoistCombatPet(state.battle.taoPet);
    } else {
      state.battle.enemyX = Math.max(LANE.aggroRange, state.battle.enemyX);
      state.battle.taoPet.worldX = taoistPetSummonWorldX();
    }
  }
  state.battle.cameraX = state.battle.playerX - playerScreenX();
  state.battle.travelStartedAt = now;
  state.battle.travelStartedX = state.battle.playerX;
  state.battle.nextPlayerAttackAt = report.finalEnemy?.hp > 0 ? now + playerAttackDelayMs(now) : 0;
  state.battle.nextEnemyAttackAt = report.finalEnemy?.hp > 0 ? now + Math.max(1, Number(enemy.attackMs) || 2500) : 0;
  state.enemy.index = enemy.monsterIndex;
  state.enemy.action = "standing";
  state.enemy.frame = 0;
  state.enemy.oneShot = false;
  state.enemy.lastTick = now;
  setPlayerAction(report.finalEnemy?.hp > 0 ? "stance" : "walking", now);
}

function presentOfflineReport(report) {
  const duration = formatDuration(report.elapsedMs);
  const dropsText = reportCountText(report.drops, 3);
  const ignoredText = reportCountText(report.ignoredDrops, 2);
  const potionText = reportCountText(report.potionsUsed, 2);
  const isBossParty = report.kind === "bossParty";
  const lines = isBossParty
    ? [
      `Offline party ${duration}: ${report.kills} kills`,
      `+${report.xp} XP, +${report.gold} gold`,
    ]
    : [
      `Offline ${duration}: ${report.kills} kills`,
      `+${report.xp} XP, +${report.gold} gold`,
    ];
  if (report.wavesCleared > 0) lines.push(`Waves cleared: ${report.wavesCleared}`);
  if (report.levels.length) lines.push(`Level ${report.levels.at(-1)}`);
  if (dropsText) lines.push(`Found ${dropsText}`);
  if (ignoredText) lines.push(`No room for ${ignoredText}`);
  if (potionText) lines.push(`Used ${potionText}`);
  if (report.diedAtMs) lines.push(`Defeated after ${formatDuration(report.diedAtMs)}`);
  if (report.capped) lines.push("Offline cap reached: 8h");

  state.game.offlineReport = {
    kind: isBossParty ? "bossParty" : "zone",
    duration,
    kills: report.kills,
    xp: report.xp,
    gold: report.gold,
    level: report.levels.at(-1) ?? null,
    drops: [...report.drops.entries()],
    ignoredDrops: [...report.ignoredDrops.entries()],
    potionsUsed: [...report.potionsUsed.entries()],
    defeatedAfter: report.diedAtMs ? formatDuration(report.diedAtMs) : "",
    capped: report.capped,
  };
  state.game.recentLoot = [...lines, ...state.game.recentLoot].slice(0, 6);
  for (const line of [...lines].reverse()) pushBattleLog(line);
  addLootNotice(report.diedAtMs ? "Offline: defeated" : `Offline: ${report.kills} kills`, report.diedAtMs ? "full" : "item");
  renderOfflineReport();
}

function presentGroupDungeonOfflineNotice(pending) {
  const awayMs = Math.max(0, Math.trunc(Number(pending?.rawElapsedMs ?? pending?.elapsedMs) || 0));
  const duration = formatDuration(awayMs);
  const message = "Offline simulation does not work in group dungeons, but your progress was saved.";
  state.game.offlineReport = {
    kind: "groupDungeon",
    duration,
    message,
  };
  pushBattleLog(message);
  addLootNotice("Group dungeon: progress saved", "item");
  renderOfflineReport();
}

function renderOfflineReport() {
  const report = state.game.offlineReport;
  if (!els.offlineReport) return;
  if (!report) {
    els.offlineReport.hidden = true;
    els.offlineReport.innerHTML = "";
    return;
  }

  if (report.kind === "groupDungeon") {
    els.offlineReport.hidden = false;
    els.offlineReport.innerHTML = `
      <div class="offline-report-window" role="dialog" aria-modal="true" aria-labelledby="offlineReportTitle">
        <header>
          <div>
            <p class="eyebrow">Offline Progress</p>
            <h2 id="offlineReportTitle">While You Were Away</h2>
          </div>
          <button type="button" data-close-offline-report aria-label="Close offline report">X</button>
        </header>
        <p class="offline-report-message">${escapeHtml(report.message)}</p>
        ${report.duration ? `<dl><dt>Away</dt><dd>${escapeHtml(String(report.duration))}</dd></dl>` : ""}
        <button type="button" class="primary" data-close-offline-report>Continue</button>
      </div>
    `;
    return;
  }

  const rows = [["Away", report.duration]];
  if (report.kind === "mining") {
    rows.push(["Swings", report.swings ?? 0]);
    rows.push(["Ore finds", report.hits ?? 0]);
    if (report.drops?.length) rows.push(["Found", reportEntriesText(report.drops, 6)]);
    if (report.ignoredDrops?.length) rows.push(["No Room", reportEntriesText(report.ignoredDrops, 4)]);
    rows.push(["Result", report.capped ? "8 hour cap reached" : "Still mining"]);
  } else {
    rows.push(["Kills", report.kills ?? 0]);
    rows.push(["XP", `+${report.xp ?? 0}`]);
    rows.push(["Gold", `+${report.gold ?? 0}`]);
    if (report.level) rows.push(["Level", report.level]);
    if (report.potionsUsed?.length) rows.push(["Potions", reportEntriesText(report.potionsUsed, 4)]);
    if (report.drops?.length) rows.push(["Found", reportEntriesText(report.drops, 5)]);
    if (report.ignoredDrops?.length) rows.push(["No Room", reportEntriesText(report.ignoredDrops, 4)]);
    if (report.defeatedAfter) rows.push(["Result", `Defeated after ${report.defeatedAfter}`]);
    else rows.push(["Result", report.capped ? "8 hour cap reached" : "Still hunting"]);
  }

  els.offlineReport.hidden = false;
  els.offlineReport.innerHTML = `
    <div class="offline-report-window" role="dialog" aria-modal="true" aria-labelledby="offlineReportTitle">
      <header>
        <div>
          <p class="eyebrow">Offline Progress</p>
          <h2 id="offlineReportTitle">While You Were Away</h2>
        </div>
        <button type="button" data-close-offline-report aria-label="Close offline report">X</button>
      </header>
      <dl>
        ${rows.map(([label, value]) => `<dt>${escapeHtml(String(label))}</dt><dd>${escapeHtml(String(value))}</dd>`).join("")}
      </dl>
      <button type="button" class="primary" data-close-offline-report>Continue</button>
    </div>
  `;
}

function closeOfflineReport() {
  state.game.offlineReport = null;
  renderOfflineReport();
}

function ensureMusicAudio() {
  if (musicAudio) return musicAudio;
  musicAudio = new Audio();
  musicAudio.preload = "auto";
  musicAudio.volume = normalizedVolume(state.settings.musicVolume);
  musicAudio.addEventListener("ended", () => handleMusicEnded());
  musicAudio.addEventListener("error", () => {
    musicStatusText = `Could not play ${currentMusicTrack()?.id ?? "music"}.`;
    sceneSignature = "";
    renderSceneOverlay();
  });
  return musicAudio;
}

function currentMusicTrack() {
  return BACKGROUND_MUSIC_TRACKS[musicTrackIndex] ?? BACKGROUND_MUSIC_TRACKS[0] ?? null;
}

function normalizedVolume(value) {
  return Math.max(0, Math.min(1, Number(value) || 0));
}

function normalizedMusicMode(value) {
  return value === MUSIC_MODE_TRACK ? MUSIC_MODE_TRACK : MUSIC_MODE_PLAYLIST;
}

function syncBackgroundMusic() {
  const audio = ensureMusicAudio();
  audio.volume = normalizedVolume(state.settings.musicVolume);
  if (!state.settings.musicEnabled) {
    audio.pause();
    musicStatusText = "";
    return;
  }
  if (!audio.src) setMusicTrack(musicTrackIndex, false);
  playCurrentMusic();
}

function playCurrentMusic() {
  const audio = ensureMusicAudio();
  const track = currentMusicTrack();
  if (!track) return;
  if (!audio.src || !audio.src.endsWith(track.src.replace("./", ""))) {
    audio.src = track.src;
  }
  audio.volume = normalizedVolume(state.settings.musicVolume);
  const playPromise = audio.play();
  if (playPromise?.catch) {
    playPromise
      .then(() => {
        musicStatusText = "";
        sceneSignature = "";
        renderSceneOverlay();
      })
      .catch(() => {
        musicStatusText = "Click Music On or Next once to start audio.";
        sceneSignature = "";
        renderSceneOverlay();
      });
  }
}

function setMusicTrack(index, autoplay = true, mode = state.settings.musicMode) {
  const count = BACKGROUND_MUSIC_TRACKS.length;
  if (!count) return;
  musicTrackIndex = ((Math.trunc(Number(index) || 0) % count) + count) % count;
  state.settings.musicMode = normalizedMusicMode(mode);
  const audio = ensureMusicAudio();
  const track = currentMusicTrack();
  audio.src = track.src;
  audio.currentTime = 0;
  sceneSignature = "";
  if (autoplay && state.settings.musicEnabled) playCurrentMusic();
  renderSceneOverlay();
}

function handleMusicEnded() {
  if (!state.settings.musicEnabled) return;
  if (normalizedMusicMode(state.settings.musicMode) === MUSIC_MODE_TRACK) {
    setMusicTrack(musicTrackIndex, true, MUSIC_MODE_TRACK);
    return;
  }
  playNextMusicTrack();
}

function playNextMusicTrack() {
  setMusicTrack(musicTrackIndex + 1, state.settings.musicEnabled, MUSIC_MODE_PLAYLIST);
}

function setMusicEnabled(enabled) {
  state.settings.musicEnabled = Boolean(enabled);
  if (state.settings.musicEnabled && !ensureMusicAudio().src) setMusicTrack(musicTrackIndex, false);
  syncBackgroundMusic();
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
}

function setMusicVolume(value) {
  state.settings.musicVolume = normalizedVolume(value);
  if (musicAudio) musicAudio.volume = state.settings.musicVolume;
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
}

function sfxEntry(key) {
  return state.sfxManifest?.byKey?.[key] ?? null;
}

function ensureSfxPool(key) {
  const entry = sfxEntry(key);
  if (!entry?.src) return null;
  let pool = sfxPools.get(key);
  if (!pool) {
    pool = Array.from({ length: SFX_POOL_SIZE }, () => {
      const audio = new Audio(entry.src);
      audio.preload = "auto";
      return audio;
    });
    sfxPools.set(key, pool);
    sfxPoolIndexes.set(key, 0);
  }
  return pool;
}

function playSfx(key, options = {}) {
  if (!state.settings.sfxEnabled) return false;
  const pool = ensureSfxPool(key);
  if (!pool?.length) return false;

  const now = performance.now();
  const throttleMs = Math.max(0, Number(options.throttleMs) || 0);
  if (!options.force && throttleMs > 0 && now - (sfxLastPlayedAt.get(key) ?? -Infinity) < throttleMs) return false;
  sfxLastPlayedAt.set(key, now);

  const startIndex = sfxPoolIndexes.get(key) ?? 0;
  const audio = pool.find((candidate) => candidate.paused || candidate.ended) ?? pool[startIndex];
  sfxPoolIndexes.set(key, (startIndex + 1) % pool.length);
  try {
    audio.currentTime = 0;
  } catch {
    // Some browsers can briefly reject currentTime before metadata is ready.
  }
  audio.volume = normalizedVolume(state.settings.sfxVolume) * normalizedVolume(options.volume ?? 1);
  const playPromise = audio.play();
  if (playPromise?.catch) playPromise.catch(() => {});
  return true;
}

function setSfxEnabled(enabled) {
  state.settings.sfxEnabled = Boolean(enabled);
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
}

function setSfxVolume(value) {
  state.settings.sfxVolume = normalizedVolume(value);
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
}

function loadPrototypeStatsPlayerId() {
  try {
    const existing = localStorage.getItem(STATS_PLAYER_ID_KEY);
    if (existing) return existing;
    const generated = globalThis.crypto?.randomUUID?.() ?? `anon-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
    localStorage.setItem(STATS_PLAYER_ID_KEY, generated);
    return generated;
  } catch {
    return `anon-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
  }
}

function prototypeStatsPlayerLabel(playerId = state.prototypeStats.playerId) {
  const accountId = String(playerId ?? "").split(":")[0];
  if (!accountId) return "Player ????????";
  return `Player ${accountId.slice(0, 8)}`;
}

function prototypeStatsNoticeRequired() {
  if (!state.settings.prototypeStatsEnabled) return false;
  return Math.max(0, Math.trunc(Number(state.settings.prototypeStatsNoticeVersion) || 0)) < STATS_NOTICE_VERSION;
}

function prototypeResetNoticeRequired(now = Date.now()) {
  const seenVersion = Math.max(0, Math.trunc(Number(state.settings.prototypeResetNoticeVersion) || 0));
  const lastSeenAt = Math.max(0, Math.trunc(Number(state.settings.prototypeResetNoticeLastSeenAt) || 0));
  return seenVersion < PROTOTYPE_RESET_NOTICE_VERSION
    || now - lastSeenAt >= PROTOTYPE_RESET_NOTICE_INTERVAL_MS;
}

function prototypeStatsCanSubmit() {
  return Boolean(
    state.settings.prototypeStatsEnabled
      && state.prototypeStats.configured
      && state.prototypeStats.endpoint
      && !prototypeStatsNoticeRequired(),
  );
}

async function loadPrototypeStatsConfig() {
  const config = await loadJson(STATS_CONFIG_URL).catch(() => ({}));
  const endpoint = typeof config.endpoint === "string" ? config.endpoint.trim() : "";
  const panelUrl = typeof config.panel === "string" ? config.panel.trim() : "";
  state.prototypeStats.endpoint = endpoint;
  state.prototypeStats.panelUrl = panelUrl;
  state.prototypeStats.configured = Boolean(endpoint) && config.enabled !== false;
  state.prototypeStats.statusText = state.prototypeStats.configured
    ? (panelUrl ? "Anonymous progress stats ready. Leaderboard panel available." : "Anonymous progress stats ready.")
    : "Stats endpoint not configured yet.";
}

function setPrototypeStatsEnabled(enabled) {
  state.settings.prototypeStatsEnabled = Boolean(enabled);
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
  renderPrototypeStatsNotice();
  if (state.settings.prototypeStatsEnabled) void submitPrototypeStats("enabled");
}

function maybeSubmitPrototypeStats(now) {
  if (!prototypeStatsCanSubmit()) return;
  if (state.prototypeStats.submitting) return;
  if (now - state.prototypeStats.lastSubmittedAt < STATS_SUBMIT_INTERVAL_MS) return;
  void submitPrototypeStats("interval", now);
}

function flushPrototypeStats(reason = "session-end") {
  if (!prototypeStatsCanSubmit()) return false;
  const snapshot = prototypeStatsSnapshot();
  const payloadHash = JSON.stringify(snapshot);
  if (payloadHash === state.prototypeStats.lastPayloadHash) return false;
  const payload = JSON.stringify({
    ...snapshot,
    reason,
    submittedAt: new Date().toISOString(),
  });
  if (!navigator.sendBeacon) {
    void submitPrototypeStats(reason);
    return true;
  }
  const sent = navigator.sendBeacon(state.prototypeStats.endpoint, new Blob([payload], { type: "application/json" }));
  if (sent) {
    state.prototypeStats.lastPayloadHash = payloadHash;
    state.prototypeStats.lastSubmittedAt = performance.now();
  }
  return sent;
}

function prototypeStatsInt(value, fallback = 0) {
  const number = Math.trunc(Number(value));
  return Number.isFinite(number) ? Math.max(0, number) : fallback;
}

function prototypeStatsCharacterSummaries() {
  captureActiveCharacterState();
  return CHARACTER_SELECT_CLASSES
    .filter((entry) => !entry.disabled)
    .map((entry) => prototypeStatsCharacterSummary(entry.id, state.characters[entry.id]))
    .filter(Boolean);
}

function prototypeStatsCharacterSummary(classId, character) {
  const game = character?.game;
  const progress = game?.progress;
  if (!game || !progress) return null;
  const stats = characterSnapshotTotalStats(classId, character, { includeBuffs: false });
  return {
    characterClass: normalizeCharacterId(classId),
    level: Math.max(1, prototypeStatsInt(progress.level, 1)),
    experience: prototypeStatsInt(progress.experience),
    kills: prototypeStatsInt(game.kills),
    zoneKills: prototypeStatsInt(game.zoneKills),
    gold: prototypeStatsInt(progress.gold ?? character.inventory?.gold),
    activeZoneId: game.activeZoneId ?? null,
    playtimeMs: prototypeStatsInt(game.playtimeMs),
    stats: {
      hp: prototypeStatsInt(stats.hp),
      maxHp: prototypeStatsInt(stats.maxHp),
      mp: prototypeStatsInt(stats.mp),
      maxMp: prototypeStatsInt(stats.maxMp),
      dc: [prototypeStatsInt(stats.dc?.[0]), prototypeStatsInt(stats.dc?.[1])],
      mc: [prototypeStatsInt(stats.mc?.[0]), prototypeStatsInt(stats.mc?.[1])],
      sc: [prototypeStatsInt(stats.sc?.[0]), prototypeStatsInt(stats.sc?.[1])],
      ac: [prototypeStatsInt(stats.ac?.[0]), prototypeStatsInt(stats.ac?.[1])],
      amc: [prototypeStatsInt(stats.amc?.[0]), prototypeStatsInt(stats.amc?.[1])],
      accuracy: prototypeStatsInt(stats.accuracy),
      agility: prototypeStatsInt(stats.agility),
      luck: prototypeStatsInt(stats.luck),
    },
  };
}

function prototypeStatsSnapshot() {
  const account = accountStatsSnapshot();
  const characters = prototypeStatsCharacterSummaries();
  const totalKills = characters.reduce((sum, character) => sum + character.kills, 0);
  const totalPlaytimeMs = characters.reduce((sum, character) => sum + character.playtimeMs, 0);
  return {
    game: "lom-idle-v2",
    saveVersion: SAVE_VERSION,
    playerId: state.prototypeStats.playerId,
    activeCharacterId: state.activeCharacterId,
    account,
    characters,
    highestLevel: account.highestCharacterLevel,
    experience: characters.reduce((best, character) => Math.max(best, character.experience), 0),
    kills: totalKills,
    zoneKills: characters.reduce((best, character) => Math.max(best, character.zoneKills), 0),
    bossKills: account.bossKills,
    gold: account.totalGold,
    activeZoneId: state.game.activeZoneId ?? null,
    playtimeMs: totalPlaytimeMs,
    characterCount: characters.length,
  };
}

async function submitPrototypeStats(reason = "manual", now = performance.now()) {
  if (!prototypeStatsCanSubmit()) return false;
  const snapshot = prototypeStatsSnapshot();
  const payloadHash = JSON.stringify(snapshot);
  if (reason !== "enabled" && payloadHash === state.prototypeStats.lastPayloadHash) return false;

  state.prototypeStats.submitting = true;
  state.prototypeStats.lastSubmittedAt = now;
  try {
    const response = await fetch(state.prototypeStats.endpoint, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...snapshot,
        reason,
        submittedAt: new Date().toISOString(),
      }),
      keepalive: true,
    });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    state.prototypeStats.lastPayloadHash = payloadHash;
    state.prototypeStats.statusText = `Anonymous stats submitted: ${snapshot.account.rebirthCount} rebirths, top level ${snapshot.account.highestCharacterLevel}.`;
    sceneSignature = "";
    renderSceneOverlay();
    return true;
  } catch (err) {
    state.prototypeStats.statusText = "Stats upload failed. Progress is still saved locally.";
    console.warn("Unable to submit prototype stats", err);
    sceneSignature = "";
    renderSceneOverlay();
    return false;
  } finally {
    state.prototypeStats.submitting = false;
  }
}

function renderPrototypeStatsNotice() {
  if (!els.prototypeStatsNotice) return;
  if (!prototypeStatsNoticeRequired()) {
    if (prototypeResetNoticeRequired()) {
      renderPrototypeResetNotice();
      return;
    }

    els.prototypeStatsNotice.classList.remove("prototype-reset-notice-overlay");
    els.prototypeStatsNotice.hidden = true;
    els.prototypeStatsNotice.innerHTML = "";
    return;
  }

  els.prototypeStatsNotice.classList.remove("prototype-reset-notice-overlay");
  els.prototypeStatsNotice.hidden = false;
  els.prototypeStatsNotice.innerHTML = `
    <div class="prototype-stats-notice-window" role="dialog" aria-modal="true" aria-labelledby="prototypeStatsNoticeTitle">
      <h2 id="prototypeStatsNoticeTitle">Anonymous Prototype Stats</h2>
      <p>
        This prototype can submit anonymous per-character gameplay progress such as level, XP, kills, gold, current zone, and playtime so I can tune balance and test leaderboards.
      </p>
      <p>
        No name, email, account, or personal details are sent. You can turn this off now, or later in Options.
      </p>
      <div class="prototype-stats-notice-actions">
        <button type="button" data-disable-prototype-stats>Turn Off</button>
        <button type="button" class="primary" data-accept-prototype-stats>Continue</button>
      </div>
    </div>
  `;
}

function renderPrototypeResetNotice() {
  if (!els.prototypeStatsNotice) return;
  els.prototypeStatsNotice.classList.add("prototype-reset-notice-overlay");
  els.prototypeStatsNotice.hidden = false;
  els.prototypeStatsNotice.innerHTML = `
    <div class="prototype-stats-notice-window prototype-reset-notice-window" role="dialog" aria-modal="true" aria-labelledby="prototypeResetNoticeTitle">
      <h2 id="prototypeResetNoticeTitle">Prototype Notice</h2>
      <p>
        This is still a public prototype for testing balance, progression, and overall feel.
      </p>
      <p>
        Saves are stored locally in this browser, but future updates may reset progress or make older saves incompatible.
      </p>
      <p class="prototype-reset-notice-note">
        This reminder appears at most once per day.
      </p>
      <div class="prototype-stats-notice-actions">
        <button type="button" class="primary" data-accept-prototype-reset-notice>Got it</button>
      </div>
    </div>
  `;
}

function acceptPrototypeStatsNotice() {
  state.settings.prototypeStatsNoticeVersion = STATS_NOTICE_VERSION;
  saveGameState(true);
  renderPrototypeStatsNotice();
  sceneSignature = "";
  renderSceneOverlay();
  void submitPrototypeStats("notice-accepted");
}

function disablePrototypeStatsFromNotice() {
  state.settings.prototypeStatsEnabled = false;
  state.settings.prototypeStatsNoticeVersion = STATS_NOTICE_VERSION;
  state.prototypeStats.statusText = "Anonymous progress tracking disabled.";
  saveGameState(true);
  renderPrototypeStatsNotice();
  sceneSignature = "";
  renderSceneOverlay();
}

function acceptPrototypeResetNotice() {
  state.settings.prototypeResetNoticeVersion = PROTOTYPE_RESET_NOTICE_VERSION;
  state.settings.prototypeResetNoticeLastSeenAt = Date.now();
  saveGameState(true);
  renderPrototypeStatsNotice();
}

function incrementReportCount(map, label, amount = 1) {
  map.set(label, (map.get(label) ?? 0) + amount);
}

function reportEntriesText(entries, limit = 3) {
  return entries
    .slice(0, limit)
    .map(([label, count]) => `${label}${count > 1 ? ` x${count}` : ""}`)
    .join(", ");
}

function reportCountText(map, limit = 3) {
  return reportEntriesText([...map.entries()], limit);
}

function formatDuration(ms) {
  const totalSeconds = Math.max(0, Math.floor(ms / 1000));
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  if (hours > 0) return `${hours}h ${minutes}m`;
  if (minutes > 0) return `${minutes}m ${seconds}s`;
  return `${seconds}s`;
}

function formatBossRespawnDelay(minutes) {
  const value = Math.max(0, Math.trunc(Number(minutes) || 0));
  if (value >= 60 && value % 60 === 0) {
    const hours = value / 60;
    return hours === 1 ? "1 hour" : `${hours} hours`;
  }
  return `${value} minute${value === 1 ? "" : "s"}`;
}

function normalizeSavedProgress() {
  let nextLevelXp = xpForNextLevel(state.game.progress.level);
  while (Number.isFinite(nextLevelXp) && state.game.progress.experience >= nextLevelXp) {
    state.game.progress.experience -= nextLevelXp;
    state.game.progress.level += 1;
    nextLevelXp = xpForNextLevel(state.game.progress.level);
  }
}

function sanitizeDropPity(savedPity) {
  if (!savedPity || typeof savedPity !== "object") return {};
  return Object.fromEntries(
    PROTOTYPE_ZONES.map((zone) => [
      zone.id,
      Math.max(0, Math.min(DROP_PITY_KILLS, Math.trunc(Number(savedPity[zone.id]) || 0))),
    ]),
  );
}

function finiteNumberOrNull(value) {
  if (value == null || value === "") return null;
  const number = Number(value);
  return Number.isFinite(number) ? number : null;
}

function totalPlaytimeMs() {
  return Math.max(0, Math.trunc(Number(state.game.playtimeMs) || 0)) + Math.max(0, performance.now() - sessionStartedAt);
}

function maybeAutoSave(now) {
  if (!saveReady || now - lastSaveAt < SAVE_INTERVAL_MS) return;
  saveGameState();
}

async function resetSavedGame() {
  if (!window.confirm("Reset your saved LOM Idle V2 prototype progress?")) return;
  try {
    localStorage.removeItem(SAVE_KEY);
  } catch (err) {
    console.warn("Unable to clear game save", err);
  }

  saveReady = false;
  resetRuntimeGameState();
  resetBattle();
  await reloadAtlases();
  await reloadEnemyAtlas();
  saveReady = true;
  saveGameState(true);
  invalidateUi();
  renderLayerControls();
  renderMapControls();
  renderGamePanel();
  renderBattlePanel();
  renderSceneOverlay();
  renderOfflineReport();
  renderCombatSkillBar();
  renderHotbar();
  render();
}

