function sceneButtonsHtml() {
  return `
    <div class="scene-buttons">
      <button data-open-scene="character" class="${state.openScenes.character ? "active" : ""}">Character</button>
      <button data-open-scene="inventory" class="${state.openScenes.inventory ? "active" : ""}">Inventory</button>
      <button data-open-scene="upgrades" class="${state.openScenes.upgrades ? "active" : ""}">Upgrades</button>
      <button data-open-scene="characterSelect" class="${state.openScenes.characterSelect ? "active" : ""}">Characters</button>
      <button data-open-scene="gettingStarted" class="${state.openScenes.gettingStarted ? "active" : ""}">Guide</button>
      <button data-open-scene="options" class="${state.openScenes.options ? "active" : ""}">Options</button>
    </div>
  `;
}

function bindSceneButtons(rootEl) {
  rootEl.querySelectorAll("[data-open-scene]").forEach((button) => {
    button.addEventListener("click", () => openScene(button.dataset.openScene));
  });
  rootEl.querySelectorAll("[data-teleport-region]").forEach((button) => {
    button.addEventListener("click", () => {
      const region = teleportRegionById(button.dataset.teleportRegion);
      state.teleportRegionId = region.id;
      state.teleportBrowseRegionId = region.id;
      sceneSignature = "";
      renderSceneOverlay();
    });
  });
  rootEl.querySelectorAll("[data-teleport-back]").forEach((button) => {
    button.addEventListener("click", () => {
      state.teleportBrowseRegionId = null;
      sceneSignature = "";
      renderSceneOverlay();
    });
  });
  rootEl.querySelectorAll("[data-enter-zone]").forEach((button) => {
    button.addEventListener("click", async () => {
      await requestZoneEntry(button.dataset.enterZone);
    });
  });
  rootEl.querySelectorAll("[data-head-to-mines]").forEach((button) => {
    button.addEventListener("click", () => enterMiningFromRefiner());
  });
  rootEl.querySelectorAll("[data-sell-all-junk-ore]").forEach((button) => {
    button.addEventListener("click", () => sellAllJunkOre());
  });
  rootEl.querySelectorAll("[data-open-weapon-refine]").forEach((button) => {
    button.addEventListener("click", () => openWeaponRefineScene());
  });
  rootEl.querySelectorAll("[data-refine-slot]").forEach((button) => {
    button.addEventListener("click", () => {
      handleWeaponRefineSlotClick(button.dataset.refineSlot, Number(button.dataset.refineIndex) || 0);
    });
  });
  rootEl.querySelectorAll("[data-refine-pick]").forEach((button) => {
    button.addEventListener("click", () => assignWeaponRefinePick(button.dataset.refinePick));
  });
  rootEl.querySelectorAll("[data-attempt-weapon-refine]").forEach((button) => {
    button.addEventListener("click", () => attemptWeaponRefine());
  });
  rootEl.querySelectorAll("[data-upgrade-category]").forEach((button) => {
    button.addEventListener("click", () => {
      state.upgradeCategory = normalizeUpgradeCategory(button.dataset.upgradeCategory);
      sceneSignature = "";
      renderSceneOverlay();
    });
  });
}

function initialOpenScenesFromUrl() {
  const scene = new URLSearchParams(window.location.search).get("scene");
  const scenes = new Set(String(scene ?? "").split(",").filter(Boolean));
  return {
    character: scene === "both" || scenes.has("character"),
    inventory: scene === "both" || scenes.has("inventory"),
    upgrades: scenes.has("upgrades"),
    characterSelect: scenes.has("characterSelect") || scenes.has("characters"),
    gettingStarted: scenes.has("gettingStarted") || scenes.has("guide"),
    options: scenes.has("options"),
  };
}

function openScene(scene, updateUrl = true) {
  if (!["character", "inventory", "upgrades", "characterSelect", "gettingStarted", "options"].includes(scene)) return;
  state.game.selectedTownNpcId = null;
  if (state.activeScene === "townNpc" || state.activeScene === "storage" || state.activeScene === "bossEntry" || state.activeScene === "weaponRefine") state.activeScene = null;
  if (scene === "characterSelect") {
    state.openScenes.character = false;
    state.openScenes.inventory = false;
    state.openScenes.upgrades = false;
    state.openScenes.gettingStarted = false;
    state.openScenes.options = false;
  } else {
    state.openScenes.characterSelect = false;
  }
  state.openScenes[scene] = true;
  playSfx("ui.button", { volume: 0.35, throttleMs: 80 });
  if (updateUrl) setSceneUrl();
  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
}

function closeScene(scene = null, updateUrl = true) {
  if (typeof scene === "boolean") {
    updateUrl = scene;
    scene = null;
  }
  if (scene === "character" || scene === "inventory" || scene === "upgrades" || scene === "characterSelect" || scene === "gettingStarted" || scene === "options") {
    state.openScenes[scene] = false;
    if (scene === "inventory") state.pendingInventoryDestroyEntryId = null;
  } else if (scene === "weaponRefine") {
    restoreAllWeaponRefineStagedEntries();
    state.weaponRefine.picker = { kind: "weapon", index: 0 };
    state.activeScene = state.game.selectedTownNpcId ? "townNpc" : null;
  } else if (scene === "townNpc" || scene === "storage" || scene === "bossEntry") {
    state.game.selectedTownNpcId = null;
    if (scene === "storage") state.pendingStoragePageUnlock = null;
    if (state.activeScene === "townNpc" || state.activeScene === "storage" || state.activeScene === "bossEntry" || state.activeScene === "weaponRefine") state.activeScene = null;
    if (scene === "bossEntry") {
      state.bossEntryZoneId = null;
      state.bossEntryFromGroupDungeonAdvance = false;
      state.bossEmpowerSelected = false;
    }
    if (scene === "townNpc") resetWeaponRefineState();
  } else {
    if (state.activeScene === "weaponRefine" || Object.keys(state.weaponRefine?.stagedEntries ?? {}).length) {
      restoreAllWeaponRefineStagedEntries();
      state.weaponRefine.picker = { kind: "weapon", index: 0 };
    }
    if (state.activeScene === "townNpc" || state.activeScene === "storage" || state.activeScene === "weaponRefine") state.game.selectedTownNpcId = null;
    state.bossEntryZoneId = null;
    state.bossEntryFromGroupDungeonAdvance = false;
    state.activeScene = null;
    state.openScenes.character = false;
    state.openScenes.inventory = false;
    state.openScenes.upgrades = false;
    state.openScenes.characterSelect = false;
    state.openScenes.gettingStarted = false;
    state.openScenes.options = false;
    state.pendingInventoryDestroyEntryId = null;
  }
  if (updateUrl) setSceneUrl();
  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
}

function setSceneUrl() {
  const url = new URL(window.location.href);
  const open = Object.entries(state.openScenes).filter(([, enabled]) => enabled).map(([scene]) => scene);
  if (open.length === 2 && open.includes("character") && open.includes("inventory")) url.searchParams.set("scene", "both");
  else if (open.length === 1) url.searchParams.set("scene", open[0]);
  else if (open.length > 1) url.searchParams.set("scene", open.join(","));
  else url.searchParams.delete("scene");
  window.history.pushState({ scene: url.searchParams.get("scene") }, "", url);
}

function renderSceneOverlay(options = {}) {
  const deferUserInteraction = Boolean(options.deferUserInteraction);
  const openScenes = ["characterSelect", "character", "inventory", "upgrades", "gettingStarted", "options"].filter((scene) => state.openScenes[scene]);
  const npcScene = state.activeScene === "townNpc" || state.activeScene === "storage" || state.activeScene === "bossEntry" || state.activeScene === "weaponRefine"
    ? state.activeScene
    : null;
  const overlayScenes = npcScene ? [...openScenes, npcScene] : openScenes;
  const destroyConfirmHtml = inventoryDestroyConfirmHtml();
  if (!overlayScenes.length && !destroyConfirmHtml) {
    cleanupInventoryCarry();
    els.sceneOverlay.hidden = true;
    els.sceneOverlay.innerHTML = "";
    sceneSignature = "";
    return;
  }

  const bossEntryZoneId = state.activeScene === "bossEntry" ? state.bossEntryZoneId : null;
  const signature = buildSceneOverlaySignature(openScenes, bossEntryZoneId);
  if (signature === sceneSignature) return;
  if (inventoryDragState) return;
  if (deferUserInteraction && sceneOverlayInteractionActive()) return;
  sceneSignature = signature;

  const scrollPositions = captureSceneScrollPositions();
  els.sceneOverlay.hidden = false;
  els.sceneOverlay.innerHTML = `
    <div class="scene-window-stack">
      ${overlayScenes.map((scene) => sceneWindowHtml(scene)).join("")}
    </div>
    ${destroyConfirmHtml}
  `;
  bindSceneButtons(els.sceneOverlay);
  bindSceneScrollPreservation(els.sceneOverlay);
  restoreSceneScrollPositions(scrollPositions);
}

function buildSceneOverlaySignature(openScenes, bossEntryZoneId) {
  const payload = {
    scene: state.activeScene,
    openScenes: state.openScenes,
    characterTab: state.characterTab,
    inventoryPage: state.inventoryPage,
    storagePage: state.storagePage,
    pendingStoragePageUnlock: state.pendingStoragePageUnlock,
    pendingInventoryDestroyEntryId: state.pendingInventoryDestroyEntryId,
    storagePage2Purchased: state.account.storage.page2Purchased,
    upgradeCategory: state.upgradeCategory,
    bossEntryZoneId: state.bossEntryZoneId,
    bossEntryFromGroupDungeonAdvance: state.bossEntryFromGroupDungeonAdvance,
    bossAssistSelection: state.bossAssistSelection,
    bossRespawns: state.game.bossRespawns,
    bossKills: state.game.bossKills,
    teleportRegionId: state.teleportRegionId,
    teleportBrowseRegionId: state.teleportBrowseRegionId,
    selectedTownNpcId: state.game.selectedTownNpcId,
    weaponRefine: state.weaponRefine,
    combatClass: state.battle.combatClass,
    accountUpgrades: state.account.upgrades,
    autoCastSlotLimit: autoCastSlotLimit(),
    autoPotionSlotLimit: autoPotionSlotLimit(),
    settings: state.settings,
    musicTrackIndex,
    musicStatusText,
  };
  if (bossEntryZoneId) {
    payload.bossEntryRespawnSec = Math.ceil(bossRespawnRemainingMs(bossEntryZoneId) / 1000);
  }
  if (openScenes.includes("character")) {
    payload.level = state.game.progress.level;
    payload.experience = state.game.progress.experience;
    payload.magic = sceneMagicSignature();
    if (state.characterTab === "character") {
      payload.equipment = state.inventory.equipment;
    }
    if (state.characterTab === "status") {
      const stats = characterTotalStats();
      payload.statusStats = {
        hp: stats.hp,
        mp: stats.mp,
        ac: stats.ac,
        amc: stats.amc,
        dc: stats.dc,
        mc: stats.mc,
        sc: stats.sc,
      };
      payload.statBuffs = pruneStatBuffs(state.battle.statBuffs ?? []);
    }
  }
  if (openScenes.includes("inventory") || openScenes.includes("weaponRefine")) {
    payload.gold = state.inventory.gold;
    payload.inventoryPagesUnlocked = state.inventory.pagesUnlocked;
    payload.inventoryItems = state.inventory.items.map(inventoryEntrySignature);
  }
  if (openScenes.includes("storage") || state.activeScene === "storage") {
    payload.storagePagesUnlocked = state.account.storage.pagesUnlocked;
    payload.storagePage2Purchased = state.account.storage.page2Purchased;
    payload.storageItems = state.account.storage.items.map(inventoryEntrySignature);
  }
  return JSON.stringify(payload);
}

function bindSceneScrollPreservation(root) {
  for (const element of root.querySelectorAll("[data-preserve-scroll]")) {
    const key = element.dataset.preserveScroll;
    if (!key) continue;
    const persistScroll = () => {
      sceneScrollPositions.set(key, {
        left: element.scrollLeft,
        top: element.scrollTop,
      });
      noteSceneOverlayInteraction(700);
    };
    element.addEventListener("scroll", persistScroll, { passive: true });
    element.addEventListener("wheel", () => noteSceneOverlayInteraction(900), { passive: true });
    element.addEventListener("pointerdown", () => noteSceneOverlayInteraction(900), { passive: true });
  }
}

function captureSceneScrollPositions() {
  for (const element of els.sceneOverlay.querySelectorAll("[data-preserve-scroll]")) {
    const key = element.dataset.preserveScroll;
    if (!key) continue;
    sceneScrollPositions.set(key, {
      left: element.scrollLeft,
      top: element.scrollTop,
    });
  }
  return sceneScrollPositions;
}

function restoreSceneScrollPositions(positions) {
  const source = positions?.size ? positions : sceneScrollPositions;
  if (!source?.size) return;
  for (const element of els.sceneOverlay.querySelectorAll("[data-preserve-scroll]")) {
    const key = element.dataset.preserveScroll;
    const position = source.get(key);
    if (!key || !position) continue;
    const maxTop = Math.max(0, element.scrollHeight - element.clientHeight);
    const maxLeft = Math.max(0, element.scrollWidth - element.clientWidth);
    element.scrollTop = Math.min(position.top, maxTop);
    element.scrollLeft = Math.min(position.left, maxLeft);
  }
}

function sceneWindowHtml(scene) {
  return `
    <div class="${sceneClassName(scene)}" data-scene-window="${scene}">
      <header class="scene-header">
        <div>
          <p class="eyebrow">Town Menu</p>
          <h2>${escapeHtml(sceneTitle(scene))}</h2>
        </div>
        <button data-close-scene="${scene}">Back</button>
      </header>
      ${sceneBodyHtml(scene)}
    </div>
  `;
}

function sceneClassName(scene) {
  if (scene === "characterSelect") return "scene-window character-select-window";
  if (scene === "townNpc") return "scene-window npc-dialog-window";
  if (scene === "bossEntry") return "scene-window boss-entry-window";
  if (scene === "storage") return "scene-window storage-window";
  if (scene === "weaponRefine") return "scene-window weapon-refine-window";
  if (scene === "inventory") return "scene-window inventory-window";
  if (scene === "character") return "scene-window character-window";
  if (scene === "upgrades") return "scene-window upgrades-window";
  if (scene === "gettingStarted") return "scene-window getting-started-window";
  if (scene === "options") return "scene-window options-window";
  return "scene-window";
}

function sceneTitle(scene) {
  if (scene === "characterSelect") return "Character Select";
  if (scene === "character") return "Character";
  if (scene === "inventory") return "Inventory";
  if (scene === "storage") return "Storage";
  if (scene === "weaponRefine") return "Weapon Refine";
  if (scene === "upgrades") return "Upgrades";
  if (scene === "gettingStarted") return "Getting Started";
  if (scene === "options") return "Options";
  if (scene === "bossEntry") {
    const zone = bossEntryZone();
    if (groupDungeonZone(zone)) return zone?.label ?? "Group Dungeon";
    return bossRoomDef(zone?.id)?.bossName ?? "Boss Room";
  }
  return selectedTownNpc()?.label ?? "NPC";
}

function sceneBodyHtml(scene) {
  if (scene === "characterSelect") return characterSelectSceneHtml();
  if (scene === "character") return characterSceneHtml();
  if (scene === "inventory") return inventorySceneHtml();
  if (scene === "storage") return storageSceneHtml();
  if (scene === "upgrades") return upgradesSceneHtml();
  if (scene === "gettingStarted") return gettingStartedSceneHtml();
  if (scene === "options") return optionsSceneHtml();
  if (scene === "bossEntry") return bossEntrySceneHtml();
  if (scene === "weaponRefine") return weaponRefineSceneHtml();
  if (scene === "townNpc") return townNpcSceneHtml();
  return "";
}

function characterAvailableForBossAssist(classId) {
  if (classId === state.activeCharacterId) return false;
  return Boolean(state.characters?.[classId]);
}

function selectedBossAssistIds() {
  return new Set((state.bossAssistSelection ?? []).filter((classId) => (
    classId !== state.activeCharacterId
      && BOSS_ASSIST_OPTIONS.some((option) => option.classId === classId)
      && characterAvailableForBossAssist(classId)
  )));
}

function toggleBossAssistSelection(classId) {
  const option = BOSS_ASSIST_OPTIONS.find((entry) => entry.classId === classId);
  if (!option || !characterAvailableForBossAssist(classId)) return false;
  const selected = selectedBossAssistIds();
  if (selected.has(classId)) selected.delete(classId);
  else selected.add(classId);
  state.bossAssistSelection = [...selected].sort((a, b) => BOSS_PARTY_ORDER.indexOf(a) - BOSS_PARTY_ORDER.indexOf(b));
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.35, throttleMs: 80 });
  return true;
}

function toggleBossEmpowerSelection() {
  if (!bossEmpowermentUnlocked()) return false;
  state.bossEmpowerSelected = !state.bossEmpowerSelected;
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.35, throttleMs: 80 });
  return true;
}

function bossAssistOptionHtml(option) {
  const available = characterAvailableForBossAssist(option.classId);
  const selected = selectedBossAssistIds().has(option.classId);
  const disabled = available ? "" : "disabled";
  const status = !available
    ? option.classId === state.activeCharacterId ? "Current character" : "No character"
    : selected
    ? "Selected"
    : "Ready";
  return `
    <button type="button" class="boss-assist-button ${selected ? "selected" : ""}" ${disabled} data-boss-assist="${escapeHtml(option.classId)}">
      <span>${escapeHtml(option.label)}</span>
      <strong>${escapeHtml(status)}</strong>
    </button>
  `;
}

function partyAssistPickerHtml() {
  return `
      <div class="boss-entry-actions">
        ${BOSS_ASSIST_OPTIONS.map(bossAssistOptionHtml).join("")}
      </div>
      <p class="boss-entry-note">Optionally bring saved characters into the fight.</p>
  `;
}

function groupDungeonBossSwarmEntrySummary(zone, config) {
  const base = zone?.groupDungeonBossSwarmConfig ?? {};
  if (Array.isArray(base.spawnQueue) && base.spawnQueue.length) {
    const parts = base.spawnQueue.map((entry) => {
      const count = Math.max(1, Math.trunc(Number(entry.count) || 1));
      const name = ENEMY_TEMPLATES.find((template) => template.id === Math.trunc(Number(entry.templateId)))?.name ?? "boss";
      const delaySec = Math.round(Math.max(0, Math.trunc(Number(entry.spawnDelayMs) || 0)) / 1000);
      if (delaySec <= 0) {
        const rowNote = entry.mapRowOffset === 1 ? " (one row south)" : "";
        return `${count}× ${name}${rowNote} immediately`;
      }
      return `${count}× ${name} after ${delaySec}s`;
    });
    if (config.spawnAllAtOnce) return `${parts.join(", ")} — all emerge at once from the east.`;
    return `${parts.join("; ")} — advancing from the east.`;
  }
  const boss = ENEMY_TEMPLATES.find((enemy) => zone.enemyIds.includes(enemy.id));
  const intervalSec = Math.round(config.spawnIntervalMs / 1000);
  return `${config.totalSpawns} ${boss?.name ?? "bosses"} — one emerges immediately, then one every ${intervalSec}s, advancing from the east like a swarm.`;
}

function groupDungeonBossSwarmEntrySceneHtml(zone) {
  const config = groupDungeonBossSwarmConfig(zone);
  const selected = selectedBossAssistIds();
  const nextZone = groupDungeonNextFloorZone(zone);
  const bossName = groupDungeonBossSwarmLabel(zone);
  const remainingMs = groupDungeonBossRespawnRemainingMs(zone);
  const respawning = remainingMs > 0;
  const respawnMinutes = groupDungeonBossRespawnMinutes(zone);
  const base = zone?.groupDungeonBossSwarmConfig ?? {};
  const spawnSchedule = config.spawnAllAtOnce
    ? `${config.totalSpawns} total · all at once`
    : Array.isArray(base.spawnQueue) && base.spawnQueue.some((entry) => (entry.spawnDelayMs || 0) > 0)
      ? base.spawnQueue.map((entry) => {
        const count = Math.max(1, Math.trunc(Number(entry.count) || 1));
        const delaySec = Math.round(Math.max(0, Math.trunc(Number(entry.spawnDelayMs) || 0)) / 1000);
        return delaySec <= 0 ? `${count} now` : `${count} after ${delaySec}s`;
      }).join(" · ")
      : config.firstSpawnDelayMs <= 0
        ? `${config.totalSpawns} total · now, +${Math.round(config.spawnIntervalMs / 1000)}s, +${Math.round(config.spawnIntervalMs / 1000) * 2}s`
        : `${config.totalSpawns} total · every ${Math.round(config.spawnIntervalMs / 1000)}s`;
  const bossRows = Array.isArray(base.spawnQueue) && base.spawnQueue.length
    ? base.spawnQueue.map((entry) => {
      const template = ENEMY_TEMPLATES.find((enemy) => enemy.id === Math.trunc(Number(entry.templateId)));
      const count = Math.max(1, Math.trunc(Number(entry.count) || 1));
      return `<dt>${escapeHtml(template?.name ?? "Boss")}</dt><dd>${count} · ${template?.maxHp ?? "-"} HP · ${escapeHtml(enemyAttackDefenceGuidance(template))}</dd>`;
    }).join("")
    : (() => {
      const boss = ENEMY_TEMPLATES.find((enemy) => zone.enemyIds.includes(enemy.id));
      return `<dt>Boss</dt><dd>${escapeHtml(boss?.name ?? "Boss")}</dd>
        <dt>HP</dt><dd>${boss?.maxHp ?? "-"}</dd>
        <dt>Defend with</dt><dd>${escapeHtml(enemyAttackDefenceGuidance(boss))}</dd>`;
    })();
  const respawnStatusHtml = respawning
    ? `
      <div class="boss-entry-respawn-status" aria-live="polite">
        <strong class="boss-entry-respawn-boss">${escapeHtml(bossName)}</strong>
        <span class="boss-entry-respawn-label">Respawns in</span>
        <strong class="boss-entry-respawn-countdown">${escapeHtml(formatDuration(remainingMs))}</strong>
        <p class="boss-entry-note muted">The bosses will not appear until then. You can still enter the room and wait, or advance to the next floor from there.</p>
      </div>
    `
    : respawnMinutes > 0
      ? `<p class="boss-warning muted">After a clear, ${escapeHtml(bossName)} respawns in ${escapeHtml(formatBossRespawnDelay(respawnMinutes))}.</p>`
      : "";
  return `
    <section class="boss-entry-panel">
      <p class="boss-warning">
        You're entering ${escapeHtml(zone.label)} with your ${escapeHtml(state.activeCharacterId)}.
      </p>
      ${respawnStatusHtml}
      <p class="boss-warning muted">
        ${respawning ? `Defeat all ${escapeHtml(bossName)} to continue once they return.` : escapeHtml(groupDungeonBossSwarmEntrySummary(zone, config))}
      </p>
      <dl class="boss-entry-stats">
        ${bossRows}
        <dt>Spawns</dt><dd>${spawnSchedule}</dd>
        <dt>Party</dt><dd>${1 + selected.size}</dd>
      </dl>
      ${partyAssistPickerHtml()}
      <footer class="boss-entry-footer">
        <button
          type="button"
          class="primary boss-entry-fight-button"
          data-confirm-boss-zone="${escapeHtml(zone.id)}"
        >
          Enter ${escapeHtml(zone.label)}
        </button>
        ${nextZone ? `<p class="boss-entry-note muted">Clear all ${config.totalSpawns} to unlock ${escapeHtml(nextZone.label)}.</p>` : ""}
      </footer>
    </section>
  `;
}

function groupDungeonAdvancePartyLabel() {
  const classIds = bossPartyClassOrder([state.activeCharacterId, ...selectedBossAssistIds()]);
  return classIds.map((classId) => escapeHtml(classId)).join(", ");
}

