function characterSelectSceneHtml() {
  return `
    <section class="character-select-scene">
      <div class="character-select-choices">
        ${CHARACTER_SELECT_CLASSES.map(characterSelectCardHtml).join("")}
      </div>
    </section>
  `;
}

function characterSelectCardHtml(entry) {
  const active = entry.id === state.battle.combatClass;
  const disabled = entry.disabled || COMBAT_CLASSES.some((combatClass) => combatClass.id === entry.id && combatClass.disabled);
  const character = active ? serializeCurrentCharacterState() : state.characters[entry.id];
  const progress = character?.game?.progress ?? { level: PLAYER_TEMPLATE.level, gold: PLAYER_TEMPLATE.gold };
  return `
    <button
      type="button"
      class="character-select-card ${active ? "active" : ""} ${disabled ? "disabled" : ""}"
      data-select-player-class="${escapeHtml(entry.id)}"
      ${disabled ? "disabled" : ""}
      aria-pressed="${active ? "true" : "false"}"
    >
      <span class="character-select-portrait">
        <img src="${escapeHtml(entry.image)}" alt="" />
      </span>
      <strong>${escapeHtml(entry.label)}</strong>
      <span>${active ? "Selected" : escapeHtml(entry.role)} | Lv ${progress.level} | ${progress.gold}g</span>
    </button>
  `;
}

function characterSceneHtml() {
  const stats = characterTotalStats();
  const currentTab = CHARACTER_TABS.some((tab) => tab.id === state.characterTab) ? state.characterTab : "character";
  return `
    <section class="crystal-character" aria-label="Character">
      <span class="crystal-character-name">${escapeHtml(state.battle.combatClass)}</span>
      <span class="crystal-character-guild">Level ${state.game.progress.level} | ${escapeHtml(xpProgressText())}</span>
      <span class="crystal-character-class-icon" aria-hidden="true"></span>
      ${CHARACTER_TABS.map((tab) => crystalCharacterTabHtml(tab, currentTab)).join("")}
      ${currentTab === "character" ? crystalCharacterEquipmentPageHtml() : crystalCharacterStatusPageHtml(stats, currentTab)}
    </section>
  `;
}

function crystalCharacterTabHtml(tab, currentTab) {
  return `
    <button
      class="crystal-character-tab ${currentTab === tab.id ? "active" : ""}"
      type="button"
      data-character-tab="${tab.id}"
      title="${escapeHtml(tab.label)}"
      style="left:${tab.x}px; background-position:${-tab.slot * 64}px 0;"
    ></button>
  `;
}

function crystalCharacterEquipmentPageHtml() {
  return `
    <div class="crystal-character-panel"></div>
    ${crystalCharacterPaperDollHtml()}
    ${EQUIPMENT_SLOTS.map((slot) => crystalEquipmentSlotHtml(slot)).join("")}
  `;
}

function crystalCharacterPaperDollHtml() {
  const armourItem = equippedItem("armour");
  const weaponItem = equippedItem("weapon");
  const helmetItem = equippedItem("helmet");
  const layers = [
    armourItem ? crystalPaperDollLayerHtml(armourItem, "armour") : "",
    weaponItem ? crystalPaperDollLayerHtml(weaponItem, "weapon") : "",
    helmetItem ? crystalPaperDollLayerHtml(helmetItem, "helmet") : crystalPaperDollFrameHtml(CHARACTER_PAPER_DOLL_FRAMES.hair, "Hair"),
  ].filter(Boolean);
  return `<div class="crystal-paper-doll" aria-hidden="true">${layers.join("")}</div>`;
}

function crystalPaperDollLayerHtml(item, label) {
  const frame = state.characterStateItems?.[item.icon?.frame] ?? CHARACTER_PAPER_DOLL_FRAMES[item.icon?.frame];
  if (!frame) return "";
  return crystalPaperDollFrameHtml(frame, item.name ?? label);
}

function crystalPaperDollFrameHtml(frame, label) {
  if (frame.sheet) {
    return `
    <div
      class="crystal-paper-doll-layer"
      title="${escapeHtml(label)}"
      style="left:${frame.x}px; top:${frame.y}px; width:${frame.w}px; height:${frame.h}px; background:url('${escapeHtml(frame.sheet)}') -${frame.sx}px -${frame.sy}px no-repeat;"
    ></div>
  `;
  }
  return `
    <img
      class="crystal-paper-doll-layer"
      src="${escapeHtml(frame.src)}"
      alt=""
      title="${escapeHtml(label)}"
      style="left:${frame.x}px; top:${frame.y}px; width:${frame.w}px; height:${frame.h}px;"
    />
  `;
}

function crystalCharacterStatusPageHtml(stats, tabId) {
  const pageSlot = tabId === "state" ? 1 : tabId === "skill" ? 2 : 0;
  const body = tabId === "status"
    ? STATUS_VALUE_ROWS.map((row) => crystalStatusValueHtml(row, stats)).join("")
    : tabId === "state"
    ? crystalCharacterStatePageHtml()
    : tabId === "skill"
    ? crystalCharacterSkillPageHtml()
    : `<span class="crystal-character-page-note">Later</span>`;
  return `
    <div class="crystal-character-page ${tabId === "skill" || tabId === "state" ? "skill-page" : ""}" style="background-position:${-pageSlot * 248}px 0;">
      ${body}
    </div>
  `;
}

function crystalCharacterStatePageHtml() {
  const account = accountStatsSnapshot();
  const bossRows = Object.entries(BOSS_ROOM_DEFS).map(([zoneId, def]) => ({
    zoneId,
    label: def.bossName,
    kills: bossKillCount(zoneId),
  }));
  const characterRows = CHARACTER_SELECT_CLASSES
    .filter((entry) => !entry.disabled)
    .map((entry) => {
      const character = state.characters[entry.id];
      const stats = characterSnapshotTotalStats(entry.id, character, { includeBuffs: false });
      return {
        classId: entry.id,
        label: entry.label ?? entry.id,
        level: Math.max(1, Math.trunc(Number(character?.game?.progress?.level) || 1)),
        dc: `${stats.dc[0]}-${stats.dc[1]}`,
        mc: `${stats.mc[0]}-${stats.mc[1]}`,
        sc: `${stats.sc[0]}-${stats.sc[1]}`,
        ac: `${stats.ac[0]}-${stats.ac[1]}`,
        amc: `${stats.amc[0]}-${stats.amc[1]}`,
        accuracy: stats.accuracy,
        agility: stats.agility,
        luck: stats.luck,
      };
    });
  return `
    <div class="crystal-state-list" data-preserve-scroll="character-state">
      <div class="crystal-state-heading">Account</div>
      <div class="crystal-state-row">
        <span class="crystal-state-label">Total Gold</span>
        <span class="crystal-state-value">${account.totalGold.toLocaleString()}</span>
      </div>
      <div class="crystal-state-row">
        <span class="crystal-state-label">Rebirths</span>
        <span class="crystal-state-value">${account.rebirthCount}</span>
      </div>
      <div class="crystal-state-row">
        <span class="crystal-state-label">Points Gained</span>
        <span class="crystal-state-value">${account.rebirthPointsGained}</span>
      </div>
      <div class="crystal-state-row">
        <span class="crystal-state-label">Points Spent</span>
        <span class="crystal-state-value">${account.rebirthPointsSpent}</span>
      </div>
      <div class="crystal-state-row">
        <span class="crystal-state-label">Rebirth Points</span>
        <span class="crystal-state-value">${account.rebirthPointsHeld}</span>
      </div>
      <div class="crystal-state-row">
        <span class="crystal-state-label">Awakening Souls</span>
        <span class="crystal-state-value">${account.awakeningSoulsHeld ?? 0}</span>
      </div>
      ${bossRows.map((row) => `
        <div class="crystal-state-row">
          <span class="crystal-state-label">${escapeHtml(row.label)}</span>
          <span class="crystal-state-value">${row.kills}</span>
        </div>
      `).join("")}
      <div class="crystal-state-heading">Characters</div>
      ${characterRows.map((row) => `
        <div class="crystal-state-block">
          <div class="crystal-state-row">
            <span class="crystal-state-label">${escapeHtml(row.label)}</span>
            <span class="crystal-state-value">Lv ${row.level}</span>
          </div>
          <div class="crystal-state-note">DC ${escapeHtml(row.dc)} | MC ${escapeHtml(row.mc)} | SC ${escapeHtml(row.sc)}</div>
          <div class="crystal-state-note">AC ${escapeHtml(row.ac)} | AMC ${escapeHtml(row.amc)} | Acc ${row.accuracy} | Agi ${row.agility} | Luck ${row.luck}</div>
        </div>
      `).join("")}
    </div>
  `;
}

function crystalCharacterSkillPageHtml() {
  const spells = characterSkillSpells();
  if (!spells.length) {
    return `<span class="crystal-character-page-note">${escapeHtml(state.battle.combatClass)} spells not added yet</span>`;
  }
  return `
    <div class="crystal-skill-list" data-preserve-scroll="character-skills">
      ${spells.map((spell) => crystalSkillRowHtml(spell, learnedMagic(spell.id))).join("")}
    </div>
  `;
}

function characterSkillSpells(classId = state.battle.combatClass) {
  if (classId === "Warrior") return CRYSTAL_WARRIOR_SPELLS;
  if (classId === "Wizard") return CRYSTAL_WIZARD_SPELLS;
  if (classId === "Taoist") return CRYSTAL_TAOIST_SPELLS;
  return [];
}

function crystalSkillRowHtml(spell, learned) {
  const isLearned = Boolean(learned);
  const level = isLearned ? Number(learned?.level) || 0 : 0;
  const nextNeed = spellExperienceTarget(spell, level);
  const nextLevel = spellLevelRequirement(spell, level);
  const progress = !isLearned ? "Unlearned" : level >= 3 ? "Mastered" : `${learned?.experience ?? 0}/${nextNeed}`;
  const mp = spellMpCost(spell, learned);
  const cooldown = spellDelayMs(spell, learned);
  const controlLabel = spell.toggle ? "toggle" : "auto cast";
  const combatClass = combatAutoCastClassForSpell(spell.id);
  const combatAutoSpell = Boolean(combatClass);
  const autoLimitReached = isLearned
    && combatAutoSpell
    && !learned?.autoCast
    && autoCastSlotsUsed(combatClass) >= autoCastSlotLimit();
  const queued = isLearned && combatClass && isQueuedCombatSpell(spell.id, combatClass);
  const autoLabel = learned?.autoCast ? "On" : autoLimitReached ? "Max" : "Off";
  const autoTitle = queued
    ? `${spell.label} is queued as the next manual cast`
    : learned?.autoCast
    ? `Disable ${controlLabel}`
    : autoLimitReached
    ? `Autocast slots full (${autoCastSlotsUsed(combatClass)}/${autoCastSlotLimit()})`
    : `Enable ${controlLabel}`;
  const autoControl = !isLearned
    ? ""
    : spell.passive
    ? `<span class="crystal-skill-passive">Passive</span>`
    : `<button class="crystal-skill-auto ${learned?.autoCast ? "active" : ""} ${queued ? "queued" : ""}" type="button" data-toggle-skill-auto="${escapeHtml(spell.id)}" title="${escapeHtml(autoTitle)}">${autoLabel}</button>`;
  const meta = isLearned
    ? spell.passive
      ? `${level >= 3 ? "Done" : `Req ${nextLevel}`} | Passive | ${spellDropZoneText(spell)}`
      : spell.toggle
      ? `${level >= 3 ? "Done" : `Req ${nextLevel}`} | Toggle | 2 tiles | ${spellDropZoneText(spell)}`
      : `${level >= 3 ? "Done" : `Req ${nextLevel}`} | MP ${mp} | ${Math.round(cooldown / 1000)}s | ${spellDropZoneText(spell)}`
    : spellDropZoneText(spell);
  return `
    <div class="crystal-skill-row ${spell.passive ? "passive" : ""} ${learned?.autoCast ? "auto" : ""} ${queued ? "queued" : ""} ${isLearned ? "" : "unlearned"}">
      <img src="${escapeHtml(magicIconSrc(spell))}" alt="" />
      <span class="crystal-skill-name">${escapeHtml(spell.label)}</span>
      <span class="crystal-skill-level">${isLearned ? `Lv ${level}` : "Lv -"}</span>
      ${autoControl}
      <span class="crystal-skill-exp">${escapeHtml(progress)}</span>
      <span class="crystal-skill-meta">${escapeHtml(meta)}</span>
    </div>
  `;
}

function crystalStatusValueHtml(row, stats) {
  const value = characterStatusValue(row.key, stats);
  return `<span class="crystal-status-value" style="left:${row.x}px; top:${row.y}px;">${escapeHtml(value)}</span>`;
}

function characterStatusValue(key, stats) {
  const values = {
    hp: `${stats.hp ?? stats.maxHp}/${stats.maxHp}`,
    mp: `${stats.mp ?? stats.maxMp}/${stats.maxMp}`,
    ac: formatStatRange(stats.ac),
    amc: formatStatRange(stats.amc),
    dc: formatStatRange(stats.dc),
    mc: formatStatRange(stats.mc),
    sc: formatStatRange(stats.sc),
    critRate: "0%",
    critDamage: "0",
    attackSpeed: characterAttackSpeedLabel(),
    accuracy: `+${stats.accuracy}`,
    agility: `+${stats.agility}`,
    luck: String(stats.luck),
  };
  return values[key] ?? "";
}

function equippedItem(slotId) {
  const entry = equippedEntry(slotId);
  return entry ? itemDefinition(entry.itemId) : null;
}

function crystalEquipmentSlotHtml(slot) {
  const entry = equippedEntry(slot.id);
  const item = entry ? itemDefinition(entry.itemId) : null;
  const position = CRYSTAL_EQUIPMENT_SLOT_POSITIONS[slot.id] ?? { x: 0, y: 0 };
  const content = entry && item ? crystalEquipmentItemHtml(entry, item, slot.id) : "";
  return `
    <div
      class="crystal-equipment-slot ${item ? "has-tooltip" : ""}"
      data-equipment-slot="${slot.id}"
      ${item ? `data-tooltip-item="${item.id}"` : ""}
      ${entry ? `data-tooltip-entry="${entry.id}"` : ""}
      title="${escapeHtml(slot.label)}"
      style="left:${8 + position.x}px; top:${90 + position.y}px;"
    >
      ${content}
    </div>
  `;
}

function crystalEquipmentItemHtml(entry, item, slotId) {
  return `
    <div
      class="crystal-equipment-item has-tooltip"
      data-tooltip-item="${item.id}"
      data-tooltip-entry="${entry.id}"
      data-inventory-entry="${entry.id}"
      data-equipped-slot="${slotId}"
      draggable="false"
      title="${escapeHtml(itemDisplayName(item, entry))}"
    >
      ${itemIconMarkup(item)}
    </div>
  `;
}

function inventorySceneHtml() {
  ensureInventorySlots();
  const pageCount = inventoryPageCount();
  if (!inventoryPageUnlocked(state.inventoryPage)) state.inventoryPage = 0;
  const pageStart = state.inventoryPage * INVENTORY_PAGE_SIZE;
  const visibleSlots = Math.min(INVENTORY_PAGE_SIZE, state.inventory.maxSlots - pageStart);
  return `
    <section class="crystal-inventory" aria-label="Inventory">
      ${inventoryPageTabsHtml(pageCount)}
      <span class="crystal-inventory-gold">${state.inventory.gold}</span>
      <button type="button" class="crystal-inventory-sort" data-sort-inventory title="Sort inventory">Sort</button>
      <span class="crystal-inventory-weight">${inventoryUsedSlots()}/${state.inventory.maxSlots}</span>
      ${Array.from({ length: visibleSlots }, (_, index) => crystalInventorySlotHtml(pageStart + index, index)).join("")}
    </section>
  `;
}

function storageSceneHtml() {
  ensureStorageSlots();
  const pageCount = storagePageCount();
  if (!storagePageUnlocked(state.storagePage)) state.storagePage = 0;
  const pageStart = state.storagePage * STORAGE_PAGE_SIZE;
  const visibleSlots = Math.min(STORAGE_PAGE_SIZE, state.account.storage.maxSlots - pageStart);
  return `
    <section class="crystal-storage" aria-label="Storage">
      <span class="crystal-storage-title" aria-hidden="true"></span>
      ${storagePageTabsHtml(pageCount)}
      ${storagePageUnlockConfirmHtml()}
      <span class="crystal-storage-count">${storageUsedSlots()}/${state.account.storage.maxSlots}</span>
      ${Array.from({ length: visibleSlots }, (_, index) => crystalStorageSlotHtml(pageStart + index, index)).join("")}
    </section>
  `;
}

function crystalStorageSlotHtml(slot, displayIndex = slot) {
  const entry = storageEntryAtSlot(slot);
  const x = 9 + (displayIndex % STORAGE_COLUMNS) * 37;
  const y = 60 + Math.floor(displayIndex / STORAGE_COLUMNS) * 33;
  const item = entry ? itemDefinition(entry.itemId) : null;
  const content = entry && item ? crystalStorageItemHtml(entry, item) : "";
  return `
    <div class="crystal-storage-slot" data-storage-slot="${slot}" style="left:${x}px; top:${y}px;">
      ${content}
    </div>
  `;
}

function crystalStorageItemHtml(entry, item) {
  const stack = isStackableItem(item) && entry.quantity > 1 ? `<span class="crystal-item-qty">${entry.quantity}</span>` : "";
  return `
    <div
      class="crystal-storage-item has-tooltip"
      data-tooltip-item="${item.id}"
      data-tooltip-entry="${entry.id}"
      data-storage-entry="${entry.id}"
      draggable="false"
      title="${escapeHtml(itemDisplayName(item, entry))}"
    >
      ${itemIconMarkup(item)}
      ${stack}
    </div>
  `;
}

function inventoryPageTabsHtml(pageCount = inventoryPageCount()) {
  return Array.from({ length: pageCount }, (_, page) => {
    const active = page === state.inventoryPage ? " active" : "";
    const secondary = page > 0 ? " secondary" : "";
    const locked = inventoryPageUnlocked(page) ? "" : " locked";
    const left = page === 0 ? 6 : 76 + (page - 1) * 70;
    const label = page === 0 ? "" : inventoryPageUnlocked(page) ? `ITEMS ${page + 1}` : `${inventoryPageUnlockCost(page).toLocaleString()}g`;
    const title = inventoryPageUnlocked(page) ? `Items ${page + 1}` : `Unlock Items ${page + 1} for ${inventoryPageUnlockCost(page).toLocaleString()} gold`;
    return `
      <button
        class="crystal-inventory-tab${active}${secondary}${locked}"
        type="button"
        data-inventory-page="${page}"
        style="left:${left}px;"
        title="${title}"
      >${label}</button>
    `;
  }).join("");
}

function storagePageTabsHtml(pageCount = storagePageCount()) {
  return Array.from({ length: pageCount }, (_, page) => {
    const pageClass = page === 0 ? "page-1" : "page-2";
    const active = page === state.storagePage ? " active" : "";
    const locked = storagePageUnlocked(page) ? "" : " locked";
    const title = storagePageUnlocked(page)
      ? `Storage ${page + 1}`
      : `Unlock Storage ${page + 1} for ${storagePageUnlockCost(page).toLocaleString()} gold`;
    return `
      <button
        class="crystal-storage-page ${pageClass}${active}${locked}"
        type="button"
        data-storage-page="${page}"
        title="${title}"
        aria-label="${title}"
      ></button>
    `;
  }).join("");
}

function storagePageUnlockConfirmHtml() {
  const page = state.pendingStoragePageUnlock;
  if (page === null || !Number.isInteger(page) || storagePageUnlocked(page)) {
    return "";
  }
  const cost = storagePageUnlockCost(page);
  const canAfford = state.inventory.gold >= cost;
  return `
    <div class="crystal-storage-unlock-confirm" role="dialog" aria-label="Confirm storage unlock">
      <p class="crystal-storage-unlock-text">
        Unlock Storage ${page + 1} for <strong>${cost.toLocaleString()}</strong> gold?
      </p>
      <div class="crystal-storage-unlock-actions">
        <button
          type="button"
          class="crystal-storage-unlock-confirm-btn"
          data-confirm-storage-page-unlock="${page}"
          ${canAfford ? "" : "disabled"}
        >Unlock</button>
        <button type="button" class="crystal-storage-unlock-cancel-btn" data-cancel-storage-page-unlock>Cancel</button>
      </div>
      ${canAfford ? "" : `<p class="crystal-storage-unlock-note">Need ${cost.toLocaleString()} gold (you have ${state.inventory.gold.toLocaleString()}).</p>`}
    </div>
  `;
}

function crystalInventorySlotHtml(slot, displaySlot = slot) {
  const entry = inventoryEntryAtSlot(slot);
  const x = 9 + (displaySlot % 8) * 37;
  const y = 37 + Math.floor(displaySlot / 8) * 33;
  const item = entry ? itemDefinition(entry.itemId) : null;
  const content = entry && item ? crystalInventoryItemHtml(entry, item) : "";
  return `
    <div class="crystal-inventory-slot" data-inventory-slot="${slot}" style="left:${x}px; top:${y}px;">
      ${content}
    </div>
  `;
}

function crystalInventoryItemHtml(entry, item) {
  const equipped = isEquippedEntry(entry.id);
  const requirement = itemRequirementStatus(item, characterEquipmentStats());
  const stack = isStackableItem(item) && entry.quantity > 1 ? `<span class="crystal-item-qty">${entry.quantity}</span>` : "";
  const locked = !requirement.ok && (isEquipableItem(item) || isBookItem(item));
  return `
    <div
      class="crystal-inventory-item has-tooltip ${equipped ? "equipped" : ""} ${locked ? "locked" : ""}"
      data-tooltip-item="${item.id}"
      data-tooltip-entry="${entry.id}"
      data-inventory-entry="${entry.id}"
      draggable="false"
      title="${escapeHtml(itemDisplayName(item, entry))}"
    >
      ${itemIconMarkup(item)}
      ${stack}
    </div>
  `;
}

function characterEquipmentStats() {
  const stats = cloneStats({
    ...PLAYER_TEMPLATE,
    ...crystalPlayerBaseStats(state.battle.combatClass ?? PLAYER_TEMPLATE.class, state.game.progress.level),
  });
  applyRebirthUpgradeStats(stats);
  for (const slot of EQUIPMENT_SLOTS) {
    const entry = equippedEntry(slot.id);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (item?.stats) addStats(stats, itemEntryStats(entry, item));
  }
  applyLearnedMagicStats(stats);
  return stats;
}

function characterTotalStats() {
  const stats = characterEquipmentStats();
  applyStatBuffsToStats(stats, pruneStatBuffs(state.battle.statBuffs ?? []));
  stats.hp = state.battle.player?.hp ?? stats.maxHp;
  stats.mp = state.battle.player?.mp ?? stats.maxMp;
  return stats;
}

function applyLearnedMagicStats(stats) {
  applyLearnedMagicStatsForClass(stats, state.battle.combatClass, state.magic);
}

function characterSnapshotTotalStats(classId, character, options = {}) {
  const includeBuffs = options.includeBuffs !== false;
  const level = Math.max(1, Math.trunc(Number(character?.game?.progress?.level) || PLAYER_TEMPLATE.level));
  const stats = cloneStats({
    ...PLAYER_TEMPLATE,
    ...crystalPlayerBaseStats(classId ?? PLAYER_TEMPLATE.class, level),
  });
  applyRebirthUpgradeStats(stats);
  const inventory = character?.inventory ?? createStarterInventoryState(classId);
  for (const slot of EQUIPMENT_SLOTS) {
    const entryId = inventory.equipment?.[slot.id] ?? null;
    const entry = inventory.items?.find((candidate) => candidate.id === entryId) ?? null;
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (item?.stats) addStats(stats, itemEntryStats(entry, item));
  }
  applyLearnedMagicStatsForClass(stats, classId, character?.magic ?? { learned: {} });
  if (includeBuffs) {
    applyStatBuffsToStats(stats, sanitizeStatBuffs(character?.battle?.statBuffs));
  }
  const savedHp = finiteNumberOrNull(character?.battle?.playerHp);
  const savedMp = finiteNumberOrNull(character?.battle?.playerMp);
  stats.hp = savedHp == null ? stats.maxHp : Math.max(0, Math.min(stats.maxHp, savedHp));
  stats.mp = savedMp == null ? stats.maxMp : Math.max(0, Math.min(stats.maxMp, savedMp));
  return stats;
}

function applyLearnedMagicStatsForClass(stats, classId, magic = state.magic) {
  const learnedFor = (spellId) => magic?.learned?.[spellId] ?? null;
  if (classId === "Warrior") {
    const fencing = learnedFor("Fencing");
    if (fencing) stats.accuracy += Math.max(0, Number(fencing.level) || 0) * 3;
    const slaying = learnedFor("Slaying");
    if (slaying) {
      const slayingMaxDcBonus = [5, 6, 7, 8][Math.max(0, Math.min(3, Number(slaying.level) || 0))] ?? 5;
      stats.accuracy += Math.max(0, Number(slaying.level) || 0);
      stats.dc[1] += slayingMaxDcBonus;
    }
  }

  if (classId === "Taoist") {
    const spiritSword = learnedFor("SpiritSword");
    if (spiritSword) {
      const spiritSwordAccuracyBonus = [0, 3, 5, 8][Math.max(0, Math.min(3, Number(spiritSword.level) || 0))] ?? 0;
      stats.accuracy += spiritSwordAccuracyBonus;
    }
  }
}

function statListHtml(stats) {
  return `
    <dl class="stat-list">
      <dt>HP</dt><dd>${stats.hp ?? stats.maxHp}/${stats.maxHp}</dd>
      <dt>MP</dt><dd>${stats.mp ?? stats.maxMp}/${stats.maxMp}</dd>
      <dt>DC</dt><dd>${formatStatRange(stats.dc)}</dd>
      <dt>MC</dt><dd>${formatStatRange(stats.mc)}</dd>
      <dt>SC</dt><dd>${formatStatRange(stats.sc)}</dd>
      <dt>AC</dt><dd>${formatStatRange(stats.ac)}</dd>
      <dt>AMC</dt><dd>${formatStatRange(stats.amc)}</dd>
      <dt>Acc</dt><dd>${stats.accuracy}</dd>
      <dt>Agi</dt><dd>${stats.agility}</dd>
      <dt>Luck</dt><dd>${stats.luck}</dd>
      <dt>A Speed</dt><dd>${characterAttackSpeedLabel()}</dd>
    </dl>
  `;
}

function equipmentSlotHtml(slot) {
  const entry = equippedEntry(slot.id);
  const item = entry ? itemDefinition(entry.itemId) : null;
  return `
    <div class="equipment-slot ${item ? "has-tooltip" : ""}" data-equipment-slot="${slot.id}" ${item ? `data-tooltip-item="${item.id}" data-tooltip-entry="${entry.id}"` : ""}>
      <span>${slot.label}</span>
      <strong>${item ? escapeHtml(itemDisplayName(item, entry)) : "Empty"}</strong>
      ${item ? `<button data-unequip-slot="${slot.id}">Unequip</button>` : ""}
    </div>
  `;
}

function beginInventoryClickCarry(event, itemElement) {
  const refineBoardKind = itemElement.dataset.refineBoardKind ?? null;
  const refineBoardIndex = Number(itemElement.dataset.refineBoardIndex);
  const sourceContainer = refineBoardKind
    ? "weaponRefine"
    : itemElement.dataset.storageEntry
      ? "storage"
      : "inventory";
  const entryId = itemElement.dataset.refineBoardEntry
    ?? itemElement.dataset.storageEntry
    ?? itemElement.dataset.inventoryEntry;
  const entry = sourceContainer === "storage"
    ? storageEntryById(entryId)
    : sourceContainer === "weaponRefine"
      ? weaponRefineEntryById(entryId)
      : inventoryEntryById(entryId);
  if (!entry) return false;
  cleanupInventoryCarry();
  const rect = itemElement.getBoundingClientRect();
  const ghost = itemElement.cloneNode(true);
  ghost.classList.remove("dragging", "locked");
  ghost.classList.add("inventory-drag-ghost");
  ghost.style.width = `${rect.width}px`;
  ghost.style.height = `${rect.height}px`;
  document.body.appendChild(ghost);
  inventoryDragState = {
    entryId,
    sourceContainer,
    sourceEquipmentSlot: itemElement.dataset.equippedSlot ?? null,
    refineBoardSlot: refineBoardKind
      ? { kind: refineBoardKind, index: Math.max(0, refineBoardIndex) }
      : null,
    source: itemElement,
    ghost,
    dropTarget: null,
    offsetX: rect.width / 2,
    offsetY: rect.height / 2,
  };
  itemElement.classList.add("dragging");
  hideItemTooltip();
  updateInventoryCarryPointer(event);
  playSfx("item.move", { volume: 0.32, throttleMs: 80 });
  return true;
}

function updateInventoryCarryPointer(event) {
  if (!inventoryDragState) return;
  inventoryDragState.ghost.style.left = `${event.clientX - inventoryDragState.offsetX}px`;
  inventoryDragState.ghost.style.top = `${event.clientY - inventoryDragState.offsetY}px`;
  setInventoryDropTarget(inventoryDropTargetAt(event));
}

function handleInventoryCarryClick(event) {
  if (inventoryDragState) {
    finishInventoryClickCarry(event);
    return true;
  }

  const commandTarget = event.target.closest(
    "[data-use-entry], [data-equip-entry], [data-sell-entry], [data-buy-item], [data-buy-stack], [data-buy-account-upgrade], [data-smith-combine], [data-cast-combat-skill], [data-toggle-skill-auto], [data-unequip-slot], [data-sort-inventory], [data-confirm-inventory-destroy], [data-confirm-inventory-destroy-suppress], [data-cancel-inventory-destroy]",
  );
  if (commandTarget && root.contains(commandTarget)) return false;

  const itemElement = event.target.closest("[data-inventory-entry], [data-storage-entry], [data-refine-board-entry]");
  if (!itemElement || !root.contains(itemElement)) return false;
  event.preventDefault();
  return beginInventoryClickCarry(event, itemElement);
}

function finishInventoryClickCarry(event) {
  const carry = inventoryDragState;
  const dropTarget = inventoryDropTargetAt(event);
  cleanupInventoryCarry();
  event.preventDefault();
  if (!carry) return false;
  if (!dropTarget) {
    if (carry.sourceContainer === "weaponRefine" && carry.refineBoardSlot) {
      clearWeaponRefineSlot(carry.refineBoardSlot.kind, carry.refineBoardSlot.index);
    } else if (carry.sourceContainer === "inventory") {
      void confirmDestroyInventoryEntry(carry.entryId);
    }
    return false;
  }

  const refineSlot = dropTarget.closest("[data-refine-slot]");
  if (refineSlot && root.contains(refineSlot)) {
    const kind = refineSlot.dataset.refineSlot;
    const index = Number(refineSlot.dataset.refineIndex) || 0;
    if ((kind === "ore" || kind === "material")
      && (carry.sourceContainer === "inventory" || carry.sourceContainer === "weaponRefine")) {
      assignWeaponRefineSlot(
        kind,
        index,
        carry.entryId,
        { fromRefine: carry.sourceContainer === "weaponRefine" ? carry.refineBoardSlot : null },
      );
      return true;
    }
  }

  const equipmentSlot = dropTarget.closest("[data-equipment-slot]");
  if (equipmentSlot && root.contains(equipmentSlot)) {
    const slotId = equipmentSlot.dataset.equipmentSlot;
    if (carry.sourceContainer === "inventory") {
      const sourceEntry = inventoryEntryById(carry.entryId);
      const sourceItem = itemDefinition(sourceEntry?.itemId);
      const slotEntry = equippedEntry(slotId);
      if (isGemUpgradeItem(sourceItem) && slotEntry) {
        applyGemUpgrade(carry.entryId, slotEntry.id);
        return true;
      }
    }
    if (carry.sourceContainer === "storage") {
      const check = canEquipStorageEntryToSlot(carry.entryId, slotId);
      if (check.ok) equipStorageEntryToSlot(carry.entryId, slotId);
      else rejectInventoryMove(check.reason);
    } else {
      const check = canEquipEntryToSlot(carry.entryId, slotId);
      if (check.ok) equipInventoryEntryToSlot(carry.entryId, slotId);
      else rejectInventoryMove(check.reason);
    }
    return true;
  }

  const targetInventoryEntry = dropTarget.closest("[data-inventory-entry]");
  if (targetInventoryEntry && root.contains(targetInventoryEntry) && carry.sourceContainer === "inventory") {
    const targetEntryId = targetInventoryEntry.dataset.inventoryEntry;
    if (targetEntryId && targetEntryId !== carry.entryId) {
      const sourceItem = itemDefinition(inventoryEntryById(carry.entryId)?.itemId);
      const targetItem = itemDefinition(inventoryEntryById(targetEntryId)?.itemId);
      if (isGemUpgradeItem(sourceItem) && isEquipableItem(targetItem)) {
        applyGemUpgrade(carry.entryId, targetEntryId);
        return true;
      }
      combineInventoryStackEntries(carry.entryId, targetEntryId);
    }
    return true;
  }

  const targetStorageEntry = dropTarget.closest("[data-storage-entry]");
  if (targetStorageEntry && root.contains(targetStorageEntry) && carry.sourceContainer === "storage") {
    const targetEntryId = targetStorageEntry.dataset.storageEntry;
    if (targetEntryId && targetEntryId !== carry.entryId) {
      combineStorageStackEntries(carry.entryId, targetEntryId);
    }
    return true;
  }

  const storageSlot = dropTarget.closest("[data-storage-slot]");
  if (storageSlot && root.contains(storageSlot)) {
    const targetSlot = Number(storageSlot.dataset.storageSlot);
    if (carry.sourceContainer === "storage") {
      if (canDropEntryToStorageSlot(carry.entryId, targetSlot, "storage").ok) moveStorageEntryToStorageSlot(carry.entryId, targetSlot);
    } else if (canDropEntryToStorageSlot(carry.entryId, targetSlot, "inventory").ok) {
      storeInventoryEntryInStorage(carry.entryId, targetSlot, carry.sourceEquipmentSlot);
    }
    return true;
  }

  const hotbarSlot = dropTarget.closest("[data-hotbar-slot]");
  if (hotbarSlot && root.contains(hotbarSlot)) {
    if (carry.sourceContainer === "storage") return true;
    const targetSlot = Number(hotbarSlot.dataset.hotbarSlot);
    if (canDropEntryToHotbarSlot(carry.entryId, targetSlot).ok) dropInventoryEntryToHotbarSlot(carry.entryId, targetSlot);
    return true;
  }

  const inventorySlot = dropTarget.closest("[data-inventory-slot]");
  if (inventorySlot && root.contains(inventorySlot)) {
    if (carry.sourceContainer === "weaponRefine" && carry.refineBoardSlot) {
      clearWeaponRefineSlot(
        carry.refineBoardSlot.kind,
        carry.refineBoardSlot.index,
        { targetSlot: Number(inventorySlot.dataset.inventorySlot) },
      );
      return true;
    }
    const targetSlot = Number(inventorySlot.dataset.inventorySlot);
    if (carry.sourceContainer === "storage") {
      if (canWithdrawStorageEntryToInventorySlot(carry.entryId, targetSlot).ok) withdrawStorageEntryToInventorySlot(carry.entryId, targetSlot);
    } else if (canDropEntryToInventorySlot(carry.entryId, targetSlot, carry.sourceEquipmentSlot).ok) {
      dropInventoryEntryToInventorySlot(carry.entryId, targetSlot, carry.sourceEquipmentSlot);
    }
    return true;
  }

  return false;
}

function cleanupInventoryCarry() {
  if (!inventoryDragState) return;
  inventoryDragState.dropTarget?.classList.remove("drag-over", "drag-invalid");
  inventoryDragState.source?.classList.remove("dragging");
  inventoryDragState.ghost?.remove();
  inventoryDragState = null;
}

async function confirmDestroyInventoryEntry(entryId) {
  const entry = inventoryEntryById(entryId);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !item) return false;
  if (inventoryDestroyConfirmSuppressed()) {
    await destroyInventoryEntry(entry.id);
    return true;
  }
  state.pendingInventoryDestroyEntryId = entry.id;
  hideItemTooltip();
  sceneSignature = "";
  renderSceneOverlay();
  return true;
}

function inventoryDestroyConfirmSuppressed(now = Date.now()) {
  return Math.max(0, Number(state.inventoryDestroyConfirmSuppressUntil) || 0) > now;
}

function inventoryDestroyConfirmHtml() {
  const entryId = state.pendingInventoryDestroyEntryId;
  if (!entryId) return "";
  const entry = inventoryEntryById(entryId);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !item) {
    state.pendingInventoryDestroyEntryId = null;
    return "";
  }
  const quantity = Math.max(1, Math.trunc(Number(entry.quantity) || 1));
  const label = `${quantity > 1 ? `${quantity}x ` : ""}${itemDisplayName(item, entry)}`;
  return `
    <div class="inventory-destroy-confirm" role="dialog" aria-modal="true" aria-label="Destroy item confirmation">
      <div class="inventory-destroy-confirm-window">
        <button type="button" class="inventory-destroy-close" data-cancel-inventory-destroy aria-label="Cancel destroy item">X</button>
        <div class="inventory-destroy-title">Destroy Item</div>
        <div class="inventory-destroy-item has-tooltip" data-tooltip-item="${escapeHtml(item.id)}" data-tooltip-entry="${escapeHtml(entry.id)}">
          ${itemIconMarkup(item)}
          <strong>${escapeHtml(label)}</strong>
        </div>
        <p>This will destroy the item.</p>
        <p>Are you sure?</p>
        <div class="inventory-destroy-actions">
          <button type="button" class="wide danger" data-confirm-inventory-destroy-suppress="${escapeHtml(entry.id)}">Yes, don't ask me again for 5 minutes</button>
          <button type="button" class="danger" data-confirm-inventory-destroy="${escapeHtml(entry.id)}">Destroy</button>
          <button type="button" data-cancel-inventory-destroy>Cancel</button>
        </div>
      </div>
    </div>
  `;
}

function cancelInventoryDestroyConfirm() {
  state.pendingInventoryDestroyEntryId = null;
  hideItemTooltip();
  sceneSignature = "";
  renderSceneOverlay();
}

async function confirmPendingInventoryDestroy(entryId) {
  const pendingId = state.pendingInventoryDestroyEntryId;
  if (!pendingId || pendingId !== entryId) return false;
  state.pendingInventoryDestroyEntryId = null;
  return destroyInventoryEntry(pendingId);
}

async function confirmPendingInventoryDestroyAndSuppress(entryId) {
  const pendingId = state.pendingInventoryDestroyEntryId;
  if (!pendingId || pendingId !== entryId) return false;
  state.inventoryDestroyConfirmSuppressUntil = Date.now() + 5 * 60 * 1000;
  state.pendingInventoryDestroyEntryId = null;
  return destroyInventoryEntry(pendingId);
}

async function destroyInventoryEntry(entryId) {
  const entry = inventoryEntryById(entryId);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !item) return false;
  if (state.pendingInventoryDestroyEntryId === entry.id) state.pendingInventoryDestroyEntryId = null;
  const displayName = itemDisplayName(item, entry);
  const equippedSlot = equippedSlotForEntry(entry.id);
  if (equippedSlot) state.inventory.equipment[equippedSlot] = null;
  clearHotbarEntry(entry.id);
  state.inventory.items = state.inventory.items.filter((candidate) => candidate.id !== entry.id);
  ensureInventorySlots();
  syncBossPartyControlledInventoryFromState();
  hideItemTooltip();
  pushBattleLog(`${displayName} destroyed.`);
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  hotbarSignature = "";
  playSfx("item.move", { volume: 0.36, throttleMs: 80 });
  saveGameState(true);
  if (equippedSlot) {
    await applyEquipmentChanges();
  } else {
    renderHotbar();
    renderSceneOverlay();
    renderGamePanel();
    renderBattlePanel();
  }
  return true;
}

function inventoryDropTargetAt(event) {
  const target = document.elementFromPoint(event.clientX, event.clientY);
  const dropTarget = target?.closest?.(
    "[data-inventory-entry], [data-storage-entry], [data-inventory-slot], [data-equipment-slot], [data-hotbar-slot], [data-storage-slot], [data-refine-slot]",
  );
  return dropTarget && root.contains(dropTarget) ? dropTarget : null;
}

function setInventoryDropTarget(dropTarget) {
  if (!inventoryDragState || inventoryDragState.dropTarget === dropTarget) return;
  inventoryDragState.dropTarget?.classList.remove("drag-over", "drag-invalid");
  inventoryDragState.dropTarget = dropTarget;
  if (!inventoryDragState.dropTarget) return;
  inventoryDragState.dropTarget.classList.add(inventoryDropTargetAccepts(dropTarget) ? "drag-over" : "drag-invalid");
}

function inventoryDropTargetAccepts(dropTarget) {
  if (!inventoryDragState || !dropTarget) return false;
  const sourceEntry = inventoryDragState.sourceContainer === "inventory"
    ? inventoryEntryById(inventoryDragState.entryId)
    : inventoryDragState.sourceContainer === "storage"
      ? storageEntryById(inventoryDragState.entryId)
      : null;
  const sourceItem = sourceEntry ? itemDefinition(sourceEntry.itemId) : null;
  const equipmentSlot = dropTarget.closest("[data-equipment-slot]");
  if (equipmentSlot && root.contains(equipmentSlot)) {
    if (isGemUpgradeItem(sourceItem) && inventoryDragState.sourceContainer === "inventory") {
      const slotEntry = equippedEntry(equipmentSlot.dataset.equipmentSlot);
      return Boolean(slotEntry && canApplyGemToEntry(inventoryDragState.entryId, slotEntry.id).ok);
    }
    if (inventoryDragState.sourceContainer === "storage") {
      return canEquipStorageEntryToSlot(inventoryDragState.entryId, equipmentSlot.dataset.equipmentSlot).ok;
    }
    return canEquipEntryToSlot(inventoryDragState.entryId, equipmentSlot.dataset.equipmentSlot).ok;
  }
  const targetInventoryEntry = dropTarget.closest("[data-inventory-entry]");
  if (targetInventoryEntry && root.contains(targetInventoryEntry) && inventoryDragState.sourceContainer === "inventory") {
    const targetEntryId = targetInventoryEntry.dataset.inventoryEntry;
    if (!targetEntryId || targetEntryId === inventoryDragState.entryId) return true;
    if (isGemUpgradeItem(sourceItem)) {
      return canApplyGemToEntry(inventoryDragState.entryId, targetEntryId).ok;
    }
    const targetEntry = inventoryEntryById(targetEntryId);
    return stackEntriesCombinable(sourceEntry, targetEntry);
  }
  const targetStorageEntry = dropTarget.closest("[data-storage-entry]");
  if (targetStorageEntry && root.contains(targetStorageEntry) && inventoryDragState.sourceContainer === "storage") {
    const targetEntryId = targetStorageEntry.dataset.storageEntry;
    if (!targetEntryId || targetEntryId === inventoryDragState.entryId) return true;
    const sourceEntry = storageEntryById(inventoryDragState.entryId);
    const targetEntry = storageEntryById(targetEntryId);
    return stackEntriesCombinable(sourceEntry, targetEntry);
  }
  const storageSlot = dropTarget.closest("[data-storage-slot]");
  if (storageSlot && root.contains(storageSlot)) {
    return canDropEntryToStorageSlot(
      inventoryDragState.entryId,
      Number(storageSlot.dataset.storageSlot),
      inventoryDragState.sourceContainer,
      inventoryDragState.sourceEquipmentSlot,
    ).ok;
  }
  const inventorySlot = dropTarget.closest("[data-inventory-slot]");
  if (inventorySlot && root.contains(inventorySlot)) {
    if (inventoryDragState.sourceContainer === "weaponRefine") return true;
    if (inventoryDragState.sourceContainer === "storage") {
      return canWithdrawStorageEntryToInventorySlot(inventoryDragState.entryId, Number(inventorySlot.dataset.inventorySlot)).ok;
    }
    return canDropEntryToInventorySlot(
      inventoryDragState.entryId,
      Number(inventorySlot.dataset.inventorySlot),
      inventoryDragState.sourceEquipmentSlot,
    ).ok;
  }
  const hotbarSlot = dropTarget.closest("[data-hotbar-slot]");
  if (hotbarSlot && root.contains(hotbarSlot)) {
    if (inventoryDragState.sourceContainer === "storage") return false;
    return canDropEntryToHotbarSlot(inventoryDragState.entryId, Number(hotbarSlot.dataset.hotbarSlot)).ok;
  }
  const refineSlot = dropTarget.closest("[data-refine-slot]");
  if (refineSlot && root.contains(refineSlot)) {
    const kind = refineSlot.dataset.refineSlot;
    const index = Number(refineSlot.dataset.refineIndex) || 0;
    if (kind !== "ore" && kind !== "material") return false;
    if (inventoryDragState.sourceContainer === "storage") return false;
    const entry = weaponRefineEntryById(inventoryDragState.entryId) ?? inventoryEntryById(inventoryDragState.entryId);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (kind === "ore") return canPlaceWeaponRefineOre(entry, item, index);
    return canPlaceWeaponRefineMaterial(entry, item, index);
  }
  return false;
}

function inventoryItemHtml(entry) {
  const item = itemDefinition(entry.itemId);
  if (!item) return `<div class="inventory-item missing"><span>?</span><strong>${escapeHtml(entry.itemId)}</strong></div>`;
  const stack = isStackableItem(item) ? `<span class="item-qty">${entry.quantity}</span>` : "";
  const equipped = isEquippedEntry(entry.id);
  const requirement = itemRequirementStatus(item);
  const locked = !requirement.ok && (isEquipableItem(item) || isBookItem(item));
  const tag = equipped ? "Equipped" : isStackableItem(item) ? `Stack ${entry.quantity}/${maxItemStack(item)}` : "Item";
  const command = isEquipableItem(item)
    ? `<button data-equip-entry="${entry.id}" ${equipped || !requirement.ok ? "disabled" : ""}>${equipped ? "Equipped" : requirement.ok ? "Equip" : "Locked"}</button>`
    : isPotionItem(item) || isBenedictionOilItem(item)
    ? `<button data-use-entry="${entry.id}">Use</button>`
    : "";
  return `
    <div class="inventory-item has-tooltip ${equipped ? "equipped" : ""} ${locked ? "locked" : ""}" data-tooltip-item="${item.id}" data-tooltip-entry="${entry.id}">
      ${itemIconMarkup(item)}
      ${stack}
      <strong>${escapeHtml(itemDisplayName(item, entry))}</strong>
      <span>${requirement.ok ? tag : requirement.reason}</span>
      ${command}
    </div>
  `;
}

function itemTooltipHtml(item, entry = null) {
  return `
    <strong>${escapeHtml(itemDisplayName(item, entry))}</strong>
    <span>${escapeHtml(title(item.type))}${item.slot ? ` | ${escapeHtml(slotLabel(item.slot))}` : ""}</span>
    ${entry?.refineLevel ? `<span>Smith: +${Math.max(0, Math.trunc(Number(entry.refineLevel) || 0))}</span>` : ""}
    ${entry?.gemCount ? `<span>Gem upgrades: ${Math.max(0, Math.trunc(Number(entry.gemCount) || 0))}</span>` : ""}
    ${entry?.weaponRefineLevel ? `<span>Refine: +${Math.max(0, Math.trunc(Number(entry.weaponRefineLevel) || 0))} / ${WEAPON_REFINE_MAX}</span>` : ""}
    ${entry && isOreItem(item) ? itemOreTooltipHtml(entry, item) : ""}
    ${entry && itemUsesEntryDurability(item) && !isOreItem(item) ? itemDurabilityTooltipHtml(entry, item) : ""}
    ${item.source?.name ? `<span>Crystal: ${escapeHtml(item.source.name)} #${item.source.crystalIndex}</span>` : ""}
    ${item.visual ? `<span>Visual: ${escapeHtml(item.visual.layer)} ${item.visual.index}</span>` : ""}
    ${itemSpellTooltipHtml(item)}
    ${itemRequirementTooltipHtml(item)}
    ${isGemUpgradeItem(item) ? itemGemTooltipHtml(item) : ""}
    ${isBookItem(item) ? "" : isBenedictionOilItem(item) ? itemBenedictionTooltipHtml(item, entry) : isPotionItem(item) ? itemPotionTooltipHtml(item) : isPoisonItem(item) ? itemPoisonTooltipHtml(item) : isTaoistAmuletItem(item) ? itemAmuletTooltipHtml(item) : itemStatsTooltipHtml(itemEntryStats(entry, item))}
    ${item.stackable ? `<span>Stack: ${maxItemStack(item)}</span>` : ""}
  `;
}

function itemSpellTooltipHtml(item) {
  if (!isBookItem(item)) return "";
  const spell = magicSpellByShape(item.spell?.shape) ?? magicSpellById(item.spell?.id);
  if (!spell) return `<span>Teaches: unknown spell #${escapeHtml(item.spell?.shape ?? item.spell?.id ?? "")}</span>`;
  const learned = learnedMagic(spell.id);
  return `
    <span>Teaches: ${escapeHtml(spell.label)}${learned ? " (learned)" : ""}</span>
    <span>${escapeHtml(spell.description ?? "")}</span>
  `;
}

function itemRequirementTooltipHtml(item) {
  const requirement = itemRequirementStatus(item);
  const label = itemRequirementLabel(item.requirements);
  if (!label) return "";
  return `<span class="${requirement.ok ? "requirement-ok" : "requirement-bad"}">Requires: ${escapeHtml(label)}${requirement.ok ? "" : ` (${escapeHtml(requirement.reason)})`}</span>`;
}

function itemGemTooltipHtml(item) {
  const gem = item.gem;
  if (!gem) return "";
  const statLabel = gemUpgradeStatLabel(gem);
  const amount = gem.durabilityBonus > 0 ? gem.durabilityBonus : (gem.stat?.amount ?? 1);
  const kindLabel = gem.kind === "orb" ? "Orb (safe — item never breaks on failure)" : "Gem (failed upgrades can destroy the item)";
  const slotLabels = Object.entries(GEM_VALID_SLOT_FLAGS)
    .filter(([, flag]) => (Math.trunc(Number(gem.unique) || 0) & flag) !== 0)
    .map(([slotId]) => slotLabel(slotId))
    .join(", ");
  return `
    <span>${escapeHtml(kindLabel)}</span>
    <span>Adds +${amount} ${escapeHtml(statLabel)} on success</span>
    <span>Base success: ${Math.max(0, Math.trunc(Number(gem.criticalRate) || 0))}% (drops as stat is added)</span>
    <span>Max ${Math.max(0, Math.trunc(Number(gem.maxStatCount) || 0))} ${escapeHtml(statLabel)} / ${Math.max(0, Math.trunc(Number(gem.criticalDamage) || 0))} total upgrades</span>
    ${slotLabels ? `<span>Valid on: ${escapeHtml(slotLabels)}</span>` : ""}
    <span>Drag onto equipment to apply</span>
  `;
}

function itemBenedictionTooltipHtml(item, entry = null) {
  const weaponEntryId = state.inventory.equipment?.weapon ?? null;
  const weaponEntry = weaponEntryId ? inventoryEntryById(weaponEntryId) : null;
  const weaponItem = weaponEntry ? itemDefinition(weaponEntry.itemId) : null;
  const weaponLuck = weaponEntry && weaponItem?.slot === "weapon" ? weaponEntryLuck(weaponEntry, weaponItem) : null;
  const rates = weaponLuck == null ? null : benedictionOutcomeRates(weaponLuck);
  const totalLuck = weaponLuck == null ? null : Math.max(-CRYSTAL_MAX_LUCK, Math.min(CRYSTAL_MAX_LUCK, 1 + weaponLuck));
  const equippedLine = weaponEntry && weaponItem
    ? `<span>Equipped weapon: ${escapeHtml(itemDisplayName(weaponItem, weaponEntry))}${weaponLuck != null ? ` (${escapeHtml(benedictionLuckLabel(weaponLuck))})` : ""}${rates ? ` — bless ${rates.bless.toFixed(1)}%, curse ${rates.curse.toFixed(0)}%, no effect ${rates.none.toFixed(1)}%` : ""}${totalLuck != null ? ` — combat max-hit ${combatMaxHitChancePercent(totalLuck).toFixed(0)}%` : ""}</span>`
    : `<span>Requires an equipped weapon.</span>`;
  return `
    <span>Blesses your equipped weapon for +1 Luck (max +${BENEDICTION_MAX_WEAPON_LUCK}).</span>
    <span>5% curse chance. Bless rates: +0 guaranteed, +1›+2 20%, +2›+4 10%, +4 and above 5%. Cursed weapons recover on the next successful bless.</span>
    <span>Total luck = base 1 + weapon luck. Luck ${CRYSTAL_MAX_LUCK} always rolls maximum damage.</span>
    ${equippedLine}
  `;
}

function itemOreTooltipHtml(entry, item) {
  const purity = orePurity(entry, item);
  const percent = entryDurabilityPercent(entry, item);
  return `<span>Purity: ${purity}${percent != null ? ` (${percent}% durability)` : ""}</span>`;
}

function itemDurabilityTooltipHtml(entry, item) {
  const percent = entryDurabilityPercent(entry, item);
  if (percent == null) return "";
  return `<span>Durability: ${percent}%</span>`;
}

function itemPotionTooltipHtml(item) {
  const def = buffPotionDefForItem(item);
  if (def) {
    const classes = def.classes.join(" / ");
    const durationMin = Math.round(BUFF_POTION_DURATION_MS / 60000);
    return `<span>Buff (${escapeHtml(classes)}): ${escapeHtml(statBuffBonusLabel(def))} for ${durationMin} min</span>`;
  }
  const restores = [];
  const hp = potionRestoreAmount(item, "hp");
  const mp = potionRestoreAmount(item, "mp");
  if (hp > 0) restores.push(`${hp} HP`);
  if (mp > 0) restores.push(`${mp} MP`);
  if (!restores.length) return `<p>No restore effect</p>`;
  const mode = potionRestoreMode(item) === "instant" ? "instantly" : "over time";
  return `<span>Restores ${escapeHtml(mode)}: ${escapeHtml(restores.join(" and "))}</span>`;
}

function itemPoisonTooltipHtml(item) {
  const kind = poisonItemKind(item);
  if (kind === "green") return `<span>Used by Poisoning: damage over time.</span>`;
  return `<span>Used by Poisoning: weakens monster defences.</span>`;
}

function itemAmuletTooltipHtml() {
  return `<span>Used by Taoist spells such as Soul Fire Ball.</span>`;
}

function itemStatsTooltipHtml(stats) {
  const lines = [];
  for (const [key, label] of [
    ["dc", "DC"],
    ["mc", "MC"],
    ["sc", "SC"],
    ["ac", "AC"],
    ["amc", "AMC"],
  ]) {
    if (hasRangeValue(stats?.[key])) lines.push(`<dt>${label}</dt><dd>${formatStatRange(stats[key])}</dd>`);
  }
  for (const [key, label] of [
    ["hp", "HP"],
    ["mp", "MP"],
    ["accuracy", "Acc"],
    ["agility", "Agi"],
    ["luck", "Luck"],
    ["attackSpeed", "A Speed"],
    ["poisonAttack", "Poison"],
    ["freezing", "Freezing"],
    ["magicResist", "Magic Resist"],
    ["poisonResist", "Poison Resist"],
    ["healthRecovery", "HP Recovery"],
    ["poisonRecovery", "Poison Recovery"],
    ["strong", "Strong"],
  ]) {
    const value = Number(stats?.[key]) || 0;
    if (value !== 0) lines.push(`<dt>${label}</dt><dd>${value > 0 ? `+${value}` : value}</dd>`);
  }
  if (!lines.length) return `<p>No stat bonus</p>`;
  return `<dl>${lines.join("")}</dl>`;
}

function hasRangeValue(stat) {
  return Array.isArray(stat) && ((Number(stat[0]) || 0) !== 0 || (Number(stat[1]) || 0) !== 0);
}

function slotLabel(slotId) {
  return EQUIPMENT_SLOTS.find((slot) => slot.id === slotId)?.label ?? title(slotId);
}

function itemRequirementStatus(item, stats = characterTotalStats()) {
  const req = item?.requirements;
  if (!req || req.type === "none") return { ok: true, reason: "" };
  if (!classRequirementMet(req.classMask)) return { ok: false, reason: "wrong class" };
  const amount = Number(req.amount) || 0;
  const checks = {
    level: { value: state.game.progress.level, label: `level ${amount}` },
    maxAC: { value: stats.ac[1], label: `AC ${amount}` },
    maxAMC: { value: stats.amc[1], label: `AMC ${amount}` },
    maxDC: { value: stats.dc[1], label: `DC ${amount}` },
    maxMC: { value: stats.mc[1], label: `MC ${amount}` },
    maxSC: { value: stats.sc[1], label: `SC ${amount}` },
    maxLevel: { value: state.game.progress.level, label: `max level ${amount}`, max: true },
    minAC: { value: stats.ac[0], label: `AC ${amount}` },
    minAMC: { value: stats.amc[0], label: `AMC ${amount}` },
    minDC: { value: stats.dc[0], label: `DC ${amount}` },
    minMC: { value: stats.mc[0], label: `MC ${amount}` },
    minSC: { value: stats.sc[0], label: `SC ${amount}` },
  };
  const check = checks[req.type];
  if (!check) return { ok: true, reason: "" };
  const ok = check.max ? check.value <= amount : check.value >= amount;
  return { ok, reason: ok ? "" : `requires ${check.label}` };
}

function itemRequirementLabel(req) {
  if (!req || req.type === "none") return "";
  const amount = Number(req.amount) || 0;
  const labels = {
    level: `Level ${amount}`,
    maxAC: `Max AC ${amount}`,
    maxAMC: `Max AMC ${amount}`,
    maxDC: `Max DC ${amount}`,
    maxMC: `Max MC ${amount}`,
    maxSC: `Max SC ${amount}`,
    maxLevel: `Level at most ${amount}`,
    minAC: `Min AC ${amount}`,
    minAMC: `Min AMC ${amount}`,
    minDC: `Min DC ${amount}`,
    minMC: `Min MC ${amount}`,
    minSC: `Min SC ${amount}`,
  };
  return labels[req.type] ?? "";
}

function classRequirementMet(classMask) {
  const mask = Number(classMask) || 31;
  const classBits = { Warrior: 1, Wizard: 2, Taoist: 4 };
  return Boolean(mask & (classBits[state.battle.combatClass] ?? 1));
}

async function selectPlayerClass(classId) {
  const nextClass = CHARACTER_SELECT_CLASSES.find((entry) => entry.id === classId);
  const combatClass = COMBAT_CLASSES.find((entry) => entry.id === classId);
  if (!nextClass || nextClass.disabled || combatClass?.disabled) return false;

  if (bossPartyOnField()) {
    pushBattleLog("Return to town before switching characters.");
    closeScene("characterSelect");
    return false;
  }

  if (state.battle.combatClass === classId) {
    closeScene("characterSelect");
    return true;
  }

  captureActiveCharacterState();
  stopOneStepTest();
  state.continuousWalk = false;
  applyCharacterState(classId, state.characters[classId] ?? createDefaultCharacterState(classId));
  resetBattleForCurrentMode(false);
  state.battle.log = [`${classId} selected.`];
  await reloadAtlases();
  await reloadEnemyAtlas();

  saveGameState(true);
  invalidateUi();
  closeScene("characterSelect");
  renderMapControls();
  renderCombatSkillBar();
  renderGamePanel();
  renderBattlePanel();
  render();
  return true;
}

async function requestZoneEntry(zoneId) {
  const zone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId);
  if (!zone) return;
  if (bossRoomDef(zone.id) || groupDungeonZone(zone)) {
    state.bossEntryZoneId = zone.id;
    state.bossEmpowerSelected = false;
    state.bossAssistSelection = [];
    state.activeScene = "bossEntry";
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.35, throttleMs: 80 });
    return;
  }
  closeScene(false);
  await enterZone(zone.id);
}

async function confirmBossZoneEntry(zoneId) {
  const zone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId);
  const isBossRoom = Boolean(zone && bossRoomDef(zone.id));
  const isGroupDungeon = Boolean(zone && groupDungeonZone(zone));
  const advancingFromDungeon = Boolean(state.bossEntryFromGroupDungeonAdvance);
  if (!zone || (!isBossRoom && !isGroupDungeon)) return;
  if (!advancingFromDungeon && isBossRoom && bossRespawnRemainingMs(zone.id) > 0) {
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.25, throttleMs: 120 });
    return;
  }
  if (advancingFromDungeon) {
    const party = state.battle.bossParty;
    if (party?.members?.length) {
      syncBossPartyMembersToCharacters(party, { applyControlled: false });
      state.battle.bossParty = null;
    }
    clearGroupDungeonRunState();
    state.game.groupDungeonRun = null;
    state.bossEntryFromGroupDungeonAdvance = false;
    state.bossEntryZoneId = null;
    closeScene(false);
    pushBattleLog(`Advancing to ${zone.label}.`);
    await enterZone(zone.id);
    return;
  }
  captureActiveCharacterState();
  state.pendingBossAssistSelection = [...selectedBossAssistIds()];
  state.bossEntryZoneId = null;
  state.bossEntryFromGroupDungeonAdvance = false;
  closeScene(false);
  await enterZone(zone.id);
}

async function enterZone(zoneId, options = {}) {
  const zone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId) ?? PROTOTYPE_ZONES[0];
  if (!zone || zone.miningOnly) return;
  if (!options.preview) state.zoneBuilderPreviewZoneId = null;
  stopOneStepTest();
  state.continuousWalk = false;
  state.showEnemies = true;
  state.game.mode = "zone";
  state.game.activeZoneId = zone.id;
  clearStampBackgroundCache();
  lastStageShellSize = { w: 0, h: 0, mode: "", scale: 0 };
  state.game.miningNextRollAt = 0;
  state.game.zoneKills = 0;
  state.game.distance = 0;
  state.game.selectedTownNpcId = null;
  state.game.lastReward = null;
  state.game.recentLoot = [];
  state.game.lootToasts = [];
  state.game.dropPity[zone.id] = state.game.dropPity[zone.id] ?? 0;
  if (isRoomOnlyZone(zone)) {
    resetBattleForRoomOnly(zone);
  } else {
    resetBattle(randomZoneEnemyTemplate(zone).id);
  }
  if (groupDungeonZone(zone)) {
    clearGroupDungeonRunState();
  } else {
    state.game.groupDungeonRun = null;
  }
  state.battle.log = [`Teleported to ${zone.label}.`];
  captureActiveCharacterState();
  playSfx("ui.teleport", { volume: 0.55, throttleMs: 300 });
  await reloadEnemyAtlas();
  startBattle();
  renderMapControls();
  gamePanelSignature = "";
  battlePanelSignature = "";
  render();
}

function returnToTown() {
  clearTransientCombatBuffs();
  returnAllCharactersToTown();
  state.zoneBuilderPreviewZoneId = null;
  stopOneStepTest();
  state.continuousWalk = false;
  state.showEnemies = false;
  state.game.miningNextRollAt = 0;
  state.battle.running = false;
  state.battle.phase = "idle";
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  dismissTaoistPet();
  state.battle.bossParty = null;
  state.battle.groundSpellEffects = [];
  if (state.battle.enemy) state.battle.enemy.poisons = [];
  state.battle.nextPlayerAttackAt = 0;
  state.battle.nextEnemyAttackAt = 0;
  state.battle.furyUntil = 0;
  state.battle.furyBonus = 0;
  state.battle.enemyAggro = false;
  state.battle.cameraX = state.battle.playerX - playerScreenX();
  state.battle.enemyX = state.battle.playerX + enemySpawnDistance();
  playSfx("ui.teleport", { volume: 0.48, throttleMs: 300 });
  applyEquippedVisualIndexes();
  queueVisualAtlasReload(["weapon"]);
  setPlayerAction("standing", performance.now());
  setEnemyLocomotion("standing", performance.now());
  pushBattleLog("Returned to town.");
  applyCharacterState(state.activeCharacterId, state.characters[state.activeCharacterId]);
  renderMapControls();
  gamePanelSignature = "";
  battlePanelSignature = "";
  render();
}

function activeZone() {
  return PROTOTYPE_ZONES.find((zone) => zone.id === state.game.activeZoneId) ?? null;
}

function bossRoomDef(zoneId) {
  return BOSS_ROOM_DEFS[zoneId] ?? null;
}

function groupDungeonZone(zone = activeZone()) {
  return Boolean(zone?.groupDungeon);
}

function groupDungeonBossZone(zone = activeZone()) {
  return Boolean(zone?.groupDungeon && zone?.groupDungeonBoss);
}

function groupDungeonBossSwarmZone(zone = activeZone()) {
  return Boolean(zone?.groupDungeon && zone?.groupDungeonBossSwarm);
}

function groupDungeonBossSwarmState() {
  return state.battle.swarm?.bossSwarm ?? null;
}

function cloneBossSwarmPlanEntry(entry = {}) {
  const cloned = {
    templateId: Math.trunc(Number(entry.templateId)),
    spawnAtMs: Math.max(0, Math.trunc(Number(entry.spawnAtMs) || 0)),
  };
  if (entry.mapRowOffset != null) cloned.mapRowOffset = Math.trunc(Number(entry.mapRowOffset));
  if (entry.lane != null) cloned.lane = Math.trunc(Number(entry.lane));
  if (entry.mapRow != null) cloned.mapRow = Math.trunc(Number(entry.mapRow));
  return cloned;
}

function buildBossSwarmSpawnPlan(base, zone) {
  const rawFirstDelay = base.firstSpawnDelayMs ?? base.spawnIntervalMs ?? 0;
  const parsedFirstDelay = Math.trunc(Number(rawFirstDelay));
  const firstSpawnDelayMs = Math.max(0, Number.isFinite(parsedFirstDelay) ? parsedFirstDelay : 0);
  const rawInterval = Math.trunc(Number(base.spawnIntervalMs));
  const spawnIntervalMs = Math.max(1000, Number.isFinite(rawInterval) ? rawInterval : 10000);

  if (Array.isArray(base.spawnQueue) && base.spawnQueue.length) {
    const plan = [];
    for (const entry of base.spawnQueue) {
      const templateId = Math.trunc(Number(entry.templateId));
      const count = Math.max(1, Math.trunc(Number(entry.count) || 1));
      if (templateId <= 0) continue;
      const spawnAtMs = Math.max(0, Math.trunc(Number(entry.spawnDelayMs) || 0));
      for (let i = 0; i < count; i += 1) {
        const lane = Array.isArray(entry.lanes)
          ? entry.lanes[i]
          : entry.lane;
        plan.push({
          templateId,
          spawnAtMs,
          mapRowOffset: entry.mapRowOffset != null ? Math.trunc(Number(entry.mapRowOffset)) : undefined,
          lane: lane != null ? Math.trunc(Number(lane)) : undefined,
        });
      }
    }
    if (plan.length) return plan;
  }

  const templateId = Math.trunc(Number(base.templateId) || zone?.enemyIds?.[0] || INCARNATED_WT_ENEMY_ID);
  const totalSpawns = Math.max(1, Math.trunc(Number(base.totalSpawns) || 3));
  return Array.from({ length: totalSpawns }, (_, index) => ({
    templateId,
    spawnAtMs: firstSpawnDelayMs + index * spawnIntervalMs,
  }));
}

function resolveBossSwarmSpawnMapRow(planEntry, arenaSpawnRow, fallbackIndex = 0) {
  const baseRow = Math.trunc(Number(arenaSpawnRow) || 0);
  if (planEntry?.mapRow != null) return Math.trunc(Number(planEntry.mapRow));
  if (planEntry?.mapRowOffset != null) return baseRow + Math.trunc(Number(planEntry.mapRowOffset));
  const lane = planEntry?.lane != null
    ? Math.trunc(Number(planEntry.lane))
    : GROUP_DUNGEON_SWARM_LANES[fallbackIndex % GROUP_DUNGEON_SWARM_LANES.length];
  return swarmLaneMapRow(lane, baseRow);
}

function groupDungeonBossSwarmConfig(zone = activeZone()) {
  const base = zone?.groupDungeonBossSwarmConfig ?? {};
  const rawInterval = Math.trunc(Number(base.spawnIntervalMs));
  const spawnIntervalMs = Math.max(1000, Number.isFinite(rawInterval) ? rawInterval : 10000);
  const rawFirstDelay = base.firstSpawnDelayMs ?? base.spawnIntervalMs ?? spawnIntervalMs;
  const parsedFirstDelay = Math.trunc(Number(rawFirstDelay));
  const firstSpawnDelayMs = Math.max(
    0,
    Number.isFinite(parsedFirstDelay) ? parsedFirstDelay : spawnIntervalMs,
  );
  const spawnPlan = buildBossSwarmSpawnPlan({ ...base, firstSpawnDelayMs, spawnIntervalMs }, zone);
  const totalSpawns = spawnPlan.length;
  const templateId = spawnPlan[0]?.templateId ?? Math.trunc(Number(base.templateId) || zone?.enemyIds?.[0] || INCARNATED_WT_ENEMY_ID);
  const spawnAllAtOnce = spawnPlan.length > 0 && spawnPlan.every((entry) => (entry.spawnAtMs ?? 0) <= 0);
  return { templateId, spawnPlan, totalSpawns, spawnIntervalMs, firstSpawnDelayMs, spawnAllAtOnce };
}

function groupDungeonBossSwarmSignature() {
  const bossSwarm = groupDungeonBossSwarmState();
  if (!bossSwarm) return null;
  return {
    spawned: bossSwarm.spawned,
    killed: bossSwarm.killed,
    totalSpawns: bossSwarm.totalSpawns,
    complete: bossSwarm.complete,
    living: groupDungeonSwarmLivingCount(),
    nextSpawnAt: bossSwarm.nextSpawnAt,
  };
}

function groupDungeonBossSwarmLabel(zone = groupDungeonWaveZone()) {
  const base = zone?.groupDungeonBossSwarmConfig ?? {};
  if (Array.isArray(base.spawnQueue) && base.spawnQueue.length) {
    const names = base.spawnQueue
      .map((entry) => ENEMY_TEMPLATES.find((template) => template.id === Math.trunc(Number(entry.templateId)))?.name)
      .filter(Boolean);
    const uniqueNames = [...new Set(names)];
    if (uniqueNames.length > 1) return uniqueNames.join(" and ");
  }
  const config = groupDungeonBossSwarmConfig(zone);
  return ENEMY_TEMPLATES.find((entry) => entry.id === config.templateId)?.name ?? "boss";
}

function resetGroupDungeonBossSwarmRun(now = performance.now(), zone = groupDungeonWaveZone(), options = {}) {
  const config = groupDungeonBossSwarmConfig(zone);
  const bossLabel = groupDungeonBossSwarmLabel(zone);
  const skipInitialSpawn = Boolean(options.skipInitialSpawn);
  state.battle.swarm = {
    enemies: [],
    nextId: 0,
    lastAdvanceAt: now,
    waves: null,
    bossSwarm: {
      spawnPlan: config.spawnPlan,
      templateId: config.templateId,
      fightStartAt: now,
      spawned: 0,
      killed: 0,
      totalSpawns: config.totalSpawns,
      spawnIntervalMs: config.spawnIntervalMs,
      nextSpawnAt: now,
      complete: false,
      waitingForRespawn: skipInitialSpawn,
    },
  };
  state.battle.enemy = null;
  state.battle.enemyId = null;
  markGroupDungeonWaveUiDirty();
  if (skipInitialSpawn) return;
  if (config.spawnAllAtOnce) {
    pushBattleLog(`${config.totalSpawns} ${bossLabel} emerge together.`);
  } else if (config.spawnPlan.some((entry, index) => index > 0 && (entry.spawnAtMs ?? 0) > 0)) {
    const firstDelaySec = Math.round((config.spawnPlan.find((entry, index) => index > 0 && (entry.spawnAtMs ?? 0) > 0)?.spawnAtMs ?? 0) / 1000);
    pushBattleLog(`${bossLabel} — the first boss emerges now; reinforcements in ${firstDelaySec}s.`);
  } else {
    const intervalSec = Math.round(config.spawnIntervalMs / 1000);
    pushBattleLog(config.firstSpawnDelayMs <= 0
      ? `${config.totalSpawns} ${bossLabel} — one now, then one every ${intervalSec}s.`
      : `${config.totalSpawns} ${bossLabel} will emerge every ${intervalSec}s.`);
  }
  spawnPendingGroupDungeonBossSwarmEnemies(now);
}

function spawnGroupDungeonBossSwarmEnemy(now = performance.now()) {
  const swarm = state.battle.swarm;
  const bossSwarm = swarm?.bossSwarm;
  if (!swarm || !bossSwarm) return null;
  if (bossSwarm.spawned >= bossSwarm.totalSpawns) return null;
  const planEntry = bossSwarm.spawnPlan?.[bossSwarm.spawned];
  const templateId = Math.trunc(Number(planEntry?.templateId) || bossSwarm.templateId);
  const template = ENEMY_TEMPLATES.find((entry) => entry.id === templateId)
    ?? randomZoneEnemyTemplate(groupDungeonWaveZone());
  if (!template) return null;

  const arenaSpawnRow = arenaSpawnMapRow();
  const enemy = buildSwarmEnemyFromTemplate(template, now, {
    mapRow: resolveBossSwarmSpawnMapRow(planEntry, arenaSpawnRow, bossSwarm.spawned),
  });
  enemy.isBossSwarm = true;
  while (swarmTileOccupied(enemy.worldX, enemy.mapRow, swarm.enemies, enemy.id)) {
    enemy.worldX += LANE_TILE_PX;
  }
  swarm.enemies.push(enemy);
  bossSwarm.spawned += 1;
  void ensureSwarmEnemyAtlas(enemy);
  syncGroupDungeonPrimaryEnemy();
  markGroupDungeonWaveUiDirty();
  return enemy;
}

function spawnPendingGroupDungeonBossSwarmEnemies(now = performance.now()) {
  const bossSwarm = groupDungeonBossSwarmState();
  if (!bossSwarm || bossSwarm.complete) return;
  if (groupDungeonBossRespawnRemainingMs(activeZone()) > 0) return;
  if (bossSwarm.waitingForRespawn) {
    bossSwarm.waitingForRespawn = false;
    bossSwarm.fightStartAt = now;
    bossSwarm.nextSpawnAt = now;
    const zone = groupDungeonWaveZone();
    const config = groupDungeonBossSwarmConfig(zone);
    const bossLabel = groupDungeonBossSwarmLabel(zone);
    if (config.spawnAllAtOnce) {
      pushBattleLog(`${config.totalSpawns} ${bossLabel} emerge together.`);
    } else if (config.spawnPlan.some((entry, index) => index > 0 && (entry.spawnAtMs ?? 0) > 0)) {
      const firstDelaySec = Math.round((config.spawnPlan.find((entry, index) => index > 0 && (entry.spawnAtMs ?? 0) > 0)?.spawnAtMs ?? 0) / 1000);
      pushBattleLog(`${bossLabel} — the first boss emerges now; reinforcements in ${firstDelaySec}s.`);
    } else {
      const intervalSec = Math.round(config.spawnIntervalMs / 1000);
      pushBattleLog(config.firstSpawnDelayMs <= 0
        ? `${config.totalSpawns} ${bossLabel} — one now, then one every ${intervalSec}s.`
        : `${config.totalSpawns} ${bossLabel} will emerge every ${intervalSec}s.`);
    }
  }
  if (bossSwarm.spawned >= bossSwarm.totalSpawns) {
    bossSwarm.nextSpawnAt = Number.POSITIVE_INFINITY;
    return;
  }
  const fightStart = bossSwarm.fightStartAt ?? now;
  while (bossSwarm.spawned < bossSwarm.totalSpawns) {
    const next = bossSwarm.spawnPlan?.[bossSwarm.spawned];
    const spawnAt = fightStart + Math.max(0, Math.trunc(Number(next?.spawnAtMs) || 0));
    if (now < spawnAt) {
      bossSwarm.nextSpawnAt = spawnAt;
      return;
    }
    const enemy = spawnGroupDungeonBossSwarmEnemy(now);
    if (!enemy) {
      bossSwarm.nextSpawnAt = spawnAt;
      return;
    }
    pushBattleLog(`${enemy.name} approaches (${bossSwarm.spawned}/${bossSwarm.totalSpawns}).`);
  }
  bossSwarm.nextSpawnAt = Number.POSITIVE_INFINITY;
}

function updateGroupDungeonBossSwarmSpawns(now) {
  spawnPendingGroupDungeonBossSwarmEnemies(now);
}

function finishGroupDungeonBossSwarmEncounter(now = performance.now()) {
  const bossSwarm = groupDungeonBossSwarmState();
  const party = state.battle.bossParty;
  if (!bossSwarm || bossSwarm.complete || !party?.active) return;
  bossSwarm.complete = true;
  const zone = activeZone();
  const nextZone = groupDungeonNextFloorZone(zone);
  const bossLabel = groupDungeonBossSwarmLabel(zone);
  const respawnMinutes = groupDungeonBossRespawnMinutes(zone);
  if (respawnMinutes > 0) {
    setBossRespawn(zone.id);
    pushBattleLog(`${bossLabel} will respawn in ${formatBossRespawnDelay(respawnMinutes)}.`);
  }
  pushBattleLog(`All ${bossLabel} defeated.`);
  pushBattleLog(nextZone
    ? `Advance to ${nextZone.label} when you are ready.`
    : "Dungeon complete — return to town when you are ready.");
  markGroupDungeonWaveUiDirty();
  gamePanelSignature = "";
  gamePanelDynamicSignature = "";
  battlePanelSignature = "";
  sceneSignature = "";
  saveGameState(true);
}

function finishGroupDungeonBossSwarmIfReady(now = performance.now()) {
  const bossSwarm = groupDungeonBossSwarmState();
  if (!bossSwarm || bossSwarm.complete) return;
  reconcileGroupDungeonSwarmDeaths(now);
  if (bossSwarm.spawned < bossSwarm.totalSpawns) return;
  if (groupDungeonSwarmLivingCount() > 0) return;
  finishGroupDungeonBossSwarmEncounter(now);
}

function groupDungeonBossSwarmSidePanelHtml() {
  const bossSwarm = groupDungeonBossSwarmState();
  if (!bossSwarm) return "";
  const zone = groupDungeonWaveZone();
  const bossName = groupDungeonBossSwarmLabel(zone);
  const living = groupDungeonSwarmLivingCount();
  const spawned = Math.min(bossSwarm.totalSpawns, bossSwarm.spawned);
  const killed = Math.min(bossSwarm.totalSpawns, bossSwarm.killed);
  let sub = bossSwarm.complete
    ? "Room cleared"
    : `${living} alive · ${killed} defeated`;
  if (!bossSwarm.complete && spawned < bossSwarm.totalSpawns && Number.isFinite(bossSwarm.nextSpawnAt)) {
    const remainingMs = Math.max(0, Math.ceil((bossSwarm.nextSpawnAt - performance.now()) / 1000));
    sub += ` · next in ${remainingMs}s`;
  }
  return `
    <section class="game-card group-dungeon-wave-card">
      <div class="game-card-title">
        <strong>Boss Swarm</strong>
        <span>${escapeHtml(bossName)}</span>
      </div>
      <p class="group-dungeon-wave-status">
        <strong>${spawned} / ${bossSwarm.totalSpawns} spawned</strong>
        <span>${escapeHtml(sub)}</span>
      </p>
    </section>
  `;
}

function groupDungeonNextFloorZone(zone = activeZone()) {
  if (!groupDungeonZone(zone)) return null;
  const floor = Math.max(1, Math.trunc(Number(zone.groupDungeonFloor) || 1));
  const dungeonId = String(zone.groupDungeon || "");
  // Floors may skip numbers if a zone is not implemented yet; pick the next higher floor.
  const candidates = PROTOTYPE_ZONES
    .map((entry) => ({
      entry,
      entryFloor: Math.max(1, Math.trunc(Number(entry.groupDungeonFloor) || 1)),
    }))
    .filter(({ entry, entryFloor }) => entry.groupDungeon === dungeonId && entryFloor > floor);
  if (!candidates.length) return null;
  candidates.sort((a, b) => a.entryFloor - b.entryFloor);
  return candidates[0].entry;
}

function groupDungeonAdvanceButtonHtml() {
  const zone = activeZone();
  const party = state.battle.bossParty;
  // Allow advancing both while active (wave/boss-swarm floors) and after a boss floor has
  // finished (victory state, party.active === false), but never once the run is defeated.
  if (!groupDungeonZone(zone) || party?.defeated || (!party?.active && !party?.finished)) return "";
  const isBossSwarm = groupDungeonBossSwarmZone(zone);
  const isBossFloor = groupDungeonBossZone(zone);
  if (isBossSwarm) {
    if (!groupDungeonBossSwarmState()?.complete && !groupDungeonBossCanSkipFloor(zone, party)) return "";
  } else if (isBossFloor && !party.finished) {
    if (!groupDungeonBossCanSkipFloor(zone, party)) return "";
  } else if (!isBossFloor) {
    const waves = groupDungeonWaveState();
    if (!waves?.endless) return "";
  }
  const nextZone = groupDungeonNextFloorZone(zone);
  if (!nextZone) return "";
  return `<button class="primary game-wide-button" type="button" data-advance-group-dungeon-floor>Advance to ${escapeHtml(nextZone.label)}</button>`;
}

async function advanceGroupDungeonFloor() {
  const zone = activeZone();
  const party = state.battle.bossParty;
  if (!groupDungeonZone(zone) || party?.defeated || (!party?.active && !party?.finished)) return;
  const isBossSwarm = groupDungeonBossSwarmZone(zone);
  const isBossFloor = groupDungeonBossZone(zone);
  if (isBossSwarm) {
    if (!groupDungeonBossSwarmState()?.complete && !groupDungeonBossCanSkipFloor(zone, party)) return;
  } else if (isBossFloor && !party.finished) {
    if (!groupDungeonBossCanSkipFloor(zone, party)) return;
  } else if (!isBossFloor) {
    const waves = groupDungeonWaveState();
    if (!waves?.endless) return;
  }
  const nextZone = groupDungeonNextFloorZone(zone);
  if (!nextZone) {
    pushBattleLog("The next floor is not ready yet.");
    gamePanelSignature = "";
    gamePanelDynamicSignature = "";
    renderGameUiPanel();
    return;
  }
  syncBossPartyMembersToCharacters(party, { applyControlled: false });
  const assistIds = bossPartyMemberClassIds(party).filter((classId) => classId !== state.activeCharacterId);
  state.pendingBossAssistSelection = assistIds;
  const isNextBossRoom = groupDungeonBossZone(nextZone) || groupDungeonBossSwarmZone(nextZone);
  if (isNextBossRoom) {
    state.bossEntryZoneId = nextZone.id;
    state.bossEntryFromGroupDungeonAdvance = true;
    state.activeScene = "bossEntry";
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.35, throttleMs: 80 });
    return;
  }
  state.battle.bossParty = null;
  clearGroupDungeonRunState();
  state.game.groupDungeonRun = null;
  pushBattleLog(`Advancing to ${nextZone.label}.`);
  await enterZone(nextZone.id);
}


function groupDungeonSwarmActive() {
  return groupDungeonZone()
    && Boolean(state.battle.bossParty?.active && state.battle.swarm && !state.battle.swarm.bossReinforcements);
}

function groupDungeonBossReinforcementsZone(zone = activeZone()) {
  return Boolean(zone?.groupDungeon && zone?.groupDungeonBoss && zone?.groupDungeonBossReinforcements);
}

function groupDungeonBossReinforcementsConfig(zone = activeZone()) {
  const base = zone?.groupDungeonBossReinforcementsConfig ?? {};
  return {
    templateId: Math.trunc(Number(base.templateId) || 309),
    spawnIntervalMs: Math.max(500, Math.trunc(Number(base.spawnIntervalMs) || 2000)),
    firstSpawnDelayMs: Math.max(0, Math.trunc(Number(base.firstSpawnDelayMs) || 2000)),
    maxLiving: Math.max(1, Math.trunc(Number(base.maxLiving) || 16)),
  };
}

function groupDungeonBossReinforcementsActive() {
  return groupDungeonBossReinforcementsZone()
    && Boolean(state.battle.bossParty?.active && state.battle.swarm?.bossReinforcements);
}

function groupDungeonSwarmSideActive() {
  return groupDungeonSwarmActive() || groupDungeonBossReinforcementsActive();
}

function initGroupDungeonBossReinforcements(now, zone = activeZone()) {
  const config = groupDungeonBossReinforcementsConfig(zone);
  state.battle.swarm = {
    bossReinforcements: true,
    enemies: [],
    nextId: 0,
    reinforcements: {
      nextSpawnAt: now + config.firstSpawnDelayMs,
      spawned: 0,
      config,
    },
  };
}

function spawnGroupDungeonBossReinforcement(now = performance.now()) {
  const swarm = state.battle.swarm;
  if (!swarm?.bossReinforcements) return null;
  const config = swarm.reinforcements?.config ?? groupDungeonBossReinforcementsConfig();
  const living = groupDungeonSwarmLivingCount(swarm);
  if (living >= config.maxLiving) return null;
  const template = ENEMY_TEMPLATES.find((entry) => entry.id === config.templateId);
  if (!template) return null;
  const arenaSpawnRow = arenaSpawnMapRow();
  const spawned = swarm.reinforcements?.spawned ?? 0;
  const spawnLane = GROUP_DUNGEON_SWARM_LANES[spawned % GROUP_DUNGEON_SWARM_LANES.length];
  const enemy = buildSwarmEnemyFromTemplate(template, now, {
    mapRow: swarmLaneMapRow(spawnLane, arenaSpawnRow),
  });
  while (swarmTileOccupied(enemy.worldX, enemy.mapRow, swarm.enemies, enemy.id)) {
    enemy.worldX += LANE_TILE_PX;
  }
  swarm.enemies.push(enemy);
  swarm.reinforcements.spawned += 1;
  swarm.reinforcements.nextSpawnAt = now + config.spawnIntervalMs;
  void ensureSwarmEnemyAtlas(enemy);
  if (swarm.reinforcements.spawned === 1) {
    pushBattleLog(`${template.name} reinforcements join the fight.`);
  }
  return enemy;
}

function updateGroupDungeonBossReinforcements(now) {
  const swarm = state.battle.swarm;
  if (!swarm?.bossReinforcements) return;
  if ((state.battle.enemy?.hp ?? 0) <= 0 || state.battle.bossParty?.finished) return;
  if (now < (swarm.reinforcements?.nextSpawnAt ?? 0)) return;
  spawnGroupDungeonBossReinforcement(now);
}

function updateBossPartyReinforcementSwarm(now) {
  if (!groupDungeonBossReinforcementsActive()) return;
  updateGroupDungeonBossReinforcements(now);
  updateSwarmEnemyPendingStrikes(now);
  updateGroupDungeonSwarmMovement(now);
  pruneGroupDungeonSwarmEnemies(now);
  runGroupDungeonSwarmAttackPass(now);
  const swarm = state.battle.swarm;
  for (const swarmEnemy of swarm.enemies) {
    tryConsumeSwarmEnemyPendingStruck(swarmEnemy, now);
  }
}


function clearGroupDungeonRunState() {
  state.battle.swarm = null;
  markGroupDungeonWaveUiDirty();
}

function applyGroupDungeonRunToWaveState(waves, run, zone = groupDungeonWaveZone(), now = performance.now()) {
  if (!waves || !run) return waves;
  waves.waveNumber = Math.max(1, Math.trunc(Number(run.waveNumber) || waves.waveNumber || 1));
  waves.targetThisWave = Math.max(1, Math.trunc(Number(run.targetThisWave) || groupDungeonWaveSpawnCount(waves.waveNumber, zone)));
  waves.killedThisWave = Math.min(waves.targetThisWave, Math.max(0, Math.trunc(Number(run.killedThisWave) || 0)));
  waves.spawnedThisWave = Math.max(
    waves.killedThisWave,
    Math.min(waves.targetThisWave, Math.max(0, Math.trunc(Number(run.spawnedThisWave) || waves.killedThisWave))),
  );
  waves.spawningComplete = Boolean(run.spawningComplete);
  waves.betweenWaves = Boolean(run.betweenWaves);
  waves.floorComplete = Boolean(run.floorComplete);
  waves.endless = Boolean(run.endless);
  waves.nextSpawnAt = now;
  return waves;
}

function restoreGroupDungeonRunStateFromRun(run, now = performance.now(), zone = groupDungeonWaveZone()) {
  const sanitized = sanitizeGroupDungeonOfflineRun(run, zone?.id, state.activeCharacterId);
  if (!sanitized || groupDungeonBossSwarmZone(zone)) return false;
  state.battle.swarm = {
    enemies: [],
    nextId: 0,
    lastAdvanceAt: now,
    waves: createGroupDungeonWaveState(now, sanitized.waveNumber, zone),
  };
  applyGroupDungeonRunToWaveState(state.battle.swarm.waves, sanitized, zone, now);
  if (sanitized.killedThisWave <= 0 && sanitized.spawnedThisWave <= 0) {
    startGroupDungeonWave(now);
  } else if (!state.battle.swarm.waves.floorComplete) {
    spawnGroupDungeonWaveBurst(now);
  }
  syncGroupDungeonPrimaryEnemy();
  markGroupDungeonWaveUiDirty();
  return true;
}

function restoreGroupDungeonBossSwarmStateFromRun(run, now = performance.now(), zone = groupDungeonWaveZone()) {
  const sanitized = sanitizeGroupDungeonOfflineRun(run, zone?.id, state.activeCharacterId);
  if (!sanitized || !groupDungeonBossSwarmZone(zone)) return false;
  const config = groupDungeonBossSwarmConfig(zone);
  const totalSpawns = Math.max(1, Math.trunc(Number(sanitized.totalSpawns) || config.totalSpawns));
  state.battle.swarm = {
    enemies: [],
    nextId: 0,
    lastAdvanceAt: now,
    waves: null,
    bossSwarm: {
      spawnPlan: config.spawnPlan,
      templateId: config.templateId,
      fightStartAt: now,
      spawned: Math.min(totalSpawns, Math.max(0, Math.trunc(Number(sanitized.spawned) || 0))),
      killed: Math.max(0, Math.trunc(Number(sanitized.killed) || 0)),
      totalSpawns,
      spawnIntervalMs: config.spawnIntervalMs,
      nextSpawnAt: now,
      complete: Boolean(sanitized.complete),
    },
  };
  spawnPendingGroupDungeonBossSwarmEnemies(now);
  syncGroupDungeonPrimaryEnemy();
  markGroupDungeonWaveUiDirty();
  return true;
}

function restoreGroupDungeonPauseSnapshot(snapshot, now = performance.now(), zone = groupDungeonWaveZone()) {
  const paused = sanitizeGroupDungeonPauseSnapshot(snapshot, zone?.id, state.activeCharacterId);
  if (!paused || paused.zoneId !== zone?.id) return false;
  const swarmSnapshot = paused.swarm;
  const restoredEnemies = (swarmSnapshot?.enemies ?? [])
    .map((enemy) => restoreGroupDungeonPausedSwarmEnemy(enemy, now))
    .filter(Boolean);
  const maxEnemyId = restoredEnemies.reduce((max, enemy) => Math.max(max, enemy.id), 0);
  const isBossSwarm = groupDungeonBossSwarmZone(zone);
  const waves = !isBossSwarm
    ? applyGroupDungeonRunToWaveState(createGroupDungeonWaveState(now, paused.run.waveNumber, zone), paused.run, zone, now)
    : null;
  if (waves && swarmSnapshot?.waves) {
    waves.spawnedThisWave = Math.max(waves.spawnedThisWave, Math.min(waves.targetThisWave, Math.trunc(Number(swarmSnapshot.waves.spawnedThisWave) || waves.spawnedThisWave)));
    waves.spawningComplete = Boolean(swarmSnapshot.waves.spawningComplete);
    waves.betweenWaves = Boolean(swarmSnapshot.waves.betweenWaves);
    waves.floorComplete = Boolean(swarmSnapshot.waves.floorComplete);
    waves.endless = Boolean(swarmSnapshot.waves.endless);
    waves.nextSpawnAt = groupDungeonPauseTimestamp(swarmSnapshot.waves.nextSpawnIn, now) || now;
  }
  const bossSwarm = isBossSwarm ? (() => {
    const config = groupDungeonBossSwarmConfig(zone);
    const saved = swarmSnapshot?.bossSwarm ?? {};
    const totalSpawns = Math.max(1, Math.trunc(Number(saved.totalSpawns) || paused.run.totalSpawns || config.totalSpawns));
    return {
      templateId: Math.trunc(Number(saved.templateId) || config.templateId),
      spawnPlan: Array.isArray(saved.spawnPlan) && saved.spawnPlan.length
        ? saved.spawnPlan.map((entry) => cloneBossSwarmPlanEntry(entry))
        : config.spawnPlan,
      fightStartAt: Math.trunc(Number(saved.fightStartAt) || now),
      spawned: Math.min(totalSpawns, Math.max(0, Math.trunc(Number(saved.spawned) || paused.run.spawned || 0))),
      killed: Math.max(0, Math.trunc(Number(saved.killed) || paused.run.killed || 0)),
      totalSpawns,
      spawnIntervalMs: Math.max(0, Math.trunc(Number.isFinite(Number(saved.spawnIntervalMs)) ? Number(saved.spawnIntervalMs) : config.spawnIntervalMs)),
      nextSpawnAt: groupDungeonPauseTimestamp(saved.nextSpawnIn, now) || now,
      complete: Boolean(saved.complete || paused.run.complete),
    };
  })() : null;
  state.battle.swarm = {
    enemies: restoredEnemies,
    nextId: Math.max(maxEnemyId, Math.trunc(Number(swarmSnapshot?.nextId) || 0)),
    lastAdvanceAt: now,
    waves,
    bossSwarm,
  };
  if (state.battle.bossParty) {
    state.battle.bossParty.petDiedThisFight = Boolean(paused.bossParty?.petDiedThisFight);
    const meleeFrontSlotWorldX = Number(paused.bossParty?.meleeFrontSlotWorldX);
    if (Number.isFinite(meleeFrontSlotWorldX)) state.battle.bossParty.meleeFrontSlotWorldX = Math.round(meleeFrontSlotWorldX);
    const pet = restoreGroupDungeonPausedPet(paused.pet, now);
    state.battle.bossParty.pet = pet;
    state.battle.taoPet = pet;
  }
  state.battle.groundSpellEffects = restoreGroupDungeonPausedGroundEffects(paused.groundSpellEffects, now);
  if (!isBossSwarm && waves && !restoredEnemies.length && !waves.floorComplete) spawnGroupDungeonWaveBurst(now);
  if (isBossSwarm && !restoredEnemies.length) spawnPendingGroupDungeonBossSwarmEnemies(now);
  syncGroupDungeonPrimaryEnemy();
  markGroupDungeonWaveUiDirty();
  void Promise.all(restoredEnemies.map((enemy) => ensureSwarmEnemyAtlas(enemy)));
  return true;
}

function resetGroupDungeonRun(now = performance.now()) {
  const zone = groupDungeonWaveZone();
  state.battle.swarm = {
    enemies: [],
    nextId: 0,
    lastAdvanceAt: now,
    waves: createGroupDungeonWaveState(now, 1, zone),
  };
  startGroupDungeonWave(now);
  markGroupDungeonWaveUiDirty();
}

function groupDungeonWaveState() {
  return state.battle.swarm?.waves ?? null;
}

function groupDungeonWaveSignature() {
  const waves = groupDungeonWaveState();
  if (!waves) return null;
  return {
    waveNumber: waves.waveNumber,
    spawnedThisWave: waves.spawnedThisWave,
    killedThisWave: waves.killedThisWave,
    targetThisWave: waves.targetThisWave,
    spawningComplete: waves.spawningComplete,
    floorComplete: waves.floorComplete,
    endless: waves.endless,
    living: groupDungeonSwarmLivingCount(),
  };
}

function groupDungeonSwarmLivingCount(swarm = state.battle.swarm) {
  return (swarm?.enemies ?? []).filter((enemy) => enemy.hp > 0 && !enemy.dying).length;
}

function groupDungeonSwarmAliveCount(swarm = state.battle.swarm) {
  return groupDungeonSwarmLivingCount(swarm);
}

function markGroupDungeonWaveUiDirty() {
  gamePanelSignature = "";
}

function invalidateGroupDungeonWaveUi() {
  markGroupDungeonWaveUiDirty();
  renderGamePanel();
}

function startGroupDungeonWave(now = performance.now()) {
  const waves = groupDungeonWaveState();
  if (!waves) return;
  const zone = groupDungeonWaveZone();
  const swarm = state.battle.swarm;
  if (swarm) {
    swarm.enemies = swarm.enemies.filter((enemy) => enemy.hp > 0 && !enemy.dying);
  }
  waves.targetThisWave = groupDungeonWaveSpawnCount(waves.waveNumber, zone);
  waves.spawnedThisWave = 0;
  waves.killedThisWave = 0;
  waves.spawningComplete = false;
  waves.betweenWaves = false;
  waves.nextSpawnAt = now;
  pushBattleLog(`Wave ${waves.waveNumber} — ${waves.targetThisWave} monsters incoming.`);
  spawnGroupDungeonWaveBurst(now);
  if (groupDungeonWaveOutstandingCount(waves) <= 0) waves.spawningComplete = true;
  invalidateGroupDungeonWaveUi();
}

function groupDungeonWaveFieldCap(waves = groupDungeonWaveState()) {
  if (!waves) return GROUP_DUNGEON_WAVE_FIELD_CAP;
  if (waves.targetThisWave <= GROUP_DUNGEON_WAVE_INSTANT_CAP) return waves.targetThisWave;
  return GROUP_DUNGEON_WAVE_FIELD_CAP;
}

/** Monsters still owed this wave: quota minus defeated and still alive. */
function groupDungeonWaveOutstandingCount(waves = groupDungeonWaveState()) {
  if (!waves || waves.betweenWaves || (waves.floorComplete && !waves.endless)) return 0;
  return Math.max(0, waves.targetThisWave - waves.killedThisWave - groupDungeonSwarmLivingCount());
}

function groupDungeonWavePendingSpawnCount(waves = groupDungeonWaveState()) {
  const outstanding = groupDungeonWaveOutstandingCount(waves);
  if (outstanding <= 0) return 0;
  const living = groupDungeonSwarmLivingCount();
  const fieldCap = groupDungeonWaveFieldCap(waves);
  if (living >= fieldCap) return 0;
  return Math.min(outstanding, fieldCap - living);
}

function groupDungeonWaveRefillBatchCount(waves = groupDungeonWaveState()) {
  const pending = groupDungeonWavePendingSpawnCount(waves);
  if (pending <= 0) return 0;

  if (waves.targetThisWave <= GROUP_DUNGEON_WAVE_INSTANT_CAP) return pending;

  if (waves.spawnedThisWave < GROUP_DUNGEON_WAVE_FIELD_CAP) return pending;
  if (groupDungeonSwarmLivingCount() >= GROUP_DUNGEON_WAVE_REFILL_THRESHOLD) return 0;
  return Math.min(GROUP_DUNGEON_WAVE_REFILL_BATCH, pending);
}

function reconcileGroupDungeonSwarmDeaths(now = performance.now()) {
  const swarm = state.battle.swarm;
  if (!swarm?.enemies?.length) return;
  for (const enemy of swarm.enemies) {
    if (enemy.hp <= 0 && !enemy.dying) onGroupDungeonSwarmEnemyKilled(enemy, now);
  }
}

function reconcileGroupDungeonWaveKillCount() {
  const waves = groupDungeonWaveState();
  if (!waves || waves.betweenWaves) return;
  if (groupDungeonSwarmLivingCount() > 0) return;
  if (waves.killedThisWave >= waves.spawnedThisWave) return;
  waves.killedThisWave = waves.spawnedThisWave;
  markGroupDungeonWaveUiDirty();
}

function spawnGroupDungeonWaveBurst(now = performance.now(), batchSize = null) {
  const waves = groupDungeonWaveState();
  if (!waves) return 0;
  const count = batchSize ?? Math.min(
    waves.targetThisWave,
    waves.targetThisWave <= GROUP_DUNGEON_WAVE_INSTANT_CAP
      ? waves.targetThisWave
      : GROUP_DUNGEON_WAVE_FIELD_CAP,
  );
  let spawned = 0;
  for (let i = 0; i < count && waves.spawnedThisWave < waves.targetThisWave; i += 1) {
    if (spawnGroupDungeonSwarmEnemy(now + i * GROUP_DUNGEON_WAVE_BURST_STAGGER_MS)) spawned += 1;
  }
  return spawned;
}

function updateGroupDungeonWaves(now) {
  const swarm = state.battle.swarm;
  const waves = swarm?.waves;
  if (!waves || waves.betweenWaves) return;

  reconcileGroupDungeonSwarmDeaths(now);
  reconcileGroupDungeonWaveKillCount();

  if (groupDungeonWaveOutstandingCount(waves) <= 0) {
    waves.spawningComplete = true;
    return;
  }

  const batch = groupDungeonWaveRefillBatchCount(waves);
  if (batch <= 0) return;
  if (now < waves.nextSpawnAt && groupDungeonSwarmLivingCount() > 0) return;

  spawnGroupDungeonWaveBurst(now, batch);
  if (groupDungeonWaveOutstandingCount(waves) <= 0) waves.spawningComplete = true;
  else waves.nextSpawnAt = now + GROUP_DUNGEON_WAVE_REFILL_COOLDOWN_MS;
  markGroupDungeonWaveUiDirty();
}

function onGroupDungeonWaveCleared(now = performance.now()) {
  const waves = groupDungeonWaveState();
  if (!waves) return;
  const zone = groupDungeonWaveZone();
  const wavesPerFloor = groupDungeonWavesPerFloor(zone);
  pushBattleLog(`Wave ${waves.waveNumber} cleared.`);

  if (waves.waveNumber >= wavesPerFloor && !waves.endless) {
    continueGroupDungeonEndlessWaves(now);
    return;
  }

  waves.waveNumber += 1;
  startGroupDungeonWave(now);
}

function finishGroupDungeonWaveIfReady(now) {
  const waves = groupDungeonWaveState();
  if (!waves || waves.betweenWaves) return;

  reconcileGroupDungeonSwarmDeaths(now);
  reconcileGroupDungeonWaveKillCount();

  if (waves.killedThisWave >= waves.targetThisWave) {
    waves.spawningComplete = true;
    onGroupDungeonWaveCleared(now);
    return;
  }

  const batch = groupDungeonWavePendingSpawnCount(waves);
  if (batch > 0) {
    spawnGroupDungeonWaveBurst(now, batch);
    markGroupDungeonWaveUiDirty();
  }
}

function continueGroupDungeonEndlessWaves(now = performance.now()) {
  const waves = groupDungeonWaveState();
  if (!waves || waves.endless) return;
  const zone = groupDungeonWaveZone();
  const wavesPerFloor = groupDungeonWavesPerFloor(zone);
  waves.endless = true;
  waves.floorComplete = false;
  waves.betweenWaves = false;
  waves.waveNumber = wavesPerFloor + 1;
  pushBattleLog("Floor cleared — endless waves continue.");
  const nextZone = groupDungeonNextFloorZone(zone);
  if (nextZone && !groupDungeonBossZone(zone)) {
    pushBattleLog(`Advance to ${nextZone.label} when you are ready.`);
  }
  startGroupDungeonWave(now);
  invalidateGroupDungeonWaveUi();
}

function groupDungeonWaveStatusText(waves) {
  if (!waves) return { main: "", sub: "" };

  const main = `${waves.killedThisWave} / ${waves.targetThisWave} defeated`;
  const living = groupDungeonSwarmLivingCount();
  const incoming = groupDungeonWaveOutstandingCount(waves);
  const subParts = [];
  if (living > 0) subParts.push(`${living} still fighting`);
  if (incoming > 0) subParts.push(`${incoming} incoming`);
  return { main, sub: subParts.join(" · ") };
}

function groupDungeonWaveProgressLabel(waves) {
  const { main, sub } = groupDungeonWaveStatusText(waves);
  if (!main) return "";
  return sub ? `${main} · ${sub}` : main;
}

function groupDungeonWaveSidePanelHtml() {
  const waves = groupDungeonWaveState();
  if (!waves) return "";
  const zone = groupDungeonWaveZone();
  const wavesPerFloor = groupDungeonWavesPerFloor(zone);
  const floorLabel = waves.endless
    ? `Endless · Wave ${waves.waveNumber}`
    : `Wave ${Math.min(waves.waveNumber, wavesPerFloor)} / ${wavesPerFloor}`;
  const { main, sub } = groupDungeonWaveStatusText(waves);
  const tracker = Array.from({ length: wavesPerFloor }, (_, index) => {
    const wave = index + 1;
    let className = "group-dungeon-wave-dot";
    if (wave < waves.waveNumber || (waves.floorComplete && !waves.endless)) className += " is-done";
    else if (wave === waves.waveNumber && !waves.floorComplete) className += " is-active";
    return `<span class="${className}" aria-label="Wave ${wave}"></span>`;
  }).join("");
  return `
    <section class="game-card group-dungeon-wave-card">
      <div class="game-card-title">
        <strong>Waves</strong>
        <span>${escapeHtml(floorLabel)}</span>
      </div>
      <div class="group-dungeon-wave-track" aria-hidden="true">${tracker}</div>
      <p class="group-dungeon-wave-status"><strong>${escapeHtml(main)}</strong>${sub ? `<span>${escapeHtml(sub)}</span>` : ""}</p>
    </section>
  `;
}

function groupDungeonSwarmMeleeWorldX() {
  const target = bossPartyFrontTarget();
  const frontX = Number(target?.worldX);
  if (Number.isFinite(frontX)) return swarmMeleeColumnWorldX(frontX);
  const slotX = bossPartyMeleeFrontWorldX();
  if (Number.isFinite(slotX)) return swarmMeleeColumnWorldX(slotX);
  return swarmMeleeColumnWorldX(0);
}

/** Crystal BDD FireWall anchor: one tile east of the party front (melee column), centre lane. */
function groupDungeonSwarmFireWallCenterTile() {
  return {
    worldX: swarmSnapTileX(groupDungeonSwarmMeleeWorldX()),
    mapRow: arenaSpawnMapRow(),
  };
}

function groupDungeonFireWallTileKey(tile) {
  return `${swarmSnapTileX(tile.worldX)}:${Math.trunc(Number(tile.mapRow) || 0)}`;
}

function activeGroupDungeonFireWallTileKeys(now) {
  const keys = new Set();
  for (const effect of state.battle.groundSpellEffects ?? []) {
    if (effect.spellId !== "FireWall" || now >= effect.expiresAt) continue;
    for (const tile of effect.tiles ?? []) keys.add(groupDungeonFireWallTileKey(tile));
  }
  return keys;
}

function groupDungeonSwarmLivingEnemies() {
  return (state.battle.swarm?.enemies ?? []).filter((enemy) => enemy.hp > 0 && !enemy.dying);
}

function groupDungeonSwarmFireWallRows() {
  const baseRow = arenaSpawnMapRow();
  return GROUP_DUNGEON_SWARM_LANES.map((lane) => swarmLaneMapRow(lane, baseRow));
}

function groupDungeonSwarmFireWallCandidateCentersForTile(tile) {
  const targetKey = groupDungeonFireWallTileKey(tile);
  const candidates = [];
  const xs = [
    tile.worldX - GROUP_DUNGEON_SWARM_TILE_PX,
    tile.worldX,
    tile.worldX + GROUP_DUNGEON_SWARM_TILE_PX,
  ];
  for (const mapRow of groupDungeonSwarmFireWallRows()) {
    for (const worldX of xs) {
      const center = { worldX: swarmSnapTileX(worldX), mapRow };
      const coversTarget = fireWallCrossTiles(center.worldX, center.mapRow)
        .some((fireTile) => groupDungeonFireWallTileKey(fireTile) === targetKey);
      if (coversTarget) candidates.push(center);
    }
  }
  return candidates;
}

function groupDungeonSwarmFireWallInRange(center, spell, member) {
  const casterX = Number(member?.worldX ?? state.battle.playerX);
  if (!Number.isFinite(casterX)) return true;
  const rangeTiles = Math.max(1, Math.trunc(Number(spell?.range) || 9));
  return Math.abs(center.worldX - casterX) <= rangeTiles * GROUP_DUNGEON_SWARM_TILE_PX;
}

function groupDungeonSwarmBestFireWallCenterTile(spell, member, now) {
  if (!groupDungeonSwarmSideActive()) return null;
  const enemies = groupDungeonSwarmLivingEnemies();
  if (!enemies.length) return null;

  const activeTiles = activeGroupDungeonFireWallTileKeys(now);
  const uncovered = enemies.filter((enemy) => !activeTiles.has(groupDungeonFireWallTileKey(swarmEnemyReservedTile(enemy))));
  if (!uncovered.length) return null;

  const candidates = new Map();
  for (const enemy of uncovered) {
    const tile = swarmEnemyReservedTile(enemy);
    for (const center of groupDungeonSwarmFireWallCandidateCentersForTile(tile)) {
      if (!groupDungeonSwarmFireWallInRange(center, spell, member)) continue;
      candidates.set(groupDungeonFireWallTileKey(center), center);
    }
  }

  let best = null;
  let bestScore = -Infinity;
  const meleeX = groupDungeonSwarmMeleeWorldX();
  for (const center of candidates.values()) {
    const fireTiles = new Set(fireWallCrossTiles(center.worldX, center.mapRow).map(groupDungeonFireWallTileKey));
    let uncoveredHits = 0;
    let totalHits = 0;
    for (const enemy of enemies) {
      const key = groupDungeonFireWallTileKey(swarmEnemyReservedTile(enemy));
      if (!fireTiles.has(key)) continue;
      totalHits += 1;
      if (!activeTiles.has(key)) uncoveredHits += 1;
    }
    if (uncoveredHits <= 0) continue;
    const distancePenalty = Math.abs(center.worldX - meleeX) / GROUP_DUNGEON_SWARM_TILE_PX;
    const score = uncoveredHits * 100 + totalHits * 5 - distancePenalty;
    if (score > bestScore) {
      best = center;
      bestScore = score;
    }
  }
  return best;
}

function groupDungeonSwarmBangCandidateCentersForTile(tile) {
  const targetKey = groupDungeonFireWallTileKey(tile);
  const candidates = [];
  const xs = [
    tile.worldX - GROUP_DUNGEON_SWARM_TILE_PX,
    tile.worldX,
    tile.worldX + GROUP_DUNGEON_SWARM_TILE_PX,
  ];
  for (const mapRow of groupDungeonSwarmFireWallRows()) {
    for (const worldX of xs) {
      const center = { worldX: swarmSnapTileX(worldX), mapRow };
      const coversTarget = spellBangAreaTiles(center.worldX, center.mapRow)
        .some((bangTile) => groupDungeonFireWallTileKey(bangTile) === targetKey);
      if (coversTarget) candidates.push(center);
    }
  }
  return candidates;
}

function groupDungeonSwarmBangInRange(center, spell, member) {
  const casterX = Number(member?.worldX ?? state.battle.playerX);
  if (!Number.isFinite(casterX)) return true;
  const rangeTiles = Math.max(1, Math.trunc(Number(spell?.range) || 9));
  return Math.abs(center.worldX - casterX) <= rangeTiles * GROUP_DUNGEON_SWARM_TILE_PX;
}

function groupDungeonSwarmBestBangCenterTile(spell, member = null) {
  if (!groupDungeonSwarmSideActive()) return null;
  const enemies = groupDungeonSwarmLivingEnemies();
  if (!enemies.length) return null;

  const candidates = new Map();
  for (const enemy of enemies) {
    const tile = swarmEnemyReservedTile(enemy);
    for (const center of groupDungeonSwarmBangCandidateCentersForTile(tile)) {
      if (!groupDungeonSwarmBangInRange(center, spell, member)) continue;
      candidates.set(groupDungeonFireWallTileKey(center), center);
    }
  }

  let best = null;
  let bestScore = -Infinity;
  for (const center of candidates.values()) {
    const bangTiles = new Set(spellBangAreaTiles(center.worldX, center.mapRow).map(groupDungeonFireWallTileKey));
    let hits = 0;
    let remainingHp = 0;
    let fitPenalty = 0;
    for (const enemy of enemies) {
      const tile = swarmEnemyReservedTile(enemy);
      if (!bangTiles.has(groupDungeonFireWallTileKey(tile))) continue;
      hits += 1;
      remainingHp += Math.max(0, Math.trunc(Number(enemy.hp) || 0));
      const xPenalty = Math.abs(tile.worldX - center.worldX) / GROUP_DUNGEON_SWARM_TILE_PX;
      const rowPenalty = Math.abs(tile.mapRow - center.mapRow) / GROUP_DUNGEON_SWARM_CELL_HEIGHT;
      fitPenalty += xPenalty + rowPenalty;
    }
    if (hits <= 0) continue;
    const score = hits * 10000 + remainingHp / 1000 - fitPenalty * 5;
    if (score > bestScore) {
      best = center;
      bestScore = score;
    }
  }
  return best;
}

function canUseGroupDungeonSwarmBangSpell(spell, member = null) {
  return Boolean(groupDungeonSwarmBestBangCenterTile(spell, member));
}

function canUseGroupDungeonSwarmFireWall(spell, member, now) {
  return Boolean(groupDungeonSwarmBestFireWallCenterTile(spell, member, now));
}

function snapBossPartyMembersToSwarmGrid(members) {
  const front = BOSS_PARTY_ORDER
    .map((classId) => members.find((member) => member.classId === classId && member.alive && member.hp > 0))
    .find(Boolean);
  if (!front) return;
  const current = Math.round(Number(front.worldX) || 0);
  const snapped = swarmSnapTileX(current);
  const delta = snapped - current;
  if (delta === 0) return;
  for (const member of members) {
    if (Number.isFinite(member.worldX)) member.worldX = Math.round(member.worldX + delta);
  }
}

function groupDungeonSwarmOffscreenSpawnX() {
  const cameraX = Number(state.battle.cameraX);
  const resolvedCamera = Number.isFinite(cameraX)
    ? cameraX
    : (Number(state.battle.playerX) || 0) - playerScreenX();
  const screenEdge = Math.round(resolvedCamera + state.stageWidth + 96);
  const swarm = state.battle.swarm;
  const eastmost = (swarm?.enemies ?? [])
    .filter((entry) => entry.hp > 0 && !entry.dying)
    .reduce((max, entry) => Math.max(max, Math.round(Number(entry.worldX) || 0)), 0);
  return Math.max(screenEdge, eastmost + LANE_TILE_PX);
}

function buildSwarmEnemyFromTemplate(template, now, options = {}) {
  const swarm = state.battle.swarm;
  const id = ++swarm.nextId;
  const spawnX = Math.round(Number(options.spawnX) || groupDungeonSwarmOffscreenSpawnX());
  return {
    id,
    templateId: template.id,
    name: template.name,
    level: template.level,
    maxHp: template.maxHp,
    maxMp: template.maxMp,
    hp: template.maxHp,
    mp: template.maxMp,
    dc: template.dc,
    meleeDc: template.meleeDc,
    rangedDc: template.rangedDc,
    mc: template.mc,
    sc: template.sc,
    ac: template.ac,
    amc: template.amc,
    accuracy: template.accuracy,
    agility: template.agility,
    luck: template.luck,
    attackMs: template.attackMs,
    moveMs: template.moveMs,
    experience: template.experience,
    monsterIndex: template.monsterIndex,
    crystalName: template.crystalName,
    attackDefenceType: template.attackDefenceType,
    attackMode: template.attackMode,
    attackRangeTiles: template.attackRangeTiles,
    attackImpactDelayMs: template.attackImpactDelayMs,
    rangedAttackDefenceType: template.rangedAttackDefenceType,
    rangedAttackExtraMs: template.rangedAttackExtraMs,
    enrageHpStages: template.enrageHpStages,
    enrageDurationMs: template.enrageDurationMs,
    enrageAttackMs: template.enrageAttackMs,
    poisons: [],
    debuffs: { slowUntil: 0, frozenUntil: 0 },
    worldX: swarmSnapTileX(spawnX),
    mapRow: Math.trunc(Number(options.mapRow) || arenaSpawnMapRow()),
    action: "standing",
    frame: 0,
    oneShot: false,
    lastTick: now,
    atlas: null,
    nextMoveAt: now + randomInt(200, 900),
    stepFromX: null,
    stepToX: null,
    stepFromMapRow: null,
    stepToMapRow: null,
    nextAttackAt: now + randomInt(500, 1400),
    dying: false,
    removeAt: 0,
    pendingStruck: false,
    pendingStrike: null,
  };
}

async function ensureSwarmEnemyAtlas(enemy) {
  if (enemy.atlas) return enemy.atlas;
  const atlas = await loadJson(monsterAtlasJsonUrl(enemy.monsterIndex)).catch(() => null);
  ensureSwarmDirectionalActions(atlas);
  enemy.atlas = atlas;
  await loadCachedImage(monsterAtlasPngUrl(enemy.monsterIndex)).catch(() => null);
  return atlas;
}

function spawnGroupDungeonSwarmEnemy(now = performance.now(), template = randomZoneEnemyTemplate()) {
  const swarm = state.battle.swarm;
  if (!swarm || !template) return null;
  const waves = swarm.waves;
  if (waves) {
    if (waves.betweenWaves || (waves.floorComplete && !waves.endless)) return null;
    if (groupDungeonWaveOutstandingCount(waves) <= 0) return null;
  }
  const living = groupDungeonSwarmLivingCount(swarm);
  if (living >= groupDungeonWaveFieldCap(waves)) return null;
  const arenaSpawnRow = arenaSpawnMapRow();
  const spawnLane = GROUP_DUNGEON_SWARM_LANES[(waves?.spawnedThisWave ?? living) % GROUP_DUNGEON_SWARM_LANES.length];
  const enemy = buildSwarmEnemyFromTemplate(template, now, {
    mapRow: swarmLaneMapRow(spawnLane, arenaSpawnRow),
  });
  while (swarmTileOccupied(enemy.worldX, enemy.mapRow, swarm.enemies, enemy.id)) {
    enemy.worldX += LANE_TILE_PX;
  }
  swarm.enemies.push(enemy);
  if (waves) waves.spawnedThisWave += 1;
  void ensureSwarmEnemyAtlas(enemy);
  syncGroupDungeonPrimaryEnemy();
  markGroupDungeonWaveUiDirty();
  return enemy;
}

function groupDungeonPrimarySwarmEnemy(swarm = state.battle.swarm) {
  if (!swarm?.enemies?.length) return null;
  const alive = swarm.enemies.filter((enemy) => enemy.hp > 0 && !enemy.dying);
  if (!alive.length) return null;
  const meleeCol = swarmSnapTileX(groupDungeonSwarmMeleeWorldX());
  const spawnRow = arenaSpawnMapRow();
  const engaged = alive
    .filter((enemy) => swarmEnemyInAttackRange(enemy, meleeCol))
    .sort((a, b) => Math.abs(a.mapRow - spawnRow) - Math.abs(b.mapRow - spawnRow));
  if (engaged.length) return engaged[0];
  const cameraX = Number(state.battle.cameraX);
  const visibleEdgeX = (Number.isFinite(cameraX) ? cameraX : meleeCol) + state.stageWidth - 32;
  const visible = alive.filter((enemy) => enemy.worldX <= visibleEdgeX);
  const pool = visible.length ? visible : alive;
  return pool.slice().sort((a, b) => {
    const da = Math.abs(a.worldX - meleeCol) + Math.abs(a.mapRow - spawnRow) * GROUP_DUNGEON_SWARM_CELL_HEIGHT;
    const db = Math.abs(b.worldX - meleeCol) + Math.abs(b.mapRow - spawnRow) * GROUP_DUNGEON_SWARM_CELL_HEIGHT;
    return da - db;
  })[0] ?? null;
}

function swarmEnemyToBattleEntity(swarmEnemy) {
  if (!swarmEnemy) return null;
  const template = ENEMY_TEMPLATES.find((entry) => entry.id === swarmEnemy.templateId);
  return {
    ...(template ?? {}),
    id: swarmEnemy.templateId,
    name: swarmEnemy.name,
    level: swarmEnemy.level,
    maxHp: swarmEnemy.maxHp,
    maxMp: swarmEnemy.maxMp,
    hp: swarmEnemy.hp,
    mp: swarmEnemy.mp,
    dc: swarmEnemy.dc,
    meleeDc: swarmEnemy.meleeDc ?? template?.meleeDc,
    rangedDc: swarmEnemy.rangedDc ?? template?.rangedDc,
    mc: swarmEnemy.mc,
    sc: swarmEnemy.sc,
    ac: swarmEnemy.ac,
    amc: swarmEnemy.amc,
    accuracy: swarmEnemy.accuracy,
    agility: swarmEnemy.agility,
    luck: swarmEnemy.luck,
    attackMs: swarmEnemy.attackMs,
    moveMs: swarmEnemy.moveMs,
    experience: swarmEnemy.experience,
    monsterIndex: swarmEnemy.monsterIndex,
    crystalName: swarmEnemy.crystalName ?? template?.crystalName,
    attackDefenceType: swarmEnemy.attackDefenceType ?? template?.attackDefenceType,
    attackMode: swarmEnemy.attackMode ?? template?.attackMode,
    attackRangeTiles: swarmEnemy.attackRangeTiles ?? template?.attackRangeTiles,
    attackImpactDelayMs: swarmEnemy.attackImpactDelayMs ?? template?.attackImpactDelayMs,
    rangedAttackDefenceType: swarmEnemy.rangedAttackDefenceType ?? template?.rangedAttackDefenceType,
    rangedAttackExtraMs: swarmEnemy.rangedAttackExtraMs ?? template?.rangedAttackExtraMs,
    enrageHpStages: swarmEnemy.enrageHpStages ?? template?.enrageHpStages,
    enrageDurationMs: swarmEnemy.enrageDurationMs ?? template?.enrageDurationMs,
    enrageAttackMs: swarmEnemy.enrageAttackMs ?? template?.enrageAttackMs,
    enrageUntil: swarmEnemy.enrageUntil,
    enrageStage: swarmEnemy.enrageStage,
    _enrageStagesTriggered: swarmEnemy._enrageStagesTriggered,
    poisons: swarmEnemy.poisons,
    debuffs: swarmEnemy.debuffs,
    swarmId: swarmEnemy.id,
  };
}

function syncBattleEnemyHpToSwarm() {
  syncBattleEnemyRuntimeToSwarm();
}

// --- Reconstructed helpers (implementations were lost in the file corruption;
// callers survived). Rebuilt from call sites + the enrage data model
// (enrageHpStages are descending HP fractions, e.g. [0.7, 0.4, 0.15]). ---

function normalizeEnemyEnrageStages(enemy) {
  const raw = Array.isArray(enemy?.enrageHpStages) ? enemy.enrageHpStages : [];
  return raw
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value) && value > 0)
    .sort((a, b) => b - a);
}

function enemyEnrageActive(enemy, now = performance.now()) {
  if (!enemy) return false;
  const until = Number(enemy.enrageUntil);
  return Number.isFinite(until) && until > now;
}

function maybeTriggerEnemyEnrage(enemy, now = performance.now()) {
  if (!enemy) return;
  const stages = normalizeEnemyEnrageStages(enemy);
  const maxHp = Number(enemy.maxHp) || 0;
  if (!stages.length || maxHp <= 0) return;
  const triggered = Array.isArray(enemy._enrageStagesTriggered) ? enemy._enrageStagesTriggered : [];
  const fraction = Math.max(0, Number(enemy.hp) || 0) / maxHp;
  let changed = false;
  for (const stage of stages) {
    if (fraction <= stage && !triggered.includes(stage)) {
      triggered.push(stage);
      enemy.enrageStage = stage;
      const duration = Math.max(0, Math.trunc(Number(enemy.enrageDurationMs) || 0)) || 8000;
      enemy.enrageUntil = now + duration;
      changed = true;
    }
  }
  if (changed) {
    enemy._enrageStagesTriggered = triggered;
    if (isDarkDevilEnemy(enemy)) {
      enemy._darkDevilRangeReadyAt = now;
      pushBattleLog(`${enemy.name} enters a rage!`);
    }
  }
}

function reduceSwarmEnemyHp(swarmEnemy, damage, now = performance.now()) {
  if (!swarmEnemy || !(damage > 0)) return;
  swarmEnemy.hp = Math.max(0, (Number(swarmEnemy.hp) || 0) - damage);
  maybeTriggerEnemyEnrage(swarmEnemy, now);
}

function syncBattleEnemyRuntimeToSwarm() {
  const battleEnemy = state.battle?.enemy;
  if (!battleEnemy || battleEnemy.swarmId == null) return;
  const swarmEnemy = findGroupDungeonSwarmEnemy(battleEnemy.swarmId);
  if (!swarmEnemy) return;
  swarmEnemy.hp = Math.max(0, Number(battleEnemy.hp) || 0);
  if (Number.isFinite(Number(battleEnemy.mp))) swarmEnemy.mp = battleEnemy.mp;
  swarmEnemy.poisons = battleEnemy.poisons;
  swarmEnemy.debuffs = battleEnemy.debuffs;
  swarmEnemy.enrageUntil = battleEnemy.enrageUntil;
  swarmEnemy.enrageStage = battleEnemy.enrageStage;
  swarmEnemy._enrageStagesTriggered = battleEnemy._enrageStagesTriggered;
}

function noteGroupDungeonKillPace(now = performance.now()) {
  const swarm = state.battle?.swarm;
  if (!swarm) return;
  const pace = swarm.killPace && typeof swarm.killPace === "object"
    ? swarm.killPace
    : (swarm.killPace = { kills: 0, lastKillAt: 0, recent: [] });
  pace.kills += 1;
  pace.lastKillAt = now;
  pace.recent.push(now);
  if (pace.recent.length > 20) pace.recent.shift();
}

// Group-dungeon pause/resume: the detailed mid-fight snapshot/restore logic was
// lost and exists in no backup. These reconstructions are intentionally
// conservative: no pause snapshot is captured, so resume falls back to the
// offline-run path (sanitizeGroupDungeonOfflineRun), which still preserves
// wave/floor progress. The restore helpers are safe no-ops for defensiveness.
function groupDungeonPauseTimestamp(savedRelativeMs, now = performance.now()) {
  const rel = Number(savedRelativeMs);
  if (!Number.isFinite(rel)) return 0;
  return now + Math.max(0, rel);
}

function createGroupDungeonPauseSnapshot() {
  return null;
}

function sanitizeGroupDungeonPauseSnapshot() {
  return null;
}

function restoreGroupDungeonPausedSwarmEnemy() {
  return null;
}

function restoreGroupDungeonPausedPet() {
  return null;
}

function restoreGroupDungeonPausedGroundEffects() {
  return [];
}

function swarmEnemyWalkInProgress(enemy) {
  return enemy?.stepToX != null;
}

// Crystal ActionFeed: the flinch queues behind movement and attacks; it is
// consumed by the end-of-tick pass in updateGroupDungeonBossPartyBattle.
function queueSwarmEnemyStruck(enemy, now) {
  if (!enemy || enemy.dying || enemy.hp <= 0) return;
  enemy.pendingStruck = true;
}

function tryConsumeSwarmEnemyPendingStruck(enemy, now) {
  if (!enemy?.pendingStruck || enemy.dying || enemy.hp <= 0) return false;
  if (swarmEnemyWalkInProgress(enemy)) return false;
  if (enemy.oneShot && enemy.action !== "standing") return false;
  if (enemy.action === "struck") return false;
  enemy.pendingStruck = false;
  setSwarmEnemyAction(enemy, "struck", true, now);
  return true;
}

function strikeGroupDungeonSwarmEnemy(enemy, now) {
  if (!groupDungeonSwarmSideActive() || !enemy?.swarmId) {
    setEnemyAction("struck", true, now);
    return;
  }
  const swarmEnemy = findGroupDungeonSwarmEnemy(enemy.swarmId);
  if (swarmEnemy) queueSwarmEnemyStruck(swarmEnemy, now);
}

function maybeKillGroupDungeonSwarmEnemy(enemy, now) {
  if (!groupDungeonSwarmSideActive() || !enemy?.swarmId || enemy.hp > 0) return;
  const swarmEnemy = findGroupDungeonSwarmEnemy(enemy.swarmId);
  if (swarmEnemy && !swarmEnemy.dying) onGroupDungeonSwarmEnemyKilled(swarmEnemy, now);
}

function syncGroupDungeonPrimaryEnemy() {
  const swarm = state.battle.swarm;
  if (!swarm || swarm.bossReinforcements) return;
  const primary = groupDungeonPrimarySwarmEnemy();
  if (!primary) {
    if (groupDungeonBossSwarmState()) {
      state.battle.enemy = null;
      state.battle.enemyId = null;
    }
    return;
  }
  const battleEnemy = swarmEnemyToBattleEntity(primary);
  state.battle.enemy = battleEnemy;
  state.battle.enemyId = primary.templateId;
  state.battle.enemyX = Math.round(primary.worldX);
  state.enemy.index = primary.monsterIndex;
  state.enemy.action = primary.action;
  state.enemy.frame = primary.frame;
  state.enemy.oneShot = primary.oneShot;
  state.enemy.lastTick = primary.lastTick;
  if (primary.atlas) state.enemy.atlas = primary.atlas;
}

function findGroupDungeonSwarmEnemy(swarmId) {
  return state.battle.swarm?.enemies?.find((enemy) => enemy.id === swarmId) ?? null;
}

function setSwarmEnemyLocomotion(enemy, action, now = performance.now()) {
  if (!enemy) return;
  action = resolveSwarmEnemyAction(enemy, action);
  if (enemy.action === action || (enemy.oneShot && enemy.action !== "standing")) return;
  enemy.action = action;
  enemy.frame = 0;
  enemy.oneShot = false;
  enemy.lastTick = now;
}

function setSwarmEnemyAction(enemy, action, oneShot = false, now = performance.now()) {
  if (!enemy) return;
  enemy.action = resolveSwarmEnemyAction(enemy, action);
  enemy.frame = 0;
  enemy.oneShot = oneShot;
  enemy.lastTick = now;
}

function swarmIsWalkAction(action) {
  return action === "walking"
    || action === "walkEast"
    || action === "walkNorth"
    || action === "walkSouth"
    || action === "walkNorthWest"
    || action === "walkSouthWest";
}

function swarmMapRowAnchorY(mapRow) {
  const spawnRow = arenaSpawnMapRow();
  const laneY = Math.floor(state.stageHeight * LANE.y);
  const enemyOffsetY = Math.trunc(Number(activeZone()?.arenaEnemyOffsetY) || 0);
  return laneY + (Math.trunc(mapRow) - spawnRow) * GROUP_DUNGEON_SWARM_CELL_HEIGHT + enemyOffsetY;
}

// Tall ground spell art (FireWall) anchors on the cell base; foot-line Y reads one row high.
function swarmGroundSpellAnchorY(mapRow) {
  return swarmMapRowAnchorY(mapRow) + GROUP_DUNGEON_SWARM_CELL_HEIGHT;
}

// Crystal client: logical cell is at destination; OffSetMove draws back toward the previous tile center.
function swarmEnemyWalkStepProgress(enemy) {
  if (enemy.stepToX == null) return 1;
  const clip = enemy.atlas?.actions?.[enemy.action];
  const count = clip?.frames?.length ?? 1;
  return Math.min(1, (enemy.frame + 1) / count);
}

function swarmEnemyWalkDrawOffset(enemy) {
  if (enemy.stepToX == null) return { x: 0, y: 0 };
  const back = 1 - swarmEnemyWalkStepProgress(enemy);
  return {
    x: Math.round((Number(enemy.stepFromX) - Number(enemy.stepToX)) * back),
    y: Math.round((Number(enemy.stepFromMapRow) - Number(enemy.stepToMapRow)) * GROUP_DUNGEON_SWARM_CELL_HEIGHT * back),
  };
}

function swarmEnemyScreenAnchor(enemy) {
  const tile = swarmEnemyTilePosition(enemy);
  const offset = swarmEnemyWalkDrawOffset(enemy);
  return {
    x: Math.floor(tile.worldX - state.battle.cameraX + offset.x),
    y: swarmMapRowAnchorY(tile.mapRow) + offset.y,
  };
}

function clearSwarmEnemyStep(enemy, now = performance.now()) {
  enemy.stepFromX = null;
  enemy.stepToX = null;
  enemy.stepFromMapRow = null;
  enemy.stepToMapRow = null;
}

function completeSwarmEnemyStep(enemy, now = performance.now()) {
  if (enemy.stepToX == null) return;
  enemy.worldX = swarmSnapTileX(enemy.stepToX);
  enemy.mapRow = Math.trunc(enemy.stepToMapRow);
  clearSwarmEnemyStep(enemy, now);
  if (enemy.hp > 0 && !enemy.dying) {
    const meleeCol = swarmSnapTileX(groupDungeonSwarmMeleeWorldX());
    enemy.action = resolveSwarmEnemyAction(enemy, swarmEnemyEngagedStanceAction(enemy, meleeCol, arenaSpawnMapRow()));
    enemy.frame = 0;
    enemy.oneShot = false;
    enemy.lastTick = now;
  }
}

function resetSwarmEnemyWalkState(enemy, now = performance.now()) {
  if (enemy.stepToX != null) {
    enemy.worldX = swarmSnapTileX(enemy.stepFromX);
    enemy.mapRow = Math.trunc(enemy.stepFromMapRow);
  }
  clearSwarmEnemyStep(enemy, now);
  if (enemy.hp > 0 && !enemy.dying && !enemy.oneShot) {
    setSwarmEnemyLocomotion(enemy, "standing", now);
  }
}

// Crystal: logical cell snaps to destination; draw offset animates from the previous tile center.
function beginSwarmEnemyTileStep(enemy, action, fromX, fromMapRow, toX, toMapRow, now) {
  enemy.stepFromX = swarmSnapTileX(fromX);
  enemy.stepToX = swarmSnapTileX(toX);
  enemy.stepFromMapRow = Math.trunc(fromMapRow);
  enemy.stepToMapRow = Math.trunc(toMapRow);
  enemy.worldX = enemy.stepToX;
  enemy.mapRow = enemy.stepToMapRow;
  enemy.nextMoveAt = now + effectiveEnemyMoveMs(enemy, now);
  setSwarmEnemyAction(enemy, action, true, now);
}

function updateGroupDungeonSwarmMovement(now) {
  const swarm = state.battle.swarm;
  if (!swarm) return;
  const meleeCol = swarmSnapTileX(groupDungeonSwarmMeleeWorldX());
  const arenaSpawnRow = arenaSpawnMapRow();

  for (const enemy of swarm.enemies) {
    if (enemy.hp <= 0 || enemy.dying) {
      resetSwarmEnemyWalkState(enemy, now);
      if (!enemy.dying) setSwarmEnemyLocomotion(enemy, "standing", now);
      continue;
    }
    if (enemyFrozenActive(enemy, now)) {
      resetSwarmEnemyWalkState(enemy, now);
      setSwarmEnemyLocomotion(enemy, "standing", now);
      continue;
    }

    if (enemy.stepToX != null) continue;

    if (enemy.oneShot && enemy.action !== "standing") continue;

    // Crystal ProcessTarget: in attack range -> stop moving, face the target.
    if (swarmEnemyInAttackRange(enemy, meleeCol)) {
      setSwarmEnemyLocomotion(enemy, swarmEnemyEngagedStanceAction(enemy, meleeCol, arenaSpawnRow), now);
      continue;
    }

    if (now < (enemy.nextMoveAt ?? 0)) continue;

    const tile = swarmEnemyTilePosition(enemy);
    const step = swarmPickWalkStep(enemy, meleeCol, arenaSpawnRow, swarm.enemies);
    if (step) {
      beginSwarmEnemyTileStep(enemy, step.action, tile.worldX, tile.mapRow, step.toX, step.toMapRow, now);
      continue;
    }
    setSwarmEnemyLocomotion(enemy, "standing", now);
    enemy.nextMoveAt = now + GROUP_DUNGEON_SWARM_BLOCKED_RETRY_MS;
  }
}

function updateGroupDungeonSwarmEnemyFrame(enemy, now) {
  const clip = enemy.atlas?.actions?.[enemy.action];
  if (state.paused || !clip?.frames?.length) return;
  const dt = now - (enemy.lastTick ?? now);
  if (dt < clip.interval) return;
  const steps = Math.floor(dt / clip.interval);
  const terminal = enemy.oneShot || enemy.action === "struck" || enemy.action === "die";
  if (terminal) {
    const nextFrame = enemy.frame + steps;
    if (nextFrame >= clip.frames.length) {
      if (enemy.action === "die") {
        enemy.frame = clip.frames.length - 1;
        enemy.removeAt = now + 120;
      } else if (enemy.hp > 0) {
        if (enemy.stepToX != null && swarmIsWalkAction(enemy.action)) {
          completeSwarmEnemyStep(enemy, now);
        } else {
          const meleeCol = swarmSnapTileX(groupDungeonSwarmMeleeWorldX());
          enemy.action = resolveSwarmEnemyAction(enemy, swarmEnemyEngagedStanceAction(enemy, meleeCol, arenaSpawnMapRow()));
          enemy.frame = 0;
          enemy.oneShot = false;
          enemy.lastTick = now;
        }
      } else {
        enemy.frame = clip.frames.length - 1;
      }
    } else {
      enemy.frame = nextFrame;
    }
  } else {
    enemy.frame = (enemy.frame + steps) % clip.frames.length;
  }
  enemy.lastTick += steps * clip.interval;
}

function updateGroupDungeonSwarmFrames(now) {
  const swarm = state.battle.swarm;
  if (!swarm) return;
  for (const enemy of swarm.enemies) updateGroupDungeonSwarmEnemyFrame(enemy, now);
  syncGroupDungeonPrimaryEnemy();
}

function pruneGroupDungeonSwarmEnemies(now) {
  const swarm = state.battle.swarm;
  if (!swarm) return;
  reconcileGroupDungeonSwarmDeaths(now);
  swarm.enemies = swarm.enemies.filter((enemy) => {
    if (enemy.hp > 0) return true;
    if (!enemy.dying) return false;
    return !enemy.removeAt || now < enemy.removeAt;
  });
}

function awardGroupDungeonSwarmKill(swarmEnemy, now = performance.now()) {
  const party = state.battle.bossParty;
  if (!party || !swarmEnemy) return;
  const savedEnemy = state.battle.enemy;
  state.battle.enemy = swarmEnemyToBattleEntity(swarmEnemy);
  awardBossPartyKillShare(now);
  state.battle.enemy = savedEnemy;
  addLootNotice(`${swarmEnemy.name} defeated`, "mob");
}

function onGroupDungeonSwarmEnemyKilled(swarmEnemy, now = performance.now()) {
  if (!swarmEnemy || swarmEnemy.dying) return;
  const bossSwarm = groupDungeonBossSwarmState();
  if (swarmEnemy.isBossSwarm) {
    const party = state.battle.bossParty;
    const entity = swarmEnemyToBattleEntity(swarmEnemy);
    const lootClassId = party?.leaderClassId ?? state.activeCharacterId;
    if (bossDropTableForEnemy(entity)) {
      awardBossPartyBossKillShare(entity, now, lootClassId);
    } else {
      const savedEnemy = state.battle.enemy;
      state.battle.enemy = entity;
      awardBossPartyKillShare(now, { enemy: entity });
      state.battle.enemy = savedEnemy;
    }
    addLootNotice(`${swarmEnemy.name} defeated`, "boss");
    if (bossSwarm) bossSwarm.killed += 1;
  } else {
    awardGroupDungeonSwarmKill(swarmEnemy, now);
    noteGroupDungeonKillPace(now);
  }
  swarmEnemy.dying = true;
  swarmEnemy.hp = 0;
  setSwarmEnemyAction(swarmEnemy, "die", true, now);
  playMonsterSfx("death", swarmEnemy);
  pushBattleLog(`${swarmEnemy.name} is defeated.`);
  const waves = groupDungeonWaveState();
  if (waves && !groupDungeonBossReinforcementsActive()) waves.killedThisWave += 1;
  markGroupDungeonWaveUiDirty();
  syncGroupDungeonPrimaryEnemy();
}


function isIncarnatedRedThunderZumaEnemy(enemy) {
  if (!enemy) return false;
  const id = Math.trunc(Number(enemy.id ?? enemy.templateId) || 0);
  return id === INCARNATED_RTZ_ENEMY_ID;
}

function isRedThunderZumaSwarmEnemy(swarmEnemy) {
  return swarmEnemy?.templateId === INCARNATED_RTZ_ENEMY_ID;
}

function syncPrimarySwarmVisual(swarmEnemy, attackAction, now) {
  if (state.battle.swarm?.bossReinforcements) return;
  if (swarmEnemy.id !== groupDungeonPrimarySwarmEnemy()?.id) return;
  state.enemy.action = attackAction;
  state.enemy.frame = 0;
  state.enemy.oneShot = true;
  state.enemy.lastTick = now;
}

function redThunderZumaAttackRangeTiles(enemy) {
  return Math.max(1, Math.trunc(Number(enemy?.attackRangeTiles) || 9));
}

function redThunderZumaRangedExtraMs(enemy) {
  return Math.max(0, Math.trunc(Number(enemy?.rangedAttackExtraMs) || 500));
}

function bossPartyAllLivingTargets() {
  const party = state.battle.bossParty;
  const targets = [];
  if (party?.pet?.active && (party.pet.hp ?? 0) > 0) targets.push(party.pet);
  for (const member of party?.members ?? []) {
    if (member.alive && member.hp > 0) targets.push(member);
  }
  return targets;
}

function bossPartyRandomLivingTarget() {
  const targets = bossPartyAllLivingTargets();
  if (!targets.length) return null;
  return targets[Math.floor(Math.random() * targets.length)];
}

function bossPartyRandomLivingRangedTarget() {
  const targets = bossPartyAllLivingTargets();
  if (!targets.length) return null;
  const tank = bossPartyFrontTarget();
  const nonTank = tank ? targets.filter((target) => target !== tank) : targets;
  const pool = nonTank.length ? nonTank : targets;
  return pool[Math.floor(Math.random() * pool.length)];
}

function bossPartyLivingTargetsInSwarmRange(tile, partyRow, rangeTiles) {
  return bossPartyAllLivingTargets().filter(
    (target) => swarmRangeTilesBetween(tile.worldX, tile.mapRow, target.worldX, partyRow) <= rangeTiles,
  );
}

function bossPartyRandomRangedTargetInSwarmRange(tile, partyRow, rangeTiles) {
  const inRange = bossPartyLivingTargetsInSwarmRange(tile, partyRow, rangeTiles);
  if (!inRange.length) return null;
  const tank = bossPartyFrontTarget();
  const nonTank = tank ? inRange.filter((target) => target !== tank) : inRange;
  const pool = nonTank.length ? nonTank : inRange;
  return pool[Math.floor(Math.random() * pool.length)];
}

function bossPartyCombatTargetAnchor(target) {
  if (!target) return combatAnchor("player");
  return {
    x: Math.round((Number.isFinite(Number(target.worldX)) ? Number(target.worldX) : state.battle.playerX) - state.battle.cameraX),
    y: Math.round(state.stageHeight * LANE.y + 2),
  };
}

// Aim arrows at the middle of the *visible* sprite pixels (offsetY..offsetY+h), not the full slot.
const ZUMA_ARCHER_TORSO_FRACTION = 0.5;

function torsoAnchorFromFrame(anchorX, anchorY, atlas, meta, fallbackY) {
  if (!atlas || !meta || meta.empty) {
    return { x: Math.round(anchorX), y: Math.round(fallbackY) };
  }
  const width = Number(meta.w) || atlas.slotWidth || 0;
  const height = Number(meta.h) || atlas.slotHeight || 0;
  const offsetX = Number(meta.offsetX) || 0;
  const offsetY = Number(meta.offsetY) || 0;
  return {
    x: Math.round(anchorX + offsetX + width / 2),
    y: Math.round(anchorY + offsetY + height * ZUMA_ARCHER_TORSO_FRACTION),
  };
}

/** Torso aim point for party sprites (mid-height of the rendered body, not the foot line). */
function bossPartyMemberTorsoAnchor(member) {
  const anchorX = Math.round((Number(member?.worldX ?? state.battle.playerX)) - state.battle.cameraX);
  const anchorY = Math.floor(state.stageHeight * LANE.y);
  const action = member?.visualAction ?? (member?.alive !== false ? "stance" : "die");
  const torsoLayers = ["armour", "hair", "weapon", "weaponBack", "weaponFront", "weaponAlt", "effect"];
  for (const layer of torsoLayers) {
    const atlas = member?.visualAtlases?.[layer]
      ?? (member?.classId === bossPartyControlledClassId() ? state.atlases[layer] : null);
    if (!atlas) continue;
    const clip = atlas.actions?.[action] ?? atlas.actions?.stance ?? atlas.actions?.standing;
    const frameIndex = Math.max(0, Math.min(Number(member?.visualFrame) || 0, (clip?.frames?.length ?? 1) - 1));
    const meta = clip?.frames?.[frameIndex] ?? clip?.frames?.[0];
    if (!clip || !meta || meta.empty) continue;
    return torsoAnchorFromFrame(anchorX, anchorY, atlas, meta, anchorY - 40);
  }
  return { x: anchorX, y: Math.round(anchorY - 40) };
}

/** Zuma Archer travel arrow aim point — torso center, not feet. */
function zumaArcherProjectileTargetAnchor(target) {
  const party = state.battle.bossParty;
  if (target === party?.pet) {
    const pet = state.battle.taoPet;
    const anchor = taoistPetAnchor();
    const atlas = taoPetAtlasFor(pet);
    const clip = atlas?.actions?.[pet?.action];
    const meta = clip?.frames?.[pet?.frame ?? 0] ?? clip?.frames?.[0];
    return torsoAnchorFromFrame(anchor.x, anchor.y, atlas, meta, anchor.y - 28);
  }
  return bossPartyMemberTorsoAnchor(target);
}

function swarmRangeTilesBetween(worldXA, mapRowA, worldXB, mapRowB) {
  const ax = kingScorpionLaneTile(worldXA);
  const bx = kingScorpionLaneTile(worldXB);
  const ay = Math.trunc(Number(mapRowA) || 0);
  const by = Math.trunc(Number(mapRowB) || 0);
  return Math.max(Math.abs(ax - bx), Math.abs(ay - by));
}

function redThunderZumaSwarmMeleeAttack(swarmEnemy, entity, target, tile, partyRow, now) {
  const lane = swarmLaneFromMapRow(tile.mapRow, partyRow);
  const attackAction = swarmAttackActionForLane(lane);
  setSwarmEnemyAction(swarmEnemy, attackAction, true, now);
  syncPrimarySwarmVisual(swarmEnemy, attackAction, now);
  playMonsterSfx("attack", swarmEnemy);
  applySwarmEnemyStrikeToTarget(swarmEnemy, entity, target, now, { ranged: false });
  swarmEnemy.nextAttackAt = now + effectiveEnemyAttackMs(swarmEnemy, now);
  return true;
}

function redThunderZumaSwarmRangedAttack(swarmEnemy, entity, target, now) {
  const impactDelay = Math.max(100, Math.trunc(Number(entity.attackImpactDelayMs) || 500));
  const attackAction = swarmEnemy.atlas?.actions?.attackRange2
    ? "attackRange2"
    : (swarmEnemy.atlas?.actions?.attackRange1 ? "attackRange1" : "attack1");
  setSwarmEnemyAction(swarmEnemy, attackAction, true, now);
  syncPrimarySwarmVisual(swarmEnemy, attackAction, now);
  playMonsterSfx("attack", swarmEnemy);
  swarmEnemy.pendingStrike = {
    startedAt: now,
    at: now + impactDelay,
    vfxUntil: now + RED_THUNDER_ZUMA_LIGHTNING_DELAY_MS + RED_THUNDER_ZUMA_LIGHTNING_DURATION_MS,
    variantIndex: Math.floor(Math.random() * 3),
    ranged: true,
    target,
    resolved: false,
  };
  swarmEnemy.nextAttackAt = now + effectiveEnemyAttackMs(swarmEnemy, now) + redThunderZumaRangedExtraMs(entity);
  return true;
}

function beginRedThunderZumaSwarmAttack(swarmEnemy, now) {
  if (!swarmEnemy || swarmEnemy.hp <= 0 || swarmEnemy.pendingStrike) return false;
  if (!state.battle.enemyRevealed) return false;

  const entity = swarmEnemyToBattleEntity(swarmEnemy);
  const tile = swarmEnemyTilePosition(swarmEnemy);
  const partyRow = arenaSpawnMapRow();
  const rangeTiles = redThunderZumaAttackRangeTiles(entity);

  const tank = bossPartyFrontTarget();
  if (tank) {
    const tankDistance = swarmRangeTilesBetween(tile.worldX, tile.mapRow, tank.worldX, partyRow);
    if (tankDistance <= 1) {
      return redThunderZumaSwarmMeleeAttack(swarmEnemy, entity, tank, tile, partyRow, now);
    }
  }

  const target = bossPartyRandomRangedTargetInSwarmRange(tile, partyRow, rangeTiles);
  if (!target) return false;

  return redThunderZumaSwarmRangedAttack(swarmEnemy, entity, target, now);
}

const applySwarmEnemyStrikeToTarget = (swarmEnemy, entity, target, now, { ranged = false } = {}) => {
  const { hit, damage } = ranged
    ? resolveIncomingEnemyRangedAttack(entity, defenceTargetForIncomingAttack(target))
    : resolveIncomingEnemyAttack(entity, defenceTargetForIncomingAttack(target));
  if (!hit) {
    addCombatText(
      target.classId === bossPartyControlledClassId() ? "player" : (target === state.battle.bossParty?.pet ? "pet" : "enemy"),
      "Miss",
      "miss",
      now,
    );
    pushBattleLog(`${swarmEnemy.name} misses ${target.name ?? target.classId}.`);
    return;
  }
  target.hp = Math.max(0, target.hp - damage);
  if (target === state.battle.bossParty?.pet) {
    setTaoPetAction("struck", true, now);
    addCombatText("pet", damage, "enemyDamage", now);
    if (target.hp <= 0) bossPartyMarkPetDead(now);
  } else if (target.classId === bossPartyControlledClassId()) {
    setPlayerAction("struck", now + 250, true);
    addCombatText("player", damage, "enemyDamage", now);
    playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
  } else {
    target.visualAction = "struck";
    target.visualFrame = 0;
    target.visualOneShot = true;
    target.visualLastTick = now;
    addCombatText("enemy", damage, "enemyDamage", now);
    playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
  }
  pushBattleLog(`${swarmEnemy.name} hits ${target.name ?? target.classId} for ${damage}.`);
  if (target !== state.battle.bossParty?.pet && target.hp <= 0) bossPartyMarkMemberDead(target, now);
}

const beginZumaArcherSwarmAttack = createZumaArcherSwarmAttack({
  swarmEnemyToBattleEntity,
  arenaSpawnMapRow,
  bossPartyFrontTarget,
  bossPartyRandomRangedTargetInSwarmRange,
  swarmRangeTilesBetween,
  setSwarmEnemyAction,
  syncPrimarySwarmVisual,
  playMonsterSfx,
  enemyAttackSfxKind,
  swarmEnemyScreenAnchor,
  zumaArcherProjectileTargetAnchor,
  enemyProjectileVfxUntil,
  effectiveEnemyAttackMs,
  applySwarmEnemyStrikeToTarget,
  enemyRevealed: () => Boolean(state.battle.enemyRevealed),
});

function resolveSwarmRangedStrike(swarmEnemy, strike, now) {
  const target = strike?.target;
  if (!target || (target.hp ?? 0) <= 0) return;
  const entity = swarmEnemyToBattleEntity(swarmEnemy);
  applySwarmEnemyStrikeToTarget(swarmEnemy, entity, target, now, { ranged: true });
}

function resolveRedThunderZumaSwarmRangedStrike(swarmEnemy, strike, now) {
  resolveSwarmRangedStrike(swarmEnemy, strike, now);
}

function updateSwarmEnemyPendingStrikes(now) {
  const swarm = state.battle.swarm;
  if (!swarm?.enemies?.length) return;
  for (const swarmEnemy of swarm.enemies) {
    const strike = swarmEnemy.pendingStrike;
    if (!strike) continue;
    if (now >= strike.at && !strike.resolved) {
      strike.resolved = true;
      if (isRedThunderZumaSwarmEnemy(swarmEnemy)) {
        resolveRedThunderZumaSwarmRangedStrike(swarmEnemy, strike, now);
      } else {
        resolveSwarmRangedStrike(swarmEnemy, strike, now);
      }
    }
    if (now >= (Number(strike.vfxUntil) || strike.at)) {
      swarmEnemy.pendingStrike = null;
    }
  }
}

function groupDungeonSwarmEnemyAttack(swarmEnemy, now) {
  if (isRedThunderZumaSwarmEnemy(swarmEnemy)) {
    return beginRedThunderZumaSwarmAttack(swarmEnemy, now);
  }
  if (isZumaArcherSwarmEnemy(swarmEnemy)) {
    return beginZumaArcherSwarmAttack(swarmEnemy, now);
  }
  const target = bossPartyFrontTarget();
  if (!swarmEnemy || !target || swarmEnemy.hp <= 0 || !state.battle.enemyRevealed) return false;
  const meleeCol = swarmSnapTileX(groupDungeonSwarmMeleeWorldX());
  if (!swarmEnemyInAttackRange(swarmEnemy, meleeCol)) return false;
  const lane = swarmLaneFromMapRow(swarmEnemyTilePosition(swarmEnemy).mapRow, arenaSpawnMapRow());
  const attackAction = swarmAttackActionForLane(lane);
  setSwarmEnemyAction(swarmEnemy, attackAction, true, now);
  syncPrimarySwarmVisual(swarmEnemy, attackAction, now);
  playMonsterSfx("attack", swarmEnemy);
  const { hit, damage } = resolveIncomingEnemyAttack(swarmEnemy, defenceTargetForIncomingAttack(target));
  if (!hit) {
    addCombatText(target.classId === bossPartyControlledClassId() ? "player" : "enemy", "Miss", "miss", now);
    pushBattleLog(`${swarmEnemy.name} misses ${target.name}.`);
    return true;
  }
  target.hp = Math.max(0, target.hp - damage);
  if (target === state.battle.bossParty.pet) {
    setTaoPetAction("struck", true, now);
    if (target.hp <= 0) bossPartyMarkPetDead(now);
  } else if (target.classId === bossPartyControlledClassId()) {
    setPlayerAction("struck", now + 250, true);
    addCombatText("player", damage, "enemyDamage", now);
    playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
  } else {
    target.visualAction = "struck";
    target.visualFrame = 0;
    target.visualOneShot = true;
    target.visualLastTick = now;
    playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
  }
  pushBattleLog(`${swarmEnemy.name} hits ${target.name} for ${damage}.`);
  if (target !== state.battle.bossParty.pet && target.hp <= 0) bossPartyMarkMemberDead(target, now);
  return true;
}

function runGroupDungeonSwarmAttackPass(now) {
  const swarm = state.battle.swarm;
  if (!swarm?.enemies?.length) return;
  for (const swarmEnemy of swarm.enemies) {
    if (swarmEnemy.hp <= 0 || swarmEnemy.dying) continue;
    if (enemyFrozenActive(swarmEnemy, now)) continue;
    if (swarmEnemy.pendingStrike) continue;
    if (swarmEnemy.stepToX != null) continue;
    if (swarmEnemy.oneShot && swarmEnemy.action !== "standing") continue;
    if (now < (swarmEnemy.nextAttackAt ?? 0)) continue;
    if (groupDungeonSwarmEnemyAttack(swarmEnemy, now)) {
      if (!isRedThunderZumaSwarmEnemy(swarmEnemy) && !isZumaArcherSwarmEnemy(swarmEnemy)) {
        swarmEnemy.nextAttackAt = now + effectiveEnemyAttackMs(swarmEnemy, now);
      }
    }
  }
}

function updateGroupDungeonBossPartyBattle(now) {
  const party = state.battle.bossParty;
  const swarm = state.battle.swarm;
  if (!party?.active || !swarm) return false;
  bossPartySyncControlledPlayerRef();
  updateBossPartyVisualFrames(now);
  updateBossPartyMeleeAdvance(now);
  for (const member of party.members) {
    updateBossPartyMemberPotionRegen(member, now);
    updateBossPartyMemberHealRegen(member, now);
    bossPartyAutoUsePotions(member, now);
  }
  if (party.pet) updateBossPartyMemberHealRegen(party.pet, now);
  syncBossPartyControlledRecoveryToState();
  updateEnemyPoisons(now);
  updateBossPartyPendingPoison(now);
  updateGroundSpellEffects(now);
  updateBossPartyEffects(now);
  updateBossPartyImpacts(now);
  updateBossPartyHealFx(now);
  updateDefenceBuffFx(now);
  updatePendingTwinDrakeHits(now);
  updateAttachedSpellFx(now);
  updatePendingEnemyStrike(now);
  updatePendingPetAttack(now);
  updateCombatantPoisons(now);
  if (bossPartyAllMembersDead()) {
    finishBossPartyDefeat(now);
    return true;
  }

  updateGroupDungeonBossSwarmSpawns(now);
  if (!groupDungeonBossSwarmState()) {
    updateGroupDungeonWaves(now);
  }

  updateSwarmEnemyPendingStrikes(now);
  updateGroupDungeonSwarmMovement(now);
  pruneGroupDungeonSwarmEnemies(now);
  syncGroupDungeonPrimaryEnemy();
  if (groupDungeonBossSwarmState()) {
    finishGroupDungeonBossSwarmIfReady(now);
  } else {
    finishGroupDungeonWaveIfReady(now);
  }

  const enemy = state.battle.enemy;
  if (party.pet?.active && now >= (party.pet.nextAttackAt ?? 0)) bossPartyPetAttack(now);

  for (const member of party.members) {
    if (!member.alive || member.hp <= 0 || now < (member.nextActionAt ?? 0)) continue;
    if (bossPartyMemberIsWalkingToMelee(member)) continue;
    bossPartyMemberAction(member, now);
  }

  runGroupDungeonSwarmAttackPass(now);

  // Crystal ActionFeed ordering: flinches play only after movement and attacks resolve.
  for (const swarmEnemy of swarm.enemies) {
    tryConsumeSwarmEnemyPendingStruck(swarmEnemy, now);
  }

  updateBossPartyMeleeAdvance(now);
  bossPartySyncControlledPlayerRef();
  if (!isPlayerOneShotAction()) setPlayerLocomotion("stance", now);
  return true;
}

function partyEntryZone() {
  return PROTOTYPE_ZONES.find((zone) => zone.id === state.bossEntryZoneId) ?? null;
}

function bossEntryZone() {
  return partyEntryZone();
}

function accountBossRespawns() {
  return sanitizeBossRespawns(state.account?.bossRespawns ?? {});
}

function migrateAccountBossRespawns() {
  const merged = { ...accountBossRespawns() };
  for (const classId of CHARACTER_IDS) {
    const respawns = sanitizeBossRespawns(state.characters[classId]?.game?.bossRespawns);
    for (const [zoneId, readyAt] of Object.entries(respawns)) {
      if (readyAt > (merged[zoneId] ?? 0)) merged[zoneId] = readyAt;
    }
  }
  state.account.bossRespawns = merged;
  syncAccountBossRespawnsToCharacters();
}

function syncAccountBossRespawnsToCharacters() {
  const respawns = accountBossRespawns();
  state.game.bossRespawns = { ...respawns };
  for (const classId of CHARACTER_IDS) {
    const character = state.characters[classId];
    if (!character) continue;
    character.game.bossRespawns = { ...respawns };
  }
}

function groupDungeonBossRespawnMinutes(zone = activeZone()) {
  if (!zone || (!groupDungeonBossZone(zone) && !groupDungeonBossSwarmZone(zone))) return 0;
  return Math.max(0, Math.trunc(Number(zone?.groupDungeonBossRespawnMinutes) || 0));
}

function zoneTracksBossRespawn(zoneId) {
  if (bossRoomDef(zoneId)) return true;
  const zone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId);
  return groupDungeonBossRespawnMinutes(zone) > 0;
}

function groupDungeonBossRespawnRemainingMs(zone = activeZone()) {
  const zoneId = typeof zone === "string" ? zone : zone?.id;
  const zoneRef = typeof zone === "string" ? PROTOTYPE_ZONES.find((entry) => entry.id === zone) : zone;
  if (!zoneId || groupDungeonBossRespawnMinutes(zoneRef) <= 0) return 0;
  return bossRespawnRemainingMs(zoneId);
}

function groupDungeonBossCanSkipFloor(zone = activeZone(), party = state.battle.bossParty) {
  if (!party?.active || party.finished || party.defeated) return false;
  if (groupDungeonBossRespawnRemainingMs(zone) <= 0) return false;
  if (groupDungeonBossZone(zone)) {
    return !state.battle.enemy;
  }
  if (groupDungeonBossSwarmZone(zone)) {
    const bossSwarm = groupDungeonBossSwarmState();
    return Boolean(bossSwarm && !bossSwarm.complete && bossSwarm.spawned === 0 && groupDungeonSwarmLivingCount() === 0);
  }
  return false;
}

function bossRespawnDelayMs(zoneId) {
  const def = bossRoomDef(zoneId);
  if (def) return Math.max(0, Math.trunc(Number(def.respawnMinutes) || 0) * 60 * 1000);
  const zone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId);
  return groupDungeonBossRespawnMinutes(zone) * 60 * 1000;
}

function bossRespawnReadyAt(zoneId) {
  return Math.max(0, Math.trunc(Number(accountBossRespawns()[zoneId]) || 0));
}

function setBossRespawn(zoneId, defeatedAt = Date.now()) {
  if (!zoneTracksBossRespawn(zoneId)) return;
  let defeatTime = Math.max(0, Math.trunc(Number(defeatedAt) || Date.now()));
  // Boss-swarm finish passes performance.now(); respawn checks use Date.now().
  if (defeatTime < 1_000_000_000_000) defeatTime = Date.now();
  const readyAt = defeatTime + bossRespawnDelayMs(zoneId);
  state.account.bossRespawns = {
    ...accountBossRespawns(),
    [zoneId]: readyAt,
  };
  syncAccountBossRespawnsToCharacters();
  incrementAccountBossKill(zoneId);
}

function bossRespawnRemainingMs(zoneId, now = Date.now()) {
  return Math.max(0, bossRespawnReadyAt(zoneId) - now);
}

function incrementAccountBossKill(zoneId) {
  if (!zoneTracksBossRespawn(zoneId)) return;
  const kills = accountBossKills();
  kills[zoneId] = Math.max(0, Math.trunc(Number(kills[zoneId]) || 0)) + 1;
  ensureAccountStats();
  state.account.stats.bossKills = kills;
  syncAccountBossKillsToCharacters();
}

function incrementBossKill(zoneId, gameState = null) {
  incrementAccountBossKill(zoneId);
  if (gameState) {
    gameState.bossKills = { ...accountBossKills() };
  }
}

function bossKillCount(zoneId) {
  return Math.max(0, Math.trunc(Number(accountBossKills()[zoneId]) || 0));
}

function selectedTownNpc() {
  return TOWN_NPCS.find((npc) => npc.id === state.game.selectedTownNpcId) ?? null;
}

function townNpcSceneHtml() {
  const npc = selectedTownNpc();
  if (!npc) {
    return `<p class="battle-state">No NPC selected.</p>`;
  }
  if (npc.role === "Teleport") return teleportNpcSceneHtml(npc);
  if (npc.role === "Trainer") return trainerNpcSceneHtml(npc);
  if (npc.role === "Trader") return traderNpcSceneHtml(npc);
  if (npc.role === "Shop") return alchemistNpcSceneHtml(npc);
  if (npc.role === "Smith") return smithNpcSceneHtml(npc);
  if (npc.role === "Refiner") return refinerNpcSceneHtml(npc);
  if (npc.role === "Storage") return storageSceneHtml();
  return `
    <section class="npc-panel">
      <strong>${escapeHtml(npc.label)}</strong>
      <span>${escapeHtml(npc.panel)}</span>
      <div class="battle-buttons">
        <button class="primary">Open ${escapeHtml(npc.role)}</button>
      </div>
    </section>
  `;
}

function traderNpcSceneHtml(npc) {
  const rows = sellableInventoryEntries()
    .map(({ entry, item }) => traderSellRowHtml(entry, item))
    .join("");
  return `
    <section class="npc-panel crystal-npc-text npc-shop-panel trader-panel">
      <div class="npc-shop-summary">
        <span>Your gold</span>
        <strong>${state.inventory.gold}g</strong>
      </div>
      <div class="npc-shop-list trader-sell-list" data-preserve-scroll="npc-trader-sell">
        ${rows || `<span class="trader-empty">No bag items to sell.</span>`}
      </div>
    </section>
  `;
}

function sellableInventoryEntries() {
  ensureInventorySlots();
  return inventoryEntries()
    .map((entry) => ({ entry, item: itemDefinition(entry.itemId) }))
    .filter(({ item }) => item && itemSellValue(item) > 0);
}

function traderSellRowHtml(entry, item) {
  const quantity = Math.max(1, Number(entry.quantity) || 1);
  const stack = quantity > 1 ? `<small>x${quantity}</small>` : "";
  const value = itemSellValue(item, quantity);
  return `
    <div class="npc-shop-row trader-sell-row" data-tooltip-item="${escapeHtml(item.id)}" data-tooltip-entry="${escapeHtml(entry.id)}">
      ${itemIconMarkup(item)}
      <span class="npc-shop-item">
        <strong>${escapeHtml(itemDisplayName(item, entry))}${stack}</strong>
        <span>${escapeHtml(shopItemMetaText(item))}</span>
      </span>
      <span class="npc-shop-price">${value}g</span>
      <button type="button" data-sell-entry="${entry.id}">Sell</button>
    </div>
  `;
}

function itemSellValue(item, quantity = 1) {
  return Math.max(0, Number(item?.shop?.sell) || 0) * Math.max(1, Number(quantity) || 1);
}

function alchemistNpcSceneHtml(npc) {
  const rows = ALCHEMIST_STOCK_IDS.map((itemId) => itemDefinition(itemId))
    .filter(Boolean)
    .map(shopBuyRowHtml)
    .join("");
  return `
    <section class="npc-panel crystal-npc-text npc-shop-panel alchemist-panel">
      <div class="npc-shop-summary">
        <span>Your gold</span>
        <strong>${state.inventory.gold}g</strong>
      </div>
      <div class="npc-shop-list" data-preserve-scroll="npc-alchemist-buy">
        ${rows || `<span class="trader-empty">No potion stock loaded.</span>`}
      </div>
    </section>
  `;
}

function shopBuyRowHtml(item) {
  const price = itemBuyValue(item);
  const owned = state.inventory.items
    .filter((entry) => entry.itemId === item.id)
    .reduce((sum, entry) => sum + Math.max(1, Math.floor(Number(entry.quantity) || 1)), 0);
  const stackQuantity = maxItemStack(item);
  const canBuy = state.inventory.gold >= price && availablePurchaseCapacityForItem(item) > 0;
  const disabled = canBuy ? "" : "disabled";
  const buttonText = state.inventory.gold < price ? "Gold" : availablePurchaseCapacityForItem(item) > 0 ? "Buy" : "Full";
  const stackButton = isStackableItem(item)
    ? `<button type="button" data-buy-stack="${escapeHtml(item.id)}" ${disabled} title="Buy up to ${stackQuantity}">x${stackQuantity}</button>`
    : "";
  return `
    <div class="npc-shop-row shop-buy-row ${canBuy ? "" : "locked"}" data-tooltip-item="${escapeHtml(item.id)}">
      ${itemIconMarkup(item)}
      <span class="npc-shop-item">
        <strong>${escapeHtml(item.name)}</strong>
        <span>${escapeHtml(shopItemMetaText(item))}${owned ? ` | Have ${owned}` : ""}</span>
      </span>
      <span class="npc-shop-price">${price}g</span>
      <span class="npc-shop-actions ${isStackableItem(item) ? "stackable" : ""}">
        <button type="button" data-buy-item="${escapeHtml(item.id)}" ${disabled}>${buttonText}</button>
        ${stackButton}
      </span>
    </div>
  `;
}

function itemBuyValue(item, quantity = 1) {
  return Math.max(0, Number(item?.shop?.buy) || 0) * Math.max(1, Number(quantity) || 1);
}

function smithNpcSceneHtml(npc) {
  const rows = smithCombineOptions().map(smithCombineRowHtml).join("");
  return `
    <section class="npc-panel crystal-npc-text npc-shop-panel smith-panel">
      <p>Combine two matching equipment items. The weaker copy is consumed. The best copy is kept (Ref level, smith +, stats, durability). Success adds +1 to the kept item's strongest stat.</p>
      <div class="npc-shop-summary">
        <span>Success chance</span>
        <strong>By + level / gem type</strong>
      </div>
      <div class="npc-shop-list smith-combine-list" data-preserve-scroll="npc-smith-combine">
        ${rows || `<span class="trader-empty">Bring me two matching equipment items.</span>`}
      </div>
    </section>
  `;
}

function refinerNpcSceneHtml(npc) {
  const junk = junkOreSellPreview();
  const sellLabel = junk.count > 0
    ? `Sell all junk ore (${junk.count.toLocaleString()} · ${junk.gold.toLocaleString()}g)`
    : "Sell all junk ore";
  return `
    <section class="npc-panel crystal-npc-text refiner-panel">
      <p>${escapeHtml(npc.panel)} Black iron ore is kept for weapon refining.</p>
      <div class="refiner-actions">
        <button type="button" class="refiner-action-button primary" data-open-weapon-refine>Refine weapon</button>
        <button type="button" class="refiner-action-button" data-head-to-mines>Head to the mines</button>
        <button type="button" class="refiner-action-button"${junk.count > 0 ? "" : " disabled"} data-sell-all-junk-ore>${escapeHtml(sellLabel)}</button>
      </div>
    </section>
  `;
}

function weaponRefineSceneHtml() {
  const oreFilled = weaponRefineOreCount();
  const materialFilled = weaponRefineMaterialCount();
  const chancePreview = weaponRefineChancePreview();
  const costPreview = weaponRefineCostPreview();
  const refineFx = weaponRefineResultFxKind();
  const canRefine = weaponRefineBoardReady()
    && chancePreview
    && !chancePreview.autoFail
    && costPreview?.canAfford
    && !refineFx;
  const weaponPickerRows = refineEligibleInventoryEntries("weapon")
    .map(({ entry, item }) => weaponRefinePickerRowHtml(entry, item))
    .join("");

  return `
    <section class="npc-panel crystal-npc-text weapon-refine-panel">
      <p class="weapon-refine-intro">
        You can input up to 5 black iron ore and 5 bits of jewellery to refine your weapon.
        Jewellery uses whichever of DC, MC, or SC totals the highest across your pieces:
        +1% per stat for the first 20, +2% for the next 20, then +0.5% beyond that (up to 50% from jewellery).
        Black iron ore and purity add up to 50% more. Best jewellery and ore can reach 100% success through Ref +5.
        From Ref +6 onward, existing refine stats on the weapon reduce success chance.
        Refine costs 50,000 gold per level (+1 costs 50k, +2 costs 100k, and so on). Gold is spent even if the refine fails.
        Failed refines will break the weapon.
      </p>
      <div class="weapon-refine-board">
        <div class="weapon-refine-row weapon-refine-row-weapon">
          <span class="weapon-refine-row-label">Weapon</span>
          ${weaponRefineSlotHtml("weapon", 0, { large: true })}
        </div>
        <div class="weapon-refine-row">
          <span class="weapon-refine-row-label">Ore</span>
          <div class="weapon-refine-slot-row">
            ${Array.from({ length: WEAPON_REFINE_ORE_SLOTS }, (_, index) => weaponRefineSlotHtml("ore", index)).join("")}
          </div>
        </div>
        <div class="weapon-refine-row">
          <span class="weapon-refine-row-label">Jewellery</span>
          <div class="weapon-refine-slot-row">
            ${Array.from({ length: WEAPON_REFINE_MATERIAL_SLOTS }, (_, index) => weaponRefineSlotHtml("material", index)).join("")}
          </div>
        </div>
      </div>
      <p class="weapon-refine-hint">
        Drag black iron ore and jewellery from inventory into the slots.
        Drag out of a slot to remove it.
        Ore ${oreFilled}/${WEAPON_REFINE_ORE_SLOTS} · Jewellery ${materialFilled}/${WEAPON_REFINE_MATERIAL_SLOTS}
      </p>
      <p class="weapon-refine-cost">${escapeHtml(weaponRefineCostText(costPreview))}</p>
      <p class="weapon-refine-chance">${escapeHtml(weaponRefineChanceText(chancePreview))}</p>
      ${refineFx ? `<p class="weapon-refine-result weapon-refine-result-${escapeHtml(refineFx)}">${refineFx === "fail" ? "The weapon shattered…" : refineFx === "crit" ? "Critical refine!" : "Refine successful!"}</p>` : ""}
      <div class="weapon-refine-weapon-picker">
        <p class="weapon-refine-picker-label">Place weapon</p>
        <div class="npc-shop-list weapon-refine-picker" data-preserve-scroll="weapon-refine-picker">
          ${weaponPickerRows || `<span class="trader-empty">No eligible weapons in your bag.</span>`}
        </div>
      </div>
      <div class="weapon-refine-actions">
        <button type="button" class="refiner-action-button primary"${canRefine ? "" : " disabled"} data-attempt-weapon-refine>${costPreview ? `Refine weapon (${costPreview.cost.toLocaleString()}g)` : "Refine weapon"}</button>
      </div>
    </section>
  `;
}

function weaponRefineSlotHtml(kind, index, { large = false } = {}) {
  const picker = state.weaponRefine.picker ?? { kind: "weapon", index: 0 };
  const selected = kind === "weapon" && picker.kind === kind && picker.index === index;
  const refineFx = kind === "weapon" ? weaponRefineResultFxKind() : null;
  const { entry, item } = weaponRefineSlotEntry(kind, index);
  const slotClass = [
    "weapon-refine-slot",
    large ? "weapon-refine-slot-weapon" : "",
    selected ? "selected" : "",
    entry ? "filled" : "",
    kind === "ore" || kind === "material" ? "weapon-refine-slot-drop" : "",
    refineFx ? `weapon-refine-fx-${refineFx}` : "",
    refineFx ? "weapon-refine-fx-active" : "",
  ].filter(Boolean).join(" ");
  const purity = entry && item && kind === "ore" ? `<span class="weapon-refine-purity">P${orePurity(entry, item)}</span>` : "";
  const filledContent = entry && item
    ? `
      <div
        class="weapon-refine-slot-item has-tooltip ${kind === "weapon" ? "" : "weapon-refine-slot-draggable"}"
        ${kind === "weapon" ? "" : `data-refine-board-entry="${escapeHtml(entry.id)}" data-refine-board-kind="${escapeHtml(kind)}" data-refine-board-index="${index}"`}
        data-tooltip-item="${escapeHtml(item.id)}"
        data-tooltip-entry="${escapeHtml(entry.id)}"
        title="${escapeHtml(itemDisplayName(item, entry))}"
      >
        ${itemIconMarkup(item)}
        ${purity}
        ${kind === "weapon" && refineFx === "fail" ? `<span class="weapon-refine-crack" aria-hidden="true"></span>` : ""}
      </div>
    `
    : `<span class="weapon-refine-slot-empty">+</span>`;

  if (kind === "weapon") {
    return `
      <button
        type="button"
        class="${slotClass}"
        data-refine-slot="${escapeHtml(kind)}"
        data-refine-index="${index}"
        ${refineFx ? "disabled" : ""}
        title="${entry && item ? escapeHtml(itemDisplayName(item, entry)) : "Select weapon slot"}"
      >${filledContent}</button>
    `;
  }

  return `
    <div
      class="${slotClass}"
      data-refine-slot="${escapeHtml(kind)}"
      data-refine-index="${index}"
      title="${kind === "ore" ? "Drop black iron ore here" : "Drop jewellery here"}"
    >${filledContent}</div>
  `;
}

function weaponRefinePickerRowHtml(entry, item) {
  const purity = isOreItem(item) ? ` | Purity ${orePurity(entry, item)}` : "";
  const statHint = isRefineJewelleryItem(item) ? refineJewelleryStatHint(entry, item) : "";
  return `
    <div class="npc-shop-row weapon-refine-picker-row" data-tooltip-item="${escapeHtml(item.id)}" data-tooltip-entry="${escapeHtml(entry.id)}">
      ${itemIconMarkup(item)}
      <span class="npc-shop-item">
        <strong>${escapeHtml(itemDisplayName(item, entry))}</strong>
        <span>${escapeHtml(statHint || shopItemMetaText(item))}${purity}</span>
      </span>
      <button type="button" data-refine-pick="${escapeHtml(entry.id)}">Place</button>
    </div>
  `;
}

function refineJewelleryStatHint(entry, item) {
  const stats = itemEntryStats(entry, item);
  const dc = refineOffensiveStatSum(stats, "dc");
  const mc = refineOffensiveStatSum(stats, "mc");
  const sc = refineOffensiveStatSum(stats, "sc");
  const parts = [];
  if (dc > 0) parts.push(`DC ${dc}`);
  if (mc > 0) parts.push(`MC ${mc}`);
  if (sc > 0) parts.push(`SC ${sc}`);
  if (parts.length === 0) {
    const ac = smithRangeStatValue(stats, "ac");
    const amc = smithRangeStatValue(stats, "amc");
    if (ac > 0) parts.push(`AC ${ac}`);
    if (amc > 0) parts.push(`AMC ${amc}`);
  }
  return parts.length ? parts.join(" · ") : title(item.slot);
}

function smithCombineRowHtml(option) {
  const { item, target, material, entries, stat, chance } = option;
  const count = entries.length;
  const keepName = itemDisplayName(item, target);
  const consumeName = itemDisplayName(item, material);
  const consumeLabel = keepName === consumeName
    ? "plain copy"
    : escapeHtml(consumeName);
  return `
    <div class="npc-shop-row smith-combine-row" data-tooltip-item="${escapeHtml(item.id)}" data-tooltip-entry="${escapeHtml(target.id)}">
      ${itemIconMarkup(item)}
      <span class="npc-shop-item">
        <strong>${escapeHtml(keepName)}</strong>
        <span>${count} owned | Keeps best | +1 ${escapeHtml(stat.label)} | Consumes ${consumeLabel}</span>
      </span>
      <span class="npc-shop-price">${smithChanceText(chance)}</span>
      <button type="button" data-smith-combine="${escapeHtml(target.id)}">Combine</button>
    </div>
  `;
}

function shopItemMetaText(item) {
  if (isPotionItem(item)) {
    const parts = potionRestoreParts(potionRestoreAmount(item, "hp"), potionRestoreAmount(item, "mp"));
    const mode = potionRestoreMode(item) === "instant" ? "instant" : "over time";
    return parts ? `${parts}, ${mode}` : "Potion";
  }
  if (isPoisonItem(item)) return item.poison?.type === "green" ? "Poison damage powder" : "Defence weakening powder";
  if (isTaoistAmuletItem(item)) return "Taoist spell amulet";
  if (item?.type === "book") return "Skill book";
  if (item?.slot) return title(item.slot);
  return title(item?.type ?? "Item");
}

function teleportRegionById(regionId) {
  return TELEPORT_REGIONS.find((region) => region.id === regionId) ?? TELEPORT_REGIONS[0];
}

function teleportRegionZones(region) {
  const zoneIds = new Set(region.zoneIds ?? []);
  return PROTOTYPE_ZONES.filter((zone) => zoneIds.has(zone.id));
}

function trainerNpcSceneHtml(npc) {
  const zone = PROTOTYPE_ZONES.find((entry) => entry.trainingRoom);
  return `
    <section class="npc-panel crystal-npc-text trainer-panel">
      <span>${escapeHtml(npc.panel)}</span>
      <button
        type="button"
        data-enter-zone="${escapeHtml(zone?.id ?? "")}"
        class="trainer-enter-button"
        ${zone ? "" : "disabled"}
      >
        <strong>Enter Academy</strong>
        <span>Practice autocast spells on a training dummy</span>
      </button>
    </section>
  `;
}

function teleportNpcSceneHtml(npc) {
  const browseRegionId = state.teleportBrowseRegionId;
  if (!browseRegionId) {
    const regionButtons = TELEPORT_REGIONS.map((entry) => {
      const zoneCount = teleportRegionZones(entry).length;
      return `
        <button type="button" data-teleport-region="${escapeHtml(entry.id)}" class="teleport-region-button">
          <strong>${escapeHtml(entry.label)}</strong>
          <span>${zoneCount} ${zoneCount === 1 ? "zone" : "zones"}</span>
        </button>
      `;
    }).join("");
    return `
      <section class="npc-panel crystal-npc-text teleport-panel">
        <span>${escapeHtml(npc.panel)}</span>
        <div class="teleport-region-list" data-preserve-scroll="npc-teleport-regions">
          ${regionButtons}
        </div>
      </section>
    `;
  }

  const region = teleportRegionById(browseRegionId);
  const regionZones = teleportRegionZones(region);
  const zoneButtons = regionZones.map((zone) => {
    return `
      <button data-enter-zone="${zone.id}" class="teleport-zone-button">
        <strong>${escapeHtml(zone.label)}</strong>
      </button>
    `;
  }).join("");
  return `
    <section class="npc-panel crystal-npc-text teleport-panel">
      <header class="teleport-zone-header">
        <button type="button" data-teleport-back class="teleport-back-button">Back</button>
        <strong>${escapeHtml(region.label)}</strong>
      </header>
      <div class="teleport-zone-list" data-preserve-scroll="npc-teleport-zones-${escapeHtml(region.id)}">
        ${zoneButtons || `<span class="teleport-empty">No hunting grounds open here yet.</span>`}
      </div>
    </section>
  `;
}

function randomZoneEnemyTemplate(zone = activeZone()) {
  if (isTrainingRoomZone(zone)) return trainingRoomEnemyTemplate(zone);
  const ids = zone?.enemyIds?.length ? zone.enemyIds : ENEMY_TEMPLATES.map((enemy) => enemy.id);
  const pickedId = ids[randomInt(0, ids.length - 1)];
  return ENEMY_TEMPLATES.find((enemy) => enemy.id === pickedId) ?? ENEMY_TEMPLATES[0];
}

function renderSpellControls() {
  const availableFx = new Set(state.spellIndex.spells);
  const groups = SPELL_GROUPS.map((group) => {
    const options = group.items
      .map((spell) => {
        const fx = spell === "None" || availableFx.has(spell) ? "" : " (body only)";
        return `<option value="${spell}" ${spell === state.spell ? "selected" : ""}>${spellLabel(spell)}${fx}</option>`;
      })
      .join("");
    return `<optgroup label="${group.label}">${options}</optgroup>`;
  }).join("");
  const mapped = bodyActionForSpell(state.spell);
  els.spellControls.innerHTML = `
    <label>
      Spell / skill
      <select id="spell">${groups}</select>
    </label>
    <label class="check">
      <input id="syncBodyToSpell" type="checkbox" ${state.syncBodyToSpell ? "checked" : ""} />
      Sync body action
    </label>
    <label>
      Cast gap
      <input id="castCooldown" type="range" min="0" max="3000" step="250" value="${state.castCooldownMs}" />
    </label>
    <p class="hint" id="spellMapping">Body: ${PLAYER_ACTIONS[mapped]?.label ?? mapped}</p>
  `;
  els.spellControls.querySelector("#spell").addEventListener("change", async (event) => {
    const now = performance.now();
    state.spell = event.currentTarget.value;
    state.spellStartedAt = now;
    applySpellBodyMapping(now);
    updateActionButtons();
    updateSpellMappingText();
    await reloadSpell();
    render();
  });
  els.spellControls.querySelector("#syncBodyToSpell").addEventListener("change", (event) => {
    const now = performance.now();
    state.syncBodyToSpell = event.currentTarget.checked;
    state.spellStartedAt = now;
    applySpellBodyMapping(now);
    updateActionButtons();
    updateSpellMappingText();
    render();
  });
  els.spellControls.querySelector("#castCooldown").addEventListener("input", (event) => {
    state.castCooldownMs = Number(event.currentTarget.value);
    updateSpellMappingText();
  });
}

function updateSpellMappingText() {
  const el = els.spellControls.querySelector("#spellMapping");
  if (!el) return;
  const mapped = bodyActionForSpell(state.spell);
  const fx = state.spell === "None" || state.spellIndex.spells.includes(state.spell) ? "FX" : "body only";
  el.textContent = `Body: ${PLAYER_ACTIONS[mapped]?.label ?? mapped} | ${fx} | gap ${state.castCooldownMs}ms`;
}

function applySpellBodyMapping(now = performance.now()) {
  if (!state.syncBodyToSpell) return;
  const action = bodyActionForSpell(state.spell);
  if (!PLAYER_ACTIONS[action]) return;
  state.action = action;
  state.frame = 0;
  state.playerOneShot = false;
  state.lastTick = now;
}

async function reloadSpell() {
  if (state.spell === "None" || !state.spellIndex.spells.includes(state.spell)) {
    state.spellAtlas = null;
    return;
  }
  state.spellAtlas = await loadJson(`./public/spellfx/${state.spell}/atlas.json`).catch(() => null);
}

async function loadCatalogue(spriteSet) {
  return loadJson(`./public/sprite-sets/${spriteSet}/layers.json`).catch(() => ({
    direction: 2,
    actions: Object.keys(PLAYER_ACTIONS),
    layers: {
      armour: { count: 1, indexes: [0] },
      hair: { count: 1, indexes: [0] },
      weapon: { count: 1, indexes: [0] },
    },
  }));
}

function renderLayerControls() {
  const setOptions = Object.entries(SPRITE_SETS)
    .map(([value, set]) => `<option value="${value}" ${value === state.spriteSet ? "selected" : ""}>${set.label}</option>`)
    .join("");
  const setControl = `
    <label>
      Sprite set
      <select id="spriteSet">${setOptions}</select>
    </label>
  `;

  const layerControls = layerNames()
    .map((layer) => {
      const indexes = state.catalogue.layers?.[layer]?.indexes ?? [0];
      const emptyOption = layer === "weapon" ? `<option value="" ${state.indexes[layer] == null ? "selected" : ""}>None</option>` : "";
      const options = indexes
        .slice(0, 120)
        .map((value) => `<option value="${value}" ${value === state.indexes[layer] ? "selected" : ""}>${value}</option>`)
        .join("");
      const capped = indexes.length > 120 ? `<option disabled>+ ${indexes.length - 120} more after export</option>` : "";
      return `
        <label>
          ${title(layer)}
          <select data-layer="${layer}">${emptyOption}${options}${capped}</select>
        </label>
      `;
    })
    .join("");

  els.layerControls.innerHTML = setControl + layerControls;

  els.layerControls.querySelector("#spriteSet").addEventListener("change", async (event) => {
    state.spriteSet = event.currentTarget.value;
    state.catalogue = await loadCatalogue(state.spriteSet);
    state.indexes = {};
    for (const layer of layerNames()) {
      state.indexes[layer] = layer === "weapon" ? null : state.catalogue.layers?.[layer]?.indexes?.[0] ?? 0;
    }
    applyEquippedVisualIndexes();
    renderLayerControls();
    await reloadAtlases();
  });

  els.layerControls.querySelectorAll("select").forEach((select) => {
    if (select.id === "spriteSet") return;
    select.addEventListener("change", async () => {
      state.indexes[select.dataset.layer] = select.value === "" ? null : Number(select.value);
      await reloadAtlases();
    });
  });
}

function renderActionControls() {
  els.actionGroups.innerHTML = ACTION_GROUPS.map((group) => {
    const buttons = group.actions
      .map((action) => {
        const spec = PLAYER_ACTIONS[action];
        return `<button data-action="${action}" title="${action}">${spec.label}</button>`;
      })
      .join("");
    return `<section><h2>${group.label}</h2><div class="action-grid">${buttons}</div></section>`;
  }).join("");

  els.actionGroups.querySelectorAll("button").forEach((button) => {
    button.addEventListener("click", () => {
      stopOneStepTest();
      state.action = button.dataset.action;
      state.frame = 0;
      state.playerOneShot = false;
      state.lastTick = performance.now();
      updateActionButtons();
      render();
    });
  });
  updateActionButtons();
}

function bindControls() {
  root.addEventListener("click", (event) => {
    if (handleInventoryCarryClick(event)) {
      event.stopImmediatePropagation();
      return;
    }

    const sceneButton = event.target.closest("[data-open-scene]");
    if (sceneButton && root.contains(sceneButton)) {
      openScene(sceneButton.dataset.openScene);
      return;
    }
    const selectPlayerClassButton = event.target.closest("[data-select-player-class]");
    if (selectPlayerClassButton && root.contains(selectPlayerClassButton)) {
      void selectPlayerClass(selectPlayerClassButton.dataset.selectPlayerClass);
      return;
    }
    const switchPartyMemberButton = event.target.closest("[data-switch-party-member]");
    if (switchPartyMemberButton && root.contains(switchPartyMemberButton)) {
      switchControlledPartyMember(switchPartyMemberButton.dataset.switchPartyMember);
      return;
    }
    const exportSaveButton = event.target.closest("[data-export-save]");
    if (exportSaveButton && root.contains(exportSaveButton)) {
      exportGameSave();
      return;
    }
    const importSaveButton = event.target.closest("[data-import-save]");
    if (importSaveButton && root.contains(importSaveButton)) {
      const textarea = root.querySelector("#saveImportText");
      void importGameSaveFromText(textarea?.value ?? "");
      return;
    }
    const resetSaveButton = event.target.closest("[data-reset-save]");
    if (resetSaveButton && root.contains(resetSaveButton)) {
      resetSavedGame();
      return;
    }
    const musicToggleButton = event.target.closest("[data-toggle-music]");
    if (musicToggleButton && root.contains(musicToggleButton)) {
      setMusicEnabled(!state.settings.musicEnabled);
      return;
    }
    const sfxToggleButton = event.target.closest("[data-toggle-sfx]");
    if (sfxToggleButton && root.contains(sfxToggleButton)) {
      setSfxEnabled(!state.settings.sfxEnabled);
      if (!state.settings.sfxEnabled) return;
      playSfx("ui.button");
      return;
    }
    const prototypeStatsToggleButton = event.target.closest("[data-toggle-prototype-stats]");
    if (prototypeStatsToggleButton && root.contains(prototypeStatsToggleButton)) {
      setPrototypeStatsEnabled(!state.settings.prototypeStatsEnabled);
      return;
    }
    const musicNextButton = event.target.closest("[data-music-next]");
    if (musicNextButton && root.contains(musicNextButton)) {
      if (!state.settings.musicEnabled) state.settings.musicEnabled = true;
      playNextMusicTrack();
      saveGameState(true);
      return;
    }
    const musicTrackButton = event.target.closest("[data-music-track]");
    if (musicTrackButton && root.contains(musicTrackButton)) {
      if (!state.settings.musicEnabled) state.settings.musicEnabled = true;
      setMusicTrack(Number(musicTrackButton.dataset.musicTrack), true, MUSIC_MODE_TRACK);
      saveGameState(true);
      return;
    }
    const closeOfflineReportButton = event.target.closest("[data-close-offline-report]");
    if (closeOfflineReportButton && root.contains(closeOfflineReportButton)) {
      closeOfflineReport();
      return;
    }
    const acceptPrototypeStatsButton = event.target.closest("[data-accept-prototype-stats]");
    if (acceptPrototypeStatsButton && root.contains(acceptPrototypeStatsButton)) {
      acceptPrototypeStatsNotice();
      return;
    }
    const acceptPrototypeResetButton = event.target.closest("[data-accept-prototype-reset-notice]");
    if (acceptPrototypeResetButton && root.contains(acceptPrototypeResetButton)) {
      acceptPrototypeResetNotice();
      return;
    }
    const disablePrototypeStatsButton = event.target.closest("[data-disable-prototype-stats]");
    if (disablePrototypeStatsButton && root.contains(disablePrototypeStatsButton)) {
      disablePrototypeStatsFromNotice();
      return;
    }
    const closeButton = event.target.closest("[data-close-scene]");
    if (closeButton && root.contains(closeButton)) {
      closeScene(closeButton.dataset.closeScene || null);
      return;
    }
    const bossAssistButton = event.target.closest("[data-boss-assist]");
    if (bossAssistButton && root.contains(bossAssistButton)) {
      toggleBossAssistSelection(bossAssistButton.dataset.bossAssist);
      return;
    }
    const bossEmpowerButton = event.target.closest("[data-toggle-boss-empower]");
    if (bossEmpowerButton && root.contains(bossEmpowerButton)) {
      toggleBossEmpowerSelection();
      return;
    }
    const confirmBossZoneButton = event.target.closest("[data-confirm-boss-zone]");
    if (confirmBossZoneButton && root.contains(confirmBossZoneButton)) {
      void confirmBossZoneEntry(confirmBossZoneButton.dataset.confirmBossZone);
      return;
    }
    const advanceGroupDungeonFloorButton = event.target.closest("[data-advance-group-dungeon-floor]");
    if (advanceGroupDungeonFloorButton && root.contains(advanceGroupDungeonFloorButton)) {
      void advanceGroupDungeonFloor();
      return;
    }
    const sortInventoryButton = event.target.closest("[data-sort-inventory]");
    if (sortInventoryButton && root.contains(sortInventoryButton)) {
      sortInventoryEntries();
      return;
    }
    const confirmInventoryDestroyButton = event.target.closest("[data-confirm-inventory-destroy]");
    if (confirmInventoryDestroyButton && root.contains(confirmInventoryDestroyButton)) {
      void confirmPendingInventoryDestroy(confirmInventoryDestroyButton.dataset.confirmInventoryDestroy);
      return;
    }
    const confirmInventoryDestroySuppressButton = event.target.closest("[data-confirm-inventory-destroy-suppress]");
    if (confirmInventoryDestroySuppressButton && root.contains(confirmInventoryDestroySuppressButton)) {
      void confirmPendingInventoryDestroyAndSuppress(confirmInventoryDestroySuppressButton.dataset.confirmInventoryDestroySuppress);
      return;
    }
    const cancelInventoryDestroyButton = event.target.closest("[data-cancel-inventory-destroy]");
    if (cancelInventoryDestroyButton && root.contains(cancelInventoryDestroyButton)) {
      cancelInventoryDestroyConfirm();
      return;
    }
    const useButton = event.target.closest("[data-use-entry]");
    if (useButton && root.contains(useButton)) {
      useInventoryEntry(useButton.dataset.useEntry);
      return;
    }
    const hotbarUseButton = event.target.closest("[data-hotbar-use-entry]");
    if (hotbarUseButton && root.contains(hotbarUseButton)) {
      const slot = hotbarSlotForEntry(hotbarUseButton.dataset.hotbarUseEntry);
      if (slot >= 0) useHotbarSlot(slot);
      return;
    }
    const quickPotionButton = event.target.closest("[data-use-potion-kind]");
    if (quickPotionButton && root.contains(quickPotionButton)) {
      useFirstPotionOfKind(quickPotionButton.dataset.usePotionKind);
      return;
    }
    const equipButton = event.target.closest("[data-equip-entry]");
    if (equipButton && root.contains(equipButton)) {
      equipInventoryEntry(equipButton.dataset.equipEntry);
      return;
    }
    const sellButton = event.target.closest("[data-sell-entry]");
    if (sellButton && root.contains(sellButton)) {
      sellInventoryEntry(sellButton.dataset.sellEntry);
      return;
    }
    const buyButton = event.target.closest("[data-buy-item]");
    if (buyButton && root.contains(buyButton)) {
      buyShopItem(buyButton.dataset.buyItem);
      return;
    }
    const buyStackButton = event.target.closest("[data-buy-stack]");
    if (buyStackButton && root.contains(buyStackButton)) {
      const item = itemDefinition(buyStackButton.dataset.buyStack);
      buyShopItem(buyStackButton.dataset.buyStack, maxItemStack(item));
      return;
    }
    const accountUpgradeButton = event.target.closest("[data-buy-account-upgrade]");
    if (accountUpgradeButton && root.contains(accountUpgradeButton)) {
      buyAccountUpgrade(accountUpgradeButton.dataset.buyAccountUpgrade);
      return;
    }
    const performRebirthButton = event.target.closest("[data-perform-rebirth]");
    if (performRebirthButton && root.contains(performRebirthButton)) {
      performAccountRebirth();
      return;
    }
    const smithCombineButton = event.target.closest("[data-smith-combine]");
    if (smithCombineButton && root.contains(smithCombineButton)) {
      combineSmithItem(smithCombineButton.dataset.smithCombine);
      return;
    }
    const castSkillButton = event.target.closest("[data-cast-combat-skill]");
    if (castSkillButton && root.contains(castSkillButton)) {
      queueCombatSkillCast(castSkillButton.dataset.castCombatSkill);
      return;
    }
    const autoSkillButton = event.target.closest("[data-toggle-skill-auto]");
    if (autoSkillButton && root.contains(autoSkillButton)) {
      toggleSkillAutoCast(autoSkillButton.dataset.toggleSkillAuto);
      return;
    }
    const unequipButton = event.target.closest("[data-unequip-slot]");
    if (unequipButton && root.contains(unequipButton)) {
      unequipSlot(unequipButton.dataset.unequipSlot);
    }
  });
  root.addEventListener("input", (event) => {
    const volumeInput = event.target.closest("[data-music-volume]");
    if (volumeInput && root.contains(volumeInput)) {
      setMusicVolume(Number(volumeInput.value) / 100);
      return;
    }
    const sfxVolumeInput = event.target.closest("[data-sfx-volume]");
    if (sfxVolumeInput && root.contains(sfxVolumeInput)) {
      setSfxVolume(Number(sfxVolumeInput.value) / 100);
    }
  });
  root.addEventListener("change", (event) => {
    const importFileInput = event.target.closest("[data-import-save-file]");
    if (!importFileInput || !root.contains(importFileInput)) return;
    const file = importFileInput.files?.[0];
    importFileInput.value = "";
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      const textarea = root.querySelector("#saveImportText");
      if (textarea) textarea.value = String(reader.result ?? "");
    };
    reader.onerror = () => {
      window.alert("Could not read that file.");
    };
    reader.readAsText(file);
  });
  window.addEventListener("pointerdown", () => {
    if (state.settings.musicEnabled) syncBackgroundMusic();
  }, { once: true });
  window.addEventListener("pagehide", () => {
    saveGameState(true);
    flushPrototypeStats("session-end");
  });
  document.addEventListener("visibilitychange", () => {
    if (document.visibilityState === "hidden") {
      saveGameState(true);
      flushPrototypeStats("hidden");
    }
  });
  root.addEventListener("dblclick", (event) => {
    const inventoryItem = event.target.closest("[data-inventory-entry]");
    if (!inventoryItem || !root.contains(inventoryItem)) return;
    if (inventoryItem.closest("[data-hotbar-slot]")) return;
    if (inventoryItem.dataset.equippedSlot) {
      unequipSlot(inventoryItem.dataset.equippedSlot);
      return;
    }
    useInventoryEntry(inventoryItem.dataset.inventoryEntry);
  });
  root.addEventListener("click", (event) => {
    const tabButton = event.target.closest("[data-character-tab]");
    if (!tabButton || !root.contains(tabButton)) return;
    state.characterTab = tabButton.dataset.characterTab;
    sceneSignature = "";
    renderSceneOverlay();
  });
  root.addEventListener("click", (event) => {
    const pageButton = event.target.closest("[data-inventory-page]");
    if (!pageButton || !root.contains(pageButton)) return;
    const page = Math.max(0, Math.min(inventoryPageCount() - 1, Number(pageButton.dataset.inventoryPage) || 0));
    if (!inventoryPageUnlocked(page)) {
      unlockInventoryPage(page);
      return;
    }
    state.inventoryPage = page;
    sceneSignature = "";
    renderSceneOverlay();
  });
  root.addEventListener("click", (event) => {
    const confirmStorageUnlockButton = event.target.closest("[data-confirm-storage-page-unlock]");
    if (confirmStorageUnlockButton && root.contains(confirmStorageUnlockButton)) {
      const page = Math.max(0, Math.min(storagePageCount() - 1, Number(confirmStorageUnlockButton.dataset.confirmStoragePageUnlock) || 0));
      state.pendingStoragePageUnlock = null;
      unlockStoragePage(page);
      return;
    }
    const cancelStorageUnlockButton = event.target.closest("[data-cancel-storage-page-unlock]");
    if (cancelStorageUnlockButton && root.contains(cancelStorageUnlockButton)) {
      state.pendingStoragePageUnlock = null;
      sceneSignature = "";
      renderSceneOverlay();
      return;
    }
    const storagePageButton = event.target.closest("[data-storage-page]");
    if (!storagePageButton || !root.contains(storagePageButton)) return;
    const page = Math.max(0, Math.min(storagePageCount() - 1, Number(storagePageButton.dataset.storagePage) || 0));
    if (!storagePageUnlocked(page)) {
      state.pendingStoragePageUnlock = page;
      sceneSignature = "";
      renderSceneOverlay();
      return;
    }
    state.pendingStoragePageUnlock = null;
    state.storagePage = page;
    sceneSignature = "";
    renderSceneOverlay();
  });
  root.addEventListener("contextmenu", (event) => {
    const hotbarSlot = event.target.closest("[data-hotbar-slot]");
    if (!hotbarSlot || !root.contains(hotbarSlot)) return;
    const entry = hotbarEntryAtSlot(Number(hotbarSlot.dataset.hotbarSlot));
    if (!entry) return;
    event.preventDefault();
    const freeSlot = nextFreeInventorySlot();
    if (freeSlot >= state.inventory.maxSlots) {
      rejectInventoryMove("Cannot clear hotbar slot: inventory is full.");
      return;
    }
    dropInventoryEntryToInventorySlot(entry.id, freeSlot);
  });
  root.addEventListener("pointerover", (event) => {
    const tooltipTarget = event.target.closest("[data-tooltip-item]");
    if (!tooltipTarget || !root.contains(tooltipTarget)) return;
    showItemTooltip(tooltipTarget.dataset.tooltipItem, event, tooltipTarget.dataset.tooltipEntry ?? null);
  });
  root.addEventListener("pointermove", (event) => {
    if (!els.itemTooltip.hidden) positionItemTooltip(event);
  });
  root.addEventListener("pointerout", (event) => {
    const tooltipTarget = event.target.closest("[data-tooltip-item]");
    if (!tooltipTarget || !root.contains(tooltipTarget)) return;
    if (tooltipTarget.contains(event.relatedTarget)) return;
    hideItemTooltip();
  });
  window.addEventListener("popstate", () => {
    state.openScenes = initialOpenScenesFromUrl();
    sceneSignature = "";
    gamePanelSignature = "";
    renderSceneOverlay();
    renderGamePanel();
  });
  window.addEventListener("keydown", (event) => {
    if (event.altKey || event.ctrlKey || event.metaKey || event.shiftKey) return;
    if (event.target instanceof HTMLInputElement || event.target instanceof HTMLTextAreaElement || event.target instanceof HTMLSelectElement) return;
    if (!/^[1-6]$/.test(event.key)) return;
    event.preventDefault();
    useHotbarSlot(Number(event.key) - 1);
  });
  window.addEventListener("beforeunload", () => {
    saveGameState();
  });
  window.addEventListener("pointermove", updateInventoryCarryPointer);

  els.scale.addEventListener("input", () => {
    state.scale = Number(els.scale.value);
    updateStageSize();
    if (!state.battle.running && state.battle.phase === "idle") {
      state.battle.enemyX = state.battle.playerX + enemySpawnDistance();
    }
    render();
  });
  els.smooth.addEventListener("change", () => {
    state.smooth = els.smooth.checked;
    invalidateStampBackgroundCache();
    render();
  });
  els.pause.textContent = state.paused ? "Resume" : "Pause";
  els.pause.addEventListener("click", () => {
    state.paused = !state.paused;
    els.pause.textContent = state.paused ? "Resume" : "Pause";
    state.lastTick = performance.now();
  });
}

function bindStageCanvasEvents() {
  if (!stageCanvas || stageCanvas.dataset.townEventsBound === "true") return;
  stageCanvas.dataset.townEventsBound = "true";
  stageCanvas.addEventListener("click", (event) => {
    if (state.game.mode !== "town") return;
    const point = canvasPointFromEvent(event);
    const npc = townNpcAt(point.x, point.y);
    if (!npc) {
      closeTownNpc();
      return;
    }
    openTownNpc(npc.id);
  });
  stageCanvas.addEventListener("pointermove", (event) => {
    if (state.game.mode !== "town") {
      stageCanvas.style.cursor = "";
      setHoveredTownNpc(null);
      return;
    }
    const point = canvasPointFromEvent(event);
    const npc = townNpcAt(point.x, point.y);
    stageCanvas.style.cursor = npc ? "pointer" : "";
    setHoveredTownNpc(npc?.id ?? null);
  });
  stageCanvas.addEventListener("pointerleave", () => {
    stageCanvas.style.cursor = "";
    setHoveredTownNpc(null);
  });
}

function canvasPointFromEvent(event) {
  const rect = stageCanvas.getBoundingClientRect();
  return {
    x: ((event.clientX - rect.left) / rect.width) * state.stageWidth,
    y: ((event.clientY - rect.top) / rect.height) * state.stageHeight,
  };
}

function openTownNpc(npcId) {
  const npc = TOWN_NPCS.find((entry) => entry.id === npcId) ?? null;
  state.game.selectedTownNpcId = npc?.id ?? null;
  if (npc?.role === "Teleport") state.teleportBrowseRegionId = null;
  state.activeScene = npc?.role === "Storage" ? "storage" : state.game.selectedTownNpcId ? "townNpc" : null;
  if (npc?.role === "Storage") state.openScenes.inventory = true;
  if (state.game.selectedTownNpcId) playSfx("ui.npc", { volume: 0.46, throttleMs: 120 });
  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  render();
}

function closeTownNpc() {
  if (!state.game.selectedTownNpcId) return;
  state.game.selectedTownNpcId = null;
  if (state.activeScene === "townNpc" || state.activeScene === "storage" || state.activeScene === "weaponRefine") state.activeScene = null;
  resetWeaponRefineState();
  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  render();
}

function setHoveredTownNpc(npcId) {
  if (state.game.hoveredTownNpcId === npcId) return;
  state.game.hoveredTownNpcId = npcId;
  render();
}

function showItemTooltip(itemId, event, entryId = null) {
  const item = itemDefinition(itemId);
  if (!item) return;
  const entry = entryId ? itemEntryById(entryId) : null;
  els.itemTooltip.innerHTML = itemTooltipHtml(item, entry);
  els.itemTooltip.hidden = false;
  positionItemTooltip(event);
}

function hideItemTooltip() {
  els.itemTooltip.hidden = true;
  els.itemTooltip.innerHTML = "";
}

function positionItemTooltip(event) {
  const margin = 14;
  const width = els.itemTooltip.offsetWidth || 230;
  const height = els.itemTooltip.offsetHeight || 160;
  let x = event.clientX + margin;
  let y = event.clientY + margin;
  if (x + width > window.innerWidth - margin) x = event.clientX - width - margin;
  if (y + height > window.innerHeight - margin) y = window.innerHeight - height - margin;
  els.itemTooltip.style.left = `${Math.max(margin, x)}px`;
  els.itemTooltip.style.top = `${Math.max(margin, y)}px`;
}

async function reloadAtlases({ refreshLayers = [] } = {}) {
  const reloadVersion = ++atlasReloadVersion;
  const reloadKey = atlasIndexKey();
  const refreshLayerSet = new Set(refreshLayers);
  for (const layer of refreshLayerSet) {
    if (state.indexes[layer] != null) imageCache.delete(sheetUrl(state.spriteSet, layer, state.indexes[layer]));
  }
  const entries = await Promise.all(
    layerNames().map(async (layer) => [
      layer,
      await loadAtlas(state.spriteSet, layer, state.indexes[layer]).catch(() => null),
    ]),
  );
  if (reloadVersion !== atlasReloadVersion) return;
  state.atlases = Object.fromEntries(entries);
  state.atlasIndexes = Object.fromEntries(layerNames().map((layer) => [layer, state.indexes[layer] ?? null]));
  await Promise.all(
    entries.map(([layer, atlas]) => (
      atlas && state.indexes[layer] != null
        ? loadCachedImage(sheetUrl(state.spriteSet, layer, state.indexes[layer])).catch(() => null)
        : null
    )),
  );
  if (reloadVersion !== atlasReloadVersion) return;
  if (queuedAtlasReloadKey === reloadKey) queuedAtlasReloadKey = "";
  updateCoverage();
  render();
}

function scheduleEquipmentRedraw() {
  requestAnimationFrame(() => render());
  setTimeout(() => render(), 80);
}

function atlasIndexKey() {
  return JSON.stringify({
    spriteSet: state.spriteSet,
    indexes: Object.fromEntries(layerNames().map((layer) => [layer, state.indexes[layer] ?? null])),
  });
}

function queueVisualAtlasReload(refreshLayers = []) {
  const key = atlasIndexKey();
  if (queuedAtlasReloadKey === key) return;
  queuedAtlasReloadKey = key;
  void reloadAtlases({ refreshLayers }).finally(() => {
    if (queuedAtlasReloadKey === key) queuedAtlasReloadKey = "";
  });
}

function ensureEquippedVisualsFresh() {
  const changedLayers = applyEquippedVisualIndexes();
  const staleLayers = ["weapon", "armour"].filter((layer) => (
    (state.atlasIndexes?.[layer] ?? null) !== (state.indexes[layer] ?? null)
  ));
  const reloadLayers = [...new Set([...changedLayers, ...staleLayers])];
  if (reloadLayers.length) queueVisualAtlasReload(reloadLayers);
}

async function reloadEnemyAtlas() {
  const index = state.enemy.index;
  clearMonsterAtlasImageCache(index);
  state.enemy.atlas = await loadJson(monsterAtlasJsonUrl(index)).catch(() => null);
  await loadCachedImage(monsterAtlasPngUrl(index)).catch(() => null);
  render();
}

function tick(now) {
  updatePerfClock(now);
  catchUpSimulation(now);
  lastSimulationAt = now;
  const shouldRender = runSimulationStep(now, { autoSave: true });
  if (shouldRender) render();
  requestAnimationFrame(tick);
}

function catchUpSimulation(now) {
  const elapsed = Math.max(0, now - lastSimulationAt);
  if (elapsed <= SIMULATION_STEP_MS) return;

  if (elapsed > MAX_SIMULATION_CATCH_UP_MS) {
    const pending = {
      elapsedMs: Math.min(elapsed, OFFLINE_PROGRESS_CAP_MS),
      rawElapsedMs: elapsed,
      capped: elapsed > OFFLINE_PROGRESS_CAP_MS,
      savedAt: Date.now() - elapsed,
      kind: state.game.mode === "mining" ? "mining" : "zone",
      performancePausedAt: lastSimulationAt,
    };
    const groupDungeonRun = groupDungeonOfflineRunSnapshot()
      ?? sanitizeGroupDungeonOfflineRun(state.game.groupDungeonRun, state.game.activeZoneId, state.activeCharacterId);
    if (groupDungeonRun?.zoneId === state.game.activeZoneId) pending.groupDungeonRun = groupDungeonRun;
    const groupDungeonPauseSnapshot = createGroupDungeonPauseSnapshot(lastSimulationAt, groupDungeonRun);
    if (groupDungeonPauseSnapshot?.zoneId === state.game.activeZoneId) pending.groupDungeonPauseSnapshot = groupDungeonPauseSnapshot;
    if (pending.kind === "mining") applyOfflineMiningProgress(pending);
    else applyOfflineProgress(pending);
    return;
  }

  const catchUpMs = Math.min(elapsed, MAX_SIMULATION_CATCH_UP_MS);
  const catchUpEnd = lastSimulationAt + catchUpMs;
  suppressSimulationRender = true;
  try {
    for (let simNow = lastSimulationAt + SIMULATION_STEP_MS; simNow < catchUpEnd; simNow += SIMULATION_STEP_MS) {
      runSimulationStep(simNow);
    }
  } finally {
    suppressSimulationRender = false;
  }
}

function runSimulationStep(now, options = {}) {
  if (options.autoSave) {
    maybeAutoSave(now);
    maybeSubmitPrototypeStats(now);
  }
  let recoveryChanged = false;
  if (!state.paused) {
    if (!bossPartyActiveFight()) {
      recoveryChanged = updatePendingHeal(now) || recoveryChanged;
      recoveryChanged = updateHealingRegen(now) || recoveryChanged;
      recoveryChanged = updatePotionRegen(now) || recoveryChanged;
    }
    recoveryChanged = updateStatBuffs(now) || recoveryChanged;
  }
  const stepTesting = updateOneStepTest(now);
  const continuousWalkTesting = !stepTesting && updateContinuousWalkTest(now);
  if (!stepTesting && !continuousWalkTesting) {
    if (state.game.mode === "mining") {
      updateMining(now);
    } else {
      updateBattle(now);
      updateBattleRestState(now);
      if (!bossPartyActiveFight()) {
        recoveryChanged = (!state.paused && updateAutoPotions(now)) || recoveryChanged;
      }
    }
    updateEnemyFrame(now);
    updateTaoPetFrame(now);
  }
  const clip = currentClip();
  if (!state.paused && clip && !stepTesting && !continuousWalkTesting && !state.stepTest.complete) {
    updateFrame(now, clip);
    return true;
  } else {
    state.lastTick = now;
    return Boolean(state.spellAtlas || state.levelUpEffects.length || stepTesting || continuousWalkTesting || recoveryChanged);
  }
}

function updatePerfClock(now) {
  state.perf.frames += 1;
  const elapsed = now - state.perf.lastFpsAt;
  if (elapsed < 500) return;
  state.perf.fps = Math.round((state.perf.frames * 1000) / elapsed);
  state.perf.frames = 0;
  state.perf.lastFpsAt = now;
}

function updateContinuousWalkTest(now) {
  if (!state.continuousWalk || state.paused) return false;
  const action = state.continuousMoveAction;
  const spec = PLAYER_ACTIONS[action];
  const cycleMs = spec.count * spec.interval;
  const elapsed = Math.max(0, now - state.continuousWalkStartedAt);
  const distance = movementDistanceForAction(action, elapsed);
  const frameTime = elapsed % cycleMs;

  state.battle.playerX = state.continuousWalkStartX + distance;
  state.battle.cameraX = state.continuousWalkStartCameraX + distance;
  state.battle.phase = "advance";
  state.battle.lastMotionAt = now;
  const previousFrame = state.frame;
  state.action = action;
  state.frame = Math.min(spec.count - 1, Math.floor(frameTime / spec.interval));
  maybePlayPlayerFootstep(previousFrame, state.frame, action);
  state.playerOneShot = false;
  state.lastTick = now;
  return true;
}

function updateOneStepTest(now) {
  const test = state.stepTest;
  if (!test.active) return false;
  const clip = currentClip();
  const frameCount = clip?.frames.length ?? PLAYER_ACTIONS.walking.count;
  const t = Math.max(0, Math.min(1, (now - test.startAt) / test.durationMs));

  state.battle.playerX = test.startX + test.distancePx * t;
  state.battle.cameraX = test.startCameraX + test.distancePx * t;
  const previousFrame = state.frame;
  state.action = "walking";
  state.frame = Math.min(frameCount - 1, Math.floor(t * frameCount));
  maybePlayPlayerFootstep(previousFrame, state.frame, "walking");
  state.playerOneShot = false;
  state.lastTick = now;

  if (t >= 1) {
    state.battle.playerX = test.startX + test.distancePx;
    state.battle.cameraX = test.startCameraX + test.distancePx;
    state.frame = frameCount - 1;
    test.active = false;
    test.complete = true;
    pushBattleLog(`One-step test complete: player +${test.distancePx}px, ground +${test.distancePx}px.`);
    battlePanelSignature = "";
  }
  return true;
}

function beginBossPartyFight(zoneId, now = performance.now()) {
  const pendingSelected = [...new Set(state.pendingBossAssistSelection ?? [])]
    .filter((classId) => classId !== state.activeCharacterId && characterAvailableForBossAssist(classId));
  const pausedSnapshot = sanitizeGroupDungeonPauseSnapshot(state.game.groupDungeonPauseSnapshot, zoneId, state.activeCharacterId);
  const restoredRun = pausedSnapshot?.run ?? sanitizeGroupDungeonOfflineRun(state.game.groupDungeonRun, zoneId, state.activeCharacterId);
  const selected = pendingSelected.length
    ? pendingSelected
    : restoredRun?.zoneId === zoneId
      ? restoredRun.classIds.filter((classId) => classId !== state.activeCharacterId && state.characters?.[classId])
      : [];
  state.pendingBossAssistSelection = [];
  const classIds = bossPartyClassOrder([state.activeCharacterId, ...selected]);
  const entryZoneForRun = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId) ?? activeZone();
  const isBossSwarmRun = groupDungeonBossSwarmZone(entryZoneForRun);
  const bossSwarmConfig = isBossSwarmRun ? groupDungeonBossSwarmConfig(entryZoneForRun) : null;
  const freshGroupDungeonRun = isBossSwarmRun ? {
    kind: "groupDungeonBossSwarm",
    zoneId,
    leaderClassId: state.activeCharacterId,
    classIds,
    spawned: 0,
    killed: 0,
    totalSpawns: bossSwarmConfig.totalSpawns,
    complete: false,
  } : {
    kind: "groupDungeon",
    zoneId,
    leaderClassId: state.activeCharacterId,
    classIds,
    waveNumber: 1,
    killedThisWave: 0,
    targetThisWave: groupDungeonWaveSpawnCount(1, entryZoneForRun),
    endless: false,
  };
  state.game.groupDungeonRun = sanitizeGroupDungeonOfflineRun(
    restoredRun?.zoneId === zoneId ? restoredRun : freshGroupDungeonRun,
    zoneId,
    state.activeCharacterId,
  ) ?? null;

  captureActiveCharacterState();
  const members = classIds.map((classId, index) => {
    const member = bossPartyMemberFromCharacter(classId, state.characters[classId], now + index * BOSS_PARTY_MEMBER_ACTION_GAP_MS);
    refreshBossPartyMemberMagicSettings(member);
    return member;
  });
  const controlledClassId = state.activeCharacterId;
  const entryZone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId) ?? activeZone();
  const isGroupDungeonBoss = groupDungeonBossZone(entryZone);
  const isBossSwarm = groupDungeonBossSwarmZone(entryZone);
  const isGroupDungeon = groupDungeonZone(entryZone) && !isGroupDungeonBoss && !isBossSwarm;
  const resumeGroupDungeon = Boolean(pausedSnapshot?.zoneId === zoneId);
  if ((isGroupDungeon || isBossSwarm) && !resumeGroupDungeon) clearGroupDungeonRunState();
  positionBossPartyMembers(members, controlledClassId);
  if (isGroupDungeon || isBossSwarm) snapBossPartyMembersToSwarmGrid(members);
  const frontMeleeMember = bossPartyClassOrder(members.map((member) => member.classId))
    .filter((classId) => bossPartyIsMeleeClass(classId))
    .map((classId) => members.find((member) => member.classId === classId && member.alive && member.hp > 0))
    .find(Boolean) ?? null;
  const meleeFrontSlotWorldX = frontMeleeMember
    ? Math.round(Number(frontMeleeMember.worldX) || 0)
    : null;
  resetBossPartySoloRecoveryState();
  state.battle.bossParty = {
    active: true,
    zoneId,
    leaderClassId: controlledClassId,
    controlledClassId,
    members,
    pet: null,
    petDiedThisFight: false,
    effects: [],
    pendingPoison: null,
    finished: false,
    startedAt: now,
    lastAdvanceAt: now,
    lockedCameraX: null,
    lockedArenaWorldX: null,
    meleeFrontSlotWorldX,
    meleeStepCameraX: null,
    cameraLerpFromX: 0,
    cameraLerpToX: 0,
    cameraLerpUntil: 0,
    defeated: false,
  };

  const controlled = bossPartyControlledMember();
  if (controlled) {
    state.battle.player = controlled;
    state.battle.combatClass = controlled.classId;
    state.battle.playerX = controlled.worldX;
  }
  const enemy = state.battle.enemy;
  if (enemyUsesFixedArenaSpawn(enemy)) {
    const spawnX = arenaBossSpawnWorldX();
    positionBossPartyMembersForFixedSpawn(members, spawnX, controlledClassId);
    if (controlled) state.battle.playerX = controlled.worldX;
    applyFixedArenaEnemySpawn(now, { skipPlayerPosition: true });
  } else {
    state.battle.phase = "engaged";
    state.battle.enemyAggro = true;
    state.battle.enemyRevealed = true;
    state.battle.enemyX = bossPartyEnemyApproachX(members);
    state.battle.bossParty.lastAdvanceAt = now;
    state.battle.cameraX = (groupDungeonCameraAnchorWorldX() ?? state.battle.playerX) - playerScreenX();
    state.battle.bossParty.lockedCameraX = null;
    ensureMapStampArenaLock();
    state.battle.nextEnemyAttackAt = now + Math.max(400, Math.trunc(Number(enemy?.attackMs) || 1400));
    setPlayerAction("stance", now);
    if (!isGroupDungeon && !isGroupDungeonBoss && !isBossSwarm) setEnemyLocomotion("standing", now);
  }
  if (isBossSwarm) {
    if (resumeGroupDungeon && restoreGroupDungeonPauseSnapshot(pausedSnapshot, now, entryZone)) {
      state.game.groupDungeonPauseSnapshot = null;
    } else if (restoredRun?.zoneId === zoneId && restoredRun.kind === "groupDungeonBossSwarm") {
      restoreGroupDungeonBossSwarmStateFromRun(restoredRun, now, entryZone);
    } else {
      const bossRespawning = groupDungeonBossRespawnRemainingMs(entryZone) > 0;
      resetGroupDungeonBossSwarmRun(now, entryZone, { skipInitialSpawn: bossRespawning });
      if (bossRespawning) {
        state.battle.phase = "idle";
        state.battle.enemyAggro = false;
        state.battle.enemyRevealed = false;
        state.battle.nextEnemyAttackAt = 0;
        setPlayerAction("stance", now);
        pushBattleLog(`${groupDungeonBossSwarmLabel(entryZone)} is recovering. Respawns in ${formatDuration(groupDungeonBossRespawnRemainingMs(entryZone))}. Advance to the next floor anytime, or wait here.`);
      }
    }
    syncGroupDungeonPrimaryEnemy();
    void reloadEnemyAtlas();
  } else if (isGroupDungeon) {
    if (resumeGroupDungeon && restoreGroupDungeonPauseSnapshot(pausedSnapshot, now, entryZone)) {
      state.game.groupDungeonPauseSnapshot = null;
    } else if (restoredRun?.zoneId === zoneId) {
      restoreGroupDungeonRunStateFromRun(restoredRun, now, entryZone);
    } else {
      resetGroupDungeonRun(now);
    }
    syncGroupDungeonPrimaryEnemy();
    void reloadEnemyAtlas();
  } else if (isGroupDungeonBoss) {
    clearGroupDungeonRunState();
    const bossRespawning = groupDungeonBossRespawnRemainingMs(entryZone) > 0;
    state.battle.bossParty.lastAdvanceAt = now;
    state.battle.cameraX = (groupDungeonCameraAnchorWorldX() ?? state.battle.playerX) - playerScreenX();
    state.battle.bossParty.lockedCameraX = null;
    ensureMapStampArenaLock();
    if (bossRespawning) {
      const bossTemplate = ENEMY_TEMPLATES.find((entry) => entryZone.enemyIds.includes(entry.id));
      state.battle.enemy = null;
      state.battle.enemyId = null;
      state.battle.enemyAggro = false;
      state.battle.enemyRevealed = false;
      state.battle.nextEnemyAttackAt = 0;
      state.battle.phase = "idle";
      setPlayerAction("stance", now);
      pushBattleLog(`${bossTemplate?.name ?? "The boss"} is recovering. Respawns in ${formatDuration(groupDungeonBossRespawnRemainingMs(entryZone))}. Advance to the next floor anytime, or wait here.`);
    } else {
      state.battle.phase = "engaged";
      state.battle.enemyAggro = true;
      state.battle.enemyRevealed = true;
      state.battle.enemyX = bossPartyEnemyApproachX(members);
      state.battle.nextEnemyAttackAt = now + Math.max(400, Math.trunc(Number(enemy?.attackMs) || 1400));
      setEnemyLocomotion("standing", now);
      if (enemy?.monsterIndex) {
        state.enemy.index = enemy.monsterIndex;
        void reloadEnemyAtlas();
      }
      if (groupDungeonBossReinforcementsZone(entryZone)) {
        initGroupDungeonBossReinforcements(now, entryZone);
      }
    }
  } else if (enemy?.monsterIndex) {
    state.enemy.index = enemy.monsterIndex;
    void reloadEnemyAtlas();
  }
  void preloadBossPartyVisualAtlases(members);
  if (resumeGroupDungeon && (isBossSwarm || isGroupDungeon)) {
    pushBattleLog(`Party resumes ${entryZone.label}: ${members.map((member) => member.classId).join(", ")}.`);
  } else if (isBossSwarm) {
    pushBattleLog(`Party enters ${entryZone.label}: ${members.map((member) => member.classId).join(", ")}.`);
  } else if (isGroupDungeon) {
    pushBattleLog(`Party enters ${entryZone.label}: ${members.map((member) => member.classId).join(", ")}.`);
    if (restoredRun?.zoneId === zoneId && restoredRun.waveNumber > 1) {
      pushBattleLog(`Continuing at wave ${restoredRun.waveNumber}.`);
    } else {
      pushBattleLog("Waves reset — starting at wave 1.");
    }
  } else if (isGroupDungeonBoss) {
    pushBattleLog(`Party enters ${entryZone.label}: ${members.map((member) => member.classId).join(", ")}.`);
    if (!groupDungeonBossRespawnRemainingMs(entryZone)) {
      pushBattleLog(`${enemy?.name ?? "The boss"} engages the party.`);
    }
  } else {
    pushBattleLog(`Boss party formed: ${members.map((member) => member.classId).join(", ")}.`);
    if (enemyUsesFixedArenaSpawn(enemy)) {
      pushBattleLog(`${enemy?.name ?? "The boss"} waits beneath the floor...`);
    } else {
      pushBattleLog(`${enemy?.name ?? "Boss"} engages the party.`);
    }
  }
  captureActiveCharacterState();
  persistCharacterGameLocation({
    mode: "zone",
    zoneId,
    classIds,
    running: true,
  });
  saveGameState(true);
  initMapLightningSchedule(now);
  battlePanelSignature = "";
  gamePanelSignature = "";
  return true;
}

function bossPartyClassOrder(classIds) {
  const unique = [...new Set(classIds.map(normalizeCharacterId))];
  return BOSS_PARTY_ORDER.filter((classId) => unique.includes(classId));
}

function bossPartyIsMeleeClass(classId) {
  return classId === "Warrior" || classId === "Taoist";
}

function bossPartyMemberLineSlot(classId) {
  return BOSS_PARTY_MEMBER_LINE_SLOTS[normalizeCharacterId(classId)] ?? 0;
}

function bossPartyMemberLineWorldX(frontX, classId) {
  return Math.round(frontX - bossPartyMemberLineSlot(classId) * LANE_TILE_PX);
}

function bossPartyAliveMeleeMembers(party = state.battle.bossParty) {
  if (!party?.members?.length) return [];
  return bossPartyClassOrder(party.members.map((member) => member.classId))
    .filter((classId) => bossPartyIsMeleeClass(classId))
    .map((classId) => party.members.find((member) => member.classId === classId && member.alive && member.hp > 0))
    .filter(Boolean);
}

function bossPartyMeleeFrontSlotWorldX(party = state.battle.bossParty) {
  const slot = Number(party?.meleeFrontSlotWorldX);
  return Number.isFinite(slot) ? Math.round(slot) : null;
}

function bossPartyMeleeFrontWorldX() {
  const slotX = bossPartyMeleeFrontSlotWorldX();
  if (Number.isFinite(slotX)) return slotX;
  const enemyX = Number(state.battle.enemyX) || 0;
  if (enemyUsesFixedArenaSpawn()) {
    return Math.round((enemyX || arenaBossSpawnWorldX()) - BOSS_PARTY_ENEMY_MELEE_GAP);
  }
  return Math.round(enemyX - BOSS_PARTY_ENEMY_MELEE_GAP);
}

function layoutBossPartyMembers(members, frontX, controlledClassId = state.activeCharacterId) {
  for (const member of members) {
    bossPartyInitMemberVisuals(member);
    member.targetWorldX = null;
    member.meleeAdvanceFromX = null;
    member.meleeAdvanceStartedAt = null;
    if (!member.alive || member.hp <= 0) continue;
    member.worldX = bossPartyMemberLineWorldX(frontX, member.classId);
  }

  const controlled = members.find((member) => member.classId === controlledClassId) ?? members[0];
  if (controlled) state.battle.playerX = controlled.worldX;
}

function bossPartyMemberIsWalkingToMelee(member) {
  return member?.targetWorldX != null;
}

function bossPartyMemberSteppingToMelee(party = state.battle.bossParty) {
  return party?.members?.some((member) => member?.targetWorldX != null) ?? false;
}

function queueBossPartyMeleeAdvance(member, nextX, now = performance.now()) {
  const current = Number(member.worldX) || 0;
  nextX = Math.round(nextX);
  if (Math.round(current) === nextX) {
    member.targetWorldX = null;
    member.meleeAdvanceFromX = null;
    member.meleeAdvanceStartedAt = null;
    return false;
  }
  member.targetWorldX = nextX;
  member.meleeAdvanceFromX = current;
  member.meleeAdvanceStartedAt = now;
  return true;
}

function bossPartyMeleeFrontMember(party = state.battle.bossParty) {
  return bossPartyAliveMeleeMembers(party)[0] ?? null;
}

function refreshBossPartyMeleePositions(options = {}) {
  if (!bossPartyMembersStepToMelee()) return null;
  const party = state.battle.bossParty;
  if (!party?.members?.length) return null;
  const now = Number(options.now) || performance.now();
  const frontX = Math.round(Number(options.frontX) || bossPartyMeleeFrontWorldX());
  const frontMember = bossPartyMeleeFrontMember(party);
  if (!frontMember) return null;

  // Only the current front-liner steps up to melee; rear melee stay put until
  // they become the front-liner (e.g. Warrior after pet dies, Taoist after Warrior dies).
  for (const member of party.members) {
    if (member === frontMember) continue;
    if (member?.targetWorldX == null) continue;
    member.targetWorldX = null;
    member.meleeAdvanceFromX = null;
    member.meleeAdvanceStartedAt = null;
    if (member.alive && member.hp > 0 && member.visualAction === "walking" && !member.visualOneShot) {
      member.visualAction = "stance";
      member.visualFrame = 0;
    }
  }

  const currentX = Math.round(Number(frontMember.worldX) || 0);
  if (currentX >= frontX) {
    frontMember.targetWorldX = null;
    frontMember.meleeAdvanceFromX = null;
    frontMember.meleeAdvanceStartedAt = null;
    return null;
  }
  if (!queueBossPartyMeleeAdvance(frontMember, frontX, now)) return null;
  return frontMember;
}

function bossPartyFinishMeleeAdvance(member, now) {
  member.targetWorldX = null;
  member.meleeAdvanceFromX = null;
  member.meleeAdvanceStartedAt = null;
  if (member.alive && member.hp > 0 && !member.visualOneShot) {
    member.visualAction = "stance";
    member.visualFrame = 0;
    member.visualLastTick = now;
  }
}

function updateBossPartyMeleeAdvance(now) {
  if (!bossPartyMembersStepToMelee()) return false;
  const party = state.battle.bossParty;
  if (!party?.members?.length) return false;
  let anyMoving = false;

  for (const member of party.members) {
    if (member?.targetWorldX == null) continue;
    const to = Math.round(member.targetWorldX);
    const from = Number(member.meleeAdvanceFromX);
    const origin = Number.isFinite(from) ? from : (Number(member.worldX) || 0);
    if (!Number.isFinite(from)) member.meleeAdvanceFromX = origin;
    const start = member.meleeAdvanceStartedAt ?? now;
    if (member.meleeAdvanceStartedAt == null) member.meleeAdvanceStartedAt = now;
    const durationMs = Math.max(1, (Math.abs(to - origin) / Math.max(1, LANE.playerSpeed)) * 1000);
    const t = Math.min(1, Math.max(0, (now - start) / durationMs));
    member.worldX = Math.round(origin + (to - origin) * t);

    if (t >= 1) {
      member.worldX = to;
      bossPartyFinishMeleeAdvance(member, now);
      anyMoving = true;
      continue;
    }

    if (member.alive && member.hp > 0 && !member.visualOneShot) {
      if (member.visualAction !== "walking") {
        member.visualFrame = 0;
        member.visualLastTick = now;
      }
      member.visualAction = "walking";
    }
    anyMoving = true;
  }

  if (anyMoving) {
    syncBossPartyPetPosition();
    bossPartySyncControlledPlayerRef();
  }
  return anyMoving;
}

function positionBossPartyMembers(members, controlledClassId = state.activeCharacterId) {
  const frontX = state.battle.playerX + BOSS_PARTY_FRONT_OFFSET;
  layoutBossPartyMembers(members, frontX, controlledClassId);
}

function bossPartyInitMemberVisuals(member, now = performance.now()) {
  member.visualAction = member.alive ? "stance" : "die";
  member.visualFrame = 0;
  member.visualOneShot = false;
  member.visualLastTick = now;
  member.visualIndexes = bossPartyMemberVisualIndexes(member);
  member.visualAtlases = {};
}

function positionBossPartyMembersForFixedSpawn(members, spawnX, controlledClassId = state.activeCharacterId) {
  layoutBossPartyMembers(members, Math.round(spawnX - BOSS_PARTY_ENEMY_MELEE_GAP), controlledClassId);
}

// Where the boss first appears: a few tiles in front of the lead member, so it
// visibly walks in to melee instead of starting on top of the party.
function bossPartyEnemyApproachX(members = state.battle.bossParty?.members ?? []) {
  const ordered = bossPartyClassOrder(members.map((member) => member.classId));
  const frontClassId = ordered[0];
  const front = members.find((member) => member.classId === frontClassId) ?? members[0];
  return Math.round((front?.worldX ?? state.battle.playerX) + BOSS_PARTY_ENEMY_APPROACH_GAP);
}

// A tanking pet stands just in front of the Warrior (independent of the boss),
// so the Warrior can Thrust over it while the pet soaks the boss's hits.
function bossPartyMemberByClassId(classId) {
  return state.battle.bossParty?.members?.find(
    (member) => member.classId === classId && member.alive && member.hp > 0,
  ) ?? null;
}

function bossPartyFormationFrontWorldX() {
  const warrior = state.battle.bossParty?.members?.find((member) => member.classId === "Warrior");
  const warriorX = Number(warrior?.worldX);
  if (Number.isFinite(warriorX)) return warriorX;
  const frontMember = bossPartyMemberByClassId(bossPartyNextAliveMember()?.classId)
    ?? bossPartyNextAliveMember();
  const frontX = Number(frontMember?.worldX);
  if (!Number.isFinite(frontX)) return Number(state.battle.playerX) || 0;
  return frontX + bossPartyMemberLineSlot(frontMember.classId) * LANE_TILE_PX;
}

function bossPartyWarriorWorldX() {
  const warrior = state.battle.bossParty?.members?.find((member) => member.classId === "Warrior");
  const warriorX = Number(warrior?.worldX);
  if (Number.isFinite(warriorX)) return warriorX;
  const front = bossPartyNextAliveMember();
  return Number(front?.worldX ?? state.battle.playerX) || 0;
}

function bossPartyPetWorldX() {
  if (enemyUsesFixedArenaSpawn()) return fixedArenaPetWorldX();
  const base = bossPartyWarriorWorldX();
  return Math.round(base + BOSS_PARTY_PET_STAND_GAP);
}

// Shinsu uses 2-tile range and attacks through the Warrior — slot 1 between Warrior and Taoist.
function bossPartyShinsuPetWorldX() {
  const warrior = bossPartyMemberByClassId("Warrior");
  const taoist = bossPartyMemberByClassId("Taoist");
  if (warrior && taoist) {
    const warriorX = Number(warrior.worldX);
    const taoistX = Number(taoist.worldX);
    if (Number.isFinite(warriorX) && Number.isFinite(taoistX)) {
      return Math.round((warriorX + taoistX) / 2);
    }
  }
  return Math.round(bossPartyFormationFrontWorldX() - BOSS_PARTY_SHINSU_LINE_SLOT * LANE_TILE_PX);
}

function bossPartyPetWorldXFor(pet) {
  if (pet?.spellId === "SummonShinsu") return bossPartyShinsuPetWorldX();
  return bossPartyPetWorldX();
}

function resolvedTaoPetWorldX(pet = state.battle.taoPet) {
  const worldX = Number(pet?.worldX);
  if (Number.isFinite(worldX)) return worldX;
  if (bossPartyOnField()) return bossPartyPetWorldXFor(pet);
  return Number(state.battle.playerX) || 0;
}

function fixedArenaPetWorldX() {
  const enemyX = Number(state.battle.enemyX) || arenaBossSpawnWorldX();
  return Math.round(enemyX - TAOIST_PET_ENEMY_GAP);
}

function fixedArenaPartyShiftForPet(petWorldX) {
  const gap = bossPartyOnField() ? BOSS_PARTY_PET_STAND_GAP : TAOIST_PET_SUMMON_MIN_GAP;
  const anchorX = bossPartyOnField()
    ? Number(bossPartyNextAliveMember()?.worldX ?? state.battle.playerX)
    : Number(state.battle.playerX);
  const requiredAnchorX = petWorldX - gap;
  return Math.max(0, Math.round(anchorX - requiredAnchorX));
}

function shiftFixedArenaPartyForPet(petWorldX) {
  if (!enemyUsesFixedArenaSpawn()) return 0;
  const shift = fixedArenaPartyShiftForPet(petWorldX);
  if (shift <= 0) return 0;
  state.battle.playerX = Math.round((Number(state.battle.playerX) || 0) - shift);
  const party = state.battle.bossParty;
  if (party?.members?.length) {
    for (const member of party.members) {
      if (Number.isFinite(Number(member.worldX))) {
        member.worldX = Math.round(Number(member.worldX) - shift);
      }
    }
  }
  return shift;
}

function syncBossPartyPetPosition() {
  const pet = state.battle.bossParty?.pet;
  if (!pet?.active || (pet.hp ?? 0) <= 0) return;
  pet.worldX = bossPartyPetWorldXFor(pet);
}

function placeTaoistCombatPet(pet) {
  if (!pet) return pet;
  const isShinsu = pet.spellId === "SummonShinsu";
  if (enemyUsesFixedArenaSpawn()) {
    if (isShinsu && bossPartyOnField()) {
      pet.worldX = bossPartyShinsuPetWorldX();
    } else {
      pet.worldX = fixedArenaPetWorldX();
      const shift = shiftFixedArenaPartyForPet(pet.worldX);
      if (shift > 0) {
        pushBattleLog(bossPartyOnField()
          ? "The party steps back to make room for the pet."
          : "You step back to make room for the pet.");
      }
    }
  } else if (bossPartyOnField()) {
    pet.worldX = bossPartyPetWorldXFor(pet);
  } else {
    pet.worldX = taoistPetSummonWorldX();
  }
  return pet;
}

function bossPartyMemberEnemyDistance(member) {
  return Math.max(0, (Number(state.battle.enemyX) || 0) - (Number(member?.worldX) || 0));
}

function bossPartyPetEnemyDistance(pet, enemy = state.battle.enemy) {
  if (!pet || !enemy) return Infinity;
  const petX = resolvedTaoPetWorldX(pet);
  if (groupDungeonSwarmSideActive() && enemy.swarmId) {
    const swarmEnemy = findGroupDungeonSwarmEnemy(enemy.swarmId);
    if (swarmEnemy) return Math.max(0, (Number(swarmEnemy.worldX) || 0) - petX);
  }
  return Math.max(0, (Number(state.battle.enemyX) || 0) - petX);
}

// Mobile bosses walk to melee distance from the current tank; stationary bosses stay put
// while party members step forward into the front slot.
function bossPartyAdvanceEnemy(now) {
  if (enemyBossIsStationary()) return;
  const party = state.battle.bossParty;
  if (!party) return;
  const enemy = state.battle.enemy;
  if (enemyFrozenActive(enemy, now)) {
    setEnemyLocomotion("standing", now);
    return;
  }
  const desired = bossPartyDesiredEnemyX();
  if (desired == null) return;
  const current = Number(state.battle.enemyX);
  if (!Number.isFinite(current)) {
    state.battle.enemyX = desired;
    party.lastAdvanceAt = now;
    return;
  }
  const dt = Math.min(120, Math.max(0, now - (party.lastAdvanceAt || now))) / 1000;
  party.lastAdvanceAt = now;
  if (current === desired) {
    setEnemyLocomotion("standing", now);
    return;
  }
  const closingGap = Math.abs(current - desired);
  const inWalkIn = closingGap > BOSS_PARTY_ENEMY_MELEE_GAP + 6;
  const speed = enemyAdvanceSpeed(enemy, inWalkIn ? BOSS_PARTY_BOSS_APPROACH_SPEED : LANE.enemySpeed, now);
  const step = Math.max(1, speed * dt);
  const delta = desired - current;
  if (Math.abs(delta) <= step) {
    state.battle.enemyX = desired;
    setEnemyLocomotion("standing", now);
  } else {
    state.battle.enemyX = Math.round(current + Math.sign(delta) * step);
    setEnemyLocomotion("walking", now);
  }
}

function bossPartyDesiredEnemyX() {
  const party = state.battle.bossParty;
  if (partyPetCanTank()) {
    const petX = Number(party?.pet?.worldX);
    if (Number.isFinite(petX)) return Math.round(petX + BOSS_PARTY_ENEMY_MELEE_GAP);
  }
  // Stationary bosses: party members step to a fixed front slot; the boss stays put.
  if (bossPartyMembersStepToMelee()) {
    const slotX = bossPartyMeleeFrontSlotWorldX(party);
    if (Number.isFinite(slotX)) return Math.round(slotX + BOSS_PARTY_ENEMY_MELEE_GAP);
  }
  // Mobile bosses: party holds formation; the boss walks to whoever is tanking.
  const target = bossPartyFrontTarget();
  const targetX = Number(target?.worldX);
  if (Number.isFinite(targetX)) return Math.round(targetX + BOSS_PARTY_ENEMY_MELEE_GAP);
  return null;
}

function bossPartyTargetEnemyDistance(target) {
  if (target === state.battle.bossParty?.pet) {
    return Math.max(0, (Number(state.battle.enemyX) || 0) - (Number(target?.worldX) || 0));
  }
  return bossPartyMemberEnemyDistance(target);
}

// A Warrior with Thrusting on autocast reaches the second tile; everyone else
// (and a Warrior without Thrusting) has normal one-tile weapon reach.
function bossPartyHasThrusting(member) {
  return member?.classId === "Warrior" && bossPartyAutoSpells(member).some((skill) => skill.id === "Thrusting");
}

function bossPartyMemberReach(member) {
  return bossPartyHasThrusting(member) ? BOSS_PARTY_THRUSTING_REACH : BOSS_PARTY_WARRIOR_REACH;
}

function bossPartyCanWeaponReach(member) {
  return bossPartyMemberEnemyDistance(member) <= bossPartyMemberReach(member);
}

// A member may only melee auto-attack if it is the current front-liner (no
// living higher-priority member ahead of it) AND the boss is within reach.
// This stops a Taoist/Wizard swinging past a living Warrior; they only start
// meleeing once the members ahead of them have died and the boss has stepped
// forward into range.
function bossPartyCanMelee(member) {
  const front = bossPartyNextAliveMember();
  if (front && front.classId !== member.classId) return false;
  return bossPartyCanWeaponReach(member);
}

function bossPartyWait(member, now, delayMs = 250) {
  member.nextActionAt = now + delayMs;
  if (!member.visualOneShot && !bossPartyMemberIsWalkingToMelee(member)) {
    member.visualAction = "stance";
    member.visualFrame = 0;
    member.visualLastTick = now;
  }
  return false;
}

function bossPartySfxVolume(member, controlledVolume = 0.42, assistVolume = 0.14) {
  return member?.classId === bossPartyControlledClassId() ? controlledVolume : assistVolume;
}

// Boss party combat plays SFX for every member, like the Crystal client. The
// character you control is mixed at full volume and bypasses the per-sound
// throttle so your own actions are always crisp; assist members are a touch
// quieter and stay throttled so several of them don't pile into a wall of sound
// or steal the controlled character's throttle/pool slot.
function bossPartySfxParamsForClass(classId, volume, throttleMs = 80) {
  if (classId === bossPartyControlledClassId()) return { volume, throttleMs: 0, force: true };
  return { volume: volume * BOSS_PARTY_ASSIST_SFX_SCALE, throttleMs };
}

function bossPartySfxParams(member, volume, throttleMs = 80) {
  return bossPartySfxParamsForClass(member?.classId, volume, throttleMs);
}

function bossPartyCastSfx(member, spellId, volume, throttleMs) {
  return playSpellSfx(spellId, "cast", bossPartySfxParams(member, volume, throttleMs));
}

function bossPartyWeaponSfxFamily(member, kind = "swing") {
  const resolver = kind === "hit" ? weaponHitSfxFamilyForItem : weaponSwingSfxFamilyForItem;
  if (member?.classId === bossPartyControlledClassId()) {
    return kind === "hit" ? currentWeaponHitSfxFamily() : currentWeaponSwingSfxFamily();
  }
  const entryId = member?.inventory?.equipment?.weapon ?? null;
  const entry = entryId ? bossPartyInventoryEntryById(member, entryId) : null;
  return resolver(entry ? itemDefinition(entry.itemId) : null);
}

function bossPartyMemberFromCharacter(classId, character = createDefaultCharacterState(classId), nextActionAt = performance.now()) {
  const statBuffs = sanitizeStatBuffs(character.battle?.statBuffs);
  const stats = characterSnapshotTotalStats(classId, character, { includeBuffs: false });
  const inventory = cloneInventoryState(character.inventory);
  const hotbar = cloneHotbarState(character.hotbar);
  const magic = cloneMagicState(character.magic);
  const game = {
    ...character.game,
    progress: { ...character.game.progress },
    recentLoot: [...(character.game.recentLoot ?? [])],
    dropPity: { ...(character.game.dropPity ?? {}) },
    bossRespawns: { ...(character.game.bossRespawns ?? {}) },
    bossKills: { ...(character.game.bossKills ?? {}) },
  };
  return {
    ...PLAYER_TEMPLATE,
    ...stats,
    name: classId,
    class: classId,
    classId,
    level: Math.max(1, Math.trunc(Number(game.progress.level) || PLAYER_TEMPLATE.level)),
    experience: Math.max(0, Math.trunc(Number(game.progress.experience) || 0)),
    hp: stats.hp > 0 ? stats.hp : stats.maxHp,
    mp: stats.mp > 0 ? stats.mp : stats.maxMp,
    alive: true,
    inventory,
    hotbar,
    magic,
    game,
    nextActionAt,
    autoPotionReadyAt: { hp: 0, mp: 0 },
    potHealthAmount: Math.max(0, Math.trunc(Number(character.battle?.potHealthAmount) || 0)),
    potManaAmount: Math.max(0, Math.trunc(Number(character.battle?.potManaAmount) || 0)),
    potTickAt: 0,
    healAmount: Math.max(0, Math.trunc(Number(character.battle?.healAmount) || 0)),
    healTickAt: 0,
    furyUntil: 0,
    furyBonus: 0,
    flamingSwordReady: false,
    flamingSwordReadyAt: 0,
    flamingSwordExpiresAt: 0,
    twinDrakeReady: false,
    twinDrakeReadyAt: 0,
    twinDrakeChargeFxStartedAt: 0,
    twinDrakeChargeFxUntil: 0,
    slayingReady: false,
    slayingReadyAt: 0,
    wizardSpellLockUntil: 0,
    poisons: [],
    statBuffs: [...statBuffs],
  };
}

function bossPartyMemberVisualIndexes(member) {
  return Object.fromEntries(layerNames().map((layer) => [layer, bossPartyMemberVisualIndex(member, layer)]));
}

function bossPartyMemberVisualIndex(member, layer) {
  if (layer === "hair") return state.indexes.hair ?? 0;
  if (layer !== "weapon" && layer !== "armour") return state.indexes[layer] ?? null;
  const fallback = layer === "weapon" ? null : 0;
  const item = bossPartyMemberEquippedVisualItem(member, layer);
  const index = item?.visual?.index ?? fallback;
  if (index == null) return fallback;
  return state.catalogue?.layers?.[layer]?.indexes?.includes(index) ? index : fallback;
}

function bossPartyMemberEquippedVisualItem(member, layer) {
  const equipment = member?.inventory?.equipment ?? {};
  for (const entryId of Object.values(equipment)) {
    if (!entryId) continue;
    const entry = bossPartyInventoryEntryById(member, entryId);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (item?.visual?.layer === layer) return item;
  }
  return null;
}

async function preloadBossPartyVisualAtlases(members) {
  await Promise.all(members.map((member) => preloadBossPartyMemberVisualAtlases(member)));
  render();
}

async function preloadBossPartyMemberVisualAtlases(member) {
  member.visualIndexes = bossPartyMemberVisualIndexes(member);
  member.visualAtlases = member.visualAtlases ?? {};
  await Promise.all(layerNames().map(async (layer) => {
    const index = member.visualIndexes[layer];
    if (index == null || index === "") {
      member.visualAtlases[layer] = null;
      return;
    }
    const key = `${state.spriteSet}:${layer}:${index}`;
    if (!bossPartyVisualAtlasCache.has(key)) {
      bossPartyVisualAtlasCache.set(key, loadAtlas(state.spriteSet, layer, index).catch(() => null));
    }
    const atlas = await bossPartyVisualAtlasCache.get(key);
    member.visualAtlases[layer] = atlas;
    if (atlas) await loadCachedImage(sheetUrl(state.spriteSet, layer, index)).catch(() => null);
  }));
}

function updateBossPartyVisualFrames(now) {
  const party = state.battle.bossParty;
  if (!party?.members?.length) return;
  for (const member of party.members) updateBossPartyMemberVisualFrame(member, now);
}

function updateBossPartyMemberVisualFrame(member, now) {
  const action = member.visualAction ?? (member.alive ? "stance" : "die");
  const clip = bossPartyMemberVisualClip(member, action);
  if (state.paused || !clip?.frames?.length) return;
  const dt = now - (member.visualLastTick ?? now);
  if (dt < clip.interval) return;
  const steps = Math.floor(dt / clip.interval);
  const nextFrame = (member.visualFrame ?? 0) + steps;
  const terminal = member.visualOneShot || action === "struck" || action === "die";
  if (terminal) {
    if (nextFrame >= clip.frames.length) {
      if (member.alive && member.hp > 0) {
        member.visualAction = bossPartyMemberIsWalkingToMelee(member) ? "walking" : "stance";
        member.visualFrame = 0;
        member.visualOneShot = false;
        if (member.classId === "Warrior") member.fxSpellId = null;
        member.visualLastTick = now;
        return;
      }
      member.visualFrame = clip.frames.length - 1;
    } else {
      member.visualFrame = nextFrame;
    }
  } else {
    member.visualFrame = nextFrame % clip.frames.length;
  }
  member.visualLastTick = (member.visualLastTick ?? now) + steps * clip.interval;
}

function bossPartyMemberVisualClip(member, action = member?.visualAction) {
  for (const layer of layerNames()) {
    const atlas = member?.visualAtlases?.[layer] ?? (member?.classId === bossPartyControlledClassId() ? state.atlases[layer] : null);
    const clip = atlas?.actions?.[action];
    if (clip?.frames?.length) return clip;
  }
  return null;
}

function spawnGroupDungeonBossEnemy(now, zone = activeZone()) {
  const party = state.battle.bossParty;
  if (!party?.active || !groupDungeonBossZone(zone) || groupDungeonBossRespawnRemainingMs(zone) > 0) return false;
  const template = ENEMY_TEMPLATES.find((enemy) => zone.enemyIds.includes(enemy.id));
  if (!template) return false;
  state.battle.enemyId = template.id;
  state.battle.enemy = {
    ...template,
    hp: template.maxHp,
    mp: template.maxMp,
    poisons: [],
    debuffs: [],
  };
  state.battle.phase = "engaged";
  state.battle.enemyAggro = true;
  state.battle.enemyRevealed = true;
  state.battle.enemyX = bossPartyEnemyApproachX(party.members);
  state.battle.nextEnemyAttackAt = now + Math.max(400, Math.trunc(Number(template.attackMs) || 1400));
  setEnemyLocomotion("standing", now);
  if (template.monsterIndex) {
    state.enemy.index = template.monsterIndex;
    void reloadEnemyAtlas();
  }
  if (groupDungeonBossReinforcementsZone(zone)) {
    initGroupDungeonBossReinforcements(now, zone);
  }
  pushBattleLog(`${template.name} enters the fight.`);
  return true;
}

function updateGroupDungeonBossWaitingRoom(now) {
  const party = state.battle.bossParty;
  if (!party?.active || !groupDungeonBossZone(activeZone())) return false;
  bossPartySyncControlledPlayerRef();
  updateBossPartyVisualFrames(now);
  for (const member of party.members) {
    updateBossPartyMemberPotionRegen(member, now);
    updateBossPartyMemberHealRegen(member, now);
    bossPartyAutoUsePotions(member, now);
  }
  if (party.pet) updateBossPartyMemberHealRegen(party.pet, now);
  syncBossPartyControlledRecoveryToState();
  updateBossPartyEffects(now);
  updateBossPartyHealFx(now);
  updateDefenceBuffFx(now);
  spawnGroupDungeonBossEnemy(now);
  return true;
}

function updateBossPartyBattle(now) {
  const party = state.battle.bossParty;
  if (!party?.active) return false;
  if (groupDungeonSwarmActive()) return updateGroupDungeonBossPartyBattle(now);
  const enemy = state.battle.enemy;
  if (!enemy) {
    if (groupDungeonBossZone(activeZone())) return updateGroupDungeonBossWaitingRoom(now);
    return false;
  }
  bossPartySyncControlledPlayerRef();
  updateBossPartyVisualFrames(now);
  updateBossPartyMeleeAdvance(now);
  for (const member of party.members) {
    updateBossPartyMemberPotionRegen(member, now);
    updateBossPartyMemberHealRegen(member, now);
    bossPartyAutoUsePotions(member, now);
  }
  if (party.pet) updateBossPartyMemberHealRegen(party.pet, now);
  syncBossPartyControlledRecoveryToState();
  updateEnemyPoisons(now);
  updateBossPartyPendingPoison(now);
  updateGroundSpellEffects(now);
  updateMapLightning(now);
  updateBossPartyEffects(now);
  updateBossPartyImpacts(now);
  updateBossPartyHealFx(now);
  updateDefenceBuffFx(now);
  updatePendingTwinDrakeHits(now);
  updateAttachedSpellFx(now);
  updatePendingEnemyStrike(now);
  updatePendingPetAttack(now);
  updateCombatantPoisons(now);
  updateWarriorChargeExpiry(now);
  if (enemy.hp <= 0) {
    finishBossPartyEnemy(now);
    return true;
  }
  if (bossPartyAllMembersDead()) {
    finishBossPartyDefeat(now);
    return true;
  }

  if (party.pet?.active && now >= (party.pet.nextAttackAt ?? 0)) bossPartyPetAttack(now);
  for (const member of party.members) {
    if (!member.alive || member.hp <= 0 || now < (member.nextActionAt ?? 0)) continue;
    if (bossPartyMemberIsWalkingToMelee(member)) continue;
    bossPartyMemberAction(member, now);
    if (enemy.hp <= 0) {
      finishBossPartyEnemy(now);
      return true;
    }
  }

  if (!enemyFrozenActive(enemy, now) && now >= (state.battle.nextEnemyAttackAt ?? 0) && bossPartyEnemyAttack(now)) {
    state.battle.nextEnemyAttackAt = now + effectiveEnemyAttackMs(enemy, now);
  }
  updateBossPartyMeleeAdvance(now);
  bossPartyAdvanceEnemy(now);
  updateBossPartyReinforcementSwarm(now);
  bossPartySyncControlledPlayerRef();
  if (!isPlayerOneShotAction()) setPlayerLocomotion("stance", now);
  return true;
}

function updateBossPartyAftermath(now) {
  const party = state.battle.bossParty;
  if (!party?.finished || !state.battle.enemy) return false;
  updatePendingEnemyStrike(now);
  bossPartySyncControlledPlayerRef();
  for (const member of party.members) updateBossPartyMemberRestState(member, now);
  updateBossPartyVisualFrames(now);
  return true;
}

function bossPartyMemberAction(member, now) {
  if (combatantParalyzed(member)) return bossPartyWait(member, now, 250);
  if (member.classId === "Wizard") return bossPartyWizardAction(member, now);
  if (member.classId === "Taoist") return bossPartyTaoistAction(member, now);
  return bossPartyWarriorAction(member, now);
}

function bossPartyChargeWarriorSkill(member, skill, learned, now) {
  const cost = spellMpCost(skill, learned);
  member.mp -= cost;
  bossPartySetWarriorSpellCastReadyAt(member, skill, learned, now);
  if (skill.id === "FlamingSword") {
    applyFlamingSwordChargeState(member, now);
    if (member.classId === bossPartyControlledClassId()) applyFlamingSwordChargeState(state.battle, now);
  } else if (skill.id === "TwinDrakeBlade") {
    applyTwinDrakeChargeState(member, now);
    if (member.classId === bossPartyControlledClassId()) applyTwinDrakeChargeState(state.battle, now);
  }
  sceneSignature = "";
  pushBattleLog(`${member.classId} readies ${skill.label}.`);
}

function bossPartyMaybeAutoChargeWarriorSkill(member, now) {
  if (warriorSlayingPending(member)) return false;
  for (const spellId of WARRIOR_AUTO_CHARGE_ORDER) {
    if (spellId === "FlamingSword" && member.flamingSwordReady) continue;
    if (spellId === "TwinDrakeBlade" && member.twinDrakeReady) continue;
    const skill = warriorSpellById(spellId);
    const learned = bossPartyLearned(member, spellId);
    if (!skill || !learned?.autoCast) continue;
    if (!bossPartyCanUseWarriorSkill(member, skill, learned, now, { requireAuto: true })) continue;
    bossPartyChargeWarriorSkill(member, skill, learned, now);
    return true;
  }
  return false;
}

function bossPartyChargeTwinDrake(member, skill, learned, now) {
  bossPartyChargeWarriorSkill(member, skill, learned, now);
}

function bossPartyWarriorAction(member, now) {
  const enemy = state.battle.enemy;
  const queuedWarrior = bossPartyQueuedWarriorSkill(member, now);

  if (queuedWarrior && !queuedWarrior.queuedWaiting && queuedWarrior.skill.buff) {
    const { skill, learned, cost } = queuedWarrior;
    member.mp -= cost;
    learned.castReadyAt = now + spellDelayMs(skill, learned);
    member.furyUntil = now + 60000 + (Number(learned.level) || 0) * 10000;
    member.furyBonus = 4;
    member.nextActionAt = now + CRYSTAL_PLAYER_ACTION_LOCK_MS;
    clearQueuedCombatSpell(skill.id);
    bossPartyControlledVisual(member, skill, "spell", now);
    bossPartyCastSfx(member, skill.id, 0.42, 160);
    bossPartyLevelMagicSkill(member, skill, learned, now);
    pushBattleLog(`${member.classId} casts ${skill.label}.`);
    return true;
  }

  const autoSkills = bossPartyAutoSpells(member);
  const fury = autoSkills.find((skill) => skill.id === "Fury");
  const furyLearned = bossPartyLearned(member, "Fury");
  if (fury && furyLearned && now >= (furyLearned.castReadyAt ?? 0) && now >= (member.furyUntil ?? 0) && member.mp >= spellMpCost(fury, furyLearned)) {
    member.mp -= spellMpCost(fury, furyLearned);
    furyLearned.castReadyAt = now + spellDelayMs(fury, furyLearned);
    member.furyUntil = now + 60000 + (Number(furyLearned.level) || 0) * 10000;
    member.furyBonus = 4;
    member.nextActionAt = now + CRYSTAL_PLAYER_ACTION_LOCK_MS;
    bossPartyControlledVisual(member, fury, "spell", now);
    bossPartyCastSfx(member, fury.id, 0.42, 160);
    bossPartyLevelMagicSkill(member, fury, furyLearned, now);
    pushBattleLog(`${member.classId} casts ${fury.label}.`);
    return true;
  }

  // Out of reach (boss still closing the gap, or a pet is tanking and the
  // Warrior lacks Thrusting): hold position rather than swinging at air.
  if (!bossPartyCanWeaponReach(member)) return bossPartyWait(member, now);

  const distance = bossPartyMemberEnemyDistance(member);
  const thrusting = autoSkills.find((skill) => skill.id === "Thrusting");
  const thrustingLearned = bossPartyLearned(member, "Thrusting");
  const useThrusting = Boolean(thrusting && thrustingLearned
    && distance > BOSS_PARTY_WARRIOR_REACH && distance <= BOSS_PARTY_THRUSTING_REACH);
  const halfMoon = autoSkills.find((skill) => skill.id === "HalfMoon");
  const halfMoonLearned = bossPartyLearned(member, "HalfMoon");
  const useHalfMoon = Boolean(halfMoon && halfMoonLearned
    && !useThrusting
    && canUseHalfMoonAttack(distance, member.mp ?? 0, halfMoonLearned));
  let attackSkill = null;
  let learned = null;
  let cost = 0;
  let usingFlamingSword = false;
  let usingTwinDrake = false;
  let usingSlaying = false;
  let usingHalfMoon = false;

  if (warriorSlayingPending(member) && bossPartyLearned(member, "Slaying")) {
    attackSkill = warriorSpellById("Slaying");
    learned = bossPartyLearned(member, "Slaying");
    cost = 0;
    usingSlaying = Boolean(attackSkill);
  } else if (queuedWarrior && !queuedWarrior.queuedWaiting && !queuedWarrior.skill.buff) {
    attackSkill = queuedWarrior.skill;
    learned = queuedWarrior.learned;
    cost = queuedWarrior.cost;
    if (attackSkill.id === "Thrusting" && !useThrusting) {
      attackSkill = null;
      learned = null;
      cost = 0;
    }
    if (attackSkill.id === "HalfMoon" && !useHalfMoon) {
      attackSkill = null;
      learned = null;
      cost = 0;
    }
  }
  if (!attackSkill && !usingSlaying) {
    attackSkill = useThrusting
      ? thrusting
      : useHalfMoon
        ? halfMoon
        : autoSkills.find((skill) => {
        if (isWarriorChargeSkill(skill) && !warriorMemberChargeReady(member, skill.id)) return false;
        const skillLearned = bossPartyLearned(member, skill.id);
        return !skill.buff && !skill.toggle
          && !bossPartySpellOnCooldown(member, skill, skillLearned, now)
          && member.mp >= spellMpCost(skill, skillLearned);
      });
  }
  if (!usingSlaying) {
    if (member.flamingSwordReady) {
      const flaming = warriorSpellById("FlamingSword");
      const flamingLearned = bossPartyLearned(member, "FlamingSword");
      if (flaming && flamingLearned) {
        attackSkill = flaming;
        learned = flamingLearned;
        cost = 0;
        usingFlamingSword = true;
      } else {
        clearFlamingSwordChargeState(member);
        if (member.classId === bossPartyControlledClassId()) clearFlamingSwordChargeState(state.battle);
      }
    } else if (member.twinDrakeReady) {
      const twinDrake = warriorSpellById("TwinDrakeBlade");
      const twinDrakeLearned = bossPartyLearned(member, "TwinDrakeBlade");
      if (twinDrake && twinDrakeLearned && member.mp >= spellMpCost(twinDrake, twinDrakeLearned)) {
        attackSkill = twinDrake;
        learned = twinDrakeLearned;
        cost = spellMpCost(twinDrake, twinDrakeLearned);
        usingTwinDrake = true;
      } else {
        clearTwinDrakeChargeState(member);
        if (member.classId === bossPartyControlledClassId()) clearTwinDrakeChargeState(state.battle);
      }
    }
  }
  if (!attackSkill && !usingSlaying) {
    if (!learned) learned = null;
  } else if (!learned && attackSkill) {
    learned = bossPartyLearned(member, attackSkill.id);
  }
  if (!cost && attackSkill && learned) cost = spellMpCost(attackSkill, learned);
  if (usingSlaying) {
    clearWarriorSlayingReady(member);
  } else if (usingFlamingSword) {
    clearFlamingSwordChargeState(member);
    if (member.classId === bossPartyControlledClassId()) clearFlamingSwordChargeState(state.battle);
    bossPartySetWarriorSpellCastReadyAt(member, attackSkill, learned, now);
  } else if (usingTwinDrake) {
    clearTwinDrakeChargeState(member);
    if (member.classId === bossPartyControlledClassId()) clearTwinDrakeChargeState(state.battle);
    member.mp -= cost;
    bossPartySetWarriorSpellCastReadyAt(member, attackSkill, learned, now);
  } else if (learned) {
    member.mp -= cost;
    if (!attackSkill.toggle) bossPartySetWarriorSpellCastReadyAt(member, attackSkill, learned, now);
  }
  usingHalfMoon = isHalfMoonAttackSkill(attackSkill);
  if (queuedWarrior?.queued && attackSkill && learned && attackSkill.id === queuedWarrior.skill.id) {
    clearQueuedCombatSpell(attackSkill.id);
  }
  member.nextActionAt = now + (usingTwinDrake
    ? twinDrakeAttackDelayMs(bossPartyEffectiveAttackSpeed(member, now), member.level)
    : attackDelayMs(bossPartyEffectiveAttackSpeed(member, now), member.level));
  bossPartyControlledVisual(member, attackSkill, attackSkill?.bodyAction ?? BASIC_ATTACK_SKILL.bodyAction, now);
  bossPartyWarriorSwingSfx(member, learned ? attackSkill : null);
  let twinDrakeRawDamage = 0;
  bossPartyAttackEnemy(member, learned ? attackSkill.label : "Attack", () => {
    twinDrakeRawDamage = usingHalfMoon
      ? rollDamage(effectiveCombatStats(member).dc, enemyPhysicalDefence(enemy), member.luck)
      : learned
        ? rollWarriorMagicDamage(attackSkill, learned, member, enemy)
        : rollDamage(effectiveCombatStats(member).dc, enemyPhysicalDefence(enemy), member.luck);
    return twinDrakeRawDamage;
  }, "physical", now, () => {
    if (learned) bossPartyLevelMagicSkill(member, attackSkill, learned, now);
    bossPartyLevelPassiveWeaponMagic(member, now);
    if (usingTwinDrake && enemy.hp > 0) queueTwinDrakeSecondHit(member, learned, twinDrakeRawDamage, now);
    if (usingHalfMoon && learned) bossPartyHalfMoonSplash(member, attackSkill, learned, enemy, now);
  }, learned ? attackSkill : null);
  bossPartyRollSlayingCharge(member, now);
  if (!warriorSlayingPending(member)) bossPartyMaybeAutoChargeWarriorSkill(member, now);
  return true;
}

// Mirrors the solo Warrior swing audio: a weapon skill plays its own attack/cast
// sound (impact lands on hit); a plain swing plays the weapon swing.
function bossPartyWarriorSwingSfx(member, skill) {
  if (skill && skill.id !== BASIC_ATTACK_SKILL.id) {
    const params = bossPartySfxParams(member, 0.58, 90);
    if (playWarriorSpellSwingSfx(skill, params)) return;
    return;
  }
  playWeaponSwingSfx({ ...bossPartySfxParams(member, 0.52, 90), family: bossPartyWeaponSfxFamily(member, "swing") });
}

function bossPartyRollSlayingCharge(member, now) {
  if (!member || member.classId !== "Warrior" || warriorSlayingPending(member)) return;
  const learned = bossPartyLearned(member, "Slaying");
  if (!learned) return;
  const level = Math.max(0, Math.min(3, Number(learned.level) || 0));
  if (randomInt(0, 11) > level) return;
  setWarriorSlayingReady(now, member);
  if (member.classId === bossPartyControlledClassId()) pushBattleLog("Slaying readied for the next attack.");
}

function bossPartyQueuedWarriorSkill(member, now) {
  if (member.classId !== bossPartyControlledClassId()) return null;
  const queued = queuedCombatSpell("Warrior");
  if (!queued) return null;
  const { spell: skill, learned, cost } = queued;
  if (!bossPartyCanUseWarriorSkill(member, skill, learned, now, { requireAuto: false })) {
    return { skill: BASIC_ATTACK_SKILL, learned: null, cost: 0, queuedWaiting: true };
  }
  return { skill, learned, cost, queued: true };
}

function bossPartyQueuedWizardSpell(member, now) {
  if (member.classId !== bossPartyControlledClassId()) return null;
  const queued = queuedCombatSpell("Wizard");
  if (!queued) return null;
  const { spell, learned, cost } = queued;
  return {
    spell,
    learned,
    cost,
    cooldownWaiting: (learned.castReadyAt ?? 0) > now || wizardCastLocked(now, member),
  };
}

function bossPartyWizardAction(member, now) {
  const enemy = state.battle.enemy;
  const queuedDefence = bossPartyUsableQueuedWizardDefenceBuff(member, now);
  if (queuedDefence && bossPartyCastWizardDefenceBuff(member, queuedDefence, now)) return true;
  const magicShield = bossPartyUsableWizardDefenceBuff(member, now);
  if (magicShield && bossPartyCastWizardDefenceBuff(member, magicShield, now)) return true;
  const spells = bossPartyWizardAttackSpells(member);
  const queuedWizard = bossPartyQueuedWizardSpell(member, now);
  if (queuedWizard?.cooldownWaiting) return bossPartyWeaponAttack(member, now);
  const queuedSpell = queuedWizard?.spell
    && queuedWizard.spell.id !== "MagicShield"
    && !(queuedWizard.spell.id === "FireWall" && !bossPartyFireWallHasUsefulTarget(queuedWizard.spell, member, now))
    ? queuedWizard.spell
    : null;
  if (queuedWizard && !queuedSpell) return bossPartyWeaponAttack(member, now);
  const spell = queuedSpell ?? spells.find((candidate) => {
    const learned = bossPartyLearned(member, candidate.id);
    if (!canWizardCastSpell(candidate, learned, now, member)) return false;
    if (candidate.id === "FireWall") return bossPartyFireWallHasUsefulTarget(candidate, member, now);
    if (!wizardAutoSpellEligible(candidate, member)) return false;
    return true;
  });
  if (!spell) return bossPartyWeaponAttack(member, now);
  const learned = bossPartyLearned(member, spell.id);
  const cost = spellMpCost(spell, learned);
  member.mp -= cost;
  applyWizardCastCooldown(spell, learned, now, member);
  clearQueuedCombatSpell(spell.id);
  const bangCenterTile = spell.impactMode === "bang" ? wizardBangCenterTile(enemy, spell, member) : null;
  bossPartyControlledVisual(member, spell, spell.bodyAction ?? "spell", now, { centerTile: bangCenterTile });
  if (spell.impactMode !== "target") bossPartyCastSfx(member, spell.id, 0.5, 120);

  if (spell.id === "FireWall") {
    const value = rollWizardMagicValue(spell, learned, member);
    const centerTile = groupDungeonSwarmSideActive()
      ? groupDungeonSwarmBestFireWallCenterTile(spell, member, now)
      : null;
    if (groupDungeonSwarmSideActive() && !centerTile) return false;
    createWizardGroundSpellEffect(spell, { value, worldX: state.battle.enemyX, centerTile }, now, member, learned);
    pushBattleLog(`${member.classId} casts ${spell.label}${centerTile ? " into the swarm" : ` under ${enemy.name}`}.`);
    return true;
  }
  if (spell.impactMode === "bang") {
    const baseValue = rollWizardMagicValue(spell, learned, member);
    const centerTile = bangCenterTile ?? wizardBangCenterTile(enemy, spell, member);
    state.battle.activeWizardSpellCenterTile = centerTile;
    member.fxCenterTile = centerTile;
    partyBossImpacts().push({
      at: now + wizardImpactDelay(spell, state.wizardSpellAtlases[spell.id] ?? null),
      spellId: spell.id,
      label: spell.label,
      baseValue,
      bang: true,
      centerTile,
      casterClassId: member.classId,
    });
    pushBattleLog(`${member.classId} casts ${spell.label}.`);
    return true;
  }
  if (spell.impactMode === "buff") return true;

  if (spell.impactMode === "projectile") playSpellSfx(spell.id, "fly", bossPartySfxParams(member, 0.38, 120));
  bossPartyQueueImpact(member, spell, spell.label, state.wizardSpellAtlases[spell.id] ?? null, now, () => (
    rollWizardMagicDamage(spell, learned, member, enemy)
  ));
  return true;
}

function bossPartyTaoistAction(member, now) {
  if (member.classId === bossPartyControlledClassId()) {
    const queuedRequest = queuedCombatSpell("Taoist");
    const queued = bossPartyUsableQueuedTaoistSpell(member, now);
    if (queued && bossPartyCastQueuedTaoistSpell(member, queued, now)) return true;
    if (queuedRequest) return bossPartyWeaponAttack(member, now);
  }

  const spells = bossPartyAutoSpells(member);
  const healing = spells.find((spell) => spell.id === "Healing");
  const healTarget = healing ? bossPartyHealTarget() : null;
  if (healTarget && bossPartyCanCast(member, healing, now)) {
    const learned = bossPartyLearned(member, healing.id);
    const amount = rollTaoistHealingAmount(healing, learned, member);
    member.mp -= spellMpCost(healing, learned);
    learned.castReadyAt = now + spellDelayMs(healing, learned);
    member.nextActionAt = now + spellDelayMs(healing, learned);
    healTarget.healAmount = Math.min(65535, (healTarget.healAmount ?? 0) + amount);
    healTarget.healTickAt = healTarget.healTickAt || now + CRYSTAL_HEAL_DELAY_MS;
    bossPartyControlledVisual(member, healing, healing.bodyAction ?? "spell", now);
    bossPartyCastSfx(member, healing.id, 0.38, 160);
    bossPartyQueueHealFx(member, healTarget, healing, now);
    bossPartyLevelMagicSkill(member, healing, learned, now);
    pushBattleLog(`${member.classId} casts ${healing.label} on ${healTarget.name}.`);
    return true;
  }

  const summon = spells.find((spell) => spell.id === "SummonSkeleton");
  if (summon && !bossPartyActivePet() && !state.battle.bossParty.petDiedThisFight && bossPartyCanCast(member, summon, now)) {
    const amuletCost = taoistSummonAmuletCost(summon.id);
    if (bossPartyAmuletInventoryCount(member) >= amuletCost && bossPartyConsumeAmuletInventoryUnits(member, amuletCost)) {
      const learned = bossPartyLearned(member, summon.id);
      member.mp -= spellMpCost(summon, learned);
      learned.castReadyAt = now + spellDelayMs(summon, learned);
      member.nextActionAt = now + spellDelayMs(summon, learned);
      state.battle.bossParty.pet = createTaoistSummonPet(summon.id, Math.max(0, Number(learned.level) || 0), now);
      state.battle.bossParty.pet.name = `${member.classId}'s ${state.battle.bossParty.pet.name}`;
      state.battle.taoPet = state.battle.bossParty.pet;
      state.taoPetAtlas = taoPetAtlasFor(state.battle.taoPet);
      bossPartyControlledVisual(member, summon, summon.bodyAction ?? "spell", now);
      bossPartyCastSfx(member, summon.id, 0.38, 160);
      bossPartyLevelMagicSkill(member, summon, learned, now);
      playTaoPetAppearSfx({ volume: bossPartySfxVolume(member, 0.4, 0.18), throttleMs: 250, pet: state.battle.taoPet });
      pushBattleLog(`${member.classId} summons ${state.battle.bossParty.pet.name}.`);
      return true;
    }
  }

  const shinsu = spells.find((spell) => spell.id === "SummonShinsu");
  if (shinsu && !bossPartyActivePet() && !state.battle.bossParty.petDiedThisFight && bossPartyCanCast(member, shinsu, now)) {
    const amuletCost = taoistSummonAmuletCost(shinsu.id);
    if (bossPartyAmuletInventoryCount(member) >= amuletCost && bossPartyConsumeAmuletInventoryUnits(member, amuletCost)) {
      const learned = bossPartyLearned(member, shinsu.id);
      member.mp -= spellMpCost(shinsu, learned);
      learned.castReadyAt = now + spellDelayMs(shinsu, learned);
      member.nextActionAt = now + spellDelayMs(shinsu, learned);
      state.battle.bossParty.pet = createTaoistSummonPet(shinsu.id, Math.max(0, Number(learned.level) || 0), now);
      state.battle.bossParty.pet.name = `${member.classId}'s ${state.battle.bossParty.pet.name}`;
      state.battle.taoPet = state.battle.bossParty.pet;
      state.taoPetAtlas = taoPetAtlasFor(state.battle.taoPet);
      bossPartyControlledVisual(member, shinsu, shinsu.bodyAction ?? "spell", now);
      bossPartyCastSfx(member, shinsu.id, 0.38, 160);
      bossPartyLevelMagicSkill(member, shinsu, learned, now);
      playTaoPetAppearSfx({ volume: bossPartySfxVolume(member, 0.4, 0.18), throttleMs: 250, pet: state.battle.taoPet });
      pushBattleLog(`${member.classId} summons ${state.battle.bossParty.pet.name}.`);
      return true;
    }
  }

  for (const spellId of ["SoulShield", "BlessedArmour"]) {
    const defenceBuff = bossPartyUsableTaoistDefenceBuff(member, spellId, now);
    if (defenceBuff && bossPartyCastDefenceBuff(member, defenceBuff, now)) return true;
  }

  const ultimateEnhancer = bossPartyUsableTaoistUltimateEnhancer(member, now);
  if (ultimateEnhancer && bossPartyCastUltimateEnhancer(member, ultimateEnhancer, now)) return true;

  const poison = spells.find((spell) => spell.id === "Poisoning");
  if (poison && !state.battle.bossParty.pendingPoison && bossPartyCanCast(member, poison, now)) {
    const entry = bossPartyPoisonCandidate(member, state.battle.enemy, now);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (entry && item && bossPartyConsumeOneInventoryUnit(member, entry.id)) {
      const learned = bossPartyLearned(member, poison.id);
      member.mp -= spellMpCost(poison, learned);
      learned.castReadyAt = now + spellDelayMs(poison, learned);
      member.nextActionAt = now + spellDelayMs(poison, learned);
      bossPartyQueuePoisonApply(member, poison, learned, item, now);
      return true;
    }
  }

  const soulFireBall = spells.find((spell) => spell.id === "SoulFireBall");
  if (soulFireBall && bossPartyCanCast(member, soulFireBall, now)) {
    const amulet = bossPartyAmuletCandidate(member);
    if (amulet && bossPartyConsumeOneInventoryUnit(member, amulet.id)) {
      const learned = bossPartyLearned(member, soulFireBall.id);
      member.mp -= spellMpCost(soulFireBall, learned);
      learned.castReadyAt = now + spellDelayMs(soulFireBall, learned);
      member.nextActionAt = now + spellDelayMs(soulFireBall, learned);
      bossPartyControlledVisual(member, soulFireBall, soulFireBall.bodyAction ?? "spell", now);
      bossPartyCastSfx(member, soulFireBall.id, 0.38, 160);
      playSpellSfx(soulFireBall.id, "fly", bossPartySfxParams(member, 0.38, 120));
      bossPartyQueueImpact(member, soulFireBall, soulFireBall.label, state.taoistSpellAtlases[soulFireBall.id] ?? null, now, () => (
        rollTaoistMagicDamage(soulFireBall, learned, member, state.battle.enemy)
      ));
      return true;
    }
  }

  return bossPartyWeaponAttack(member, now);
}

function bossPartyAttackEnemy(member, label, rollDamageFn, kind, now, onHit, skill) {
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) return false;
  if (kind === "physical" && !rollHit(member.accuracy, enemy.agility)) {
    bossPartyShowEnemyMiss(member.classId, now);
    pushBattleLog(`${member.classId} ${label.toLowerCase()} misses ${enemy.name}.`);
    return true;
  }
  const damage = scaleEnemyPhysicalDamage(rollDamageFn(), enemy, now);
  if (damage <= 0) {
    bossPartyShowEnemyMiss(member.classId, now);
    pushBattleLog(`${member.classId} ${label.toLowerCase()} misses ${enemy.name}.`);
    return true;
  }
  reduceEnemyHp(enemy, damage);
  syncBattleEnemyHpToSwarm();
  strikeGroupDungeonSwarmEnemy(enemy, now);
  playMonsterSfx("flinch", enemy, bossPartySfxParams(member, 0.42, 80));
  if (kind === "physical") {
    // A weapon skill (Slaying/Thrusting/etc.) plays its own impact sound, falling
    // back to the weapon hit; a plain swing just plays the weapon hit (mirrors solo).
    const skillImpact = skill && skill.id !== BASIC_ATTACK_SKILL.id
      && playSpellSfx(skill.id, "impact", bossPartySfxParams(member, 0.5, 80));
    if (!skillImpact) playWeaponHitSfx({ ...bossPartySfxParams(member, 0.5, 90), family: bossPartyWeaponSfxFamily(member, "hit") });
  }
  bossPartyShowEnemyDamage(member.classId, damage, now);
  pushBattleLog(`${member.classId} ${label} hits ${enemy.name} for ${damage}.`);
  if (kind === "physical" && enemy.hp > 0) applyCrystalFreezingAttackProc(member, enemy, now);
  if (typeof onHit === "function") onHit(damage);
  maybeKillGroupDungeonSwarmEnemy(enemy, now);
  return true;
}

function bossPartyWeaponAttack(member, now) {
  if (!bossPartyCanMelee(member)) return bossPartyWait(member, now);
  member.nextActionAt = now + attackDelayMs(bossPartyEffectiveAttackSpeed(member, now), member.level);
  bossPartyControlledVisual(member, BASIC_ATTACK_SKILL, BASIC_ATTACK_SKILL.bodyAction, now);
  playWeaponSwingSfx({ ...bossPartySfxParams(member, 0.52, 90), family: bossPartyWeaponSfxFamily(member, "swing") });
  return bossPartyAttackEnemy(member, "Attack", () => rollDamage(effectiveCombatStats(member).dc, enemyPhysicalDefence(state.battle.enemy), member.luck), "physical", now, () => bossPartyLevelPassiveWeaponMagic(member, now));
}

function bossPartyControlledVisual(member, skill, bodyAction, now, options = {}) {
  member.visualAction = bodyAction ?? "attack1";
  member.visualFrame = 0;
  member.visualOneShot = true;
  member.visualLastTick = now;
  member.fxCenterTile = options.centerTile ?? null;
  // Track per-member spell FX so assist members render their own overlays at their
  // position. The controlled member is drawn via the battle.active* path.
  if (member.classId === "Wizard" || member.classId === "Taoist") {
    member.fxSpellId = skill?.id ?? null;
    member.fxStartedAt = now;
  } else if (member.classId === "Warrior" && skill?.id && skill.id !== BASIC_ATTACK_SKILL.id) {
    member.fxSpellId = skill.id;
    member.fxStartedAt = now;
  }
  if (member.classId !== bossPartyControlledClassId()) return;
  state.battle.activeSkill = member.classId === "Warrior" ? (skill?.id ?? "None") : "None";
  state.battle.activeSkillAtlas = member.classId === "Warrior" ? (state.warriorSkillAtlases[skill?.id] ?? null) : null;
  state.battle.activeSkillStartedAt = now;
  state.battle.activeWizardSpell = member.classId === "Wizard" ? skill?.id ?? null : null;
  state.battle.activeWizardSpellAtlas = member.classId === "Wizard" ? (state.wizardSpellAtlases[skill?.id] ?? null) : null;
  state.battle.activeWizardSpellStartedAt = now;
  state.battle.activeWizardSpellCenterTile = member.classId === "Wizard" ? (options.centerTile ?? null) : null;
  state.battle.activeTaoSpell = member.classId === "Taoist" ? skill?.id ?? null : null;
  state.battle.activeTaoSpellAtlas = member.classId === "Taoist" ? (state.taoistSpellAtlases[skill?.id] ?? null) : null;
  state.battle.activeTaoSpellStartedAt = now;
  setPlayerAction(bodyAction ?? "attack1", now, true);
}

function bossPartyCanCast(member, spell, now) {
  const learned = bossPartyLearned(member, spell?.id);
  if (!spell || !learned || spell.passive) return false;
  if (member.classId === "Wizard") return canWizardCastSpell(spell, learned, now, member);
  if ((learned.castReadyAt ?? 0) > now) return false;
  return member.mp >= spellMpCost(spell, learned);
}

function bossPartyCanUseWarriorSkill(member, skill, learned, now, options = {}) {
  if (!skill || !learned || skill.passive) return false;
  if (options.requireAuto && !learned.autoCast) return false;
  if (isWarriorChargeSkill(skill) && warriorMemberChargeReady(member, skill.id)) return false;
  const distance = bossPartyMemberEnemyDistance(member);
  if (skill.toggle) {
    if (skill.id === "Thrusting") {
      return distance > BOSS_PARTY_WARRIOR_REACH && distance <= BOSS_PARTY_THRUSTING_REACH;
    }
    if (skill.id === "HalfMoon") {
      const learned = bossPartyLearned(member, skill.id);
      return canUseHalfMoonAttack(distance, member.mp ?? 0, learned);
    }
    return false;
  }
  const chargeCast = isWarriorChargeSkill(skill) && !warriorMemberChargeReady(member, skill.id);
  if (!skill.buff && !chargeCast && distance > bossPartyMemberReach(member)) return false;
  if (skill.id === "Fury" && now < (member.furyUntil ?? 0)) return false;
  if (bossPartySpellOnCooldown(member, skill, learned, now)) return false;
  return member.mp >= spellMpCost(skill, learned);
}

function bossPartyCanUseTaoistSpell(member, spell, learned, now, options = {}) {
  if (!spell || !learned || spell.passive) return false;
  if (options.requireAuto) {
    if (!learned.autoCast) return false;
    if (!bossPartyAutoSpells(member).some((autoSpell) => autoSpell.id === spell.id)) return false;
  }
  if ((learned.castReadyAt ?? 0) > now) return false;
  return member.mp >= spellMpCost(spell, learned);
}

function bossPartyCanUseWizardSpell(member, spell, learned, now, options = {}) {
  if (!spell || !learned || spell.passive) return false;
  if (options.requireAuto) {
    if (!learned.autoCast) return false;
    if (!bossPartyAutoSpells(member).some((autoSpell) => autoSpell.id === spell.id)) return false;
  }
  if (!canWizardCastSpell(spell, learned, now, member)) return false;
  if (spell.id === "FireWall" && bossPartyGroundEffectActive("FireWall", now)) return false;
  return member.mp >= spellMpCost(spell, learned);
}

function bossPartyUsableTaoistHealing(member, now, options = {}) {
  const spell = taoistCombatSpell("Healing");
  const learned = bossPartyLearned(member, spell.id);
  const manual = options.requireAuto === false;
  if (!bossPartyCanUseTaoistSpell(member, spell, learned, now, { requireAuto: !manual })) return null;
  const target = bossPartyHealTarget(manual);
  if (!target) return null;
  return { spell, learned, cost: spellMpCost(spell, learned), target };
}

function bossPartyUsableTaoistPoisoning(member, now, options = {}) {
  const spell = taoistCombatSpell("Poisoning");
  const learned = bossPartyLearned(member, spell.id);
  if (!bossPartyCanUseTaoistSpell(member, spell, learned, now, { requireAuto: options.requireAuto !== false })) return null;
  if (state.battle.bossParty.pendingPoison) return null;
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0) return null;
  if (!options.ignoreRange && bossPartyMemberEnemyDistance(member) > crystalSpellRangePx(spell)) return null;
  const entry = bossPartyPoisonCandidate(member, enemy, now);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !isPoisonItem(item)) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry,
    item,
    kind: poisonItemKind(item),
  };
}

function bossPartyUsableTaoistSoulFireBall(member, now, options = {}) {
  const spell = taoistCombatSpell("SoulFireBall");
  const learned = bossPartyLearned(member, spell.id);
  if (!bossPartyCanUseTaoistSpell(member, spell, learned, now, { requireAuto: options.requireAuto !== false })) return null;
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0) return null;
  if (!options.ignoreRange && bossPartyMemberEnemyDistance(member) > taoistSoulFireBallRangePx(spell)) return null;
  const amulet = bossPartyAmuletCandidate(member);
  const item = amulet ? itemDefinition(amulet.itemId) : null;
  if (!amulet || !isTaoistAmuletItem(item)) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry: amulet,
    item,
  };
}

function bossPartyUsableTaoistUltimateEnhancer(member, now, options = {}) {
  const spell = taoistCombatSpell("UltimateEnhancer");
  const learned = bossPartyLearned(member, spell?.id);
  const manual = options.requireAuto === false;
  if (!spell || !learned || !bossPartyCanUseTaoistSpell(member, spell, learned, now, { requireAuto: !manual })) return null;
  const targets = ultimateEnhancerTargets(now);
  if (!targets.length) return null;
  if (!manual && !ultimateEnhancerNeedsCast(now)) return null;
  const amulet = bossPartyAmuletCandidate(member);
  const item = amulet ? itemDefinition(amulet.itemId) : null;
  if (!amulet || !isTaoistAmuletItem(item)) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry: amulet,
    item,
    targets,
  };
}

function bossPartyCastUltimateEnhancer(member, castBundle, now) {
  if (!bossPartyConsumeOneInventoryUnit(member, castBundle.entry.id)) return false;
  const targets = ultimateEnhancerTargets(now);
  if (!targets.length) return false;
  member.mp -= castBundle.cost;
  castBundle.learned.castReadyAt = now + spellDelayMs(castBundle.spell, castBundle.learned);
  member.nextActionAt = now + spellDelayMs(castBundle.spell, castBundle.learned);
  clearQueuedCombatSpell(castBundle.spell.id);
  const applied = applyUltimateEnhancerToTargets(
    castBundle.spell,
    castBundle.learned,
    member,
    targets,
    now,
    { levelSkill: false },
  );
  if (!applied) return false;
  bossPartyLevelMagicSkill(member, castBundle.spell, castBundle.learned, now);
  bossPartyControlledVisual(member, castBundle.spell, castBundle.spell.bodyAction ?? "spell", now);
  bossPartyCastSfx(member, castBundle.spell.id, 0.38, 160);
  showUltimateEnhancerBuffTexts(applied, now);
  queueUltimateEnhancerImpactFx(castBundle.spell, applied, now, {
    soundPlayed: member.classId !== bossPartyControlledClassId(),
  });
  pushBattleLog(formatUltimateEnhancerAppliedLog(castBundle.spell, member.classId, applied, applied.durationMs));
  return true;
}

function resolveBossPartyMember(member) {
  if (!member?.classId || !state.battle.bossParty?.active) return member;
  return state.battle.bossParty.members?.find((entry) => entry.classId === member.classId) ?? member;
}

function bossPartyMemberPlayerBuffs(member) {
  const partyMember = resolveBossPartyMember(member);
  if (!partyMember) return state.battle.statBuffs ?? [];
  const memberBuffs = Array.isArray(partyMember.statBuffs) ? partyMember.statBuffs : [];
  if (partyMember.classId === bossPartyControlledClassId()) {
    const battleBuffs = state.battle.statBuffs ?? [];
    const merged = [...memberBuffs];
    for (const buff of battleBuffs) {
      if (!merged.some((entry) => entry.kind === buff.kind)) merged.push(buff);
    }
    return merged.length > 0 ? merged : memberBuffs;
  }
  return memberBuffs;
}

function bossPartyWizardAttackSpells(member) {
  return bossPartyAutoSpells(member).filter((spell) => spell.impactMode !== "buff");
}

function bossPartyUsableTaoistDefenceBuff(member, spellId, now, options = {}) {
  const spell = taoistCombatSpell(spellId);
  const learned = bossPartyLearned(member, spell?.id);
  const manual = options.requireAuto === false;
  if (!spell || !learned || !bossPartyCanUseTaoistSpell(member, spell, learned, now, { requireAuto: !manual })) return null;
  if (!manual && !needsDefenceBuff(spellId, now)) return null;
  const amulet = bossPartyAmuletCandidate(member);
  const item = amulet ? itemDefinition(amulet.itemId) : null;
  if (!amulet || !isTaoistAmuletItem(item)) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry: amulet,
    item,
  };
}

function bossPartyCastDefenceBuff(member, castBundle, now) {
  if (!bossPartyConsumeOneInventoryUnit(member, castBundle.entry.id)) return false;
  member.mp -= castBundle.cost;
  castBundle.learned.castReadyAt = now + spellDelayMs(castBundle.spell, castBundle.learned);
  member.nextActionAt = now + spellDelayMs(castBundle.spell, castBundle.learned);
  clearQueuedCombatSpell(castBundle.spell.id);
  const applied = applyTaoistDefenceBuffEffect(
    castBundle.spell,
    castBundle.learned,
    member,
    now,
    { member, levelSkill: false },
  );
  if (!applied?.results?.length) return false;
  const { bonus, durationMs } = applied;
  bossPartyLevelMagicSkill(member, castBundle.spell, castBundle.learned, now);
  bossPartyControlledVisual(member, castBundle.spell, castBundle.spell.bodyAction ?? "spell", now);
  bossPartyCastSfx(member, castBundle.spell.id, 0.38, 160);
  queueDefenceBuffImpactTargets(castBundle.spell, now, {
    worldX: member.worldX ?? state.battle.playerX,
    soundPlayed: member.classId !== bossPartyControlledClassId(),
  });
  showTaoistDefenceBuffTexts(castBundle.spell, bonus, applied, now);
  pushBattleLog(`${member.classId} casts ${castBundle.spell.label} (${formatTaoistDefenceBuffAppliedLog(castBundle.spell, bonus, applied, durationMs)}).`);
  return true;
}

function bossPartyUsableWizardDefenceBuff(member, now, options = {}) {
  const spell = wizardCombatSpell("MagicShield");
  const learned = bossPartyLearned(member, spell?.id);
  const manual = options.requireAuto === false;
  if (!spell || !learned || !bossPartyCanUseWizardSpell(member, spell, learned, now, { requireAuto: !manual })) return null;
  if (!manual && !needsDefenceBuff("MagicShield", now, { playerBuffs: bossPartyMemberPlayerBuffs(member) })) return null;
  return { spell, learned, cost: spellMpCost(spell, learned) };
}

function bossPartyUsableQueuedWizardDefenceBuff(member, now) {
  const queued = queuedCombatSpell("Wizard");
  if (!queued || member.classId !== bossPartyControlledClassId() || queued.spell.id !== "MagicShield") return null;
  return bossPartyUsableWizardDefenceBuff(member, now, { requireAuto: false });
}

function bossPartyCastWizardDefenceBuff(member, castBundle, now) {
  const partyMember = resolveBossPartyMember(member);
  if (!partyMember) return false;
  partyMember.mp -= castBundle.cost;
  applyWizardCastCooldown(castBundle.spell, castBundle.learned, now, partyMember);
  clearQueuedCombatSpell(castBundle.spell.id);
  const { bonus, durationMs, reductionPercent } = applyDefenceBuffEffect(
    castBundle.spell,
    castBundle.learned,
    partyMember,
    now,
    { member: partyMember, levelSkill: false },
  );
  bossPartyLevelMagicSkill(partyMember, castBundle.spell, castBundle.learned, now);
  bossPartyControlledVisual(partyMember, castBundle.spell, castBundle.spell.bodyAction ?? "spell", now);
  bossPartyCastSfx(partyMember, castBundle.spell.id, 0.38, 160);
  if (partyMember.classId === bossPartyControlledClassId()) {
    state.battle.activeWizardSpell = null;
    state.battle.activeWizardSpellAtlas = null;
  }
  partyMember.fxSpellId = null;
  startMagicShieldLoopFx({
    expiresAt: now + durationMs,
    memberClassId: partyMember.classId === bossPartyControlledClassId() ? null : partyMember.classId,
    now,
  });
  const applied = formatDefenceBuffApplied(castBundle.spell, bonus, reductionPercent);
  pushBattleLog(`${partyMember.classId} casts ${castBundle.spell.label} (${applied}, ${formatBuffRemaining(durationMs)}).`);
  return true;
}

function bossPartyUsableTaoistSummonSpell(member, spellId, now, options = {}) {
  const spell = taoistCombatSpell(spellId);
  if (!spell) return null;
  const learned = bossPartyLearned(member, spell.id);
  if (!bossPartyCanUseTaoistSpell(member, spell, learned, now, { requireAuto: options.requireAuto !== false })) return null;
  const party = state.battle.bossParty;
  if (party.petDiedThisFight || bossPartyActivePet() || party.pendingTaoPet || state.battle.pendingTaoPet) return null;
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0) return null;
  if (!options.ignoreRange && bossPartyMemberEnemyDistance(member) > taoistSummonPetRangePx()) return null;
  const amuletCost = taoistSummonAmuletCost(spell.id);
  const amulet = bossPartyAmuletCandidate(member);
  const item = amulet ? itemDefinition(amulet.itemId) : null;
  if (!amulet || !isTaoistAmuletItem(item) || bossPartyAmuletInventoryCount(member) < amuletCost) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry: amulet,
    item,
    amuletCost,
  };
}

function bossPartyUsableTaoistSummonSkeleton(member, now, options = {}) {
  return bossPartyUsableTaoistSummonSpell(member, "SummonSkeleton", now, options);
}

function bossPartyUsableTaoistSummonShinsu(member, now, options = {}) {
  return bossPartyUsableTaoistSummonSpell(member, "SummonShinsu", now, options);
}

function bossPartyUsableQueuedTaoistSpell(member, now) {
  const queued = queuedCombatSpell("Taoist");
  if (!queued || member.classId !== bossPartyControlledClassId()) return null;
  if (queued.spell.id === "Healing") return bossPartyUsableTaoistHealing(member, now, { requireAuto: false });
  if (queued.spell.id === "Poisoning") return bossPartyUsableTaoistPoisoning(member, now, { requireAuto: false });
  if (queued.spell.id === "SoulFireBall") return bossPartyUsableTaoistSoulFireBall(member, now, { requireAuto: false });
  if (queued.spell.id === "SummonSkeleton") return bossPartyUsableTaoistSummonSkeleton(member, now, { requireAuto: false });
  if (queued.spell.id === "SummonShinsu") return bossPartyUsableTaoistSummonShinsu(member, now, { requireAuto: false });
  if (queued.spell.id === "SoulShield") return bossPartyUsableTaoistDefenceBuff(member, "SoulShield", now, { requireAuto: false });
  if (queued.spell.id === "BlessedArmour") return bossPartyUsableTaoistDefenceBuff(member, "BlessedArmour", now, { requireAuto: false });
  if (queued.spell.id === "UltimateEnhancer") return bossPartyUsableTaoistUltimateEnhancer(member, now, { requireAuto: false });
  clearQueuedCombatSpell(queued.spell.id);
  return null;
}

function bossPartyCastQueuedTaoistSpell(member, queued, now) {
  if (!queued?.spell) return false;
  if (queued.spell.id === "Healing") {
    const learned = queued.learned;
    const amount = rollTaoistHealingAmount(queued.spell, learned, member);
    member.mp -= queued.cost;
    learned.castReadyAt = now + spellDelayMs(queued.spell, learned);
    member.nextActionAt = now + spellDelayMs(queued.spell, learned);
    queued.target.healAmount = Math.min(65535, (queued.target.healAmount ?? 0) + amount);
    queued.target.healTickAt = queued.target.healTickAt || now + CRYSTAL_HEAL_DELAY_MS;
    clearQueuedCombatSpell(queued.spell.id);
    bossPartyControlledVisual(member, queued.spell, queued.spell.bodyAction ?? "spell", now);
    bossPartyCastSfx(member, queued.spell.id, 0.38, 160);
    bossPartyQueueHealFx(member, queued.target, queued.spell, now);
    bossPartyLevelMagicSkill(member, queued.spell, learned, now);
    pushBattleLog(`${member.classId} casts ${queued.spell.label} on ${queued.target.name}.`);
    return true;
  }
  if (queued.spell.id === "Poisoning") {
    if (!bossPartyConsumeOneInventoryUnit(member, queued.entry.id)) return false;
    member.mp -= queued.cost;
    queued.learned.castReadyAt = now + spellDelayMs(queued.spell, queued.learned);
    member.nextActionAt = now + spellDelayMs(queued.spell, queued.learned);
    clearQueuedCombatSpell(queued.spell.id);
    bossPartyQueuePoisonApply(member, queued.spell, queued.learned, queued.item, now);
    return true;
  }
  if (queued.spell.id === "SoulFireBall") {
    if (!bossPartyConsumeOneInventoryUnit(member, queued.entry.id)) return false;
    member.mp -= queued.cost;
    queued.learned.castReadyAt = now + spellDelayMs(queued.spell, queued.learned);
    member.nextActionAt = now + spellDelayMs(queued.spell, queued.learned);
    clearQueuedCombatSpell(queued.spell.id);
    bossPartyControlledVisual(member, queued.spell, queued.spell.bodyAction ?? "spell", now);
    bossPartyCastSfx(member, queued.spell.id, 0.38, 160);
    playSpellSfx(queued.spell.id, "fly", bossPartySfxParams(member, 0.38, 120));
    bossPartyQueueImpact(member, queued.spell, queued.spell.label, state.taoistSpellAtlases[queued.spell.id] ?? null, now, () => (
      rollTaoistMagicDamage(queued.spell, queued.learned, member, state.battle.enemy)
    ));
    return true;
  }
  if (queued.spell.id === "SummonSkeleton" || queued.spell.id === "SummonShinsu") {
    const amuletCost = queued.amuletCost ?? taoistSummonAmuletCost(queued.spell.id);
    if (!bossPartyConsumeAmuletInventoryUnits(member, amuletCost)) return false;
    member.mp -= queued.cost;
    queued.learned.castReadyAt = now + spellDelayMs(queued.spell, queued.learned);
    member.nextActionAt = now + spellDelayMs(queued.spell, queued.learned);
    clearQueuedCombatSpell(queued.spell.id);
    state.battle.bossParty.pet = createTaoistSummonPet(
      queued.spell.id,
      Math.max(0, Number(queued.learned.level) || 0),
      now,
    );
    state.battle.bossParty.pet.name = `${member.classId}'s ${state.battle.bossParty.pet.name}`;
    state.battle.taoPet = state.battle.bossParty.pet;
    state.taoPetAtlas = taoPetAtlasFor(state.battle.taoPet);
    bossPartyControlledVisual(member, queued.spell, queued.spell.bodyAction ?? "spell", now);
    bossPartyCastSfx(member, queued.spell.id, 0.38, 160);
    bossPartyLevelMagicSkill(member, queued.spell, queued.learned, now);
    playTaoPetAppearSfx({ volume: bossPartySfxVolume(member, 0.4, 0.18), throttleMs: 250, pet: state.battle.taoPet });
    pushBattleLog(`${member.classId} summons ${state.battle.bossParty.pet.name}.`);
    return true;
  }
  if (queued.spell.id === "SoulShield" || queued.spell.id === "BlessedArmour") {
    return bossPartyCastDefenceBuff(member, queued, now);
  }
  if (queued.spell.id === "UltimateEnhancer") {
    return bossPartyCastUltimateEnhancer(member, queued, now);
  }
  return false;
}

function bossPartyAutoSpells(member) {
  return combatAutoCastSpells(member.classId)
    .map((spell) => ({ spell, learned: bossPartyLearned(member, spell.id) }))
    .filter(({ learned }) => learned?.autoCast)
    .sort((a, b) => autoCastPriorityForClass(member.classId, a.spell) - autoCastPriorityForClass(member.classId, b.spell))
    .slice(0, Math.max(1, autoCastSlotLimit()))
    .map(({ spell }) => spell);
}

function bossPartyActiveFight() {
  return Boolean(state.battle.bossParty?.active);
}

function resetBossPartySoloRecoveryState() {
  state.battle.healAmount = 0;
  state.battle.healTickAt = 0;
  state.battle.potHealthAmount = 0;
  state.battle.potManaAmount = 0;
  state.battle.potTickAt = 0;
  state.battle.pendingHeal = null;
}

function refreshBossPartyMemberMagicSettings(member) {
  const characterLearned = state.characters[member.classId]?.magic?.learned;
  if (!characterLearned || !member.magic?.learned) return;
  for (const [spellId, learned] of Object.entries(member.magic.learned)) {
    const saved = characterLearned[spellId];
    if (saved) learned.autoCast = Boolean(saved.autoCast);
  }
}

function syncBossPartyMemberAutoCastFromState(classId = state.battle.combatClass) {
  const party = state.battle.bossParty;
  if (!party?.active || !classId) return;
  const member = party.members.find((candidate) => candidate.classId === classId);
  if (!member?.magic?.learned) return;
  for (const [spellId, memberLearned] of Object.entries(member.magic.learned)) {
    const live = state.magic.learned[spellId];
    if (live) memberLearned.autoCast = Boolean(live.autoCast);
    const saved = state.characters[classId]?.magic?.learned?.[spellId];
    if (saved) saved.autoCast = Boolean(live?.autoCast ?? memberLearned.autoCast);
  }
}

function loadBossPartyMemberMagicIntoState(member) {
  if (!member?.magic) return;
  state.magic = cloneMagicState(member.magic);
  removeRetiredTestingDefaultMagic(member.classId, state.magic);
  normalizeAutoCastSpellsForClass(member.classId);
}

function bossPartyLearned(member, spellId) {
  const learned = member?.magic?.learned?.[spellId] ?? null;
  if (!learned) return null;
  if (!state.battle.bossParty?.active) return learned;
  if (member.classId === state.battle.combatClass) {
    const live = state.magic.learned[spellId];
    if (live) {
      learned.autoCast = Boolean(live.autoCast);
      const effectiveReady = Math.max(
        Math.max(0, Number(learned.castReadyAt) || 0),
        Math.max(0, Number(live.castReadyAt) || 0),
      );
      learned.castReadyAt = effectiveReady;
      live.castReadyAt = effectiveReady;
    }
  } else {
    const saved = state.characters[member.classId]?.magic?.learned?.[spellId];
    if (saved) learned.autoCast = Boolean(saved.autoCast);
  }
  return learned;
}

// Member-aware port of levelMagicSkill: trains a party member's own spell using
// its character level/experience so spells and passives progress in boss fights
// exactly like solo. Progress lives on member.magic and persists back to the
// character via syncBossPartyMembersToCharacters at the end of the fight.
function bossPartyLevelMagicSkill(member, spell, learned, now) {
  if (!member || !spell || !learned || learned.level >= 3) return false;
  if ((Number(member.game?.progress?.level) || 1) < spellLevelRequirement(spell, learned.level)) return false;
  const need = spellExperienceTarget(spell, learned.level);
  if (!need) return false;
  learned.experience += randomInt(1, 3);
  if (learned.experience >= need) {
    learned.level += 1;
    learned.experience = 0;
    pushBattleLog(`${member.classId}'s ${spell.label} reached level ${learned.level}.`);
    if (member.classId === bossPartyControlledClassId()) addLootNotice(`${spell.label} Lv ${learned.level}`, "level");
    // Passives that modify stats need the member's combat stats recomputed.
    if (spell.id === "Fencing" || spell.id === "SpiritSword" || spell.id === "Slaying") bossPartyRefreshMemberStats(member);
    battlePanelSignature = "";
    combatSkillBarSignature = "";
  }
  return true;
}

function bossPartyLevelPassiveWeaponMagic(member, now) {
  if (member.classId === "Warrior") {
    const spell = warriorSpellById("Fencing");
    const fencing = bossPartyLearned(member, "Fencing");
    if (spell && fencing) bossPartyLevelMagicSkill(member, spell, fencing, now);
    return;
  }
  if (member.classId === "Taoist") {
    const spell = taoistSpellById("SpiritSword");
    const spiritSword = bossPartyLearned(member, "SpiritSword");
    if (spell && spiritSword) bossPartyLevelMagicSkill(member, spell, spiritSword, now);
  }
}

// Recompute a member's derived combat stats (so a passive that levelled mid-fight
// takes effect immediately) while preserving its current HP/MP.
function bossPartyRefreshMemberStats(member) {
  const stats = characterSnapshotTotalStats(member.classId, {
    game: member.game,
    inventory: member.inventory,
    magic: member.magic,
    battle: { playerHp: member.hp, playerMp: member.mp },
  });
  const curHp = member.hp;
  const curMp = member.mp;
  Object.assign(member, stats);
  member.hp = Math.max(0, Math.min(member.maxHp, curHp));
  member.mp = Math.max(0, Math.min(member.maxMp, curMp));
}

function bossPartyEffectiveAttackSpeed(member, now) {
  return (Number(member.attackSpeed) || 0) + (now < (member.furyUntil ?? 0) ? Number(member.furyBonus) || 0 : 0);
}

function partyBossEffects() {
  if (!state.battle.bossParty) return [];
  if (!Array.isArray(state.battle.bossParty.effects)) state.battle.bossParty.effects = [];
  return state.battle.bossParty.effects;
}

function bossPartyGroundEffectActive(spellId, now) {
  const onGround = (state.battle.groundSpellEffects ?? []).some(
    (effect) => effect.spellId === spellId && now < effect.expiresAt,
  );
  if (onGround) return true;
  return partyBossEffects().some((effect) => effect.spellId === spellId && now < effect.expiresAt);
}

function bossPartyFireWallHasUsefulTarget(spell, member, now) {
  if (groupDungeonSwarmSideActive()) return canUseGroupDungeonSwarmFireWall(spell, member, now);
  return !bossPartyGroundEffectActive("FireWall", now);
}

function updateBossPartyEffects(now) {
  const enemy = state.battle.enemy;
  const effects = partyBossEffects();
  for (const effect of effects) {
    if (now >= effect.expiresAt || enemy.hp <= 0) continue;
    let guard = 0;
    while (now >= effect.nextTickAt && guard < 4) {
      guard += 1;
      effect.nextTickAt += 2000;
      const damage = applyWizardMagicDefence(effect.value, enemy);
      reduceEnemyHp(enemy, damage);
      syncBattleEnemyHpToSwarm();
      bossPartyShowEnemyDamage(effect.casterClassId, damage, now);
      pushBattleLog(`${effect.spellId} burns ${enemy.name} for ${damage}.`);
      playSpellSfx(effect.spellId, "impact", { volume: 0.35, throttleMs: 180 });
      maybeKillGroupDungeonSwarmEnemy(enemy, now);
      if (enemy.hp <= 0) break;
    }
  }
  state.battle.bossParty.effects = effects.filter((effect) => now < effect.expiresAt);
}

function partyBossImpacts() {
  if (!state.battle.bossParty) return [];
  if (!Array.isArray(state.battle.bossParty.impacts)) state.battle.bossParty.impacts = [];
  return state.battle.bossParty.impacts;
}

function partyBossHealFx() {
  if (!state.battle.bossParty) return [];
  if (!Array.isArray(state.battle.bossParty.healFx)) state.battle.bossParty.healFx = [];
  return state.battle.bossParty.healFx;
}

// Crystal's Healing plays two effects: the cast swirl on the caster (Magic frame
// 200, handled by bossPartyControlledVisual) and a separate "restore" burst on the
// healed target (Magic frame 370) that lands -- with its own sound -- after the
// cast delay. We queue that target-side effect here.
function bossPartyQueueHealFx(member, target, spell, now) {
  if (!target) return;
  const fx = partyBossHealFx();
  fx.push({
    target,
    casterClassId: member.classId,
    soundSpellId: spell.id,
    startAt: now + (Number(spell.impactDelayMs) || CRYSTAL_HEAL_APPLY_DELAY_MS),
    soundPlayed: false,
  });
  state.battle.bossParty.healFx = fx.slice(-6);
}

function bossPartyHealFxAtlasDurationMs(atlas) {
  if (!atlas?.layers?.length) return 800;
  return Math.max(0, ...atlas.layers.map((layer) => (layer.delayMs ?? 0) + layer.frames.length * layer.interval));
}

function updateBossPartyHealFx(now) {
  const fx = partyBossHealFx();
  if (!fx.length) return;
  const duration = bossPartyHealFxAtlasDurationMs(state.healingRestoreAtlas);
  const remaining = [];
  for (const entry of fx) {
    if (now < entry.startAt) {
      remaining.push(entry);
      continue;
    }
    if (!entry.soundPlayed) {
      entry.soundPlayed = true;
      const caster = state.battle.bossParty?.members?.find((m) => m.classId === entry.casterClassId);
      const params = caster ? bossPartySfxParams(caster, 0.46, 160) : { volume: 0.46, throttleMs: 160 };
      playSpellSfx(entry.soundSpellId, "impact", params) || playSpellSfx(entry.soundSpellId, "cast", params);
    }
    if (now - entry.startAt <= duration) remaining.push(entry);
  }
  state.battle.bossParty.healFx = remaining;
}

function defenceBuffFxList() {
  if (!Array.isArray(state.battle.defenceBuffFx)) state.battle.defenceBuffFx = [];
  return state.battle.defenceBuffFx;
}

function defenceBuffImpactAtlas(spellId) {
  if (spellId === "UltimateEnhancer") {
    return state.taoistSpellAtlases?.UltimateEnhancer ?? null;
  }
  return state.taoistDefenceBuffImpactAtlases?.[spellId] ?? null;
}

function defenceBuffFxAtlasDurationMs(atlas) {
  if (!atlas?.layers?.length) return 1200;
  return Math.max(0, ...atlas.layers.map((layer) => (layer.delayMs ?? 0) + layer.frames.length * layer.interval));
}

function queueDefenceBuffImpactFx(spell, anchor, now, options = {}) {
  if (!spell?.id || !defenceBuffImpactAtlas(spell.id)) return;
  const fx = defenceBuffFxList();
  fx.push({
    spellId: spell.id,
    anchor,
    worldX: options.worldX ?? null,
    memberClassId: options.memberClassId ?? null,
    petFx: Boolean(options.petFx),
    startAt: now,
    soundPlayed: Boolean(options.soundPlayed),
  });
  state.battle.defenceBuffFx = fx.slice(-16);
}

function ultimateEnhancerImpactFxOptions(entity) {
  if (!entity) return { anchor: "player" };
  if (entity === state.battle.bossParty?.pet || entity === state.battle.taoPet) {
    return { anchor: "pet", petFx: true };
  }
  if (entity.classId && state.battle.bossParty?.active) {
    return { memberClassId: entity.classId };
  }
  return { anchor: "player" };
}

function queueUltimateEnhancerImpactFx(spell, applied, now = performance.now(), options = {}) {
  if (!spell?.id || !defenceBuffImpactAtlas(spell.id) || suppressSimulationRender) return;
  const entities = applied?.results?.map((entry) => entry.entity) ?? [];
  let soundPlayed = Boolean(options.soundPlayed);
  for (const entity of entities) {
    if (!entity || entity.hp <= 0) continue;
    const impactOptions = ultimateEnhancerImpactFxOptions(entity);
    queueDefenceBuffImpactFx(spell, impactOptions.anchor ?? null, now, {
      ...impactOptions,
      soundPlayed,
    });
    soundPlayed = true;
  }
}

function queueDefenceBuffImpactTargets(spell, now, options = {}) {
  if (spell?.id === "SoulShield" || spell?.id === "BlessedArmour") {
    queueDefenceBuffImpactFx(spell, "player", now, {
      worldX: options.worldX ?? null,
      soundPlayed: Boolean(options.soundPlayed),
    });
    return;
  }
  queueDefenceBuffImpactFx(spell, "player", now, options);
  const pet = options.pet ?? state.battle.taoPet ?? state.battle.bossParty?.pet;
  if (pet?.active) queueDefenceBuffImpactFx(spell, "pet", now, { soundPlayed: true, petFx: true });
}

function updateDefenceBuffFx(now) {
  const fx = defenceBuffFxList();
  if (!fx.length) return;
  const remaining = [];
  for (const entry of fx) {
    const atlas = defenceBuffImpactAtlas(entry.spellId);
    const duration = defenceBuffFxAtlasDurationMs(atlas);
    if (now < entry.startAt) {
      remaining.push(entry);
      continue;
    }
    if (!entry.soundPlayed) {
      entry.soundPlayed = true;
      playSpellSfx(entry.spellId, "impact", { volume: 0.46, throttleMs: 120 })
        || playSpellSfx(entry.spellId, "cast", { volume: 0.42, throttleMs: 120 });
    }
    if (now - entry.startAt <= duration) remaining.push(entry);
  }
  state.battle.defenceBuffFx = remaining;
}

// Mirrors solo `castTaoistPoisoning` + `updatePendingPoison`: cast SFX on use,
// impact SFX when the poison actually lands on the boss after the Crystal delay.
function bossPartyQueuePoisonApply(member, poison, learned, item, now) {
  const party = state.battle.bossParty;
  if (!party) return;
  party.pendingPoison = {
    at: now + CRYSTAL_POISON_APPLY_DELAY_MS,
    memberClassId: member.classId,
    spellId: poison.id,
    value: rollTaoistPoisonPower(poison, learned, member),
    kind: poisonItemKind(item),
    itemName: item.name,
  };
  bossPartyControlledVisual(member, poison, poison.bodyAction ?? "spell", now);
  bossPartyCastSfx(member, poison.id, 0.38, 160);
  pushBattleLog(`${member.classId} casts ${poison.label} with ${item.name}.`);
}

function updateBossPartyPendingPoison(now) {
  const party = state.battle.bossParty;
  const pending = party?.pendingPoison;
  const enemy = state.battle.enemy;
  if (!pending || now < pending.at || !enemy || enemy.hp <= 0) return;
  party.pendingPoison = null;
  const spell = taoistCombatSpell(pending.spellId);
  const member = party.members.find((entry) => entry.classId === pending.memberClassId);
  const learned = member ? bossPartyLearned(member, spell.id) : null;
  const level = Math.max(0, Math.min(3, Math.trunc(Number(learned?.level) || 0)));
  const value = Math.max(0, Math.trunc(Number(pending.value) || 0));
  const durationTicks = Math.max(1, value * 2 + (level + 1) * 7);
  const poisonKind = pending.kind === "green" ? "green" : "yellow";
  const poisonAttack = Math.max(0, Math.trunc(Number(member?.poisonAttack) || 0));
  const tickValue = poisonKind === "green"
    ? Math.max(1, Math.floor(value / 15) + level + 1 + (poisonAttack > 0 ? randomInt(0, poisonAttack - 1) : 0))
    : 0;
  const applied = applyEnemyPoison(enemy, {
    kind: poisonKind,
    value: tickValue,
    ticksRemaining: durationTicks,
  }, now);
  if (member && learned) bossPartyLevelMagicSkill(member, spell, learned, now);
  const sfx = bossPartySfxParamsForClass(pending.memberClassId, 0.5, 0);
  playSpellSfx(spell.id, "impact", sfx) || playSpellSfx(spell.id, "cast", sfx);
  const label = poisonKind === "green" ? "Green Poison" : "Yellow Poison";
  addCombatText("enemy", poisonKind === "green" ? "Poison" : "Weaken", poisonKind === "green" ? "poison" : "debuff", now);
  pushBattleLog(applied ? `${label} affects ${enemy.name}.` : `${enemy.name} resists the weaker ${label}.`);
}

// Projectile/targeted spells (Wizard nukes, SoulFireBall) land their damage when
// the projectile reaches the boss, matching the solo `pendingImpact` timing
// instead of resolving instantly. Hit/damage are rolled at cast time so stats
// are locked in; only the application is deferred.
function bossPartyQueueImpact(member, spell, label, atlas, now, rollDamageFn) {
  const enemy = state.battle.enemy;
  if (!enemy) return;
  const hit = rollMagicHit(enemy);
  const damage = hit ? Math.max(0, Math.trunc(Number(rollDamageFn()) || 0)) : 0;
  partyBossImpacts().push({
    at: now + wizardImpactDelay(spell, atlas),
    spellId: spell.id,
    label,
    damage,
    hit: hit && damage > 0,
    casterClassId: member.classId,
  });
}

function updateBossPartyImpacts(now) {
  const enemy = state.battle.enemy;
  const impacts = partyBossImpacts();
  if (!impacts.length) return;
  const remaining = [];
  for (const impact of impacts) {
    if (now < impact.at) {
      remaining.push(impact);
      continue;
    }
    if (impact.bang) {
      const caster = state.battle.bossParty?.members.find((m) => m.classId === impact.casterClassId);
      const spell = combatAttackSpell(impact.spellId);
      const learned = caster ? bossPartyLearned(caster, impact.spellId) : null;
      if (spell && state.battle.enemy?.hp > 0 && state.battle.enemyRevealed) {
        applyWizardBangSpellImpact(spell, impact, now, {
          learned,
          partyMember: caster,
          sfx: bossPartySfxParamsForClass(impact.casterClassId, 0.42, 80),
        });
      }
      continue;
    }
    bossPartySpellStrikeSfx(impact.spellId, impact.casterClassId);
    const canApply = enemy && enemy.hp > 0 && state.battle.enemyRevealed;
    if (!canApply) continue;
    if (!impact.hit || impact.damage <= 0) {
      bossPartyShowEnemyMiss(impact.casterClassId, now);
      pushBattleLog(`${impact.label} misses ${enemy.name}.`);
      continue;
    }
    reduceEnemyHp(enemy, impact.damage);
    syncBattleEnemyHpToSwarm();
    strikeGroupDungeonSwarmEnemy(enemy, now);
    playMonsterSfx("flinch", enemy, bossPartySfxParamsForClass(impact.casterClassId, 0.42, 80));
    bossPartyShowEnemyDamage(impact.casterClassId, impact.damage, now);
    pushBattleLog(`${impact.label} hits ${enemy.name} for ${impact.damage}.`);
    maybeKillGroupDungeonSwarmEnemy(enemy, now);
    const caster = state.battle.bossParty?.members.find((m) => m.classId === impact.casterClassId);
    const spell = combatAttackSpell(impact.spellId);
    const learned = caster ? bossPartyLearned(caster, impact.spellId) : null;
    if (impact.spellId === "FrostCrunch" && impact.damage > 0 && caster && learned) {
      applyFrostCrunchEffects(enemy, learned, caster, now);
    }
    if (caster && spell && learned) bossPartyLevelMagicSkill(caster, spell, learned, now);
  }
  state.battle.bossParty.impacts = remaining;
}

function partyPetCanTank() {
  const pet = state.battle.bossParty?.pet;
  return Boolean(pet?.active) && (pet.hp ?? 0) > 0 && pet.spellId !== "SummonShinsu";
}

function bossPartyActivePet() {
  const pet = state.battle.bossParty?.pet;
  return pet?.active && (pet.hp ?? 0) > 0 ? pet : null;
}

function bossPartyFrontTarget() {
  if (partyPetCanTank()) return state.battle.bossParty.pet;
  return BOSS_PARTY_ORDER
    .map((classId) => state.battle.bossParty?.members.find((member) => member.classId === classId && member.alive && member.hp > 0))
    .find(Boolean) ?? null;
}

function bossPartyAliveMembersOrdered(party = state.battle.bossParty) {
  return BOSS_PARTY_ORDER
    .map((classId) => party?.members?.find((member) => member.classId === classId && member.alive && member.hp > 0))
    .filter(Boolean);
}

function bossPartyAoeRangedTarget() {
  const alive = bossPartyAliveMembersOrdered();
  if (alive.length === 3) return alive[1];
  return bossPartyFrontTarget();
}

// Heal whoever in the party is most hurt (below 50%), not just the front
// tank: the pet, the Warrior, the casting Taoist itself, or the Wizard behind.
// Mirrors the solo Taoist, which heals itself/its pet rather than only a tank.
function bossPartyHealTarget(manual = false) {
  const party = state.battle.bossParty;
  if (!party) return null;
  const candidates = [];
  const pet = bossPartyActivePet();
  if (pet) candidates.push(pet);
  for (const member of party.members ?? []) {
    if (member.alive && member.hp > 0) candidates.push(member);
  }
  let best = null;
  let bestRatio = Infinity;
  for (const target of candidates) {
    const maxHp = Math.max(1, Number(target.maxHp) || 0);
    if (target.hp >= maxHp) continue;
    // Skip if a heal already in flight will close the gap.
    if (Math.max(0, Number(target.healAmount) || 0) >= maxHp - target.hp) continue;
    const ratio = target.hp / maxHp;
    if (!manual && ratio >= AUTO_POTION_THRESHOLD) continue;
    if (ratio < bestRatio) {
      bestRatio = ratio;
      best = target;
    }
  }
  return best;
}

function isEvilCentipedeEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "evilCentipede" || enemy?.crystalName === "EvilCentipede";
}

function isEvilSnakeEnemy(enemy = state.battle.enemy) {
  return enemy?.id === EVIL_SNAKE_ENEMY_ID || enemy?.crystalName === "EvilSnake";
}

function isZumaTaurusEnemy(enemy = state.battle.enemy) {
  return enemy?.id === ZUMA_TAURUS_ENEMY_ID || enemy?.crystalName === "ZumaTaurus";
}

function isBoneLordEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "boneLord" || enemy?.id === BONE_LORD_ENEMY_ID || enemy?.crystalName === "BoneLord";
}

function isPrajnaGuardEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "prajnaGuard"
    || PRAJNA_GUARD_ENEMY_IDS.has(enemy?.id)
    || enemy?.crystalName === "RightGuard"
    || enemy?.crystalName === "LeftGuard";
}

function isYimoogiEnemy(enemy = state.battle.enemy) {
  return enemy?.id === YIMOOGI_ENEMY_ID || enemy?.crystalName === "Yimoogi";
}

function isMinotaurKingEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "minotaurKing"
    || enemy?.id === MINOTAUR_KING_ENEMY_ID
    || enemy?.crystalName === "MinotaurKing";
}

function isKingHogEnemy(enemy = state.battle.enemy) {
  return enemy?.id === KING_HOG_ENEMY_ID || enemy?.crystalName === "KingHog";
}


function isKingScorpionEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "kingScorpion" || enemy?.crystalName === "KingScorpion";
}

function isScalyBeastEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "scalyBeast"
    || enemy?.id === SCALY_BEAST_ENEMY_ID
    || enemy?.crystalName === "ScalyBeast";
}

function isDarkDevilEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "darkDevil"
    || enemy?.id === DARK_DEVIL_ENEMY_ID
    || enemy?.crystalName === "DarkDevil";
}

function darkDevilBurstTargets(enemy = state.battle.enemy) {
  if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) return [];
  const targets = [];
  const consider = (kind, entity, logName) => {
    if (!entity || (entity.hp ?? 0) <= 0) return;
    targets.push({
      kind,
      entity,
      logName,
      stats: defenceStatsForEntity(entity),
    });
  };
  if (bossPartyActiveFight()) {
    const party = state.battle.bossParty;
    if (party?.pet?.active) consider("pet", party.pet, party.pet.name);
    for (const member of party?.members ?? []) {
      if (!member.alive || (member.hp ?? 0) <= 0) continue;
      consider("member", member, member.classId);
    }
    return targets;
  }
  const battle = state.battle;
  if (taoistPetCanTank() && battle.taoPet?.active && (battle.taoPet.hp ?? 0) > 0) {
    consider("pet", battle.taoPet, battle.taoPet.name);
  }
  if ((battle.player?.hp ?? 0) > 0) {
    consider("player", battle.player, battle.combatClass);
  }
  return targets;
}

function darkDevilMeleeRange(enemy = state.battle.enemy) {
  const tiles = Math.max(1, Math.trunc(Number(enemy?.darkDevilMeleeRangeTiles) || 1));
  return bossPartyActiveFight() ? tiles * LANE_TILE_PX : LANE.enemyRange;
}

function darkDevilRangeReady(enemy = state.battle.enemy, now = performance.now()) {
  return now >= (Number(enemy?._darkDevilRangeReadyAt) || 0);
}

function scheduleDarkDevilRangeCooldown(enemy = state.battle.enemy, now = performance.now()) {
  const enraged = enemyEnrageActive(enemy, now);
  const minMs = Math.max(
    0,
    Math.trunc(Number(enraged ? enemy.darkDevilEnrageRangeCooldownMinMs : enemy.darkDevilRangeCooldownMinMs) || (enraged ? 800 : 2000)),
  );
  const maxMs = Math.max(
    minMs,
    Math.trunc(Number(enraged ? enemy.darkDevilEnrageRangeCooldownMaxMs : enemy.darkDevilRangeCooldownMaxMs) || (enraged ? 1800 : 5000)),
  );
  enemy._darkDevilRangeReadyAt = now + minMs + Math.floor(Math.random() * (maxMs - minMs + 1));
}

function darkDevilTargetDistance() {
  if (bossPartyActiveFight()) {
    const target = bossPartyFrontTarget();
    return target ? bossPartyTargetEnemyDistance(target) : Infinity;
  }
  return enemyTargetDistance();
}

function darkDevilUsesRangeAttack(enemy = state.battle.enemy, now = performance.now()) {
  if (enemyEnrageActive(enemy, now) && enemy.enrageAlwaysRanged) return true;
  return darkDevilRangeReady(enemy, now);
}

function canDarkDevilAttack() {
  const battle = state.battle;
  if (battle.phase !== "engaged" || !battle.enemyRevealed || !battle.enemy?.hp) return false;
  if (enemyFrozenActive(battle.enemy)) return false;
  if (!battle.enemyAggro) return false;
  const enemy = battle.enemy;
  if (darkDevilUsesRangeAttack(enemy)) {
    return darkDevilBurstTargets(enemy).length > 0;
  }
  return darkDevilTargetDistance() <= darkDevilMeleeRange(enemy);
}

function resolveDarkDevilBurstTarget(enemy, target, now, offsetIndex = 0) {
  const multiplier = Math.max(1, Number(enemy.darkDevilRangeDamageMultiplier) || 3);
  const boosted = { ...enemy, dc: scaleStatRange(enemy.dc, multiplier) };
  resolveSplashStrikeTarget(boosted, target, now, offsetIndex, {
    defenceType: enemy.rangedAttackDefenceType || "MACAgility",
    ranged: true,
  });
}

function beginDarkDevilAttack(now) {
  if (state.battle.pendingEnemyStrike) return false;
  const enemy = state.battle.enemy;
  if (!canDarkDevilAttack()) return false;

  if (darkDevilUsesRangeAttack(enemy, now)) {
    scheduleDarkDevilRangeCooldown(enemy, now);
    const startedAt = now;
    const moveDurationMs = Math.max(0, Math.trunc(Number(enemy.attackImpactDelayMs) || 500));
    const impactAt = startedAt + moveDurationMs;
    const projectile = state.enemy.atlas?.projectile;
    state.battle.pendingEnemyStrike = {
      kind: "darkDevilBurst",
      at: impactAt,
      startedAt,
      ranged: true,
      moveDurationMs,
      vfxUntil: Math.max(impactAt, enemyProjectileVfxUntil(startedAt, projectile)),
    };
    setEnemyAction(enemy.atlas?.actions?.attackRange1 ? "attackRange1" : "attack1", true, now);
    playMonsterSfx("attack", enemy, { force: true, throttleMs: 0 });
    return true;
  }

  const target = bossPartyActiveFight() ? bossPartyFrontTarget() : null;
  if (bossPartyActiveFight()) {
    if (!target) return false;
    setEnemyAction("attack1", true, now);
    playMonsterSfx("attack", enemy);
    const { hit, damage } = resolveIncomingEnemyAttack(enemy, defenceTargetForIncomingAttack(target));
    if (!hit) {
      addCombatText(target.classId === bossPartyControlledClassId() ? "player" : "enemy", "Miss", "miss", now);
      pushBattleLog(`${enemy.name} misses ${target.name}.`);
      return true;
    }
    target.hp = Math.max(0, target.hp - damage);
    if (target === state.battle.bossParty.pet) {
      setTaoPetAction("struck", true, now);
      if (target.hp <= 0) bossPartyMarkPetDead(now);
    } else if (target.classId === bossPartyControlledClassId()) {
      setPlayerAction("struck", now + 250, true);
      addCombatText("player", damage, "enemyDamage", now);
      playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
    } else {
      target.visualAction = "struck";
      target.visualFrame = 0;
      target.visualOneShot = true;
      target.visualLastTick = now;
      playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
    }
    pushBattleLog(`${enemy.name} hits ${target.name} for ${damage}.`);
    if (target !== state.battle.bossParty.pet && target.hp <= 0) bossPartyMarkMemberDead(target, now);
    return true;
  }

  return enemyAttack(now);
}

function isFlamingMutantEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "flamingMutant"
    || enemy?.id === FLAMING_MUTANT_ENEMY_ID
    || enemy?.crystalName === "FlamingMutant";
}

function isMassBurstEnemy(enemy = state.battle.enemy) {
  return enemy?.attackMode === "massBurst"
    || enemy?.id === MANECTRIC_KING_ENEMY_ID
    || enemy?.id === FLAME_QUEEN_ENEMY_ID
    || enemy?.crystalName === "ManectricKing"
    || enemy?.crystalName === "FlameQueen";
}

function massBurstStyle(enemy = state.battle.enemy) {
  if (enemy?.massBurstStyle) return enemy.massBurstStyle;
  if (enemy?.crystalName === "ManectricKing") return "line";
  if (enemy?.crystalName === "FlameQueen") return "boneLord";
  return "boneLord";
}

function massBurstHpRatio(enemy = state.battle.enemy) {
  const ratio = Number(enemy?.massBurstHpRatio);
  return Number.isFinite(ratio) ? Math.max(0, Math.min(1, ratio)) : 0.2;
}

function massBurstTiles(enemy = state.battle.enemy) {
  return Math.max(1, Math.trunc(Number(enemy?.massBurstTiles) || 7));
}

function shouldMassBurstNow(enemy = state.battle.enemy, now = performance.now()) {
  if (!enemy || enemy.maxHp <= 0) return false;
  if (!enemy.alwaysAoe && (enemy.hp / enemy.maxHp) > massBurstHpRatio(enemy)) return false;
  return now >= (Number(enemy._massBurstCooldownUntil) || 0);
}

function scheduleMassBurstCooldown(enemy = state.battle.enemy, now = performance.now()) {
  if (!enemy) return;
  if (enemy.alwaysAoe) {
    enemy._massBurstCooldownUntil = now + 1000;
    return;
  }
  const span = MASS_BURST_COOLDOWN_MAX_MS - MASS_BURST_COOLDOWN_MIN_MS;
  enemy._massBurstCooldownUntil = now + MASS_BURST_COOLDOWN_MIN_MS + Math.floor(Math.random() * (span + 1));
}

function enemyHasRangedMeleeAttack(enemy = state.battle.enemy) {
  if (isMassBurstEnemy(enemy) && enemy.alwaysAoe) return false;
  if (isMassBurstEnemy(enemy) && massBurstStyle(enemy) === "boneLord" && !shouldMassBurstNow(enemy)) {
    return true;
  }
  return isBoneLordEnemy(enemy) || isPrajnaGuardEnemy(enemy) || isMinotaurKingEnemy(enemy) || isFlamingMutantEnemy(enemy);
}

function minotaurKingSplashRadiusPx(enemy = state.battle.enemy) {
  const tiles = Math.max(1, Math.trunc(Number(enemy?.aoeSplashTiles) || 3));
  return tiles * LANE_TILE_PX;
}

function minotaurKingAoeInterval(enemy = state.battle.enemy) {
  return Math.max(1, Math.trunc(Number(enemy?.aoeSplashEvery) || MINOTAUR_KING_AOE_EVERY_N_ATTACKS));
}

function minotaurKingAttackCount(enemy = state.battle.enemy) {
  return Math.max(0, Math.trunc(Number(enemy?.minotaurKingAttackCount) || 0));
}

function beginMinotaurKingAttack(enemy = state.battle.enemy) {
  if (!enemy) return 0;
  enemy.minotaurKingAttackCount = minotaurKingAttackCount(enemy) + 1;
  return enemy.minotaurKingAttackCount;
}

function minotaurKingAoeChance(enemy = state.battle.enemy) {
  const chance = Number(enemy?.aoeSplashChance);
  return Number.isFinite(chance) ? Math.max(0, Math.min(1, chance)) : 0;
}

function minotaurKingAttackIsAoe(count, enemy = state.battle.enemy) {
  if (count > 0 && count % minotaurKingAoeInterval(enemy) === 0) return true;
  const chance = minotaurKingAoeChance(enemy);
  return chance > 0 && Math.random() < chance;
}

function minotaurKingStrikeUsesAoe(strike = state.battle.pendingEnemyStrike) {
  return Boolean(strike?.aoe);
}

function enemyAttackDamageStat(enemy = state.battle.enemy, options = {}) {
  if ((options.aoe || options.massBurst) && statRange(enemy?.mc)[1] > 0) {
    if (isMinotaurKingEnemy(enemy) || isMassBurstEnemy(enemy) || isFlamingMutantEnemy(enemy)) {
      return enemy.mc;
    }
  }
  if (options.ranged && isKingScorpionEnemy(enemy) && statRange(enemy?.mc)[1] > 0) {
    return enemy.mc;
  }
  if (options.ranged && isFlamingMutantEnemy(enemy) && statRange(enemy?.mc)[1] > 0) {
    return enemy.mc;
  }
  if (isIncarnatedRedThunderZumaEnemy(enemy)) {
    if (options.ranged && enemy.rangedDc) return enemy.rangedDc;
    if (enemy.meleeDc) return enemy.meleeDc;
  }
  return enemy.dc;
}

function minotaurKingSplashTargets(primaryTarget, enemy = state.battle.enemy) {
  if (!primaryTarget) return [];
  const party = state.battle.bossParty;
  if (!party) return [primaryTarget];
  const radiusPx = minotaurKingSplashRadiusPx(enemy);
  const primaryX = Number(primaryTarget.worldX) || 0;
  const targets = [primaryTarget];
  const consider = (entity) => {
    if (!entity || entity === primaryTarget || (entity.hp ?? 0) <= 0) return;
    if (Math.abs((Number(entity.worldX) || 0) - primaryX) > radiusPx) return;
    targets.push(entity);
  };
  consider(party.pet);
  for (const member of party.members ?? []) {
    if (member.alive && member.hp > 0) consider(member);
  }
  return targets;
}

function boneLordAttackRange(enemy = state.battle.enemy) {
  const tiles = Math.max(1, Math.trunc(Number(enemy?.attackRangeTiles) || 7));
  return tiles * LANE_TILE_PX;
}

function boneLordMeleeRange() {
  return bossPartyActiveFight() ? BOSS_PARTY_BOSS_REACH : LANE.enemyRange;
}

function boneLordTargetDistance() {
  if (bossPartyActiveFight()) {
    const target = bossPartyFrontTarget();
    return target ? bossPartyTargetEnemyDistance(target) : Number.POSITIVE_INFINITY;
  }
  return enemyTargetDistance();
}

function boneLordUsesRangedAttack(distancePx = boneLordTargetDistance()) {
  return distancePx > boneLordMeleeRange();
}

function kingScorpionLaneTile(worldX) {
  return Math.round(Number(worldX) / LANE_TILE_PX);
}

function kingScorpionLineTileDistance(enemy = state.battle.enemy) {
  const base = Math.max(1, Math.trunc(Number(enemy?.attackRangeTiles) || KING_SCORPION_LINE_TILES));
  if (!enemyEnrageActive(enemy)) return base;
  const enrageRange = Math.max(base, Math.trunc(Number(enemy?.enrageAttackRangeTiles) || 3));
  const finalStage = normalizeEnemyEnrageStages(enemy).at(-1);
  const finalRange = Math.max(enrageRange, Math.trunc(Number(enemy?.enrageFinalAttackRangeTiles) || enrageRange));
  if (finalStage != null && Number(enemy?.enrageStage) <= finalStage) return finalRange;
  return enrageRange;
}

function kingScorpionLineStepMs(enemy = state.battle.enemy) {
  if (enemyEnrageActive(enemy)) {
    return Math.max(10, Math.trunc(Number(enemy?.enrageLineStepMs) || 25));
  }
  return KING_SCORPION_LINE_STEP_MS;
}

function kingScorpionAttackableTargets() {
  if (bossPartyActiveFight()) {
    const targets = [];
    const pet = bossPartyActivePet();
    if (pet) targets.push({ kind: "pet", entity: pet, worldX: pet.worldX, logName: pet.name });
    for (const member of bossPartyAliveMembersOrdered()) {
      targets.push({ kind: "member", entity: member, worldX: member.worldX, logName: member.classId });
    }
    return targets;
  }
  const battle = state.battle;
  const targets = [];
  if (taoistPetCanTank() && battle.taoPet?.active && (battle.taoPet.hp ?? 0) > 0) {
    targets.push({
      kind: "pet",
      entity: battle.taoPet,
      worldX: Number(battle.taoPet.worldX) || taoistPetSummonWorldX(),
      logName: battle.taoPet.name,
    });
  }
  if ((battle.player?.hp ?? 0) > 0) {
    targets.push({
      kind: "player",
      entity: battle.player,
      worldX: battle.playerX,
      logName: battle.combatClass,
    });
  }
  return targets;
}

function kingScorpionPrimaryTarget() {
  if (bossPartyActiveFight()) {
    const target = bossPartyFrontTarget();
    if (!target) return null;
    return {
      kind: target === state.battle.bossParty?.pet ? "pet" : "member",
      entity: target,
      worldX: target.worldX,
      logName: target.name ?? target.classId,
    };
  }
  const target = enemyAttackTarget();
  if (!target) return null;
  if (target.kind === "pet") {
    const pet = state.battle.taoPet;
    return {
      kind: "pet",
      entity: pet,
      worldX: Number(pet?.worldX) || taoistPetSummonWorldX(),
      logName: pet?.name ?? "Pet",
    };
  }
  return {
    kind: "player",
    entity: state.battle.player,
    worldX: state.battle.playerX,
    logName: state.battle.combatClass,
  };
}

function kingScorpionTargetInAttackRange(targetRef = kingScorpionPrimaryTarget()) {
  if (!targetRef) return false;
  const maxTiles = kingScorpionLineTileDistance();
  const bossTile = kingScorpionLaneTile(state.battle.enemyX);
  const targetTile = kingScorpionLaneTile(targetRef.worldX);
  const tilesAhead = bossTile - targetTile;
  return tilesAhead >= 1 && tilesAhead <= maxTiles;
}

function kingScorpionForwardCellOccupied() {
  const forwardTile = kingScorpionLaneTile(state.battle.enemyX) - 2;
  return kingScorpionAttackableTargets().some((target) => kingScorpionLaneTile(target.worldX) === forwardTile);
}

function kingScorpionLineTargets(lineDistance = kingScorpionLineTileDistance()) {
  const bossTile = kingScorpionLaneTile(state.battle.enemyX);
  const hits = [];
  for (let tile = 1; tile <= lineDistance; tile += 1) {
    const lineTile = bossTile - tile;
    const target = kingScorpionAttackableTargets().find((entry) => kingScorpionLaneTile(entry.worldX) === lineTile);
    if (target) hits.push({ ...target, tile });
  }
  return hits;
}

function kingScorpionMeleeTargets(lineDistance = kingScorpionLineTileDistance()) {
  const primary = kingScorpionPrimaryTarget();
  if (!primary) return [];
  const bossTile = kingScorpionLaneTile(state.battle.enemyX);
  const tile = bossTile - kingScorpionLaneTile(primary.worldX);
  if (tile < 1 || tile > lineDistance) return [];
  return [{ ...primary, tile }];
}

function kingScorpionAttackTargets(ranged, lineDistance = kingScorpionLineTileDistance()) {
  return ranged ? kingScorpionLineTargets(lineDistance) : kingScorpionMeleeTargets(lineDistance);
}

function kingScorpionLineImpactDelay(tileDistance, enemy = state.battle.enemy) {
  const tiles = Math.max(1, Math.trunc(Number(tileDistance) || 1));
  const base = Math.max(0, Math.trunc(Number(enemy?.attackImpactDelayMs) || KING_SCORPION_LINE_IMPACT_MS));
  return tiles * kingScorpionLineStepMs(enemy) + base;
}

function kingScorpionLineProjectileVfxMs(projectile, stretch = KING_SCORPION_LINE_VFX_STRETCH) {
  const frames = Math.max(1, Math.trunc(Number(projectile?.frames?.length) || 1));
  const interval = Math.max(1, Number(projectile?.interval) || 30);
  return frames * interval * Math.max(1, Number(stretch) || 1);
}

function canKingScorpionAttack() {
  const battle = state.battle;
  if (battle.phase !== "engaged" || !battle.enemyRevealed || !battle.enemy?.hp) return false;
  if (enemyFrozenActive(battle.enemy)) return false;
  if (!battle.enemyAggro) return false;
  return kingScorpionTargetInAttackRange();
}

function kingScorpionAttackEnemy(ranged) {
  const enemy = state.battle.enemy;
  if (ranged) {
    return {
      ...enemy,
      attackDefenceType: enemy.rangedAttackDefenceType || "MACAgility",
    };
  }
  return {
    ...enemy,
    attackDefenceType: enemy.attackDefenceType || "ACAgility",
  };
}

function applyKingScorpionLineDamage(targetRef, hit, damage, now) {
  const enemy = state.battle.enemy;
  const logName = targetRef.logName ?? targetRef.entity?.name ?? targetRef.entity?.classId ?? "Target";
  if (!hit) {
    if (targetRef.kind === "member" && targetRef.entity?.classId === bossPartyControlledClassId()) {
      addCombatText("player", "Miss", "miss", now);
    } else if (targetRef.kind === "player") {
      addCombatText("player", "Miss", "miss", now);
    } else if (targetRef.kind === "pet") {
      addCombatText("pet", "Miss", "miss", now);
    } else {
      addCombatText("enemy", "Miss", "miss", now);
    }
    pushBattleLog(`${enemy.name} misses ${logName}.`);
    return;
  }

  const entity = targetRef.entity;
  entity.hp = Math.max(0, entity.hp - damage);
  if (targetRef.kind === "pet") {
    setTaoPetAction("struck", true, now);
    addCombatText("pet", damage, "enemyDamage", now);
    if (entity.hp <= 0) {
      if (bossPartyActiveFight()) bossPartyMarkPetDead(now);
      else markTaoistPetDead(now);
    }
  } else if (targetRef.kind === "member") {
    if (entity.classId === bossPartyControlledClassId()) {
      setPlayerAction("struck", now + 250, true);
      maybeNotifyMagicShieldStruck(null, now);
      addCombatText("player", damage, "enemyDamage", now);
    } else {
      entity.visualAction = "struck";
      entity.visualFrame = 0;
      entity.visualOneShot = true;
      entity.visualLastTick = now;
      notifyWizardMagicShieldStruckOnHit(entity, now);
      addCombatText("enemy", damage, "enemyDamage", now);
    }
    playSfx("player.flinch", bossPartySfxParams(entity, 0.45, 120));
    if (entity.hp <= 0) bossPartyMarkMemberDead(entity, now);
  } else {
    maybeNotifyMagicShieldStruck(null, now);
    setPlayerAction("struck", now + 250, true);
    addCombatText("player", damage, "enemyDamage", now);
    playSfx("player.flinch", { volume: 0.45, throttleMs: 120, force: true });
    if (entity.hp <= 0) {
      if (bossPartyActiveFight()) bossPartyMarkMemberDead(entity, now);
      else {
        finishBattle(now);
        setPlayerAction("die", now);
        playSfx("player.death", { volume: 0.58 });
        pushBattleLog(`${state.battle.combatClass} falls.`);
      }
    }
  }
  pushBattleLog(`${enemy.name} hits ${logName} for ${damage}.`);
}

function resolveKingScorpionLineHit(hit, ranged, now) {
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed || !hit?.entity || (hit.entity.hp ?? 0) <= 0) return;
  const attackEnemy = kingScorpionAttackEnemy(ranged);
  const { hit: didHit, damage } = resolveIncomingEnemyAttack(
    attackEnemy,
    defenceTargetForIncomingAttack(hit.entity),
    ranged ? { ranged: true } : {},
  );
  applyKingScorpionLineDamage(hit, didHit, damage, now);
}

function beginKingScorpionAttack(now) {
  if (state.battle.pendingEnemyStrike) return false;
  if (!canKingScorpionAttack()) return false;
  const enemy = state.battle.enemy;
  const enraged = enemyEnrageActive(enemy, now);
  const ranged = (enraged && enemy.enrageAlwaysRanged)
    || kingScorpionForwardCellOccupied()
    || randomInt(0, 4) === 0;
  const lineTargets = kingScorpionAttackTargets(ranged);
  const lineTiles = kingScorpionLineTileDistance(enemy);
  const animAction = ranged && state.enemy.atlas?.actions?.attackRange1 ? "attackRange1" : "attack1";
  const clip = state.enemy.atlas?.actions?.[animAction];
  const animMs = Math.max(300, (clip?.frames?.length ?? 6) * (clip?.interval ?? 100));
  const projectile = ranged ? state.enemy.atlas?.projectile : null;
  const projectileVfxMs = ranged ? kingScorpionLineProjectileVfxMs(projectile) : 0;
  const lastHitDelay = lineTargets.length
    ? Math.max(...lineTargets.map((target) => kingScorpionLineImpactDelay(target.tile, enemy)))
    : 0;
  state.battle.pendingEnemyStrike = {
    kind: "kingScorpionLine",
    startedAt: now,
    ranged,
    lineTiles,
    hits: lineTargets.map((target) => ({
      kind: target.kind,
      entity: target.entity,
      tile: target.tile,
      logName: target.logName,
      at: now + kingScorpionLineImpactDelay(target.tile),
      resolved: false,
    })),
    vfxUntil: now + Math.max(lastHitDelay, ranged ? projectileVfxMs : animMs),
  };
  setEnemyAction(animAction, true, now);
  playMonsterSfx(enemyAttackSfxKind(enemy, ranged), enemy, { force: true, throttleMs: 0 });
  return true;
}

function bossSplashRadiusPx(enemy = state.battle.enemy, tilesField = "aoeSplashTiles", fallbackTiles = 2) {
  const tiles = Math.max(1, Math.trunc(Number(enemy?.[tilesField]) || fallbackTiles));
  return tiles * LANE_TILE_PX;
}

function splashTargetsNearEnemy(enemy = state.battle.enemy, options = {}) {
  if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) return [];
  const radiusPx = bossSplashRadiusPx(enemy, options.tilesField, options.fallbackTiles ?? 2);
  const centerX = Number(state.battle.enemyX) || 0;
  const targets = [];
  const consider = (kind, entity, logName) => {
    if (!entity || (entity.hp ?? 0) <= 0) return;
    const worldX = Number(entity.worldX ?? state.battle.playerX);
    if (Math.abs(centerX - worldX) > radiusPx) return;
    targets.push({
      kind,
      entity,
      logName,
      stats: defenceStatsForEntity(entity),
    });
  };
  if (bossPartyActiveFight()) {
    const party = state.battle.bossParty;
    if (party?.pet?.active) consider("pet", party.pet, party.pet.name);
    for (const member of party?.members ?? []) {
      if (!member.alive || (member.hp ?? 0) <= 0) continue;
      consider("member", member, member.classId);
    }
    return targets;
  }
  const battle = state.battle;
  if (taoistPetCanTank() && battle.taoPet?.active && (battle.taoPet.hp ?? 0) > 0) {
    consider("pet", battle.taoPet, battle.taoPet.name);
  }
  if ((battle.player?.hp ?? 0) > 0 && Math.abs(centerX - Number(battle.playerX)) <= radiusPx) {
    consider("player", battle.player, battle.combatClass);
  }
  return targets;
}

function massBurstTargetsInRange(enemy = state.battle.enemy) {
  const range = massBurstTiles(enemy) * LANE_TILE_PX;
  const centerX = Number(state.battle.enemyX) || 0;
  const targets = [];
  const consider = (kind, entity, logName) => {
    if (!entity || (entity.hp ?? 0) <= 0) return;
    const worldX = Number(entity.worldX ?? state.battle.playerX);
    if (Math.abs(centerX - worldX) > range) return;
    targets.push({
      kind,
      entity,
      logName,
      stats: defenceStatsForEntity(entity),
    });
  };
  if (bossPartyActiveFight()) {
    const party = state.battle.bossParty;
    if (party?.pet?.active) consider("pet", party.pet, party.pet.name);
    for (const member of party?.members ?? []) {
      if (!member.alive || (member.hp ?? 0) <= 0) continue;
      consider("member", member, member.classId);
    }
    return targets;
  }
  const battle = state.battle;
  if (taoistPetCanTank() && battle.taoPet?.active && (battle.taoPet.hp ?? 0) > 0) {
    consider("pet", battle.taoPet, battle.taoPet.name);
  }
  if ((battle.player?.hp ?? 0) > 0 && Math.abs(centerX - Number(battle.playerX)) <= range) {
    consider("player", battle.player, battle.combatClass);
  }
  return targets;
}

function scalyBeastMeleeRange() {
  return bossPartyActiveFight() ? BOSS_PARTY_BOSS_REACH : LANE.enemyRange;
}

function canScalyBeastAttack() {
  const battle = state.battle;
  if (battle.phase !== "engaged" || !battle.enemyRevealed || !battle.enemy?.hp) return false;
  if (enemyFrozenActive(battle.enemy)) return false;
  if (!battle.enemyAggro) return false;
  if (bossPartyActiveFight()) {
    const target = bossPartyFrontTarget();
    return Boolean(target && bossPartyTargetEnemyDistance(target) <= scalyBeastMeleeRange());
  }
  return enemyTargetDistance() <= scalyBeastMeleeRange();
}

function scalyBeastStompChance(enemy = state.battle.enemy) {
  if (enemy?.alwaysAoe) return 1;
  const chance = Number(enemy?.aoeSplashChance);
  return Number.isFinite(chance) ? Math.max(0, Math.min(1, chance)) : 0.34;
}

function applyScalyBeastParalysis(enemy, combatant, now) {
  const poisonValue = rollStat(enemy.sc ?? [0, 0], enemy.luck ?? 0);
  return applyCombatantPoison(combatant, {
    kind: "paralysis",
    value: poisonValue,
    ticksRemaining: FLAMING_MUTANT_PARALYSIS_POISON_TICKS,
  }, now);
}

function applyFlamingMutantParalysis(enemy, combatant, now) {
  if (Math.random() >= 0.5) return false;
  return applyScalyBeastParalysis(enemy, combatant, now);
}

function resolveSplashStrikeTarget(enemy, target, now, offsetIndex = 0, options = {}) {
  const defenceType = options.defenceType || enemy.attackDefenceType || "ACAgility";
  const attackEnemy = { ...enemy, attackDefenceType: defenceType };
  const { hit, damage } = resolveIncomingEnemyAttack(
    attackEnemy,
    target.stats ?? defenceTargetForIncomingAttack(target.entity),
    options.ranged ? { ranged: true, aoe: true, massBurst: options.massBurst } : { aoe: true, massBurst: options.massBurst },
  );
  const offsetX = offsetIndex * 14;
  if (!hit) {
    addCombatantPoisonText(target.kind, target.entity, "Miss", "miss", now, offsetX);
    pushBattleLog(`${enemy.name} misses ${target.logName}.`);
    return;
  }
  target.entity.hp = Math.max(0, target.entity.hp - damage);
  if (target.kind === "pet") {
    setTaoPetAction("struck", true, now);
    addCombatantPoisonText(target.kind, target.entity, damage, "enemyDamage", now, offsetX);
    if (target.entity.hp <= 0) {
      if (bossPartyActiveFight()) bossPartyMarkPetDead(now);
      else markTaoistPetDead(now);
    }
  } else if (target.kind === "member") {
    if (target.entity.classId === bossPartyControlledClassId()) {
      setPlayerAction("struck", now + 250, true);
      maybeNotifyMagicShieldStruck(null, now);
      addCombatText("player", damage, "enemyDamage", now, offsetX);
      playSfx("player.flinch", { volume: 0.45, throttleMs: 120, force: true });
    } else {
      target.entity.visualAction = "struck";
      target.entity.visualFrame = 0;
      target.entity.visualOneShot = true;
      target.entity.visualLastTick = now;
      notifyWizardMagicShieldStruckOnHit(target.entity, now);
      addCombatText("enemy", damage, "enemyDamage", now, offsetX);
      playSfx("player.flinch", bossPartySfxParams(target.entity, 0.45, 120));
    }
    if (target.entity.hp <= 0) bossPartyMarkMemberDead(target.entity, now);
  } else {
    setPlayerAction("struck", now + 250, true);
    maybeNotifyMagicShieldStruck(null, now);
    addCombatText("player", damage, "enemyDamage", now, offsetX);
    playSfx("player.flinch", { volume: 0.45, throttleMs: 120, force: true });
    if (target.entity.hp <= 0) {
      if (bossPartyActiveFight()) bossPartyMarkMemberDead(target.entity, now);
      else {
        finishBattle(now);
        setPlayerAction("die", now);
        playSfx("player.death", { volume: 0.58 });
        pushBattleLog(`${state.battle.combatClass} falls.`);
      }
    }
  }
  pushBattleLog(`${enemy.name} hits ${target.logName} for ${damage}.`);
  if (options.paralysis && applyScalyBeastParalysis(enemy, target.entity, now)) {
    pushBattleLog(`${target.logName} is paralyzed.`);
    addCombatantPoisonText(target.kind, target.entity, "Paralysis", "poison", now, offsetX);
  }
}


function beginScalyBeastAttack(now) {
  if (state.battle.pendingEnemyStrike) return false;
  if (!canScalyBeastAttack()) return false;
  const enemy = state.battle.enemy;
  const stomp = Math.random() < scalyBeastStompChance(enemy);
  const impactMs = stomp ? SCALY_BEAST_STOMP_IMPACT_MS : SCALY_BEAST_MELEE_IMPACT_MS;
  const projectile = state.enemy.atlas?.projectile;
  const vfxUntil = stomp ? enemyProjectileVfxUntil(now, projectile) : now + impactMs;
  state.battle.pendingEnemyStrike = {
    kind: stomp ? "scalyStomp" : "scalyMelee",
    at: now + impactMs,
    startedAt: now,
    vfxUntil,
  };
  setEnemyAction("attack1", true, now);
  playMonsterSfx("attack", enemy, { force: true, throttleMs: 0 });
  return true;
}

function beginMassBurstAttack(now) {
  if (state.battle.pendingEnemyStrike) return false;
  const enemy = state.battle.enemy;
  if (shouldMassBurstNow(enemy, now)) {
    if (massBurstTargetsInRange().length === 0) return false;
    const projectile = state.enemy.atlas?.projectile;
    const startedAt = now;
    state.battle.pendingEnemyStrike = {
      kind: "massBurst",
      at: startedAt + MASS_BURST_IMPACT_MS,
      startedAt,
      ranged: true,
      aoe: true,
      vfxUntil: enemyProjectileVfxUntil(startedAt, projectile),
    };
    setEnemyAction("attackRange1", true, now);
    playMonsterSfx("attack", enemy, { force: true, throttleMs: 0 });
    return true;
  }
  if (enemy.alwaysAoe) return false;
  if (massBurstStyle(enemy) === "line") return beginKingScorpionAttack(now);
  return beginBoneLordAttack(now);
}

function canMassBurstAttack() {
  const battle = state.battle;
  if (battle.phase !== "engaged" || !battle.enemyRevealed || !battle.enemy?.hp) return false;
  if (enemyFrozenActive(battle.enemy)) return false;
  if (!battle.enemyAggro) return false;
  if (battle.enemy.alwaysAoe && massBurstTargetsInRange().length > 0) return true;
  if (shouldMassBurstNow(battle.enemy) && massBurstTargetsInRange().length > 0) return true;
  if (massBurstStyle(battle.enemy) === "line") return canKingScorpionAttack();
  return canBoneLordAttack();
}

function boneLordImpactDelay(distancePx, enemy = state.battle.enemy) {
  const tiles = Math.max(1, Math.round(Math.max(0, distancePx) / LANE_TILE_PX));
  const base = Math.max(0, Math.trunc(Number(enemy?.attackImpactDelayMs) || BONE_LORD_ATTACK_IMPACT_MS));
  return Math.round(tiles * 50 + base);
}

function canBoneLordAttack() {
  const battle = state.battle;
  if (battle.phase !== "engaged" || !battle.enemyRevealed || !battle.enemy?.hp) return false;
  if (enemyFrozenActive(battle.enemy)) return false;
  if (!battle.enemyAggro) return false;
  return boneLordTargetDistance() <= boneLordAttackRange(battle.enemy);
}


function boneLordProjectileTargetAnchor() {
  if (bossPartyActiveFight()) {
    const useAoe = minotaurKingStrikeUsesAoe(state.battle.pendingEnemyStrike);
    const target = useAoe ? bossPartyAoeRangedTarget() : bossPartyFrontTarget();
    if (target === state.battle.bossParty?.pet) return taoistPetAnchor();
    if (target) {
      return {
        x: Math.round((Number(target.worldX) || state.battle.playerX) - state.battle.cameraX),
        y: Math.round(state.stageHeight * LANE.y + 2),
      };
    }
  }
  if (taoistPetCanTank()) return taoistPetAnchor();
  return combatAnchor("player");
}

function isRedThunderZumaEnemy(enemy = state.battle.enemy) {
  return enemy?.id === RED_THUNDER_ZUMA_ENEMY_ID
    || enemy?.id === INCARNATED_RTZ_ENEMY_ID
    || enemy?.crystalName === "RedThunderZuma";
}

function evilCentipedeAttackRange(enemy = state.battle.enemy) {
  const tiles = Math.max(1, Math.trunc(Number(enemy?.attackRangeTiles) || 7));
  return tiles * LANE_TILE_PX;
}

function evilCentipedeImpactDelay(enemy = state.battle.enemy) {
  return Math.max(0, Math.trunc(Number(enemy?.attackImpactDelayMs) || EVIL_CENTIPEDE_ATTACK_IMPACT_MS));
}

function evilCentipedeDistanceToTarget(entity, kind = "member") {
  const enemyX = Number(state.battle.enemyX);
  if (kind === "player") return Math.max(0, enemyX - Number(state.battle.playerX));
  return Math.max(0, enemyX - Number(entity?.worldX ?? state.battle.playerX));
}

function evilCentipedeTargetStats(entity) {
  return defenceStatsForEntity(entity);
}

function evilCentipedeTargetsInRange() {
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) return [];
  const range = evilCentipedeAttackRange(enemy);
  const targets = [];

  if (bossPartyActiveFight()) {
    const party = state.battle.bossParty;
    if (party?.pet?.active && (party.pet.hp ?? 0) > 0) {
      const dist = evilCentipedeDistanceToTarget(party.pet, "pet");
      if (dist <= range) {
        targets.push({
          kind: "pet",
          entity: party.pet,
          logName: party.pet.name,
          stats: evilCentipedeTargetStats(party.pet),
        });
      }
    }
    for (const member of party?.members ?? []) {
      if (!member.alive || (member.hp ?? 0) <= 0) continue;
      if (evilCentipedeDistanceToTarget(member, "member") > range) continue;
      targets.push({
        kind: "member",
        entity: member,
        logName: member.classId,
        stats: evilCentipedeTargetStats(member),
      });
    }
    return targets;
  }

  const battle = state.battle;
  if (taoistPetCanTank()) {
    const pet = battle.taoPet;
    if ((pet?.hp ?? 0) > 0 && evilCentipedeDistanceToTarget(pet, "pet") <= range) {
      targets.push({
        kind: "pet",
        entity: pet,
        logName: pet.name,
        stats: evilCentipedeTargetStats(pet),
      });
    }
  }
  if ((battle.player?.hp ?? 0) > 0 && enemyDistance() <= range) {
    targets.push({
      kind: "player",
      entity: battle.player,
      logName: battle.combatClass,
      stats: evilCentipedeTargetStats(battle.player),
    });
  }
  return targets;
}

function canEvilCentipedeAttack() {
  const battle = state.battle;
  return battle.phase === "engaged"
    && battle.enemyRevealed
    && battle.enemy?.hp > 0
    && evilCentipedeTargetsInRange().length > 0;
}

function combatantPoison(entity, kind) {
  const poisons = Array.isArray(entity?.poisons) ? entity.poisons : [];
  return poisons.find((poison) => poison.kind === kind && (Number(poison.ticksRemaining) || 0) > 0) ?? null;
}

function combatantParalyzed(entity) {
  return Boolean(combatantPoison(entity, "paralysis"));
}

function rollPoisonResist(target) {
  const resist = Math.max(0, Math.min(CRYSTAL_POISON_RESIST_WEIGHT, Number(target?.poisonResist) || 0));
  return resist <= 0 || randomInt(0, CRYSTAL_POISON_RESIST_WEIGHT - 1) >= resist;
}

function rollPoisonProc(chance) {
  const safeChance = Math.max(1, Math.trunc(Number(chance) || 1));
  return randomInt(0, safeChance - 1) === 0;
}

function applyCombatantPoison(combatant, poison, now = performance.now()) {
  if (!combatant || (combatant.hp ?? 0) <= 0 || !poison) return false;
  if (!rollPoisonResist(combatant)) return false;
  if (!Array.isArray(combatant.poisons)) combatant.poisons = [];
  const ticksRemaining = Math.max(1, Math.trunc(Number(poison.ticksRemaining) || 1));
  const value = Math.max(0, Math.trunc(Number(poison.value) || 0));
  const kind = poison.kind === "green" ? "green" : poison.kind === "paralysis" ? "paralysis" : null;
  if (!kind) return false;

  const existing = combatantPoison(combatant, kind);
  if (kind === "paralysis" && existing) return false;
  if (existing) {
    if (kind === "green" && (Number(existing.value) || 0) > value) return false;
    if (kind !== "green" && (Number(existing.ticksRemaining) || 0) > ticksRemaining) return false;
    Object.assign(existing, {
      ...poison,
      kind,
      value,
      ticksRemaining,
      tickMs: CRYSTAL_POISON_TICK_MS,
      nextTickAt: now + CRYSTAL_POISON_TICK_MS,
      appliedAt: now,
    });
    return true;
  }

  combatant.poisons.push({
    ...poison,
    kind,
    value,
    ticksRemaining,
    tickMs: CRYSTAL_POISON_TICK_MS,
    nextTickAt: now + CRYSTAL_POISON_TICK_MS,
    appliedAt: now,
  });
  return true;
}

function applyEvilCentipedePoisons(enemy, combatant, now) {
  const poisonValue = rollStat(enemy.sc ?? [0, 0], enemy.luck ?? 0);
  let applied = false;
  if (rollPoisonProc(EVIL_CENTIPEDE_GREEN_POISON_CHANCE)) {
    applied = applyCombatantPoison(combatant, {
      kind: "green",
      value: poisonValue,
      ticksRemaining: EVIL_CENTIPEDE_GREEN_POISON_TICKS,
    }, now) || applied;
  }
  if (rollPoisonProc(EVIL_CENTIPEDE_PARALYSIS_POISON_CHANCE)) {
    applied = applyCombatantPoison(combatant, {
      kind: "paralysis",
      value: poisonValue,
      ticksRemaining: EVIL_CENTIPEDE_PARALYSIS_POISON_TICKS,
    }, now) || applied;
  }
  return applied;
}

function addCombatantPoisonText(targetKind, entity, text, kind, now, offsetX = 0) {
  if (targetKind === "player" || (targetKind === "member" && entity?.classId === bossPartyControlledClassId())) {
    addCombatText("player", text, kind, now, offsetX);
    return;
  }
  if (targetKind === "pet") {
    addCombatText("pet", text, kind, now, offsetX);
    return;
  }
  addCombatText("enemy", text, kind, now, offsetX);
}

function handleCombatantPoisonDeath(entity, targetKind, now, options = {}) {
  if ((entity?.hp ?? 0) > 0) return;
  if (options.offline) return;
  if (targetKind === "pet") {
    if (bossPartyActiveFight()) bossPartyMarkPetDead(now);
    else markTaoistPetDead(now);
    return;
  }
  if (targetKind === "member") {
    bossPartyMarkMemberDead(entity, now);
    return;
  }
  if (targetKind === "player") {
    finishBattle(now);
    setPlayerAction("die", now);
    playSfx("player.death", { volume: 0.58 });
    pushBattleLog(`${state.battle.combatClass} falls.`);
  }
}

function updateEntityPoisons(entity, targetKind, now, options = {}) {
  const poisons = Array.isArray(entity?.poisons) ? entity.poisons : [];
  if (!poisons.length || (entity?.hp ?? 0) <= 0) return false;
  const active = [];
  let changed = false;

  for (const poison of poisons) {
    poison.tickMs = Math.max(1, Math.trunc(Number(poison.tickMs) || CRYSTAL_POISON_TICK_MS));
    poison.nextTickAt = Number(poison.nextTickAt) || now + poison.tickMs;
    poison.ticksRemaining = Math.max(0, Math.trunc(Number(poison.ticksRemaining) || 0));

    if (poison.kind === "paralysis") {
      let steps = 0;
      while ((entity.hp ?? 0) > 0 && poison.ticksRemaining > 0 && now >= poison.nextTickAt && steps < 20) {
        poison.nextTickAt += poison.tickMs;
        poison.ticksRemaining -= 1;
        steps += 1;
        changed = true;
      }
      if (steps >= 20 && poison.ticksRemaining > 0) poison.nextTickAt = now + poison.tickMs;
      if (poison.ticksRemaining > 0 && (entity.hp ?? 0) > 0) active.push(poison);
      continue;
    }

    if (poison.kind !== "green") continue;

    let steps = 0;
    while ((entity.hp ?? 0) > 0 && poison.ticksRemaining > 0 && now >= poison.nextTickAt && steps < 20) {
      const tickAt = poison.nextTickAt;
      poison.nextTickAt += poison.tickMs;
      poison.ticksRemaining -= 1;
      steps += 1;
      const damage = Math.max(0, Math.trunc(Number(poison.value) || 0));
      if (damage > 0) {
        entity.hp = Math.max(0, entity.hp - damage);
        changed = true;
        if (!options.offline) addCombatantPoisonText(targetKind, entity, damage, "poison", tickAt);
      }
    }
    if (steps >= 20 && poison.ticksRemaining > 0) poison.nextTickAt = now + poison.tickMs;
    if (poison.ticksRemaining > 0 && (entity.hp ?? 0) > 0) active.push(poison);
  }

  entity.poisons = active;
  if ((entity?.hp ?? 0) <= 0) handleCombatantPoisonDeath(entity, targetKind, now, options);
  return changed;
}

function updateCombatantPoisons(now, options = {}) {
  let changed = false;
  if (bossPartyActiveFight()) {
    const party = state.battle.bossParty;
    for (const member of party?.members ?? []) {
      if (updateEntityPoisons(member, "member", now, options)) changed = true;
    }
    if (party?.pet?.active && updateEntityPoisons(party.pet, "pet", now, options)) changed = true;
    return changed;
  }
  const battle = state.battle;
  if (battle.player && updateEntityPoisons(battle.player, "player", now, options)) changed = true;
  if (battle.taoPet?.active && updateEntityPoisons(battle.taoPet, "pet", now, options)) changed = true;
  return changed;
}

function beginEvilCentipedeAttack(now) {
  if (state.battle.pendingEnemyStrike) return false;
  if (!canEvilCentipedeAttack()) return false;
  state.battle.pendingEnemyStrike = { at: now + evilCentipedeImpactDelay() };
  setEnemyAction("attack1", true, now);
  playMonsterSfx("attack", state.battle.enemy, { force: true, throttleMs: 0 });
  return true;
}

function enemyRangedStrikeVfxUntil(startedAt, moveDurationMs, projectile) {
  if (!projectile || projectile.style !== "targetBurst") return startedAt + moveDurationMs;
  const burstDelayMs = Number(projectile.burstDelayMs);
  const burstDurationMs = Math.max(1, Number(projectile.burstDurationMs) || 300);
  if (Number.isFinite(burstDelayMs)) return startedAt + burstDelayMs + burstDurationMs;
  return startedAt + moveDurationMs;
}

function beginBoneLordAttack(now) {
  if (state.battle.pendingEnemyStrike) return false;
  if (!canBoneLordAttack()) return false;
  const enemy = state.battle.enemy;
  const distance = boneLordTargetDistance();
  const kingAttackCount = isMinotaurKingEnemy(enemy) ? beginMinotaurKingAttack(enemy) : 0;
  const useAoe = (isMinotaurKingEnemy(enemy) && minotaurKingAttackIsAoe(kingAttackCount, enemy))
    || (isFlamingMutantEnemy(enemy) && (enemy.alwaysAoe || boneLordUsesRangedAttack(distance)));
  if (useAoe || boneLordUsesRangedAttack(distance) || (isFlamingMutantEnemy(enemy) && enemy.alwaysAoe)) {
    const startedAt = now;
    const moveDurationMs = boneLordImpactDelay(distance, enemy);
    const projectile = state.enemy.atlas?.projectile;
    state.battle.pendingEnemyStrike = {
      at: startedAt + moveDurationMs,
      startedAt,
      ranged: true,
      aoe: useAoe,
      moveDurationMs,
      vfxUntil: useAoe
        ? enemyRangedStrikeVfxUntil(startedAt, moveDurationMs, projectile)
        : startedAt + moveDurationMs,
    };
    setEnemyAction("attackRange1", true, now);
    playMonsterSfx(enemyAttackSfxKind(enemy, true), enemy, { force: true, throttleMs: 0 });
    return true;
  }
  if (bossPartyActiveFight()) return resolveBoneLordBossPartyMelee(now);
  return resolveBoneLordSoloMelee(now);
}

function resolveBoneLordBossPartyMelee(now) {
  const enemy = state.battle.enemy;
  const target = bossPartyFrontTarget();
  if (!enemy || !target || !state.battle.enemyRevealed) return false;
  if (bossPartyTargetEnemyDistance(target) > BOSS_PARTY_BOSS_REACH) return false;
  setEnemyAction("attack1", true, now);
  playMonsterSfx("attack");
  const { hit, damage } = resolveIncomingEnemyAttack(enemy, defenceTargetForIncomingAttack(target));
  if (!hit) {
    addCombatText(target.classId === bossPartyControlledClassId() ? "player" : "enemy", "Miss", "miss", now);
    pushBattleLog(`${enemy.name} misses ${target.name}.`);
    return true;
  }
  target.hp = Math.max(0, target.hp - damage);
  if (target === state.battle.bossParty.pet) {
    setTaoPetAction("struck", true, now);
    if (target.hp <= 0) bossPartyMarkPetDead(now);
  } else {
    if (target.classId === bossPartyControlledClassId()) {
      setPlayerAction("struck", now + 250, true);
      maybeNotifyMagicShieldStruck(null, now);
      addCombatText("player", damage, "enemyDamage", now);
    } else {
      target.visualAction = "struck";
      target.visualFrame = 0;
      target.visualOneShot = true;
      target.visualLastTick = now;
      notifyWizardMagicShieldStruckOnHit(target, now);
    }
    playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
  }
  pushBattleLog(`${enemy.name} hits ${target.name} for ${damage}.`);
  if (target !== state.battle.bossParty.pet && target.hp <= 0) bossPartyMarkMemberDead(target, now);
  return true;
}

function resolveBoneLordSoloMelee(now) {
  const battle = state.battle;
  const enemy = battle.enemy;
  const target = enemyAttackTarget();
  if (enemyTargetDistance() > LANE.enemyRange) return false;
  setEnemyAction("attack1", true, now);
  playMonsterSfx("attack");
  const { hit, damage } = resolveIncomingEnemyAttack(enemy, target);
  if (!hit) {
    addCombatText(target.anchor, "Miss", "miss", now);
    pushBattleLog(`${enemy.name} misses ${target.name}.`);
    return true;
  }
  target.applyDamage(damage, now);
  addCombatText(target.anchor, damage, "enemyDamage", now);
  pushBattleLog(`${enemy.name} hits ${target.name} for ${damage}.`);
  if (target.kind === "player" && battle.player.hp <= 0) {
    finishBattle(now);
    setPlayerAction("die", now);
    playSfx("player.death", { volume: 0.58 });
    pushBattleLog(`${battle.combatClass} falls.`);
  }
  return true;
}

function resolveMinotaurKingSoloAoeStrike(enemy, now) {
  const battle = state.battle;
  const targets = [];
  if ((battle.player?.hp ?? 0) > 0) targets.push(enemyAttackTarget());
  const pet = battle.taoPet;
  if (pet?.active && (pet.hp ?? 0) > 0 && !taoistPetCanTank()) {
    const defence = defenceStatsForEntity(pet);
    targets.push({
      kind: "pet",
      name: pet.name,
      anchor: "pet",
      ac: defence.ac,
      amc: defence.amc,
      magicResist: defence.magicResist,
      agility: defence.agility,
      applyDamage: (damage, impactNow) => {
        pet.hp = Math.max(0, pet.hp - damage);
        setTaoPetAction("struck", true, impactNow);
        if (pet.hp <= 0) markTaoistPetDead(impactNow);
      },
    });
  } else if (pet?.active && (pet.hp ?? 0) > 0 && taoistPetCanTank() && (battle.player?.hp ?? 0) > 0) {
    const playerTarget = {
      kind: "player",
      name: battle.combatClass,
      anchor: "player",
      ac: battle.player.ac,
      amc: battle.player.amc,
      magicResist: battle.player.magicResist ?? 0,
      agility: battle.player.agility,
      applyDamage: (damage, impactNow) => {
        battle.player.hp = Math.max(0, battle.player.hp - damage);
        maybeNotifyMagicShieldStruck(null, impactNow);
        setPlayerAction("struck", impactNow + 250, true);
        playSfx("player.flinch", { volume: 0.45, throttleMs: 120 });
      },
    };
    targets.push(playerTarget);
  }
  let primaryLogged = false;
  for (const target of targets) {
    const { hit, damage } = resolveIncomingEnemyRangedAttack(enemy, target, { aoe: true });
    if (!hit) {
      if (!primaryLogged) {
        addCombatText(target.anchor, "Miss", "miss", now);
        pushBattleLog(`${enemy.name} misses ${target.name}.`);
        primaryLogged = true;
      }
      continue;
    }
    target.applyDamage(damage, now);
    addCombatText(target.anchor, damage, "enemyDamage", now);
    pushBattleLog(`${enemy.name} hits ${target.name} for ${damage}.`);
    if (target.kind === "player" && battle.player.hp <= 0) {
      finishBattle(now);
      setPlayerAction("die", now);
      playSfx("player.death", { volume: 0.58 });
      pushBattleLog(`${battle.combatClass} falls.`);
      break;
    }
  }
}

function resolveBoneLordRangedStrike(now) {
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) return;
  const useAoe = isMinotaurKingEnemy(enemy) && minotaurKingStrikeUsesAoe();
  if (bossPartyActiveFight()) {
    const primaryTarget = useAoe ? bossPartyAoeRangedTarget() : bossPartyFrontTarget();
    if (!primaryTarget) return;
    const distance = bossPartyTargetEnemyDistance(primaryTarget);
    if (distance > boneLordAttackRange(enemy)) return;
    const splashTargets = useAoe
      ? minotaurKingSplashTargets(primaryTarget, enemy)
      : [primaryTarget];
    for (const target of splashTargets) {
      const { hit, damage } = resolveIncomingEnemyRangedAttack(
        enemy,
        defenceTargetForIncomingAttack(target),
        { aoe: useAoe, ranged: true },
      );
      if (!hit) {
        if (target === primaryTarget) {
          addCombatText(target.classId === bossPartyControlledClassId() ? "player" : "enemy", "Miss", "miss", now);
          pushBattleLog(`${enemy.name} misses ${target.name}.`);
        }
        continue;
      }
      target.hp = Math.max(0, target.hp - damage);
      if (target === state.battle.bossParty.pet) {
        setTaoPetAction("struck", true, now);
        addCombatText("pet", damage, "enemyDamage", now);
        if (target.hp <= 0) bossPartyMarkPetDead(now);
      } else if (target.classId === bossPartyControlledClassId()) {
        setPlayerAction("struck", now + 250, true);
        maybeNotifyMagicShieldStruck(null, now);
        addCombatText("player", damage, "enemyDamage", now);
        playSfx("player.flinch", { volume: 0.45, throttleMs: 120, force: true });
      } else {
        target.visualAction = "struck";
        target.visualFrame = 0;
        target.visualOneShot = true;
        target.visualLastTick = now;
        notifyWizardMagicShieldStruckOnHit(target, now);
        addCombatText("enemy", damage, "enemyDamage", now);
        playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
      }
      pushBattleLog(`${enemy.name} hits ${target.logName ?? target.name} for ${damage}.`);
      if (target !== state.battle.bossParty.pet && target.hp <= 0) bossPartyMarkMemberDead(target, now);
      if (isFlamingMutantEnemy(enemy) && useAoe && applyFlamingMutantParalysis(enemy, target, now)) {
        pushBattleLog(`${target.name} is paralyzed.`);
        addCombatText(target.classId === bossPartyControlledClassId() ? "player" : "enemy", "Paralysis", "poison", now);
      }
    }
    return;
  }
  const target = enemyAttackTarget();
  const distance = enemyTargetDistance();
  if (distance > boneLordAttackRange(enemy)) return;
  if (useAoe) {
    resolveMinotaurKingSoloAoeStrike(enemy, now);
    return;
  }
  const { hit, damage } = resolveIncomingEnemyRangedAttack(enemy, target, { ranged: true });
  if (!hit) {
    addCombatText(target.anchor, "Miss", "miss", now);
    pushBattleLog(`${enemy.name} misses ${target.name}.`);
    return;
  }
  target.applyDamage(damage, now);
  addCombatText(target.anchor, damage, "enemyDamage", now);
  pushBattleLog(`${enemy.name} hits ${target.name} for ${damage}.`);
  if (target.kind === "player" && state.battle.player.hp <= 0) {
    finishBattle(now);
    setPlayerAction("die", now);
    playSfx("player.death", { volume: 0.58 });
    pushBattleLog(`${state.battle.combatClass} falls.`);
  }
}

function resolveEvilCentipedeStrikeTarget(enemy, target, now, offsetIndex = 0) {
  const { hit, damage } = resolveIncomingEnemyAttack(enemy, target.stats);
  const offsetX = offsetIndex * 14;
  if (!hit) {
    addCombatantPoisonText(target.kind, target.entity, "Miss", "miss", now, offsetX);
    pushBattleLog(`${enemy.name} misses ${target.logName}.`);
    return;
  }

  target.entity.hp = Math.max(0, target.entity.hp - damage);
  if (target.kind === "pet") {
    setTaoPetAction("struck", true, now);
    addCombatantPoisonText(target.kind, target.entity, damage, "enemyDamage", now, offsetX);
    if (target.entity.hp <= 0) {
      if (bossPartyActiveFight()) bossPartyMarkPetDead(now);
      else markTaoistPetDead(now);
    }
  } else if (target.kind === "member") {
    if (target.entity.classId === bossPartyControlledClassId()) {
      setPlayerAction("struck", now + 250, true);
      maybeNotifyMagicShieldStruck(null, now);
      addCombatText("player", damage, "enemyDamage", now, offsetX);
      playSfx("player.flinch", { volume: 0.45, throttleMs: 120, force: true });
    } else {
      target.entity.visualAction = "struck";
      target.entity.visualFrame = 0;
      target.entity.visualOneShot = true;
      target.entity.visualLastTick = now;
      notifyWizardMagicShieldStruckOnHit(target.entity, now);
      addCombatText("enemy", damage, "enemyDamage", now, offsetX);
      playSfx("player.flinch", bossPartySfxParams(target.entity, 0.45, 120));
    }
    if (target.entity.hp <= 0) bossPartyMarkMemberDead(target.entity, now);
  } else {
    setPlayerAction("struck", now + 250, true);
    maybeNotifyMagicShieldStruck(null, now);
    addCombatText("player", damage, "enemyDamage", now, offsetX);
    playSfx("player.flinch", { volume: 0.45, throttleMs: 120, force: true });
    if (target.entity.hp <= 0) {
      finishBattle(now);
      setPlayerAction("die", now);
      playSfx("player.death", { volume: 0.58 });
      pushBattleLog(`${state.battle.combatClass} falls.`);
    }
  }
  pushBattleLog(`${enemy.name} hits ${target.logName} for ${damage}.`);
  if (applyEvilCentipedePoisons(enemy, target.entity, now)) {
    pushBattleLog(`${target.logName} is poisoned.`);
    addCombatantPoisonText(target.kind, target.entity, "Poison", "poison", now, offsetX);
  }
}

function updatePendingEnemyStrike(now) {
  const strike = state.battle.pendingEnemyStrike;
  if (!strike) return;
  const vfxUntil = Number(strike.vfxUntil) || strike.at;
  if (strike.kind === "kingScorpionLine") {
    for (const hit of strike.hits ?? []) {
      if (hit.resolved || now < hit.at) continue;
      hit.resolved = true;
      resolveKingScorpionLineHit(hit, strike.ranged, now);
    }
    if (now >= vfxUntil && (strike.hits ?? []).every((hit) => hit.resolved)) {
      state.battle.pendingEnemyStrike = null;
    }
    return;
  }
  if (strike.kind === "scalyStomp" || strike.kind === "scalyMelee") {
    if (now >= strike.at && !strike.resolved) {
      strike.resolved = true;
      const enemy = state.battle.enemy;
      if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) {
        if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
        return;
      }
      if (strike.kind === "scalyStomp") {
        const targets = splashTargetsNearEnemy(enemy);
        targets.forEach((target, index) => resolveSplashStrikeTarget(
          enemy,
          target,
          now,
          index,
          { defenceType: enemy.stompDefenceType || "ACAgility", paralysis: true },
        ));
      } else {
        let targetRef = null;
        if (bossPartyActiveFight()) {
          const target = bossPartyFrontTarget();
          if (!target) {
            if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
            return;
          }
          targetRef = {
            kind: target === state.battle.bossParty?.pet ? "pet" : "member",
            entity: target,
            logName: target.name || target.classId,
            stats: defenceStatsForEntity(target),
          };
        } else {
          const target = enemyAttackTarget();
          targetRef = {
            kind: target.kind,
            entity: target.kind === "player" ? state.battle.player : state.battle.taoPet,
            logName: target.name,
            stats: target,
          };
        }
        if (targetRef) {
          resolveSplashStrikeTarget(enemy, targetRef, now, 0, { defenceType: enemy.attackDefenceType || "MAC" });
        }
      }
    }
    if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
    return;
  }
  if (strike.kind === "massBurst") {
    if (now >= strike.at && !strike.resolved) {
      strike.resolved = true;
      const enemy = state.battle.enemy;
      if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) {
        if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
        return;
      }
      scheduleMassBurstCooldown(enemy, now);
      const targets = massBurstTargetsInRange(enemy);
      targets.forEach((target, index) => resolveSplashStrikeTarget(
        enemy,
        target,
        now,
        index,
        { defenceType: enemy.rangedAttackDefenceType || "ACAgility", massBurst: true, ranged: true },
      ));
    }
    if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
    return;
  }
  if (strike.kind === "darkDevilBurst") {
    if (now >= strike.at && !strike.resolved) {
      strike.resolved = true;
      const enemy = state.battle.enemy;
      if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) {
        if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
        return;
      }
      const targets = darkDevilBurstTargets(enemy);
      targets.forEach((target, index) => resolveDarkDevilBurstTarget(enemy, target, now, index));
    }
    if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
    return;
  }
  if (now >= strike.at && !strike.resolved) {
    strike.resolved = true;
    const enemy = state.battle.enemy;
    if (!enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) {
      if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
      return;
    }
    if (enemyHasRangedMeleeAttack(enemy)) {
      resolveBoneLordRangedStrike(now);
    } else {
      const targets = evilCentipedeTargetsInRange();
      targets.forEach((target, index) => resolveEvilCentipedeStrikeTarget(enemy, target, now, index));
    }
  }
  if (now >= vfxUntil) state.battle.pendingEnemyStrike = null;
}

function bossPartyEnemyAttack(now) {
  const enemy = state.battle.enemy;
  if (isEvilCentipedeEnemy(enemy)) return beginEvilCentipedeAttack(now);
  if (isMassBurstEnemy(enemy)) return beginMassBurstAttack(now);
  if (isScalyBeastEnemy(enemy)) return beginScalyBeastAttack(now);
  if (isDarkDevilEnemy(enemy)) return beginDarkDevilAttack(now);
  if (isKingScorpionEnemy(enemy)) return beginKingScorpionAttack(now);
  if (enemyHasRangedMeleeAttack(enemy)) return beginBoneLordAttack(now);
  const target = bossPartyFrontTarget();
  if (!enemy || !target || !state.battle.enemyRevealed) return false;
  if (bossPartyTargetEnemyDistance(target) > BOSS_PARTY_BOSS_REACH) return false;
  setEnemyAction("attack1", true, now);
  playMonsterSfx("attack");
  const { hit, damage } = resolveIncomingEnemyAttack(enemy, defenceTargetForIncomingAttack(target));
  if (!hit) {
    addCombatText(target.classId === bossPartyControlledClassId() ? "player" : "enemy", "Miss", "miss", now);
    pushBattleLog(`${enemy.name} misses ${target.name}.`);
    return true;
  }
  target.hp = Math.max(0, target.hp - damage);
  if (target === state.battle.bossParty.pet) {
    setTaoPetAction("struck", true, now);
    if (target.hp <= 0) bossPartyMarkPetDead(now);
  } else {
    if (target.classId === bossPartyControlledClassId()) {
      setPlayerAction("struck", now + 250, true);
      maybeNotifyMagicShieldStruck(null, now);
      addCombatText("player", damage, "enemyDamage", now);
    } else {
      target.visualAction = "struck";
      target.visualFrame = 0;
      target.visualOneShot = true;
      target.visualLastTick = now;
      notifyWizardMagicShieldStruckOnHit(target, now);
    }
    playSfx("player.flinch", bossPartySfxParams(target, 0.45, 120));
  }
  pushBattleLog(`${enemy.name} hits ${target.name} for ${damage}.`);
  if (target !== state.battle.bossParty.pet && target.hp <= 0) bossPartyMarkMemberDead(target, now);
  return true;
}

function bossPartyPetAttack(now) {
  const pet = state.battle.bossParty?.pet;
  const enemy = state.battle.enemy;
  if (!pet?.active || !enemy || enemy.hp <= 0 || !state.battle.enemyRevealed) return false;
  if (combatantParalyzed(pet)) return false;
  if (state.battle.pendingPetAttack) return false;
  if (pet.spellId === "SummonShinsu" && !pet.shinsuVisible && pet.action === "show") return false;
  if (bossPartyPetEnemyDistance(pet, enemy) > taoistPetAttackRangePx(pet)) {
    setTaoPetAction("standing", false, now);
    return false;
  }
  pet.nextAttackAt = now + Math.max(400, Math.trunc(Number(pet.attackMs) || 1200));
  revealTaoistShinsuPet(pet);
  const result = rollTaoistPetAttackResult(pet, enemy);
  setTaoPetAction("attack1", true, now);

  if (pet.spellId === "SummonShinsu") {
    playTaoPetSfx("attack", { volume: 0.34, throttleMs: 250 });
    state.battle.pendingPetAttack = {
      at: now + taoistShinsuAttackImpactMs(),
      hit: result.hit,
      damage: result.damage,
      offline: false,
      bossParty: true,
    };
    return true;
  }

  playTaoPetSfx("attack", { volume: 0.34, throttleMs: 250 });
  applyTaoistPetAttackResult(pet, enemy, result, now, { bossParty: true });
  return true;
}

function bossPartyMarkPetDead(now) {
  const pet = state.battle.bossParty?.pet;
  if (!pet || pet.dead) return;
  pet.active = false;
  pet.dead = true;
  pet.hp = 0;
  state.battle.bossParty.petDiedThisFight = true;
  pet.action = "die";
  pet.frame = 0;
  pet.oneShot = true;
  pet.lastTick = now;
  playTaoPetSfx("death", { volume: 0.42, throttleMs: 120 });
  pushBattleLog(`${pet.name} falls.`);
  const steppedUp = refreshBossPartyMeleePositions({ now });
  if (steppedUp) {
    updateBossPartyMeleeAdvance(now);
    pushBattleLog(`${steppedUp.classId} steps up to the front.`);
  }
}

function bossPartyMarkMemberDead(member, now) {
  member.alive = false;
  member.hp = 0;
  member.targetWorldX = null;
  member.meleeAdvanceFromX = null;
  member.meleeAdvanceStartedAt = null;
  member.visualAction = "die";
  member.visualFrame = 0;
  member.visualOneShot = true;
  member.visualLastTick = now;
  pushBattleLog(`${member.classId} falls.`);
  const steppedUp = refreshBossPartyMeleePositions({ now });
  if (steppedUp) {
    updateBossPartyMeleeAdvance(now);
    pushBattleLog(`${steppedUp.classId} steps up to the front.`);
  }
}

function bossPartyAllMembersDead() {
  return !state.battle.bossParty?.members.some((member) => member.alive && member.hp > 0);
}

function bossPartyNextAliveMember() {
  return BOSS_PARTY_ORDER
    .map((classId) => state.battle.bossParty?.members.find((member) => member.classId === classId && member.alive && member.hp > 0))
    .find(Boolean) ?? null;
}

function bossPartyLeaderClassId(party = state.battle.bossParty) {
  return normalizeCharacterId(party?.leaderClassId ?? party?.controlledClassId ?? state.activeCharacterId);
}

function bossPartyLeaderMember(party = state.battle.bossParty) {
  const classId = bossPartyLeaderClassId(party);
  return party?.members.find((member) => member.classId === classId) ?? null;
}

function bossPartyControlledClassId() {
  return bossPartyLeaderClassId();
}

function bossPartyControlledMember(party = state.battle.bossParty) {
  return bossPartyLeaderMember(party);
}

// Where a member's damage numbers float relative to the enemy: controlled member centred,
// assists fanned out to the left/right so all three are visible at once.
function bossPartyDamageTextOffset(classId) {
  const controlledId = bossPartyControlledClassId();
  if (classId === controlledId) return 0;
  const assists = BOSS_PARTY_ORDER.filter((id) => id !== controlledId);
  const index = assists.indexOf(classId);
  if (index === 0) return -BOSS_PARTY_DAMAGE_TEXT_OFFSET;
  if (index >= 1) return BOSS_PARTY_DAMAGE_TEXT_OFFSET;
  return 0;
}

function bossPartyShowEnemyDamage(classId, damage, now = performance.now()) {
  const controlled = classId === bossPartyControlledClassId();
  addCombatText("enemy", damage, controlled ? "damage" : "assistDamage", now, bossPartyDamageTextOffset(classId));
}

function bossPartyShowEnemyMiss(classId, now = performance.now()) {
  addCombatText("enemy", "Miss", "miss", now, bossPartyDamageTextOffset(classId));
}

function bossPartySyncControlledPlayerRef() {
  const party = state.battle.bossParty;
  const leader = bossPartyLeaderMember(party);
  if (!leader) return;
  const leaderClassId = bossPartyLeaderClassId(party);
  state.battle.player = leader;
  state.battle.combatClass = leaderClassId;
  state.activeCharacterId = leaderClassId;
  state.battle.playerX = leader.worldX ?? state.battle.playerX;
  syncBattleCamera();
  state.battle.level = leader.game.progress.level;
  state.battle.experience = leader.game.progress.experience;
  state.battle.gold = leader.inventory.gold;
  state.battle.furyUntil = Number(leader.furyUntil) || 0;
  state.battle.furyBonus = Number(leader.furyBonus) || 0;
  state.game.progress.level = leader.game.progress.level;
  state.game.progress.experience = leader.game.progress.experience;
  state.game.kills = leader.game.kills;
  state.game.zoneKills = leader.game.zoneKills;
  syncBossPartyControlledInventoryToState(leaderClassId);
}

// Live character switching is only offered inside group dungeons (bDD and future group
// content). Boss/KR rooms intentionally keep a fixed controlled character. Switching stays
// available after a floor is cleared (the "finished" victory state) so the player can make
// changes before advancing; it is only disabled once the run is defeated.
function bossPartyCanSwitchControl() {
  const party = state.battle.bossParty;
  if (!party || party.defeated) return false;
  if (!party.active && !party.finished) return false;
  if (!groupDungeonZone(activeZone())) return false;
  return (party.members ?? []).some((member) => member.alive && member.hp > 0);
}

// Swap which party member the player controls, live, without ever risking a character's
// saved data. The historical item-overwrite bug happened when the controlled pointer was
// moved before the outgoing member's live inventory/magic was flushed back into it (a save
// could then copy the previous character's items onto the newly selected character). The
// ordering below is the safety guarantee: FLUSH the outgoing member while live state still
// belongs to it, SWAP the pointers, then LOAD the incoming member into live state. The
// critical section is fully synchronous (no awaits) so no save/auto-save can interleave.
function switchControlledPartyMember(classId) {
  const party = state.battle.bossParty;
  if (!bossPartyCanSwitchControl()) return false;
  const targetClassId = normalizeCharacterId(classId);
  const target = party.members.find((member) => member.classId === targetClassId);
  if (!target || !target.alive || target.hp <= 0) return false;

  const currentClassId = bossPartyControlledClassId();
  if (targetClassId === currentClassId) return false;

  const now = performance.now();

  // 1) FLUSH the outgoing member. state.activeCharacterId / state.inventory / state.magic and
  //    party.leaderClassId all still point at the current member here, so this guarded sync
  //    writes the live data back into the correct member object and nowhere else.
  if (normalizeCharacterId(state.activeCharacterId) === currentClassId) {
    syncBossPartyControlledMemberFromState(currentClassId);
  }
  const outgoing = party.members.find((member) => member.classId === currentClassId) ?? null;

  // Charge/queued-cast state mirrors the controlled class into state.battle; clear the live
  // mirror so a Warrior's pending charge cannot bleed onto a Wizard, etc.
  clearFlamingSwordChargeState(state.battle);
  clearTwinDrakeChargeState(state.battle);
  state.battle.queuedCombatSpellId = null;

  // 2) SWAP. The controlled member is the leader in every sense (rewards, player ref, save),
  //    so both move together to keep all existing leader-keyed logic consistent.
  party.controlledClassId = targetClassId;
  party.leaderClassId = targetClassId;

  // 3) LOAD the incoming member into live state (member -> state is read-only for the member).
  state.activeCharacterId = targetClassId;
  state.battle.combatClass = targetClassId;
  bossPartySyncControlledPlayerRef();
  syncBossPartyControlledRecoveryToState(target);
  normalizeAutoCastSpellsForClass(targetClassId);

  // Persist immediately. The state is now fully consistent for the new controlled member, so
  // this snapshot (and any later auto-save) records each character's own data correctly.
  saveGameState(true);

  // Reset the player sprite/animation to the newly controlled character.
  setPlayerAction("stance", now);
  applyEquippedVisualIndexes();
  void reloadAtlases();
  // Refresh the outgoing member's assist sprite in case equipment changed while controlled.
  if (outgoing) void preloadBossPartyMemberVisualAtlases(outgoing).then(() => render());

  invalidateUi();
  renderCombatSkillBar();
  renderHotbar();
  renderPlayerResourceHud();
  renderGamePanel();
  renderSceneOverlay();
  renderPartySwitchBar();
  render();
  playSfx("ui.button", { volume: 0.35, throttleMs: 80 });
  pushBattleLog(`Now controlling ${targetClassId}.`);
  return true;
}

function partySwitchBarHtml() {
  const party = state.battle.bossParty;
  if (!party?.members?.length) return "";
  const controlledClassId = bossPartyControlledClassId();
  return party.members
    .slice()
    .sort((a, b) => BOSS_PARTY_ORDER.indexOf(a.classId) - BOSS_PARTY_ORDER.indexOf(b.classId))
    .map((member) => {
      const controlled = member.classId === controlledClassId;
      const dead = !member.alive || member.hp <= 0;
      const disabled = controlled || dead ? "disabled" : "";
      const classes = ["party-switch-button"];
      if (controlled) classes.push("controlled");
      if (dead) classes.push("dead");
      const stateLabel = controlled ? "Controlling" : dead ? "Defeated" : "Switch";
      return `
        <button type="button" class="${classes.join(" ")}" data-switch-party-member="${escapeHtml(member.classId)}" ${disabled}
          title="${controlled ? "Currently controlling" : dead ? "Defeated" : `Control ${escapeHtml(member.classId)}`}">
          <span class="party-switch-name">${escapeHtml(member.classId)}</span>
          <span class="party-switch-hp">${stateLabel}</span>
        </button>
      `;
    })
    .join("");
}

function renderPartySwitchBar() {
  if (!els.partySwitchBar) return;
  const party = state.battle.bossParty;
  const shouldShow = bossPartyOnField()
    && !party?.defeated
    && groupDungeonZone(activeZone())
    && (party?.members?.length ?? 0) >= 2;
  if (!shouldShow) {
    if (!els.partySwitchBar.hidden || partySwitchBarSignature) {
      els.partySwitchBar.hidden = true;
      els.partySwitchBar.innerHTML = "";
      partySwitchBarSignature = "";
    }
    return;
  }
  const signature = JSON.stringify({
    controlled: bossPartyControlledClassId(),
    members: party.members.map((member) => `${member.classId}:${member.alive && member.hp > 0 ? "alive" : "dead"}`),
  });
  if (signature === partySwitchBarSignature) return;
  partySwitchBarSignature = signature;
  els.partySwitchBar.hidden = false;
  els.partySwitchBar.innerHTML = partySwitchBarHtml();
}

function finishBossPartyEnemy(now) {
  const party = state.battle.bossParty;
  const enemy = state.battle.enemy;
  if (!party?.active || party.finished) return;
  const entryZone = PROTOTYPE_ZONES.find((entry) => entry.id === party.zoneId) ?? null;
  const isGroupDungeonBoss = groupDungeonBossZone(entryZone);
  party.finished = true;
  party.active = false;
  party.finishedAt = now;
  if (bossDropTableForEnemy(enemy)) {
    const lootClassId = party.leaderClassId ?? state.activeCharacterId;
    awardBossPartyBossKillShare(enemy, now, lootClassId);
  } else {
    awardBossPartyKillShare(now, { enemy });
  }
  if (zoneTracksBossRespawn(party.zoneId ?? state.game.activeZoneId)) {
    setBossRespawn(party.zoneId ?? state.game.activeZoneId);
  }
  freezeBossPartyMembersForAftermath(party, now);
  setEnemyAction("die", false, now);
  playMonsterSfx("death");
  state.showEnemies = true;
  state.battle.running = false;
  state.battle.phase = "victory";
  state.battle.enemyAggro = false;
  state.battle.nextPlayerAttackAt = 0;
  state.battle.nextEnemyAttackAt = 0;
  state.battle.nextEnemySpawnAt = 0;
  clearGroupDungeonRunState();
  clearTwinDrakePendingState();
  state.battle.pendingEnemyStrike = null;
  state.battle.attachedSpellFx = (state.battle.attachedSpellFx ?? []).filter((entry) => entry.spellId !== "TwinDrakeBlade");
  syncBossPartyMembersToCharacters(party, { applyControlled: true });
  persistCharacterGameLocation({
    mode: state.game.mode,
    zoneId: state.game.activeZoneId,
    classIds: bossPartyMemberClassIds(party),
    running: false,
  });
  pushBattleLog(`${enemy.name} is defeated.`);
  if (isGroupDungeonBoss) {
    const nextZone = groupDungeonNextFloorZone(entryZone);
    const respawnMinutes = groupDungeonBossRespawnMinutes(entryZone);
    if (respawnMinutes > 0) {
      pushBattleLog(`${enemy.name} will respawn in ${formatBossRespawnDelay(respawnMinutes)}.`);
    }
    pushBattleLog(nextZone
      ? `Advance to ${nextZone.label} when you are ready.`
      : "Dungeon complete — return to town when you are ready.");
  } else {
    pushBattleLog(`${enemy.name} will respawn in ${formatBossRespawnDelay(bossRoomDef(party.zoneId)?.respawnMinutes ?? BOSS_RESPAWN_MINUTES_STANDARD)}.`);
    pushBattleLog("Return To Town when you are ready.");
  }
  addLootNotice(`${enemy.name} defeated`, "boss");
  gamePanelSignature = "";
  gamePanelDynamicSignature = "";
  battlePanelSignature = "";
  sceneSignature = "";
  saveGameState(true);
}

function finishBossPartyDefeat(now) {
  const party = state.battle.bossParty;
  if (!party?.active || party.finished) return;
  party.finished = true;
  party.active = false;
  party.finishedAt = now;
  party.defeated = true;
  syncBossPartyMembersToCharacters(party, { applyControlled: true });
  state.showEnemies = true;
  state.battle.running = false;
  state.battle.phase = "defeat";
  state.battle.enemyAggro = false;
  state.battle.nextPlayerAttackAt = 0;
  state.battle.nextEnemyAttackAt = 0;
  state.battle.nextEnemySpawnAt = 0;
  setEnemyLocomotion("standing", now);
  setPlayerAction("die", now);
  playSfx("player.death", { volume: 0.58 });
  pushBattleLog("The party has been defeated.");
  pushBattleLog("Return To Town when you are ready.");
  if (groupDungeonZone(activeZone())) clearGroupDungeonRunState();
  persistCharacterGameLocation({
    mode: state.game.mode,
    zoneId: state.game.activeZoneId,
    classIds: bossPartyMemberClassIds(party),
    running: false,
  });
  applyCharacterState(state.activeCharacterId, state.characters[state.activeCharacterId]);
  gamePanelSignature = "";
  battlePanelSignature = "";
  sceneSignature = "";
  saveGameState(true);
}

function bossDropTableForEnemy(enemy = state.battle.enemy) {
  if (!enemy) return null;
  if (isIncarnatedWoomaTaurusEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Incarnated Wooma Taurus"];
  if (isIncarnatedZumaTaurusEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Incarnated Zuma Taurus"];
  if (isWoomaTaurusEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Wooma Taurus"];
  if (isEvilSnakeEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Evil Snake"];
  if (isZumaTaurusEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Zuma Taurus"];
  if (isEvilCentipedeEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Evil Centipede"];
  if (isBoneLordEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Bone Lord"];
  if (isKingScorpionEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["King Scorpion"];
  if (isMinotaurKingEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Minotaur King"];
  if (isYimoogiEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Yimoogi"];
  if (isOmaKingSpiritEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Oma King Spirit"];
  if (isKingHogEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["King Hog"];
  if (isDarkDevilEnemy(enemy)) return BOSS_DROP_TABLE_BY_LABEL["Dark Devil"];
  return null;
}

function rollBossTableDrops(dropTable, awardItem) {
  const added = [];
  const ignored = [];
  if (!dropTable) return { added, ignored };

  const oilCount = Math.max(0, Math.trunc(Number(dropTable.benedictionOils ?? 1)));
  const oil = itemDefinition(BENEDICTION_OIL_ITEM_ID);
  if (oil && oilCount > 0) {
    for (let i = 0; i < oilCount; i += 1) awardItem(oil, added, ignored);
  }

  let poolDropped = false;
  for (const entry of dropTable.items) {
    if (Math.random() >= entry.chance) continue;
    const item = itemDefinition(entry.id);
    if (!item) continue;
    awardItem(item, added, ignored);
    poolDropped = true;
  }

  if (!poolDropped && dropTable.items.length) {
    const entry = dropTable.items[Math.floor(Math.random() * dropTable.items.length)];
    const item = itemDefinition(entry.id);
    if (item) awardItem(item, added, ignored);
  }

  return { added, ignored };
}

function rollBossPartyDrops(member, enemy = state.battle.enemy) {
  if (!member) return { added: [], ignored: [] };
  syncBossPartyInventoryCapacityFromState(member.classId);
  const dropTable = bossDropTableForEnemy(enemy);
  if (!dropTable) return { added: [], ignored: [] };
  return rollBossTableDrops(dropTable, (item, added, ignored) => {
    addBossPartyZoneDropItem(member, item, added, ignored);
  });
}

function rollBossSoloDrops(enemy = state.battle.enemy) {
  syncInventoryCapacity();
  ensureInventorySlots();
  return rollBossTableDrops(bossDropTableForEnemy(enemy), (item, added, ignored) => {
    addZoneDropItem(item, added, ignored);
  });
}

function bossPartyAliveRewardMembers(party = state.battle.bossParty) {
  return (party?.members ?? []).filter((member) => member.alive && member.hp > 0);
}

function splitPartyRewardAmount(total, memberCount) {
  const count = Math.max(1, Math.trunc(Number(memberCount) || 0));
  return Math.max(0, Math.floor(Math.max(0, Math.trunc(Number(total) || 0)) / count));
}

function applyBossPartyMemberKillReward(member, {
  xp,
  gold,
  drops = { added: [], ignored: [] },
  now = performance.now(),
  includeItems = false,
  zoneId = state.battle.bossParty?.zoneId ?? state.game.activeZoneId,
}) {
  if (!member) return;
  const leveledTo = applyBossPartyExperienceReward(member, xp, now);
  member.inventory.gold += gold;
  member.game.progress.gold = member.inventory.gold;
  member.game.kills += 1;
  member.game.zoneKills += 1;
  if (includeItems && zoneId) member.game.dropPity[zoneId] = 0;
  member.game.lastReward = { xp, gold, drops: drops.added };
  member.game.recentLoot = [
    `+${gold} gold`,
    ...leveledTo.map((level) => `Level ${level}`),
    ...drops.added.map((item) => `Found ${item.name}`),
    ...drops.ignored.map((item) => `No room for ${item.name}`),
    ...member.game.recentLoot,
  ].slice(0, 6);
  pushBattleLog(`${member.classId} gained ${xp} XP and ${gold} gold.`);
  if (includeItems) {
    for (const item of drops.added) pushBattleLog(`${member.classId} received ${item.name}.`);
    for (const item of drops.ignored) pushBattleLog(`${member.classId} had no room for ${item.name}.`);
  } else {
    for (const item of drops.added) pushBattleLog(`${member.classId} found ${item.name}.`);
    for (const item of drops.ignored) pushBattleLog(`${member.classId} had no room for ${item.name}.`);
  }
  if (member.classId === bossPartyControlledClassId()) {
    if (xp > 0) addLootNotice(`+${xp} XP`, "level");
    if (gold > 0) addLootNotice(`+${gold} gold`, "gold");
    for (const item of drops.added) addLootNotice(`Found ${item.name}`, "item");
    for (const item of drops.ignored) addLootNotice(`Inventory full: ${item.name}`, "full");
    for (const level of leveledTo) addLootNotice(`Level ${level}`, "level");
  }
}

function awardBossPartyKillShare(now = performance.now(), options = {}) {
  const party = state.battle.bossParty;
  const zone = PROTOTYPE_ZONES.find((entry) => entry.id === party?.zoneId) ?? activeZone();
  const enemy = options.enemy ?? state.battle.enemy;
  if (!party || !zone || !enemy) return;

  const recipients = bossPartyAliveRewardMembers(party);
  if (!recipients.length) return;
  const shareCount = recipients.length;
  const xpPerShare = splitPartyRewardAmount(enemy.experience ?? 0, shareCount);

  const reward = zone.rewards ?? { gold: [1, 2] };
  const totalGold = randomInt(reward.gold[0], reward.gold[1]);
  const goldPerShare = splitPartyRewardAmount(totalGold, shareCount);

  for (const member of recipients) {
    const xp = adjustedKillExperience(xpPerShare, member.game.progress.level, enemy.level ?? 0);
    const drops = rollBossPartyZoneDrops(member, zone, enemy);
    applyBossPartyMemberKillReward(member, { xp, gold: goldPerShare, drops, now, zoneId: zone.id });
  }
}

function awardBossPartyBossKillShare(enemy, now = performance.now(), lootClassId) {
  const party = state.battle.bossParty;
  const dropTable = bossDropTableForEnemy(enemy);
  if (!party || !enemy || !dropTable) return;

  const recipients = bossPartyAliveRewardMembers(party);
  if (!recipients.length) return;
  const shareCount = recipients.length;
  const xpPerShare = splitPartyRewardAmount(enemy.experience ?? 0, shareCount);
  const goldPerShare = splitPartyRewardAmount(dropTable.gold, shareCount);
  const zoneId = party.zoneId ?? state.game.activeZoneId;

  for (const member of recipients) {
    const xp = adjustedKillExperience(xpPerShare, member.game.progress.level, enemy.level ?? 0);
    const includeItems = member.classId === lootClassId;
    const drops = includeItems ? rollBossPartyDrops(member, enemy) : { added: [], ignored: [] };
    applyBossPartyMemberKillReward(member, {
      xp,
      gold: goldPerShare,
      drops,
      now,
      includeItems,
      zoneId,
    });
  }
}

function applyBossPartyExperienceReward(member, xp, now) {
  const levels = [];
  member.game.progress.experience += xp;
  let nextLevelXp = xpForNextLevel(member.game.progress.level);
  while (Number.isFinite(nextLevelXp) && member.game.progress.experience >= nextLevelXp) {
    member.game.progress.experience -= nextLevelXp;
    member.game.progress.level += 1;
    member.level = member.game.progress.level;
    levels.push(member.level);
    const stats = characterSnapshotTotalStats(member.classId, {
      inventory: member.inventory,
      magic: member.magic,
      game: member.game,
      battle: {},
    });
    Object.assign(member, stats, { hp: stats.maxHp, mp: stats.maxMp });
    nextLevelXp = xpForNextLevel(member.game.progress.level);
    if (member.classId === bossPartyControlledClassId()) triggerLevelUpFx(now, member.level);
  }
  return levels;
}

function rollBossPartyZoneDrops(member, zone, enemy) {
  const added = [];
  const ignored = [];
  const candidates = zoneDropCandidates(zone, enemy);
  for (const { item, chance } of candidates) {
    if (Math.random() >= chance) continue;
    addBossPartyZoneDropItem(member, item, added, ignored);
  }
  updateBossPartyDropPity(member, zone, candidates, added, ignored);
  return { added, ignored };
}

function updateBossPartyDropPity(member, zone, candidates, added, ignored) {
  if (!zone || !candidates.length) return;
  if (added.length || ignored.length) {
    member.game.dropPity[zone.id] = 0;
    return;
  }
  const dryKills = Math.max(0, Math.trunc(Number(member.game.dropPity[zone.id]) || 0)) + 1;
  member.game.dropPity[zone.id] = dryKills;
  if (dryKills < DROP_PITY_KILLS) return;
  const forced = weightedDropCandidate(candidates);
  if (!forced) return;
  addBossPartyZoneDropItem(member, forced.item, added, ignored);
  member.game.dropPity[zone.id] = 0;
}

function addBossPartyZoneDropItem(member, item, added, ignored) {
  // Controlled character uses state.inventory during boss fights; member-only drops
  // were wiped when syncing state back over the member at fight end.
  if (member?.classId === state.activeCharacterId) {
    return addZoneDropItem(item, added, ignored);
  }
  syncBossPartyInventoryCapacityFromState(member?.classId);
  if (!bossPartyHasInventorySpaceFor(item?.id, member)) {
    ignored.push(item);
    return false;
  }
  const before = bossPartyInventoryItemQuantity(member, item.id);
  const entries = bossPartyAddInventoryItem(member, item.id, 1);
  const after = bossPartyInventoryItemQuantity(member, item.id);
  if (entries.length && after > before) {
    added.push(item);
    return true;
  }
  ignored.push(item);
  return false;
}

function bossPartyHasInventorySpaceFor(itemId, member) {
  if (!member?.inventory) return false;
  syncInventoryCapacity(member.inventory);
  ensureBossPartyInventorySlots(member);
  const item = itemDefinition(itemId);
  if (!item) return false;
  if (isStackableItem(item)) {
    const maxStack = maxItemStack(item);
    if (bossPartyCarriedInventoryEntries(member).some((entry) => entry.itemId === itemId && entry.quantity < maxStack)) {
      return true;
    }
  }
  return bossPartyInventoryEntries(member).length < member.inventory.maxSlots;
}

function ensureBossPartyInventorySlots(member) {
  const inventory = member?.inventory;
  if (!inventory) return;
  syncInventoryCapacity(inventory);
  const hotbarIds = new Set((member.hotbar?.slots ?? []).filter(Boolean));
  const equippedIds = new Set(Object.values(inventory.equipment ?? {}).filter(Boolean));
  const used = new Set();
  for (const entry of inventory.items ?? []) {
    if (equippedIds.has(entry.id) || hotbarIds.has(entry.id)) {
      entry.slot = null;
      continue;
    }
    if (Number.isInteger(entry.slot) && entry.slot >= 0 && entry.slot < inventory.maxSlots && !used.has(entry.slot)) {
      used.add(entry.slot);
      continue;
    }
    entry.slot = null;
  }
  for (const entry of inventory.items ?? []) {
    if (equippedIds.has(entry.id) || hotbarIds.has(entry.id) || entry.slot !== null) continue;
    for (let slot = 0; slot < inventory.maxSlots; slot++) {
      if (used.has(slot)) continue;
      entry.slot = slot;
      used.add(slot);
      break;
    }
  }
}

function bossPartyAddInventoryItem(member, itemId, quantity = 1) {
  syncBossPartyInventoryCapacityFromState(member?.classId);
  ensureBossPartyInventorySlots(member);
  const item = itemDefinition(itemId);
  if (!item) return [];
  const added = [];
  let remaining = Math.max(1, Math.trunc(Number(quantity) || 1));
  const maxStack = maxItemStack(item);
  while (remaining > 0) {
    if (isStackableItem(item)) {
      const existing = bossPartyCarriedInventoryEntries(member).find((entry) => entry.itemId === itemId && entry.quantity < maxStack);
      if (existing) {
        const add = Math.min(remaining, maxStack - existing.quantity);
        existing.quantity += add;
        remaining -= add;
        added.push(existing);
        continue;
      }
      const add = Math.min(remaining, maxStack);
      if (bossPartyInventoryUsedSlots(member) >= member.inventory.maxSlots) break;
      const entry = bossPartyCreateInventoryEntry(member, itemId, add);
      member.inventory.items.push(entry);
      added.push(entry);
      remaining -= add;
      continue;
    }
    if (bossPartyInventoryUsedSlots(member) >= member.inventory.maxSlots) break;
    const entry = bossPartyCreateInventoryEntry(member, itemId, 1);
    member.inventory.items.push(entry);
    added.push(entry);
    remaining -= 1;
  }
  return added;
}

function bossPartyCreateInventoryEntry(member, itemId, quantity) {
  const slot = nextFreeSlotInInventoryState(member.inventory);
  const entry = {
    id: `item-${member.inventory.nextInstanceId}`,
    itemId,
    quantity,
    slot: Number.isInteger(slot) ? slot : null,
    ...normalizeInventoryEntryFields({}, itemDefinition(itemId)),
  };
  member.inventory.nextInstanceId += 1;
  return entry;
}

function bossPartyInventoryItemQuantity(member, itemId) {
  return member.inventory.items
    .filter((entry) => entry.itemId === itemId && !bossPartyIsEquippedEntry(member, entry.id))
    .reduce((sum, entry) => sum + Math.max(1, Math.trunc(Number(entry.quantity) || 1)), 0);
}

function bossPartyInventoryEntries(member) {
  const hotbarIds = new Set((member.hotbar?.slots ?? []).filter(Boolean));
  return member.inventory.items.filter((entry) => !bossPartyIsEquippedEntry(member, entry.id) && !hotbarIds.has(entry.id));
}

function bossPartyInventoryUsedSlots(member) {
  return bossPartyInventoryEntries(member).length;
}

function bossPartyCarriedInventoryEntries(member) {
  return member.inventory.items.filter((entry) => !bossPartyIsEquippedEntry(member, entry.id));
}

function bossPartyInventoryEntryById(member, entryId) {
  return member.inventory.items.find((entry) => entry.id === entryId) ?? null;
}

function bossPartyIsEquippedEntry(member, entryId) {
  return Object.values(member.inventory.equipment ?? {}).includes(entryId);
}

function bossPartyConsumeOneInventoryUnit(member, entryId) {
  const entry = bossPartyInventoryEntryById(member, entryId);
  if (!entry || bossPartyIsEquippedEntry(member, entry.id)) return false;
  entry.quantity -= 1;
  if (entry.quantity <= 0) {
    member.hotbar.slots = member.hotbar.slots.map((id) => id === entry.id ? null : id);
    member.inventory.items = member.inventory.items.filter((candidate) => candidate.id !== entry.id);
  }
  return true;
}

function bossPartyHotbarEntryAtSlot(member, slot) {
  const entryId = member.hotbar?.slots?.[slot] ?? null;
  return entryId ? bossPartyInventoryEntryById(member, entryId) : null;
}

function bossPartyAutoUsePotions(member, now) {
  if (!member.alive || member.hp <= 0) return false;
  if (member.classId === bossPartyControlledClassId()) {
    const used = updateAutoPotions(now);
    if (used) {
      syncBossPartyControlledInventoryFromState(member.classId);
      syncBossPartyControlledRecoveryFromState(member);
    }
    return used;
  }
  let used = false;
  for (const kind of ["hp", "mp"].sort((a, b) => bossPartyResourceRatio(member, a) - bossPartyResourceRatio(member, b))) {
    if (bossPartyResourceRatio(member, kind) >= AUTO_POTION_THRESHOLD) continue;
    if ((member.autoPotionReadyAt?.[kind] ?? 0) > now) continue;
    if (kind === "hp" && (member.potHealthAmount ?? 0) > 0) continue;
    if (kind === "mp" && (member.potManaAmount ?? 0) > 0) continue;
    const candidate = autoPotionSlots()
      .map((slot) => {
        const entry = bossPartyHotbarEntryAtSlot(member, slot);
        const item = entry ? itemDefinition(entry.itemId) : null;
        return { entry, item, restore: potionRestoreAmount(item, kind), slot };
      })
      .filter((candidate) => candidate.entry && candidate.restore > 0)
      .sort((a, b) => b.restore - a.restore || a.slot - b.slot)[0];
    if (!candidate || !bossPartyConsumeOneInventoryUnit(member, candidate.entry.id)) continue;
    const hpRestore = potionRestoreAmount(candidate.item, "hp");
    const mpRestore = potionRestoreAmount(candidate.item, "mp");
    if (potionRestoreMode(candidate.item) === "instant") {
      member.hp = Math.min(member.maxHp, member.hp + hpRestore);
      member.mp = Math.min(member.maxMp, member.mp + mpRestore);
    } else {
      member.potHealthAmount = Math.min(65535, (member.potHealthAmount ?? 0) + hpRestore);
      member.potManaAmount = Math.min(65535, (member.potManaAmount ?? 0) + mpRestore);
      member.potTickAt = member.potTickAt || now + CRYSTAL_POT_DELAY_MS;
    }
    member.autoPotionReadyAt[kind] = now + AUTO_POTION_COOLDOWN_MS;
    pushBattleLog(`${member.classId} auto used ${candidate.item.name}.`);
    used = true;
  }
  return used;
}

function bossPartyResourceRatio(member, kind) {
  const max = kind === "hp" ? member.maxHp : member.maxMp;
  return max > 0 ? Math.max(0, Math.min(1, (Number(member[kind]) || 0) / max)) : 1;
}

function updateBossPartyMemberPotionRegen(member, now) {
  if (!member.alive || member.hp <= 0 || (!member.potHealthAmount && !member.potManaAmount)) return false;
  if (!member.potTickAt) member.potTickAt = now + CRYSTAL_POT_DELAY_MS;
  let changed = false;
  let steps = 0;
  while (now >= member.potTickAt && steps < 20 && (member.potHealthAmount > 0 || member.potManaAmount > 0)) {
    steps += 1;
    member.potTickAt += CRYSTAL_POT_DELAY_MS;
    const tickAmount = 5 + Math.floor((member.game.progress.level ?? 1) / 10);
    if (member.potHealthAmount > 0) {
      const amount = Math.min(tickAmount, member.potHealthAmount);
      member.potHealthAmount -= amount;
      member.hp = Math.min(member.maxHp, member.hp + amount);
      changed = true;
    }
    if (member.potManaAmount > 0) {
      const amount = Math.min(tickAmount, member.potManaAmount);
      member.potManaAmount -= amount;
      member.mp = Math.min(member.maxMp, member.mp + amount);
      changed = true;
    }
  }
  if (member.potHealthAmount <= 0 && member.potManaAmount <= 0) member.potTickAt = 0;
  return changed;
}

function addBossPartyMemberCombatText(member, text, kind, now = performance.now()) {
  if (!member || suppressSimulationRender) return;
  const bounds = bossPartyMemberFrameBounds(member);
  state.battle.floatingTexts.push({
    id: `${now}-${Math.random()}`,
    anchor: "player",
    text: String(text),
    kind,
    x: bounds.centerX,
    y: bounds.topY - 16,
    createdAt: now,
  });
  state.battle.floatingTexts = state.battle.floatingTexts.slice(-12);
}

function updateBossPartyMemberHealRegen(member, now) {
  if (!member || member.hp <= 0) return false;

  let changed = false;
  if (member.hp >= member.maxHp && member.healAmount > 0) {
    member.healAmount = 0;
    member.healTickAt = 0;
    return true;
  }

  if ((member.healAmount ?? 0) <= 0) {
    member.healTickAt = 0;
    return changed;
  }

  if (!member.healTickAt) {
    member.healTickAt = now + CRYSTAL_HEAL_DELAY_MS;
    return changed;
  }

  let steps = 0;
  const healLevel = crystalHealRegenLevel(member);
  while (now >= member.healTickAt && steps < 20 && member.healAmount > 0 && member.hp > 0) {
    const tickAt = member.healTickAt;
    member.healTickAt += CRYSTAL_HEAL_DELAY_MS;
    steps += 1;
    const amount = Math.min(crystalHealRegenTickAmount(member.healAmount, healLevel), member.healAmount);
    member.healAmount -= amount;
    const before = member.hp;
    member.hp = Math.min(member.maxHp, member.hp + amount);
    const applied = member.hp - before;
    if (applied > 0) addBossPartyMemberCombatText(member, `+${applied} HP`, "heal", tickAt);
    if (member.hp >= member.maxHp) member.healAmount = 0;
    changed = true;
  }

  if (steps >= 20 && member.healAmount > 0) member.healTickAt = now + CRYSTAL_HEAL_DELAY_MS;
  if (member.healAmount <= 0) member.healTickAt = 0;
  return changed;
}

function bossPartyPoisonCandidate(member, enemy, now) {
  const entries = bossPartyCarriedInventoryEntries(member).filter((entry) => isPoisonItem(itemDefinition(entry.itemId)));
  const green = entries.find((entry) => poisonItemKind(itemDefinition(entry.itemId)) === "green") ?? null;
  const yellow = entries.find((entry) => poisonItemKind(itemDefinition(entry.itemId)) === "yellow") ?? null;
  if (green && poisonNeedsApply(enemy, "green", now)) return green;
  if (yellow && poisonNeedsApply(enemy, "yellow", now)) return yellow;
  return null;
}

function bossPartyAmuletCandidate(member) {
  return bossPartyCarriedInventoryEntries(member).find((entry) => isTaoistAmuletItem(itemDefinition(entry.itemId))) ?? null;
}

function bossPartyAmuletInventoryCount(member, shape = 0) {
  return bossPartyCarriedInventoryEntries(member)
    .filter((entry) => {
      const item = itemDefinition(entry.itemId);
      return isTaoistAmuletItem(item) && Math.max(0, Math.trunc(Number(item.shape) || 0)) === shape;
    })
    .reduce((sum, entry) => sum + Math.max(1, Math.floor(Number(entry.quantity) || 1)), 0);
}

function syncBossPartyMembersToCharacters(party, options = {}) {
  if (!party?.members?.length) return;
  const leaderClassId = bossPartyLeaderClassId(party);
  if (normalizeCharacterId(state.activeCharacterId) === leaderClassId) {
    syncBossPartyControlledMemberFromState(leaderClassId);
  }
  for (const member of party.members) {
    const character = state.characters[member.classId] ?? createDefaultCharacterState(member.classId);
    character.inventory = cloneInventoryState(member.inventory);
    character.hotbar = cloneHotbarState(member.hotbar);
    character.magic = cloneMagicState(member.magic);
    character.game = {
      ...character.game,
      ...member.game,
      mode: state.game.mode,
      activeZoneId: state.game.activeZoneId,
      progress: { ...member.game.progress, gold: member.inventory.gold },
      recentLoot: [...(member.game.recentLoot ?? [])],
      dropPity: { ...(member.game.dropPity ?? {}) },
      bossRespawns: { ...accountBossRespawns() },
      bossKills: { ...accountBossKills() },
    };
    character.battle = {
      running: false,
      paused: false,
      playerHp: member.hp > 0 ? member.hp : 0,
      playerMp: Math.max(0, member.mp),
      potHealthAmount: Math.max(0, member.potHealthAmount ?? 0),
      potManaAmount: Math.max(0, member.potManaAmount ?? 0),
      healAmount: Math.max(0, member.healAmount ?? 0),
    };
    state.characters[member.classId] = character;
  }
  persistCharacterGameLocation({
    mode: state.game.mode,
    zoneId: state.game.activeZoneId,
    classIds: party.members.map((member) => member.classId),
    running: state.battle.running,
  });
  if (options.applyControlled) {
    const applyCharacter = state.characters[leaderClassId];
    if (applyCharacter) applyCharacterState(leaderClassId, applyCharacter);
  }
  state.showEnemies = true;
}

function updateBattle(now) {
  const battle = state.battle;
  if (battle.bossParty?.finished) {
    updateBossPartyAftermath(now);
    return;
  }
  if (!battle.running || !battle.player) return;
  if (battle.bossParty?.active) {
    updateBossPartyBattle(now);
    return;
  }
  if (!battle.enemy) return;
  if (battle.player.hp <= 0) return;

  if (isTrainingRoomCombat()) {
    updateTrainingRoomBattle(now);
    return;
  }

  updatePendingEnemyStrike(now);
  updatePendingImpact(now);
  updatePendingPetAttack(now);
  updatePendingPoison(now);
  updatePendingDefenceBuff(now);
  updatePendingUltimateEnhancer(now);
  updateDefenceBuffFx(now);
  updatePendingTwinDrakeHits(now);
  updateAttachedSpellFx(now);
  updatePendingTaoPet(now);
  updateLaneMotion(now);
  updateGroundSpellEffects(now);
  updateMapLightning(now);
  updateCombatantPoisons(now);
  updateEnemyPoisons(now);
  if (battle.enemy.hp <= 0 || battle.phase !== "engaged") return;

  updateWarriorChargeExpiry(now);
  if (maybeCastWizardDefenceBuff(now)) return;
  if (maybeCastTaoistDefenceBuffs(now)) return;
  if (maybeCastTaoistUltimateEnhancer(now)) return;
  if (maybeCastTaoistSummonSkeleton(now)) return;

  if (battle.combatClass === "Taoist" && taoistPetCanTank() && now >= battle.nextPlayerAttackAt) {
    const acted = taoistPetSupportAttack(now);
    battle.nextPlayerAttackAt = now + (acted
      ? consumeLastPlayerAttackCooldown(now)
      : TAOIST_COMBAT_POLL_MS);
  } else if (canPlayerAttack() && !combatantParalyzed(battle.player) && now >= battle.nextPlayerAttackAt) {
    if (playerAttack(now)) {
      battle.nextPlayerAttackAt = now + consumeLastPlayerAttackCooldown(now);
    }
  }

  if (battle.enemy.hp <= 0 || battle.phase !== "engaged") return;
  if (maybeAutoWarriorCharge(now)) return;
  maybeCastTaoistSoulFireBall(now);
  updateTaoistPetAttack(now);
  if (battle.enemy.hp <= 0 || battle.phase !== "engaged") return;

  if (canEnemyAttack() && now >= battle.nextEnemyAttackAt && enemyAttack(now)) {
    battle.nextEnemyAttackAt = now + effectiveEnemyAttackMs(battle.enemy, now);
  }
}

function updateLaneMotion(now) {
  const battle = state.battle;
  const dt = Math.min(120, Math.max(0, now - (battle.lastMotionAt || now))) / 1000;
  battle.lastMotionAt = now;

  if (isRoomOnlyZone()) {
    ensureMapStampArenaLock();
    battle.phase = "idle";
    battle.running = false;
    setPlayerLocomotion("standing", now);
    const lockX = battle.lockedArenaWorldX;
    if (lockX != null) battle.cameraX = lockX - playerScreenX();
    return;
  }

  if (battle.phase === "victory") {
    if (now >= battle.nextEnemySpawnAt) spawnNextEnemy(now);
    return;
  }

  if (!state.showEnemies) {
    battle.phase = "advance";
    advancePlayerTravel(now, dt);
    battle.cameraX = battle.playerX - playerScreenX();
    return;
  }

  const distance = enemyDistance();
  const playerRange = playerAttackRange();
  const engageRange = playerEngageRange(now);
  if (battle.enemy.hp > 0 && distance <= engageRange) {
    if (battle.phase !== "engaged") ensureMapStampArenaLock();
    battle.phase = "engaged";
  }

  if (battle.phase === "advance") {
    advancePlayerTravel(now, dt);
    setEnemyLocomotion("standing", now);
  } else if (battle.phase === "engaged") {
    if (taoistPetCanTank() && !isPlayerOneShotAction()) {
      setPlayerLocomotion("stance", now);
    } else if (distance > playerRange && !isPlayerOneShotAction() && !wizardHoldsCombatPosition()) {
      battle.playerX += LANE.playerSpeed * dt;
      setPlayerLocomotion("walking", now);
    } else if (!isPlayerOneShotAction()) {
      setPlayerLocomotion("stance", now);
    }

    if (
      battle.enemyRevealed
      && !isTrainingDummyEnemy(battle.enemy)
      && (taoistPetCanTank() || distance <= playerRange || wizardHoldsCombatPosition())
    ) battle.enemyAggro = true;
    const targetDistance = enemyTargetDistance();
    if (
      !isTrainingDummyEnemy(battle.enemy)
      && !enemyBossIsStationary(battle.enemy)
      && battle.enemyAggro
      && targetDistance > LANE.enemyRange
      && !isEnemyOneShotAction()
    ) {
      const speed = enemyAdvanceSpeed(battle.enemy, LANE.enemySpeed, now);
      if (speed > 0) {
        battle.enemyX -= speed * dt;
        setEnemyLocomotion("walking", now);
      } else {
        setEnemyLocomotion("standing", now);
      }
    } else if (!isEnemyOneShotAction() && battle.enemy.hp > 0) {
      setEnemyLocomotion("standing", now);
    }

    if (!battle.nextPlayerAttackAt && canPlayerAttack()) battle.nextPlayerAttackAt = now;
    if (!battle.nextEnemyAttackAt && canEnemyAttack()) {
      battle.nextEnemyAttackAt = now + effectiveEnemyAttackMs(battle.enemy, now);
    }
  }

  syncBattleCamera();
  if (state.game.mode === "zone") {
    state.game.distance = Math.max(state.game.distance, Math.max(0, battle.playerX));
  }
}

function advancePlayerTravel(now, dt) {
  const action = travelAction(now);
  const speed = action === "running" ? LANE.runSpeed : LANE.playerSpeed;
  state.battle.playerX += speed * dt;
  setPlayerLocomotion(action, now);
}

function travelAction(now) {
  if (state.continuousWalk) return "walking";
  const battle = state.battle;
  const travelled = battle.playerX - (battle.travelStartedX ?? battle.playerX);
  return travelled >= TRAVEL_WALK_DISTANCE ? "running" : "walking";
}

function playerAttack(now) {
  state.battle.enemyAggro = true;
  if (state.battle.combatClass === "Wizard") {
    wizardAttack(now);
    return true;
  }
  if (state.battle.combatClass === "Taoist") {
    taoistAttack(now);
    return true;
  }
  return warriorAttack(now);
}

function consumeLastPlayerAttackCooldown(now) {
  const fallback = playerAttackDelayMs(now);
  const pending = Math.trunc(Number(state.battle.lastPlayerAttackCooldownMs) || 0);
  state.battle.lastPlayerAttackCooldownMs = 0;
  if (pending <= 0) return fallback;
  return Math.max(1, pending);
}

function isWarriorChargeSkill(skill) {
  return WARRIOR_CHARGE_SKILL_IDS.has(skill?.id);
}

function twinDrakeAutoCastActive(learned) {
  return Boolean(learned?.autoCast);
}

function setWarriorSpellCastReadyAt(skill, learned, now) {
  if (skill?.id === "TwinDrakeBlade" && twinDrakeAutoCastActive(learned)) {
    learned.castReadyAt = 0;
    return;
  }
  learned.castReadyAt = now + spellDelayMs(skill, learned);
}

function bossPartySetWarriorSpellCastReadyAt(member, skill, learned, now) {
  if (!member || !skill || !learned) return;
  setWarriorSpellCastReadyAt(skill, learned, now);
  if (member.classId !== bossPartyControlledClassId()) return;
  const liveLearned = state.magic.learned?.[skill.id];
  if (liveLearned) liveLearned.castReadyAt = learned.castReadyAt;
}

function bossPartySpellCastReadyAt(member, spellId, learned = null) {
  const memberLearned = learned ?? member?.magic?.learned?.[spellId];
  const memberReady = Math.max(0, Number(memberLearned?.castReadyAt) || 0);
  if (!member || member.classId !== bossPartyControlledClassId()) return memberReady;
  const stateReady = Math.max(0, Number(state.magic.learned?.[spellId]?.castReadyAt) || 0);
  return Math.max(memberReady, stateReady);
}

function bossPartySpellOnCooldown(member, skill, learned, now) {
  if (!skill || !learned) return false;
  if (skill.id === "TwinDrakeBlade" && twinDrakeAutoCastActive(learned)) return false;
  return bossPartySpellCastReadyAt(member, skill.id, learned) > now;
}

function warriorSpellCastOnCooldown(skill, learned, now) {
  if (skill?.id === "TwinDrakeBlade" && twinDrakeAutoCastActive(learned)) return false;
  return (learned?.castReadyAt ?? 0) > now;
}

function warriorTwinDrakeReady() {
  if (state.battle.bossParty?.active) {
    return Boolean(bossPartyControlledMember()?.twinDrakeReady);
  }
  return Boolean(state.battle.twinDrakeReady);
}

function enemyStunned(enemy, now = performance.now()) {
  return Number(enemy?.stunnedUntil) > now;
}

function scaleEnemyPhysicalDamage(damage, enemy, now = performance.now()) {
  const scaled = Math.trunc(Math.max(0, Number(damage) || 0) * (enemyStunned(enemy, now) ? 1.5 : 1));
  return Math.max(0, scaled);
}

function tryApplyTwinDrakeStun(enemy, learned, now = performance.now()) {
  if (!enemy || enemy.hp <= 0 || !learned) return false;
  const level = Math.max(0, Math.min(3, Number(learned.level) || 0));
  const playerLevel = Math.max(1, Math.trunc(Number(state.battle.player?.level ?? state.game.progress.level) || 1));
  const enemyLevel = Math.max(0, Math.trunc(Number(enemy?.level) || 0));
  if (enemyLevel >= playerLevel + 10) return false;
  if (randomInt(0, 19) > level + 1) return false;
  const durationMs = (2 + level) * 1000;
  enemy.stunnedUntil = Math.max(Number(enemy.stunnedUntil) || 0, now + durationMs);
  pushBattleLog(`${enemy.name} is stunned.`);
  return true;
}

function playTwinDrakeBladeSfx(options = {}) {
  return playSpellSfx("TwinDrakeBlade", "cast", options);
}

function playWarriorSpellSwingSfx(skill, options = {}) {
  if (!skill || skill.id === BASIC_ATTACK_SKILL.id) return false;
  if (skill.id === "TwinDrakeBlade") return playTwinDrakeBladeSfx(options);
  return playSpellSfx(skill.id, "attack", options) || playSpellSfx(skill.id, "cast", options);
}

function warriorSkillFxLayers(spellId, phase = "attack") {
  const atlas = state.warriorSkillAtlases[spellId];
  if (!atlas?.layers?.length) return [];
  if (spellId === "TwinDrakeBlade") {
    if (phase === "charge") return atlas.layers.slice(0, 1);
    if (phase === "swing") return atlas.layers.slice(1);
  }
  return atlas.layers;
}

function warriorChargeFxDurationMs(spellId) {
  if (spellId === "TwinDrakeBlade") {
    const layer = warriorSkillFxLayers(spellId, "charge")[0];
    if (layer?.frames?.length) return layer.frames.length * layer.interval;
    return CRYSTAL_TWIN_DRAKE_CHARGE_FX_MS;
  }
  return CRYSTAL_TWIN_DRAKE_CHARGE_FX_MS;
}

function attachedSpellFxAnchor(entry) {
  if (entry?.memberClassId) {
    const party = state.battle.bossParty;
    const member = party?.members?.find((candidate) => candidate.classId === entry.memberClassId);
    if (member) {
      return {
        x: Math.floor((member.worldX ?? state.battle.playerX) - state.battle.cameraX),
        y: Math.floor(state.stageHeight * LANE.y),
      };
    }
  }
  return combatAnchor("player");
}

function queueAttachedSpellFx(spellId, options = {}) {
  const now = options.now ?? performance.now();
  const layerStart = Math.max(0, Math.trunc(Number(options.layerStart) || 0));
  const layerEnd = options.layerEnd == null
    ? layerStart + 1
    : Math.max(layerStart + 1, Math.trunc(Number(options.layerEnd) || 0));
  const durationMs = Math.max(1, Math.trunc(Number(options.durationMs) || warriorChargeFxDurationMs(spellId)));
  const battle = state.battle;
  battle.attachedSpellFx = [
    ...(battle.attachedSpellFx ?? []),
    {
      spellId,
      memberClassId: options.memberClassId ?? null,
      startedAt: now,
      expiresAt: now + durationMs,
      layerStart,
      layerEnd,
    },
  ].slice(-12);
}

function twinDrakeChargeFxDurationMs() {
  const chargeLayer = warriorSkillFxLayers("TwinDrakeBlade", "charge")[0];
  if (chargeLayer?.frames?.length) {
    return chargeLayer.frames.length * Math.max(1, Number(chargeLayer.interval) || 83);
  }
  return CRYSTAL_TWIN_DRAKE_CHARGE_FX_MS;
}

function beginTwinDrakeChargeFx(target, now) {
  const durationMs = twinDrakeChargeFxDurationMs();
  target.twinDrakeChargeFxStartedAt = now;
  target.twinDrakeChargeFxUntil = now + durationMs;
}

function spellFxLayerFrameIndex(layer, startedAt, now = performance.now()) {
  const interval = Math.max(1, Number(layer.interval) || 83);
  const frameCount = Math.max(1, layer.frames?.length ?? 1);
  const layerT = now - startedAt - (layer.delayMs ?? 0);
  const duration = frameCount * interval;
  if (layerT < 0 || layerT >= duration) return -1;
  return Math.min(frameCount - 1, Math.floor(layerT / interval));
}

function twinDrakeChargeFxEntries(now = performance.now()) {
  const entries = [];
  const battle = state.battle;

  const pushEntry = (anchor, startedAt) => {
    entries.push({ anchor, startedAt: Number(startedAt) || 0 });
  };

  if (!battle.bossParty?.active) {
    if (now < Number(battle.twinDrakeChargeFxUntil)) {
      pushEntry(combatAnchor("player"), battle.twinDrakeChargeFxStartedAt);
    }
  }

  for (const member of battle.bossParty?.members ?? []) {
    if (now < Number(member.twinDrakeChargeFxUntil)) {
      pushEntry(attachedSpellFxAnchor({ memberClassId: member.classId }), member.twinDrakeChargeFxStartedAt);
    }
  }

  return entries;
}

function queueWarriorChargeFx(spellId, memberClassId, now) {
  if (spellId === "TwinDrakeBlade") return;
  queueAttachedSpellFx(spellId, {
    now,
    memberClassId,
    layerStart: 0,
    layerEnd: 1,
    durationMs: warriorChargeFxDurationMs(spellId),
  });
}

function queueTwinDrakeSwingFx(memberClassId, now) {
  const layer = warriorSkillFxLayers("TwinDrakeBlade", "swing")[0];
  const durationMs = layer?.frames?.length ? layer.frames.length * layer.interval : CRYSTAL_TWIN_DRAKE_CHARGE_FX_MS;
  queueAttachedSpellFx("TwinDrakeBlade", {
    now,
    memberClassId,
    layerStart: 1,
    layerEnd: 2,
    durationMs,
  });
}

function magicShieldFxEntity(memberClassId) {
  const party = state.battle.bossParty;
  if (party?.active) {
    const classId = memberClassId ?? (state.battle.combatClass === "Wizard" ? bossPartyControlledClassId() : null);
    if (classId) {
      return party.members?.find((member) => member.classId === classId) ?? null;
    }
    return null;
  }
  if (state.battle.combatClass === "Wizard") return state.battle.player;
  return null;
}

function magicShieldFxActive(memberClassId, now = performance.now()) {
  const entity = magicShieldFxEntity(memberClassId);
  if (!entity) return false;
  return hasActiveDefenceBuffOnList(entityStatBuffList(entity), "magicShield", now);
}

function startMagicShieldLoopFx(options = {}) {
  const now = options.now ?? performance.now();
  const memberClassId = options.memberClassId ?? null;
  const expiresAt = Number(options.expiresAt);
  if (!Number.isFinite(expiresAt) || expiresAt <= now) return;
  const battle = state.battle;
  const others = (battle.attachedSpellFx ?? []).filter(
    (entry) => entry.spellId !== "MagicShield" || (entry.memberClassId ?? null) !== memberClassId,
  );
  battle.attachedSpellFx = [
    ...others,
    {
      spellId: "MagicShield",
      memberClassId,
      startedAt: now,
      loopStartedAt: now,
      expiresAt,
      struckAt: 0,
    },
  ].slice(-12);
}

function maybeNotifyMagicShieldStruck(memberClassId, now = performance.now()) {
  if (!magicShieldFxActive(memberClassId, now)) return;
  let entry = (state.battle.attachedSpellFx ?? []).find(
    (candidate) => candidate.spellId === "MagicShield" && (candidate.memberClassId ?? null) === memberClassId,
  );
  if (!entry) {
    const buffs = pruneStatBuffs(entityStatBuffList(magicShieldFxEntity(memberClassId)), now);
    const shield = buffs.find((buff) => buff.kind === "magicShield");
    if (!shield) return;
    startMagicShieldLoopFx({ expiresAt: shield.expiresAt, memberClassId, now });
    entry = (state.battle.attachedSpellFx ?? []).find(
      (candidate) => candidate.spellId === "MagicShield" && (candidate.memberClassId ?? null) === memberClassId,
    );
  }
  if (entry) entry.struckAt = now;
}

function magicShieldStruckMemberClassId(target) {
  if (!target || target.classId !== "Wizard") return undefined;
  if (state.battle.bossParty?.active) {
    return target.classId === bossPartyControlledClassId() ? null : "Wizard";
  }
  return null;
}

function spellFxLoopFrameIndex(layer, startedAt, now = performance.now()) {
  const interval = Math.max(1, Number(layer.interval) || 200);
  const frameCount = Math.max(1, layer.frames?.length ?? 1);
  const layerT = now - startedAt - (layer.delayMs ?? 0);
  if (layerT < 0) return -1;
  return Math.floor(layerT / interval) % frameCount;
}

function magicShieldLoopStartedAt(entry, now = performance.now()) {
  const struckAt = Number(entry.struckAt) || 0;
  if (struckAt > 0 && now >= struckAt + CRYSTAL_MAGIC_SHIELD_STRUCK_MS) {
    return struckAt + CRYSTAL_MAGIC_SHIELD_STRUCK_MS;
  }
  return entry.loopStartedAt ?? entry.startedAt;
}

function updateAttachedSpellFx(now) {
  const battle = state.battle;
  const effects = battle.attachedSpellFx ?? [];
  if (!effects.length) return;
  battle.attachedSpellFx = effects.filter((entry) => {
    if (now >= entry.expiresAt) return false;
    if (entry.spellId === "MagicShield" && !magicShieldFxActive(entry.memberClassId ?? null, now)) return false;
    return true;
  });
}

function notifyWizardMagicShieldStruckOnHit(target, now = performance.now()) {
  const memberClassId = magicShieldStruckMemberClassId(target);
  if (memberClassId !== undefined) maybeNotifyMagicShieldStruck(memberClassId, now);
}

function clearTwinDrakePendingState() {
  state.battle.pendingTwinDrakeHits = [];
}

function queueTwinDrakeSecondHit(source, learned, rawDamage, now) {
  if (!learned || rawDamage == null) return;
  const hits = state.battle.pendingTwinDrakeHits ?? [];
  hits.push({
    at: now + CRYSTAL_TWIN_DRAKE_SECOND_HIT_DELAY_MS,
    memberClassId: source?.classId ?? state.battle.combatClass,
    rawDamage: Math.max(0, Math.trunc(Number(rawDamage) || 0)),
    applyStun: true,
  });
  state.battle.pendingTwinDrakeHits = hits.slice(-6);
}

function twinDrakeLearnedForMember(classId) {
  if (state.battle.bossParty?.active) {
    const member = state.battle.bossParty.members?.find((entry) => entry.classId === classId);
    return member ? bossPartyLearned(member, "TwinDrakeBlade") : null;
  }
  return learnedMagic("TwinDrakeBlade");
}

function twinDrakeAttackerForMember(classId) {
  if (state.battle.bossParty?.active) {
    return state.battle.bossParty.members?.find((entry) => entry.classId === classId) ?? null;
  }
  return state.battle.player;
}

function updatePendingTwinDrakeHits(now) {
  const battle = state.battle;
  const pending = battle.pendingTwinDrakeHits ?? [];
  if (!pending.length || !battle.enemy || battle.enemy.hp <= 0) {
    if (pending.length && (!battle.enemy || battle.enemy.hp <= 0)) clearTwinDrakePendingState();
    return;
  }
  const skill = warriorSpellById("TwinDrakeBlade");
  const remaining = [];
  for (const entry of pending) {
    if (now < entry.at) {
      remaining.push(entry);
      continue;
    }
    const learned = twinDrakeLearnedForMember(entry.memberClassId);
    const attacker = twinDrakeAttackerForMember(entry.memberClassId);
    if (!skill || !learned || !attacker) continue;
    queueTwinDrakeSwingFx(entry.memberClassId, now);
    if (!rollHit(attacker.accuracy, battle.enemy.agility)) {
      pushBattleLog(`Twin Drake Blade follow-up misses ${battle.enemy.name}.`);
      continue;
    }
    const damage = scaleEnemyPhysicalDamage(entry.rawDamage, battle.enemy, now);
    if (damage <= 0) continue;
    reduceEnemyHp(battle.enemy, damage);
    syncBattleEnemyHpToSwarm();
    strikeGroupDungeonSwarmEnemy(battle.enemy, now);
    playMonsterSfx("flinch");
    playWeaponHitSfx();
    addCombatText("enemy", damage, "damage", now);
    pushBattleLog(`Twin Drake Blade hits ${battle.enemy.name} again for ${damage}.`);
    if (battle.enemy.hp > 0) applyCrystalFreezingAttackProc(attacker, battle.enemy, now);
    if (entry.applyStun) tryApplyTwinDrakeStun(battle.enemy, learned, now);
    if (battle.enemy.hp <= 0) {
      if (groupDungeonSwarmSideActive()) {
        maybeKillGroupDungeonSwarmEnemy(battle.enemy, now);
        clearTwinDrakePendingState();
        return;
      }
      finishEnemy(now);
      setEnemyAction("die", false, now);
      playMonsterSfx("death");
      pushBattleLog(`${battle.enemy.name} is defeated.`);
      clearTwinDrakePendingState();
      return;
    }
  }
  battle.pendingTwinDrakeHits = remaining;
}

function castWarriorCharge(skill, learned, cost, now) {
  if (warriorSlayingPending()) return;
  const battle = state.battle;
  battle.player.mp = Math.max(0, battle.player.mp - cost);
  setWarriorSpellCastReadyAt(skill, learned, now);
  clearQueuedCombatSpell(skill.id);
  if (battle.bossParty?.active) {
    const member = bossPartyControlledMember();
    const memberLearned = member?.magic?.learned?.[skill.id];
    if (memberLearned) {
      memberLearned.castReadyAt = learned.castReadyAt;
      if (skill.id === "TwinDrakeBlade" && twinDrakeAutoCastActive(memberLearned)) {
        memberLearned.castReadyAt = 0;
      }
    }
  }
  if (skill.id === "TwinDrakeBlade") {
    applyTwinDrakeChargeState(battle, now);
    if (battle.bossParty?.active) applyTwinDrakeChargeState(bossPartyControlledMember(), now);
  } else if (skill.id === "FlamingSword") {
    applyFlamingSwordChargeState(battle, now);
    if (battle.bossParty?.active) applyFlamingSwordChargeState(bossPartyControlledMember(), now);
  }
  sceneSignature = "";
  battle.pendingImpact = null;
  battle.pendingEnemyStrike = null;
  pushBattleLog(`${skill.label} readied for the next attack.`);
  battlePanelSignature = "";
  combatSkillBarSignature = "";
}

function chargedFlamingSwordAttack(now) {
  if (!warriorFlamingSwordReady()) return null;
  const skill = warriorSpellById("FlamingSword");
  const learned = learnedMagic("FlamingSword");
  if (!skill || !learned) return null;
  if (enemyDistance() > LANE.warriorRange) return null;
  return { skill, learned, cost: 0, charged: true };
}

function chargedWarriorAttack(now) {
  if (warriorSlayingPending()) return null;
  return chargedFlamingSwordAttack(now) ?? chargedTwinDrakeAttack(now);
}

function chargedTwinDrakeAttack(now) {
  if (!warriorTwinDrakeReady()) return null;
  const skill = warriorSpellById("TwinDrakeBlade");
  const learned = learnedMagic("TwinDrakeBlade");
  if (!skill || !learned) return null;
  if (enemyDistance() > LANE.warriorRange) return null;
  const cost = spellMpCost(skill, learned);
  if ((state.battle.player?.mp ?? 0) < cost) {
    clearTwinDrakeChargeState(state.battle);
    if (state.battle.bossParty?.active) clearTwinDrakeChargeState(bossPartyControlledMember());
    return null;
  }
  return { skill, learned, cost, charged: true };
}

function warriorApplyPhysicalHit(skill, learned, damage, now) {
  const battle = state.battle;
  const enemy = battle.enemy;
  const scaled = scaleEnemyPhysicalDamage(damage, enemy, now);
  if (scaled <= 0) {
    addCombatText("enemy", "Miss", "miss", now);
    pushBattleLog(`${skill.id === "None" ? "Warrior" : skill.label} misses ${enemy.name}.`);
    rollSlayingChargeAfterAttack(now);
    return false;
  }
  reduceEnemyHp(enemy, scaled);
  setEnemyAction("struck", true, now);
  playMonsterSfx("flinch");
  if (skill.id === "TwinDrakeBlade" || skill.id === "FlamingSword" || skill.id === "None") playWeaponHitSfx();
  else if (!playSpellSfx(skill.id, "impact", { volume: 0.48 })) playWeaponHitSfx();
  addCombatText("enemy", scaled, "damage", now);
  pushBattleLog(`${skill.id === "None" ? "Warrior" : skill.label} hits ${enemy.name} for ${scaled}.`);
  if (enemy.hp > 0) applyCrystalFreezingAttackProc(battle.player, enemy, now);
  if (learned) levelWarriorMagic(skill, learned, now);
  levelPassiveWeaponMagic(now);
  rollSlayingChargeAfterAttack(now);
  if (enemy.hp <= 0) {
    finishEnemy(now);
    setEnemyAction("die", false, now);
    playMonsterSfx("death");
    pushBattleLog(`${enemy.name} is defeated.`);
  }
  return true;
}

function warriorAttack(now) {
  const battle = state.battle;
  const { skill, learned, cost, charged } = usableWarriorAttackSkill(now);

  if (skill.buff) {
    battle.activeSkill = skill.id;
    battle.activeSkillAtlas = state.warriorSkillAtlases[skill.id] ?? null;
    battle.activeSkillStartedAt = now;
    setPlayerAction(skill.bodyAction ?? "spell", now, true);
    castWarriorBuff(skill, learned, cost, now);
    battle.lastPlayerAttackCooldownMs = CRYSTAL_PLAYER_ACTION_LOCK_MS;
    return true;
  }

  battle.activeSkill = skill.id;
  battle.activeSkillAtlas = state.warriorSkillAtlases[skill.id] ?? null;
  battle.activeSkillStartedAt = now;
  battle.activeWizardSpell = null;
  battle.activeWizardSpellAtlas = null;
  battle.activeTaoSpell = null;
  battle.activeTaoSpellAtlas = null;
  battle.pendingImpact = null;
  battle.pendingEnemyStrike = null;
  setPlayerAction(skill.bodyAction, now, true);
  if (skill.id === "None") playWeaponSwingSfx();
  else playWarriorSpellSwingSfx(skill, { volume: 0.5 });

  if (learned) commitWarriorSpellUse(skill, learned, cost, now);
  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, skill);
  if (!rollHit(battle.player.accuracy, battle.enemy.agility)) {
    addCombatText("enemy", "Miss", "miss", now);
    pushBattleLog(`${skill.id === "None" ? "Warrior" : skill.label} misses ${battle.enemy.name}.`);
    rollSlayingChargeAfterAttack(now);
    return true;
  }
  const damage = learned
    ? (isHalfMoonAttackSkill(skill)
      ? rollDamage(battle.player.dc, enemyPhysicalDefence(battle.enemy), battle.player.luck)
      : rollWarriorMagicDamage(skill, learned, battle.player, battle.enemy))
    : rollDamage(battle.player.dc, enemyPhysicalDefence(battle.enemy), battle.player.luck);
  if (!warriorApplyPhysicalHit(skill, learned, damage, now)) return true;
  if (skill.id === "TwinDrakeBlade" && charged && battle.enemy?.hp > 0) {
    queueTwinDrakeSecondHit({ classId: battle.combatClass }, learned, damage, now);
  }
  return true;
}

function usableWarriorAttackSkill(now) {
  const slaying = chargedSlayingAttack();
  if (slaying) return slaying;

  const charged = chargedWarriorAttack(now);
  if (charged) return charged;

  const queued = queuedWarriorAttackSkill(now);
  if (queued) return queued;

  const candidates = autoWarriorCombatSkills()
    .map((skill) => ({ skill, learned: learnedMagic(skill.id) }))
    .filter(({ skill, learned }) => {
      if (isWarriorChargeSkill(skill) && !warriorChargeReady(skill.id)) return false;
      return canAutoCastWarriorSkill(skill, learned, now);
    })
    .sort((a, b) => warriorAutoPriority(a.skill) - warriorAutoPriority(b.skill));
  if (!candidates.length) {
    return { skill: BASIC_ATTACK_SKILL, learned: null, cost: 0 };
  }
  const { skill, learned } = candidates[0];
  return { skill, learned, cost: spellMpCost(skill, learned) };
}

function queuedWarriorAttackSkill(now) {
  const queued = queuedCombatSpell("Warrior");
  if (!queued) return null;
  const { spell: skill, learned, cost } = queued;
  if (isWarriorChargeSkill(skill) && !warriorChargeReady(skill.id)) {
    return { skill: BASIC_ATTACK_SKILL, learned: null, cost: 0, queuedWaiting: true };
  }
  if (!canUseWarriorSkill(skill, learned, now, { requireAuto: false })) {
    return { skill: BASIC_ATTACK_SKILL, learned: null, cost: 0, queuedWaiting: true };
  }
  return { skill, learned, cost, queued: true };
}

function usableWizardAttackSpell(now) {
  const queued = queuedWizardAttackSpell(now);
  if (queued) {
    if (!wizardAttackSpellReady(queued.spell, now)) return null;
    return queued;
  }

  const options = activeWizardAutoSpells()
    .filter((spell) => spell.impactMode !== "buff")
    .map((spell) => {
    const learned = learnedMagic(spell.id);
    const cost = spellMpCost(spell, learned);
    return {
      spell,
      learned,
      cost,
      cooldownWaiting: !canWizardCastSpell(spell, learned, now),
    };
  });
  if (!options.length) return null;
  const ready = options.filter((option) => !option.cooldownWaiting && wizardAttackSpellReady(option.spell, now));
  const autoReady = ready.filter((option) => wizardAutoSpellEligible(option.spell));
  return autoReady.find((option) => (state.battle.player?.mp ?? 0) >= option.cost)
    ?? autoReady.find((option) => !option.cooldownWaiting)
    ?? null;
}

function queuedWizardAttackSpell(now) {
  const queued = queuedCombatSpell("Wizard");
  if (!queued) return null;
  const { spell, learned, cost } = queued;
  return {
    spell,
    learned,
    cost,
    queued: true,
    cooldownWaiting: (learned.castReadyAt ?? 0) > now,
  };
}

function chargedSlayingAttack() {
  if (!warriorSlayingPending()) return null;
  const skill = warriorSpellById("Slaying");
  const learned = learnedMagic("Slaying");
  if (!skill || !learned) return null;
  return { skill, learned, cost: 0, slaying: true };
}

function thrustingEnabled() {
  return autoWarriorCombatSkills().some((skill) => skill.id === "Thrusting");
}

function halfMoonEnabled(member = null) {
  const spells = member ? bossPartyAutoSpells(member) : autoWarriorCombatSkills();
  return spells.some((skill) => skill.id === "HalfMoon");
}

function isHalfMoonAttackSkill(skill) {
  return skill?.id === "HalfMoon";
}

function canUseHalfMoonAttack(distancePx, mp, learned) {
  const skill = warriorSpellById("HalfMoon");
  if (!skill || !learned) return false;
  return distancePx <= LANE.warriorRange && mp >= spellMpCost(skill, learned);
}

function halfMoonSplashSwarmEnemies(primarySwarmId) {
  const swarm = state.battle.swarm;
  if (!swarm || !groupDungeonSwarmSideActive()) return [];
  const primary = primarySwarmId ? findGroupDungeonSwarmEnemy(primarySwarmId) : null;
  const meleeCol = swarmSnapTileX(groupDungeonSwarmMeleeWorldX());
  const primaryTile = primary ? swarmEnemyTilePosition(primary) : null;
  return swarm.enemies.filter((enemy) => {
    if (enemy.hp <= 0 || enemy.dying) return false;
    if (primarySwarmId && enemy.id === primarySwarmId) return false;
    if (!swarmEnemyInAttackRange(enemy, meleeCol)) return false;
    if (!primaryTile) return true;
    const tile = swarmEnemyTilePosition(enemy);
    return tile.mapRow !== primaryTile.mapRow;
  });
}

function bossPartyHalfMoonSplash(member, skill, learned, primaryEnemy, now) {
  const splashTargets = halfMoonSplashSwarmEnemies(primaryEnemy?.swarmId);
  if (!splashTargets.length) return;
  for (const swarmEnemy of splashTargets) {
    if (!rollHit(member.accuracy, swarmEnemy.agility)) {
      pushBattleLog(`${member.classId} Half Moon misses ${swarmEnemy.name}.`);
      continue;
    }
    const entity = swarmEnemyToBattleEntity(swarmEnemy);
    const damage = scaleEnemyPhysicalDamage(
      rollWarriorMagicDamage(skill, learned, member, entity),
      entity,
      now,
    );
    if (damage <= 0) {
      pushBattleLog(`${member.classId} Half Moon misses ${swarmEnemy.name}.`);
      continue;
    }
    reduceSwarmEnemyHp(swarmEnemy, damage, now);
    addSwarmEnemyCombatText(swarmEnemy, damage, "damage", now);
    strikeGroupDungeonSwarmEnemy(entity, now);
    playMonsterSfx("flinch", swarmEnemy, bossPartySfxParams(member, 0.42, 80));
    pushBattleLog(`${member.classId} Half Moon hits ${swarmEnemy.name} for ${damage}.`);
    maybeKillGroupDungeonSwarmEnemy(entity, now);
  }
  syncGroupDungeonPrimaryEnemy();
}

function isThrustingAttackWindow() {
  const distance = enemyDistance();
  return distance > LANE.warriorRange && distance <= THRUSTING_RANGE;
}

function autoWarriorCombatSkills() {
  return normalizeAutoCastSpellsForClass("Warrior");
}

function autoWizardCombatSpells() {
  return activeWizardAutoSpells();
}

function autoTaoistCombatSpells() {
  return normalizeAutoCastSpellsForClass("Taoist");
}

function canAutoCastWarriorSkill(skill, learned, now) {
  return canUseWarriorSkill(skill, learned, now, { requireAuto: true });
}

function canUseWarriorSkill(skill, learned, now, options = {}) {
  if (!skill || !learned || skill.passive) return false;
  if (options.requireAuto && !learned.autoCast) return false;
  if (isWarriorChargeSkill(skill) && warriorChargeReady(skill.id)) return false;
  if (skill.toggle) {
    if (skill.id === "Thrusting") return isThrustingAttackWindow();
    if (skill.id === "HalfMoon") {
      return canUseHalfMoonAttack(enemyDistance(), state.battle.player?.mp ?? 0, learned);
    }
    return false;
  }
  const chargeCast = isWarriorChargeSkill(skill) && !warriorChargeReady(skill.id);
  if (!skill.buff && !chargeCast && enemyDistance() > LANE.warriorRange) return false;
  if (skill.id === "Fury" && now < (state.battle.furyUntil ?? 0)) return false;
  if (warriorSpellCastOnCooldown(skill, learned, now)) return false;
  return (state.battle.player?.mp ?? 0) >= spellMpCost(skill, learned);
}

function canAutoCastWizardSpell(spell, learned, now) {
  return canUseWizardSpell(spell, learned, now, { requireAuto: true });
}

function canUseWizardSpell(spell, learned, now, options = {}) {
  if (!spell || !learned || spell.passive) return false;
  if (options.requireAuto && !learned.autoCast) return false;
  if ((learned.castReadyAt ?? 0) > now) return false;
  if (spell.id === "FireWall" && !canUseWizardFireWall(now)) return false;
  return (state.battle.player?.mp ?? 0) >= spellMpCost(spell, learned);
}

function wizardFireWallRequiresMeleeRange() {
  return !bossPartyActiveFight();
}

function wizardHoldsCombatPosition() {
  return state.battle.combatClass === "Wizard"
    && !bossPartyActiveFight()
    && state.battle.phase === "engaged";
}

function wizardFireWallMeleeReady() {
  return enemyDistance() <= LANE.enemyRange;
}

function canUseWizardFireWall(now) {
  if (bossPartyGroundEffectActive("FireWall", now)) return false;
  if (!wizardFireWallRequiresMeleeRange()) return true;
  return wizardFireWallMeleeReady();
}

function wizardAttackSpellReady(spell, now, member = null) {
  if (spell?.id === "FireWall") return canUseWizardFireWall(now);
  if (spell?.impactMode === "bang" && groupDungeonSwarmSideActive()) return canUseGroupDungeonSwarmBangSpell(spell, member);
  return true;
}

function canAutoCastTaoistSpell(spell, learned, now) {
  return canUseTaoistSpell(spell, learned, now, { requireAuto: true });
}

function canUseTaoistSpell(spell, learned, now, options = {}) {
  if (!spell || !learned || spell.passive) return false;
  if (options.requireAuto) {
    if (!learned.autoCast) return false;
    if (!autoTaoistCombatSpells().some((autoSpell) => autoSpell.id === spell.id)) return false;
  }
  if ((learned.castReadyAt ?? 0) > now) return false;
  return (state.battle.player?.mp ?? 0) >= spellMpCost(spell, learned);
}

function warriorAutoPriority(skill) {
  const order = ["Fury", "FlamingSword", "TwinDrakeBlade", "Thrusting", "HalfMoon"];
  const index = order.indexOf(skill?.id);
  return index === -1 ? order.length : index;
}

function wizardAutoPriority(spell) {
  const order = ["MagicShield", "FireWall", "IceStorm", "GreatFireBall", "FrostCrunch", "FireBall", "ThunderBolt"];
  const index = order.indexOf(spell?.id);
  return index === -1 ? order.length : index;
}

function taoistAutoPriority(spell) {
  const order = ["Healing", "SoulShield", "BlessedArmour", "UltimateEnhancer", "SummonSkeleton", "SummonShinsu", "Poisoning", "SoulFireBall"];
  const index = order.indexOf(spell?.id);
  return index === -1 ? order.length : index;
}

function commitWarriorSpellUse(skill, learned, cost, now) {
  if (!learned || skill.id === BASIC_ATTACK_SKILL.id) return;
  if (skill.id === "Slaying") {
    clearWarriorSlayingReady();
    clearQueuedCombatSpell(skill.id);
    return;
  }
  if (skill.id === "FlamingSword") {
    clearFlamingSwordChargeState(state.battle);
    if (state.battle.bossParty?.active) clearFlamingSwordChargeState(bossPartyControlledMember());
    clearQueuedCombatSpell(skill.id);
    if (state.battle.bossParty?.active) {
      const member = bossPartyControlledMember();
      if (member) bossPartySetWarriorSpellCastReadyAt(member, skill, learned, now);
    }
    sceneSignature = "";
    battlePanelSignature = "";
    return;
  }
  if (skill.id === "TwinDrakeBlade") {
    clearTwinDrakeChargeState(state.battle);
    if (state.battle.bossParty?.active) clearTwinDrakeChargeState(bossPartyControlledMember());
    if (twinDrakeAutoCastActive(learned)) {
      state.battle.player.mp = Math.max(0, state.battle.player.mp - cost);
      learned.castReadyAt = 0;
      clearQueuedCombatSpell(skill.id);
      sceneSignature = "";
      battlePanelSignature = "";
      return;
    }
  }
  if (skill.toggle) {
    if (skill.id === "HalfMoon") {
      state.battle.player.mp = Math.max(0, state.battle.player.mp - cost);
    }
    clearQueuedCombatSpell(skill.id);
    return;
  }
  state.battle.player.mp = Math.max(0, state.battle.player.mp - cost);
  setWarriorSpellCastReadyAt(skill, learned, now);
  clearQueuedCombatSpell(skill.id);
  sceneSignature = "";
  battlePanelSignature = "";
}

function wizardCastCooldownMs(spell, learned) {
  return crystalSpellCastCooldownMs(spell, learned);
}

function applyWizardCastCooldown(spell, learned, now, member = null) {
  const cooldown = wizardCastCooldownMs(spell, learned);
  if (learned) learned.castReadyAt = now + cooldown;
  if (member) {
    member.wizardSpellLockUntil = now + cooldown;
    member.nextActionAt = now + cooldown;
  } else {
    state.battle.wizardSpellLockUntil = now + cooldown;
  }
  return cooldown;
}

function wizardCastLocked(now, member = null) {
  if (member) {
    if ((member.wizardSpellLockUntil ?? 0) > now) return true;
    if ((member.nextActionAt ?? 0) > now) return true;
  } else if ((state.battle.wizardSpellLockUntil ?? 0) > now) {
    return true;
  }
  const battle = state.battle;
  const pending = battle.pendingImpact;
  if (pending && isWizardCombatSpellId(pending.spellId) && now < pending.at) return true;
  if (!member && battle.activeWizardSpell && battle.activeWizardSpellStartedAt) {
    const atlas = battle.activeWizardSpellAtlas ?? state.wizardSpellAtlases[battle.activeWizardSpell];
    const elapsed = now - battle.activeWizardSpellStartedAt;
    if (elapsed >= 0 && elapsed < combatSpellVisualDurationMs(atlas)) return true;
  }
  return false;
}

function canWizardCastSpell(spell, learned, now, member = null) {
  if (!spell || !learned) return false;
  if (wizardCastLocked(now, member)) return false;
  if ((learned.castReadyAt ?? 0) > now) return false;
  const mp = member?.mp ?? state.battle.player?.mp ?? 0;
  return mp >= spellMpCost(spell, learned);
}

function commitWizardSpellUse(spell, learned, cost, now) {
  state.battle.player.mp = Math.max(0, state.battle.player.mp - cost);
  applyWizardCastCooldown(spell, learned, now);
  clearQueuedCombatSpell(spell.id);
  sceneSignature = "";
  battlePanelSignature = "";
  combatSkillBarSignature = "";
}

function commitTaoistSpellUse(spell, learned, cost, now) {
  state.battle.player.mp = Math.max(0, state.battle.player.mp - cost);
  if (learned) learned.castReadyAt = now + spellDelayMs(spell, learned);
  clearQueuedCombatSpell(spell.id);
  sceneSignature = "";
  battlePanelSignature = "";
  combatSkillBarSignature = "";
}

function rollSlayingChargeAfterAttack(now) {
  if (warriorSlayingPending()) return false;
  const spell = warriorSpellById("Slaying");
  const learned = learnedMagic("Slaying");
  if (!spell || !learned) return false;
  const level = Math.max(0, Math.min(3, Number(learned.level) || 0));
  if (randomInt(0, 11) > level) return false;
  setWarriorSlayingReady(now);
  pushBattleLog("Slaying readied for the next attack.");
  battlePanelSignature = "";
  return true;
}

function setWarriorSlayingReady(now, member = null) {
  if (member?.classId) {
    member.slayingReady = true;
    member.slayingReadyAt = now;
    if (member.classId === bossPartyControlledClassId()) {
      state.battle.slayingReady = true;
      state.battle.slayingReadyAt = now;
    }
    return;
  }
  state.battle.slayingReady = true;
  state.battle.slayingReadyAt = now;
  if (state.battle.bossParty?.active && state.battle.combatClass === "Warrior") {
    const controlled = bossPartyControlledMember();
    if (controlled) {
      controlled.slayingReady = true;
      controlled.slayingReadyAt = now;
    }
  }
}

function clearWarriorSlayingReady(member = null) {
  if (member?.classId) {
    member.slayingReady = false;
    member.slayingReadyAt = 0;
    if (member.classId === bossPartyControlledClassId()) {
      state.battle.slayingReady = false;
      state.battle.slayingReadyAt = 0;
    }
    return;
  }
  state.battle.slayingReady = false;
  state.battle.slayingReadyAt = 0;
  if (state.battle.bossParty?.active && state.battle.combatClass === "Warrior") {
    const controlled = bossPartyControlledMember();
    if (controlled) {
      controlled.slayingReady = false;
      controlled.slayingReadyAt = 0;
    }
  }
}

function warriorSlayingPending(member = null) {
  if (member?.classId) return Boolean(member.slayingReady);
  if (state.battle.slayingReady) return true;
  const controlled = state.battle.bossParty?.active ? bossPartyControlledMember() : null;
  return Boolean(controlled?.classId === "Warrior" && controlled.slayingReady);
}

function rollWarriorMagicDamage(skill, learned, player, enemy) {
  const attack = rollStat(player.dc, player.luck);
  const boosted = Math.trunc((attack + crystalMagicPower(skill, learned)) * crystalMagicMultiplier(skill, learned));
  const defence = rollStat(enemyPhysicalDefence(enemy));
  return Math.max(0, boosted - defence);
}

function rollWizardMagicDamage(spell, learned, player, enemy) {
  const boosted = rollWizardMagicValue(spell, learned, player);
  const adjusted = spell?.id === "ThunderBolt" && enemy?.undead ? Math.trunc(boosted * 1.5) : boosted;
  return applyWizardMagicDefence(adjusted, enemy);
}

function rollWizardMagicValue(spell, learned, player) {
  return crystalMagicDamageBeforeDefence(spell, learned, combatantForMagicRoll(player));
}

function rollTaoistHealingAmount(spell, learned, player) {
  const attack = rollStat(player.sc, player.luck);
  const boosted = Math.trunc(((attack * 2) + crystalMagicPower(spell, learned)) * crystalMagicMultiplier(spell, learned));
  const level = Math.max(1, Math.trunc(Number(player?.level ?? state.game.progress.level) || 1));
  return Math.max(1, boosted + level);
}

function rollTaoistMagicDamage(spell, learned, player, enemy) {
  return applyWizardMagicDefence(rollTaoistMagicValue(spell, learned, player), enemy);
}

function rollTaoistMagicValue(spell, learned, player) {
  const stats = combatantForMagicRoll(player);
  const attack = rollStat(stats.sc ?? stats.dc, stats.luck);
  return Math.trunc((attack + crystalMagicPower(spell, learned)) * crystalMagicMultiplier(spell, learned));
}

function applyWizardMagicDefence(value, enemy) {
  const defence = rollStat(enemyMagicalDefence(enemy));
  return Math.max(0, Math.trunc(Number(value) || 0) - defence);
}

function enemyPhysicalDefence(enemy) {
  return enemyDefenceStat(enemy, "ac");
}

function enemyMagicalDefence(enemy) {
  return enemyDefenceStat(enemy, "amc");
}

function enemyDefenceStat(enemy, statKey) {
  const stat = enemy?.[statKey] ?? [0, 0];
  return enemyHasPoison(enemy, "yellow") ? scaleStatRange(stat, 0.5) : stat;
}

function scaleStatRange(stat, multiplier) {
  const [min, max] = statRange(stat);
  const scale = Number(multiplier) || 0;
  return [Math.max(0, Math.floor(min * scale)), Math.max(0, Math.floor(max * scale))];
}

function enemyPoison(enemy, kind) {
  const poisons = Array.isArray(enemy?.poisons) ? enemy.poisons : [];
  return poisons.find((poison) => poison.kind === kind && (Number(poison.ticksRemaining) || 0) > 0) ?? null;
}

function enemyHasPoison(enemy, kind) {
  return Boolean(enemyPoison(enemy, kind));
}

function ensureEnemyDebuffs(enemy) {
  if (!enemy.debuffs) enemy.debuffs = { slowUntil: 0, frozenUntil: 0 };
  return enemy.debuffs;
}

function enemySlowActive(enemy, now = performance.now()) {
  return (ensureEnemyDebuffs(enemy).slowUntil ?? 0) > now;
}

function enemyFrozenActive(enemy, now = performance.now()) {
  return (ensureEnemyDebuffs(enemy).frozenUntil ?? 0) > now;
}

function effectiveEnemyAttackMs(enemy, now = performance.now()) {
  let base = Math.max(400, Math.trunc(Number(enemy?.attackMs) || 2500));
  if (enemyEnrageActive(enemy, now)) {
    base = Math.max(400, Math.trunc(Number(enemy?.enrageAttackMs) || base));
  }
  return enemySlowActive(enemy, now) ? base * 2 : base;
}

// Crystal MonsterObject.Walk: MoveTime = Envir.Time + MoveSpeed (template moveMs).
function effectiveEnemyMoveMs(enemy, now = performance.now()) {
  if (enemyFrozenActive(enemy, now)) return Number.POSITIVE_INFINITY;
  let base = Math.max(CRYSTAL_MONSTER_WALK_ACTION_MS, Math.trunc(Number(enemy?.moveMs) || 1200));
  if (enemyEnrageActive(enemy, now)) {
    base = Math.max(CRYSTAL_MONSTER_WALK_ACTION_MS, Math.trunc(Number(enemy?.enrageMoveMs) || base));
  }
  return enemySlowActive(enemy, now) ? base * 2 : base;
}

function enemyAdvanceSpeed(enemy, baseSpeed, now = performance.now()) {
  if (enemyFrozenActive(enemy, now)) return 0;
  if (enemySlowActive(enemy, now)) return baseSpeed * 0.5;
  return baseSpeed;
}

function playerFreezingStat(player = state.battle.player) {
  return Math.max(0, Math.trunc(Number(player?.freezing) || 0));
}

function crystalItemProcLevelOffset(attacker, enemy) {
  const attackerLevel = Math.max(1, Math.trunc(Number(attacker?.level ?? state.game.progress.level) || 1));
  const enemyLevel = Math.max(1, Math.trunc(Number(enemy?.level) || 1));
  return enemyLevel > attackerLevel ? 0 : Math.min(10, attackerLevel - enemyLevel);
}

function crystalItemProcLevelRoll(levelOffset) {
  const offset = Math.max(0, Math.trunc(Number(levelOffset) || 0));
  return offset <= 1 || randomInt(0, offset - 1) === 0;
}

function rollCrystalFreezingAttack(attacker, enemy) {
  const freezing = Math.max(0, Math.trunc(Number(attacker?.freezing) || 0));
  if (freezing <= 0 || !enemy || enemy.hp <= 0) return 0;
  const procChance = bossDropTableForEnemy(enemy)
    ? Math.min(FREEZING_BOSS_MAX_PROC_CHANCE, (freezing / FREEZING_BOSS_MAX_STAT) * FREEZING_BOSS_MAX_PROC_CHANCE)
    : Math.min(FREEZING_NORMAL_PROC_CHANCE_CAP, freezing / FREEZING_ATTACK_WEIGHT);
  if (Math.random() >= procChance) return 0;
  if (!crystalItemProcLevelRoll(crystalItemProcLevelOffset(attacker, enemy))) return 0;
  return Math.min(10, 3 + randomInt(0, freezing - 1)) * 1000;
}

function applyCrystalFreezingAttackProc(attacker, enemy, now = performance.now(), options = {}) {
  const durationMs = rollCrystalFreezingAttack(attacker, enemy);
  const target = options.target ?? options.swarmEnemy ?? (enemy?.swarmId ? findGroupDungeonSwarmEnemy(enemy.swarmId) : null) ?? enemy;
  if (durationMs <= 0 || !applyEnemySlow(target, durationMs, now)) return false;
  const label = options.label ?? `${enemy.name} is slowed.`;
  if (options.swarmEnemy) addSwarmEnemyCombatText(options.swarmEnemy, "Slowed", "frost", now);
  else addCombatText("enemy", "Slowed", "frost", now);
  pushBattleLog(label);
  return true;
}

function frostCrunchCanProc(player, enemy) {
  const playerLevel = Math.max(1, Math.trunc(Number(player?.level ?? state.game.progress.level) || 1));
  const enemyLevel = Math.max(1, Math.trunc(Number(enemy?.level) || 1));
  return playerLevel + 10 >= enemyLevel;
}

function rollFrostCrunchSlow(skillLevel) {
  return randomInt(0, 19) <= Math.max(0, Math.min(3, Math.trunc(Number(skillLevel) || 0)));
}

function rollFrostCrunchFrozen(skillLevel) {
  return randomInt(0, 39) <= Math.max(0, Math.min(3, Math.trunc(Number(skillLevel) || 0)));
}

function frostCrunchSlowDurationMs() {
  return (5 + randomInt(0, 4)) * 1000;
}

function frostCrunchFrozenDurationMs(freezing) {
  const stat = Math.max(0, Math.trunc(Number(freezing) || 0));
  return (5 + (stat > 0 ? randomInt(0, stat - 1) : 0)) * 1000;
}

function applyEnemySlow(enemy, durationMs, now = performance.now()) {
  if (!enemy || enemy.hp <= 0 || enemySlowActive(enemy, now)) return false;
  ensureEnemyDebuffs(enemy).slowUntil = now + Math.max(1000, Math.trunc(Number(durationMs) || 0));
  return true;
}

function applyEnemyFrozen(enemy, durationMs, now = performance.now()) {
  if (!enemy || enemy.hp <= 0 || enemyFrozenActive(enemy, now)) return false;
  ensureEnemyDebuffs(enemy).frozenUntil = now + Math.max(1000, Math.trunc(Number(durationMs) || 0));
  return true;
}

function applyFrostCrunchEffects(enemy, learned, player, now = performance.now()) {
  if (!enemy || enemy.hp <= 0 || !learned || !frostCrunchCanProc(player, enemy)) return false;
  const skillLevel = Math.max(0, Math.min(3, Math.trunc(Number(learned.level) || 0)));
  const freezing = playerFreezingStat(player);
  let applied = false;
  if (rollFrostCrunchSlow(skillLevel) && applyEnemySlow(enemy, frostCrunchSlowDurationMs(), now)) {
    addCombatText("enemy", "Slowed", "frost", now);
    pushBattleLog(`${enemy.name} is slowed.`);
    applied = true;
  }
  if (rollFrostCrunchFrozen(skillLevel) && applyEnemyFrozen(enemy, frostCrunchFrozenDurationMs(freezing), now)) {
    addCombatText("enemy", "Frozen", "frost", now);
    pushBattleLog(`${enemy.name} is frozen.`);
    applied = true;
  }
  return applied;
}

function rollTaoistPoisonPower(spell, learned, player) {
  const attack = rollStat(player.sc, player.luck);
  return Math.max(0, Math.trunc((attack + crystalMagicPower(spell, learned)) * crystalMagicMultiplier(spell, learned)));
}

function poisonCandidateForEnemy(enemy, now = performance.now()) {
  const green = poisonInventoryEntries("green")[0] ?? null;
  const yellow = poisonInventoryEntries("yellow")[0] ?? null;
  if (green && poisonNeedsApply(enemy, "green", now)) return green;
  if (yellow && poisonNeedsApply(enemy, "yellow", now)) return yellow;
  return null;
}

function poisonNeedsApply(enemy, kind, now) {
  const active = enemyPoison(enemy, kind);
  if (!active) return true;
  const ticksRemaining = Math.max(0, Math.trunc(Number(active.ticksRemaining) || 0));
  const tickMs = Math.max(1, Math.trunc(Number(active.tickMs) || CRYSTAL_POISON_TICK_MS));
  const nextTickAt = Number(active.nextTickAt) || now;
  return ticksRemaining <= 2 || nextTickAt + (ticksRemaining - 1) * tickMs - now <= tickMs * 2;
}

function applyEnemyPoison(enemy, poison, now = performance.now()) {
  if (!enemy || enemy.hp <= 0 || !poison) return false;
  if (!Array.isArray(enemy.poisons)) enemy.poisons = [];
  const ticksRemaining = Math.max(1, Math.trunc(Number(poison.ticksRemaining) || 1));
  const value = Math.max(0, Math.trunc(Number(poison.value) || 0));
  const existing = enemyPoison(enemy, poison.kind);
  if (existing) {
    if (poison.kind === "green" && (Number(existing.value) || 0) > value) return false;
    if (poison.kind !== "green" && (Number(existing.ticksRemaining) || 0) > ticksRemaining) return false;
    Object.assign(existing, {
      ...poison,
      value,
      ticksRemaining,
      tickMs: CRYSTAL_POISON_TICK_MS,
      nextTickAt: now + CRYSTAL_POISON_TICK_MS,
      appliedAt: now,
    });
    return true;
  }

  enemy.poisons.push({
    ...poison,
    value,
    ticksRemaining,
    tickMs: CRYSTAL_POISON_TICK_MS,
    nextTickAt: now + CRYSTAL_POISON_TICK_MS,
    appliedAt: now,
  });
  return true;
}

function rollMagicHit(enemy) {
  const magicResist = Math.max(0, Math.min(CRYSTAL_MAGIC_RESIST_WEIGHT, Number(enemy?.magicResist) || 0));
  return magicResist <= 0 || randomInt(0, CRYSTAL_MAGIC_RESIST_WEIGHT - 1) >= magicResist;
}

function crystalMagicMultiplier(skill, learned) {
  return (Number(skill.multiplierBase) || 1) + (Number(learned?.level) || 0) * (Number(skill.multiplierBonus) || 0);
}

function crystalMagicDamageBeforeDefence(skill, learned, player) {
  const attack = rollStat(player.mc ?? player.dc, player.luck);
  return Math.trunc((attack + crystalMagicPower(skill, learned)) * crystalMagicMultiplier(skill, learned));
}

function crystalMagicPower(skill, learned) {
  const level = Number(learned?.level) || 0;
  const mPowerBase = Number(skill.mPowerBase) || 0;
  const powerBase = Number(skill.powerBase) || 0;
  const mPower = Number(skill.mPowerBonus) > 0
    ? crystalRandomNext(mPowerBase, mPowerBase + Number(skill.mPowerBonus))
    : mPowerBase;
  const defPower = Number(skill.powerBonus) > 0
    ? crystalRandomNext(powerBase, powerBase + Number(skill.powerBonus))
    : powerBase;
  return crystalRound((mPower / 4) * (level + 1) + defPower);
}

function crystalRandomNext(min, maxExclusive) {
  const safeMin = Math.trunc(Number(min) || 0);
  const safeMax = Math.trunc(Number(maxExclusive) || safeMin);
  if (safeMax <= safeMin) return safeMin;
  return randomInt(safeMin, safeMax - 1);
}

function crystalRound(value) {
  const floor = Math.floor(value);
  const diff = value - floor;
  if (diff < 0.5) return floor;
  if (diff > 0.5) return floor + 1;
  return floor % 2 === 0 ? floor : floor + 1;
}

function castWarriorBuff(skill, learned, cost, now) {
  commitWarriorSpellUse(skill, learned, cost, now);
  if (skill.id === "Fury") {
    state.battle.furyUntil = now + 60000 + (Number(learned?.level) || 0) * 10000;
    state.battle.furyBonus = 4;
    levelWarriorMagic(skill, learned, now);
    pushBattleLog(`Fury increases attack speed for ${Math.round((state.battle.furyUntil - now) / 1000)}s.`);
    battlePanelSignature = "";
    return;
  }
  pushBattleLog(`${skill.label} is not wired into combat yet.`);
}

function levelPassiveWeaponMagic(now) {
  if (state.battle.combatClass === "Warrior") {
    const fencing = learnedMagic("Fencing");
    const spell = warriorSpellById("Fencing");
    if (fencing && spell) levelWarriorMagic(spell, fencing, now);
    return;
  }

  if (state.battle.combatClass === "Taoist") {
    const spiritSword = learnedMagic("SpiritSword");
    const spell = taoistSpellById("SpiritSword");
    if (spiritSword && spell) levelMagicSkill(spell, spiritSword, now);
  }
}

function levelWarriorMagic(spell, learned, now = performance.now()) {
  return levelMagicSkill(spell, learned, now);
}

function levelMagicSkill(spell, learned, now = performance.now()) {
  if (!spell || !learned || learned.level >= 3) return false;
  const requiredLevel = spellLevelRequirement(spell, learned.level);
  if (state.game.progress.level < requiredLevel) return false;
  const need = spellExperienceTarget(spell, learned.level);
  if (!need) return false;
  learned.experience += randomInt(1, 3);
  if (learned.experience >= need) {
    learned.level += 1;
    learned.experience = 0;
    pushBattleLog(`${spell.label} reached level ${learned.level}.`);
    addLootNotice(`${spell.label} Lv ${learned.level}`, "level");
    if (spell.id === "Fencing" || spell.id === "SpiritSword") applyEquippedStatsToBattlePlayer();
  }
  sceneSignature = "";
  battlePanelSignature = "";
  combatSkillBarSignature = "";
  return true;
}

function wizardAttack(now) {
  const battle = state.battle;
  const queuedDefence = usableQueuedWizardDefenceBuff(now);
  if (queuedDefence && castWizardDefenceBuff(queuedDefence, now)) return;
  const attackSpell = usableWizardAttackSpell(now);
  if (!attackSpell) {
    wizardWeaponAttack(now);
    return;
  }
  const { spell, learned, cost, cooldownWaiting } = attackSpell;
  const atlas = state.wizardSpellAtlases[spell.id] ?? null;
  if (cooldownWaiting) {
    wizardWeaponAttack(now);
    return;
  }
  if ((battle.player?.mp ?? 0) < cost) {
    wizardWeaponAttack(now, spell);
    return;
  }

  battle.lastPlayerAttackCooldownMs = wizardCastCooldownMs(spell, learned);
  commitWizardSpellUse(spell, learned, cost, now);
  const groundSpell = spell.impactMode === "ground";
  const bangSpell = spell.impactMode === "bang";
  const hit = groundSpell || bangSpell || rollMagicHit(battle.enemy);
  const damageValue = groundSpell ? rollWizardMagicValue(spell, learned, battle.player) : 0;
  const baseValue = bangSpell ? rollWizardMagicValue(spell, learned, battle.player) : 0;
  const damage = !groundSpell && !bangSpell && hit ? rollWizardMagicDamage(spell, learned, battle.player, battle.enemy) : 0;
  const impactAt = now + wizardImpactDelay(spell, atlas);

  battle.activeSkill = "None";
  battle.activeSkillAtlas = null;
  battle.activeWizardSpell = spell.id;
  battle.activeWizardSpellAtlas = atlas;
  battle.activeWizardSpellStartedAt = now;
  battle.activeWizardSpellCenterTile = bangSpell ? wizardBangCenterTile(null, spell) : null;
  battle.activeTaoSpell = null;
  battle.activeTaoSpellAtlas = null;
  battle.pendingImpact = groundSpell
    ? { at: impactAt, spellId: spell.id, value: damageValue, worldX: battle.enemyX }
    : bangSpell
      ? { at: impactAt, spellId: spell.id, baseValue, centerTile: battle.activeWizardSpellCenterTile }
      : { at: impactAt, spellId: spell.id, damage, hit: hit && damage > 0 };

  setPlayerAction("spell", now, true);
  if (spell.impactMode !== "target") playSpellSfx(spell.id, "cast");
  if (spell.impactMode === "projectile") playSpellSfx(spell.id, "fly", { volume: 0.38, throttleMs: 120 });
  pushBattleLog(`Wizard casts ${spell.label}.`);
}

function wizardWeaponAttack(now, failedSpell = null) {
  const battle = state.battle;
  const weaponEntry = equippedEntry("weapon");
  const weapon = weaponEntry ? itemDefinition(weaponEntry.itemId) : null;
  const weaponName = weapon ? itemDisplayName(weapon, weaponEntry) : "weapon";

  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, BASIC_ATTACK_SKILL);
  battle.activeSkill = BASIC_ATTACK_SKILL.id;
  battle.activeSkillAtlas = null;
  battle.activeSkillStartedAt = now;
  battle.activeWizardSpell = null;
  battle.activeWizardSpellAtlas = null;
  battle.activeTaoSpell = null;
  battle.activeTaoSpellAtlas = null;
  battle.pendingImpact = null;
  battle.pendingEnemyStrike = null;

  setPlayerAction(BASIC_ATTACK_SKILL.bodyAction, now, true);
  playWeaponSwingSfx();
  if (failedSpell && (!battle.lastNoMpLogAt || now - battle.lastNoMpLogAt > 5000)) {
    battle.lastNoMpLogAt = now;
    pushBattleLog(`Not enough MP to cast ${failedSpell.label}; Wizard uses ${weaponName}.`);
    addCombatText("player", "No MP", "mana", now);
  }

  if (!rollHit(battle.player.accuracy, battle.enemy.agility)) {
    addCombatText("enemy", "Miss", "miss", now);
    pushBattleLog(`Wizard swings ${weaponName} at ${battle.enemy.name} but misses.`);
    return;
  }

  const damage = rollDamage(battle.player.dc, enemyPhysicalDefence(battle.enemy), battle.player.luck);
  if (damage <= 0) {
    addCombatText("enemy", "Miss", "miss", now);
    pushBattleLog(`Wizard swings ${weaponName} at ${battle.enemy.name} but misses.`);
    return;
  }
  reduceEnemyHp(battle.enemy, damage);
  setEnemyAction("struck", true, now);
  playMonsterSfx("flinch");
  playWeaponHitSfx();
  addCombatText("enemy", damage, "damage", now);
  pushBattleLog(`Wizard hits ${battle.enemy.name} with ${weaponName} for ${damage}.`);
  if (battle.enemy.hp > 0) applyCrystalFreezingAttackProc(battle.player, battle.enemy, now);

  if (battle.enemy.hp <= 0) {
    finishEnemy(now);
    setEnemyAction("die", false, now);
    playMonsterSfx("death");
    pushBattleLog(`${battle.enemy.name} is defeated.`);
  }
}

function taoistDefenceBuffKind(spellId) {
  return defenceBuffKind(spellId);
}

function taoistDefenceBuffStat(spellId) {
  return defenceBuffStat(spellId);
}

function defenceBuffKind(spellId) {
  if (spellId === "SoulShield") return "soulShield";
  if (spellId === "BlessedArmour") return "blessedArmour";
  if (spellId === "MagicShield") return "magicShield";
  return null;
}

function defenceBuffStat(spellId) {
  if (spellId === "SoulShield") return "amc";
  if (spellId === "BlessedArmour") return "ac";
  return null;
}

function rollMagicShieldReductionPercent(learned) {
  const skillLevel = Math.max(0, Math.min(3, Math.trunc(Number(learned?.level) || 0)));
  return (skillLevel + 2) * 10;
}

function formatDefenceBuffApplied(spell, bonus, reductionPercent = 0) {
  if (spell?.id === "MagicShield") return `${reductionPercent}% damage reduction`;
  const statTag = defenceBuffStat(spell.id) === "amc" ? "MAC" : "AC";
  return `+${bonus} ${statTag}`;
}

function combatDefenceBuffSpell(spellId) {
  if (spellId === "MagicShield") return wizardCombatSpell(spellId);
  return taoistCombatSpell(spellId);
}

function rollDefenceBuffBonus(level) {
  return Math.floor(Math.max(1, Math.trunc(Number(level) || 1)) / 7) + 4;
}

function rollTaoistDefenceBuffBonus(level) {
  return rollDefenceBuffBonus(level);
}

function rollWizardDefenceBuffDurationMs(learned, caster) {
  const mc = rollStat(caster?.mc ?? [0, 0], caster?.luck ?? 0);
  const skillLevel = Math.max(0, Math.min(3, Math.trunc(Number(learned?.level) || 0)));
  return Math.max(1000, (mc * 4 + (skillLevel + 1) * 50) * 1000);
}

function rollTaoistDefenceBuffDurationMs(learned, caster) {
  const sc = rollStat(caster?.sc ?? [0, 0], caster?.luck ?? 0);
  const skillLevel = Math.max(0, Math.min(3, Math.trunc(Number(learned?.level) || 0)));
  return Math.max(1000, (sc * 4 + (skillLevel + 1) * 50) * 1000);
}

function hasActiveDefenceBuffOnList(buffList, kind, now = performance.now()) {
  return (buffList ?? []).some((buff) => buff.kind === kind && Number(buff.expiresAt) > now);
}

function needsTaoistDefenceBuff(spellId, now = performance.now(), options = {}) {
  return needsDefenceBuff(spellId, now, options);
}

function needsDefenceBuff(spellId, now = performance.now(), options = {}) {
  const kind = defenceBuffKind(spellId);
  if (!kind) return false;
  if (spellId === "MagicShield") {
    const playerBuffs = options.playerBuffs ?? state.battle.statBuffs;
    return !hasActiveDefenceBuffOnList(playerBuffs, kind, now);
  }
  return taoistPartyDefenceBuffTargets(now).some(
    (entry) => entry.entity
      && entry.entity.hp > 0
      && !hasActiveDefenceBuffOnList(entityStatBuffList(entry.entity), kind, now),
  );
}

function taoistPartyDefenceBuffTargets(now = performance.now()) {
  return ultimateEnhancerTargets(now);
}

function pushDefenceBuff(buffList, spell, bonus, expiresAt, learned = null) {
  const kind = defenceBuffKind(spell.id);
  const list = Array.isArray(buffList) ? buffList.filter((buff) => buff.kind !== kind) : [];
  if (spell.id === "MagicShield") {
    list.push({
      kind,
      label: spell.label,
      stat: "damageReduction",
      minBonus: 0,
      maxBonus: 0,
      reductionPercent: rollMagicShieldReductionPercent(learned),
      expiresAt,
    });
    return list;
  }
  const stat = defenceBuffStat(spell.id);
  list.push({
    kind,
    label: spell.label,
    stat,
    minBonus: 0,
    maxBonus: bonus,
    expiresAt,
  });
  return list;
}

function entityStatBuffList(entity) {
  if (!entity) return [];
  if (entity === state.battle.taoPet) return state.battle.petStatBuffs ?? [];
  if (entity === state.battle.bossParty?.pet) return entity.statBuffs ?? [];
  if (Array.isArray(entity.statBuffs)) return entity.statBuffs;
  return state.battle.statBuffs ?? [];
}

function entityDefenceBuffList(entity) {
  return entityStatBuffList(entity);
}

function effectiveCombatStats(entity) {
  const stats = {
    dc: [...statRange(entity?.dc)],
    mc: [...statRange(entity?.mc)],
    sc: [...statRange(entity?.sc)],
    luck: entity?.luck ?? 0,
  };
  applyStatBuffsToStats(stats, pruneStatBuffs(entityStatBuffList(entity)));
  return stats;
}

function combatantForMagicRoll(entity) {
  if (!entity) return entity;
  const effective = effectiveCombatStats(entity);
  return { ...entity, dc: effective.dc, mc: effective.mc, sc: effective.sc, luck: effective.luck };
}

function defenceStatsForEntity(entity) {
  const ac = Array.isArray(entity?.ac) ? [...entity.ac] : [0, 0];
  const amc = Array.isArray(entity?.amc) ? [...entity.amc] : ac;
  applyStatBuffsToStats({ ac, amc }, pruneStatBuffs(entityDefenceBuffList(entity)));
  return {
    ac,
    amc,
    agility: entity?.agility ?? 0,
    magicResist: entity?.magicResist ?? 0,
    poisonResist: entity?.poisonResist ?? 0,
  };
}

function defenceTargetForIncomingAttack(entity) {
  return { ...defenceStatsForEntity(entity), __buffEntity: entity };
}

function applyTaoistDefenceBuffEffect(spell, learned, caster, now, options = {}) {
  return applyDefenceBuffEffect(spell, learned, caster, now, options);
}

function applyTaoistPartyDefenceBuffToTargets(spell, learned, caster, now, options = {}) {
  const bonus = rollDefenceBuffBonus(caster?.level ?? state.game.progress.level);
  const durationMs = rollTaoistDefenceBuffDurationMs(learned, caster);
  const expiresAt = now + durationMs;
  const results = [];
  for (const { entity, name } of taoistPartyDefenceBuffTargets(now)) {
    if (!entity || entity.hp <= 0) continue;
    const nextBuffs = pushDefenceBuff(entityStatBuffList(entity), spell, bonus, expiresAt, learned);
    setEntityStatBuffList(entity, nextBuffs);
    if (entity?.classId === bossPartyControlledClassId()) {
      state.battle.statBuffs = [...(entity.statBuffs ?? nextBuffs)];
      applyEquippedStatsToBattlePlayer();
    } else if (entity === state.battle.player) {
      applyEquippedStatsToBattlePlayer();
    }
    results.push({ entity, name });
  }
  if (!results.length) return null;
  if (learned && options.levelSkill !== false) levelMagicSkill(spell, learned, now);
  return { bonus, durationMs, reductionPercent: 0, results };
}

function formatTaoistDefenceBuffAppliedLog(spell, bonus, applied, durationMs) {
  const statTag = defenceBuffStat(spell.id) === "amc" ? "MAC" : "AC";
  const names = (applied?.results ?? []).map((entry) => entry.name).filter(Boolean);
  const targets = names.length ? names.join(", ") : "party";
  return `${targets} (+${bonus} ${statTag}, ${formatBuffRemaining(durationMs)})`;
}

function showTaoistDefenceBuffTexts(spell, bonus, applied, now = performance.now()) {
  if (!applied?.results?.length || suppressSimulationRender) return;
  const statTag = defenceBuffStat(spell.id) === "amc" ? "MAC" : "AC";
  const text = `+${bonus} ${statTag}`;
  for (const entry of applied.results) {
    if (!entry.entity || entry.entity.hp <= 0) continue;
    if (state.battle.bossParty?.active) {
      if (entry.entity === state.battle.bossParty?.pet || entry.entity?.classId) {
        addBossPartyMemberCombatText(entry.entity, text, "buff", now);
      }
      continue;
    }
    const anchor = entry.entity === state.battle.taoPet
      ? "pet"
      : (entry.entity === state.battle.player ? "player" : entry.entity?.classId ?? "player");
    addCombatText(anchor, text, "buff", now);
  }
}

function applyDefenceBuffEffect(spell, learned, caster, now, options = {}) {
  if (spell?.id === "SoulShield" || spell?.id === "BlessedArmour") {
    return applyTaoistPartyDefenceBuffToTargets(spell, learned, caster, now, options);
  }
  const bonus = rollDefenceBuffBonus(caster?.level ?? state.game.progress.level);
  const reductionPercent = spell?.id === "MagicShield" ? rollMagicShieldReductionPercent(learned) : 0;
  const durationMs = spell?.id === "MagicShield"
    ? rollWizardDefenceBuffDurationMs(learned, caster)
    : rollTaoistDefenceBuffDurationMs(learned, caster);
  const expiresAt = now + durationMs;
  const pet = options.pet ?? state.battle.taoPet ?? state.battle.bossParty?.pet;
  const buffPet = spell?.id !== "MagicShield";

  if (options.member) {
    const buffMember = resolveBossPartyMember(options.member);
    buffMember.statBuffs = pushDefenceBuff(buffMember.statBuffs ?? [], spell, bonus, expiresAt, learned);
    if (buffMember.classId === bossPartyControlledClassId()) {
      state.battle.statBuffs = [...buffMember.statBuffs];
      applyEquippedStatsToBattlePlayer();
    }
  } else {
    state.battle.statBuffs = pushDefenceBuff(state.battle.statBuffs, spell, bonus, expiresAt, learned);
    applyEquippedStatsToBattlePlayer();
  }

  if (buffPet && pet?.active) {
    const currentPetBuffs = pet === state.battle.taoPet
      ? state.battle.petStatBuffs
      : (pet.statBuffs ?? []);
    const nextPetBuffs = pushDefenceBuff(currentPetBuffs, spell, bonus, expiresAt, learned);
    if (pet === state.battle.taoPet) state.battle.petStatBuffs = nextPetBuffs;
    else pet.statBuffs = nextPetBuffs;
  }

  if (learned && options.levelSkill !== false) levelMagicSkill(spell, learned, now);
  return { bonus, durationMs, reductionPercent };
}

const ULTIMATE_ENHANCER_BUFF_KIND = "ultimateEnhancer";
const ULTIMATE_ENHANCER_BONUS_CAP = 16; // Crystal default is 8; raised for higher idle-game stat growth

function ultimateEnhancerStatForTarget(entity) {
  const classId = entity === state.battle.taoPet || entity === state.battle.bossParty?.pet
    ? "pet"
    : (entity?.classId ?? state.battle.combatClass);
  if (classId === "Wizard") return "mc";
  if (classId === "Taoist") return "sc";
  return "dc";
}

function rollUltimateEnhancerBonus(caster) {
  const maxSc = statRange(caster?.sc ?? [0, 0])[1];
  return maxSc >= 5 ? Math.min(ULTIMATE_ENHANCER_BONUS_CAP, Math.floor(maxSc / 5)) : 1;
}

function ultimateEnhancerTargetEntry(entity) {
  if (!entity || (entity.hp ?? 0) <= 0) return null;
  if (entity === state.battle.bossParty?.pet || entity === state.battle.taoPet) {
    return { entity, anchor: "pet", name: entity.name ?? "pet" };
  }
  if (entity.classId) {
    return { entity, anchor: entity.classId, name: entity.name ?? entity.classId };
  }
  return { entity, anchor: "player", name: state.battle.combatClass };
}

function ultimateEnhancerTargets(now = performance.now()) {
  const targets = [];
  if (state.battle.bossParty?.active) {
    const party = state.battle.bossParty;
    for (const classId of BOSS_PARTY_ORDER) {
      const member = party.members?.find((entry) => entry.classId === classId && entry.alive && entry.hp > 0);
      const entry = member ? ultimateEnhancerTargetEntry(member) : null;
      if (entry) targets.push(entry);
    }
    if (party.pet?.active && party.pet.hp > 0) {
      const entry = ultimateEnhancerTargetEntry(party.pet);
      if (entry) targets.push(entry);
    }
    return targets;
  }
  const player = state.battle.player;
  if (player && player.hp > 0) {
    const entry = ultimateEnhancerTargetEntry(player);
    if (entry) targets.push(entry);
  }
  const pet = state.battle.taoPet;
  if (pet?.active && pet.hp > 0) {
    const entry = ultimateEnhancerTargetEntry(pet);
    if (entry) targets.push(entry);
  }
  return targets;
}

function ultimateEnhancerNeedsCast(now = performance.now()) {
  const targets = ultimateEnhancerTargets(now);
  if (!targets.length) return false;
  return targets.some((entry) => needsUltimateEnhancerTarget(entry.entity, now));
}

function hasUltimateEnhancerBuff(entity, now = performance.now()) {
  return hasActiveDefenceBuffOnList(entityStatBuffList(entity), ULTIMATE_ENHANCER_BUFF_KIND, now);
}

function needsUltimateEnhancerTarget(entity, now = performance.now()) {
  return Boolean(entity) && (entity.hp ?? 0) > 0 && !hasUltimateEnhancerBuff(entity, now);
}

function pushUltimateEnhancerBuff(buffList, spell, stat, bonus, expiresAt) {
  const list = Array.isArray(buffList) ? buffList.filter((buff) => buff.kind !== ULTIMATE_ENHANCER_BUFF_KIND) : [];
  list.push({
    kind: ULTIMATE_ENHANCER_BUFF_KIND,
    label: spell.label,
    stat,
    minBonus: 0,
    maxBonus: bonus,
    expiresAt,
  });
  return list;
}

function setEntityStatBuffList(entity, buffList) {
  if (entity === state.battle.taoPet) {
    state.battle.petStatBuffs = buffList;
    return;
  }
  if (entity === state.battle.bossParty?.pet || entity?.classId) {
    entity.statBuffs = buffList;
    return;
  }
  state.battle.statBuffs = buffList;
}

function applyUltimateEnhancerEffect(spell, learned, caster, target, now, options = {}) {
  const stat = ultimateEnhancerStatForTarget(target);
  const bonus = rollUltimateEnhancerBonus(caster);
  const durationMs = rollTaoistDefenceBuffDurationMs(learned, caster);
  const expiresAt = now + durationMs;
  const nextBuffs = pushUltimateEnhancerBuff(entityStatBuffList(target), spell, stat, bonus, expiresAt);
  setEntityStatBuffList(target, nextBuffs);

  if (target?.classId === bossPartyControlledClassId()) {
    state.battle.statBuffs = [...(target.statBuffs ?? nextBuffs)];
    applyEquippedStatsToBattlePlayer();
  } else if (target === state.battle.player) {
    applyEquippedStatsToBattlePlayer();
  }

  if (learned && options.levelSkill !== false) levelMagicSkill(spell, learned, now);
  return { bonus, durationMs, stat };
}

function applyUltimateEnhancerToTargets(spell, learned, caster, targets, now, options = {}) {
  if (!spell || !learned || !Array.isArray(targets) || !targets.length) return null;
  const bonus = rollUltimateEnhancerBonus(caster);
  const durationMs = rollTaoistDefenceBuffDurationMs(learned, caster);
  const expiresAt = now + durationMs;
  const results = [];
  for (const { entity, name } of targets) {
    if (!entity || entity.hp <= 0) continue;
    const stat = ultimateEnhancerStatForTarget(entity);
    const nextBuffs = pushUltimateEnhancerBuff(entityStatBuffList(entity), spell, stat, bonus, expiresAt);
    setEntityStatBuffList(entity, nextBuffs);
    if (entity?.classId === bossPartyControlledClassId()) {
      state.battle.statBuffs = [...(entity.statBuffs ?? nextBuffs)];
      applyEquippedStatsToBattlePlayer();
    } else if (entity === state.battle.player) {
      applyEquippedStatsToBattlePlayer();
    }
    results.push({ entity, name, stat, bonus, durationMs });
  }
  if (!results.length) return null;
  if (learned && options.levelSkill !== false) levelMagicSkill(spell, learned, now);
  return { bonus, durationMs, results };
}

function formatUltimateEnhancerAppliedLog(spell, casterLabel, applied, durationMs) {
  const parts = applied.results.map((entry) => {
    const statTag = entry.stat.toUpperCase();
    return `${entry.name} (+${entry.bonus} ${statTag})`;
  });
  return `${casterLabel} casts ${spell.label} (${parts.join(", ")}, ${formatBuffRemaining(durationMs)}).`;
}

function showUltimateEnhancerBuffTexts(applied, now = performance.now()) {
  if (!applied?.results?.length || suppressSimulationRender) return;
  for (const entry of applied.results) {
    const text = `+${entry.bonus} ${entry.stat.toUpperCase()}`;
    if (state.battle.bossParty?.active) {
      if (entry.entity === state.battle.bossParty?.pet || entry.entity?.classId) {
        addBossPartyMemberCombatText(entry.entity, text, "buff", now);
      }
      continue;
    }
    const anchor = entry.entity === state.battle.taoPet
      ? "pet"
      : (entry.entity === state.battle.player ? "player" : entry.entity?.classId ?? "player");
    addCombatText(anchor, text, "buff", now);
  }
}

function updatePendingUltimateEnhancer(now, options = {}) {
  const battle = state.battle;
  const pending = battle.pendingUltimateEnhancer;
  if (!pending || now < pending.at || !battle.player || battle.player.hp <= 0) return false;
  battle.pendingUltimateEnhancer = null;
  const spell = taoistCombatSpell(pending.spellId);
  const learned = learnedMagic(spell?.id);
  const targets = ultimateEnhancerTargets(now);
  if (!spell || !learned || !targets.length) return false;
  const applied = applyUltimateEnhancerToTargets(spell, learned, battle.player, targets, now);
  if (!applied) return false;
  if (!options.offline && !suppressSimulationRender) {
    battle.activeTaoSpell = null;
    battle.activeTaoSpellAtlas = null;
    showUltimateEnhancerBuffTexts(applied, now);
    queueUltimateEnhancerImpactFx(spell, applied, now);
    pushBattleLog(formatUltimateEnhancerAppliedLog(spell, state.battle.combatClass, applied, applied.durationMs));
  }
  playerHudSignature = "";
  battlePanelSignature = "";
  combatSkillBarSignature = "";
  return true;
}

function castTaoistUltimateEnhancer(castBundle, now, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost, entry, item, targets } = castBundle;
  if (battle.pendingUltimateEnhancer) return false;
  if (!consumeOneInventoryUnit(entry.id)) return false;
  battle.lastPlayerAttackCooldownMs = spellDelayMs(spell, learned);
  commitTaoistSpellUse(spell, learned, cost, now);

  if (options.offline) {
    const liveTargets = ultimateEnhancerTargets(now);
    applyUltimateEnhancerToTargets(spell, learned, battle.player, liveTargets, now);
    return true;
  }

  battle.pendingUltimateEnhancer = {
    at: now + (Number(spell.impactDelayMs) || CRYSTAL_HEAL_APPLY_DELAY_MS),
    spellId: spell.id,
  };

  const atlas = state.taoistSpellAtlases[spell.id] ?? null;
  battle.activeSkill = "None";
  battle.activeSkillAtlas = null;
  battle.activeWizardSpell = null;
  battle.activeWizardSpellAtlas = null;
  battle.activeTaoSpell = spell.id;
  battle.activeTaoSpellAtlas = atlas;
  battle.activeTaoSpellStartedAt = now;
  battle.pendingPoison = null;
  setPlayerAction(spell.bodyAction ?? "spell", now, true);
  playSpellSfx(spell.id, "cast");
  pushBattleLog(`Taoist casts ${spell.label} on the party with ${item.name}.`);
  return true;
}

function usableTaoistUltimateEnhancer(now, options = {}) {
  const spell = taoistCombatSpell("UltimateEnhancer");
  const learned = learnedMagic(spell?.id);
  const manual = options.requireAuto === false;
  if (!spell || !learned || !canUseTaoistSpell(spell, learned, now, { requireAuto: !manual })) return null;
  const targets = ultimateEnhancerTargets(now);
  if (!targets.length) return null;
  if (!manual && !ultimateEnhancerNeedsCast(now)) return null;
  const entry = amuletCandidate(0);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !isTaoistAmuletItem(item)) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry,
    item,
    targets,
  };
}

function maybeCastTaoistUltimateEnhancer(now) {
  const battle = state.battle;
  if (battle.combatClass !== "Taoist" || battle.phase !== "engaged") return false;
  if (queuedCombatSpell("Taoist")) return false;
  const castBundle = usableTaoistUltimateEnhancer(now);
  return Boolean(castBundle && castTaoistUltimateEnhancer(castBundle, now));
}

function updatePendingDefenceBuff(now, options = {}) {
  const battle = state.battle;
  const pending = battle.pendingDefenceBuff;
  if (!pending || now < pending.at || !battle.player || battle.player.hp <= 0) return false;
  battle.pendingDefenceBuff = null;
  const spell = combatDefenceBuffSpell(pending.spellId);
  const learned = learnedMagic(spell?.id);
  if (!spell || !learned) return false;
  const applied = applyDefenceBuffEffect(spell, learned, battle.player, now);
  if (!applied) return false;
  const { bonus, durationMs, reductionPercent, results } = applied;
  if (!options.offline && !suppressSimulationRender) {
    if (spell.id === "MagicShield") {
      startMagicShieldLoopFx({ expiresAt: now + durationMs, now });
      battle.activeWizardSpell = null;
      battle.activeWizardSpellAtlas = null;
      const appliedText = formatDefenceBuffApplied(spell, bonus, reductionPercent);
      addCombatText("player", appliedText, "buff", now);
      pushBattleLog(`${spell.label} strengthens defence (${appliedText}, ${formatBuffRemaining(durationMs)}).`);
    } else {
      queueDefenceBuffImpactTargets(spell, now, {
        worldX: state.battle.playerX,
      });
      battle.activeTaoSpell = null;
      battle.activeTaoSpellAtlas = null;
      showTaoistDefenceBuffTexts(spell, bonus, applied, now);
      pushBattleLog(`${spell.label} strengthens defence (${formatTaoistDefenceBuffAppliedLog(spell, bonus, applied, durationMs)}).`);
    }
  }
  playerHudSignature = "";
  battlePanelSignature = "";
  combatSkillBarSignature = "";
  refreshCharacterStatsOverlay();
  return true;
}

function usableWizardDefenceBuff(now, options = {}) {
  const spell = wizardCombatSpell("MagicShield");
  const learned = learnedMagic(spell?.id);
  const manual = options.requireAuto === false;
  if (!spell || !learned || !canUseWizardSpell(spell, learned, now, { requireAuto: !manual })) return null;
  if (state.battle.pendingDefenceBuff?.spellId === "MagicShield") return null;
  if (!manual && !needsDefenceBuff("MagicShield", now)) return null;
  return { spell, learned, cost: spellMpCost(spell, learned) };
}

function usableQueuedWizardDefenceBuff(now) {
  const queued = queuedCombatSpell("Wizard");
  if (!queued || queued.spell.id !== "MagicShield") return null;
  return usableWizardDefenceBuff(now, { requireAuto: false });
}

function maybeCastWizardDefenceBuff(now) {
  const battle = state.battle;
  if (battle.combatClass !== "Wizard" || battle.phase !== "engaged") return false;
  if (queuedCombatSpell("Wizard")?.spell.id === "MagicShield") return false;
  const castBundle = usableWizardDefenceBuff(now);
  return Boolean(castBundle && castWizardDefenceBuff(castBundle, now));
}

function castWizardDefenceBuff(castBundle, now, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost } = castBundle;
  if (battle.pendingDefenceBuff && battle.pendingDefenceBuff.spellId !== spell.id) return false;
  battle.lastPlayerAttackCooldownMs = wizardCastCooldownMs(spell, learned);
  commitWizardSpellUse(spell, learned, cost, now);

  if (options.offline) {
    applyDefenceBuffEffect(spell, learned, battle.player, now);
    return true;
  }

  battle.pendingDefenceBuff = {
    at: now + (Number(spell.impactDelayMs) || CRYSTAL_HEAL_APPLY_DELAY_MS),
    spellId: spell.id,
  };

  const atlas = state.wizardSpellAtlases[spell.id] ?? null;
  battle.activeSkill = "None";
  battle.activeSkillAtlas = null;
  battle.activeWizardSpell = spell.id;
  battle.activeWizardSpellAtlas = atlas;
  battle.activeWizardSpellStartedAt = now;
  battle.activeTaoSpell = null;
  battle.activeTaoSpellAtlas = null;
  battle.pendingImpact = null;
  setPlayerAction(spell.bodyAction ?? "spell", now, true);
  playSpellSfx(spell.id, "cast");
  pushBattleLog(`Wizard casts ${spell.label}.`);
  return true;
}

function castTaoistDefenceBuff(castBundle, now, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost, entry, item } = castBundle;
  if (battle.pendingDefenceBuff && battle.pendingDefenceBuff.spellId !== spell.id) return false;
  if (!consumeOneInventoryUnit(entry.id)) return false;
  battle.lastPlayerAttackCooldownMs = spellDelayMs(spell, learned);
  commitTaoistSpellUse(spell, learned, cost, now);

  if (options.offline) {
    applyTaoistDefenceBuffEffect(spell, learned, battle.player, now);
    return true;
  }

  battle.pendingDefenceBuff = {
    at: now + (Number(spell.impactDelayMs) || CRYSTAL_HEAL_APPLY_DELAY_MS),
    spellId: spell.id,
  };

  const atlas = state.taoistSpellAtlases[spell.id] ?? null;
  battle.activeSkill = "None";
  battle.activeSkillAtlas = null;
  battle.activeWizardSpell = null;
  battle.activeWizardSpellAtlas = null;
  battle.activeTaoSpell = spell.id;
  battle.activeTaoSpellAtlas = atlas;
  battle.activeTaoSpellStartedAt = now;
  battle.pendingPoison = null;
  setPlayerAction(spell.bodyAction ?? "spell", now, true);
  playSpellSfx(spell.id, "cast");
  pushBattleLog(`Taoist casts ${spell.label} with ${item.name}.`);
  return true;
}

function usableTaoistDefenceBuff(spellId, now, options = {}) {
  const spell = taoistCombatSpell(spellId);
  const learned = learnedMagic(spell?.id);
  const manual = options.requireAuto === false;
  if (!spell || !learned || !canUseTaoistSpell(spell, learned, now, { requireAuto: !manual })) return null;
  if (!manual && !needsDefenceBuff(spellId, now)) return null;
  const entry = amuletCandidate(0);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !isTaoistAmuletItem(item)) return null;
  return { spell, learned, cost: spellMpCost(spell, learned), entry, item };
}

function maybeCastTaoistDefenceBuffs(now) {
  const battle = state.battle;
  if (battle.combatClass !== "Taoist" || battle.phase !== "engaged") return false;
  if (queuedCombatSpell("Taoist")) return false;
  for (const spellId of ["SoulShield", "BlessedArmour"]) {
    const castBundle = usableTaoistDefenceBuff(spellId, now);
    if (castBundle && castTaoistDefenceBuff(castBundle, now)) return true;
  }
  return false;
}

function usableTaoistHealing(now, options = {}) {
  const spell = taoistCombatSpell("Healing");
  const learned = learnedMagic(spell.id);
  const manual = options.requireAuto === false;
  if (!canUseTaoistSpell(spell, learned, now, { requireAuto: !manual })) return null;
  const pet = taoistPetCanBeHealed() ? state.battle.taoPet : null;
  if (pet && (manual || pet.hp / Math.max(1, pet.maxHp) < AUTO_POTION_THRESHOLD)) {
    const pendingAmount = Math.max(0, Number(pet.healAmount) || 0)
      + (state.battle.pendingHeal?.target === "pet" ? Math.max(0, Number(state.battle.pendingHeal?.amount) || 0) : 0);
    if (pendingAmount < pet.maxHp - pet.hp) {
      return { spell, learned, cost: spellMpCost(spell, learned), target: "pet" };
    }
  }
  const player = state.battle.player;
  if (!player || player.hp <= 0 || player.hp >= player.maxHp) return null;
  if (!manual && player.hp / Math.max(1, player.maxHp) >= AUTO_POTION_THRESHOLD) return null;
  const pendingAmount = Math.max(0, Number(state.battle.healAmount) || 0)
    + (state.battle.pendingHeal?.target === "pet" ? 0 : Math.max(0, Number(state.battle.pendingHeal?.amount) || 0));
  if (pendingAmount >= player.maxHp - player.hp) return null;
  return { spell, learned, cost: spellMpCost(spell, learned), target: "player" };
}

function usableTaoistPoisoning(now, options = {}) {
  const spell = taoistCombatSpell("Poisoning");
  const learned = learnedMagic(spell.id);
  if (!canUseTaoistSpell(spell, learned, now, { requireAuto: options.requireAuto !== false })) return null;
  if (state.battle.pendingPoison) return null;
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0) return null;
  if (!options.ignoreRange && enemyDistance() > crystalSpellRangePx(spell)) return null;
  const entry = poisonCandidateForEnemy(enemy, now);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !isPoisonItem(item)) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry,
    item,
    kind: poisonItemKind(item),
  };
}

function usableTaoistSoulFireBall(now, options = {}) {
  const spell = taoistCombatSpell("SoulFireBall");
  const learned = learnedMagic(spell.id);
  if (!canUseTaoistSpell(spell, learned, now, { requireAuto: options.requireAuto !== false })) return null;
  const enemy = state.battle.enemy;
  if (!enemy || enemy.hp <= 0) return null;
  if (!options.ignoreRange && enemyDistance() > taoistSoulFireBallRangePx(spell)) return null;
  const entry = amuletCandidate(0);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !isTaoistAmuletItem(item)) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry,
    item,
  };
}

function usableTaoistSummonSpell(spellId, now, options = {}) {
  const spell = taoistCombatSpell(spellId);
  if (!spell) return null;
  const learned = learnedMagic(spell.id);
  if (!canUseTaoistSpell(spell, learned, now, { requireAuto: options.requireAuto !== false })) return null;
  const battle = state.battle;
  if (battle.taoPetDiedThisFight || battle.taoPet?.active || battle.pendingTaoPet) return null;
  const enemy = battle.enemy;
  if (!enemy || enemy.hp <= 0 || battle.combatClass !== "Taoist") return null;
  if (!options.ignoreRange && enemyDistance() > taoistSummonPetRangePx()) return null;
  const amuletCost = taoistSummonAmuletCost(spell.id);
  const entry = amuletCandidate(0);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !isTaoistAmuletItem(item) || amuletInventoryCount() < amuletCost) return null;
  return {
    spell,
    learned,
    cost: spellMpCost(spell, learned),
    entry,
    item,
    amuletCost,
  };
}

function usableTaoistSummonSkeleton(now, options = {}) {
  return usableTaoistSummonSpell("SummonSkeleton", now, options);
}

function usableTaoistSummonShinsu(now, options = {}) {
  return usableTaoistSummonSpell("SummonShinsu", now, options);
}

function maybeCastTaoistSummonPet(now) {
  const battle = state.battle;
  if (battle.combatClass !== "Taoist" || battle.phase !== "engaged") return false;
  if (queuedCombatSpell("Taoist")) return false;
  for (const spellId of ["SummonSkeleton", "SummonShinsu"]) {
    const summon = usableTaoistSummonSpell(spellId, now);
    if (summon && castTaoistSummonPet(summon, now)) return true;
  }
  return false;
}

function maybeCastTaoistSummonSkeleton(now) {
  return maybeCastTaoistSummonPet(now);
}

function usableQueuedTaoistSpell(now) {
  const queued = queuedCombatSpell("Taoist");
  if (!queued) return null;
  if (queued.spell.id === "Healing") return usableTaoistHealing(now, { requireAuto: false });
  if (queued.spell.id === "Poisoning") return usableTaoistPoisoning(now, { requireAuto: false });
  if (queued.spell.id === "SoulFireBall") return usableTaoistSoulFireBall(now, { requireAuto: false });
  if (queued.spell.id === "SummonSkeleton") return usableTaoistSummonSkeleton(now, { requireAuto: false });
  if (queued.spell.id === "SummonShinsu") return usableTaoistSummonShinsu(now, { requireAuto: false });
  if (queued.spell.id === "SoulShield") return usableTaoistDefenceBuff("SoulShield", now, { requireAuto: false });
  if (queued.spell.id === "BlessedArmour") return usableTaoistDefenceBuff("BlessedArmour", now, { requireAuto: false });
  if (queued.spell.id === "UltimateEnhancer") return usableTaoistUltimateEnhancer(now, { requireAuto: false });
  clearQueuedCombatSpell(queued.spell.id);
  return null;
}

function castQueuedTaoistSpell(queued, now) {
  if (!queued?.spell) return false;
  if (queued.spell.id === "Healing") return castTaoistHealing(queued, now);
  if (queued.spell.id === "Poisoning") return castTaoistPoisoning(queued, now);
  if (queued.spell.id === "SoulFireBall") return castTaoistSoulFireBall(queued, now);
  if (queued.spell.id === "SummonSkeleton" || queued.spell.id === "SummonShinsu") return castTaoistSummonPet(queued, now);
  if (queued.spell.id === "SoulShield" || queued.spell.id === "BlessedArmour") return castTaoistDefenceBuff(queued, now);
  if (queued.spell.id === "UltimateEnhancer") return castTaoistUltimateEnhancer(queued, now);
  return false;
}

function castTaoistSummonPet(summon, now, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost, item, amuletCost = taoistSummonAmuletCost(spell.id) } = summon;
  if (battle.taoPet?.active || battle.pendingTaoPet) return false;
  if (!consumeAmuletInventoryUnits(amuletCost)) return false;
  commitTaoistSpellUse(spell, learned, cost, now);
  levelMagicSkill(spell, learned, now);

  const delayMs = spell.id === "SummonShinsu"
    ? CRYSTAL_SUMMON_SHINSU_DELAY_MS
    : CRYSTAL_SUMMON_SKELETON_DELAY_MS;
  battle.pendingTaoPet = {
    at: now + delayMs,
    spellId: spell.id,
    spellLevel: Math.max(0, Math.trunc(Number(learned?.level) || 0)),
  };

  if (!options.offline) {
    const atlas = state.taoistSpellAtlases[spell.id] ?? null;
    battle.activeSkill = "None";
    battle.activeSkillAtlas = null;
    battle.activeWizardSpell = null;
    battle.activeWizardSpellAtlas = null;
    battle.activeTaoSpell = spell.id;
    battle.activeTaoSpellAtlas = atlas;
    battle.activeTaoSpellStartedAt = now;
    setPlayerAction(spell.bodyAction ?? "spell", now, true);
    playSpellSfx(spell.id, "cast");
    const amuletText = amuletCost > 1 ? `${amuletCost} ${item.name}s` : item.name;
    pushBattleLog(`Taoist casts ${spell.label} with ${amuletText}.`);
  }
  return true;
}

function castTaoistSummonSkeleton(summon, now, options = {}) {
  return castTaoistSummonPet(summon, now, options);
}

function updatePendingTaoPet(now) {
  const battle = state.battle;
  const pending = battle.pendingTaoPet;
  if (!pending || now < pending.at) return false;
  battle.pendingTaoPet = null;
  if (battle.combatClass !== "Taoist" || !battle.enemy || battle.enemy.hp <= 0 || !battle.running) return true;
  battle.taoPet = createTaoistSummonPet(pending.spellId, pending.spellLevel, now);
  state.taoPetAtlas = taoPetAtlasFor(battle.taoPet);
  battle.enemyAggro = true;
  playTaoPetAppearSfx({ volume: 0.48, throttleMs: 250 });
  pushBattleLog(`${battle.taoPet.name} joins the fight.`);
  battlePanelSignature = "";
  return true;
}

function createTaoistSummonPet(spellId, spellLevel, now = performance.now()) {
  if (spellId === "SummonShinsu") return createTaoistShinsuPet(spellLevel, now);
  return createTaoistSkeletonPet(spellLevel, now);
}

function createTaoistSkeletonPet(spellLevel, now = performance.now()) {
  const level = Math.max(0, Math.min(3, Math.trunc(Number(spellLevel) || 0)));
  const maxPetLevel = 4 + level;
  const stats = CRYSTAL_SUMMON_SKELETON_PET_STATS;
  const attackMs = Math.max(400, Math.trunc(stats.attackMs - maxPetLevel * 70));
  const pet = {
    active: true,
    dead: false,
    spellId: "SummonSkeleton",
    name: stats.name,
    monsterIndex: CRYSTAL_SUMMON_SKELETON_PET_INDEX,
    worldX: 0,
    level,
    maxPetLevel,
    maxHp: stats.maxHp + level * 20,
    hp: stats.maxHp + level * 20,
    dc: [stats.dc[0] + level, stats.dc[1] + level],
    ac: [stats.ac[0] + level * 2, stats.ac[1] + level * 2],
    amc: [stats.amc[0] + level * 2, stats.amc[1] + level * 2],
    accuracy: stats.accuracy,
    agility: stats.agility,
    luck: stats.luck,
    attackMs,
    nextAttackAt: now + 1000,
    healAmount: 0,
    healTickAt: 0,
    action: "standing",
    frame: 0,
    oneShot: false,
    lastTick: now,
    poisons: [],
    statBuffs: [],
  };
  return placeTaoistCombatPet(pet);
}

function createTaoistShinsuPet(spellLevel, now = performance.now()) {
  const level = Math.max(0, Math.min(3, Math.trunc(Number(spellLevel) || 0)));
  const maxPetLevel = 1 + level * 2;
  const stats = CRYSTAL_SUMMON_SHINSU_PET_STATS;
  const attackMs = Math.max(400, Math.trunc(stats.attackMs - maxPetLevel * 70));
  const pet = {
    active: true,
    dead: false,
    spellId: "SummonShinsu",
    name: stats.name,
    monsterIndex: CRYSTAL_SUMMON_SHINSU_PET_INDEX,
    shinsuVisible: false,
    worldX: 0,
    level,
    maxPetLevel,
    maxHp: stats.maxHp + level * 20,
    hp: stats.maxHp + level * 20,
    dc: [stats.dc[0] + level, stats.dc[1] + level],
    ac: [stats.ac[0] + level * 2, stats.ac[1] + level * 2],
    amc: [stats.amc[0] + level * 2, stats.amc[1] + level * 2],
    accuracy: stats.accuracy,
    agility: stats.agility,
    luck: stats.luck,
    attackMs,
    nextAttackAt: now + 1000,
    healAmount: 0,
    healTickAt: 0,
    action: "show",
    frame: 0,
    oneShot: true,
    lastTick: now,
    poisons: [],
    statBuffs: [],
  };
  return placeTaoistCombatPet(pet);
}

function taoShinsuPetMonsterIndex(pet) {
  if (!pet || pet.spellId !== "SummonShinsu") return CRYSTAL_SUMMON_SHINSU_PET_INDEX;
  if (pet.shinsuVisible || pet.action === "attack1" || pet.action === "struck" || pet.action === "die" || pet.action === "dead") {
    return CRYSTAL_SUMMON_SHINSU_VISIBLE_PET_INDEX;
  }
  return CRYSTAL_SUMMON_SHINSU_PET_INDEX;
}

function revealTaoistShinsuPet(pet) {
  if (!pet || pet.spellId !== "SummonShinsu" || pet.shinsuVisible) return;
  pet.shinsuVisible = true;
  pet.monsterIndex = CRYSTAL_SUMMON_SHINSU_VISIBLE_PET_INDEX;
}

function taoistPetRenderMonsterIndex(pet) {
  if (pet?.spellId === "SummonShinsu") return taoShinsuPetMonsterIndex(pet);
  return Math.trunc(Number(pet?.monsterIndex) || CRYSTAL_SUMMON_SKELETON_PET_INDEX);
}

function taoistPetAttackRangePx(pet) {
  if (pet?.spellId === "SummonShinsu") return CRYSTAL_SUMMON_SHINSU_ATTACK_RANGE_PX;
  return LANE.enemyRange + 4;
}

function taoistShinsuAttackImpactMs() {
  const atlas = state.taoPetAtlases?.[CRYSTAL_SUMMON_SHINSU_VISIBLE_PET_INDEX];
  const interval = Math.max(1, Math.trunc(Number(atlas?.actions?.attack1?.interval) || 100));
  return CRYSTAL_SHINSU_ATTACK_IMPACT_FRAME * interval;
}

function rollTaoistPetAttackResult(pet, enemy) {
  if (!rollHit(pet.accuracy, enemy.agility)) return { hit: false, damage: 0 };
  const damage = rollDamage(effectiveCombatStats(pet).dc, enemyPhysicalDefence(enemy), pet.luck);
  return { hit: damage > 0, damage };
}

function applyTaoistPetAttackResult(pet, enemy, result, now, options = {}) {
  const offline = Boolean(options.offline);
  const bossParty = Boolean(options.bossParty);
  if (!result.hit || result.damage <= 0) {
    if (!offline) {
      addCombatText("enemy", "Miss", "miss", now);
      pushBattleLog(`${pet.name} misses ${enemy.name}.`);
    }
    return;
  }
  reduceEnemyHp(enemy, result.damage);
  if (bossParty) {
    syncBattleEnemyHpToSwarm();
    strikeGroupDungeonSwarmEnemy(enemy, now);
  }
  if (!offline) {
    setEnemyAction("struck", true, now);
    playMonsterSfx("flinch");
    if (!options.skipHitSfx) {
      playTaoPetSfx("hit", { volume: 0.38, throttleMs: 120, pet });
    }
    addCombatText("enemy", result.damage, "damage", now);
    pushBattleLog(`${pet.name} hits ${enemy.name} for ${result.damage}.`);
  }
  if (enemy.hp <= 0) {
    if (offline) return;
    if (bossParty) {
      maybeKillGroupDungeonSwarmEnemy(enemy, now);
      return;
    }
    finishEnemy(now);
    setEnemyAction("die", false, now);
    playMonsterSfx("death");
    pushBattleLog(`${enemy.name} is defeated.`);
  }
}

function updatePendingPetAttack(now, options = {}) {
  const battle = state.battle;
  const impact = battle.pendingPetAttack;
  if (!impact || now < impact.at) return false;
  battle.pendingPetAttack = null;
  const pet = battle.taoPet ?? battle.bossParty?.pet;
  const enemy = battle.enemy;
  if (!pet?.active || !enemy || enemy.hp <= 0) return true;
  const offline = Boolean(options.offline || impact.offline);
  if (!offline) playTaoPetSfx("hit", { volume: 0.38, throttleMs: 120, pet });
  applyTaoistPetAttackResult(pet, enemy, impact, now, {
    offline,
    bossParty: Boolean(impact.bossParty),
    skipHitSfx: true,
  });
  return true;
}

function taoPetAtlasFor(pet) {
  const index = taoistPetRenderMonsterIndex(pet);
  return state.taoPetAtlases?.[index] ?? state.taoPetAtlas;
}

function taoistPetSummonWorldX() {
  const battle = state.battle;
  const playerX = Number(battle.playerX) || 0;
  const enemyX = Math.max(playerX + TAOIST_PET_SUMMON_MIN_GAP + 1, Number(battle.enemyX) || playerX);
  const desired = enemyX - TAOIST_PET_ENEMY_GAP;
  return clampNumber(desired, playerX + TAOIST_PET_SUMMON_MIN_GAP, enemyX - 12);
}

function clampNumber(value, min, max) {
  const safeMin = Math.min(min, max);
  const safeMax = Math.max(min, max);
  return Math.max(safeMin, Math.min(safeMax, Number(value) || 0));
}

function dismissTaoistPet(options = {}) {
  state.battle.pendingTaoPet = null;
  state.battle.pendingPetAttack = null;
  state.battle.taoPet = null;
  state.battle.petStatBuffs = [];
  if (options.clearDeathLock !== false) state.battle.taoPetDiedThisFight = false;
}

function taoistPetCanTank() {
  const pet = state.battle.taoPet;
  return state.battle.combatClass === "Taoist"
    && Boolean(pet?.active)
    && (pet.hp ?? 0) > 0;
}

function taoistPetCanBeHealed() {
  const pet = state.battle.taoPet;
  return state.battle.combatClass === "Taoist" && Boolean(pet?.active) && (pet.hp ?? 0) > 0 && (pet.hp ?? 0) < (pet.maxHp ?? 0);
}

function taoistPetEnemyDistance() {
  const pet = state.battle.taoPet;
  if (!pet) return Infinity;
  return Math.max(0, (Number(state.battle.enemyX) || 0) - resolvedTaoPetWorldX(pet));
}

function markTaoistPetDead(now = performance.now(), options = {}) {
  const pet = state.battle.taoPet;
  if (!pet || pet.dead) return;
  pet.active = false;
  pet.dead = true;
  pet.hp = 0;
  pet.healAmount = 0;
  pet.healTickAt = 0;
  pet.action = "die";
  pet.frame = 0;
  pet.oneShot = true;
  pet.lastTick = now;
  state.battle.taoPetDiedThisFight = true;
  state.battle.nextPlayerAttackAt = 0;
  state.battle.nextEnemyAttackAt = 0;
  if (options.sound !== false) playTaoPetSfx("death", { volume: 0.46, throttleMs: 120 });
  if (options.log !== false) pushBattleLog(options.message ?? `${pet.name} falls.`);
  battlePanelSignature = "";
  combatSkillBarSignature = "";
}

function retireTaoistPetAfterFight(now = performance.now()) {
  const pet = state.battle.taoPet;
  if (!pet || pet.dead) return;
  markTaoistPetDead(now, { message: `${pet.name} collapses after the fight.` });
}

function taoistPetSupportAttack(now) {
  const queuedRequest = queuedCombatSpell("Taoist");
  const queued = usableQueuedTaoistSpell(now);
  if (queued && castQueuedTaoistSpell(queued, now)) return true;
  if (queuedRequest) {
    if (!isPlayerOneShotAction()) setPlayerLocomotion("stance", now);
    return false;
  }

  const healing = usableTaoistHealing(now);
  if (healing) return castTaoistHealing(healing, now);

  for (const spellId of ["SoulShield", "BlessedArmour"]) {
    const defenceBuff = usableTaoistDefenceBuff(spellId, now);
    if (defenceBuff) return castTaoistDefenceBuff(defenceBuff, now);
  }

  const ultimateEnhancer = usableTaoistUltimateEnhancer(now);
  if (ultimateEnhancer) return castTaoistUltimateEnhancer(ultimateEnhancer, now);

  const poisoning = usableTaoistPoisoning(now);
  if (poisoning) return castTaoistPoisoning(poisoning, now);

  const soulFireBall = usableTaoistSoulFireBall(now);
  if (soulFireBall) return castTaoistSoulFireBall(soulFireBall, now);

  if (!isPlayerOneShotAction()) setPlayerLocomotion("stance", now);
  return false;
}

function taoistAttack(now) {
  const queuedRequest = queuedCombatSpell("Taoist");
  const queued = usableQueuedTaoistSpell(now);
  if (queued && castQueuedTaoistSpell(queued, now)) return;
  if (queuedRequest) {
    if (enemyDistance() > LANE.warriorRange) {
      state.battle.lastPlayerAttackCooldownMs = TAOIST_COMBAT_POLL_MS;
      if (!isPlayerOneShotAction()) setPlayerLocomotion("stance", now);
      return;
    }
    taoistWeaponAttack(now);
    return;
  }

  const healing = usableTaoistHealing(now);
  if (healing) {
    castTaoistHealing(healing, now);
    return;
  }

  for (const spellId of ["SoulShield", "BlessedArmour"]) {
    const defenceBuff = usableTaoistDefenceBuff(spellId, now);
    if (defenceBuff) {
      castTaoistDefenceBuff(defenceBuff, now);
      return;
    }
  }

  const ultimateEnhancer = usableTaoistUltimateEnhancer(now);
  if (ultimateEnhancer) {
    castTaoistUltimateEnhancer(ultimateEnhancer, now);
    return;
  }

  const summon = usableTaoistSummonSkeleton(now);
  if (summon) {
    castTaoistSummonPet(summon, now);
    return;
  }

  const shinsu = usableTaoistSummonShinsu(now);
  if (shinsu) {
    castTaoistSummonPet(shinsu, now);
    return;
  }

  const poisoning = usableTaoistPoisoning(now);
  if (poisoning) {
    castTaoistPoisoning(poisoning, now);
    return;
  }

  taoistWeaponAttack(now);
}

function castTaoistHealing(healing, now, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost, target = "player" } = healing;
  const atlas = state.taoistSpellAtlases[spell.id] ?? null;
  const amount = rollTaoistHealingAmount(spell, learned, battle.player);
  battle.lastPlayerAttackCooldownMs = spellDelayMs(spell, learned);
  commitTaoistSpellUse(spell, learned, cost, now);

  battle.pendingHeal = {
    at: now + CRYSTAL_HEAL_APPLY_DELAY_MS,
    spellId: spell.id,
    amount,
    target,
  };

  if (!options.offline) {
    battle.activeSkill = "None";
    battle.activeSkillAtlas = null;
    battle.activeWizardSpell = null;
    battle.activeWizardSpellAtlas = null;
    battle.activeTaoSpell = spell.id;
    battle.activeTaoSpellAtlas = atlas;
    battle.activeTaoSpellStartedAt = now;
    battle.pendingPoison = null;
    setPlayerAction(spell.bodyAction ?? "spell", now, true);
    playSpellSfx(spell.id, "cast");
    pushBattleLog(`Taoist casts ${spell.label}${target === "pet" ? ` on ${battle.taoPet?.name ?? "pet"}` : ""}.`);
  }
  return true;
}

function castTaoistPoisoning(poisoning, now, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost, entry, item, kind } = poisoning;
  if (battle.pendingPoison) return false;
  if (!consumeOneInventoryUnit(entry.id)) return false;
  battle.lastPlayerAttackCooldownMs = spellDelayMs(spell, learned);
  commitTaoistSpellUse(spell, learned, cost, now);

  battle.pendingPoison = {
    at: now + CRYSTAL_POISON_APPLY_DELAY_MS,
    spellId: spell.id,
    value: rollTaoistPoisonPower(spell, learned, battle.player),
    kind,
    itemName: item.name,
  };

  if (!options.offline) {
    const atlas = state.taoistSpellAtlases[spell.id] ?? null;
    battle.activeSkill = "None";
    battle.activeSkillAtlas = null;
    battle.activeWizardSpell = null;
    battle.activeWizardSpellAtlas = null;
    battle.activeTaoSpell = spell.id;
    battle.activeTaoSpellAtlas = atlas;
    battle.activeTaoSpellStartedAt = now;
    battle.pendingHeal = null;
    setPlayerAction(spell.bodyAction ?? "spell", now, true);
    playSpellSfx(spell.id, "cast");
    pushBattleLog(`Taoist casts ${spell.label} with ${item.name}.`);
  }
  return true;
}

function maybeCastTaoistSoulFireBall(now) {
  const battle = state.battle;
  if (battle.combatClass !== "Taoist" || battle.phase !== "engaged") return false;
  if (battle.pendingImpact?.spellId === "SoulFireBall") return false;
  if (activeTaoistSpellVisualBlocksSecondary(now)) return false;
  const soulFireBall = usableTaoistSoulFireBall(now);
  if (!soulFireBall) return false;
  if (battle.activeTaoSpellStartedAt === now && battle.activeTaoSpell !== "SoulFireBall") return false;
  return castTaoistSoulFireBall(soulFireBall, now, { secondary: true });
}

function activeTaoistSpellVisualBlocksSecondary(now) {
  const battle = state.battle;
  if (!battle.activeTaoSpell || battle.activeTaoSpell === "SoulFireBall") return false;
  if (battle.pendingHeal || battle.pendingPoison || battle.pendingTaoPet || battle.pendingDefenceBuff || battle.pendingUltimateEnhancer) return true;
  const elapsed = now - (battle.activeTaoSpellStartedAt || 0);
  return elapsed >= 0 && elapsed < combatSpellVisualDurationMs(battle.activeTaoSpellAtlas);
}

function combatSpellVisualDurationMs(atlas) {
  const layerDurations = (atlas?.layers ?? []).map((layer) => (
    (Number(layer.delayMs) || 0) + Math.max(0, (layer.frames?.length ?? 0) * (Number(layer.interval) || 0))
  ));
  if (atlas?.projectile) {
    layerDurations.push((Number(atlas.projectile.delayMs) || 0) + (Number(atlas.projectile.moveDurationMs) || 0));
  }
  if (atlas?.impact) {
    layerDurations.push((Number(atlas.impact.delayMs) || 0) + Math.max(0, (atlas.impact.frames?.length ?? 0) * (Number(atlas.impact.interval) || 0)));
  }
  return Math.max(0, ...layerDurations);
}

function castTaoistSoulFireBall(soulFireBall, now, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost, entry, item } = soulFireBall;
  const secondary = Boolean(options.secondary);
  if (!consumeOneInventoryUnit(entry.id)) return false;
  const atlas = state.taoistSpellAtlases[spell.id] ?? null;
  const hit = rollMagicHit(battle.enemy);
  const damage = hit ? rollTaoistMagicDamage(spell, learned, battle.player, battle.enemy) : 0;
  const impactAt = now + wizardImpactDelay(spell, atlas);

  if (!secondary) battle.lastPlayerAttackCooldownMs = spellDelayMs(spell, learned);
  commitTaoistSpellUse(spell, learned, cost, now);
  battle.activeWizardSpell = null;
  battle.activeWizardSpellAtlas = null;
  battle.activeTaoSpell = spell.id;
  battle.activeTaoSpellAtlas = atlas;
  battle.activeTaoSpellStartedAt = now;
  battle.pendingImpact = { at: impactAt, spellId: spell.id, damage, hit: hit && damage > 0 };
  if (!secondary) {
    battle.activeSkill = "None";
    battle.activeSkillAtlas = null;
    battle.pendingHeal = null;
    battle.pendingPoison = null;
  }

  if (!secondary || !isPlayerOneShotAction()) setPlayerAction(spell.bodyAction ?? "spell", now, true);
  playSpellSfx(spell.id, "cast");
  playSpellSfx(spell.id, "fly", { volume: 0.38, throttleMs: 120 });
  pushBattleLog(`Taoist casts ${spell.label} with ${item.name}.`);
  return true;
}

function updateTaoistPetAttack(now, options = {}) {
  const battle = state.battle;
  const pet = battle.taoPet;
  if (battle.combatClass !== "Taoist" || !pet?.active || !battle.enemy || battle.enemy.hp <= 0) return false;
  if (combatantParalyzed(pet)) return false;
  if (battle.pendingPetAttack) return false;
  if (now < (pet.nextAttackAt ?? 0)) return false;
  if (pet.spellId === "SummonShinsu" && !pet.shinsuVisible && pet.action === "show") {
    if (!options.offline) return false;
    revealTaoistShinsuPet(pet);
    pet.action = "standing";
    pet.frame = 0;
    pet.oneShot = false;
  }
  if (taoistPetEnemyDistance() > taoistPetAttackRangePx(pet)) {
    if (!options.offline) setTaoPetAction("standing", false, now);
    return false;
  }
  pet.nextAttackAt = now + Math.max(400, Math.trunc(Number(pet.attackMs) || 1200));
  return taoistPetAttack(now, options);
}

function taoistPetAttack(now, options = {}) {
  const battle = state.battle;
  const pet = battle.taoPet;
  const enemy = battle.enemy;
  if (!pet?.active || !enemy || enemy.hp <= 0) return false;

  battle.enemyAggro = true;
  revealTaoistShinsuPet(pet);
  const result = rollTaoistPetAttackResult(pet, enemy);
  if (!options.offline) {
    setTaoPetAction("attack1", true, now);
  }

  if (pet.spellId === "SummonShinsu") {
    if (!options.offline) playTaoPetSfx("attack", { volume: 0.36, throttleMs: 250 });
    battle.pendingPetAttack = {
      at: now + taoistShinsuAttackImpactMs(),
      hit: result.hit,
      damage: result.damage,
      offline: Boolean(options.offline),
      bossParty: false,
    };
    return true;
  }

  if (!options.offline) playTaoPetSfx("attack", { volume: 0.36, throttleMs: 250 });
  applyTaoistPetAttackResult(pet, enemy, result, now, options);
  return true;
}

function setTaoPetAction(action, oneShot = false, now = performance.now()) {
  const pet = state.battle.taoPet;
  if (!pet?.active) return;
  pet.action = action;
  pet.frame = 0;
  pet.oneShot = oneShot;
  pet.lastTick = now;
  if (action === "struck" && oneShot) {
    playTaoPetFlinchSfx({ pet });
  }
}

function playTaoPetSfx(kind, options = {}) {
  const pet = options.pet ?? state.battle.taoPet;
  const family = pet?.spellId === "SummonShinsu" ? "shinsu" : "skeleton";
  return playSfx(`pet.${family}.${kind}`, {
    volume: options.volume ?? 0.42,
    throttleMs: options.throttleMs ?? 120,
  });
}

function playTaoPetFlinchSfx(options = {}) {
  const pet = options.pet ?? state.battle.taoPet ?? state.battle.bossParty?.pet;
  const family = pet?.spellId === "SummonShinsu" ? "shinsu" : "skeleton";
  const kind = family === "shinsu" && !pet?.shinsuVisible ? "flinchBuried" : "flinch";
  return playSfx(`pet.${family}.${kind}`, {
    volume: options.volume ?? 0.42,
    throttleMs: options.throttleMs ?? 120,
  });
}

function playTaoPetAppearSfx(options = {}) {
  const pet = options.pet ?? state.battle.taoPet ?? state.battle.bossParty?.pet;
  const kind = pet?.spellId === "SummonShinsu" ? "show" : "summon";
  return playTaoPetSfx(kind, { ...options, pet });
}

function taoistWeaponAttack(now, failedSpell = null) {
  const battle = state.battle;
  const weaponEntry = equippedEntry("weapon");
  const weapon = weaponEntry ? itemDefinition(weaponEntry.itemId) : null;
  const weaponName = weapon ? itemDisplayName(weapon, weaponEntry) : "weapon";

  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, BASIC_ATTACK_SKILL);
  battle.activeSkill = BASIC_ATTACK_SKILL.id;
  battle.activeSkillAtlas = null;
  battle.activeWizardSpell = null;
  battle.activeWizardSpellAtlas = null;
  battle.pendingHeal = null;

  setPlayerAction(BASIC_ATTACK_SKILL.bodyAction, now, true);
  playWeaponSwingSfx();
  if (failedSpell && (!battle.lastNoMpLogAt || now - battle.lastNoMpLogAt > 5000)) {
    battle.lastNoMpLogAt = now;
    pushBattleLog(`Not enough MP to cast ${failedSpell.label}; Taoist uses ${weaponName}.`);
    addCombatText("player", "No MP", "mana", now);
  }

  if (!rollHit(battle.player.accuracy, battle.enemy.agility)) {
    addCombatText("enemy", "Miss", "miss", now);
    pushBattleLog(`Taoist swings ${weaponName} at ${battle.enemy.name} but misses.`);
    return;
  }

  const damage = rollDamage(battle.player.dc, enemyPhysicalDefence(battle.enemy), battle.player.luck);
  if (damage <= 0) {
    addCombatText("enemy", "Miss", "miss", now);
    pushBattleLog(`Taoist swings ${weaponName} at ${battle.enemy.name} but misses.`);
    return;
  }
  reduceEnemyHp(battle.enemy, damage);
  setEnemyAction("struck", true, now);
  playMonsterSfx("flinch");
  playWeaponHitSfx();
  addCombatText("enemy", damage, "damage", now);
  pushBattleLog(`Taoist hits ${battle.enemy.name} with ${weaponName} for ${damage}.`);
  if (battle.enemy.hp > 0) applyCrystalFreezingAttackProc(battle.player, battle.enemy, now);
  levelPassiveWeaponMagic(now);

  if (battle.enemy.hp <= 0) {
    finishEnemy(now);
    setEnemyAction("die", false, now);
    playMonsterSfx("death");
    pushBattleLog(`${battle.enemy.name} is defeated.`);
  }
}

function wizardBangCenterTile(enemy = null, spell = null, member = null) {
  const battle = state.battle;
  if (groupDungeonSwarmSideActive()) {
    const bestCenter = groupDungeonSwarmBestBangCenterTile(spell, member);
    if (bestCenter) return bestCenter;
    if (enemy?.swarmId) {
      const swarmEnemy = findGroupDungeonSwarmEnemy(enemy.swarmId);
      if (swarmEnemy) return swarmEnemyTilePosition(swarmEnemy);
    }
    if (groupDungeonSwarmLivingEnemies().length) return groupDungeonSwarmFireWallCenterTile();
  }
  return { worldX: swarmSnapTileX(battle.enemyX), mapRow: 0 };
}

function enemiesInSpellBangArea(centerTile) {
  if (groupDungeonSwarmSideActive()) {
    const tiles = spellBangAreaTiles(centerTile.worldX, centerTile.mapRow);
    const swarmEnemies = (state.battle.swarm?.enemies ?? []).filter((swarmEnemy) => {
      if (swarmEnemy.hp <= 0 || swarmEnemy.dying) return false;
      const tile = swarmEnemyReservedTile(swarmEnemy);
      return tiles.some((entry) => entry.worldX === tile.worldX && entry.mapRow === tile.mapRow);
    });
    if (swarmEnemies.length || groupDungeonSwarmSideActive()) return swarmEnemies;
  }
  const battle = state.battle;
  if (battle.enemy?.hp > 0 && battle.enemyRevealed) return [battle.enemy];
  return [];
}

function wizardBangTargetCount(centerTile = null, spell = null, member = null) {
  return enemiesInSpellBangArea(centerTile ?? wizardBangCenterTile(null, spell, member)).length;
}

function wizardAutoBangMinimumTargets(spell) {
  return 1;
}

function wizardAutoSpellEligible(spell, member = null) {
  if (spell?.impactMode === "bang") {
    return wizardBangTargetCount(groupDungeonSwarmBestBangCenterTile(spell, member), spell, member) >= wizardAutoBangMinimumTargets(spell);
  }
  return true;
}

function applyWizardBangSpellImpact(spell, impact, now, options = {}) {
  const battle = state.battle;
  const baseValue = Math.max(0, Math.trunc(Number(impact.baseValue) || 0));
  const centerTile = impact.centerTile ?? wizardBangCenterTile();
  const learned = options.learned ?? learnedMagic(spell.id);
  const sfx = options.sfx ?? { volume: 0.42, throttleMs: 80 };

  playSpellStrikeSfx(spell.id, { volume: 0.5, force: true, throttleMs: 0 });

  if (groupDungeonSwarmSideActive()) {
    const swarmEnemies = enemiesInSpellBangArea(centerTile);
    if (swarmEnemies.length) {
      let anyHit = false;
      for (const swarmEnemy of swarmEnemies) {
        if (!rollMagicHit(swarmEnemy)) {
          pushBattleLog(`${spell.label} misses ${swarmEnemy.name}.`);
          continue;
        }
        const damage = applyWizardMagicDefence(baseValue, swarmEnemy);
        if (damage <= 0) {
          addSwarmEnemyCombatText(swarmEnemy, "0", "damage", now);
          pushBattleLog(`${spell.label} is resisted by ${swarmEnemy.name}.`);
          continue;
        }
        anyHit = true;
        reduceSwarmEnemyHp(swarmEnemy, damage, now);
        addSwarmEnemyCombatText(swarmEnemy, damage, "damage", now);
        const entity = swarmEnemyToBattleEntity(swarmEnemy);
        strikeGroupDungeonSwarmEnemy(entity, now);
        playMonsterSfx("flinch", swarmEnemy, sfx);
        pushBattleLog(`${spell.label} hits ${swarmEnemy.name} for ${damage}.`);
        maybeKillGroupDungeonSwarmEnemy(entity, now);
      }
      syncGroupDungeonPrimaryEnemy();
      if (learned && anyHit) {
        if (options.partyMember) bossPartyLevelMagicSkill(options.partyMember, spell, learned, now);
        else levelMagicSkill(spell, learned, now);
      } else if (!anyHit && swarmEnemies.length) {
        pushBattleLog(`${spell.label} misses.`);
      }
      return;
    }
    if (groupDungeonSwarmSideActive()) {
      if (learned) {
        if (options.partyMember) bossPartyLevelMagicSkill(options.partyMember, spell, learned, now);
        else levelMagicSkill(spell, learned, now);
      }
      pushBattleLog(`${spell.label} misses.`);
      return;
    }
  }

  const canApply = battle.enemy && battle.enemy.hp > 0 && battle.enemyRevealed;
  if (!canApply) return;
  if (!rollMagicHit(battle.enemy)) {
    addCombatText("enemy", "Miss", "miss", now);
    pushBattleLog(`${spell.label} misses ${battle.enemy.name}.`);
    return;
  }
  const damage = applyWizardMagicDefence(baseValue, battle.enemy);
  if (damage <= 0) {
    addCombatText("enemy", "0", "damage", now);
    pushBattleLog(`${spell.label} is resisted by ${battle.enemy.name}.`);
    return;
  }
  reduceEnemyHp(battle.enemy, damage);
  setEnemyAction("struck", true, now);
  playMonsterSfx("flinch");
  addCombatText("enemy", damage, "damage", now);
  pushBattleLog(`${spell.label} hits ${battle.enemy.name} for ${damage}.`);
  if (learned) {
    if (options.partyMember) bossPartyLevelMagicSkill(options.partyMember, spell, learned, now);
    else levelMagicSkill(spell, learned, now);
  }
  if (battle.enemy.hp <= 0) {
    finishEnemy(now);
    setEnemyAction("die", false, now);
    playMonsterSfx("death");
    pushBattleLog(`${battle.enemy.name} is defeated.`);
  }
}

function updatePendingImpact(now) {
  const battle = state.battle;
  const impact = battle.pendingImpact;
  if (!impact || now < impact.at) return;
  const spell = combatAttackSpell(impact.spellId);
  battle.pendingImpact = null;
  if (!spell) return;
  if (spell.impactMode === "bang") {
    applyWizardBangSpellImpact(spell, impact, now);
    return;
  }
  if (spell.impactMode === "ground") {
    createWizardGroundSpellEffect(spell, impact, now);
    return;
  }
  playSpellStrikeSfx(spell.id, { volume: 0.5, force: true, throttleMs: 0 });
  const canApply = battle.enemy && battle.enemy.hp > 0 && battle.enemyRevealed;
  if (!canApply) return;
  if (!impact.hit) {
    addCombatText("enemy", "Miss", "miss", now);
    pushBattleLog(`${spell.label} misses ${battle.enemy.name}.`);
    return;
  }
  reduceEnemyHp(battle.enemy, impact.damage);
  setEnemyAction("struck", true, now);
  playMonsterSfx("flinch");
  addCombatText("enemy", impact.damage, "damage", now);
  pushBattleLog(`${spell.label} hits ${battle.enemy.name} for ${impact.damage}.`);
  const learned = learnedMagic(spell.id);
  if (spell.id === "FrostCrunch" && impact.damage > 0 && learned) {
    applyFrostCrunchEffects(battle.enemy, learned, battle.player, now);
  }
  if (learned) levelMagicSkill(spell, learned, now);

  if (battle.enemy.hp <= 0) {
    finishEnemy(now);
    setEnemyAction("die", false, now);
    playMonsterSfx("death");
    pushBattleLog(`${battle.enemy.name} is defeated.`);
  }
}

function createWizardGroundSpellEffect(spell, impact, now, partyCaster = null, partyLearned = null) {
  const battle = state.battle;
  const value = Math.max(0, Math.trunc(Number(impact.value) || 0));
  const widthTiles = Math.max(1, Math.trunc(Number(spell.groundWidthTiles) || 1));
  const halfWidth = Math.floor(widthTiles / 2);
  const offsets = Array.from({ length: widthTiles }, (_, index) => (index - halfWidth) * LANE_TILE_PX);
  const durationMs = wizardGroundEffectDurationMs(spell, value);
  const swarmActive = groupDungeonSwarmSideActive();
  const swarmCenterTile = swarmActive
    ? (impact.centerTile ?? groupDungeonSwarmBestFireWallCenterTile(spell, partyCaster, now) ?? groupDungeonSwarmFireWallCenterTile())
    : null;
  const effect = {
    id: `${spell.id}-${now}-${Math.random()}`,
    spellId: spell.id,
    worldX: swarmActive ? swarmCenterTile.worldX : (Number(impact.worldX) || battle.enemyX),
    offsets: swarmActive ? [] : offsets,
    tiles: swarmActive ? fireWallCrossTiles(swarmCenterTile.worldX, swarmCenterTile.mapRow) : null,
    value,
    createdAt: now,
    expiresAt: now + durationMs,
    nextTickAt: now,
    tickMs: Math.max(250, Math.trunc(Number(spell.groundTickMs) || 2000)),
  };
  battle.groundSpellEffects = [...(battle.groundSpellEffects ?? []), effect].slice(-8);
  const sfx = partyCaster
    ? bossPartySfxParams(partyCaster, 0.48, 0)
    : { volume: 0.48, throttleMs: 80 };
  playSpellSfx(spell.id, "impact", sfx) || playSpellSfx(spell.id, "cast", sfx);
  pushBattleLog(`${spell.label} burns on the ground.`);
  if (partyCaster && partyLearned) {
    bossPartyLevelMagicSkill(partyCaster, spell, partyLearned, now);
  } else {
    const learned = learnedMagic(spell.id);
    if (learned) levelMagicSkill(spell, learned, now);
  }
  updateGroundSpellEffects(now);
}

function wizardGroundEffectDurationMs(spell, value) {
  const base = Math.max(0, Math.trunc(Number(spell.groundDurationBaseMs) || 10000));
  const perPower = Math.max(0, Math.trunc(Number(spell.groundDurationPerPowerMs) || 500));
  return base + Math.max(0, Math.trunc(Number(value) || 0)) * perPower;
}

function mapLightningSettings(zone = activeZone()) {
  if (!zone?.mapLightning) return null;
  const min = Math.max(0, Math.trunc(Number(zone.mapLightningDamageMin ?? zone.mapLightningDamage) || 50));
  const max = Math.max(min, Math.trunc(Number(zone.mapLightningDamageMax ?? zone.mapLightningDamage) || 150));
  return { min, max };
}

function rollMapLightningDamage(settings) {
  return settings.min + Math.floor(Math.random() * (settings.max - settings.min + 1));
}

function mapLightningActive() {
  const settings = mapLightningSettings();
  if (!settings) return false;
  const battle = state.battle;
  if (!battle.running || battle.bossParty?.finished) return false;
  if (battle.bossParty?.active) {
    return !bossPartyAllMembersDead() && (battle.enemy?.hp ?? 0) > 0;
  }
  if (battle.phase !== "engaged" || (battle.player?.hp ?? 0) <= 0) return false;
  return Boolean(battle.enemy && battle.enemy.hp > 0);
}

function randomMapLightningIntervalMs() {
  return MAP_LIGHTNING_MIN_INTERVAL_MS
    + Math.floor(Math.random() * (MAP_LIGHTNING_MAX_INTERVAL_MS - MAP_LIGHTNING_MIN_INTERVAL_MS + 1));
}

function initMapLightningSchedule(now = performance.now()) {
  if (!mapLightningSettings()) {
    state.battle.mapLightningEffects = [];
    state.battle.nextMapLightningAt = 0;
    return;
  }
  state.battle.mapLightningEffects = [];
  state.battle.nextMapLightningAt = now + randomMapLightningIntervalMs();
}

function mapLightningTargetWorldX(target) {
  const worldX = Number(target?.worldX);
  if (Number.isFinite(worldX)) return worldX;
  if (target?.solo) return Number(state.battle.playerX) || 0;
  return Number(state.battle.playerX) || 0;
}

function mapLightningTargets() {
  const party = state.battle.bossParty;
  if (party?.active) {
    return (party.members ?? []).filter((member) => member.alive && member.hp > 0);
  }
  if ((state.battle.player?.hp ?? 0) > 0) {
    return [{ solo: true, classId: state.battle.combatClass, name: state.battle.combatClass, worldX: state.battle.playerX }];
  }
  return [];
}

function pickMapLightningWorldX(anchorWorldX) {
  const anchor = Math.round(Number(anchorWorldX) || 0);
  const spreadPx = MAP_LIGHTNING_SPREAD_TILES * LANE_TILE_PX;
  if (Math.random() < 0.25) return anchor;
  return Math.round(anchor - spreadPx + Math.random() * spreadPx * 2);
}

function resolveMapLightningDamage(rawDamage, target) {
  const amount = Math.max(0, Math.trunc(Number(rawDamage) || 0));
  if (amount <= 0) return { hit: true, damage: 0 };
  const defence = defenceTargetForIncomingAttack(target);
  if (!rollMagicHit({ magicResist: defence.magicResist ?? 0 })) {
    return { hit: false, damage: 0 };
  }
  const damage = applyIncomingDamageReduction(
    rollDamage([amount, amount], defence.amc ?? defence.ac, 0),
    defence,
  );
  return { hit: damage > 0, damage };
}

function mapLightningStrikeTargets(effect) {
  const party = state.battle.bossParty;
  if (party?.active && effect.targetClassId) {
    const member = party.members.find((member) => member.classId === effect.targetClassId && member.alive && member.hp > 0);
    return member ? [member] : [];
  }
  if (effect.solo && (state.battle.player?.hp ?? 0) > 0) {
    return [{
      solo: true,
      classId: state.battle.combatClass,
      name: state.battle.combatClass,
      worldX: state.battle.playerX,
    }];
  }
  return mapLightningTargets();
}

function mapLightningStrikeHitsTarget(effect, target) {
  if (effect.targetClassId || effect.solo) return true;
  return Math.abs(mapLightningTargetWorldX(target) - effect.worldX) <= MAP_LIGHTNING_HIT_RADIUS_PX;
}

function applyMapLightningHitToMember(member, damage, now) {
  if (!member || member.hp <= 0) return;
  if (damage > 0) member.hp = Math.max(0, member.hp - damage);
  const offsetX = bossPartyDamageTextOffset(member.classId);
  if (member.classId === bossPartyControlledClassId()) {
    setPlayerAction("struck", now + 250, true);
    maybeNotifyMagicShieldStruck(null, now);
    addCombatText("player", damage, "enemyDamage", now);
    bossPartySyncControlledPlayerRef();
  } else {
    member.visualAction = "struck";
    member.visualFrame = 0;
    member.visualOneShot = true;
    member.visualLastTick = now;
    notifyWizardMagicShieldStruckOnHit(member, now);
    addCombatText("enemy", damage, "enemyDamage", now, offsetX);
  }
  playSfx("player.flinch", bossPartySfxParams(member, 0.45, 120));
  if (member.hp <= 0) bossPartyMarkMemberDead(member, now);
}

function applyMapLightningHitToSoloPlayer(damage, now) {
  const battle = state.battle;
  const target = enemyAttackTarget();
  target.applyDamage(damage, now);
  addCombatText(target.anchor, damage, "enemyDamage", now);
  if (target.kind === "player" && battle.player.hp <= 0) {
    finishBattle(now);
    setPlayerAction("die", now);
    playSfx("player.death", { volume: 0.58 });
    pushBattleLog(`${battle.combatClass} falls.`);
  }
}

function applyMapLightningStrikeHit(effect, now) {
  if (effect.resolved) return;
  effect.resolved = true;
  const party = state.battle.bossParty;
  const targets = mapLightningStrikeTargets(effect);
  let hitAnyone = false;
  for (const target of targets) {
    if (!mapLightningStrikeHitsTarget(effect, target)) continue;
    const defenceEntity = target.solo ? state.battle.player : target;
    const { hit, damage } = resolveMapLightningDamage(effect.damage, defenceEntity);
    if (!hit) {
      if (target.solo) addCombatText("player", "Miss", "miss", now);
      else if (target.classId === bossPartyControlledClassId()) addCombatText("player", "Miss", "miss", now);
      else addCombatText("enemy", "Miss", "miss", now, bossPartyDamageTextOffset(target.classId));
      continue;
    }
    hitAnyone = true;
    if (party?.active) {
      applyMapLightningHitToMember(target, damage, now);
      pushBattleLog(`Lightning strikes ${target.classId} for ${damage}.`);
    } else {
      applyMapLightningHitToSoloPlayer(damage, now);
      pushBattleLog(`Lightning strikes ${target.name ?? target.classId} for ${damage}.`);
    }
  }
  if (!hitAnyone && effect.damage > 0) {
    pushBattleLog("Lightning crackles across the tomb floor.");
  }
}

function spawnMapLightningWave(now) {
  const settings = mapLightningSettings();
  if (!settings) return;
  const targets = mapLightningTargets();
  if (!targets.length) return;
  const effects = state.battle.mapLightningEffects ?? [];
  for (const target of targets) {
    effects.push({
      id: `map-lightning-${now}-${Math.random()}`,
      worldX: pickMapLightningWorldX(mapLightningTargetWorldX(target)),
      variantIndex: Math.floor(Math.random() * 3),
      damage: rollMapLightningDamage(settings),
      targetClassId: target.classId ?? null,
      solo: Boolean(target.solo),
      createdAt: now,
      expiresAt: now + MAP_LIGHTNING_HIT_DELAY_MS + MAP_LIGHTNING_EFFECT_MS,
      resolveBy: now + MAP_LIGHTNING_HIT_DELAY_MS + MAP_LIGHTNING_RESOLVE_GRACE_MS,
      hitAt: now + MAP_LIGHTNING_HIT_DELAY_MS,
      resolved: false,
    });
    playSfx("map.lightning", { volume: 0.55, throttleMs: 80 });
  }
  state.battle.mapLightningEffects = effects.slice(-12);
}

function updateMapLightning(now) {
  let changed = false;
  for (const effect of state.battle.mapLightningEffects ?? []) {
    if (!effect.resolved && now >= effect.hitAt) {
      applyMapLightningStrikeHit(effect, now);
      changed = true;
      if (state.battle.bossParty?.active && bossPartyAllMembersDead()) break;
      if (!state.battle.bossParty?.active && (state.battle.player?.hp ?? 0) <= 0) break;
    }
  }
  const remaining = (state.battle.mapLightningEffects ?? []).filter((effect) => {
    if (!effect.resolved) return now <= (effect.resolveBy ?? effect.expiresAt);
    return now <= effect.expiresAt;
  });
  if (remaining.length !== (state.battle.mapLightningEffects ?? []).length) {
    state.battle.mapLightningEffects = remaining;
    changed = true;
  }
  if (!mapLightningActive()) return changed;
  if (!state.battle.nextMapLightningAt) {
    state.battle.nextMapLightningAt = now + randomMapLightningIntervalMs();
  } else if (now >= state.battle.nextMapLightningAt) {
    spawnMapLightningWave(now);
    state.battle.nextMapLightningAt = now + randomMapLightningIntervalMs();
    changed = true;
  }
  return changed;
}

function mapLightningFrameIndex(effect, layer, now) {
  const variantFrames = Math.max(1, Math.trunc(Number(state.mapLightningAtlas?.variantFrameCount) || 5));
  const variantIndex = Math.max(0, Math.min(2, Math.trunc(Number(effect.variantIndex) || 0)));
  const age = Math.max(0, now - effect.createdAt);
  const localFrame = Math.min(variantFrames - 1, Math.floor(age / Math.max(1, layer.interval || 120)));
  return variantIndex * variantFrames + localFrame;
}

function updateGroundSpellEffects(now) {
  const battle = state.battle;
  const effects = Array.isArray(battle.groundSpellEffects) ? battle.groundSpellEffects : [];
  if (!effects.length) return false;

  let changed = false;
  battle.groundSpellEffects = effects.filter((effect) => now <= effect.expiresAt);
  if (battle.groundSpellEffects.length !== effects.length) changed = true;

  const swarmActive = groupDungeonSwarmSideActive();
  for (const effect of battle.groundSpellEffects) {
    while (effect.nextTickAt <= now && effect.nextTickAt <= effect.expiresAt) {
      if (swarmActive && effect.tiles?.length) {
        const swarmEnemies = battle.swarm?.enemies ?? [];
        for (const swarmEnemy of swarmEnemies) {
          if (swarmEnemy.hp <= 0 || swarmEnemy.dying) continue;
          if (!groundSpellEffectHitsSwarmEnemy(effect, swarmEnemy)) continue;
          applyGroundSpellTickToSwarmEnemy(effect, swarmEnemy, effect.nextTickAt);
          changed = true;
        }
      } else if (battle.enemy?.hp > 0 && groundSpellEffectHitsEnemy(effect)) {
        applyGroundSpellTick(effect, effect.nextTickAt);
        changed = true;
        if ((battle.enemy?.hp ?? 0) <= 0) break;
      }
      effect.nextTickAt += effect.tickMs;
    }
  }
  return changed;
}

function groundSpellEffectHitsSwarmEnemy(effect, swarmEnemy) {
  const tile = swarmEnemyReservedTile(swarmEnemy);
  return (effect.tiles ?? []).some(
    (fireTile) => fireTile.worldX === tile.worldX && fireTile.mapRow === tile.mapRow,
  );
}

function groundSpellEffectHitsEnemy(effect) {
  const battle = state.battle;
  if (!battle.enemy || battle.enemy.hp <= 0) return false;
  const hitRadius = LANE_TILE_PX * 0.55;
  return (effect.offsets ?? [0]).some((offset) => Math.abs(battle.enemyX - (effect.worldX + offset)) <= hitRadius);
}

function applyGroundSpellTick(effect, now) {
  const battle = state.battle;
  const spell = wizardCombatSpell(effect.spellId);
  const damage = applyWizardMagicDefence(effect.value, battle.enemy);
  if (damage <= 0) {
    addCombatText("enemy", "0", "damage", now);
    pushBattleLog(`${spell.label} is resisted by ${battle.enemy.name}.`);
    return;
  }

  reduceEnemyHp(battle.enemy, damage);
  setEnemyAction("struck", true, now);
  playMonsterSfx("flinch");
  playSpellSfx(spell.id, "impact", { volume: 0.42, throttleMs: 160 }) || playSpellSfx(spell.id, "cast", { volume: 0.38, throttleMs: 160 });
  addCombatText("enemy", damage, "damage", now);
  pushBattleLog(`${spell.label} burns ${battle.enemy.name} for ${damage}.`);

  if (battle.enemy.hp <= 0) {
    setEnemyAction("die", false, now);
    playMonsterSfx("death");
    if (!battle.bossParty?.active) {
      finishEnemy(now);
      pushBattleLog(`${battle.enemy.name} is defeated.`);
    }
  }
}

function applyGroundSpellTickToSwarmEnemy(effect, swarmEnemy, now) {
  const spell = wizardCombatSpell(effect.spellId);
  const damage = applyWizardMagicDefence(effect.value, swarmEnemy);
  if (damage <= 0) {
    addSwarmEnemyCombatText(swarmEnemy, "0", "damage", now);
    pushBattleLog(`${spell.label} is resisted by ${swarmEnemy.name}.`);
    return;
  }

  reduceSwarmEnemyHp(swarmEnemy, damage, now);
  const primary = groupDungeonPrimarySwarmEnemy();
  if (primary?.id === swarmEnemy.id && state.battle.enemy) {
    state.enemy.action = swarmEnemy.action;
    state.enemy.frame = swarmEnemy.frame;
    state.enemy.oneShot = swarmEnemy.oneShot;
    state.enemy.lastTick = swarmEnemy.lastTick;
  }
  queueSwarmEnemyStruck(swarmEnemy, now);
  playMonsterSfx("flinch", swarmEnemy);
  playSpellSfx(spell.id, "impact", { volume: 0.42, throttleMs: 160 }) || playSpellSfx(spell.id, "cast", { volume: 0.38, throttleMs: 160 });
  addSwarmEnemyCombatText(swarmEnemy, damage, "damage", now);
  pushBattleLog(`${spell.label} burns ${swarmEnemy.name} for ${damage}.`);

  if (swarmEnemy.hp <= 0) {
    maybeKillGroupDungeonSwarmEnemy(swarmEnemyToBattleEntity(swarmEnemy), now);
  }
}

function enemyAttack(now) {
  const battle = state.battle;
  if (isTrainingDummyEnemy(battle.enemy)) return false;
  if (isEvilCentipedeEnemy(battle.enemy)) return beginEvilCentipedeAttack(now);
  if (isMassBurstEnemy(battle.enemy)) return beginMassBurstAttack(now);
  if (isScalyBeastEnemy(battle.enemy)) return beginScalyBeastAttack(now);
  if (isDarkDevilEnemy(battle.enemy)) return beginDarkDevilAttack(now);
  if (isKingScorpionEnemy(battle.enemy)) return beginKingScorpionAttack(now);
  if (enemyHasRangedMeleeAttack(battle.enemy)) return beginBoneLordAttack(now);
  const target = enemyAttackTarget();
  setEnemyAction("attack1", true, now);
  playMonsterSfx("attack");
  const { hit, damage } = resolveIncomingEnemyAttack(battle.enemy, target);
  if (!hit) {
    addCombatText(target.anchor, "Miss", "miss", now);
    pushBattleLog(`${battle.enemy.name} misses ${target.name}.`);
    return true;
  }
  target.applyDamage(damage, now);
  addCombatText(target.anchor, damage, "enemyDamage", now);
  pushBattleLog(`${battle.enemy.name} hits ${target.name} for ${damage}.`);

  if (target.kind === "player" && battle.player.hp <= 0) {
    finishBattle(now);
    setPlayerAction("die", now);
    playSfx("player.death", { volume: 0.58 });
    pushBattleLog(`${battle.combatClass} falls.`);
  }
  return true;
}

function enemyAttackTarget() {
  const battle = state.battle;
  if (taoistPetCanTank()) {
    const pet = battle.taoPet;
    const defence = defenceStatsForEntity(pet);
    return {
      kind: "pet",
      name: pet.name,
      anchor: "pet",
      ac: defence.ac,
      amc: defence.amc,
      magicResist: defence.magicResist,
      agility: defence.agility,
      applyDamage: (damage, now) => {
        pet.hp = Math.max(0, pet.hp - damage);
        setTaoPetAction("struck", true, now);
        if (pet.hp <= 0) markTaoistPetDead(now);
      },
    };
  }
  return {
    kind: "player",
    name: battle.combatClass,
    anchor: "player",
    ac: battle.player.ac,
    amc: battle.player.amc,
    magicResist: battle.player.magicResist ?? 0,
    agility: battle.player.agility,
    applyDamage: (damage, now) => {
      battle.player.hp = Math.max(0, battle.player.hp - damage);
      maybeNotifyMagicShieldStruck(null, now);
      setPlayerAction("struck", now + 250, true);
      playSfx("player.flinch", { volume: 0.45, throttleMs: 120 });
    },
  };
}

// Crystal MapObject.GetArmour (ACAgility / MACAgility): miss when
// Random.Next(defenderAgility + 1) > attackerAccuracy.
function rollHit(accuracy, agility) {
  const acc = Math.max(0, Math.trunc(Number(accuracy) || 0));
  const agi = Math.max(0, Math.trunc(Number(agility) || 0));
  return randomInt(0, agi) <= acc;
}

function resolvePhysicalAttack(attackerAccuracy, defenderAgility, attackStat, defenceStat, luck = 0) {
  if (!rollHit(attackerAccuracy, defenderAgility)) return { hit: false, damage: 0 };
  const damage = rollDamage(attackStat, defenceStat, luck);
  return { hit: damage > 0, damage };
}

function enemyAttackDefenceType(enemy) {
  if (enemy?.attackDefenceType === "MAC") return "MAC";
  if (enemy?.attackDefenceType === "MACAgility") return "MACAgility";
  return "ACAgility";
}

function enemyAttackDefenceGuidance(enemy) {
  if (!enemy) return "-";
  const type = enemyAttackDefenceType(enemy);
  const parts = [];
  if (type === "MAC" || type === "MACAgility") {
    parts.push("Magical (MAC/AMC)");
  } else {
    parts.push("Physical (AC)");
  }
  if (type === "ACAgility" || type === "MACAgility") {
    parts.push("Agility dodges");
  }
  if (isEvilCentipedeEnemy(enemy)) {
    parts.push("Poison on hit");
  }
  return parts.join(" · ");
}

function incomingAttackDefenceStat(target, defenceType) {
  if (defenceType === "MACAgility" || defenceType === "MAC") return target.amc ?? target.ac;
  return target.ac;
}

// Crystal monster swings vs players/pets: ACAgility (physical AC) or, for
// FlamingWooma/WoomaTaurus, MACAgility (magic-resist roll + agility dodge + MAC).
// Evil Centipede uses MAC (magic-resist roll + MAC, no agility dodge).
function resolveIncomingEnemyRangedAttack(enemy, target, options = {}) {
  const rangedType = enemy?.rangedAttackDefenceType || enemy?.attackDefenceType || "MAC";
  return resolveIncomingEnemyAttack({ ...enemy, attackDefenceType: rangedType }, target, { ...options, ranged: true });
}

function incomingDamageReductionPercent(target, now = performance.now()) {
  const buffEntity = target?.__buffEntity ?? target;
  const classId = buffEntity?.classId
    ?? (buffEntity === state.battle.player ? state.battle.combatClass : null);
  if (classId && classId !== "Wizard") return 0;
  const buffs = pruneStatBuffs(entityStatBuffList(buffEntity), now);
  const shield = buffs.find((buff) => buff.kind === "magicShield");
  return Math.max(0, Math.min(100, Math.trunc(Number(shield?.reductionPercent) || 0)));
}

function applyIncomingDamageReduction(damage, target, now = performance.now()) {
  const percent = incomingDamageReductionPercent(target, now);
  if (percent <= 0) return damage;
  return Math.max(0, Math.trunc(damage - (damage * percent) / 100));
}

function resolveIncomingEnemyAttack(enemy, target, options = {}) {
  const defenceType = enemyAttackDefenceType(enemy);
  if ((defenceType === "MACAgility" || defenceType === "MAC") && !rollMagicHit({ magicResist: target.magicResist ?? 0 })) {
    return { hit: false, damage: 0 };
  }
  if (defenceType !== "MAC" && !rollHit(enemy.accuracy, target.agility)) return { hit: false, damage: 0 };
  const damage = applyIncomingDamageReduction(
    rollDamage(
      enemyAttackDamageStat(enemy, options),
      incomingAttackDefenceStat(target, defenceType),
      enemy.luck,
    ),
    target,
  );
  return { hit: damage > 0, damage };
}

function addCombatText(anchor, text, kind = "damage", now = performance.now(), offsetX = 0) {
  const bounds = combatTextBounds(anchor);
  state.battle.floatingTexts.push({
    id: `${now}-${Math.random()}`,
    anchor,
    text: String(text),
    kind,
    x: bounds.centerX + offsetX,
    y: bounds.topY - 16,
    createdAt: now,
  });
  state.battle.floatingTexts = state.battle.floatingTexts.slice(-12);
}

function addSwarmEnemyCombatText(swarmEnemy, text, kind = "damage", now = performance.now()) {
  const bounds = swarmEnemyFrameBounds(swarmEnemy);
  state.battle.floatingTexts.push({
    id: `${now}-${Math.random()}`,
    anchor: "enemy",
    text: String(text),
    kind,
    x: bounds.centerX,
    y: bounds.topY - 16,
    createdAt: now,
  });
  state.battle.floatingTexts = state.battle.floatingTexts.slice(-12);
}

function finishBattle(now) {
  state.battle.running = false;
  state.battle.phase = "idle";
  state.battle.nextPlayerAttackAt = 0;
  state.battle.nextEnemyAttackAt = 0;
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  state.battle.pendingDefenceBuff = null;
  state.battle.pendingUltimateEnhancer = null;
  state.battle.defenceBuffFx = [];
  state.battle.flamingSwordReady = false;
  state.battle.flamingSwordReadyAt = 0;
  state.battle.flamingSwordExpiresAt = 0;
  state.battle.twinDrakeReady = false;
  state.battle.twinDrakeReadyAt = 0;
  state.battle.twinDrakeChargeFxStartedAt = 0;
  state.battle.twinDrakeChargeFxUntil = 0;
  state.battle.pendingTwinDrakeHits = [];
  state.battle.attachedSpellFx = [];
  dismissTaoistPet();
  state.battle.groundSpellEffects = [];
  state.battle.mapLightningEffects = [];
  state.battle.nextMapLightningAt = 0;
  state.battle.returnToStandAt = (state.battle.player?.hp ?? 0) > 0 ? now + COMBAT_STANCE_HOLD_MS : 0;
}

function finishEnemy(now) {
  const battle = state.battle;
  if (isTrainingDummyEnemy(battle.enemy)) {
    if (battle.enemy) battle.enemy.hp = battle.enemy.maxHp;
    return;
  }
  const zone = activeZone();
  const bossDef = bossRoomDef(zone?.id);
  const trainingRoom = isTrainingRoomZone(zone);
  if (!trainingRoom) awardEnemyRewards();
  battle.phase = "victory";
  battle.enemyAggro = false;
  battle.pendingImpact = null;
  battle.pendingEnemyStrike = null;
  battle.pendingHeal = null;
  battle.pendingPoison = null;
  clearTwinDrakePendingState();
  battle.attachedSpellFx = (battle.attachedSpellFx ?? []).filter((entry) => entry.spellId !== "TwinDrakeBlade");
  retireTaoistPetAfterFight(now);
  if (battle.enemy) battle.enemy.poisons = [];
  battle.nextPlayerAttackAt = 0;
  battle.nextEnemyAttackAt = 0;
  if (bossDef && zone) {
    setBossRespawn(zone.id);
    battle.running = false;
    battle.nextEnemySpawnAt = 0;
    pushBattleLog(`${bossDef.bossName} will respawn in ${formatBossRespawnDelay(bossDef.respawnMinutes)}.`);
    addLootNotice(`${bossDef.bossName} defeated`, "boss");
    saveGameState(true);
  } else {
    battle.nextEnemySpawnAt = now + (trainingRoom ? 600 : LANE.respawnDelayMs);
  }
  if (trainingRoom) pushBattleLog("Training dummy resets.");
  const restAfterVictory = Boolean(bossDef) && (battle.player?.hp ?? 0) > 0;
  if (restAfterVictory) {
    if (state.action !== "die") setPlayerAction("stance", now);
    battle.returnToStandAt = now + COMBAT_STANCE_HOLD_MS;
  } else {
    battle.returnToStandAt = 0;
  }
}

function awardEnemyRewards() {
  if (state.game.mode !== "zone") return;
  const zone = activeZone();
  const reward = zone?.rewards ?? { gold: [1, 2] };
  const enemy = state.battle.enemy;
  const xp = adjustedKillExperience(enemy?.experience ?? 0, state.game.progress.level, enemy?.level ?? 0);
  const bossDrops = bossDropTableForEnemy(enemy);
  const gold = bossDrops
    ? bossDrops.gold
    : randomInt(reward.gold[0], reward.gold[1]);
  const drops = bossDrops
    ? rollBossSoloDrops(enemy)
    : isRedThunderZumaEnemy(enemy)
      ? rollRedThunderZumaDrops()
      : rollZoneDrops(zone, enemy);
  const leveledTo = applyExperienceReward(xp);
  state.inventory.gold += gold;
  state.game.progress.gold = state.inventory.gold;
  state.game.kills += 1;
  state.game.zoneKills += 1;
  if ((bossDrops || isRedThunderZumaEnemy(enemy)) && zone) {
    state.game.dropPity[zone.id] = 0;
  }
  state.game.lastReward = { xp, gold, drops: drops.added };
  state.battle.experience = state.game.progress.experience;
  state.battle.gold = state.game.progress.gold;
  state.battle.level = state.game.progress.level;
  if (gold > 0) playSfx("ui.gold", { volume: 0.34, throttleMs: 250 });
  pushBattleLog(`Gained ${xp} XP and ${gold} gold.`);
  if (leveledTo.length) pushBattleLog(`Level up: ${leveledTo.at(-1)}.`);
  for (const item of drops.added) pushBattleLog(`Received ${item.name}.`);
  for (const item of drops.ignored) pushBattleLog(`No room for ${item.name}.`);
  addLootNotice(`+${gold} gold`, "gold");
  for (const level of leveledTo) addLootNotice(`Level ${level}`, "level");
  for (const item of drops.added) addLootNotice(`Found ${item.name}`, "item");
  for (const item of drops.ignored) addLootNotice(`Inventory full: ${item.name}`, "full");
  if (drops.added.length || drops.ignored.length || gold > 0) {
    state.game.recentLoot = [
      `+${gold} gold`,
      ...leveledTo.map((level) => `Level ${level}`),
      ...drops.added.map((item) => `Found ${item.name}`),
      ...drops.ignored.map((item) => `No room for ${item.name}`),
      ...state.game.recentLoot,
    ].slice(0, 6);
  }
}

function applyExperienceReward(xp) {
  const levels = [];
  state.game.progress.experience += xp;
  let nextLevelXp = xpForNextLevel(state.game.progress.level);
  while (Number.isFinite(nextLevelXp) && state.game.progress.experience >= nextLevelXp) {
    state.game.progress.experience -= nextLevelXp;
    state.game.progress.level += 1;
    levels.push(state.game.progress.level);
    restoreBattlePlayerResources();
    triggerLevelUpFx(performance.now(), state.game.progress.level);
    sceneSignature = "";
    nextLevelXp = xpForNextLevel(state.game.progress.level);
  }
  if (levels.length) void submitPrototypeStats("level-up");
  return levels;
}

function xpForNextLevel(level) {
  return crystalExperienceForLevel(level);
}

function xpProgressText() {
  const needed = xpForNextLevel(state.game.progress.level);
  return Number.isFinite(needed) ? `XP ${state.game.progress.experience}/${needed}` : "XP Max";
}

function restoreBattlePlayerResources() {
  if (!state.battle.player) return;
  const stats = characterTotalStats();
  state.battle.player.level = state.game.progress.level;
  state.battle.player.experience = state.game.progress.experience;
  state.battle.player.maxHp = stats.maxHp;
  state.battle.player.maxMp = stats.maxMp;
  state.battle.player.hp = stats.maxHp;
  state.battle.player.mp = stats.maxMp;
}

function triggerLevelUpFx(now = performance.now(), level = state.game.progress.level) {
  state.levelUpEffects.push({
    id: `${now}-${level}-${Math.random()}`,
    createdAt: now,
    level,
  });
  state.levelUpEffects = state.levelUpEffects.slice(-3);
  playSfx("level.up", { volume: 0.65, throttleMs: 500 });
  render();
}

function addLootNotice(text, kind = "item") {
  state.game.lootToasts.push({
    id: `${performance.now()}-${Math.random()}`,
    text,
    kind,
    createdAt: performance.now(),
  });
  state.game.lootToasts = state.game.lootToasts.slice(-6);
}

function rollRedThunderZumaDrops() {
  const added = [];
  const ignored = [];

  const guaranteedId = ZUMA_THUNDER_GUARANTEED_DROP_IDS[
    Math.floor(Math.random() * ZUMA_THUNDER_GUARANTEED_DROP_IDS.length)
  ];
  const guaranteed = itemDefinition(guaranteedId);
  if (guaranteed) addZoneDropItem(guaranteed, added, ignored);

  for (const itemId of RED_THUNDER_ZUMA_BONUS_WEAPON_IDS) {
    if (Math.random() >= RED_THUNDER_ZUMA_BONUS_WEAPON_CHANCE) continue;
    const item = itemDefinition(itemId);
    if (item) addZoneDropItem(item, added, ignored);
  }

  if (Math.random() < RED_THUNDER_ZUMA_ZUMA_WEAPON_CHANCE) {
    const zumaId = RED_THUNDER_ZUMA_ZUMA_WEAPON_IDS[
      Math.floor(Math.random() * RED_THUNDER_ZUMA_ZUMA_WEAPON_IDS.length)
    ];
    const zumaWeapon = itemDefinition(zumaId);
    if (zumaWeapon) addZoneDropItem(zumaWeapon, added, ignored);
  }

  return { added, ignored };
}

function rollZoneDrops(zone, enemy = state.battle.enemy) {
  const added = [];
  const ignored = [];
  if (!zone) return { added, ignored };
  const candidates = zoneDropCandidates(zone, enemy);
  for (const { item, chance } of candidates) {
    if (Math.random() >= chance) continue;
    addZoneDropItem(item, added, ignored);
  }
  updateDropPity(zone, candidates, added, ignored);
  return { added, ignored };
}

function zoneDropCandidates(zone, enemy = null) {
  return state.itemData.items
    .filter((item) => item.drop?.zones?.includes(zone.id))
    .map((item) => {
      const zoneChance = item.drop?.chances?.[zone.id];
      const enemyChance = item.drop?.enemyChances?.[String(enemy?.id)]?.[zone.id];
      return {
        item,
        chance: Math.max(
          0,
          Math.min(
            1,
            Math.max(Number(zoneChance ?? item.drop?.chance) || 0, Number(enemyChance) || 0),
          ),
        ),
      };
    });
}

function updateDropPity(zone, candidates, added, ignored) {
  if (!zone || candidates.length === 0) return;
  if (added.length || ignored.length) {
    state.game.dropPity[zone.id] = 0;
    return;
  }

  const dryKills = Math.max(0, Math.trunc(Number(state.game.dropPity[zone.id]) || 0)) + 1;
  state.game.dropPity[zone.id] = dryKills;
  if (dryKills < DROP_PITY_KILLS) return;

  const forced = weightedDropCandidate(candidates);
  if (!forced) return;
  addZoneDropItem(forced.item, added, ignored);
  state.game.dropPity[zone.id] = 0;
}

function weightedDropCandidate(candidates) {
  const weighted = candidates.filter((candidate) => candidate.chance > 0);
  if (!weighted.length) return candidates[Math.floor(Math.random() * candidates.length)] ?? null;
  const total = weighted.reduce((sum, candidate) => sum + candidate.chance, 0);
  let roll = Math.random() * total;
  for (const candidate of weighted) {
    roll -= candidate.chance;
    if (roll <= 0) return candidate;
  }
  return weighted.at(-1) ?? null;
}

function addZoneDropItem(item, added, ignored) {
  if (!hasInventorySpaceFor(item.id)) {
    ignored.push(item);
    return false;
  }
  const before = state.inventory.items.reduce((sum, entry) => sum + (entry.itemId === item.id ? entry.quantity : 0), 0);
  const addedEntries = addInventoryItem(item.id, 1);
  const after = state.inventory.items.reduce((sum, entry) => sum + (entry.itemId === item.id ? entry.quantity : 0), 0);
  if (addedEntries.length && after > before) {
    added.push(item);
    return true;
  }
  ignored.push(item);
  return false;
}

function updateBattleRestState(now) {
  const battle = state.battle;
  if (!battle.returnToStandAt || battle.running || now < battle.returnToStandAt) return;
  battle.returnToStandAt = 0;
  if ((battle.player?.hp ?? 0) <= 0) return;
  if (state.game.mode === "mining") {
    setPlayerAction("mine", now, true);
    return;
  }
  setPlayerAction("standing", now);
}

function spawnNextEnemy(now) {
  const battle = state.battle;
  const currentIndex = ENEMY_TEMPLATES.findIndex((enemy) => enemy.id === battle.enemyId);
  const zone = activeZone();
  const template = state.game.mode === "zone"
    ? (isTrainingRoomZone(zone) ? trainingRoomEnemyTemplate(zone) : randomZoneEnemyTemplate(zone))
    : ENEMY_TEMPLATES[(currentIndex + 1 + ENEMY_TEMPLATES.length) % ENEMY_TEMPLATES.length];
  battle.enemyId = template.id;
  battle.enemy = { ...template, hp: template.maxHp, mp: template.maxMp, poisons: [], debuffs: { slowUntil: 0, frozenUntil: 0 } };
  battle.enemyX = battle.playerX + enemySpawnDistance();
  battle.enemyAggro = false;
  battle.phase = "advance";
  battle.travelStartedAt = now;
  battle.travelStartedX = battle.playerX;
  battle.nextEnemySpawnAt = 0;
  battle.activeSkill = "None";
  battle.activeSkillAtlas = null;
  battle.activeWizardSpell = null;
  battle.activeWizardSpellAtlas = null;
  battle.activeTaoSpell = null;
  battle.activeTaoSpellAtlas = null;
  battle.pendingImpact = null;
  battle.pendingEnemyStrike = null;
  battle.pendingPoison = null;
  clearTwinDrakePendingState();
  battle.attachedSpellFx = (battle.attachedSpellFx ?? []).filter((entry) => entry.spellId !== "TwinDrakeBlade");
  dismissTaoistPet();
  if (battle.enemy) battle.enemy.poisons = [];
  battle.floatingTexts = [];
  state.enemy.index = template.monsterIndex;
  state.enemy.action = "standing";
  state.enemy.frame = 0;
  state.enemy.oneShot = false;
  state.enemy.lastTick = now;
  reloadEnemyAtlas();
  pushBattleLog(`A ${template.name} appears ahead.`);
  setPlayerLocomotion("walking", now);
}

function setPlayerAction(action, now = performance.now(), oneShot = false) {
  state.spell = "None";
  state.spellAtlas = null;
  state.action = action;
  state.frame = 0;
  state.playerOneShot = oneShot;
  state.lastTick = now;
  updateActionButtons();
}

function setPlayerLocomotion(action, now) {
  if (state.action === action || isPlayerOneShotAction()) return;
  state.action = action;
  state.frame = 0;
  state.playerOneShot = false;
  state.lastTick = now;
  updateActionButtons();
}

function setEnemyLocomotion(action, now) {
  if (state.enemy.action === action || isEnemyOneShotAction()) return;
  state.enemy.action = action;
  state.enemy.frame = 0;
  state.enemy.oneShot = false;
  state.enemy.lastTick = now;
  updateEnemyActionButtons();
}

function warriorCombatSkill(skillId) {
  return WARRIOR_COMBAT_SKILLS.find((skill) => skill.id === skillId) ?? BASIC_ATTACK_SKILL;
}

function availableWarriorCombatSkills() {
  return [
    BASIC_ATTACK_SKILL,
    ...WARRIOR_COMBAT_SKILLS.filter((skill) => skill.id !== BASIC_ATTACK_SKILL.id && learnedMagic(skill.id)),
  ];
}

function learnedActiveWarriorSkills() {
  return WARRIOR_COMBAT_SKILLS.filter((skill) => skill.id !== BASIC_ATTACK_SKILL.id && !skill.passive && learnedMagic(skill.id));
}

function learnedActiveWizardSkills() {
  return WIZARD_COMBAT_SPELLS.filter((spell) => learnedMagic(spell.id));
}

function learnedActiveTaoistSkills() {
  return TAOIST_COMBAT_SPELLS.filter((spell) => learnedMagic(spell.id));
}

function warriorAutoSummaryText() {
  const enabled = autoWarriorCombatSkills().map((skill) => skill.label);
  return enabled.length ? enabled.join(", ") : "none";
}

function taoistAutoSummaryText() {
  const enabled = autoTaoistCombatSpells().map((spell) => spell.label);
  return enabled.length ? enabled.join(", ") : "none";
}

function combatSkillBarShouldShow(skills = null) {
  const resolvedSkills = skills ?? (state.battle.combatClass === "Wizard"
    ? learnedActiveWizardSkills()
    : state.battle.combatClass === "Taoist"
    ? learnedActiveTaoistSkills()
    : learnedActiveWarriorSkills());
  return ["Warrior", "Wizard", "Taoist"].includes(state.battle.combatClass)
    && resolvedSkills.length > 0
    && (state.game.mode === "town" || state.game.mode === "zone" || state.battle.running);
}

function renderCombatSkillBar(now = performance.now()) {
  const skills = state.battle.combatClass === "Wizard"
    ? learnedActiveWizardSkills()
    : state.battle.combatClass === "Taoist"
    ? learnedActiveTaoistSkills()
    : learnedActiveWarriorSkills();
  const shouldShow = combatSkillBarShouldShow(skills);
  if (!shouldShow) {
    if (!els.combatSkillBar.hidden || combatSkillBarSignature) {
      els.combatSkillBar.hidden = true;
      els.combatSkillBar.innerHTML = "";
      combatSkillBarSignature = "";
      applyCombatHudLayout({ skillBarVisible: false });
    }
    return;
  }

  const signature = JSON.stringify({
    mode: state.game.mode,
    running: state.battle.running,
    phase: state.battle.phase,
    mp: state.battle.player?.mp ?? 0,
    poisons: `${poisonInventoryCount("green")}:${poisonInventoryCount("yellow")}`,
    amulets: amuletInventoryCount(),
    magic: magicSignature(),
    autoCastSlotLimit: autoCastSlotLimit(),
    queuedCombatSpellId: state.battle.queuedCombatSpellId ?? "",
    flamingSwordReady: warriorFlamingSwordReady(),
    twinDrakeReady: warriorTwinDrakeReady(),
    cooldownSecond: skills.map((skill) => {
      const learned = learnedMagic(skill.id);
      const remaining = skill.toggle ? 0 : Math.ceil(Math.max(0, (learned?.castReadyAt ?? 0) - now) / 1000);
      return `${skill.id}:${remaining}`;
    }),
  });
  if (signature === combatSkillBarSignature) return;
  combatSkillBarSignature = signature;
  els.combatSkillBar.hidden = false;
  els.combatSkillBar.innerHTML = skills.map((skill) => combatSkillButtonHtml(skill, learnedMagic(skill.id), now)).join("");
  applyCombatHudLayout();
}

function combatSkillButtonHtml(skill, learned, now) {
  const remainingMs = skill.toggle ? 0 : Math.max(0, (learned?.castReadyAt ?? 0) - now);
  const remainingSeconds = Math.ceil(remainingMs / 1000);
  const mpCost = spellMpCost(skill, learned);
  const enoughMp = (state.battle.player?.mp ?? 0) >= mpCost;
  const hasPoison = skill.id !== "Poisoning" || poisonInventoryCount() > 0;
  const needsAmulet = skill.id === "SoulFireBall" || skill.id === "SummonSkeleton" || skill.id === "SummonShinsu";
  const amuletCost = taoistSummonAmuletCost(skill.id);
  const hasAmulet = !needsAmulet || amuletInventoryCount() >= (skill.id === "SoulFireBall" ? 1 : amuletCost);
  const auto = Boolean(learned?.autoCast);
  const combatClass = state.battle.combatClass;
  const queued = isQueuedCombatSpell(skill.id, combatClass);
  const chargeReady = warriorChargeReady(skill.id);
  const autoLimitReached = !auto
    && combatAutoCastClassForSpell(skill.id) === combatClass
    && autoCastSlotsUsed(combatClass) >= autoCastSlotLimit();
  const manualLabel = chargeReady ? "Ready" : queued ? "Next" : remainingSeconds > 0 ? `${remainingSeconds}` : "Cast";
  const autoLabel = auto ? "On" : autoLimitReached ? "Max" : "Off";
  const consumableText = skill.id === "Poisoning"
    ? ` | Green ${poisonInventoryCount("green")} Yellow ${poisonInventoryCount("yellow")}`
    : needsAmulet
    ? ` | Amulets ${amuletInventoryCount()}${amuletCost > 1 ? ` (need ${amuletCost})` : ""}`
    : "";
  const castTitle = chargeReady && skill.id === "TwinDrakeBlade"
    ? `${skill.label} Lv ${learned?.level ?? 0} | charged — next attack releases twin drake | click to cancel`
    : chargeReady && skill.id === "FlamingSword"
    ? `${skill.label} Lv ${learned?.level ?? 0} | charged — next attack unleashes fire | click to cancel`
    : queued
    ? `${skill.label} Lv ${learned?.level ?? 0} | queued as next manual cast`
    : isWarriorChargeSkill(skill)
    ? `${skill.label} Lv ${learned?.level ?? 0} | MP ${mpCost} | click to charge for next attack`
    : `${skill.label} Lv ${learned?.level ?? 0} | ${skill.toggle ? (skill.id === "Thrusting" ? "2 tile reach" : `MP ${mpCost} per swing`) : `MP ${mpCost}`}${consumableText} | click to cast manually`;
  const autoTitle = auto
    ? `Disable ${skill.label} auto`
    : autoLimitReached
    ? `Autocast slots full (${autoCastSlotsUsed(combatClass)}/${autoCastSlotLimit()})`
    : `Enable ${skill.label} auto`;
  return `
    <div class="combat-skill-control ${auto ? "active" : ""} ${queued || chargeReady ? "queued" : ""}">
      <button
        class="combat-skill-button ${auto ? "active" : ""} ${queued || chargeReady ? "queued" : ""} ${chargeReady ? "charged" : ""} ${remainingMs > 0 ? "cooling" : ""} ${!enoughMp || !hasPoison || !hasAmulet ? "no-mp" : ""}"
        type="button"
        data-cast-combat-skill="${escapeHtml(skill.id)}"
        title="${escapeHtml(castTitle)}"
      >
        <img src="${escapeHtml(magicIconSrc(skill))}" alt="" />
        <span class="combat-skill-level">Lv ${learned?.level ?? 0}</span>
        <span class="combat-skill-auto">${manualLabel}</span>
        ${remainingSeconds > 0 ? `<span class="combat-skill-cooldown">${remainingSeconds}</span>` : ""}
      </button>
      <button
        class="combat-skill-toggle ${auto ? "active" : ""} ${autoLimitReached ? "locked" : ""}"
        type="button"
        data-toggle-skill-auto="${escapeHtml(skill.id)}"
        title="${escapeHtml(autoTitle)}"
      >${autoLabel}</button>
    </div>
  `;
}

function normalizeHotbarSlots() {
  for (let slot = 0; slot < HOTBAR_SLOT_COUNT; slot++) {
    const entryId = state.hotbar.slots[slot];
    if (!entryId) continue;
    const entry = inventoryEntryById(entryId);
    if (!entry || isEquippedEntry(entry.id)) state.hotbar.slots[slot] = null;
  }
}

function renderHotbar() {
  normalizeHotbarSlots();
  const signature = JSON.stringify({
    autoPotionSlots: autoPotionSlotLimit(),
    slots: state.hotbar.slots.map((entryId, slot) => {
      const entry = hotbarEntryAtSlot(slot);
      return entry ? inventoryEntrySignature(entry) : "";
    }),
  });
  if (signature === hotbarSignature) return;
  hotbarSignature = signature;
  els.hotbar.innerHTML = Array.from({ length: HOTBAR_SLOT_COUNT }, (_, slot) => hotbarSlotHtml(slot)).join("");
}

function hotbarSlotHtml(slot) {
  const entry = hotbarEntryAtSlot(slot);
  const item = entry ? itemDefinition(entry.itemId) : null;
  const x = 12 + slot * 35;
  const key = slot + 1;
  const autoSlot = autoPotionSlots().includes(slot);
  const itemHtml = item
    ? `
      <button
        class="hotbar-item has-tooltip"
        type="button"
        data-hotbar-use-entry="${entry.id}"
        data-inventory-entry="${entry.id}"
        data-tooltip-item="${escapeHtml(item.id)}"
        data-tooltip-entry="${escapeHtml(entry.id)}"
        draggable="false"
        title="${escapeHtml(itemDisplayName(item, entry))}"
      >
        ${itemIconMarkup(item)}
        ${isStackableItem(item) && entry.quantity > 1 ? `<span class="hotbar-qty">${entry.quantity}</span>` : ""}
      </button>
    `
    : "";
  return `
    <div
      class="hotbar-slot ${item ? "filled" : ""} ${autoSlot ? "auto-slot" : ""}"
      data-hotbar-slot="${slot}"
      style="left:${x}px; top:3px;"
      title="Hotbar ${key}${autoSlot ? " auto potion" : ""}"
    >
      <span class="hotbar-key">${key}</span>
      ${autoSlot ? `<span class="hotbar-auto">Auto</span>` : ""}
      ${itemHtml}
    </div>
  `;
}

function wizardCombatSpell(spellId) {
  return WIZARD_COMBAT_SPELLS.find((spell) => spell.id === spellId) ?? WIZARD_COMBAT_SPELLS[0];
}

function taoistCombatSpell(spellId) {
  return TAOIST_COMBAT_SPELLS.find((spell) => spell.id === spellId) ?? TAOIST_COMBAT_SPELLS[0];
}

function combatAttackSpell(spellId) {
  return WIZARD_COMBAT_SPELLS.find((spell) => spell.id === spellId)
    ?? TAOIST_COMBAT_SPELLS.find((spell) => spell.id === spellId)
    ?? null;
}

function wizardImpactDelay(spell, atlas) {
  if (spell.impactMode === "projectile") {
    if (atlas?.projectile) {
      return Math.max((atlas.projectile.delayMs ?? 0) + 120, crystalProjectileImpactDelayMs());
    }
    return crystalProjectileImpactDelayMs();
  }
  return spell.impactDelayMs ?? 450;
}

function crystalProjectileImpactDelayMs() {
  const tileDistance = Math.max(1, Math.round(enemyDistance() / LANE_TILE_PX));
  return tileDistance * 50 + 500;
}

const COMBAT_HUD_HOTBAR_HEIGHT = 38;
const COMBAT_HUD_SKILL_BAR_HEIGHT = 81;
const COMBAT_HUD_PLAYER_GAP = 38;
const COMBAT_HUD_STACK_GAP = 6;

function combatHudLayoutMetrics(options = {}) {
  const skillBarVisible = options.skillBarVisible ?? (
    Boolean(els.combatSkillBar)
    && !els.combatSkillBar.hidden
    && Boolean(els.combatSkillBar.innerHTML.trim())
  );
  const feetPx = Math.round(combatAnchor("player").y * state.scale);
  const hotbarTop = feetPx + COMBAT_HUD_PLAYER_GAP;
  const skillTop = hotbarTop + COMBAT_HUD_HOTBAR_HEIGHT + COMBAT_HUD_STACK_GAP;
  const hudBottom = skillBarVisible
    ? skillTop + COMBAT_HUD_SKILL_BAR_HEIGHT + 4
    : hotbarTop + COMBAT_HUD_HOTBAR_HEIGHT + 4;
  const canvasHeight = state.stageHeight * state.scale;
  return {
    feetPx,
    hotbarTop,
    skillTop,
    hudBottom,
    canvasHeight,
    displayHeight: Math.max(canvasHeight, hudBottom),
    skillBarVisible,
  };
}

function combatHudViewportReservePx() {
  if (!IS_GAME_UI) return 0;
  const skillBarExpected = combatSkillBarShouldShow();
  const reserve = COMBAT_HUD_PLAYER_GAP + COMBAT_HUD_HOTBAR_HEIGHT + 4;
  if (!skillBarExpected) return reserve;
  return reserve + COMBAT_HUD_STACK_GAP + COMBAT_HUD_SKILL_BAR_HEIGHT;
}

function applyCombatHudLayout(options = {}) {
  if (!els.stage) return;
  const metrics = combatHudLayoutMetrics(options);
  els.stage.style.width = `${state.stageWidth * state.scale}px`;
  els.stage.style.height = `${metrics.displayHeight}px`;
  els.stage.style.setProperty("--combat-hud-hotbar-top", `${metrics.hotbarTop}px`);
  els.stage.style.setProperty("--combat-hud-skill-top", `${metrics.skillTop}px`);
}

function updateStageSize() {
  const shell = els.stage.parentElement;
  if (!shell) return;
  const shellWidth = shell.clientWidth;
  const shellHeight = shell.clientHeight;
  const mode = state.game.mode;
  if (
    shellWidth === lastStageShellSize.w
    && shellHeight === lastStageShellSize.h
    && mode === lastStageShellSize.mode
    && state.scale === lastStageShellSize.scale
    && state.stageWidth > 0
    && state.stageHeight > 0
  ) {
    return;
  }
  lastStageShellSize = { w: shellWidth, h: shellHeight, mode, scale: state.scale };
  const zone = activeZone();
  const inTown = state.game.mode === "town";
  const minWidth = Math.max(520, Number(zone?.stageMinWidth) || 520);
  const minHeight = Math.max(
    260,
    Number(inTown ? TOWN_VISUALS.stageMinHeight : zone?.stageMinHeight) || 260,
  );
  const maxHeight = Math.max(
    minHeight,
    Number(inTown ? TOWN_VISUALS.stageMaxHeight : zone?.stageMaxHeight) || 360,
  );
  const hudReserve = combatHudViewportReservePx();
  const width = Math.max(minWidth, Math.floor((shell.clientWidth - 24) / Math.max(1, state.scale)));
  const height = Math.max(
    minHeight,
    Math.min(maxHeight, Math.floor((shell.clientHeight - 24 - hudReserve) / Math.max(1, state.scale))),
  );
  state.stageWidth = width;
  state.stageHeight = height;
}

function enemySpawnDistance() {
  const zoneSpawnDistance = Number(activeZone()?.arenaSpawnDistance);
  if (Number.isFinite(zoneSpawnDistance) && zoneSpawnDistance > 0) {
    return Math.max(LANE.enemyRange + 8, Math.round(zoneSpawnDistance));
  }
  return Math.max(360, state.stageWidth - playerScreenX() + LANE.spawnMargin);
}

// Stable world X for map-stamp arenas — party front or player, not the moving enemy midpoint.
function mapStampArenaAnchorWorldX() {
  if (bossPartyOnField()) {
    const front = bossPartyFrontTarget() ?? bossPartyNextAliveMember();
    return Math.round(Number(front?.worldX ?? state.battle.playerX) || 0);
  }
  return Math.round(Number(state.battle.playerX) || 0);
}

function ensureMapStampArenaLock() {
  if (!currentZoneMapStamp()) return;
  if (state.battle.lockedArenaWorldX != null) return;
  if (state.battle.bossParty?.lockedArenaWorldX != null) return;
  const lockX = mapStampArenaAnchorWorldX();
  state.battle.lockedArenaWorldX = lockX;
  if (state.battle.bossParty) state.battle.bossParty.lockedArenaWorldX = lockX;
}

// World X where the map stamp focus should sit.
function mapStampArenaWorldX() {
  const arenaLocked = state.battle.lockedArenaWorldX ?? state.battle.bossParty?.lockedArenaWorldX;
  if (arenaLocked != null) return arenaLocked;
  if (currentZoneMapStamp()) return mapStampArenaAnchorWorldX();
  if (bossPartyOnField()) {
    const front = bossPartyFrontTarget() ?? bossPartyNextAliveMember();
    const frontX = Number(front?.worldX ?? state.battle.playerX) || 0;
    const desiredEnemy = bossPartyDesiredEnemyX();
    const enemyX = Number.isFinite(desiredEnemy)
      ? desiredEnemy
      : (Number(state.battle.enemyX) || frontX + BOSS_PARTY_ENEMY_MELEE_GAP);
    return Math.round((frontX + enemyX) / 2);
  }
  const playerX = Number(state.battle.playerX) || 0;
  const enemyX = Number(state.battle.enemyX);
  if (state.battle.phase === "engaged" && Number.isFinite(enemyX)) {
    return Math.round((playerX + enemyX) / 2);
  }
  return Math.round(playerX + enemySpawnDistance() * 0.5);
}

function enemyDistance() {
  return Math.max(0, state.battle.enemyX - state.battle.playerX);
}

function playerAttackRange(now = performance.now()) {
  if (state.battle.combatClass === "Wizard") return wizardAttackRange(now);
  if (state.battle.combatClass === "Taoist") return taoistAttackRange(now);
  const queuedWarriorSkill = queuedCombatSpell("Warrior")?.spell;
  if (queuedWarriorSkill?.id === "Thrusting") return THRUSTING_RANGE;
  return thrustingEnabled() ? THRUSTING_RANGE : LANE.warriorRange;
}

function playerEngageRange(now = performance.now()) {
  if (state.battle.combatClass === "Taoist") {
    return Math.max(LANE.aggroRange, playerAttackRange(now), taoistSpellEngageRange(now));
  }
  return Math.max(LANE.aggroRange, playerAttackRange(now));
}

function wizardAttackRange(now = performance.now()) {
  const attackSpell = usableWizardAttackSpell(now);
  if (!attackSpell) return LANE.warriorRange;
  const { spell, cost, cooldownWaiting } = attackSpell;
  if (cooldownWaiting) return LANE.warriorRange;
  if ((state.battle.player?.mp ?? 0) < cost) return LANE.warriorRange;
  if (spell.id === "FireWall" && wizardFireWallRequiresMeleeRange() && !wizardFireWallMeleeReady()) {
    return LANE.enemyRange;
  }
  return crystalSpellRangePx(spell);
}

function taoistAttackRange(now = performance.now()) {
  const queued = queuedCombatSpell("Taoist")?.spell;
  if (queued?.id === "SoulFireBall") return taoistSoulFireBallRangePx(queued);
  if (queued?.id === "Poisoning") return crystalSpellRangePx(queued);
  if (queued?.id === "SummonSkeleton" || queued?.id === "SummonShinsu") return taoistSummonPetRangePx();
  return LANE.warriorRange;
}

function taoistSpellEngageRange(now = performance.now()) {
  const queued = queuedCombatSpell("Taoist")?.spell;
  if (queued?.id === "SoulFireBall" && usableTaoistSoulFireBall(now, { requireAuto: false, ignoreRange: true })) return taoistSoulFireBallRangePx(queued);
  if (queued?.id === "Poisoning" && usableTaoistPoisoning(now, { requireAuto: false, ignoreRange: true })) return crystalSpellRangePx(queued);
  if ((queued?.id === "SummonSkeleton" && usableTaoistSummonSkeleton(now, { requireAuto: false, ignoreRange: true }))
    || (queued?.id === "SummonShinsu" && usableTaoistSummonShinsu(now, { requireAuto: false, ignoreRange: true }))) {
    return taoistSummonPetRangePx();
  }
  const summon = usableTaoistSummonSkeleton(now, { ignoreRange: true });
  const shinsu = usableTaoistSummonShinsu(now, { ignoreRange: true });
  const poison = usableTaoistPoisoning(now, { ignoreRange: true });
  const soulFireBall = usableTaoistSoulFireBall(now, { ignoreRange: true });
  return Math.max(
    summon ? taoistSummonPetRangePx() : 0,
    shinsu ? taoistSummonPetRangePx() : 0,
    poison ? crystalSpellRangePx(poison.spell) : 0,
    soulFireBall ? taoistSoulFireBallRangePx(soulFireBall.spell) : 0,
  );
}

function taoistSummonPetRangePx() {
  return Math.min(TAOIST_SUMMON_SKELETON_LANE_RANGE, taoistVisibleRangeLimitPx());
}

function taoistSummonSkeletonRangePx() {
  return taoistSummonPetRangePx();
}

function crystalSpellRangePx(spell) {
  const range = Math.max(0, Math.trunc(Number(spell?.range) || 0));
  return range > 0 ? range * LANE_TILE_PX : LANE.wizardRange;
}

function taoistVisibleRangeLimitPx() {
  return Math.max(LANE.aggroRange, state.stageWidth - playerScreenX() - TAOIST_VISIBLE_RANGE_MARGIN);
}

function taoistSoulFireBallRangePx(spell) {
  return Math.min(
    crystalSpellRangePx(spell),
    TAOIST_SOUL_FIRE_BALL_LANE_RANGE,
    taoistVisibleRangeLimitPx(),
  );
}

function effectivePlayerAttackSpeed(now = performance.now()) {
  const player = state.battle.player;
  const base = Number(player?.attackSpeed) || 0;
  const furyUntil = Math.max(Number(state.battle.furyUntil) || 0, Number(player?.furyUntil) || 0);
  const furyBonus = now < furyUntil
    ? Number(state.battle.furyBonus ?? player?.furyBonus) || 0
    : 0;
  return base + furyBonus;
}

function playerCombatLevel() {
  return Math.max(1, Math.trunc(Number(state.battle.level) || state.battle.player?.level || state.game?.progress?.level || 1));
}

function playerWeaponAttackCooldownMs(now = performance.now(), skill = null) {
  const speed = effectivePlayerAttackSpeed(now);
  const level = playerCombatLevel();
  if (skill?.id === "TwinDrakeBlade") return twinDrakeAttackDelayMs(speed, level);
  return attackDelayMs(speed, level);
}

function playerAttackDelayMs(now = performance.now()) {
  return playerWeaponAttackCooldownMs(now);
}

function characterAttackSpeedLabel(now = performance.now()) {
  const stats = characterTotalStats();
  const effective = effectivePlayerAttackSpeed(now);
  const delay = playerAttackDelayMs(now);
  if (effective !== stats.attackSpeed) {
    return `${stats.attackSpeed} (+${effective - stats.attackSpeed}) · ${delay}ms`;
  }
  return `${stats.attackSpeed} · ${delay}ms`;
}

function canPlayerAttack() {
  const battle = state.battle;
  if (battle.combatClass === "Taoist" && taoistPetCanTank()) return false;
  return battle.phase === "engaged" && battle.enemyRevealed && battle.enemy?.hp > 0 && enemyDistance() <= playerAttackRange();
}

function canEnemyAttack() {
  const battle = state.battle;
  if (isTrainingDummyEnemy(battle.enemy)) return false;
  if (battle.phase !== "engaged" || !battle.enemyRevealed || !battle.enemy?.hp) return false;
  if (enemyFrozenActive(battle.enemy)) return false;
  if (isEvilCentipedeEnemy(battle.enemy)) return canEvilCentipedeAttack();
  if (isMassBurstEnemy(battle.enemy)) return canMassBurstAttack();
  if (isScalyBeastEnemy(battle.enemy)) return canScalyBeastAttack();
  if (isDarkDevilEnemy(battle.enemy)) return canDarkDevilAttack();
  if (isKingScorpionEnemy(battle.enemy)) return canKingScorpionAttack();
  if (enemyHasRangedMeleeAttack(battle.enemy)) return canBoneLordAttack();
  return battle.enemyAggro && battle.enemy?.hp > 0 && enemyTargetDistance() <= LANE.enemyRange;
}

function enemyTargetDistance() {
  if (taoistPetCanTank()) return taoistPetEnemyDistance();
  return enemyDistance();
}

function movementSurfaceSfxKey() {
  return currentBackdropKind() === "cave" ? "cave" : "field";
}

function footstepSideForFrame(frame) {
  if (frame === 1) return "left";
  if (frame === 4) return "right";
  return null;
}

function maybePlayPlayerFootstep(previousFrame, nextFrame, action = state.action) {
  if (previousFrame === nextFrame || !["walking", "running"].includes(action)) return;
  if (bossPartyActiveFight()) return;
  const side = footstepSideForFrame(nextFrame);
  if (!side) return;
  const moveType = action === "running" ? "run" : "walk";
  const surface = movementSurfaceSfxKey();
  const played = playSfx(`footstep.${surface}.${moveType}.${side}`, {
    volume: action === "running" ? 0.36 : 0.28,
    throttleMs: action === "running" ? 110 : 160,
  });
  if (!played && surface === "cave" && moveType === "walk") {
    playSfx("footstep.cave.walk.left", { volume: 0.24, throttleMs: 160 });
  }
}

function maybePlayEnemyFootstep(previousFrame, nextFrame, action = state.enemy.action) {
  if (previousFrame === nextFrame || action !== "walking") return;
  if (bossPartyActiveFight()) {
    const desired = bossPartyDesiredEnemyX();
    const current = Number(state.battle.enemyX);
    if (desired != null && Number.isFinite(current) && Math.abs(desired - current) <= BOSS_PARTY_ENEMY_MELEE_GAP + 6) return;
  }
  const side = footstepSideForFrame(nextFrame);
  if (!side) return;
  const surface = movementSurfaceSfxKey();
  const played = playSfx(`footstep.${surface}.walk.${side}`, { volume: 0.16, throttleMs: 180 });
  if (!played && surface === "cave") playSfx("footstep.cave.walk.left", { volume: 0.14, throttleMs: 180 });
}

function weaponShapeForItem(item) {
  const shape = Number(item?.visual?.index);
  return Number.isFinite(shape) ? shape : null;
}

function weaponSfxFamilyFallback(item) {
  if (!item) return "long";
  const name = `${item.id} ${item.name}`.toLowerCase();
  if (name.includes("pickaxe")) return "long";
  if (name.includes("mace") || name.includes("club")) return "club";
  if (name.includes("axe") || name.includes("decapitator")) return "axe";
  if (name.includes("wood")) return "wood";
  if (name.includes("dagger") || name.includes("short")) return "short";
  if (name.includes("spear") || name.includes("trident") || name.includes("halberd")) return "long";
  return "sword";
}

function weaponSwingSfxFamilyForItem(item) {
  const shape = weaponShapeForItem(item);
  if (shape != null && WEAPON_SWING_SFX_BY_SHAPE.has(shape)) return WEAPON_SWING_SFX_BY_SHAPE.get(shape);
  return weaponSfxFamilyFallback(item);
}

function weaponHitSfxFamilyForItem(item) {
  const shape = weaponShapeForItem(item);
  if (shape != null && WEAPON_HIT_SFX_BY_SHAPE.has(shape)) return WEAPON_HIT_SFX_BY_SHAPE.get(shape);
  return weaponSfxFamilyFallback(item);
}

function weaponSfxFamilyForItem(item) {
  return weaponSwingSfxFamilyForItem(item);
}

function currentWeaponSwingSfxFamily() {
  return weaponSwingSfxFamilyForItem(equippedItem("weapon"));
}

function currentWeaponHitSfxFamily() {
  return weaponHitSfxFamilyForItem(equippedItem("weapon"));
}

function currentWeaponSfxFamily() {
  return currentWeaponSwingSfxFamily();
}

function playWeaponSwingSfx(options = {}) {
  playSfx(`weapon.swing.${options.family ?? currentWeaponSwingSfxFamily()}`, {
    volume: options.volume ?? 0.52,
    throttleMs: options.throttleMs ?? 90,
    force: options.force,
  });
}

function playWeaponHitSfx(options = {}) {
  playSfx(`weapon.hit.${options.family ?? currentWeaponHitSfxFamily()}`, {
    volume: options.volume ?? 0.5,
    throttleMs: options.throttleMs ?? 90,
    force: options.force,
  });
}

function playMiningSwingSfx() {
  // Crystal PlayAttackSound: pickaxe shape 42 falls through to SwingFist (10056, same wav as SwingLong).
  playWeaponSwingSfx({ family: "long", volume: 0.48, throttleMs: 0, force: true });
}

function playMiningHitSfx() {
  playSfx("mining.hit", { volume: 0.55, throttleMs: 0, force: true });
}

function maybePlayMiningSwingSfx(previousFrame, nextFrame) {
  if (state.game.mode !== "mining" || state.action !== "mine") return;
  if (previousFrame === nextFrame || previousFrame >= 1 || nextFrame < 1) return;
  playMiningSwingSfx();
}

function resolveMonsterSfxIndex(enemy, kind) {
  const monsterIndex = Number(enemy?.monsterIndex);
  if (!Number.isFinite(monsterIndex)) return null;
  if (sfxEntry(`monster.${monsterIndex}.${kind}`)?.src) return monsterIndex;
  return null;
}

function enemyAttackSfxKind(enemy = state.battle.enemy, ranged = false) {
  if (!ranged) return "attack";
  const monsterIndex = Number(enemy?.monsterIndex);
  if (Number.isFinite(monsterIndex) && sfxEntry(`monster.${monsterIndex}.range`)?.src) {
    return "range";
  }
  return "attack";
}

function playMonsterSfx(kind, enemy = state.battle.enemy, options = {}) {
  const monsterIndex = resolveMonsterSfxIndex(enemy, kind);
  if (monsterIndex == null) return false;
  return playSfx(`monster.${monsterIndex}.${kind}`, {
    volume: options.volume ?? (kind === "attack" ? 0.46 : kind === "death" ? 0.55 : 0.42),
    throttleMs: options.throttleMs ?? (kind === "death" ? 0 : 80),
    force: options.force,
  });
}

function playSpellSfx(spellId, phase = "cast", options = {}) {
  return playSfx(`spell.${spellId}.${phase}`, {
    volume: options.volume ?? 0.58,
    throttleMs: options.throttleMs ?? 80,
    force: options.force,
  });
}

// Target-mode spells (ThunderBolt) only ship a cast clip in Crystal; the strike
// sound is meant to land on impact. Always play once the bolt hits, including
// misses and killing blows where the enemy is already down.
function playSpellStrikeSfx(spellId, options = {}) {
  const params = {
    volume: options.volume ?? 0.5,
    throttleMs: options.throttleMs ?? 0,
    force: options.force !== false,
  };
  if (sfxEntry(`spell.${spellId}.impact`)?.src) {
    if (playSpellSfx(spellId, "impact", params)) return true;
  }
  return playSpellSfx(spellId, "cast", params);
}

function bossPartySpellStrikeSfx(spellId, casterClassId) {
  const base = bossPartySfxParamsForClass(casterClassId, 0.5, 0);
  return playSpellStrikeSfx(spellId, { ...base, force: true, throttleMs: 0 });
}

function itemEquipSfxKey(item) {
  if (!item) return "item.move";
  if (item.type === "weapon") return "item.equip.weapon";
  if (item.type === "armour") return "item.equip.armour";
  if (item.type === "helmet") return "item.equip.helmet";
  if (item.type === "ring") return "item.equip.ring";
  if (item.type === "bracelet") return "item.equip.bracelet";
  if (item.type === "necklace") return "item.equip.necklace";
  if (item.type === "boots") return "item.equip.boots";
  return "item.move";
}

function updateEnemyFrame(now) {
  if (groupDungeonSwarmActive()) {
    updateGroupDungeonSwarmFrames(now);
    return;
  }
  if (groupDungeonBossReinforcementsActive()) {
    updateGroupDungeonSwarmFrames(now);
  }
  const clip = state.enemy.atlas?.actions?.[state.enemy.action];
  if (state.paused || !clip?.frames?.length) return;
  const dt = now - state.enemy.lastTick;
  if (dt < clip.interval) return;
  const steps = Math.floor(dt / clip.interval);
  const previousFrame = state.enemy.frame;
  if (state.enemy.action === "show") {
    const nextFrame = state.enemy.frame + steps;
    if (nextFrame >= clip.frames.length) {
      state.enemy.action = "standing";
      state.enemy.frame = 0;
      state.enemy.oneShot = false;
      state.enemy.lastTick = now;
      completeEnemySpawnReveal(now);
      updateEnemyActionButtons();
      return;
    }
    state.enemy.frame = nextFrame;
    state.enemy.lastTick += steps * clip.interval;
    return;
  }
  const terminal = state.enemy.oneShot || state.enemy.action === "struck" || state.enemy.action === "die";
  if (terminal) {
    const nextFrame = state.enemy.frame + steps;
    if (nextFrame >= clip.frames.length) {
      if (state.battle.enemy?.hp > 0) {
        state.enemy.action = "standing";
        state.enemy.frame = 0;
        state.enemy.oneShot = false;
        state.enemy.lastTick = now;
        updateEnemyActionButtons();
        return;
      }
      state.enemy.frame = clip.frames.length - 1;
    } else {
      state.enemy.frame = nextFrame;
    }
  } else {
    state.enemy.frame = (state.enemy.frame + steps) % clip.frames.length;
  }
  maybePlayEnemyFootstep(previousFrame, state.enemy.frame);
  state.enemy.lastTick += steps * clip.interval;
}

function updateTaoPetFrame(now) {
  const pet = state.battle.taoPet;
  if (!pet || (!pet.active && !pet.dead)) return;
  const atlas = taoPetAtlasFor(pet);
  const clip = atlas?.actions?.[pet.action];
  if (state.paused || !clip?.frames?.length) return;
  const dt = now - pet.lastTick;
  if (dt < clip.interval) return;
  const steps = Math.floor(dt / clip.interval);
  const terminal = pet.oneShot || pet.action === "struck" || pet.action === "die";
  if (terminal) {
    const nextFrame = pet.frame + steps;
    if (nextFrame >= clip.frames.length) {
      if (pet.dead) {
        pet.action = atlas?.actions?.dead ? "dead" : pet.action;
        pet.frame = atlas?.actions?.dead ? 0 : Math.max(0, clip.frames.length - 1);
      } else if (pet.spellId === "SummonShinsu" && pet.action === "show") {
        revealTaoistShinsuPet(pet);
        pet.action = "standing";
        pet.frame = 0;
      } else {
        pet.action = "standing";
        pet.frame = 0;
      }
      pet.oneShot = false;
      pet.lastTick = now;
      return;
    }
    pet.frame = nextFrame;
  } else {
    pet.frame = (pet.frame + steps) % clip.frames.length;
  }
  pet.lastTick += steps * clip.interval;
}

function isEnemyOneShotAction() {
  return state.enemy.oneShot || state.enemy.action === "struck" || state.enemy.action === "die" || state.enemy.action === "show";
}

function updateFrame(now, clip) {
  const spellDriven = state.syncBodyToSpell && state.spell !== "None";
  if (!spellDriven) {
    const dt = now - state.lastTick;
    if (dt >= clip.interval) {
      const steps = Math.floor(dt / clip.interval);
      const previousFrame = state.frame;
      if (isPlayerOneShotAction()) {
        const nextFrame = state.frame + steps;
        if (nextFrame >= clip.frames.length && state.battle.player?.hp > 0) {
          const previousAction = state.action;
          state.action = nextPlayerActionAfterOneShot();
          state.frame = 0;
          state.playerOneShot = false;
          state.lastTick = now;
          if (state.game.mode === "mining" && previousAction === "mine" && state.action === "stance") {
            state.battle.returnToStandAt = now + COMBAT_STANCE_HOLD_MS;
            rollMiningOreOnSwing();
          }
          updateActionButtons();
          return;
        }
        if (nextFrame >= clip.frames.length) {
          state.frame = clip.frames.length - 1;
        } else {
          state.frame = nextFrame;
        }
      } else {
        const frameStep = isPlayerSmoothLoopAction() ? 1 : steps;
        state.frame = (state.frame + frameStep) % clip.frames.length;
      }
      maybePlayPlayerFootstep(previousFrame, state.frame);
      maybePlayMiningSwingSfx(previousFrame, state.frame);
      state.lastTick = isPlayerSmoothLoopAction() ? now : state.lastTick + steps * clip.interval;
    }
    return;
  }

  const bodyDuration = clip.frames.length * clip.interval;
  const cycleDuration = bodyDuration + state.castCooldownMs;
  const t = (now - state.spellStartedAt) % Math.max(1, cycleDuration);
  state.frame = t < bodyDuration ? Math.min(clip.frames.length - 1, Math.floor(t / clip.interval)) : 0;
}

function isPlayerOneShotAction() {
  return state.playerOneShot
    || state.action === "struck"
    || state.action === "die"
    || (state.game.mode === "mining" && state.action === "mine");
}

function nextPlayerActionAfterOneShot() {
  if (state.game.mode === "mining") return "stance";
  if (state.battle.returnToStandAt && (state.battle.player?.hp ?? 0) > 0) return "stance";
  if (bossPartyActiveFight()) return "stance";
  if (isBattleEngaged()) {
    if (wizardHoldsCombatPosition()) return "stance";
    return canPlayerAttack() ? "stance" : "walking";
  }
  return state.playerOneShot && isPlayerMeleeAction(state.action) ? "stance" : "standing";
}

function isPlayerMeleeAction(action) {
  return action === "attack1" || action === "attack2" || action === "attack3" || action === "attack4" || action === "mine";
}

function isPlayerSmoothLoopAction() {
  return state.action === "walking" || state.action === "running" || state.action === "mountWalking" || state.action === "mountRunning";
}

function movementDistanceForAction(action, elapsedMs) {
  const spec = PLAYER_ACTIONS[action];
  const cycleMs = spec.count * spec.interval;
  return (Math.max(0, elapsedMs) / cycleMs) * movementCycleDistance(action);
}

function movementCycleDistance(action) {
  return action === "running" || action === "mountRunning" ? LANE_TILE_PX * 2 : LANE_TILE_PX;
}

function isBattleEngaged() {
  return state.battle.running && state.battle.phase === "engaged" && (state.battle.player?.hp ?? 0) > 0 && (state.battle.enemy?.hp ?? 0) > 0;
}

function currentClip() {
  for (const layer of layerNames()) {
    const clip = state.atlases[layer]?.actions?.[state.action];
    if (clip?.frames?.length) return clip;
  }
  return null;
}

function render() {
  if (suppressSimulationRender) return;
  ensureEquippedVisualsFresh();
  const previousStageWidth = state.stageWidth;
  updateStageSize();
  if (!state.battle.running && state.battle.phase === "idle" && previousStageWidth !== state.stageWidth) {
    state.battle.cameraX = state.battle.playerX - playerScreenX();
    state.battle.enemyX = state.battle.playerX + enemySpawnDistance();
  }
  const clip = currentClip();
  const frameCount = clip?.frames.length ?? PLAYER_ACTIONS[state.action].count;
  state.frame = Math.max(0, Math.min(state.frame, Math.max(0, frameCount - 1)));
  const displayFrame = playbackFrameIndex(frameCount);

  renderCanvasStage(displayFrame, frameCount);
  renderPlayerResourceHud();
  renderHotbar();

  const srcFrame = sourceFrameFor(state.action, displayFrame);
  const spec = PLAYER_ACTIONS[state.action];
  const spellText = state.spell === "None" ? "" : ` | skill ${spellLabel(state.spell)}`;
  const phaseText = state.syncBodyToSpell && state.spell !== "None" ? ` | cast gap ${state.castCooldownMs}ms` : "";
  els.readout.textContent = `${spec.label}${spellText}${phaseText} | frame ${state.frame + 1}/${frameCount} | Crystal source frame ${srcFrame} | ${perfReadout()}`;
  els.frameMeta.innerHTML = `
    <dt>Action</dt><dd>${state.action}</dd>
    <dt>Skill</dt><dd>${spellLabel(state.spell)}</dd>
    <dt>Mapped</dt><dd>${bodyActionForSpell(state.spell)}</dd>
    <dt>Start</dt><dd>${spec.start}</dd>
    <dt>Count</dt><dd>${spec.count}</dd>
    <dt>Skip</dt><dd>${spec.skip}</dd>
    <dt>Direction</dt><dd>2 / east</dd>
    <dt>Formula</dt><dd>start + (count + skip) * direction + frame</dd>
  `;
  renderGamePanel();
  renderBattlePanel();
  renderSceneOverlay({ deferUserInteraction: true });
  renderCombatSkillBar();
  renderPartySwitchBar();
  applyCombatHudLayout();
}

function renderPlayerResourceHud() {
  const player = state.battle.player;
  const shouldShow = Boolean(player) && (state.game.mode === "zone" || state.game.mode === "mining" || state.battle.running || state.showEnemies);
  if (!shouldShow) {
    if (!els.playerResourceHud.hidden || playerHudSignature) {
      els.playerResourceHud.hidden = true;
      els.playerResourceHud.innerHTML = "";
      playerHudSignature = "";
    }
    return;
  }

  const hpPotions = potionInventoryCount("hp");
  const mpPotions = potionInventoryCount("mp");
  const pendingHp = (state.battle.potHealthAmount ?? 0) + (state.battle.healAmount ?? 0);
  const pendingMp = state.battle.potManaAmount ?? 0;
  const now = performance.now();
  const activeBuffs = pruneStatBuffs(state.battle.statBuffs ?? [], now).map((buff) => ({
    label: buff.label,
    bonus: statBuffBonusLabel(buff),
    remaining: formatBuffRemaining(buff.expiresAt - now),
  }));
  const signature = JSON.stringify({
    className: state.battle.combatClass,
    level: state.game.progress.level,
    hp: player.hp,
    maxHp: player.maxHp,
    mp: player.mp,
    maxMp: player.maxMp,
    pendingHp,
    pendingMp,
    hpPotions,
    mpPotions,
    activeBuffs,
  });
  if (signature === playerHudSignature) return;
  playerHudSignature = signature;

  els.playerResourceHud.hidden = false;
  const titleHtml = IS_GAME_UI
    ? `<div class="player-resource-title game-minimal"><span>Lv ${state.game.progress.level}</span></div>`
    : `
      <div class="player-resource-title">
        <strong>${escapeHtml(state.battle.combatClass)}</strong>
        <span>Lv ${state.game.progress.level}</span>
      </div>
    `;
  els.playerResourceHud.innerHTML = `
    ${titleHtml}
    ${playerResourceBarHtml("hp", "HP", player.hp, player.maxHp, pendingHp)}
    ${playerResourceBarHtml("mp", "MP", player.mp, player.maxMp, pendingMp)}
    <div class="player-resource-potions">
      ${potionQuickButtonHtml("hp", "HP", hpPotions)}
      ${potionQuickButtonHtml("mp", "MP", mpPotions)}
    </div>
    ${activeBuffs.length ? `<div class="player-resource-buffs">${activeBuffs.map((buff) => `<span class="player-stat-buff">${escapeHtml(buff.label)} ${escapeHtml(buff.bonus)} · ${escapeHtml(buff.remaining)}</span>`).join("")}</div>` : ""}
  `;
}

function playerResourceBarHtml(kind, label, value, max, pending = 0) {
  const pct = resourcePercentage(value, max);
  const pendingText = pending > 0 ? ` +${Math.floor(pending)}` : "";
  return `
    <div class="player-resource-row ${kind}">
      <span class="player-resource-label">${label}</span>
      <span class="player-resource-track">
        <span class="player-resource-fill" style="width:${pct}%"></span>
      </span>
      <span class="player-resource-value">${Math.max(0, Math.floor(value))}/${Math.max(0, Math.floor(max))}${pendingText}</span>
    </div>
  `;
}

function potionQuickButtonHtml(kind, label, count) {
  return `<button type="button" class="player-potion-button ${kind}" data-use-potion-kind="${kind}" ${count > 0 ? "" : "disabled"}>${label} x${count}</button>`;
}

function resourcePercentage(value, max) {
  return max > 0 ? Math.max(0, Math.min(100, (value / max) * 100)) : 0;
}

function renderCanvasStage(displayFrame, frameCount) {
  const drawStartedAt = performance.now();
  const canvas = ensureStageCanvas();
  const ctx = stageContext;
  if (!canvas || !ctx) return;

  if (canvas.width !== state.stageWidth || canvas.height !== state.stageHeight) {
    canvas.width = state.stageWidth;
    canvas.height = state.stageHeight;
    invalidateStampBackgroundCache();
  }
  const displayWidth = state.stageWidth * state.scale;
  const displayHeight = state.stageHeight * state.scale;
  if (displayWidth !== lastStageDisplaySize.w || displayHeight !== lastStageDisplaySize.h) {
    lastStageDisplaySize = { w: displayWidth, h: displayHeight };
    canvas.style.width = `${displayWidth}px`;
    canvas.style.height = `${displayHeight}px`;
  }
  ctx.imageSmoothingEnabled = state.smooth;
  ctx.clearRect(0, 0, state.stageWidth, state.stageHeight);

  if (state.game.mode === "town") {
    drawTownCanvas(ctx, displayFrame);
    drawLevelUpFxCanvas(ctx);
    drawLootNotices(ctx);
    state.perf.drawMs = performance.now() - drawStartedAt;
    return;
  }

  drawMapCanvas(ctx);
  drawGroundSpellEffectsCanvas(ctx);
  drawMapLightningEffectsCanvas(ctx);
  if (bossPartyOnField()) drawBossPartyDeadMembers(ctx);
  if (!drawStampArenaEntityLayers(ctx, displayFrame)) {
    drawEnemyCanvas(ctx);
    drawZoneMapStampForeground(ctx);
    if (bossPartyOnField()) {
      drawBossPartyLivingMembers(ctx);
      drawTaoistPetCanvas(ctx);
    } else {
      drawTaoistPetCanvas(ctx);
      drawPlayerCanvas(ctx, displayFrame);
    }
  }
  drawEnemyRangeProjectileCanvas(ctx);
  drawSwarmEnemyRangeProjectileCanvas(ctx);
  drawEnemyHealthBar(ctx);
  drawTaoistPetHealthBar(ctx);
  drawEnemyPoisonDots(ctx);
  drawSpellFxCanvas(ctx, displayFrame, frameCount);
  drawAttachedSpellFxCanvas(ctx);
  drawTwinDrakeReadyFxCanvas(ctx);
  drawCombatSkillFxCanvas(ctx);
  drawCombatWizardFxCanvas(ctx);
  drawCombatTaoistFxCanvas(ctx);
  drawDefenceBuffFxCanvas(ctx);
  if (state.battle.bossParty?.active || state.battle.bossParty?.finished) {
    drawBossPartySpellFxCanvas(ctx);
    drawBossPartyHealFxCanvas(ctx);
  }
  drawLevelUpFxCanvas(ctx);
  drawFloatingCombatText(ctx);
  drawLootNotices(ctx);
  state.perf.drawMs = performance.now() - drawStartedAt;
}

function perfReadout() {
  return `FPS ${state.perf.fps || "--"} | draw ${state.perf.drawMs.toFixed(1)}ms | canvas nodes 1`;
}

function ensureStageCanvas() {
  if (stageCanvas && stageCanvas.isConnected) return stageCanvas;
  stageCanvas = document.createElement("canvas");
  stageCanvas.className = "stage-canvas";
  stageCanvas.width = state.stageWidth;
  stageCanvas.height = state.stageHeight;
  els.stage.prepend(stageCanvas);
  stageContext = stageCanvas.getContext("2d");
  bindStageCanvasEvents();
  return stageCanvas;
}

function drawTownCanvas(ctx, displayFrame) {
  drawTownMapCanvas(ctx);
  drawTownNpcs(ctx);
  drawPlayerCanvas(ctx, displayFrame);
  drawTownNameplates(ctx);
}

function invalidateStampBackgroundCache() {
  stampBackgroundCache.key = "";
}

function clearStampBackgroundCache() {
  stampBackgroundCache.key = "";
  stampBackgroundCache.canvas = null;
}

function blitCachedStampBackground(ctx, key, painter) {
  if (!key) {
    painter(ctx);
    return;
  }
  if (stampBackgroundCache.key === key && stampBackgroundCache.canvas) {
    ctx.drawImage(stampBackgroundCache.canvas, 0, 0);
    return;
  }
  if (!stampBackgroundCache.canvas) stampBackgroundCache.canvas = document.createElement("canvas");
  const cacheCanvas = stampBackgroundCache.canvas;
  if (cacheCanvas.width !== state.stageWidth || cacheCanvas.height !== state.stageHeight) {
    cacheCanvas.width = state.stageWidth;
    cacheCanvas.height = state.stageHeight;
  }
  const cacheCtx = cacheCanvas.getContext("2d");
  cacheCtx.imageSmoothingEnabled = state.smooth;
  cacheCtx.clearRect(0, 0, state.stageWidth, state.stageHeight);
  painter(cacheCtx);
  stampBackgroundCache.key = key;
  ctx.drawImage(cacheCanvas, 0, 0);
}

function townStampBackgroundCacheKey(stamp = currentTownMapStamp()) {
  if (!stamp) return "";
  return [
    "town",
    stamp.id,
    state.stageWidth,
    state.stageHeight,
    state.smooth ? 1 : 0,
    MAP_STAMP_ASSET_VERSION,
    TOWN_VISUALS.mapStampOffsetY,
    TOWN_VISUALS.mapStampViewUpTiles,
    Number(stamp.offsetY) || 0,
    Number(stamp.scale) || 1,
  ].join("|");
}

function zoneStampBehindBackgroundCacheKey(stamp = currentZoneMapStamp()) {
  if (!stamp) return "";
  const anchor = mapStampAnchor(stamp);
  return [
    "zone-behind",
    stamp.id,
    state.game.activeZoneId,
    state.stageWidth,
    state.stageHeight,
    state.smooth ? 1 : 0,
    MAP_STAMP_ASSET_VERSION,
    arenaSpawnMapRow(),
    anchor.x,
    anchor.y,
  ].join("|");
}

function zoneMapStampSheetReady(stamp = currentZoneMapStamp()) {
  if (!stamp?.sheet) return false;
  return Boolean(cachedImage(`./public/mapstamps/${stamp.sheet}?v=${MAP_STAMP_ASSET_VERSION}`));
}

function townMapStampSheetReady(stamp = currentTownMapStamp()) {
  if (!stamp?.sheet) return false;
  return Boolean(cachedImage(`./public/mapstamps/${stamp.sheet}?v=${MAP_STAMP_ASSET_VERSION}`));
}

function drawTownMapCanvas(ctx) {
  const stamp = currentTownMapStamp();
  if (stamp?.layers?.length) {
    const key = townMapStampSheetReady(stamp) ? townStampBackgroundCacheKey(stamp) : "";
    const paint = (targetCtx) => {
      drawBackdropGradient(targetCtx);
      drawTownMapStamp(targetCtx, stamp);
    };
    if (key) blitCachedStampBackground(ctx, key, paint);
    else paint(ctx);
    return;
  }

  drawBackdropGradient(ctx);

  const set = currentMapSet();
  if (!set?.tiles?.length) return;

  const sheet = cachedImage(`./public/maptiles/${set.sheet}`);
  if (!sheet) return;

  const rows = Math.ceil(state.stageHeight / 28) + 4;
  const cols = Math.ceil(state.stageWidth / set.slotWidth) + 4;
  const baseY = Math.floor(state.stageHeight * 0.42);
  for (let row = 0; row < rows; row++) {
    for (let col = -2; col < cols; col++) {
      const slot = mapLaneTileSlot(set, row, col + row * 3);
      const x = col * set.slotWidth + (row % 2 ? Math.floor(set.slotWidth / 2) : 0) - 24;
      const y = baseY + row * 28 - 58;
      drawMapTile(ctx, sheet, set, slot, x, y);
    }
  }
}

function currentTownMapStamp() {
  if (state.game.mode !== "town") return null;
  const stampId = TOWN_VISUALS.mapStamp;
  if (!stampId) return null;
  return state.mapStampIndex.stamps.find((stamp) => stamp.id === stampId) ?? null;
}

function townViewOffsetYPx() {
  return (Number(TOWN_VISUALS.mapStampViewUpTiles) || 0) * MAP_TILE_ANCHOR_ROW_STEP;
}

function drawTownMapStamp(ctx, stamp) {
  const townStamp = {
    ...stamp,
    anchor: "townCenter",
    offsetY: (Number(stamp.offsetY) || 0)
      + (Number(TOWN_VISUALS.mapStampOffsetY) || 0)
      + townViewOffsetYPx(),
  };
  const layers = (townStamp.layers ?? []).filter((layer) => !mapStampLayerIsGroundLightGlow(layer));
  drawStampLayerBatch(ctx, townStamp, layers);
}

function drawTownNpcs(ctx) {
  for (const npc of TOWN_NPCS) {
    const bounds = townNpcBounds(npc);
    const selected = npc.id === state.game.selectedTownNpcId;
    ctx.save();
    ctx.fillStyle = selected ? "rgba(216, 176, 92, 0.34)" : "rgba(0, 0, 0, 0.24)";
    ctx.beginPath();
    ctx.ellipse(bounds.centerX, bounds.bottomY - 4, bounds.width * 0.55, 9, 0, 0, Math.PI * 2);
    ctx.fill();
    if (!drawTownNpcSprite(ctx, npc, bounds)) {
      drawTownNpcPlaceholder(ctx, bounds, selected);
    }
    if (selected) {
      ctx.strokeStyle = "#d8b05c";
      ctx.strokeRect(bounds.left + 0.5, bounds.top + 0.5, bounds.width - 1, bounds.height - 1);
    }
    ctx.restore();
  }
}

function drawTownNpcSprite(ctx, npc, bounds) {
  const atlas = state.townNpcAtlases[npc.sprite];
  const layer = atlas?.layers?.[0];
  if (!layer?.frames?.length) return false;
  const sheet = cachedImage(`./public/npcs/${npc.sprite}/${layer.sheet}`);
  if (!sheet) return false;

  const totalDuration = layer.interval * layer.frames.length;
  const frameIndex = Math.floor((performance.now() % totalDuration) / layer.interval);
  const meta = layer.frames[frameIndex] ?? layer.frames[0];
  if (!meta || meta.empty) return false;
  const baseMeta = layer.frames[0] ?? meta;
  const offsetX = (meta.offsetX ?? 0) - (baseMeta.offsetX ?? 0);
  const offsetY = (meta.offsetY ?? 0) - (baseMeta.offsetY ?? 0);

  ctx.drawImage(
    sheet,
    meta.slot * layer.slotWidth,
    0,
    layer.slotWidth,
    layer.slotHeight,
    Math.round(bounds.centerX - layer.slotWidth / 2 + offsetX),
    Math.round(bounds.bottomY - layer.slotHeight + offsetY),
    layer.slotWidth,
    layer.slotHeight,
  );
  return true;
}

function drawTownNpcPlaceholder(ctx, bounds, selected) {
  ctx.fillStyle = "#3e3328";
  ctx.fillRect(bounds.left + 12, bounds.top + 26, bounds.width - 24, bounds.height - 30);
  ctx.fillStyle = "#6c4b32";
  ctx.fillRect(bounds.left + 8, bounds.top + 32, bounds.width - 16, 24);
  ctx.fillStyle = "#d8bd93";
  ctx.fillRect(bounds.left + 14, bounds.top + 8, bounds.width - 28, 24);
  ctx.fillStyle = "#2b211b";
  ctx.fillRect(bounds.left + 10, bounds.top + 4, bounds.width - 20, 10);
  ctx.strokeStyle = selected ? "#d8b05c" : "rgba(255, 238, 196, 0.32)";
  ctx.strokeRect(bounds.left + 0.5, bounds.top + 0.5, bounds.width - 1, bounds.height - 1);
}

function drawTownNameplates(ctx) {
  const hoveredNpc = TOWN_NPCS.find((npc) => npc.id === state.game.hoveredTownNpcId);
  if (!hoveredNpc) return;
  ctx.save();
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.font = "700 12px Segoe UI, system-ui, sans-serif";
  const bounds = townNpcBounds(hoveredNpc);
  const text = hoveredNpc.label;
  const width = Math.max(72, ctx.measureText(text).width + 16);
  const x = Math.round(bounds.centerX);
  const y = Math.round(bounds.top - 12);
  ctx.fillStyle = "rgba(10, 10, 8, 0.78)";
  ctx.fillRect(Math.round(x - width / 2), y - 10, width, 20);
  ctx.strokeStyle = "rgba(255, 238, 196, 0.48)";
  ctx.strokeRect(Math.round(x - width / 2) + 0.5, y - 9.5, width - 1, 19);
  ctx.fillStyle = "#f4ddb0";
  ctx.fillText(text, x, y);
  ctx.restore();
}

function townNpcAt(x, y) {
  return TOWN_NPCS.find((npc) => {
    const bounds = townNpcBounds(npc);
    return x >= bounds.left && x <= bounds.right && y >= bounds.top && y <= bounds.bottom;
  }) ?? null;
}

function townNpcBounds(npc) {
  const npcOffsetX = (Number(TOWN_VISUALS.npcOffsetXTiles) || 0) * LANE_TILE_PX;
  const npcOffsetY = (Number(npc.yOffsetTiles) || 0) * LANE_TILE_PX;
  const centerX = Math.round(state.stageWidth * npc.x + npcOffsetX);
  const bottomY = Math.round(state.stageHeight * npc.y + npcOffsetY + townViewOffsetYPx());
  const spriteSize = townNpcSpriteSize(npc);
  const width = spriteSize.width;
  const height = spriteSize.height;
  return {
    centerX,
    bottomY,
    width,
    height,
    left: centerX - width / 2,
    right: centerX + width / 2,
    top: bottomY - height,
    bottom: bottomY,
  };
}

function townNpcSpriteSize(npc) {
  const layer = state.townNpcAtlases[npc.sprite]?.layers?.[0];
  return {
    width: layer?.slotWidth ?? npc.width,
    height: layer?.slotHeight ?? npc.height,
  };
}

function zoneMapStampReplacesTiles(zone = activeZone()) {
  const stamp = currentZoneMapStamp();
  if (!stamp?.layers?.length) return false;
  if (zone?.mapStampOnly === true || state.game.mode === "mining") return true;
  const mapSetId = zone?.mapSet ?? currentMapSetId();
  const set = mapSetById(mapSetId);
  return !(set?.tiles?.length);
}

function drawMapCanvas(ctx) {
  const stamp = currentZoneMapStamp();
  if (stamp?.layers?.length && zoneMapStampReplacesTiles()) {
    const key = zoneMapStampSheetReady(stamp) ? zoneStampBehindBackgroundCacheKey(stamp) : "";
    const paint = (targetCtx) => {
      drawBackdropGradient(targetCtx);
      drawZoneMapStampLayers(targetCtx, "behind");
    };
    if (key) blitCachedStampBackground(ctx, key, paint);
    else paint(ctx);
    return;
  }

  const set = currentMapSet();
  if (!set?.tiles?.length) {
    ctx.fillStyle = "#151512";
    ctx.fillRect(0, 0, state.stageWidth, state.stageHeight);
    return;
  }
  const sheet = cachedImage(`./public/maptiles/${set.sheet}`);
  drawBackdropGradient(ctx);
  if (!sheet) return;

  const edgeGroundRowOffset = currentZoneEdgeSet()?.skipTopGroundRows ?? 0;
  const groundRows = currentZoneGroundRows();
  const firstGroundRow = edgeGroundRowOffset - groundRows.top;
  const rows = 5 + edgeGroundRowOffset + groundRows.bottom;
  const cols = Math.ceil(state.stageWidth / set.slotWidth) + 10;
  const baseY = Math.floor(state.stageHeight * LANE.y) - 34;
  const tileCameraX = (state.battle.cameraX ?? 0) * LANE.tileScrollRatio;
  const scrollCameraX = movementTestScrollCameraX(tileCameraX);
  const scroll = Math.floor(positiveModulo(scrollCameraX, set.slotWidth));
  const tileColumn = Math.floor(scrollCameraX / set.slotWidth);

  drawCaveEdgeStrip(ctx, scrollCameraX, baseY, "top");

  const tileAnchor2x2 = currentZoneTileAnchor2x2();
  if (tileAnchor2x2) {
    // Crystal back tiles use 32px row step; lane row math uses 28px — convert by pixel coverage.
    const lastLaneRow = rows - 1;
    const firstAnchorRow = Math.floor((firstGroundRow * MAP_LANE_ROW_STEP) / MAP_TILE_ANCHOR_ROW_STEP);
    const lastAnchorRowFromLane = Math.ceil((lastLaneRow * MAP_LANE_ROW_STEP) / MAP_TILE_ANCHOR_ROW_STEP) + 1;
    const sampleTile = set.tiles[0];
    const tileDrawBottom = (Number(sampleTile?.offsetY) || 0)
      + (Number(sampleTile?.h) || set.slotHeight)
      - 58;
    const minAnchorForStage = Math.ceil((state.stageHeight - baseY - tileDrawBottom) / MAP_TILE_ANCHOR_ROW_STEP);
    const lastAnchorRow = Math.max(lastAnchorRowFromLane, minAnchorForStage + 1);
    const firstDrawAnchorRow = firstAnchorRow % 2 === 0 ? firstAnchorRow : firstAnchorRow + 1;
    for (let anchorRow = firstDrawAnchorRow; anchorRow < lastAnchorRow; anchorRow += 2) {
      for (let col = -5; col < cols; col++) {
        const worldColumn = col + tileColumn;
        const slot = mapAnchor2x2TileSlot(set, anchorRow, worldColumn);
        const { x, y } = mapTilePositionAnchor2x2(set, anchorRow, col, scroll, baseY);
        drawMapTile(ctx, sheet, set, slot, x, y);
      }
    }
  } else {
    for (let row = firstGroundRow; row < rows; row++) {
      for (let col = -5; col < cols; col++) {
        const worldColumn = col + tileColumn;
        const slot = mapLaneTileSlot(set, row, worldColumn);
        const { x, y } = mapTilePosition(set, row, col, scroll, baseY);
        drawMapTile(ctx, sheet, set, slot, x, y);
      }
    }
  }

  drawZoneMapStamp(ctx);
  drawZoneDecorations(ctx, scrollCameraX, baseY);
}

function mapTilePosition(set, row, col, scroll, baseY) {
  return {
    x: col * set.slotWidth - scroll + (row % 2 ? Math.floor(set.slotWidth / 2) : 0) - 24,
    y: baseY + row * MAP_LANE_ROW_STEP - 58,
  };
}

// Crystal back tiles anchor on even map cells and cover a 2x2 block (96x64 art, 32px row step).
function mapTilePositionAnchor2x2(set, anchorRow, col, scroll, baseY) {
  return {
    x: col * set.slotWidth - scroll - 24,
    y: baseY + anchorRow * MAP_TILE_ANCHOR_ROW_STEP - 58,
  };
}

function mapLaneTileSlot(set, row, worldColumn) {
  const pattern = currentZonePattern();
  const rowPattern = pattern[positiveModulo(row, pattern.length)];
  return positiveModulo(rowPattern[positiveModulo(worldColumn, rowPattern.length)], set.tiles.length);
}

// Crystal back tiles anchor on even map rows only; pattern rows are one per 2 cell rows.
function mapAnchor2x2TileSlot(set, anchorMapRow, worldColumn) {
  const pattern = currentZonePattern();
  const patternRow = positiveModulo(Math.trunc(anchorMapRow / 2), pattern.length);
  const rowPattern = pattern[patternRow];
  return positiveModulo(rowPattern[positiveModulo(worldColumn, rowPattern.length)], set.tiles.length);
}

function drawMapTile(ctx, sheet, set, slot, x, y, alpha = 1) {
  const tile = set.tiles[positiveModulo(slot, set.tiles.length)];
  if (!tile) return;
  const sourceW = Number(tile.w) || set.slotWidth;
  const sourceH = Number(tile.h) || set.slotHeight;
  const destX = x + (Number(tile.offsetX) || 0);
  const destY = y + (Number(tile.offsetY) || 0);
  ctx.save();
  ctx.globalAlpha = alpha;
  ctx.drawImage(
    sheet,
    tile.slot * set.slotWidth,
    0,
    sourceW,
    sourceH,
    destX,
    destY,
    sourceW,
    sourceH,
  );
  ctx.restore();
}

function arenaSpawnMapRow(zone = activeZone()) {
  const spot = state.game.mode === "mining" ? activeMiningSpot() : null;
  const spawnRow = Math.trunc(Number(spot?.arenaSpawnMap?.y ?? zone?.arenaSpawnMap?.y) || 0);
  if (spawnRow > 0) return spawnRow;
  const focusRow = Math.trunc(Number(spot?.arenaFocusMap?.y ?? zone?.arenaFocusMap?.y) || 0);
  return focusRow > 0 ? focusRow : 0;
}

// Crystal DrawObjects: tall front objects on the spawn row draw before monsters; only objects
// rooted on southern rows (mapY > spawn) are drawn after the monster and can occlude the body.
function mapStampLayerDrawsOverEnemy(layer, spawnRow = arenaSpawnMapRow()) {
  if (!spawnRow || !layer) return false;
  if (layer.kind === "back" || layer.kind === "middle" || layer.floor) return false;
  if (layer.inFront === true) return true;
  const mapRow = Math.trunc(Number(layer.mapRow) || 0);
  return mapRow > spawnRow;
}

function mapStampHasForegroundLayers(stamp = currentZoneMapStamp(), spawnRow = arenaSpawnMapRow()) {
  return Boolean(stamp?.layers?.some((layer) => mapStampLayerDrawsOverEnemy(layer, spawnRow)));
}

function stampSheetColumns(stamp) {
  const columns = Math.trunc(Number(stamp?.sheetColumns) || 0);
  if (columns > 0) return columns;
  const assetCount = Array.isArray(stamp?.assets) ? stamp.assets.length : 0;
  return Math.max(1, assetCount);
}

function stampSheetSlotOrigin(stamp, slot) {
  const columns = stampSheetColumns(stamp);
  const slotWidth = Math.max(1, Math.trunc(Number(stamp.slotWidth) || 1));
  const slotHeight = Math.max(1, Math.trunc(Number(stamp.slotHeight) || 1));
  const index = Math.max(0, Math.trunc(Number(slot) || 0));
  return {
    sx: (index % columns) * slotWidth,
    sy: Math.floor(index / columns) * slotHeight,
  };
}

// 100x100 ground glow sprites (2723-2732). Lamp posts are frame 2733 — keep those.
function mapStampLayerIsGroundLightGlow(layer) {
  const match = /^(\d+):(\d+)$/.exec(String(layer?.source ?? ""));
  if (!match) return false;
  const slot = Number(match[1]);
  const frame = Number(match[2]);
  return slot === 2 && frame >= 2723 && frame <= 2732;
}

function drawStampLayerBatch(ctx, stamp, layers) {
  if (!stamp?.sheet || !layers?.length) return;
  const sheet = cachedImage(`./public/mapstamps/${stamp.sheet}?v=${MAP_STAMP_ASSET_VERSION}`);
  if (!sheet) return;

  const { baseX, baseY, scale, slotWidth, slotHeight } = mapStampDrawBase(stamp);

  ctx.save();
  for (const layer of layers) {
    const layerWidth = Math.max(1, Math.trunc(Number(layer.w) || slotWidth));
    const layerHeight = Math.max(1, Math.trunc(Number(layer.h) || slotHeight));
    const { sx, sy } = stampSheetSlotOrigin(stamp, layer.slot);
    ctx.drawImage(
      sheet,
      sx,
      sy,
      layerWidth,
      layerHeight,
      baseX + Math.round((Number(layer.x) || 0) * scale),
      baseY + Math.round((Number(layer.y) || 0) * scale),
      Math.round(layerWidth * scale),
      Math.round(layerHeight * scale),
    );
  }
  ctx.restore();
}

function mapStampDrawBase(stamp) {
  const anchor = mapStampAnchor(stamp);
  const scale = Math.max(0.1, Number(stamp.scale) || 1);
  const offsetX = Number(stamp.offsetX) || 0;
  const offsetY = Number(stamp.offsetY) || 0;
  const focusX = Number(stamp.focusX) || 0;
  const focusY = Number(stamp.focusY) || 0;
  const slotWidth = Math.max(1, Math.trunc(Number(stamp.slotWidth) || 1));
  const slotHeight = Math.max(1, Math.trunc(Number(stamp.slotHeight) || 1));
  const baseX = Math.round(anchor.x - focusX * scale + offsetX);
  const baseY = stamp.anchor === "townBottom"
    ? Math.round(anchor.y - Number(stamp.height) * scale + offsetY)
    : Math.round(anchor.y - focusY * scale + offsetY);
  return { baseX, baseY, scale, slotWidth, slotHeight };
}

function stampForegroundLayersByRow(stamp = currentZoneMapStamp(), spawnRow = arenaSpawnMapRow()) {
  const byRow = new Map();
  if (!stamp?.layers?.length || !spawnRow) return byRow;
  for (const layer of stamp.layers) {
    if (!mapStampLayerDrawsOverEnemy(layer, spawnRow)) continue;
    const row = Math.trunc(Number(layer.mapRow) || 0);
    if (!byRow.has(row)) byRow.set(row, []);
    byRow.get(row).push(layer);
  }
  return byRow;
}

const STAMP_ARENA_KIND_RANK = { corpse: -1, party: 0, player: 0, pet: 1, enemy: 2 };

function buildStampArenaDrawList(displayFrame) {
  const spawnRow = arenaSpawnMapRow();
  if (!spawnRow) return [];
  const entities = [];

  if (bossPartyOnField()) {
    const party = state.battle.bossParty;
    for (const member of party?.members ?? []) {
      if (!member.alive || member.hp <= 0) continue;
      entities.push({
        zRow: spawnRow,
        worldX: Number(member.worldX) || 0,
        kindRank: STAMP_ARENA_KIND_RANK.party,
        draw: (ctx) => drawBossPartyMemberCanvas(ctx, member),
      });
    }
  } else if (state.battle.player && state.showEnemies) {
    entities.push({
      zRow: spawnRow,
      worldX: Number(state.battle.playerX) || 0,
      kindRank: STAMP_ARENA_KIND_RANK.player,
      draw: (ctx) => drawPlayerCanvas(ctx, displayFrame),
    });
  }

  if (state.showEnemies) {
    const pet = state.battle.taoPet;
    if (pet && (pet.active || pet.dead)) {
      entities.push({
        zRow: spawnRow,
        worldX: resolvedTaoPetWorldX(pet),
        kindRank: STAMP_ARENA_KIND_RANK.pet,
        draw: (ctx) => drawTaoistPetCanvas(ctx),
      });
    }
  }

  if (state.showEnemies && groupDungeonSwarmSideActive()) {
    const swarm = state.battle.swarm;
    for (const enemy of swarm?.enemies ?? []) {
      if (enemy.hp <= 0 && !enemy.dying) continue;
      if (!state.battle.enemyRevealed) continue;
      const tile = swarmEnemyTilePosition(enemy);
      const corpse = enemy.dying || enemy.hp <= 0;
      entities.push({
        zRow: corpse ? spawnRow : swarmEnemyTilePosition(enemy).mapRow,
        worldX: tile.worldX,
        kindRank: corpse ? STAMP_ARENA_KIND_RANK.corpse : STAMP_ARENA_KIND_RANK.enemy,
        draw: (ctx) => drawGroupDungeonSwarmEnemyCanvas(ctx, enemy),
      });
    }
  }
  if (state.showEnemies && state.battle.enemy && !groupDungeonSwarmActive()) {
    const visible = state.battle.enemyRevealed || state.enemy.action === "show";
    if (visible) {
      const enemyMapRowOffset = arenaEnemyVisualDrawOffset().mapRow;
      entities.push({
        zRow: spawnRow + enemyMapRowOffset,
        worldX: Number(state.battle.enemyX) || 0,
        kindRank: STAMP_ARENA_KIND_RANK.enemy,
        draw: (ctx) => drawEnemyCanvas(ctx),
      });
    }
  }

  return entities;
}

function shouldUseStampArenaEntityLayers() {
  return Boolean(currentZoneMapStamp() && arenaSpawnMapRow() > 0);
}

// Crystal DrawObjects row pass: tall fronts on row Y, then characters on row Y west›east.
function drawStampArenaEntityLayers(ctx, displayFrame) {
  if (!shouldUseStampArenaEntityLayers()) return false;
  const stamp = currentZoneMapStamp();
  const spawnRow = arenaSpawnMapRow();
  const entities = buildStampArenaDrawList(displayFrame);
  const fgByRow = stampForegroundLayersByRow(stamp, spawnRow);
  const rows = new Set([spawnRow, ...fgByRow.keys()]);
  for (const entity of entities) rows.add(entity.zRow);
  const sortedRows = [...rows].sort((a, b) => a - b);

  for (const row of sortedRows) {
    const fgLayers = fgByRow.get(row);
    if (fgLayers?.length) drawStampLayerBatch(ctx, stamp, fgLayers);
    const rowEntities = entities.filter((entity) => entity.zRow === row);
    const corpseEntities = rowEntities
      .filter((entity) => entity.kindRank === STAMP_ARENA_KIND_RANK.corpse)
      .sort((a, b) => a.worldX - b.worldX);
    const livingEntities = rowEntities
      .filter((entity) => entity.kindRank !== STAMP_ARENA_KIND_RANK.corpse)
      .sort((a, b) => a.worldX - b.worldX || a.kindRank - b.kindRank);
    for (const entity of corpseEntities) entity.draw(ctx);
    for (const entity of livingEntities) entity.draw(ctx);
  }
  return true;
}

function drawZoneMapStampLayers(ctx, depth = "behind") {
  const stamp = currentZoneMapStamp();
  if (!stamp?.layers?.length || !stamp.sheet) return;
  const spawnRow = arenaSpawnMapRow();
  const hasForeground = mapStampHasForegroundLayers(stamp, spawnRow);
  const layers = stamp.layers.filter((layer) => {
    const inFront = mapStampLayerDrawsOverEnemy(layer, spawnRow);
    if (!hasForeground) return true;
    if (depth === "behind") return !inFront;
    if (depth === "front") return inFront;
    return true;
  });
  drawStampLayerBatch(ctx, stamp, layers);
}

function drawZoneMapStamp(ctx) {
  drawZoneMapStampLayers(ctx, "behind");
}

function drawZoneMapStampForeground(ctx) {
  if (!mapStampHasForegroundLayers()) return;
  drawZoneMapStampLayers(ctx, "front");
}

function mapStampAnchor(stamp) {
  if (stamp.anchor === "townBottom") {
    return {
      x: Math.round(state.stageWidth * 0.5),
      y: Math.round(state.stageHeight - (Number(TOWN_VISUALS.mapStampBottomPadding) || 0)),
    };
  }
  if (stamp.anchor === "townCenter") {
    return {
      x: Math.round(state.stageWidth * 0.5),
      y: Math.round(state.stageHeight * 0.55),
    };
  }
  if (stamp.anchor === "arenaSpawn") {
    return {
      x: Math.round(mapStampArenaWorldX() - (state.battle.cameraX ?? 0)),
      y: Math.round(arenaLaneYPx()),
    };
  }
  if (stamp.anchor === "enemy" && state.battle.enemy) {
    return combatAnchor("enemy");
  }
  if (stamp.anchor === "player" && state.battle.player) {
    return combatAnchor("player");
  }
  return {
    x: Math.round(state.stageWidth * 0.5),
    y: Math.round(state.stageHeight * LANE.y),
  };
}

function drawZoneDecorations(ctx, scrollCameraX, baseY) {
  const set = currentMapObjectSet();
  const decorations = currentZoneDecorations();
  if (set?.objects?.length && decorations.length) {
    const sheet = cachedImage(`./public/mapobjects/${set.sheet}`);
    if (sheet) {
      for (const decoration of decorations) {
        if (!Array.isArray(decoration.slots) || !decoration.slots.length) continue;

        const repeatEvery = decoration.repeatEvery ?? 0;
        const startX = repeatEvery > 0
          ? decoration.worldX - Math.ceil((decoration.worldX - scrollCameraX) / repeatEvery) * repeatEvery
          : decoration.worldX;
        const copies = repeatEvery > 0 ? Math.ceil(state.stageWidth / repeatEvery) + 3 : 1;
        for (let copy = 0; copy < copies; copy++) {
          const worldX = startX + copy * (repeatEvery || 0);
          const screenX = Math.floor(worldX - scrollCameraX);
          const decorWidth = decoration.slots.reduce((max, slotIndex) => {
            const object = set.objects[positiveModulo(slotIndex, set.objects.length)];
            return Math.max(max, Number(object?.w) || set.slotWidth);
          }, set.slotWidth);
          if (screenX < -decorWidth - 48 || screenX > state.stageWidth + 48) continue;
          const row = decorationSpawnRow(decoration, worldX);
          const y = Math.floor(baseY + row * 28 - set.slotHeight + 28);
          drawObjectPair(ctx, sheet, set, decoration.slots, screenX, y);
        }
      }
    }
  }

  drawZoneObjectPattern(ctx, scrollCameraX, baseY);
}

function drawZoneObjectPattern(ctx, scrollCameraX, baseY) {
  const pattern = currentZoneObjectPattern();
  if (!pattern.length) return;
  const set = currentZoneObjectSet();
  if (!set?.objects?.length) return;
  const sheet = cachedImage(`./public/mapobjects/${set.sheet}`);
  if (!sheet) return;

  const scroll = Math.floor(positiveModulo(scrollCameraX, set.slotWidth));
  const objectColumn = Math.floor(scrollCameraX / set.slotWidth);
  const cols = Math.ceil(state.stageWidth / set.slotWidth) + 10;
  const wallTop = Math.floor(baseY - 132);
  for (let row = 0; row < pattern.length; row++) {
    const rowPattern = pattern[row];
    if (!rowPattern?.length) continue;
    for (let col = -5; col < cols; col++) {
      const worldColumn = col + objectColumn;
      const slot = rowPattern[positiveModulo(worldColumn, rowPattern.length)];
      if (slot === ZONE_OBJECT_EMPTY || slot == null) continue;
      const object = set.objects[positiveModulo(slot, set.objects.length)];
      if (!object) continue;
      const x = col * set.slotWidth - scroll - 24;
      const y = wallTop + row * 32;
      ctx.drawImage(
        sheet,
        object.slot * set.slotWidth,
        0,
        set.slotWidth,
        set.slotHeight,
        x,
        y,
        set.slotWidth,
        set.slotHeight,
      );
    }
  }
}

function drawObjectPair(ctx, sheet, set, slots, x, y) {
  let offsetX = 0;
  for (let index = 0; index < slots.length; index++) {
    const object = set.objects[positiveModulo(slots[index], set.objects.length)];
    if (!object) continue;
    const width = Math.max(1, Number(object.w) || set.slotWidth);
    const height = Math.max(1, Number(object.h) || set.slotHeight);
    const sourceX = object.slot * set.slotWidth;
    const sourceY = set.slotHeight - height;
    const destY = y + (set.slotHeight - height);
    ctx.drawImage(
      sheet,
      sourceX,
      sourceY,
      width,
      height,
      x + offsetX,
      destY,
      width,
      height,
    );
    offsetX += width;
  }
}

function drawCaveEdgeStrip(ctx, scrollCameraX, baseY, edgeName) {
  const edgeSet = currentZoneEdgeSet();
  const edge = edgeSet?.[edgeName];
  if (!edge?.src) return;

  const y = Math.round(baseY + (edge.yOffsetFromBase ?? 0));
  const clipTop = edgeName === "bottom"
    ? Math.max(0, Math.round(baseY + (edge.clipTopOffsetFromBase ?? 0)))
    : 0;
  const clipBottom = edgeName === "top"
    ? Math.min(state.stageHeight, Math.round(baseY + (edge.clipBottomOffsetFromBase ?? 0)))
    : state.stageHeight;

  if (clipBottom <= clipTop) return;
  drawRepeatingCaveEdge(ctx, edge, scrollCameraX, y, clipTop, clipBottom);
}

function drawRepeatingCaveEdge(ctx, edge, scrollCameraX, y, clipTop = 0, clipBottom = state.stageHeight) {
  if (!edge?.src) return false;
  const image = cachedImage(edge.src);
  if (!image) return false;

  const width = image.naturalWidth || image.width;
  const height = image.naturalHeight || image.height;
  if (!width || !height) return false;

  const scroll = positiveModulo(scrollCameraX * (edge.scrollRatio ?? 1), width);
  const startX = Math.floor(-scroll) - width;

  ctx.save();
  ctx.beginPath();
  ctx.rect(0, clipTop, state.stageWidth, clipBottom - clipTop);
  ctx.clip();
  for (let x = startX; x < state.stageWidth + width; x += width) {
    ctx.drawImage(image, Math.round(x), y, width, height);
  }
  ctx.restore();
  return true;
}

function drawBackdropGradient(ctx) {
  if (currentBackdropKind() === "cave") {
    const cave = ctx.createLinearGradient(0, 0, 0, state.stageHeight);
    cave.addColorStop(0, "#030303");
    cave.addColorStop(0.42, "#080706");
    cave.addColorStop(0.45, "#0d0a08");
    cave.addColorStop(1, "#17110c");
    ctx.fillStyle = cave;
    ctx.fillRect(0, 0, state.stageWidth, state.stageHeight);
    return;
  }

  const sky = ctx.createLinearGradient(0, 0, 0, state.stageHeight);
  sky.addColorStop(0, "#0b100e");
  sky.addColorStop(0.44, "#111814");
  sky.addColorStop(0.45, "#15150f");
  sky.addColorStop(1, "#191611");
  ctx.fillStyle = sky;
  ctx.fillRect(0, 0, state.stageWidth, state.stageHeight);
}

function redThunderZumaDragonLightningLayer() {
  return state.mapLightningAtlas?.layers?.[0] ?? null;
}

function redThunderZumaLightningFrameIndex(strike, layer, now) {
  const variantFrames = Math.max(1, Math.trunc(Number(state.mapLightningAtlas?.variantFrameCount) || 5));
  const variantIndex = Math.max(0, Math.min(2, Math.trunc(Number(strike.variantIndex) || 0)));
  const startedAt = Number(strike.startedAt) || now;
  const vfxStart = startedAt + RED_THUNDER_ZUMA_LIGHTNING_DELAY_MS;
  const age = now - vfxStart;
  if (age < 0 || age >= RED_THUNDER_ZUMA_LIGHTNING_DURATION_MS) return -1;
  const interval = RED_THUNDER_ZUMA_LIGHTNING_FRAME_MS;
  const localFrame = Math.min(variantFrames - 1, Math.floor(age / interval));
  return variantIndex * variantFrames + localFrame;
}

function drawSwarmEnemyRangeProjectileCanvas(ctx) {
  if (!groupDungeonSwarmSideActive()) return;
  for (const enemy of state.battle.swarm?.enemies ?? []) {
    const strike = enemy.pendingStrike;
    if (!strike?.ranged) continue;
    const now = performance.now();
    const startedAt = Number(strike.startedAt) || now;
    const vfxUntil = Number(strike.vfxUntil) || strike.at;
    if (now > vfxUntil) continue;
    const targetAnchor = bossPartyCombatTargetAnchor(strike.target);

    const dragonLayer = isRedThunderZumaSwarmEnemy(enemy) ? redThunderZumaDragonLightningLayer() : null;
    if (dragonLayer?.frames?.length) {
      const frameIndex = redThunderZumaLightningFrameIndex(strike, dragonLayer, now);
      if (frameIndex >= 0) {
        withScreenBlend(ctx, () => {
          drawSpellLayerCanvas(ctx, MAP_LIGHTNING_FX_ID, dragonLayer, frameIndex, targetAnchor.x, targetAnchor.y);
        });
      }
      continue;
    }

    const atlas = enemy.atlas;
    const projectile = atlas?.projectile;
    if (!projectile?.frames?.length) continue;
    const sheet = cachedImage(monsterAtlasPngUrl(enemy.monsterIndex));
    if (!sheet) continue;
    const style = projectile.style ?? "targetBurst";
    const slotWidth = projectile.slotWidth ?? atlas.slotWidth;
    const slotHeight = projectile.slotHeight ?? atlas.slotHeight;

    if (style === "travel") {
      const moveDurationMs = Math.max(1, Number(strike.moveDurationMs) || (strike.at - startedAt));
      if (now < startedAt || now > vfxUntil) continue;
      const origin = {
        x: Number(strike.originX),
        y: Number(strike.originY),
      };
      const end = (isZumaArcherSwarmEnemy(enemy) && strike.target)
        ? zumaArcherProjectileTargetAnchor(strike.target)
        : {
          x: Number.isFinite(Number(strike.targetAnchorX)) ? Number(strike.targetAnchorX) : targetAnchor.x,
          y: Number.isFinite(Number(strike.targetAnchorY)) ? Number(strike.targetAnchorY) : targetAnchor.y,
        };
      if (!Number.isFinite(origin.x) || !Number.isFinite(origin.y)) {
        const anchor = swarmEnemyScreenAnchor(enemy);
        const fallback = swarmEnemyRangedProjectileOrigin(enemy, anchor);
        origin.x = fallback.x;
        origin.y = fallback.y;
      }
      const travelT = Math.min(1, Math.max(0, (now - startedAt) / moveDurationMs));
      const x = origin.x + (end.x - origin.x) * travelT;
      const y = origin.y + (end.y - origin.y) * travelT;
      const useRotation = projectile.rotate !== false;
      if (useRotation) {
        const baseFrame = travelProjectileBaseFrame(projectile);
        if (!baseFrame || baseFrame.empty) continue;
        const baseAngleDeg = Number(projectile.baseAngleDeg);
        const baseAngleRad = Number.isFinite(baseAngleDeg)
          ? (baseAngleDeg * Math.PI) / 180
          : (97 * Math.PI) / 180;
        const angleRad = travelProjectileAngleRad(origin.x, origin.y, end.x, end.y, baseAngleRad);
        // Zuma arrow: pivot on the sprite centre so the body lands on the target, not the tail.
        const pivot = isZumaArcherSwarmEnemy(enemy) ? "center" : "anchor";
        drawRotatedAtlasSprite(ctx, sheet, slotWidth, slotHeight, baseFrame, x, y, angleRad, 1, pivot);
      } else {
        const meta = travelProjectileFrameMeta(projectile, origin.x, origin.y, end.x, end.y);
        if (!meta || meta.empty) continue;
        drawAtlasFrame(
          ctx,
          sheet,
          slotWidth,
          slotHeight,
          { ...meta, offsetX: meta.offsetX + x, offsetY: meta.offsetY + y },
          0,
          0,
        );
      }
      continue;
    }

    if (style !== "targetBurst") continue;
    const burstDurationMs = Math.max(1, Number(projectile.burstDurationMs) || 300);
    const burstDelayMs = Number(projectile.burstDelayMs);
    const burstStartAt = Number.isFinite(burstDelayMs)
      ? startedAt + Math.max(0, burstDelayMs)
      : strike.at - burstDurationMs;
    const burstEndAt = Number.isFinite(burstDelayMs)
      ? (Number(strike.vfxUntil) || burstStartAt + burstDurationMs)
      : strike.at;
    if (now < burstStartAt || now > burstEndAt) continue;
    const frameIndex = Math.min(
      projectile.frames.length - 1,
      Math.floor((now - burstStartAt) / Math.max(1, projectile.interval ?? 60)),
    );
    const meta = projectile.frames[frameIndex] ?? projectile.frames[0];
    if (!meta || meta.empty) continue;
    const frameSlotWidth = projectile.frameSlotWidth ?? slotWidth;
    const frameSlotHeight = projectile.frameSlotHeight ?? slotHeight;
    withScreenBlend(ctx, () => {
      drawAtlasFrame(
        ctx,
        sheet,
        frameSlotWidth,
        frameSlotHeight,
        { ...meta, offsetX: meta.offsetX + targetAnchor.x, offsetY: meta.offsetY + targetAnchor.y },
        0,
        0,
      );
    });
  }
}

function drawGroupDungeonSwarmEnemyCanvas(ctx, enemy) {
  if (!state.showEnemies || !enemy) return;
  const atlas = enemy.atlas;
  const clip = atlas?.actions?.[enemy.action];
  const meta = clip?.frames?.[enemy.frame] ?? clip?.frames?.[0];
  if (!atlas || !clip || !meta || meta.empty) return;
  const sheet = cachedImage(monsterAtlasPngUrl(enemy.monsterIndex));
  if (!sheet) return;
  const { x: anchorX, y: anchorY } = swarmEnemyScreenAnchor(enemy);
  drawAtlasFrame(ctx, sheet, atlas.slotWidth, atlas.slotHeight, meta, anchorX, anchorY);
  drawEnemyActionBlendCanvas(ctx, atlas, sheet, anchorX, anchorY, enemy.action, enemy.frame);
  drawEnemyDebuffTintCanvas(ctx, atlas, sheet, anchorX, anchorY, enemy.action, enemy.frame, enemyDebuffTint(enemy));
}

function drawEnemyCanvas(ctx) {
  if (!state.showEnemies) return;
  if (groupDungeonSwarmActive()) return;
  if (!state.battle.enemyRevealed && state.enemy.action !== "show") return;
  const atlas = state.enemy.atlas;
  const clip = atlas?.actions?.[state.enemy.action];
  const meta = clip?.frames?.[state.enemy.frame] ?? clip?.frames?.[0];
  if (!atlas || !clip || !meta || meta.empty) return;
  const sheet = cachedImage(monsterAtlasPngUrl(state.enemy.index));
  if (!sheet) return;
  const { x: anchorX, y: anchorY } = enemyVisualAnchor();
  drawAtlasFrame(ctx, sheet, atlas.slotWidth, atlas.slotHeight, meta, anchorX, anchorY);
  drawEnemyActionBlendCanvas(ctx, atlas, sheet, anchorX, anchorY, state.enemy.action, state.enemy.frame);
  drawEnemyDebuffTintCanvas(ctx, atlas, sheet, anchorX, anchorY, state.enemy.action, state.enemy.frame, enemyDebuffTint(state.battle.enemy));
}

function enemyActionBlendKey(action) {
  if (action === "standing") return "standingBlend";
  if (action === "walking") return "walkingBlend";
  if (action === "attack1") return "attack1Blend";
  if (action === "attackRange1") return "attackRange1Blend";
  if (action === "die") return "dieBlend";
  return null;
}

function drawEnemyActionBlendCanvas(ctx, atlas, sheet, anchorX, anchorY, action, frame) {
  const blendKey = enemyActionBlendKey(action);
  const blendClip = blendKey ? atlas?.actions?.[blendKey] : null;
  if (!blendClip?.frames?.length) return;
  // Death blend is a one-shot overlay; clamping to the last frame leaves it stuck on the corpse.
  if (action === "die" && frame >= blendClip.frames.length) return;
  const frameIndex = Math.max(0, Math.min(frame, blendClip.frames.length - 1));
  const blendMeta = blendClip.frames[frameIndex];
  if (!blendMeta || blendMeta.empty) return;
  withScreenBlend(ctx, () => {
    drawAtlasFrame(ctx, sheet, atlas.slotWidth, atlas.slotHeight, blendMeta, anchorX, anchorY);
  });
}

function enemyDebuffTint(enemy, now = performance.now()) {
  if (!enemy || enemy.hp <= 0) return null;
  if (enemyFrozenActive(enemy, now)) return { color: "#3b6dff", alpha: 0.5 };
  if (enemySlowActive(enemy, now)) return { color: "#7b3fd1", alpha: 0.42 };
  return null;
}

function drawEnemyDebuffTintCanvas(ctx, atlas, sheet, anchorX, anchorY, action, frame, tint) {
  if (!tint) return;
  const clip = atlas?.actions?.[action];
  const meta = clip?.frames?.[frame] ?? clip?.frames?.[0];
  if (meta && !meta.empty) drawAtlasFrameTint(ctx, sheet, atlas.slotWidth, atlas.slotHeight, meta, anchorX, anchorY, tint);
  const blendKey = enemyActionBlendKey(action);
  const blendClip = blendKey ? atlas?.actions?.[blendKey] : null;
  if (!blendClip?.frames?.length) return;
  if (action === "die" && frame >= blendClip.frames.length) return;
  const frameIndex = Math.max(0, Math.min(frame, blendClip.frames.length - 1));
  const blendMeta = blendClip.frames[frameIndex];
  if (blendMeta && !blendMeta.empty) drawAtlasFrameTint(ctx, sheet, atlas.slotWidth, atlas.slotHeight, blendMeta, anchorX, anchorY, tint);
}

function enemyProjectileVfxUntil(startedAt, projectile) {
  if (!projectile?.frames?.length) return startedAt + 600;
  const burstDelayMs = Math.max(0, Number(projectile.burstDelayMs) || 0);
  const burstDurationMs = Math.max(1, Number(projectile.burstDurationMs) || 300);
  const interval = Math.max(1, Number(projectile.interval) || 60);
  const animMs = projectile.frames.length * interval;
  return startedAt + burstDelayMs + Math.max(burstDurationMs, animMs);
}

function enemyProjectileBurstAnchor(projectile, strike) {
  if (projectile?.anchor === "boss" || strike?.kind === "massBurst" || strike?.kind === "scalyStomp" || strike?.kind === "darkDevilBurst") {
    return combatAnchor("enemy");
  }
  return boneLordProjectileTargetAnchor();
}

function strikeShowsEnemyProjectileVfx(strike = state.battle.pendingEnemyStrike) {
  if (!strike) return false;
  if (strike.kind === "kingScorpionLine") return Boolean(strike.ranged);
  if (strike.kind === "massBurst" || strike.kind === "scalyStomp" || strike.kind === "darkDevilBurst") return true;
  if (!strike.ranged) return false;
  if (isFlamingMutantEnemy(state.battle.enemy) && strike.aoe) return true;
  if (isMinotaurKingEnemy(state.battle.enemy)) return minotaurKingStrikeUsesAoe(strike);
  return enemyHasRangedMeleeAttack(state.battle.enemy);
}

function drawEnemyRangeProjectileCanvas(ctx) {
  const strike = state.battle.pendingEnemyStrike;
  if (!strike) return;
  if (strike.kind === "kingScorpionLine") {
    if (!strike.ranged) return;
    const atlas = state.enemy.atlas;
    const projectile = atlas?.projectile;
    if (!projectile?.frames?.length) return;
    const sheet = cachedImage(monsterAtlasPngUrl(state.enemy.index));
    if (!sheet) return;
    const now = performance.now();
    const startedAt = Number(strike.startedAt) || now;
    const projectileEndAt = startedAt + kingScorpionLineProjectileVfxMs(projectile);
    if (now < startedAt || now >= projectileEndAt) return;
    const lineTiles = Math.max(1, Math.trunc(Number(strike.lineTiles) || kingScorpionLineTileDistance()));
    const stretchX = lineTiles / KING_SCORPION_LINE_VFX_BASE_TILES;
    const frameIndex = Math.min(
      projectile.frames.length - 1,
      Math.floor((now - startedAt) / Math.max(1, (projectile.interval ?? 30) * KING_SCORPION_LINE_VFX_STRETCH)),
    );
    const meta = projectile.frames[frameIndex] ?? projectile.frames[0];
    if (!meta || meta.empty) return;
    const enemyAnchor = combatAnchor("enemy");
    const slotWidth = projectile.slotWidth ?? atlas.slotWidth;
    const slotHeight = projectile.slotHeight ?? atlas.slotHeight;
    const w = Math.max(1, Math.trunc(Number(meta.w) || slotWidth));
    const h = Math.max(1, Math.trunc(Number(meta.h) || slotHeight));
    const ox = Math.trunc(Number(meta.offsetX) || 0);
    const oy = Math.trunc(Number(meta.offsetY) || 0);
    const sx = Math.trunc(Number(meta.slot) || 0) * slotWidth;
    ctx.save();
    ctx.translate(enemyAnchor.x, enemyAnchor.y);
    ctx.scale(stretchX, 1);
    withScreenBlend(ctx, () => {
      ctx.drawImage(sheet, sx, 0, w, h, ox, oy, w, h);
    });
    ctx.restore();
    return;
  }
  if (!strikeShowsEnemyProjectileVfx(strike)) return;
  const atlas = state.enemy.atlas;
  const projectile = atlas?.projectile;
  if (!projectile?.frames?.length) return;
  const sheet = cachedImage(monsterAtlasPngUrl(state.enemy.index));
  if (!sheet) return;
  const now = performance.now();
  const startedAt = Number(strike.startedAt) || (strike.at - (strike.moveDurationMs ?? BONE_LORD_ATTACK_IMPACT_MS));
  const moveDurationMs = Math.max(1, Number(strike.moveDurationMs) || (strike.at - startedAt));
  const slotWidth = projectile.slotWidth ?? atlas.slotWidth;
  const slotHeight = projectile.slotHeight ?? atlas.slotHeight;
  const style = projectile.style ?? "travel";

  if (strike.kind === "darkDevilBurst") {
    if (!state.battle.enemy || (state.battle.enemy?.hp ?? 0) <= 0) return;
    const vfxUntil = Number(strike.vfxUntil) || startedAt + 600;
    if (now < startedAt || now > vfxUntil) return;
    const frameIndex = Math.min(
      projectile.frames.length - 1,
      Math.floor((now - startedAt) / Math.max(1, projectile.interval ?? 30)),
    );
    const meta = projectile.frames[frameIndex] ?? projectile.frames[0];
    if (!meta || meta.empty) return;
    const enemyAnchor = combatAnchor("enemy");
    const frameSlotWidth = projectile.frameSlotWidth ?? slotWidth;
    const frameSlotHeight = projectile.frameSlotHeight ?? slotHeight;
    withScreenBlend(ctx, () => {
      drawAtlasFrame(
        ctx,
        sheet,
        frameSlotWidth,
        frameSlotHeight,
        { ...meta, offsetX: meta.offsetX + enemyAnchor.x, offsetY: meta.offsetY + enemyAnchor.y },
        0,
        0,
      );
    });
    return;
  }

  if (style === "targetBurst") {
    if (isMinotaurKingEnemy() && !minotaurKingStrikeUsesAoe(strike)) return;
    const burstDurationMs = Math.max(1, Number(projectile.burstDurationMs) || 300);
    const burstDelayMs = Number(projectile.burstDelayMs);
    const burstStartAt = Number.isFinite(burstDelayMs)
      ? startedAt + Math.max(0, burstDelayMs)
      : strike.at - burstDurationMs;
    const burstEndAt = Number.isFinite(burstDelayMs)
      ? (Number(strike.vfxUntil) || burstStartAt + burstDurationMs)
      : strike.at;
    if (now < burstStartAt || now > burstEndAt) return;
    const frameIndex = Math.min(
      projectile.frames.length - 1,
      Math.floor((now - burstStartAt) / Math.max(1, projectile.interval ?? 60)),
    );
    const meta = projectile.frames[frameIndex] ?? projectile.frames[0];
    if (!meta || meta.empty) return;
    const targetAnchor = enemyProjectileBurstAnchor(projectile, strike);
    const frameSlotWidth = projectile.frameSlotWidth ?? slotWidth;
    const frameSlotHeight = projectile.frameSlotHeight ?? slotHeight;
    withScreenBlend(ctx, () => {
      drawAtlasFrame(
        ctx,
        sheet,
        frameSlotWidth,
        frameSlotHeight,
        { ...meta, offsetX: meta.offsetX + targetAnchor.x, offsetY: meta.offsetY + targetAnchor.y },
        0,
        0,
      );
    });
    return;
  }

  if (now < startedAt || now > strike.at) return;
  const travelT = Math.min(1, Math.max(0, (now - startedAt) / moveDurationMs));
  const frameIndex = Math.min(
    projectile.frames.length - 1,
    Math.floor((now - startedAt) / Math.max(1, projectile.interval ?? 30)) % projectile.frames.length,
  );
  const meta = projectile.frames[frameIndex] ?? projectile.frames[0];
  if (!meta || meta.empty) return;
  const enemyAnchor = combatAnchor("enemy");
  const targetAnchor = boneLordProjectileTargetAnchor();
  const x = enemyAnchor.x + (targetAnchor.x - enemyAnchor.x) * travelT;
  const y = enemyAnchor.y + (targetAnchor.y - enemyAnchor.y) * travelT;
  withScreenBlend(ctx, () => {
    drawAtlasFrame(
      ctx,
      sheet,
      slotWidth,
      slotHeight,
      { ...meta, offsetX: meta.offsetX + x, offsetY: meta.offsetY + y },
      0,
      0,
    );
  });
}

function drawEnemyAttackBlendCanvas(ctx, atlas, sheet, anchorX, anchorY) {
  drawEnemyActionBlendCanvas(ctx, atlas, sheet, anchorX, anchorY, "attack1", state.enemy.frame);
}

function drawTaoistPetCanvas(ctx) {
  const pet = state.battle.taoPet;
  if (!state.showEnemies || !pet || (!pet.active && !pet.dead)) return;
  const atlas = taoPetAtlasFor(pet);
  const clip = atlas?.actions?.[pet.action];
  const meta = clip?.frames?.[pet.frame] ?? clip?.frames?.[0];
  if (!atlas || !clip || !meta || meta.empty) return;
  const sheet = cachedImage(`./public/monsters/monster/${taoistPetRenderMonsterIndex(pet)}.png`);
  if (!sheet) return;
  const { x: anchorX, y: anchorY } = taoistPetAnchor();
  drawAtlasFrame(ctx, sheet, atlas.slotWidth, atlas.slotHeight, meta, anchorX, anchorY);
  if (pet.spellId === "SummonShinsu" && pet.shinsuVisible && pet.action === "attack1") {
    const breathFrame = pet.frame - CRYSTAL_SHINSU_ATTACK_IMPACT_FRAME;
    if (breathFrame >= 0) {
      drawEnemyActionBlendCanvas(ctx, atlas, sheet, anchorX, anchorY, "attack1", breathFrame);
    }
  }
}

function taoistPetAnchor() {
  const pet = state.battle.taoPet;
  if (pet) {
    return {
      x: Math.round(resolvedTaoPetWorldX(pet) - state.battle.cameraX),
      y: Math.round(state.stageHeight * LANE.y + 2),
    };
  }
  const enemyAnchor = combatAnchor("enemy");
  return {
    x: Math.round(enemyAnchor.x + 54),
    y: Math.round(enemyAnchor.y + 2),
  };
}

function drawUnitHealthBar(ctx, bounds, hp, maxHp) {
  const width = 30;
  const height = 4;
  const x = Math.round(bounds.centerX - width / 2);
  const y = Math.round(bounds.topY - 9);
  const pct = Math.max(0, Math.min(1, hp / Math.max(1, maxHp)));

  ctx.save();
  ctx.fillStyle = "rgba(0, 0, 0, 0.72)";
  ctx.fillRect(x - 1, y - 1, width + 2, height + 2);
  ctx.fillStyle = "#3b1513";
  ctx.fillRect(x, y, width, height);
  ctx.fillStyle = "#a82622";
  ctx.fillRect(x, y, Math.round(width * pct), height);
  ctx.strokeStyle = "rgba(255, 226, 198, 0.45)";
  ctx.lineWidth = 1;
  ctx.strokeRect(x - 0.5, y - 0.5, width + 1, height + 1);
  ctx.restore();
}

function drawGroupDungeonSwarmHealthBars(ctx) {
  const swarm = state.battle.swarm;
  if (!swarm?.enemies?.length) return;
  for (const enemy of swarm.enemies) {
    if (enemy.dying || enemy.hp <= 0 || enemy.hp >= enemy.maxHp) continue;
    drawUnitHealthBar(ctx, swarmEnemyFrameBounds(enemy), enemy.hp, enemy.maxHp);
  }
}

function drawEnemyHealthBar(ctx) {
  if (!state.showEnemies || !state.battle.enemyRevealed) return;
  if (!state.battle.running && state.battle.phase === "idle") return;
  if (groupDungeonSwarmActive()) {
    drawGroupDungeonSwarmHealthBars(ctx);
    return;
  }
  if (groupDungeonBossReinforcementsActive()) {
    drawGroupDungeonSwarmHealthBars(ctx);
  }
  if (!state.battle.enemy || state.battle.enemy.hp <= 0) return;
  drawUnitHealthBar(ctx, enemyFrameBounds(), state.battle.enemy.hp, state.battle.enemy.maxHp);
}

function drawTaoistPetHealthBar(ctx) {
  const pet = state.battle.taoPet;
  if (!state.showEnemies || !pet?.active || pet.hp <= 0) return;
  if (!state.battle.running && state.battle.phase === "idle") return;
  const bounds = taoistPetFrameBounds();
  const width = 30;
  const height = 4;
  const x = Math.round(bounds.centerX - width / 2);
  const y = Math.round(bounds.topY - 9);
  const pct = Math.max(0, Math.min(1, pet.hp / Math.max(1, pet.maxHp)));

  ctx.save();
  ctx.fillStyle = "rgba(0, 0, 0, 0.72)";
  ctx.fillRect(x - 1, y - 1, width + 2, height + 2);
  ctx.fillStyle = "#1d2d1c";
  ctx.fillRect(x, y, width, height);
  ctx.fillStyle = "#4fa34d";
  ctx.fillRect(x, y, Math.round(width * pct), height);
  ctx.strokeStyle = "rgba(221, 245, 201, 0.45)";
  ctx.lineWidth = 1;
  ctx.strokeRect(x - 0.5, y - 0.5, width + 1, height + 1);
  ctx.restore();
}

function drawEnemyPoisonDots(ctx) {
  const enemy = state.battle.enemy;
  const poisons = Array.isArray(enemy?.poisons) ? enemy.poisons.filter((poison) => (Number(poison.ticksRemaining) || 0) > 0) : [];
  if (!state.showEnemies || !enemy || enemy.hp <= 0 || !poisons.length) return;
  const bounds = enemyFrameBounds();
  const size = 4;
  const gap = 3;
  const totalWidth = poisons.length * size + (poisons.length - 1) * gap;
  let x = Math.round(bounds.centerX - totalWidth / 2);
  const y = Math.round(bounds.topY - 18);

  ctx.save();
  for (const poison of poisons) {
    ctx.fillStyle = "rgba(0, 0, 0, 0.72)";
    ctx.fillRect(x - 1, y - 1, size + 2, size + 2);
    ctx.fillStyle = poison.kind === "green" ? "#35b457" : "#d8b54f";
    ctx.fillRect(x, y, size, size);
    x += size + gap;
  }
  ctx.restore();
}

function swarmEnemyFrameBounds(enemy) {
  const { x: anchorX, y: anchorY } = swarmEnemyScreenAnchor(enemy);
  const atlas = enemy.atlas ?? state.enemy.atlas;
  const clip = atlas?.actions?.[enemy.action];
  const meta = clip?.frames?.[enemy.frame] ?? clip?.frames?.[0];
  if (!atlas || !meta || meta.empty) {
    return { centerX: anchorX, topY: anchorY - 64, width: 96, height: 112 };
  }
  const width = meta.w || atlas.slotWidth;
  const height = meta.h || atlas.slotHeight;
  return {
    centerX: anchorX + meta.offsetX + width / 2,
    topY: anchorY + meta.offsetY,
    width,
    height,
  };
}

function enemyFrameBounds() {
  if (groupDungeonSwarmActive()) {
    const primary = groupDungeonPrimarySwarmEnemy();
    if (primary) return swarmEnemyFrameBounds(primary);
  }
  const anchor = combatAnchor("enemy");
  const atlas = state.enemy.atlas;
  const clip = atlas?.actions?.[state.enemy.action];
  const meta = clip?.frames?.[state.enemy.frame] ?? clip?.frames?.[0];
  if (!atlas || !meta || meta.empty) {
    return { centerX: anchor.x, topY: anchor.y - 64, width: 96, height: 112 };
  }
  const width = meta.w || atlas.slotWidth;
  const height = meta.h || atlas.slotHeight;
  return {
    centerX: anchor.x + meta.offsetX + width / 2,
    topY: anchor.y + meta.offsetY,
    width,
    height,
  };
}

function drawPlayerCanvas(ctx, displayFrame) {
  const { x: anchorX, y: anchorY } = combatAnchor("player");
  for (const layer of layerNames()) {
    const atlas = state.atlases[layer];
    const index = state.indexes[layer];
    const clip = atlas?.actions?.[state.action];
    const meta = clip?.frames?.[displayFrame] ?? clip?.frames?.[0];
    if (!atlas || !clip || !meta || meta.empty) continue;
    const sheet = cachedImage(sheetUrl(state.spriteSet, layer, index));
    if (!sheet) continue;
    drawAtlasFrame(ctx, sheet, atlas.slotWidth, atlas.slotHeight, meta, anchorX, anchorY);
  }
}

function drawBossPartyCharacters(ctx) {
  drawBossPartyDeadMembers(ctx);
  drawBossPartyLivingMembers(ctx);
}

function bossPartyMembersByDepth(members, { living = null } = {}) {
  return [...members]
    .filter((member) => {
      const isLiving = member.alive && member.hp > 0;
      if (living === true) return isLiving;
      if (living === false) return !isLiving;
      return true;
    })
    .sort((a, b) => (a.worldX ?? 0) - (b.worldX ?? 0));
}

function drawBossPartyDeadMembers(ctx) {
  const party = state.battle.bossParty;
  if (!party?.members?.length) return;
  for (const member of bossPartyMembersByDepth(party.members, { living: false })) {
    drawBossPartyMemberCanvas(ctx, member);
  }
}

function drawBossPartyLivingMembers(ctx) {
  const party = state.battle.bossParty;
  if (!party?.members?.length) return;
  for (const member of bossPartyMembersByDepth(party.members, { living: true })) {
    drawBossPartyMemberCanvas(ctx, member);
  }
}

// Renders assist members' spell FX at their own position. The character you control
// is already drawn by drawCombat*FxCanvas off the battle.active* fields.
function drawBossPartySpellFxCanvas(ctx) {
  const party = state.battle.bossParty;
  if (!party?.members?.length) return;
  const now = performance.now();
  for (const member of party.members) {
    if (member.classId === bossPartyControlledClassId()) continue;
    drawBossPartyMemberSpellFx(ctx, member, now);
  }
}

function drawBossPartyMemberSpellFx(ctx, member, now) {
  const spellId = member.fxSpellId;
  if (!spellId) return;

  if (member.classId === "Warrior") {
    const atlas = state.warriorSkillAtlases[spellId];
    const skill = warriorCombatSkill(spellId);
    if (!atlas?.layers?.length || !member.visualOneShot) {
      if (!member.visualOneShot) member.fxSpellId = null;
      return;
    }
    if (member.visualAction !== skill.bodyAction) return;
    const memberAnchor = {
      x: Math.floor((member.worldX ?? state.battle.playerX) - state.battle.cameraX),
      y: Math.floor(state.stageHeight * LANE.y),
    };
    const layers = warriorSkillFxLayers(spellId, "swing");
    const fxStartedAt = member.fxStartedAt ?? now;
    withScreenBlend(ctx, () => {
      for (const layer of layers) {
        const frameIndex = spellFxLayerFrameIndex(layer, fxStartedAt, now);
        if (frameIndex < 0) {
          member.fxSpellId = null;
          continue;
        }
        drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, memberAnchor.x, memberAnchor.y);
      }
    });
    return;
  }

  const atlas = member.classId === "Wizard"
    ? state.wizardSpellAtlases[spellId]
    : member.classId === "Taoist" ? state.taoistSpellAtlases[spellId] : null;
  const spell = member.classId === "Wizard" ? wizardCombatSpell(spellId)
    : member.classId === "Taoist" ? taoistCombatSpell(spellId) : null;
  if (!atlas || !spell) return;
  const t = now - (member.fxStartedAt ?? 0);
  const hitAt = wizardImpactDelay(spell, atlas);
  const layerEnd = Math.max(0, ...atlas.layers.map((layer) => (layer.delayMs ?? 0) + layer.frames.length * layer.interval));
  const total = Math.max(layerEnd, spell.impactMode === "projectile" ? hitAt + (spell.impactFlashMs ?? 250) : 0);
  if (t < 0 || t > total) {
    member.fxSpellId = null;
    return;
  }
  const memberAnchor = {
    x: Math.floor((member.worldX ?? state.battle.playerX) - state.battle.cameraX),
    y: Math.floor(state.stageHeight * LANE.y),
  };
  const enemyAnchor = spell?.impactMode === "bang"
    ? wizardBangSpellAnchorFromCenter(member.fxCenterTile, combatAnchor("enemy"))
    : combatAnchor("enemy");
  const fxAnchor = spell.effectAnchor === "enemy" ? enemyAnchor : memberAnchor;
  withScreenBlend(ctx, () => {
    for (const layer of atlas.layers) {
      const layerDelay = layer.delayMs ?? 0;
      const layerT = t - layerDelay;
      const duration = layer.frames.length * layer.interval;
      if (layerT < 0 || layerT > duration) continue;
      const layerAnchor = wizardSpellFxLayerAnchor(spell, layer, memberAnchor, enemyAnchor);
      const frameIndex = Math.min(layer.frames.length - 1, Math.floor(layerT / layer.interval));
      drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, layerAnchor.x, layerAnchor.y);
    }
    if (spell.impactMode === "projectile") drawCombatProjectileCanvas(ctx, atlas, t, memberAnchor, enemyAnchor, hitAt);
    if (spell.impactMode === "projectile" && t >= hitAt && t <= hitAt + (spell.impactFlashMs ?? 250)) {
      drawImpactFlashCanvas(ctx, atlas, t - hitAt, enemyAnchor);
    }
  });
}

// Render the Crystal heal-restore burst (Magic frame 370) on the body of whoever is
// being healed (member or pet) when the heal lands. The casting Taoist still shows
// the cast swirl (frame 200) via bossPartyControlledVisual.
function drawBossPartyHealFxCanvas(ctx) {
  const fx = partyBossHealFx();
  if (!fx.length) return;
  const atlas = state.healingRestoreAtlas;
  if (!atlas?.layers?.length) return;
  const now = performance.now();
  const groundY = Math.floor(state.stageHeight * LANE.y);
  for (const entry of fx) {
    const target = entry.target;
    if (!target) continue;
    const t = now - (entry.startAt ?? 0);
    if (t < 0) continue;
    const worldX = target.worldX ?? state.battle.playerX;
    const anchorX = Math.floor(worldX - state.battle.cameraX);
    withScreenBlend(ctx, () => {
      for (const layer of atlas.layers) {
        const layerT = t - (layer.delayMs ?? 0);
        const duration = layer.frames.length * layer.interval;
        if (layerT < 0 || layerT > duration) continue;
        const frameIndex = Math.min(layer.frames.length - 1, Math.floor(layerT / layer.interval));
        drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, anchorX, groundY);
      }
    });
  }
}

function drawBossPartyMemberCanvas(ctx, member) {
  const action = member.visualAction ?? (member.alive ? "stance" : "die");
  const anchorX = Math.round((member.worldX ?? state.battle.playerX) - state.battle.cameraX);
  const anchorY = Math.floor(state.stageHeight * LANE.y);
  for (const layer of layerNames()) {
    const index = member.visualIndexes?.[layer];
    if (index == null || index === "") continue;
    const atlas = member.visualAtlases?.[layer] ?? (member.classId === bossPartyControlledClassId() ? state.atlases[layer] : null);
    const clip = atlas?.actions?.[action] ?? atlas?.actions?.stance ?? atlas?.actions?.standing;
    const frameIndex = Math.max(0, Math.min(member.visualFrame ?? 0, (clip?.frames?.length ?? 1) - 1));
    const meta = clip?.frames?.[frameIndex] ?? clip?.frames?.[0];
    if (!atlas || !clip || !meta || meta.empty) continue;
    const sheet = cachedImage(sheetUrl(state.spriteSet, layer, index));
    if (!sheet) continue;
    drawAtlasFrame(ctx, sheet, atlas.slotWidth, atlas.slotHeight, meta, anchorX, anchorY);
  }
}

function drawAtlasFrame(ctx, sheet, slotWidth, slotHeight, meta, anchorX, anchorY, scale = 1) {
  const drawScale = Math.max(0.1, Number(scale) || 1);
  ctx.drawImage(
    sheet,
    meta.slot * slotWidth,
    0,
    slotWidth,
    slotHeight,
    anchorX + meta.offsetX * drawScale,
    anchorY + meta.offsetY * drawScale,
    slotWidth * drawScale,
    slotHeight * drawScale,
  );
}

let atlasTintScratchCanvas = null;
let atlasTintScratchCtx = null;

function drawAtlasFrameTint(ctx, sheet, slotWidth, slotHeight, meta, anchorX, anchorY, tint, scale = 1) {
  if (!tint || !sheet || !meta || meta.empty) return;
  const drawScale = Math.max(0.1, Number(scale) || 1);
  const w = Math.max(1, Math.trunc(Number(slotWidth) || 1));
  const h = Math.max(1, Math.trunc(Number(slotHeight) || 1));
  if (!atlasTintScratchCanvas) {
    atlasTintScratchCanvas = document.createElement("canvas");
    atlasTintScratchCtx = atlasTintScratchCanvas.getContext("2d");
  }
  if (!atlasTintScratchCtx) return;
  if (atlasTintScratchCanvas.width !== w || atlasTintScratchCanvas.height !== h) {
    atlasTintScratchCanvas.width = w;
    atlasTintScratchCanvas.height = h;
  }
  atlasTintScratchCtx.clearRect(0, 0, w, h);
  atlasTintScratchCtx.globalCompositeOperation = "source-over";
  atlasTintScratchCtx.globalAlpha = 1;
  atlasTintScratchCtx.drawImage(sheet, meta.slot * slotWidth, 0, slotWidth, slotHeight, 0, 0, w, h);
  atlasTintScratchCtx.globalCompositeOperation = "source-atop";
  atlasTintScratchCtx.fillStyle = tint.color;
  atlasTintScratchCtx.fillRect(0, 0, w, h);
  atlasTintScratchCtx.globalCompositeOperation = "source-over";

  ctx.save();
  ctx.globalAlpha = Math.max(0, Math.min(1, Number(tint.alpha) || 0.42));
  ctx.drawImage(
    atlasTintScratchCanvas,
    anchorX + meta.offsetX * drawScale,
    anchorY + meta.offsetY * drawScale,
    slotWidth * drawScale,
    slotHeight * drawScale,
  );
  ctx.restore();
}

/**
 * Draw a compact atlas sprite rotated to an exact screen angle.
 * pivot "anchor" (default): rotate around the lib offset / tail.
 * pivot "center": rotate around the sprite centre so (anchorX, anchorY) is the body centre.
 */
function drawRotatedAtlasSprite(ctx, sheet, slotWidth, slotHeight, meta, anchorX, anchorY, angleRad, scale = 1, pivot = "anchor") {
  if (!meta || meta.empty || !sheet) return;
  const drawScale = Math.max(0.1, Number(scale) || 1);
  const w = Math.max(1, Math.trunc(Number(meta.w) || slotWidth));
  const h = Math.max(1, Math.trunc(Number(meta.h) || slotHeight));
  const ox = Math.trunc(Number(meta.offsetX) || 0);
  const oy = Math.trunc(Number(meta.offsetY) || 0);
  const sx = Math.trunc(Number(meta.slot) || 0) * slotWidth;
  const drawX = pivot === "center" ? -(w * drawScale) / 2 : ox * drawScale;
  const drawY = pivot === "center" ? -(h * drawScale) / 2 : oy * drawScale;
  ctx.save();
  ctx.translate(anchorX, anchorY);
  ctx.rotate(angleRad);
  ctx.drawImage(
    sheet,
    sx,
    0,
    w,
    h,
    drawX,
    drawY,
    w * drawScale,
    h * drawScale,
  );
  ctx.restore();
}

function drawSpellFxCanvas(ctx, bodyFrame, bodyFrameCount) {
  const atlas = state.spellAtlas;
  if (!atlas) return;
  const { x: anchorX, y: anchorY } = combatAnchor("player");
  const now = performance.now();
  const durations = atlas.layers.map((layer) => layer.frames.length * layer.interval);
  if (atlas.projectile) durations.push(atlas.projectile.delayMs + atlas.projectile.moveDurationMs);
  const spellDriven = state.syncBodyToSpell && state.spell !== "None";
  const bodyMs = bodyFrameCount * (currentClip()?.interval ?? 100);
  const cycleMs = spellDriven ? Math.max(bodyMs, ...durations) + state.castCooldownMs : Math.max(1, ...durations);
  const t = (now - state.spellStartedAt) % cycleMs;
  if (spellDriven && t >= cycleMs - state.castCooldownMs) return;

  withScreenBlend(ctx, () => {
    for (const layer of atlas.layers) {
      const frameIndex =
        state.syncBodyToSpell && layer.frames.length === bodyFrameCount
          ? Math.min(layer.frames.length - 1, bodyFrame)
          : Math.min(layer.frames.length - 1, Math.floor(t / layer.interval));
      drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, anchorX, anchorY);
    }
    if (atlas.projectile) drawProjectileCanvas(ctx, atlas, t, anchorX, anchorY);
  });
}

function drawTwinDrakeReadyFxCanvas(ctx) {
  const atlas = state.warriorSkillAtlases.TwinDrakeBlade;
  const chargeLayer = warriorSkillFxLayers("TwinDrakeBlade", "charge")[0];
  const now = performance.now();
  const entries = twinDrakeChargeFxEntries(now);
  if (!atlas || !chargeLayer?.frames?.length || !entries.length) return;

  withScreenBlend(ctx, () => {
    for (const entry of entries) {
      const frameIndex = spellFxLayerFrameIndex(chargeLayer, entry.startedAt, now);
      if (frameIndex < 0) continue;
      drawSpellLayerCanvas(ctx, atlas.spellId, chargeLayer, frameIndex, entry.anchor.x, entry.anchor.y);
    }
  });
}

function drawAttachedSpellFxCanvas(ctx) {
  const effects = state.battle.attachedSpellFx ?? [];
  if (!effects.length) return;
  const now = performance.now();
  withScreenBlend(ctx, () => {
    for (const entry of effects) {
      if (now < entry.startedAt || now > entry.expiresAt) continue;
      if (entry.spellId === "MagicShield") {
        drawMagicShieldLoopFxCanvas(ctx, entry, now);
        continue;
      }
      const atlas = state.warriorSkillAtlases[entry.spellId] ?? state.wizardSpellAtlases[entry.spellId] ?? state.taoistSpellAtlases[entry.spellId];
      if (!atlas?.layers?.length) continue;
      const layers = atlas.layers.slice(entry.layerStart, entry.layerEnd);
      if (!layers.length) continue;
      const { x: anchorX, y: anchorY } = attachedSpellFxAnchor(entry);
      for (const layer of layers) {
        const frameIndex = spellFxLayerFrameIndex(layer, entry.startedAt, now);
        if (frameIndex < 0) continue;
        drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, anchorX, anchorY);
      }
    }
  });
}

function drawMagicShieldLoopFxCanvas(ctx, entry, now) {
  const atlas = state.wizardSpellAtlases?.MagicShield;
  if (!atlas?.layers?.length) return;
  const { x: anchorX, y: anchorY } = attachedSpellFxAnchor(entry);
  const struckAt = Number(entry.struckAt) || 0;
  const struckLayer = atlas.layers[CRYSTAL_MAGIC_SHIELD_STRUCK_LAYER];
  if (struckAt > 0 && now - struckAt < CRYSTAL_MAGIC_SHIELD_STRUCK_MS && struckLayer) {
    const frameIndex = spellFxLayerFrameIndex(struckLayer, struckAt, now);
    if (frameIndex < 0) return;
    drawSpellLayerCanvas(ctx, atlas.spellId, struckLayer, frameIndex, anchorX, anchorY);
    return;
  }
  const loopLayer = atlas.layers[CRYSTAL_MAGIC_SHIELD_LOOP_LAYER];
  if (!loopLayer) return;
  const frameIndex = spellFxLoopFrameIndex(loopLayer, magicShieldLoopStartedAt(entry, now), now);
  if (frameIndex < 0) return;
  drawSpellLayerCanvas(ctx, atlas.spellId, loopLayer, frameIndex, anchorX, anchorY);
}

function drawCombatSkillFxCanvas(ctx) {
  const battle = state.battle;
  const atlas = battle.activeSkillAtlas;
  if (!atlas || !state.playerOneShot || battle.activeSkill === "None") return;
  if (state.action !== warriorCombatSkill(battle.activeSkill).bodyAction) return;
  const { x: anchorX, y: anchorY } = combatAnchor("player");
  const layers = warriorSkillFxLayers(battle.activeSkill, "swing");
  const now = performance.now();
  const startedAt = battle.activeSkillStartedAt ?? now;

  withScreenBlend(ctx, () => {
    for (const layer of layers) {
      const frameIndex = spellFxLayerFrameIndex(layer, startedAt, now);
      if (frameIndex < 0) continue;
      drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, anchorX, anchorY);
    }
  });
}

function drawCombatWizardFxCanvas(ctx) {
  const battle = state.battle;
  const atlas = battle.activeWizardSpellAtlas;
  if (!atlas || !battle.activeWizardSpell) return;
  const spell = wizardCombatSpell(battle.activeWizardSpell);
  const t = performance.now() - battle.activeWizardSpellStartedAt;
  const playerAnchor = combatAnchor("player");
  const enemyAnchor = combatAnchor("enemy");
  const spellEnemyAnchor = wizardCombatSpellEnemyAnchor(spell, enemyAnchor);
  const fxAnchor = spell.effectAnchor === "enemy" ? spellEnemyAnchor : playerAnchor;
  const buffCast = spell.impactMode === "buff";
  const projectileTarget = buffCast ? playerAnchor : spellEnemyAnchor;
  const hitAt = buffCast
    ? (Number(spell.impactDelayMs) || CRYSTAL_HEAL_APPLY_DELAY_MS)
    : wizardImpactDelay(spell, atlas);

  withScreenBlend(ctx, () => {
    const castLayers = battle.activeWizardSpell === "MagicShield"
      ? (atlas.layers ?? []).slice(0, CRYSTAL_MAGIC_SHIELD_CAST_LAYER_END)
      : atlas.layers;
    for (const layer of castLayers) {
      const layerDelay = layer.delayMs ?? 0;
      const layerT = t - layerDelay;
      const duration = layer.frames.length * layer.interval;
      if (layerT < 0 || layerT > duration) continue;
      const layerAnchor = wizardSpellFxLayerAnchor(spell, layer, playerAnchor, spellEnemyAnchor);
      const frameIndex = Math.min(layer.frames.length - 1, Math.floor(layerT / layer.interval));
      drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, layerAnchor.x, layerAnchor.y);
    }
    if (spell.impactMode === "projectile" || (buffCast && atlas.projectile)) {
      drawCombatProjectileCanvas(ctx, atlas, t, playerAnchor, projectileTarget, hitAt);
    }
    if (spell.impactMode === "projectile" && t >= hitAt && t <= hitAt + (spell.impactFlashMs ?? 250)) {
      drawImpactFlashCanvas(ctx, atlas, t - hitAt, enemyAnchor);
    }
  });
}

function drawCombatTaoistFxCanvas(ctx) {
  const battle = state.battle;
  const atlas = battle.activeTaoSpellAtlas;
  if (!atlas || !battle.activeTaoSpell) return;
  const spell = taoistCombatSpell(battle.activeTaoSpell);
  const t = performance.now() - battle.activeTaoSpellStartedAt;
  const playerAnchor = combatAnchor("player");
  const enemyAnchor = combatAnchor("enemy");
  const fxAnchor = spell.effectAnchor === "enemy" ? enemyAnchor : playerAnchor;
  const buffCast = spell.impactMode === "buff";
  const projectileTarget = buffCast ? playerAnchor : enemyAnchor;
  const hitAt = buffCast
    ? (Number(spell.impactDelayMs) || CRYSTAL_HEAL_APPLY_DELAY_MS)
    : wizardImpactDelay(spell, atlas);

  withScreenBlend(ctx, () => {
    for (const layer of atlas.layers) {
      const layerDelay = layer.delayMs ?? 0;
      const layerT = t - layerDelay;
      const duration = layer.frames.length * layer.interval;
      if (layerT < 0 || layerT > duration) continue;
      const layerAnchor = layer.anchor === "enemy" ? enemyAnchor : layer.anchor === "player" ? playerAnchor : fxAnchor;
      const frameIndex = Math.min(layer.frames.length - 1, Math.floor(layerT / layer.interval));
      drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, layerAnchor.x, layerAnchor.y);
    }
    if (spell.impactMode === "projectile" || (buffCast && atlas.projectile)) {
      drawCombatProjectileCanvas(ctx, atlas, t, playerAnchor, projectileTarget, hitAt);
    }
    if (spell.impactMode === "projectile" && t >= hitAt && t <= hitAt + (spell.impactFlashMs ?? 250)) {
      drawImpactFlashCanvas(ctx, atlas, t - hitAt, enemyAnchor);
    }
  });
}

function spellTargetCellAnchorY(anchorY = Math.floor(state.stageHeight * LANE.y)) {
  // Crystal map effects use TargetPoint * CellHeight (cell top), not the foot line we use for sprites.
  return anchorY - LANE_TILE_PX;
}
function wizardCombatSpellEnemyAnchor(spell, fallbackAnchor) {
  if (spell?.impactMode !== "bang") return fallbackAnchor;
  return wizardBangSpellAnchorFromCenter(state.battle.activeWizardSpellCenterTile, fallbackAnchor);
}

function wizardBangSpellAnchorFromCenter(centerTile, fallbackAnchor) {
  if (!centerTile || !Number.isFinite(Number(centerTile.worldX))) return fallbackAnchor;
  const mapRow = Math.trunc(Number(centerTile.mapRow) || arenaSpawnMapRow());
  return {
    x: Math.floor(Number(centerTile.worldX) - state.battle.cameraX),
    y: swarmMapRowAnchorY(mapRow),
  };
}

function wizardSpellFxLayerAnchor(spell, layer, playerAnchor, enemyAnchor) {
  if (layer.anchor === "player") return playerAnchor;
  if (layer.anchor === "enemy") {
    if (spell?.impactMode === "bang" || spell?.impactMode === "target") {
      return { x: enemyAnchor.x, y: spellTargetCellAnchorY(enemyAnchor.y) };
    }
    return enemyAnchor;
  }
  return spell?.effectAnchor === "enemy" ? enemyAnchor : playerAnchor;
}

function ultimateEnhancerImpactAnchor(entry) {
  const laneY = Math.floor(state.stageHeight * LANE.y);
  if (entry.petFx || entry.anchor === "pet") {
    const pet = state.battle.bossParty?.pet ?? state.battle.taoPet;
    const worldX = resolvedTaoPetWorldX(pet);
    return { x: Math.floor(worldX - state.battle.cameraX), y: laneY };
  }
  if (entry.memberClassId && state.battle.bossParty?.active) {
    const member = state.battle.bossParty.members?.find((candidate) => candidate.classId === entry.memberClassId);
    if (member) {
      return {
        x: Math.floor((Number(member.worldX) || 0) - state.battle.cameraX),
        y: laneY,
      };
    }
  }
  const playerAnchor = combatAnchor("player");
  return { x: playerAnchor.x, y: laneY };
}

function defenceBuffImpactAnchor(entry) {
  const laneY = Math.floor(state.stageHeight * LANE.y);
  if (entry.spellId === "UltimateEnhancer") {
    return ultimateEnhancerImpactAnchor(entry);
  }
  if (entry.anchor === "pet") {
    const petAnchor = taoistPetAnchor();
    return { x: petAnchor.x, y: spellTargetCellAnchorY(petAnchor.y) };
  }
  if (entry.worldX != null) {
    return {
      x: Math.floor(entry.worldX - state.battle.cameraX),
      y: spellTargetCellAnchorY(laneY),
    };
  }
  const playerAnchor = combatAnchor("player");
  return { x: playerAnchor.x, y: spellTargetCellAnchorY(playerAnchor.y) };
}

function drawDefenceBuffFxCanvas(ctx) {
  const fx = defenceBuffFxList();
  if (!fx.length) return;
  const now = performance.now();
  for (const entry of fx) {
    const atlas = defenceBuffImpactAtlas(entry.spellId);
    if (!atlas?.layers?.length) continue;
    const t = now - entry.startAt;
    if (t < 0) continue;
    const { x: anchorX, y: anchorY } = defenceBuffImpactAnchor(entry);
    withScreenBlend(ctx, () => {
      for (const layer of atlas.layers) {
        const layerT = t - (layer.delayMs ?? 0);
        const duration = layer.frames.length * layer.interval;
        if (layerT < 0 || layerT > duration) continue;
        const frameIndex = Math.min(layer.frames.length - 1, Math.floor(layerT / layer.interval));
        drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, anchorX, anchorY);
      }
    });
  }
}

function drawGroundSpellEffectsCanvas(ctx) {
  const now = performance.now();
  const effects = (state.battle.groundSpellEffects ?? []).filter((effect) => now <= effect.expiresAt);
  if (effects.length !== (state.battle.groundSpellEffects ?? []).length) state.battle.groundSpellEffects = effects;
  if (!effects.length) return;

  const groundY = Math.floor(state.stageHeight * LANE.y);
  withScreenBlend(ctx, () => {
    for (const effect of effects) {
      const atlas = state.wizardSpellAtlases[effect.spellId];
      const layer = wizardGroundFxLayer(atlas);
      if (!layer?.frames?.length) continue;
      const interval = Math.max(1, Math.trunc(Number(layer.interval) || 83));
      const duration = Math.max(interval, layer.frames.length * interval);
      const age = Math.max(0, now - (Number(effect.createdAt) || now));
      const frameIndex = Math.min(layer.frames.length - 1, Math.floor((age % duration) / interval));
      if (groupDungeonSwarmSideActive() && effect.tiles?.length) {
        for (const tile of effect.tiles) {
          const x = Math.floor(tile.worldX - state.battle.cameraX);
          if (x < -layer.slotWidth || x > state.stageWidth + layer.slotWidth) continue;
          drawSpellLayerCanvas(ctx, effect.spellId, layer, frameIndex, x, swarmGroundSpellAnchorY(tile.mapRow));
        }
      } else {
        for (const offset of effect.offsets ?? [0]) {
          const x = Math.floor(effect.worldX + offset - state.battle.cameraX);
          if (x < -layer.slotWidth || x > state.stageWidth + layer.slotWidth) continue;
          drawSpellLayerCanvas(ctx, effect.spellId, layer, frameIndex, x, groundY);
        }
      }
    }
  });
}

function drawMapLightningEffectsCanvas(ctx) {
  const atlas = state.mapLightningAtlas;
  const layer = atlas?.layers?.[0];
  const effects = (state.battle.mapLightningEffects ?? []).filter((effect) => performance.now() <= effect.expiresAt);
  if (!layer?.frames?.length || !effects.length) return;

  const now = performance.now();
  const groundY = Math.floor(state.stageHeight * LANE.y);
  withScreenBlend(ctx, () => {
    for (const effect of effects) {
      const x = Math.floor(effect.worldX - state.battle.cameraX);
      if (x < -layer.slotWidth || x > state.stageWidth + layer.slotWidth) continue;
      const frameIndex = mapLightningFrameIndex(effect, layer, now);
      drawSpellLayerCanvas(ctx, MAP_LIGHTNING_FX_ID, layer, frameIndex, x, groundY);
    }
  });
}

function wizardGroundFxLayer(atlas) {
  if (!atlas) return null;
  return atlas.ground ?? atlas.layers?.find((layer) => layer.sheet === "ground.png" || Number(layer.baseIndex) === 1630) ?? null;
}

function drawLevelUpFxCanvas(ctx) {
  const atlas = state.levelUpAtlas;
  if (!atlas?.layers?.length || !state.levelUpEffects.length) return;
  const now = performance.now();
  const duration = Math.max(...atlas.layers.map((layer) => layer.frames.length * layer.interval));
  const effects = state.levelUpEffects.filter((effect) => now - effect.createdAt <= duration);
  if (effects.length !== state.levelUpEffects.length) state.levelUpEffects = effects;
  if (!effects.length) return;

  const anchor = combatAnchor("player");
  withScreenBlend(ctx, () => {
    for (const effect of effects) {
      const age = Math.max(0, now - effect.createdAt);
      for (const layer of atlas.layers) {
        const frameIndex = Math.min(layer.frames.length - 1, Math.floor(age / layer.interval));
        drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, anchor.x, anchor.y);
      }
    }
  });
}

function drawFloatingCombatText(ctx) {
  const now = performance.now();
  const duration = 1050;
  const texts = state.battle.floatingTexts.filter((entry) => now - entry.createdAt < duration);
  if (texts.length !== state.battle.floatingTexts.length) state.battle.floatingTexts = texts;
  if (!texts.length) return;

  ctx.save();
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.font = "700 14px Segoe UI, system-ui, sans-serif";
  for (const entry of texts) {
    const age = now - entry.createdAt;
    const t = Math.max(0, Math.min(1, age / duration));
    const x = entry.x;
    const y = entry.y - t * 34;
    const alpha = t < 0.72 ? 1 : Math.max(0, 1 - (t - 0.72) / 0.28);
    ctx.globalAlpha = alpha;
    ctx.lineWidth = 3;
    ctx.strokeStyle = "rgba(0, 0, 0, 0.72)";
    ctx.fillStyle = combatTextColor(entry.kind);
    ctx.strokeText(entry.text, x, y);
    ctx.fillText(entry.text, x, y);
  }
  ctx.restore();
}

function combatTextColor(kind) {
  if (kind === "miss") return "#d7d0c3";
  if (kind === "enemyDamage") return "#ef7f72";
  if (kind === "heal") return "#80e28a";
  if (kind === "mana") return "#7fb7ff";
  if (kind === "poison") return "#69d879";
  if (kind === "frost") return "#9de8ff";
  if (kind === "debuff") return "#e2c45f";
  if (kind === "buff") return "#f0b35c";
  if (kind === "assistDamage") return "#c6a0ff";
  return "#f3d16b";
}

function drawLootNotices(ctx) {
  const now = performance.now();
  const duration = 3200;
  const notices = state.game.lootToasts.filter((entry) => now - entry.createdAt < duration);
  if (notices.length !== state.game.lootToasts.length) state.game.lootToasts = notices;
  if (!notices.length) return;

  ctx.save();
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.font = "700 12px Segoe UI, system-ui, sans-serif";
  const x = Math.round(state.stageWidth / 2);
  notices.slice(-4).forEach((entry, index) => {
    const age = now - entry.createdAt;
    const t = Math.max(0, Math.min(1, age / duration));
    const alpha = t < 0.78 ? 1 : Math.max(0, 1 - (t - 0.78) / 0.22);
    const y = 28 + index * 22 - Math.min(10, t * 10);
    const textWidth = Math.min(260, Math.max(92, ctx.measureText(entry.text).width + 24));
    ctx.globalAlpha = alpha;
    ctx.fillStyle = "rgba(9, 9, 7, 0.76)";
    ctx.fillRect(Math.round(x - textWidth / 2), Math.round(y - 10), textWidth, 20);
    ctx.strokeStyle = lootNoticeBorder(entry.kind);
    ctx.strokeRect(Math.round(x - textWidth / 2) + 0.5, Math.round(y - 10) + 0.5, textWidth - 1, 19);
    ctx.fillStyle = lootNoticeColor(entry.kind);
    ctx.fillText(entry.text, x, y);
  });
  ctx.restore();
}

function lootNoticeColor(kind) {
  if (kind === "level") return "#e6f0ff";
  if (kind === "gold") return "#e2ba54";
  if (kind === "full") return "#d98572";
  return "#d8d0bf";
}

function lootNoticeBorder(kind) {
  if (kind === "level") return "rgba(158, 205, 255, 0.82)";
  if (kind === "gold") return "rgba(226, 186, 84, 0.72)";
  if (kind === "full") return "rgba(217, 133, 114, 0.72)";
  return "rgba(216, 208, 191, 0.54)";
}

function combatTextBounds(anchorName) {
  if (anchorName === "enemy") return enemyFrameBounds();
  if (anchorName === "pet") return taoistPetFrameBounds();
  return playerFrameBounds();
}

function playerFrameBounds() {
  const partyMember = bossPartyOnField() ? bossPartyControlledMember() : null;
  if (partyMember) return bossPartyMemberFrameBounds(partyMember);
  const anchor = combatAnchor("player");
  for (const layer of layerNames()) {
    const atlas = state.atlases[layer];
    const clip = atlas?.actions?.[state.action];
    const meta = clip?.frames?.[state.frame] ?? clip?.frames?.[0];
    if (!atlas || !clip || !meta || meta.empty) continue;
    const width = meta.w || atlas.slotWidth;
    return {
      centerX: anchor.x + meta.offsetX + width / 2,
      topY: anchor.y + meta.offsetY,
    };
  }
  return { centerX: anchor.x, topY: anchor.y - 80 };
}

function bossPartyMemberFrameBounds(member) {
  const anchor = {
    x: Math.round((member.worldX ?? state.battle.playerX) - state.battle.cameraX),
    y: Math.floor(state.stageHeight * LANE.y),
  };
  const action = member.visualAction ?? (member.alive ? "stance" : "die");
  for (const layer of layerNames()) {
    const atlas = member.visualAtlases?.[layer] ?? (member.classId === bossPartyControlledClassId() ? state.atlases[layer] : null);
    const clip = atlas?.actions?.[action] ?? atlas?.actions?.stance ?? atlas?.actions?.standing;
    const frameIndex = Math.max(0, Math.min(member.visualFrame ?? 0, (clip?.frames?.length ?? 1) - 1));
    const meta = clip?.frames?.[frameIndex] ?? clip?.frames?.[0];
    if (!atlas || !clip || !meta || meta.empty) continue;
    const width = meta.w || atlas.slotWidth;
    const height = meta.h || atlas.slotHeight;
    return {
      centerX: anchor.x + meta.offsetX + width / 2,
      topY: anchor.y + meta.offsetY,
      height,
    };
  }
  return { centerX: anchor.x, topY: anchor.y - 80, height: 112 };
}

function taoistPetFrameBounds() {
  const anchor = taoistPetAnchor();
  const pet = state.battle.taoPet;
  const atlas = taoPetAtlasFor(pet);
  const clip = atlas?.actions?.[pet?.action];
  const meta = clip?.frames?.[pet?.frame ?? 0] ?? clip?.frames?.[0];
  if (!atlas || !meta || meta.empty) {
    return { centerX: anchor.x, topY: anchor.y - 64 };
  }
  const width = meta.w || atlas.slotWidth;
  const height = meta.h || atlas.slotHeight;
  return {
    centerX: anchor.x + meta.offsetX + width / 2,
    topY: anchor.y + meta.offsetY,
    height,
  };
}

function drawProjectileCanvas(ctx, atlas, t, anchorX, anchorY) {
  const p = atlas.projectile;
  if (!p || t < p.delayMs) return;
  const travelT = Math.min(1, (t - p.delayMs) / Math.max(1, p.moveDurationMs));
  const frameIndex = Math.min(p.frames.length - 1, Math.floor((t - p.delayMs) / p.interval) % p.frames.length);
  const meta = p.frames[frameIndex] ?? p.frames[0];
  if (!meta || meta.empty) return;
  const moveX = p.startOffsetX + (p.endOffsetX - p.startOffsetX) * travelT;
  const moveY = p.startOffsetY + (p.endOffsetY - p.startOffsetY) * travelT;
  drawSpellFrameCanvas(ctx, atlas.spellId, p.sheet, p.slotWidth, p.slotHeight, { ...meta, offsetX: meta.offsetX + moveX, offsetY: meta.offsetY + moveY }, anchorX, anchorY);
}

function drawCombatProjectileCanvas(ctx, atlas, t, playerAnchor, enemyAnchor, impactAt = null) {
  const p = atlas.projectile;
  const moveDurationMs = Math.max(1, (Number(impactAt) || ((p?.delayMs ?? 0) + (p?.moveDurationMs ?? 0))) - (p?.delayMs ?? 0));
  if (!p || t < p.delayMs || t > p.delayMs + moveDurationMs) return;
  const travelT = Math.min(1, (t - p.delayMs) / moveDurationMs);
  const frameIndex = Math.min(p.frames.length - 1, Math.floor((t - p.delayMs) / p.interval) % p.frames.length);
  const meta = p.frames[frameIndex] ?? p.frames[0];
  if (!meta || meta.empty) return;
  // Crystal missiles interpolate map-cell draw locations; the frame offsets carry the visual height.
  const startX = playerAnchor.x;
  const startY = playerAnchor.y;
  const targetX = enemyAnchor.x;
  const targetY = enemyAnchor.y;
  const x = startX + (targetX - startX) * travelT;
  const y = startY + (targetY - startY) * travelT;
  drawSpellFrameCanvas(ctx, atlas.spellId, p.sheet, p.slotWidth, p.slotHeight, { ...meta, offsetX: meta.offsetX + x, offsetY: meta.offsetY + y }, 0, 0);
}

function drawImpactFlashCanvas(ctx, atlas, t, enemyAnchor) {
  const layer = atlas.impact ?? atlas.layers[0];
  if (!layer?.frames?.length) return;
  const frameIndex = Math.min(layer.frames.length - 1, Math.floor(t / layer.interval));
  drawSpellLayerCanvas(ctx, atlas.spellId, layer, frameIndex, enemyAnchor.x, enemyAnchor.y);
}

function drawSpellLayerCanvas(ctx, spellId, layer, frameIndex, anchorX, anchorY) {
  const meta = layer.frames[frameIndex] ?? layer.frames[0];
  if (!meta || meta.empty) return;
  drawSpellFrameCanvas(ctx, spellId, layer.sheet, layer.slotWidth, layer.slotHeight, meta, anchorX, anchorY);
}

function drawSpellFrameCanvas(ctx, spellId, sheetName, slotWidth, slotHeight, meta, anchorX, anchorY) {
  const sheet = cachedImage(`./public/spellfx/${spellId}/${sheetName}`);
  if (!sheet) return;
  drawAtlasFrame(ctx, sheet, slotWidth, slotHeight, meta, anchorX, anchorY);
}

function withScreenBlend(ctx, draw) {
  ctx.save();
  ctx.globalCompositeOperation = "screen";
  draw();
  ctx.restore();
}

function cachedImage(src) {
  const existing = imageCache.get(src);
  if (existing?.complete && existing.naturalWidth > 0) return existing;
  if (existing) return null;

  const image = new Image();
  image.decoding = "async";
  image.onload = () => render();
  image.onerror = () => imageCache.delete(src);
  image.src = src;
  imageCache.set(src, image);
  return null;
}

function loadCachedImage(src) {
  let existing = imageCache.get(src);
  if (existing?.complete && existing.naturalWidth > 0) return Promise.resolve(existing);
  if (existing?.complete) {
    imageCache.delete(src);
    existing = null;
  }
  if (existing) {
    return new Promise((resolve, reject) => {
      existing.addEventListener("load", () => resolve(existing), { once: true });
      existing.addEventListener("error", reject, { once: true });
    });
  }

  return new Promise((resolve, reject) => {
    const image = new Image();
    image.decoding = "async";
    image.onload = () => {
      render();
      resolve(image);
    };
    image.onerror = (event) => {
      imageCache.delete(src);
      reject(event);
    };
    image.src = src;
    imageCache.set(src, image);
  });
}

function renderBattlePanel() {
  if (IS_GAME_UI) {
    renderGameUiBattlePanel();
    return;
  }

  const battle = state.battle;
  const p = battle.player;
  const e = battle.enemy;
  if (!p || !e) {
    battlePanelSignature = "";
    els.battlePanel.innerHTML = "";
    return;
  }
  const signature = JSON.stringify({
    running: battle.running,
    gameMode: state.game.mode,
    activeZoneId: state.game.activeZoneId,
    zoneKills: state.game.zoneKills,
    phase: battle.phase,
    enemyId: battle.enemyId,
    combatClass: battle.combatClass,
    warriorSkill: battle.warriorSkill,
    wizardSpell: battle.wizardSpell,
    magic: magicSignature(),
    playerHp: p.hp,
    playerMp: p.mp,
    playerAttackSpeed: p.attackSpeed,
    furyUntil: Math.floor((battle.furyUntil ?? 0) / 100),
    level: battle.level,
    experience: battle.experience,
    gold: battle.gold,
    enemyHp: e.hp,
    enemyMp: e.mp,
    bossParty: bossPartySignature(),
    showEnemies: state.showEnemies,
    continuousWalk: state.continuousWalk,
    continuousMoveAction: state.continuousMoveAction,
    distance: state.showEnemies ? Math.round(enemyDistance() / 10) * 10 : 0,
    groundSpeedRatio: state.groundSpeedRatio,
    stepTestActive: state.stepTest.active,
    stepTestComplete: state.stepTest.complete,
    travelAction: battle.phase === "advance" ? travelAction(performance.now()) : "",
    log: battle.log,
  });
  if (signature === battlePanelSignature) return;
  battlePanelSignature = signature;

  const enemyOptions = ENEMY_TEMPLATES.map(
    (enemy) => `<option value="${enemy.id}" ${enemy.id === battle.enemyId ? "selected" : ""}>${enemy.name}</option>`,
  ).join("");
  const classOptions = COMBAT_CLASSES.map((combatClass) => {
    const disabled = combatClass.disabled ? "disabled" : "";
    const suffix = combatClass.disabled ? " (soon)" : "";
    return `<option value="${combatClass.id}" ${combatClass.id === battle.combatClass ? "selected" : ""} ${disabled}>${combatClass.label}${suffix}</option>`;
  }).join("");
  const wizardOptions = WIZARD_COMBAT_SPELLS.map((spell) => {
    const disabled = !state.wizardSpellAtlases[spell.id] ? "disabled" : "";
    const suffix = disabled ? " (missing FX)" : "";
    return `<option value="${spell.id}" ${spell.id === battle.wizardSpell ? "selected" : ""} ${disabled}>${spell.label}${suffix}</option>`;
  }).join("");
  const classAbilityControl = battle.combatClass === "Wizard"
    ? `
      <label>
        Wizard spell
        <select id="wizardSpell">${wizardOptions}</select>
      </label>
    `
    : battle.combatClass === "Taoist"
    ? `<p class="battle-state">Auto skills: ${escapeHtml(taoistAutoSummaryText())}</p>`
    : `<p class="battle-state">Auto skills: ${escapeHtml(warriorAutoSummaryText())}</p>`;
  els.battlePanel.innerHTML = `
    <label>
      Battle enemy
      <select id="battleEnemy">${enemyOptions}</select>
    </label>
    <label>
      Class
      <select id="combatClass">${classOptions}</select>
    </label>
    <div class="battle-grid">
      ${statBlock(battle.combatClass, p)}
      ${statBlock(e.name, e)}
    </div>
    <p class="battle-state">
      Level ${battle.level} | ${xpProgressText()} | Gold ${battle.gold}
    </p>
    <label>
      Attack speed: ${p.attackSpeed}${effectivePlayerAttackSpeed() !== p.attackSpeed ? ` +${effectivePlayerAttackSpeed() - p.attackSpeed}` : ""} (${playerAttackDelayMs()}ms)
      <input id="playerAttackSpeed" type="range" min="0" max="10" step="1" value="${p.attackSpeed}" />
    </label>
    <p class="battle-state">
      ${state.game.mode === "zone"
        ? `Zone: ${activeZone()?.label ?? "Unknown"} | Phase: ${title(battle.phase)} | Distance: ${Math.round(enemyDistance())} | Range: ${playerAttackRange()}`
        : state.stepTest.active || state.stepTest.complete
        ? `One-step test | ${state.stepTest.distancePx}px tile | ${state.stepTest.durationMs}ms | ground +${state.stepTest.distancePx}px`
        : state.continuousWalk ? `Deterministic ${PLAYER_ACTIONS[state.continuousMoveAction].label.toLowerCase()} | 1 cycle = ${movementCycleDistance(state.continuousMoveAction)}px`
        : state.showEnemies ? `Phase: ${title(battle.phase)} | Distance: ${Math.round(enemyDistance())} | Range: ${playerAttackRange()}` : `Ground tuning | ${state.groundSpeedRatio.toFixed(2)}x`}
      <br />
      Move model: walk ${LANE_TILE_PX}px/${WALK_CYCLE_MS}ms (${LANE.playerSpeed}px/s), run ${LANE_TILE_PX * 2}px/${RUN_CYCLE_MS}ms (${LANE.runSpeed}px/s)
    </p>
    ${classAbilityControl}
    ${bossPartyStatusHtml()}
    <div class="battle-buttons">
      <button id="battleToggle" class="primary">${battle.running ? "Pause Battle" : state.game.mode === "town" ? "Start Zone 1" : "Start Battle"}</button>
      <button id="battleReset">Reset</button>
    </div>
    <div class="battle-log">
      ${battle.log.map((line) => `<p>${line}</p>`).join("")}
    </div>
  `;
  els.battlePanel.querySelector("#battleEnemy").addEventListener("change", async (event) => {
    await selectBattleEnemy(event.currentTarget.value);
    battlePanelSignature = "";
  });
  els.battlePanel.querySelector("#playerAttackSpeed").addEventListener("input", (event) => {
    p.attackSpeed = Number(event.currentTarget.value);
    battlePanelSignature = "";
    if (battle.running) {
      battle.nextPlayerAttackAt = performance.now() + playerAttackDelayMs();
    }
    render();
  });
  els.battlePanel.querySelector("#combatClass").addEventListener("change", (event) => {
    battle.combatClass = event.currentTarget.value;
    battle.pendingImpact = null;
    battle.pendingEnemyStrike = null;
    battle.pendingHeal = null;
    battle.pendingPoison = null;
    battle.activeSkill = "None";
    battle.activeSkillAtlas = null;
    battle.activeWizardSpell = null;
    battle.activeWizardSpellAtlas = null;
    battle.activeTaoSpell = null;
    battle.activeTaoSpellAtlas = null;
    battle.furyUntil = 0;
    battle.furyBonus = 0;
    battlePanelSignature = "";
    render();
  });
  els.battlePanel.querySelector("#warriorSkill")?.addEventListener("change", (event) => {
    battle.warriorSkill = event.currentTarget.value;
    battlePanelSignature = "";
    render();
  });
  els.battlePanel.querySelector("#wizardSpell")?.addEventListener("change", (event) => {
    battle.wizardSpell = event.currentTarget.value;
    battlePanelSignature = "";
    render();
  });
  els.battlePanel.querySelector("#battleToggle").addEventListener("click", async () => {
    if (battle.running) stopBattle();
    else if (state.game.mode === "town") await enterZone(PROTOTYPE_ZONES[0].id);
    else startBattle();
    battlePanelSignature = "";
    render();
  });
  els.battlePanel.querySelector("#battleReset").addEventListener("click", async () => {
    await selectBattleEnemy(battle.enemyId);
    battlePanelSignature = "";
  });
}

function bossPartySignature() {
  const party = state.battle.bossParty;
  if (!party) return "";
  return JSON.stringify({
    active: party.active,
    finished: party.finished,
    defeated: party.defeated,
    controlledClassId: party.controlledClassId,
    pet: party.pet ? `${party.pet.hp}/${party.pet.maxHp}:${party.pet.active ? 1 : 0}` : "",
    members: party.members.map((member) => `${member.classId}:${member.hp}/${member.maxHp}:${member.mp}/${member.maxMp}:${member.alive ? 1 : 0}`),
  });
}

function bossPartyStatusHtml() {
  const party = state.battle.bossParty;
  if (!party?.members?.length) return "";
  const leaderClassId = bossPartyLeaderClassId(party);
  const pet = party.pet
    ? `<div class="boss-party-row pet ${party.pet.active ? "" : "dead"}"><span>${escapeHtml(party.pet.name)}</span><strong>${Math.max(0, Math.floor(party.pet.hp))}/${party.pet.maxHp}</strong></div>`
    : "";
  return `
    <div class="boss-party-status">
      <div class="boss-party-heading">
        <strong>${party.defeated ? "Defeated" : party.finished ? "Victory" : "Boss Party"}</strong>
        <span>Leader: ${escapeHtml(leaderClassId)}</span>
      </div>
      ${pet}
      ${party.members.map((member) => `
        <div class="boss-party-row ${member.classId === leaderClassId ? "controlled" : ""} ${member.alive ? "" : "dead"}">
          <span>${escapeHtml(member.classId)}</span>
          <strong>${Math.max(0, Math.floor(member.hp))}/${member.maxHp} HP</strong>
          <em>${Math.max(0, Math.floor(member.mp))}/${member.maxMp} MP</em>
        </div>
      `).join("")}
    </div>
  `;
}

function renderGameUiBattlePanel() {
  if (battlePanelSignature === "__game_ui_side_panel_log__") return;
  battlePanelSignature = "__game_ui_side_panel_log__";
  els.battlePanel.innerHTML = "";
}

function gameResourceMeterHtml(label, value, max, kind) {
  const pct = resourcePercentage(value, max);
  return `
    <div class="game-resource-meter ${kind}">
      <div>
        <span>${escapeHtml(label)}</span>
        <strong>${Math.max(0, Math.floor(value))}/${Math.max(0, Math.floor(max))}</strong>
      </div>
      <span class="game-resource-track">
        <span class="game-resource-fill" style="width:${pct}%"></span>
      </span>
    </div>
  `;
}

function gameLogLinesHtml() {
  const lines = state.battle.log.length ? state.battle.log : ["Adventure started."];
  return lines.map((line) => `<p class="${gameLogLineClass(line)}">${escapeHtml(line)}</p>`).join("");
}

function gameLogLineClass(line) {
  const text = String(line ?? "");
  if (text.startsWith(COMBAT_LOG_SUMMARY_PREFIX)) return "game-log-line is-combat-summary";
  if (/defeated|falls|steps up|Wave|Floor|received|found|gained|Level up|respawn|Return To Town/i.test(text)) {
    return "game-log-line is-event";
  }
  return "game-log-line";
}

function statBlock(name, stats) {
  const level = Math.max(1, Math.trunc(Number(stats.level) || state.battle.level || playerCombatLevel()));
  const effective = effectivePlayerAttackSpeed();
  const speedLine = stats.attackSpeed != null
    ? `<dt>AS</dt><dd>${stats.attackSpeed}${effective !== stats.attackSpeed ? ` (+${effective - stats.attackSpeed})` : ""} · ${playerAttackDelayMs()}ms</dd>`
    : `<dt>ATK</dt><dd>${stats.attackMs}ms</dd>`;
  const magicLine = stats.mc ? `<dt>MC</dt><dd>${formatStatRange(stats.mc)}</dd>` : "";
  const spiritLine = stats.sc ? `<dt>SC</dt><dd>${formatStatRange(stats.sc)}</dd>` : "";
  return `
    <section class="stat-block">
      <strong>${name}</strong>
      ${bar("HP", stats.hp, stats.maxHp)}
      ${bar("MP", stats.mp, stats.maxMp)}
      <dl>
        <dt>DC</dt><dd>${formatStatRange(stats.dc)}</dd>
        ${magicLine}
        ${spiritLine}
        <dt>AC</dt><dd>${formatStatRange(stats.ac)}</dd>
        <dt>AMC</dt><dd>${formatStatRange(stats.amc)}</dd>
        <dt>Acc</dt><dd>${stats.accuracy ?? 0}</dd>
        <dt>Agi</dt><dd>${stats.agility ?? 0}</dd>
        <dt>Luck</dt><dd>${stats.luck ?? 0}</dd>
        ${speedLine}
      </dl>
    </section>
  `;
}

function bar(label, value, max) {
  const pct = max > 0 ? Math.max(0, Math.min(100, (value / max) * 100)) : 0;
  return `
    <div class="bar-row">
      <span>${label}</span>
      <div class="bar-track"><div class="bar-fill" style="width:${pct}%"></div></div>
      <span>${value}/${max}</span>
    </div>
  `;
}

function movementTestScrollCameraX(tileCameraX) {
  if (state.continuousWalk) {
    return state.continuousWalkStartScrollX + (tileCameraX - state.continuousWalkStartCameraX * LANE.tileScrollRatio);
  }
  if (!state.stepTest.active && !state.stepTest.complete) return tileCameraX * state.groundSpeedRatio;
  return state.stepTest.startScrollX + (tileCameraX - state.stepTest.startCameraX * LANE.tileScrollRatio);
}

function positiveModulo(value, divisor) {
  return ((value % divisor) + divisor) % divisor;
}

function hashDecorationSeed(text) {
  let hash = 0;
  for (let i = 0; i < text.length; i++) {
    hash = ((hash << 5) - hash + text.charCodeAt(i)) | 0;
  }
  return hash;
}

function decorationSpawnRow(decoration, worldX) {
  if (typeof decoration?.row === "number") return decoration.row;
  const rows = Array.isArray(decoration?.rows) && decoration.rows.length
    ? decoration.rows
    : currentZoneDecorationRows();
  if (!rows.length) return 0;
  const seed = Math.trunc(worldX) + hashDecorationSeed(String(decoration?.id ?? ""));
  return rows[positiveModulo(seed, rows.length)];
}

function clonePattern(pattern) {
  return pattern.map((row) => [...row]);
}

function createEmptyObjectPattern(rows = DEFAULT_OBJECT_PATTERN_ROWS, cols = DEFAULT_OBJECT_PATTERN_COLS) {
  return Array.from({ length: rows }, () => Array(cols).fill(ZONE_OBJECT_EMPTY));
}

function cloneDecorations(decorations = []) {
  return decorations.map((decoration) => ({
    ...decoration,
    slots: Array.isArray(decoration.slots) ? [...decoration.slots] : [],
    frames: Array.isArray(decoration.frames) ? [...decoration.frames] : [],
    groups: Array.isArray(decoration.groups) ? [...decoration.groups] : [],
    rows: Array.isArray(decoration.rows) ? [...decoration.rows] : decoration.rows,
  }));
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

function currentMapSet() {
  return state.mapTileIndex.sets.find((set) => set.id === currentMapSetId()) ?? state.mapTileIndex.sets[0];
}

function zoneVisualDraft(zone = activeZone()) {
  if (!zone || state.game.mode !== "zone") return null;
  if (state.zoneBuilderPreviewZoneId !== zone.id) return null;
  return state.zoneBuilderDrafts[zone.id] ?? null;
}

function currentMapSetId() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  if (state.game.mode === "zone" && draft?.mapSet) return draft.mapSet;
  if (state.game.mode === "zone" && zone?.mapSet) return zone.mapSet;
  return state.mapSet;
}

function mapSetById(mapSetId) {
  return state.mapTileIndex.sets.find((set) => set.id === mapSetId) ?? null;
}

function currentZonePattern() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  if (state.game.mode === "zone" && Array.isArray(draft?.tilePattern) && draft.tilePattern.length) {
    return draft.tilePattern;
  }
  if (state.game.mode === "zone" && Array.isArray(zone?.tilePattern) && zone.tilePattern.length) {
    return zone.tilePattern;
  }
  return state.zonePattern?.length ? state.zonePattern : DEFAULT_ZONE_PATTERN;
}

function currentZoneDecorations() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  if (state.game.mode === "zone" && draft && Object.hasOwn(draft, "decorations")) {
    return Array.isArray(draft.decorations) ? draft.decorations : [];
  }
  if (state.game.mode === "zone" && zone && Object.hasOwn(zone, "decorations")) {
    return Array.isArray(zone.decorations) ? zone.decorations : [];
  }
  return state.zoneDecorations;
}

function currentZoneDecorationRows() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  if (state.game.mode === "zone" && draft && Object.hasOwn(draft, "decorationRows")) {
    return Array.isArray(draft.decorationRows) ? draft.decorationRows : [];
  }
  if (state.game.mode === "zone" && zone && Object.hasOwn(zone, "decorationRows")) {
    return Array.isArray(zone.decorationRows) ? zone.decorationRows : [];
  }
  return [];
}

function currentZoneGroundRows() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  const top = state.game.mode === "zone" ? draft?.groundTopRows ?? zone?.groundTopRows ?? 0 : 0;
  const bottom = state.game.mode === "zone" ? draft?.groundBottomRows ?? zone?.groundBottomRows ?? 0 : 0;
  return {
    top: Math.max(0, Number(top) || 0),
    bottom: Math.max(0, Number(bottom) || 0),
  };
}

function currentZoneTileAnchor2x2() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  if (state.game.mode === "zone" && draft && Object.hasOwn(draft, "tileAnchor2x2")) {
    return draft.tileAnchor2x2 === true;
  }
  if (state.game.mode === "zone" && zone?.tileAnchor2x2 === true) {
    return true;
  }
  return false;
}

function currentZoneObjectSet() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  const objectSetId = state.game.mode === "zone" ? draft?.objectSet ?? zone?.objectSet : null;
  return objectSetId ? mapObjectSetById(objectSetId) : null;
}

function currentZoneObjectPattern() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  if (state.game.mode === "zone" && Array.isArray(draft?.objectPattern) && draft.objectPattern.length) {
    return draft.objectPattern;
  }
  if (state.game.mode === "zone" && Array.isArray(zone?.objectPattern) && zone.objectPattern.length) {
    return zone.objectPattern;
  }
  return [];
}

function currentBackdropKind() {
  if (state.game.mode === "town") return TOWN_VISUALS.backdrop ?? "field";
  if (state.game.mode === "mining") return activeZone()?.backdrop ?? "cave";
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  return state.game.mode === "zone" ? draft?.backdrop ?? zone?.backdrop ?? "field" : "field";
}

function currentZoneMapStamp() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  if (state.game.mode === "mining") {
    const spot = activeMiningSpot();
    const stampId = spot?.mapStamp ?? null;
    return stampId ? state.mapStampIndex.stamps.find((stamp) => stamp.id === stampId) ?? null : null;
  }
  if (state.game.mode !== "zone") return null;
  const stampId = draft?.mapStamp ?? zone?.mapStamp ?? null;
  return stampId ? state.mapStampIndex.stamps.find((stamp) => stamp.id === stampId) ?? null : null;
}

function currentZoneEdgeSet() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  const edgeSetId = state.game.mode === "zone" ? draft?.edgeSet ?? zone?.edgeSet : null;
  return edgeSetId ? CAVE_EDGE_SETS[edgeSetId] ?? null : null;
}

function zoneBuilderTarget() {
  return PROTOTYPE_ZONES.find((zone) => zone.id === state.zoneBuilderTargetId) ?? PROTOTYPE_ZONES[0];
}

function zoneBuilderDraft(zoneId = state.zoneBuilderTargetId) {
  const zone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId) ?? PROTOTYPE_ZONES[0];
  if (!state.zoneBuilderDrafts[zone.id]) {
    state.zoneBuilderDrafts[zone.id] = createZoneBuilderDraft(zone);
  }
  return state.zoneBuilderDrafts[zone.id];
}

function createZoneBuilderDraft(zone) {
  const hasZoneDecorations = Object.hasOwn(zone, "decorations");
  const objectPattern = Array.isArray(zone.objectPattern) && zone.objectPattern.length
    ? clonePattern(zone.objectPattern)
    : createEmptyObjectPattern();
  return {
    mapSet: zone.mapSet ?? state.mapSet,
    backdrop: zone.backdrop ?? "field",
    edgeSet: zone.edgeSet ?? null,
    groundTopRows: zone.groundTopRows ?? 0,
    groundBottomRows: zone.groundBottomRows ?? 0,
    decorationSet: zone.decorationSet ?? ZONE_DECORATION_SET,
    decorationRows: Array.isArray(zone.decorationRows) ? [...zone.decorationRows] : zone.decorationRows,
    objectSet: zone.objectSet ?? null,
    objectPattern,
    tilePattern: clonePattern(Array.isArray(zone.tilePattern) && zone.tilePattern.length ? zone.tilePattern : DEFAULT_ZONE_PATTERN),
    tileAnchor2x2: zone.tileAnchor2x2 === true,
    decorations: cloneDecorations(hasZoneDecorations ? zone.decorations : state.zoneDecorations),
  };
}

function currentMapObjectSet() {
  const zone = activeZone();
  const draft = zoneVisualDraft(zone);
  const decorationSetId = state.game.mode === "zone"
    ? draft?.decorationSet ?? zone?.decorationSet ?? ZONE_DECORATION_SET
    : ZONE_DECORATION_SET;
  return state.mapObjectIndex.sets.find((set) => set.id === decorationSetId) ?? state.mapObjectIndex.sets[0];
}

function mapObjectSetById(objectSetId) {
  return state.mapObjectIndex.sets.find((set) => set.id === objectSetId) ?? null;
}

function preferredMapSetOrder(sets) {
  const priority = ["wemade-mir2-custom", "oma-cave", "prajna-cave", "viper-cave", "prajna-temple", "wooma-temple", "stone-temple", "zuma-temple", "bdd-dungeon", "wemade-mir2", "forest", "shanda-mir2", "wemade-mir3", "wood", "sand", "snow"];
  return [...sets].sort((a, b) => {
    const aIndex = priority.indexOf(a.id);
    const bIndex = priority.indexOf(b.id);
    const aRank = aIndex === -1 ? priority.length : aIndex;
    const bRank = bIndex === -1 ? priority.length : bIndex;
    return aRank - bRank || a.label.localeCompare(b.label);
  });
}

function arenaLaneYRatio(zone = activeZone()) {
  const ratio = Number(zone?.arenaLaneY);
  return Number.isFinite(ratio) && ratio > 0 && ratio < 1 ? ratio : LANE.y;
}

function arenaLaneYPx(zone = activeZone()) {
  return Math.floor(state.stageHeight * arenaLaneYRatio(zone));
}

// Visual-only nudge for stamp-arena bosses (sprite draw + z-row); combatAnchor / enemyX unchanged.
function arenaEnemyVisualDrawOffset(zone = activeZone()) {
  return {
    x: Math.trunc(Number(zone?.arenaEnemyVisualOffsetX) || 0),
    y: Math.trunc(Number(zone?.arenaEnemyVisualOffsetY) || 0),
    mapRow: Math.trunc(Number(zone?.arenaEnemyMapRowOffset) || 0),
  };
}

function enemyVisualAnchor() {
  const base = combatAnchor("enemy");
  const offset = arenaEnemyVisualDrawOffset();
  return {
    x: base.x + offset.x,
    y: base.y + offset.y,
  };
}

function combatAnchor(name) {
  const battle = state.battle;
  const laneY = arenaLaneYPx();
  const enemyOffsetY = name === "enemy" ? Math.trunc(Number(activeZone()?.arenaEnemyOffsetY) || 0) : 0;
  if (battle.player && battle.enemy) {
    const worldX = name === "enemy" ? battle.enemyX : battle.playerX;
    return {
      x: Math.floor(worldX - battle.cameraX),
      y: laneY + enemyOffsetY,
    };
  }
  const anchor = COMBAT_ANCHORS[name] ?? COMBAT_ANCHORS.player;
  const townYOffset = state.game.mode === "town" ? townViewOffsetYPx() : 0;
  if (state.game.mode === "town" && name === "player") {
    return {
      x: Math.floor(state.stageWidth * 0.34),
      y: Math.floor(state.stageHeight * 0.58 + townYOffset),
    };
  }
  if (state.game.mode === "zone") {
    return {
      x: Math.floor(state.stageWidth * anchor.x),
      y: laneY + (name === "enemy" ? enemyOffsetY : 0),
    };
  }
  return {
    x: Math.floor(state.stageWidth * anchor.x),
    y: Math.floor(state.stageHeight * anchor.y + townYOffset),
  };
}

function layerNames() {
  const names = Object.keys(state.catalogue?.layers ?? {});
  if (names.length === 0) return ["armour", "hair", "weapon"];
  const preferred = ["weaponBack", "armour", "hair", "weapon", "weaponFront", "weaponAlt", "effect"];
  return [
    ...preferred.filter((name) => names.includes(name)),
    ...names.filter((name) => !preferred.includes(name)),
  ];
}

function playbackFrameIndex(frameCount) {
  const spec = PLAYER_ACTIONS[state.action];
  if (!spec.reverse) return state.frame;
  return Math.max(0, frameCount - 1 - state.frame);
}

function updateActionButtons() {
  els.actionGroups.querySelectorAll("button").forEach((button) => {
    button.classList.toggle("active", button.dataset.action === state.action);
  });
}

function updateCoverage() {
  const allActions = Object.keys(PLAYER_ACTIONS);
  const missing = Object.fromEntries(
    layerNames().map((layer) => [layer, missingActions(state.atlases[layer], allActions)]),
  );
  const availableCount = allActions.filter((action) =>
    layerNames().some((layer) => state.atlases[layer]?.actions?.[action]),
  ).length;

  const set = SPRITE_SETS[state.spriteSet];
  els.status.textContent = `${set.label}: ${availableCount}/${allActions.length} actions`;
  els.status.classList.toggle("warn", availableCount < allActions.length);
  els.coverage.innerHTML = layerNames()
    .map((layer) => {
      const text = missing[layer].length ? missing[layer].join(", ") : "complete";
      return `<p><strong>${title(layer)}</strong><span>${text}</span></p>`;
    })
    .join("");
}

function title(text) {
  return text.charAt(0).toUpperCase() + text.slice(1);
}
